/* ============================================================
   Procedure: [dbo].[usp_tsk_ChatlogData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_tsk_ChatlogData
@LeadId bigint
as
begin
	select ul.ID as LeadId, ch.ChatHtml  from UserLeads(nolock) ul 
		inner join tbl_MergeLeadsEnquiry(nolock) mle on ul.LeadNo = mle.LeadNo
		inner join tbl_ttc_PrechatFormData(nolock) pfd on mle.EnquiryNo = pfd.EnquiryId
		left join tbl_ttc_ChatHistories(nolock) ch on pfd.VisitorId = ch.VisitorId
		where 
			ul.ID = @LeadId
end



GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GenerateCallTask]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_tsk_GenerateCallTask
@Id bigint,
@Title nvarchar(255),
@MobileNo varchar(50),
@EndDate datetime,
@UserId bigint,
@Status nvarchar(255) ='open',
@IsTask bit = 1,
@IsAppointment bit = 0,
@CompletedOn datetime
as
begin	
	declare @LeadId bigint ;
	 select Top 1 @LeadId = Id from UserLeads where ParentID = ( select ParentId from User_Detail where User_ID = @UserId) and (  MobileNo = @MobileNo or MobileNo1 = @MobileNo  or MobileNo2 = @MobileNo )

	IF(@Id = 0)
		begin
			INSERT INTO tbl_tsk_TaskHistory (Title, EndDate, LeadId, AssignedTo, IsActive, TaskId, CreatedBy, [Status], IsTask, IsAppointment, TaskType, CompletedOn, CreatedOn )
				VALUES (@Title, @EndDate, @LeadId, @UserId, 1, 4, @UserId, @Status, 1, 0, '',  null, GETDATE() )	
		end
	else
		begin
			UPDATE tbl_tsk_TaskHistory
				SET
					Title = IIF(ISNULL(@Title, '') = '', Title, @Title),
					EndDate = IIF(ISNULL(@EndDate, '') = '', EndDate, @EndDate),
					AssignedTo = IIF(ISNULL(@UserId, '') = '', AssignedTo, @UserId),
					[Status] = IIF(ISNULL(@Status, '') = '', [Status], @Status),
					CompletedOn = IIF(ISNULL(@CompletedOn, '') = '', CompletedOn, @CompletedOn)
				WHERE 
					Id = @Id
		end
end


