CREATE   PROCEDURE usp_tsk_GetAllOutcomeByUserId
@UserId bigint
as
begin
	declare @ParentId bigint

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId
	
	select OutcomeName from tbl_tsk_UserOutcomeMaster where (ParentId = @ParentId or ParentId = 0) and OutcomeName <>  ''
