   Procedure: [dbo].[usp_tsk_GetAttachmentListByTaskId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_tsk_GetAttachmentListByTaskId @TaskId BIGINT  
AS  
    BEGIN  
        SELECT ad.Id, ad.FileName, ad.CreatedOn, LTRIM(RTRIM(ud.FName)) + ' ' + LTRIM(RTRIM(ud.LName)) AS CreatedBy, AD.CreatedOn, ad.TaskId, ad.ParentId
        FROM tbl_tsk_AttachmentDetails(nolock) ad inner join User_Detail(nolock) ud  on ad.CreatedBy = ud.User_ID
        WHERE ad.IsDeleted <> 1 and  ad.TaskId = @TaskId  
    END;  



