/* ============================================================
   Procedure: [dbo].[usp_tsk_GetEventForCalendar]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tsk_GetEventForCalendar]    
(    
 @UserId    BIGINT,     
 @StartDate DATETIME,     
 @EndDate   DATETIME    
)    
AS    
    BEGIN  
	 DECLARE @ParentId BIGINT = 0;              
 DECLARE @IsAdmin bit = 0;              
 DECLARE @RoleType varchar(10);              
 Declare @TeamCode VARCHAR(20)                            

SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;              

if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end

CREATE TABLE #tblUserIds(
   UserId bigint  NOT NULL)

select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode
where tum.UserId = @UserId
 
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))
Begin
--set @RoleType = 'Global'
Insert into #tblUserIds (UserId)
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId 
End
Else if(@TeamCode != null) 
Begin
---set @RoleType = 'Team'
Insert into #tblUserIds (UserId)
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode
End
Else 
Begin
--set @RoleType = 'User'
Insert into #tblUserIds (UserId)
select @UserId 
End

        SELECT *    
        FROM    
        (    
            SELECT Id AS [id],     
                   Title AS [title],     
                   (CASE    
                        WHEN IsTask = 1    
                        THEN EndDate    
                        ELSE StartDate    
                    END) AS [start],     
                   (CASE    
                        WHEN IsTask = 1    
                        THEN DATEADD(MINUTE, 5, EndDate)  
                        ELSE EndDate    
                    END) AS [end]    
            FROM tbl_tsk_TaskHistory(NOLOCK)    
            WHERE CreatedBy in (select UserId From #tblUserIds) 
        ) e    
        WHERE e.start BETWEEN @StartDate AND @EndDate;    
    END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetPhysicalAppointmentListByUserId_WithScoreCard_Search_Export_WithSegment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tsk_GetPhysicalAppointmentListByUserId_WithScoreCard_Search_Export_WithSegment] 
  @FilterText VARCHAR(500)  
 ,@UserId BIGINT  
 ,@Mode VARCHAR(20)
 ,@CriteriaName nvarchar(500) = '' --null
AS   

begin

	
 
	declare 
		@AType nvarchar(25) = '',
		@OffsetValue int =0,
		@PagingSize int =9999999,
		@uiId bigint = 0,
		@FromDate date = null,
		@EndDate date = null
		--@FilterText nvarchar(max) = '',
		--@UserId BIGINT = 46138,
		--@Mode VARCHAR(20) = 'p'

	if(isnull(@AType, '') <> '' and isnull(@AType, '') <> ''  and isnull(@AType, '') <> '' and isnull(@AType, '') <> '' )
	begin
		set @FilterText = concat(N' and 1 = ( case ',
		N' when ''', @AType, ''' = ''Visit'' and isnull(geci.GeoEntityCheckId, '''') <> '''' and A.AssignedTo = ', @uiId, '  THEN 1 ',
		N' when ''', @AType, ''' = ''Assigned'' and A.AssignedTo = ', @uiId, ' THEN 1 ',
		N' when ''', @AType, ''' = ''Missed'' and A.StartDate < GETDATE() and isnull(geci.GeoEntityCheckId, '''') = '''' and A.AssignedTo = ', @uiId, ' THEN 1 ',
		N' when ''', @AType, ''' = ''Pending'' and A.StartDate > GETDATE() and isnull(geci.GeoEntityCheckId, '''') = '''' and A.AssignedTo = ', @uiId, ' THEN 1',
		N' else 0 end ) and StartDate >= cast(''', @FromDate, ''' as date) and EndDate <= cast(''', @EndDate, ''' as date) ')
	end


	 DECLARE @ParentId BIGINT = 0, @iUserId bigint = @UserId
	 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                    
	 DECLARE @RoleType varchar(10);    


	 Declare @TeamCode varchar(10) = ''  
	 Declare @ScopeCode varchar(10) = ''   
	 Declare @UserIdTeamLst varchar(Max) = ''   
	 Declare @UserLoginTeamLst varchar(Max) = ''   

	  drop table if exists #tbluser
	 create table #tbluser (User_ID bigint,Name varchar(100), Image varchar(100),ParentID bigint)  
	 declare @IsAdmin bit = 0  
	 select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId  
	 if(@IsAdmin = 1)  
	 begin  
	  set @UserId = 0;  
	  --insert into @tbluser  
	  insert into #tbluser  
	  exec usp_GetUserDetailWithParent @ParentId  
	 end  
	 else  
	 Begin  
	  --insert into @tbluser  
	  insert into #tbluser  
	  exec usp_GetUserDetailWithParent @UserId  
	 End  
  
	select @UserIdTeamLst = isnull(STRING_AGG(User_ID,','),'') From #tbluser  

	declare @FinalSql nvarchar(max), @ScriptPrefix nvarchar(max), @FirstSql nvarchar(max), @SecondSql nvarchar(max),
		@ThirdSql nvarchar(max), @FouthSql nvarchar(max), @ScriptSufix nvarchar(max), @StartPoint int, @Endpoint int

	set @StartPoint = @OffsetValue + 1;
	set @Endpoint = (@StartPoint + @PagingSize) - 1


	set @ScriptPrefix = concat( N'SELECT  Title, Description, Address, StartDate, EndDate, STATUS,  ',
		N' AssignedTo,CreatedBy as CreatorName, CompletedOn=format(CompletedOn,''dd-MMM-yyyy HH:mm:ss''), Remarks,Collaboraters,OwnerName,OutcomeName, TaskStatus,'''' as ThresholdColor
		FROM (SELECT ',
			N'ROW_NUMBER() OVER(partition by (select null) order by A.PhysicalAppointmentId desc) AS Sno, ',
			N'COUNT(A.PhysicalAppointmentId) OVER() AS TotalRow, ',
			N'A.PhysicalAppointmentId, A.Title, A.Description, A.Address, A.StartDate, A.EndDate,A.CompletedOn,  ',
			N'A.STATUS, A.TaskStatus, A.ParentID, dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS AssignedTo,dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) as CreatedBy, dbo.udf_tsk_GetPhysicalAppointmentCollaboratersNames(A.PhysicalAppointmentId) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], A.UserId, A.OutcomesId, A.IsActive, ',
			N' A.TaskTypeId, A.Remarks, A.CreatedDate, A.UpdatedDate, A.GeoEntitySiteId, ',
			N'UOM.OutcomeName, SM.GeoEntitySiteName, GE.GeoEntityName, ISNULL(GE.GeoEntityType, ''location'') as [GeoEntityType], GE.EntityId, GE.Mobile, GE.EmailId, TM.TasKName, TM.IconClass, TM.has_view as [TmhHasView], TM.has_edit as [TmhHasEdit],  ',
			N'TM.has_remove as [TmhHasRemove], TM.has_completion as [TmhHasCompletion], TM.has_comment as [TmhHasComment], ',
			N'EP.has_view as [FepHasView], EP.has_edit as [FepHasEdit], EP.has_remove as [FephHasRemove], ',
			N'EP.has_completion as [FepHasCompletion], EP.has_comment as [FepHasComment], colb.Has_viewLead, colb.Has_editLead,colb.Has_fieldviewLead, colb.Has_fieldeditLead,  ',
			N'CASE WHEN A.Assignedto=',@iuserid,' THEN ''Owner''
				When 1= (Select distinct 1 from TBL_ET_PhyAppointCollaboratorUserMapping col where Userid=',@iUserId,' and col.PhysicalAppointmentId=A.PhysicalAppointmentId) THEN ''Collab''
				When 1= (Select distinct 1 from TBL_ET_PhyAppointUserMapping upm where Userid=',@iUserId,' and upm.PhysicalAppointmentId=A.PhysicalAppointmentId) THEN ''Field''
			END UserType ',
		 N'FROM ( ' )


	set @FirstSql  = concat( N'	SELECT TH.PhysicalAppointmentId, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, (CASE  WHEN LOWER(TH.STATUS) = ''completed'' THEN ''Completed''
					ELSE (CASE WHEN CAST(TH.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled''
                    WHEN CAST(TH.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due''
                    ELSE ''Due Today'' END) END) AS [TaskStatus],  UD.ParentID, ',
		 N' th.AssignedTo AS AssignedTo,TH.CreatedBy, UD.User_ID AS [UserId], TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskTypeId, TH.Remarks, ',
		 N'TH.CreatedDate, TH.UpdatedDate, TH.GeoEntitySiteId FROM TBL_ET_PhysicalAppointment(NOLOCK) TH  ',
					N'LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = (case when ', @IsAdmin, ' = 1 then TH.CreatedBy ELSE UD.User_ID end )',
			N'WHERE TH.CreatedBy IN( ', @UserIdTeamLst, ' ) AND TH.IsActive = 1  ' )

	set @SecondSql  = concat( N' UNION SELECT TH.PhysicalAppointmentId, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, (CASE  WHEN LOWER(TH.STATUS) = ''completed'' THEN ''Completed''
					ELSE (CASE WHEN CAST(TH.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled''
                    WHEN CAST(TH.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due''
                    ELSE ''Due Today'' END) END) AS [TaskStatus], ',
			N'UD.ParentID,  th.AssignedTo AS AssignedTo, TH.CreatedBy, UD.User_ID AS [UserId], TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskTypeId, ',
			N'TH.Remarks, TH.CreatedDate, TH.UpdatedDate, TH.GeoEntitySiteId FROM TBL_ET_PhysicalAppointment(NOLOCK) TH ',
			N'LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = (case when ', @IsAdmin, ' = 1 then TH.AssignedTo ELSE UD.User_ID end )',
			N'WHERE TH.AssignedTo IN( ', @UserIdTeamLst, ' ) AND TH.IsActive = 1  ' )
	
	set @ThirdSql  = concat( N' UNION SELECT TH.PhysicalAppointmentId, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, (CASE  WHEN LOWER(TH.STATUS) = ''completed'' THEN ''Completed''
					ELSE (CASE WHEN CAST(TH.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled''
                    WHEN CAST(TH.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due''
                    ELSE ''Due Today'' END) END) AS [TaskStatus], ',
			N'TH.ParentID,  th.AssignedTo AS AssignedTo, TH.CreatedBy, TCM.UserId AS [UserId], TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskTypeId, ',
			N'TH.Remarks, TH.CreatedDate, TH.UpdatedDate, TH.GeoEntitySiteId FROM TBL_ET_PhysicalAppointment(NOLOCK) TH ',
			N'LEFT JOIN TBL_ET_PhyAppointCollaboratorUserMapping(NOLOCK) TCM ON TH.PhysicalAppointmentId = TCM.PhysicalAppointmentId ',
			N'WHERE TCM.UserId IN( ', @UserIdTeamLst, ' ) AND TH.IsActive = 1  ' )

	set @FouthSql  = concat( N' UNION SELECT TH.PhysicalAppointmentId, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, (CASE  WHEN LOWER(TH.STATUS) = ''completed'' THEN ''Completed''
					ELSE (CASE WHEN CAST(TH.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled''
                    WHEN CAST(TH.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due''
                    ELSE ''Due Today'' END) END) AS [TaskStatus], ',
			N'Th.ParentID, TH.AssignedTo, TH.CreatedBy, TCM.UserId AS [UserId], TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskTypeId, ',
			N'TH.Remarks, TH.CreatedDate, TH.UpdatedDate, TH.GeoEntitySiteId FROM TBL_ET_PhysicalAppointment(NOLOCK) TH ',
			N'LEFT JOIN TBL_ET_PhyAppointUserMapping(NOLOCK) TCM ON TH.PhysicalAppointmentId = TCM.PhysicalAppointmentId ',
			N'WHERE TCM.UserId IN( ', @UserIdTeamLst, ' ) AND TH.IsActive = 1  ' )

	set @ScriptSufix = concat( N' ) A ',
		N' LEFT JOIN TBL_ET_GeoEntitySiteMaster(NOLOCK) SM ON A.GeoEntitySiteId = SM.GeoEntitySiteId ',
		N' LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId ',
		N' LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) TM ON A.TaskTypeId = TM.Id ',
		N' LEFT JOIN TBL_ET_PhyApptTypeFieldExecutivePermission(NOLOCK) EP  ON A.TaskTypeId = EP.task_type_id ',
		N' LEFT JOIN TBL_ET_GeoEntityMaster(NOLOCK) GE ON SM.GeoEntityId = GE.GeoEntityId ',
		N' LEFT JOIN TBL_ET_GeoEntityCheckInOut(nolock) geci on A.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
		N' Outer APPLY dbo.udf_tsk_GetCollaboratersLeadEditView1(A.PhysicalAppointmentId,',@iUserId,',', @ParentId,') colb',
		N' WHERE A.UserId = ', @iUserId, ' ', iif(isnull(@FilterText, '') <> '', @FilterText,  ''), ' ) T  WHERE T.Sno between ', @StartPoint, ' and ', @Endpoint )


	print @ScriptPrefix
	print @FirstSql
	print @SecondSql
	print @ThirdSql
	print @FouthSql
	print @ScriptSufix

	set @FinalSql = concat( @ScriptPrefix, @FirstSql, @SecondSql, @ThirdSql, @FouthSql, @ScriptSufix )

	execute sp_executesql @FinalSql

end





GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskHistoryLisByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_tsk_GetTaskHistoryLisByUserId 
	@FilterText VARCHAR(500),               
	@UserId BIGINT,               
	@Mode VARCHAR(20)              
AS

BEGIN	
	DECLARE @ParentId BIGINT = 0;
	SELECT @ParentId = ParentID FROM User_Detail WHERE User_ID = 29453;

    DECLARE @Query VARCHAR(MAX)= 'SELECT *, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus FROM ( SELECT TH.LeadId as LeadId, TH.Id as [TaskHistoryId], TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], (UD.FName + '' '' + UD.LName) as CreatorName, UD.ParentID, TH.AssignedTo, TH.CreatedBy, UD.User_Id as [UserId], TH.IsTask, TH.IsAppointment, ISNULL(UOM.OutcomeName, '''') AS OutcomeName , TH.IsActive, TH.CompletedOn, TH.TaskId, UTM.IconClass, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus, dbo.udf_mk_GetTotalAttachment(TH.Id) as [TotalAttachments] FROM tbl_tsk_TaskHistory(nolock) TH JOIN User_Detail(nolock) UD ON TH.CreatedBy = UD.User_ID  JOIN  User_Detail AT ON  TH.AssignedTo = AT.User_ID INNER JOIN UserLeads(nolock) UL ON TH.LeadId = UL.ID LEFT JOIN tbl_tsk_UserTaskMaster(nolock) UTM ON TH.TaskId = UTM.Id LEFT JOIN tbl_tsk_UserOutcomeMaster(nolock) UOM ON UOM.Id = TH.OutcomesId       
   UNION        
		SELECT TH.LeadId as LeadId, TH.Id as [TaskHistoryId], TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], (UD.FName + '' '' + UD.LName) as CreatorName, UD.ParentID, TH.AssignedTo, TH.CreatedBy, TCM.User_Id as [UserId], TH.IsTask, TH.IsAppointment, ISNULL(UOM.OutcomeName, '''') AS OutcomeName, TH.IsActive, TH.CompletedOn, TH.TaskId, UTM.IconClass, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus, dbo.udf_mk_GetTotalAttachment(TH.Id) as [TotalAttachments]  FROM tbl_tsk_TaskHistory(nolock) TH JOIN User_Detail(nolock) UD ON TH.CreatedBy = UD.User_ID  JOIN  User_Detail AT ON  TH.AssignedTo = AT.User_ID INNER JOIN  UserLeads(nolock) UL ON TH.LeadId = UL.ID LEFT JOIN tbl_tsk_UserTaskMaster(nolock) UTM ON TH.TaskId = UTM.Id  LEFT  JOIN tbl_tsk_CollaborationUserMapping(nolock) TCM ON TH.Id  = TCM.TaskHistoryId  LEFT JOIN tbl_tsk_UserOutcomeMaster(nolock) UOM ON UOM.Id = TH.OutcomesId  AND  TCM.DeletedOn is NULL ) A  WHERE ' + 
	CASE
		WHEN @UserId = @ParentID 
			THEN ' A.ParentId = ' + CAST(@UserId AS VARCHAR(10)) + ' ' 
		ELSE
			' A.UserId = ' + CAST(@UserId AS VARCHAR(10)) +  '  OR A.AssignedTo = ' + CAST(@UserId AS VARCHAR(10)) + '  ' 
	END
	+ ' AND IsActive = 1 and  A.IsAppointment=Case when ''' + @Mode + ''' = ''A'' then 1 else A.IsAppointment end and   A.IsTask=Case when ''' + @Mode + ''' = ''T'' then 1 else A.IsTask end   ';              
                    
  IF(ISNULL(@FilterText, '') <> '')              
            SET @Query = @Query + @FilterText;              
        PRINT @Query;              
        EXEC (@Query);              
    END;


GO

