CREATE   PROCEDURE usp_tsk_GetTaskHistoryListByUserId   
 @FilterText VARCHAR(500),                 
 @UserId BIGINT,                 
 @Mode VARCHAR(20)                
AS  
  
BEGIN   
 DECLARE @ParentId BIGINT = 0;  
 SELECT @ParentId = ParentID FROM User_Detail WHERE User_ID = @UserId;  
    DECLARE @Query VARCHAR(MAX)= 'SELECT *, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus FROM ( SELECT TH.LeadId as LeadId, TH.Id as [TaskHistoryId], TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(TH.CreatedBy) as [CreatorName], UD.ParentID, TH.AssignedTo, TH.CreatedBy, UD.User_Id as [UserId], TH.IsTask, TH.IsAppointment, ISNULL(UOM.OutcomeName, '''') AS OutcomeName , TH.IsActive, TH.CompletedOn, TH.TaskId, UTM.IconClass, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS 
Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus, dbo.udf_mk_GetTotalAttachment(TH.Id) as [TotalAttachments], TH.Remarks, TH.CreatedOn, TH.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(TH.Id) as [Collaboraters], dbo.udf_mk_GetTaskCreatorName(TH.AssignedTo) as [OwnerName] FROM tbl_tsk_TaskHistory(nolock) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID INNER JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(nolock) UTM ON TH.TaskId = UTM.Id LEFT JOIN tbl_tsk_UserOutcomeMaster(nolock) UOM ON UOM.Id = TH.OutcomesId         
   UNION
   SELECT TH.LeadId as LeadId, TH.Id as [TaskHistoryId], TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(TH.CreatedBy) as [CreatorName], UD.ParentID, TH.AssignedTo, TH.CreatedBy, UD.User_Id as [UserId], TH.IsTask, TH.IsAppointment, ISNULL(UOM.OutcomeName, '''') AS OutcomeName , TH.IsActive, TH.CompletedOn, TH.TaskId, UTM.IconClass, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus, dbo.udf_mk_GetTotalAttachment(TH.Id) as [TotalAttachments], TH.Remarks, TH.CreatedOn, TH.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(TH.Id) as [Collaboraters], dbo.udf_mk_GetTaskCreatorName(TH.AssignedTo) as [OwnerName] FROM tbl_tsk_TaskHistory(nolock) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID INNER JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(nolock) UTM ON TH.TaskId = UTM.Id LEFT JOIN tbl_tsk_UserOutcomeMaster(nolock) UOM ON UOM.Id = TH.OutcomesId         
   UNION
  SELECT TH.LeadId as LeadId, TH.Id as [TaskHistoryId], TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(TH.CreatedBy) as [CreatorName], UD.ParentID, TH.AssignedTo, TH.CreatedBy, TCM.User_Id as [UserId], TH.IsTask, TH.IsAppointment, ISNULL(UOM.OutcomeName, '''') AS OutcomeName, TH.IsActive, TH.CompletedOn, TH.TaskId, UTM.IconClass, ( CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date ) THEN ''Scheduled'' WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date ) THEN ''Over Due'' ELSE ''Due Today'' END) AS TaskStatus, dbo.udf_mk_GetTotalAttachment(TH.Id) as [TotalAttachments], TH.Remarks, TH.CreatedOn, TH.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(TH.Id) as [Collaboraters], dbo.udf_mk_GetTaskCreatorName(TH.AssignedTo) as [OwnerName]   FROM tbl_tsk_TaskHistory(nolock) TH JOIN User_Detail(nolock) UD ON TH.CreatedBy = UD.User_ID INNER JOIN  UserLeads(nolock) UL ON TH.LeadId = UL.ID LEFT JOIN tbl_tsk_UserTaskMaster(nolock) UTM ON TH.TaskId = UTM.Id  LEFT  JOIN tbl_tsk_CollaborationUserMapping(nolock) TCM ON TH.Id  = TCM.TaskHistoryId  LEFT JOIN tbl_tsk_UserOutcomeMaster(nolock) UOM ON UOM.Id = TH.OutcomesId  AND  TCM.DeletedOn is NULL  
  ) A  WHERE  A.UserId = ' + CAST(@UserId AS VARCHAR(10)) + '  AND IsActive = 1 and  A.IsAppointment=Case when ''' + @Mode + ''' = ''A'' then 1 else A.IsAppointment end and   A.IsTask=Case when ''' + @Mode + ''' = ''T'' then 1 else A.IsTask end   ';                
                      
	IF(ISNULL(@FilterText, '') <> '') 
		begin
            SET @Query = @Query + ' ' +  @FilterText;                
        end
	else
		begin
			 SET @Query = @Query + ' order by EndDate desc'
		end
		
		PRINT @Query;                
        EXEC (@Query);                
    END;


GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard]             
 @FilterText VARCHAR(500),                                   
 @UserId BIGINT,                                   
 @Mode VARCHAR(20) ,  
 @OffsetValue int  = 0,  
 @PagingSize int  = 20                                
AS
BEGIN  
  
 --exec  mysms.dbo.usp_tsk_GetTaskHistoryListByUserId_WithScoreCard @FilterText,@UserId,@Mode   
  
 --declare @FilterText VARCHAR(500) = N' AND (  Status = ''open''  or TaskStatus = ''Over Due'' ) And ( (  (enddate between convert(date,''01-Jan-1900'') and convert(date,''25-Aug-2025'')) )) And   ( AssignedTo in (select User_id from #tbluser) and isnull(outcomesid,0)=0) ',@UserId BIGINT = 32222,@Mode VARCHAR(20) = 'A',@OffsetValue int = 0,@PagingSize int = 20
  --declare @FilterText VARCHAR(500) = N'AND (  Status = ''open''  or TaskStatus = ''Over Due''  ) And ( ( enddate between convert(date,''01-Jan-1900'') and convert(date,''26-Aug-2025'')  ) ) And   ( AssignedTo in (select User_id from #tbluser) and isnull(outcomesid,0)=0)',@UserId BIGINT = 32222,@Mode VARCHAR(20) = 'T',@OffsetValue int = 0,@PagingSize int = 20
  
 DECLARE @ParentId BIGINT = 0, @iUserId bigint = @UserId
 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                    
 DECLARE @RoleType varchar(10);                    
  
 --declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))  
 drop table if exists #tbluser
 create table #tbluser (User_ID bigint,Name varchar(100), Image varchar(100),ParentID bigint)  
 declare @IsAdmin bit = 0  
 select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId  
 if(@IsAdmin = 1)  
 begin  
  set @UserId = 0;  
  --insert into @tbluser  
  insert into #tbluser  
  exec usp_GetUserDetailWithParent @ParentId  
 end  
 else  
 Begin  
  --insert into @tbluser  
  insert into #tbluser  
  exec usp_GetUserDetailWithParent @UserId  
 End  
  
      
 Declare @TeamCode varchar(10) = ''  
 Declare @ScopeCode varchar(10) = ''   
 Declare @UserIdTeamLst varchar(Max) = ''   
 Declare @UserLoginTeamLst varchar(Max) = ''   
  
-- select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
  
--if(trim(@UserIdTeamLst) ='')  
--begin  
--set @UserIdTeamLst = cast(@UserId as nvarchar)  
--end  
  
--select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst, @UserLoginTeamLst  
  
--select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser  
select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From #tbluser  
  
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history_latest(nolock)e
 where parentid=@ParentId),0)                    
                
declare @hot int  ,@warm int , @cold int             
                    
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentId                          
 if @hot is null                          
 begin                          
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0
 end             
            
    DECLARE @Query NVARCHAR(MAX)= N'SELECT  count(TaskHistoryId) over() as TotalRow, TaskHistoryId, LeadId, Title, Description, Address, StartDate, EndDate, STATUS, RelatedTo, RelatedToProfile, ParentID, AssignedTo, CreatedBy, CreatorName, UserId, CreatorName,IsTask, IsAppointment, OutcomesId, IsActive, CompletedOn, TaskId,  TotalAttachments, Remarks, CreatedOn, UpdatedOn, Collaboraters, OwnerName,  OutcomeName, IconClass, TaskStatus, CurrentScore, Profit_Loss, ThresholdColor,        hasEdit, hasView, hasRemove, hasCompletion, hasComment ,Has_viewLead, Has_editLead FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId,  A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UTM.IconClass, (CASE WHEN LOWER(A.STATUS) = ''completed'' THEN ''Completed'' ELSE( CASE WHEN CAST(A.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled'' WHEN CAST(A.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due'' ELSE ''Due Today'' END) END ) AS TaskStatus,  CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) + N', 0.00)) * 99, 0) AS INT) AS [CurrentScore], (CASE WHEN LS.ScoreAdded > 0 THEN ''Green_Up'' WHEN LS.ScoreAdded < 0 THEN ''Red_Down'' ELSE '''' END ) AS [Profit_Loss], (CASE WHEN CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) + N', 0.00)) * 99, 0) AS INT) > '+ cast(@warm as nvarchar(50)) + N' THEN ''Hot'' WHEN CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) +N', 0.00)) * 99, 0) AS INT ) BETWEEN ' + cast(@cold as nvarchar(50)) + N' AND '+cast(@warm as nvarchar(50)) + N' THEN ''Warm'' ELSE ''Cold'' END ) AS [ThresholdColor], iif( '+ cast(@iUserId as nvarchar) +' = A.AssignedTo, 1, ISNULL(tap.has_edit, 0)) AS hasEdit, iif( '+ cast(@iUserId as nvarchar) +' = A.AssignedTo, 1, ISNULL(tap.has_view, 1)) AS hasView, iif( '+ cast(@iUserId as nvarchar) +' = A.AssignedTo, 1, ISNULL(tap.has_remove, 0)) AS hasRemove, iif( '+ cast(@iUserId as nvarchar) +' = A.AssignedTo, 1, ISNULL(tap.has_completion, 0)) AS hasCompletion, iif( '+ cast(@iUserId as nvarchar) +' = A.AssignedTo, 1, ISNULL(tap.has_comment, 1)) AS hasComment, 
	Case When '+Cast(@IsAdmin as varchar)+'=1 then 1 
			When '+ cast(@iUserId as nvarchar) +' = A.AssignedTo then 1
			Else ISNULL(colb.Has_viewLead, 0) END Has_viewLead, 
	Case When '+Cast(@IsAdmin as varchar)+'=1 then 1 
			When '+ cast(@iUserId as nvarchar) +' = A.AssignedTo then 1 Else  ISNULL(colb.Has_editLead, 0) END  Has_editLead
	FROM ( SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH left JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id ' + CASE WHEN (@ParentId > 0 and @UserId = 0) THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX)) End + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END  
    UNION'  
     
 declare @Query1 nvarchar(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH left JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id ' + CASE WHEN (@ParentId > 0 and @UserId = 0) THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX)) End + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END  
    UNION SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE TCM.User_Id ' + CASE WHEN (@ParentId > 0 and @UserId = 0) THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX)) End + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END ) A left JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID outer APPLY dbo.udf_tsk_GetCollaboratersLeadEditView1(A.Id, '+Cast(@iuserid as varchar)+', '+Cast(@parentid as varchar)+') colb  LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = '+ cast(@ParentId as nvarchar) +' ) T where 1 = 1 and taskid <> 4 ';           
      
 IF(ISNULL(@FilterText, '') <> '')            
 BEGIN  
  set @Query1 = @Query1 + ' ' + @FilterText;  
 END   
   
 declare @OrderBy nvarchar(max) = ' order by EndDate desc  '  
 declare @PaginScript nvarchar(max) = ' offset ' +str(@OffsetValue) +' rows fetch next ' + str(@PagingSize)+' rows only '  
   
 if(@FilterText not like '%order by%')  
 begin  
  set @Query1 = @Query1 + @OrderBy   
 end    
  
 declare @Query2 nvarchar(max) = @Query + @Query1 + @PaginScript  
            
 print @Query  
 print @Query1  
 print @PaginScript  
 --print @Query2   
 
 execute sp_executesql @Query2  
  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_Local]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_tsk_GetTaskHistoryListByUserId_WithScoreCard @FilterText=N'',@UserId=34594,@Mode=N'A'
--GO

    
CREATE   PROCEDURE [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_Local]           
	@FilterText VARCHAR(500),                                 
	@UserId BIGINT,                                 
	@Mode VARCHAR(20) ,
	@OffsetValue int  = 0,
	@PagingSize int  = 20                              
AS                  
                  
BEGIN                   
        
 --exec  mysms.dbo.usp_tsk_GetTaskHistoryListByUserId_WithScoreCard @FilterText,@UserId,@Mode      
      
      
--declare @FilterText VARCHAR(500) = '',                                 
-- @UserId BIGINT = 31871,                                 
-- @Mode VARCHAR(20) = 'T'             
 
 DECLARE @ParentId BIGINT = 0;
 DECLARE @IsAdmin bit = 0;                  
 DECLARE @RoleType varchar(10);                  
 Declare @TeamCode VARCHAR(20)                                
    
 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                  
    
 if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end    
    
 CREATE TABLE #tblUserIds(    
    UserId bigint  NOT NULL)    
    
 select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum    
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode    
where tum.UserId = @UserId    
     
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))    
Begin    
--set @RoleType = 'Global'    
Insert into #tblUserIds (UserId)    
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId     
End    
Else if(@TeamCode != null)     
Begin    
---set @RoleType = 'Team'    
Insert into #tblUserIds (UserId)    
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode    
End    
Else     
Begin    
--set @RoleType = 'User'    
Insert into #tblUserIds (UserId)    
select @UserId     
End    
    
          
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history_latest(nolock)e   
 where parentid=@ParentId),0)                  
              
declare @hot int  ,@warm int , @cold int           
                  
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentId                        
 if @hot is null                        
 begin                        
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                      
 end           
          
    DECLARE @Query NVARCHAR(MAX)= N'SELECT  count(TaskHistoryId) over() as TotalRow, TaskHistoryId, LeadId, Title, Description, Address, StartDate, EndDate,
STATUS, RelatedTo, RelatedToProfile, ParentID, AssignedTo, CreatedBy, CreatorName, UserId, CreatorName,IsTask, IsAppointment, OutcomesId, 
IsActive, CompletedOn, TaskId,  TotalAttachments, Remarks, CreatedOn, UpdatedOn, Collaboraters, OwnerName,  OutcomeName, IconClass, TaskStatus, CurrentScore, Profit_Loss, ThresholdColor  FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName],
A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId,  A.IsActive, A.CompletedOn, A.TaskId,
	dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn,
	dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName],
	UOM.OutcomeName, UTM.IconClass, (CASE WHEN LOWER(A.STATUS) = ''completed'' THEN ''Completed'' ELSE( CASE WHEN CAST(A.EndDate AS DATE) > 
	CAST(GETDATE() AS DATE) THEN ''Scheduled'' WHEN CAST(A.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due'' ELSE ''Due Today'' END) END )
	AS TaskStatus,  CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) + N', 0.00)) * 99, 0) AS INT) AS [CurrentScore],
    (CASE WHEN LS.ScoreAdded > 0 THEN ''Green_Up'' WHEN LS.ScoreAdded < 0 THEN ''Red_Down'' ELSE '''' END ) AS [Profit_Loss], 
	(CASE WHEN CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) + N', 0.00)) * 99, 0) AS INT) > '+ cast(@warm as nvarchar(50)) + N' THEN ''Hot'' WHEN CAST(ISNULL((LS.currentscore / NULLIF('+ cast(@maxScore as nvarchar(50)) +N', 0.00)) * 99, 0) AS INT)
	BETWEEN ' + cast(@cold as nvarchar(50)) + N' AND '+cast(@warm as nvarchar(50)) + N' THEN ''Warm'' ELSE ''Cold'' END ) AS [ThresholdColor] FROM ( 
    SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, 
           TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, 
           TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4
		   LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID
		   WHERE UD.User_Id IN ( SELECT UserId FROM #tblUserIds) AND IsActive = 1 AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END
    UNION'
   
 declare @Query1 nvarchar(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 
           0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn
    FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4
         LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID 
		 LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id
	WHERE UD.User_Id IN ( SELECT UserId FROM #tblUserIds ) AND IsActive = 1
			AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END
			AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END
    UNION
    SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, 
           TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, 
           TH.Remarks, TH.CreatedOn, TH.UpdatedOn
    FROM tbl_tsk_TaskHistory(NOLOCK) TH JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4 
	LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId
		 WHERE TCM.User_Id IN ( SELECT UserId FROM #tblUserIds ) AND IsActive = 1
		 AND TH.IsAppointment = CASE WHEN '''+ @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END
		 AND TH.IsTask = CASE WHEN '''+ @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END 
	) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id ) T where 1 = 1 ';         
   
	IF(ISNULL(@FilterText, '') <> '')          
		BEGIN          
			SET @Query1 = @Query1 + ' ' + @FilterText;          
	END          
		ELSE          
		BEGIN          
			SET @Query1 = @Query1 + N' order by EndDate desc offset ' +str(@OffsetValue) +' rows fetch next ' + str(@PagingSize)+' rows only ';          
	END            
                  
	set @Query = @Query + @Query1
          
	--print @Query 
    execute sp_executesql @Query
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_Search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_Search '', 41181, 'A'    
 CREATE   PROCEDURE [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_Search]
 (
	@FilterText VARCHAR(500),
	@UserId BIGINT,
	@Mode VARCHAR(20)
 )
AS  
BEGIN  
   --declare @FilterText VARCHAR(500)='',
   --  @UserId BIGINT= 38990 --34594 --41181 
  --	,@Mode VARCHAR(20)='A'
 --exec  mysms.dbo.usp_tsk_GetTaskHistoryListByUserId_WithScoreCard @FilterText,@UserId,@Mode         
 DECLARE @ParentId BIGINT = 0,@iUserId BIGINT = @UserId  
  
 SELECT @ParentId = ParentID  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserId;  
  
 DECLARE @RoleType VARCHAR(10);  
  
 --declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))        
 DROP TABLE IF EXISTS #tbluser  

  CREATE TABLE #tbluser (  
   User_ID BIGINT  
   ,Name VARCHAR(100)  
   ,IMAGE VARCHAR(100)  
   ,ParentID BIGINT  
   )  
  
 DECLARE @IsAdmin BIT = 0  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserId  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  SET @UserId = 0;  
  
  --insert into @tbluser        
  INSERT INTO #tbluser  
  EXEC usp_GetUserDetailWithParent @ParentId  
 END  
 ELSE  
 BEGIN  
  --insert into @tbluser        
  INSERT INTO #tbluser  
  EXEC usp_GetUserDetailWithParent @UserId  
 END  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''  
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''  
  
 -- select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)         
 --if(trim(@UserIdTeamLst) ='')        
 --begin        
 --set @UserIdTeamLst = cast(@UserId as nvarchar)        
 --end        
 --select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst, @UserLoginTeamLst        
 --select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser        
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM #tbluser  
  
 DECLARE @maxScore NUMERIC(18, 2) = isnull((  
    SELECT (max(currentscore) * 100) / 99  
    FROM lead_score_history_latest(NOLOCK) e  
    WHERE parentid = @ParentId  
    ), 0)  
 DECLARE @hot INT  
  ,@warm INT  
  ,@cold INT  
  
 SELECT @hot = hot  
  ,@warm = warm  
  ,@cold = cold  
 FROM lead_cateogy_thresholds(NOLOCK)  
 WHERE parentid = @ParentId  
  
 IF @hot IS NULL  
 BEGIN  
  SELECT @hot = hot  
   ,@warm = warm  
   ,@cold = cold  
  FROM lead_cateogy_thresholds(NOLOCK)  
  WHERE parentid = 0  
 END  
  
 DECLARE @Query NVARCHAR(MAX) =   
  N'SELECT  count(TaskHistoryId) over() as TotalRow, TaskHistoryId, LeadId, LeadNo, Title, Description, Address, StartDate, EndDate, STATUS, RelatedTo, RelatedToProfile, ParentID, AssignedTo, CreatedBy, CreatorName, UserId, CreatorName,IsTask, IsAppointment, OutcomesId, IsActive, CompletedOn, TaskId,  TotalAttachments, Remarks, CreatedOn, UpdatedOn, Collaboraters, OwnerName,  OutcomeName, IconClass, TaskStatus, CurrentScore, Profit_Loss, ThresholdColor,        hasEdit, hasView, hasRemove, hasCompletion, hasComment  FROM ( SELECT A.LeadId, A.LeadNo ,A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, format(A.StartDate ,''dd-MMM-yyyy HH:mm:ss'') as StartDate, format(A.EndDate ,''dd-MMM-yyyy HH:mm:ss'') as EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId,  A.IsActive, format(A.CompletedOn,''dd-MMM-yyyy HH:mm:ss'') as CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UTM.IconClass, (CASE WHEN LOWER(A.STATUS) = ''completed'' THEN ''Completed'' ELSE( CASE WHEN CAST(A.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled'' WHEN CAST(A.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due'' ELSE ''Due Today'' END) END ) AS TaskStatus,  CAST(ISNULL((LS.currentscore / NULLIF('   
  + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) AS [CurrentScore], (CASE WHEN LS.ScoreAdded > 0 THEN ''Green_Up'' WHEN LS.ScoreAdded < 0 THEN ''Red_Down'' ELSE '''' END ) AS [Profit_Loss], (CASE WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) > ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Hot'' WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT ) BETWEEN ' + cast(@cold AS NVARCHAR(50)) + N' AND ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Warm'' ELSE ''Cold'' END ) AS [ThresholdColor], iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_edit, 0)) AS hasEdit, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_view, 1)) AS hasView, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_remove, 0)) AS hasRemove, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_completion, 0)) AS hasCompletion, iif( ' +   
  cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_comment, 1)) AS hasComment FROM ( SELECT TH.LeadId, UL.LeadNo ,TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id ' + CASE   
   WHEN (  
     @ParentId > 0  
     AND @UserId = 0  
     )  
    THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
   ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))  
   END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END        
    UNION'  
 DECLARE @Query1 NVARCHAR(max) = N' SELECT TH.LeadId,UL.LeadNo,TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id ' + CASE   
   WHEN (  
     @ParentId > 0  
     AND @UserId = 0  
     )  
    THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
   ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))  
   END + ' AND IsActive = 1 AND  TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END        
    UNION SELECT TH.LeadId,UL.LeadNo,TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH Join UserLeads(nolock) UL on TH.LeadId = UL.ID JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE UD.User_Id ' 
+ CASE   
   WHEN (  
     @ParentId > 0  
     AND @UserId = 0  
     )  
    THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
   ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))  
   END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END ) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = ' + cast(@ParentId AS NVARCHAR) + ' ) T where 1 = 1 ';  
  
 IF (ISNULL(@FilterText, '') <> '')  
 BEGIN  
  SET @Query1 = @Query1 + ' ' + @FilterText;  
 END  
  
 DECLARE @OrderBy NVARCHAR(max) = ' order by EndDate desc  '  
  
 -- declare @PaginScript nvarchar(max) = ' offset ' +str(@OffsetValue) +' rows fetch next ' + str(@PagingSize)+' rows only '        
 IF (@FilterText NOT LIKE '%order by%')  
 BEGIN  
  SET @Query1 = @Query1 + @OrderBy  
 END  
  
 DECLARE @Query2 NVARCHAR(max) = @Query + @Query1 --+ @PaginScript        
  
 PRINT @Query  
 PRINT @Query1  
  
 -- print @PaginScript        
 --print @Query2         
 EXECUTE sp_executesql @Query2  
  
 DECLARE @Activity_type VARCHAR(max)  
  
 IF @Mode = 'T'  
 BEGIN  
  SET @Activity_type = 'View_Task_Exp'  
 END  
  
 IF @Mode = 'A'  
 BEGIN  
  SET @Activity_type = 'View_Appoint_Exp'  
 END  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = @Activity_type  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'tbl_tsk_TaskHistory'  
END  



