    WHERE parentid = @ParentId  
    ), 0)  
 DECLARE @hot INT,@warm INT,@cold INT  
  
 SELECT @hot = hot,@warm = warm,@cold = cold  
 FROM lead_cateogy_thresholds(NOLOCK)  
 WHERE parentid = @ParentId  
  
 IF @hot IS NULL  
 BEGIN  
  SELECT @hot = hot,@warm = warm,@cold = cold  
  FROM lead_cateogy_thresholds(NOLOCK)  
  WHERE parentid = 0  
 END  
  
 DECLARE @Query NVARCHAR(MAX) =   @QueryTotality  + ' ; ' + 
  N'SELECT  count(TaskHistoryId) over() as TotalRow, TaskHistoryId, LeadId, [LeadNo], Title, Description, Address, StartDate=format(StartDate,''dd-MMM-yyyy HH:mm:ss''), EndDate=format(StartDate,''dd-MMM-yyyy HH:mm:ss''), STATUS, RelatedTo, RelatedToProfile,Parent, AssignedTo, CreatorName,IsTask, IsAppointment, OutcomesId, IsActive, CompletedOn=format(CompletedOn,''dd-MMM-yyyy HH:mm:ss''), TaskId,  TotalAttachments, Remarks, CreatedOn, UpdatedOn, Collaboraters, OwnerName,  OutcomeName, IconClass, TaskStatus, CurrentScore, Profit_Loss, ThresholdColor, hasEdit, hasView, hasRemove, hasCompletion, hasComment  FROM ( SELECT A.LeadId, [A].LeadNo, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName],dbo.udf_mk_GetTaskCreatorName(A.ParentID) AS [Parent], A.ParentID, dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [AssignedTo], A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId, A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UTM.IconClass,  
(CASE WHEN LOWER(A.STATUS) = ''completed'' THEN ''Completed'' ELSE( CASE WHEN CAST(A.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled'' WHEN CAST(A.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due'' ELSE ''Due Today'' END) END ) AS TaskStatus,   
CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) AS [CurrentScore], (CASE WHEN LS.ScoreAdded > 0 THEN ''Green_Up'' WHEN LS.ScoreAdded < 0 THEN ''Red_Down'' ELSE '''' END ) AS [Profit_Loss], (CASE WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) > ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Hot'' WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT ) BETWEEN ' + cast(@cold AS NVARCHAR(50)) + N' AND ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Warm'' ELSE ''Cold'' END ) AS [ThresholdColor],  iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_edit, 0)) AS hasEdit, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_view, 1)) AS hasView, iif(' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_remove, 0)) AS hasRemove, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_completion, 0)) AS hasCompletion, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_comment, 1)) AS hasComment FROM ( SELECT TH.LeadId, UL.LeadNo, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 join #userleadsBySegment as uls on UL.ID = uls.ID LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id ' + CASE WHEN (@ParentId > 0  AND @UserId = 0) THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX)) END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END          
    UNION'  
 DECLARE @Query1 NVARCHAR(max) = N' SELECT TH.LeadId, UL.LeadNo, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 join #userleadsBySegment as uls on UL.ID = uls.ID  LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id ' + CASE WHEN (@ParentId > 0 AND @UserId = 0) THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX)) END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END
   UNION 
   SELECT TH.LeadId, UL.LeadNo, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) AS UL ON TH.LeadId = UL.ID AND th.taskid <> 4 join #userleadsBySegment as uls on UL.ID = uls.ID  JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE UD.User_Id ' + CASE WHEN (@ParentId > 0 AND @UserId = 0)  
    THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
   ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))  
   END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END ) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID join #userleadsBySegment as uls on UL.ID = uls.ID  LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = ' + cast(@ParentId AS NVARCHAR) + ' ) T where 1 = 1 ';  
  
 IF (ISNULL(@FilterText, '') <> '')  
 BEGIN  
  SET @Query1 = @Query1 + ' ' + @FilterText;  
 END  
  
 DECLARE @OrderBy NVARCHAR(max) = ' order by EndDate desc  '  
  
 -- declare @PaginScript nvarchar(max) = ' offset ' +str(@OffsetValue) +' rows fetch next ' + str(@PagingSize)+' rows only '          
 IF (@FilterText NOT LIKE '%order by%')  
 BEGIN  
  SET @Query1 = @Query1 + @OrderBy  
 END  
  
 DECLARE @Query2 NVARCHAR(max) = @Query + @Query1 --+ @PaginScript          
  
 PRINT @Query  
 PRINT @Query1  
  
 -- print @PaginScript          
 --print @Query2           
 EXECUTE sp_executesql @Query2  

   drop table if exists #userleadsBySegment 

END  



