CREATE   PROCEDURE [dbo].[usp_tsk_GetTaskHistoryListByUserId_WithScoreCard_WithSegmentation] 
	@FilterText VARCHAR(500),
	@UserId BIGINT,
	@Mode VARCHAR(20),
	@OffsetValue INT = 0,
	@PagingSize INT = 20,
	@CriteriaName nvarchar(500) = '' --null
AS
BEGIN
	
	set nocount on;

	declare @SPID bigint = isnull((select @@SPID),0)

	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID    

	--declare @FilterText VARCHAR(500) = N'   And (  OwnerName like ''31871-user13'' ) order by EndDate desc ',@UserId BIGINT = 31871,@Mode VARCHAR(20) = 'A',@OffsetValue int = 0,@PagingSize int = 20

