		  exec usp_tsk_GetTaskHistoryListByUserId_WithScoreCard @FilterText,@UserId,@Mode,@OffsetValue,@PagingSize   
		  return 
		  --goto XYZ;
		
		end

   --begin transaction  

     drop table if exists  #userleadsBySegment 


    declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)
    
	/*

   declare @ProcParam nvarchar(max) = N''' set nocount on;  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'+cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''
    WITH RESULT SETS
	(
	  (
		ID bigint
	  )
	)''' 
    
	*/


	-- print @ProcParam
	  
	  /*
      declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment  
     FROM  
      OPENROWSET(''sqlncli11'',''Server=10.0.0.132;Database=mysms_dev;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')' , ' ;  ' )  

	  */

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	  delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
	  declare @QueryTotality nvarchar(max) = ''


	 /*
	 declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment  
     FROM  
      OPENROWSET(''sqlncli11'',''Server=aznetpocdbs01;Database=mysms_dev;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')' )  

	  */

	DECLARE @RoleType VARCHAR(10);

	--declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))  
	DROP TABLE IF EXISTS #tbluser

		CREATE TABLE #tbluser (
			User_ID BIGINT
			,Name VARCHAR(100)
			,IMAGE VARCHAR(100)
			,ParentID BIGINT
			)

	DECLARE @IsAdmin BIT = 0

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	IF (@IsAdmin = 1)
	BEGIN
		SET @UserId = 0;

		--insert into @tbluser  
		INSERT INTO #tbluser
		EXEC usp_GetUserDetailWithParent @ParentId
	END
	ELSE
	BEGIN
		--insert into @tbluser  
		INSERT INTO #tbluser
		EXEC usp_GetUserDetailWithParent @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	-- select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
	--if(trim(@UserIdTeamLst) ='')  
	--begin  
	--set @UserIdTeamLst = cast(@UserId as nvarchar)  
	--end  
	--select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst, @UserLoginTeamLst  
	--select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser  
	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM #tbluser

	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history_latest(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentId

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	DECLARE @Query NVARCHAR(MAX) =  @QueryTotality  + ' ; ' + 
		N'SELECT  count(TaskHistoryId) over() as TotalRow, TaskHistoryId, LeadId, Title, Description, Address, StartDate, EndDate, STATUS, RelatedTo, RelatedToProfile, ParentID, AssignedTo, CreatedBy, CreatorName, UserId, CreatorName,IsTask, IsAppointment, OutcomesId, IsActive, CompletedOn, TaskId,  TotalAttachments, Remarks, CreatedOn, UpdatedOn, Collaboraters, OwnerName,  OutcomeName, IconClass, TaskStatus, CurrentScore, Profit_Loss, ThresholdColor,        hasEdit, hasView, hasRemove, hasCompletion, hasComment  FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId,  A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], concat(trim(U.FName), '' '', TRIM(U.LName), '' ('', U.User_Login, '')'') as [OwnerName], U.User_Login AS [UserLogin], UOM.OutcomeName, UTM.IconClass, (CASE WHEN LOWER(A.STATUS) = ''completed'' THEN ''Completed'' ELSE( CASE WHEN CAST(A.EndDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''Scheduled'' WHEN CAST(A.EndDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''Over Due'' ELSE ''Due Today'' END) END ) AS TaskStatus,  CAST(ISNULL((LS.currentscore / NULLIF(' 
		+ cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) AS [CurrentScore], (CASE WHEN LS.ScoreAdded > 0 THEN ''Green_Up'' WHEN LS.ScoreAdded < 0 THEN ''Red_Down'' ELSE '''' END ) AS [Profit_Loss], (CASE WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT) > ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Hot'' WHEN CAST(ISNULL((LS.currentscore / NULLIF(' + cast(@maxScore AS NVARCHAR(50)) + N', 0.00)) * 99, 0) AS INT ) BETWEEN ' + cast(@cold AS NVARCHAR(50)) + N' AND ' + cast(@warm AS NVARCHAR(50)) + N' THEN ''Warm'' ELSE ''Cold'' END ) AS [ThresholdColor], iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_edit, 0)) AS hasEdit, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_view, 1)) AS hasView, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_remove, 0)) AS hasRemove, iif( ' + cast(@iUserId AS NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_completion, 0)) AS hasCompletion, iif( ' + cast(@iUserId AS 
			NVARCHAR) + ' = A.AssignedTo, 1, ISNULL(tap.has_comment, 1)) AS hasComment FROM ( SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4  join #userleadsBySegment as uls on UL.ID = uls.ID  LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id ' + CASE 
			WHEN (
					@ParentId > 0
					AND @UserId = 0
					)
				THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
			ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))
			END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END  
    UNION'
	DECLARE @Query1 NVARCHAR(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 join #userleadsBySegment as uls on UL.ID = uls.ID LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id ' + CASE 
			WHEN (
					@ParentId > 0
					AND @UserId = 0
					)
				THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
			ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))
			END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END  
    UNION SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH join #userleadsBySegment as uls on TH.LeadID = uls.ID  JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE UD.User_Id ' + CASE 
			WHEN (
					@ParentId > 0
					AND @UserId = 0
					)
				THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
			ELSE ' = ' + CAST(@UserId AS NVARCHAR(MAX))
			END + ' AND IsActive = 1 AND TH.IsAppointment = CASE WHEN ''' + @Mode + N''' = ''A'' THEN 1 ELSE TH.IsAppointment END AND TH.IsTask = CASE WHEN ''' + @Mode + N''' = ''T'' THEN 1 ELSE TH.IsTask END ) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID  join #userleadsBySegment as uls on UL.ID = uls.ID  LEFT JOIN User_Detail(NOLOCK) U ON A.AssignedTo = U.User_ID LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = ' + cast(@ParentId AS NVARCHAR) + ' ) T where 1 = 1 ';

	IF (ISNULL(@FilterText, '') <> '')
	BEGIN
		SET @Query1 = @Query1 + ' ' + @FilterText;
	END

	DECLARE @OrderBy NVARCHAR(max) = ' order by EndDate desc  '
	DECLARE @PaginScript NVARCHAR(max) = ' offset ' + str(@OffsetValue) + ' rows fetch next ' + str(@PagingSize) + ' rows only '

	IF (@FilterText NOT LIKE '%order by%')
	BEGIN
		SET @Query1 = @Query1 + @OrderBy
	END

	DECLARE @Query2 NVARCHAR(max) = @Query + @Query1 + @PaginScript -- +  ' ; set nocount off ;'

	--PRINT @Query
	--PRINT @Query1
	--PRINT @PaginScript

	--print @Query2   
	EXECUTE sp_executesql @Query2

	DECLARE @Activity_type VARCHAR(max)

	IF @Mode = 'T'
	BEGIN
		SET @Activity_type = 'View_Task'
	END

	IF @Mode = 'A'
	BEGIN
		SET @Activity_type = 'View_Appoint'
	END

	
		--/*

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @iUserId
		,@Activity_type = @Activity_type
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_tsk_TaskHistory'

	--	*/
  --commit;  
   XYZ:
   
      delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
      drop table if exists  #userleadsBySegment 
   
   set nocount off;
end



