/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_tsk_GetTaskListByUserId
@UserId BIGINT
AS
BEGIN
	SELECT *, (
		CASE WHEN CAST( EndDate AS Date ) > CAST( GETDATE() AS Date )
			THEN 'Scheduled'
			WHEN CAST( EndDate AS Date ) < CAST( GETDATE() AS Date )
				THEN 'Over Due'
			ELSE
				'Due Today'
				END) AS 'TaskStatus'
		 FROM (
			SELECT TH.Id as [TaskHistoryId], TH.Title, TH.Description, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], (UD.FName + ' ' + UD.LName) as CreatorName, UD.ParentID, TH.CreatedBy, UD.User_Id
				FROM tbl_tsk_TaskHistory TH JOIN User_Detail UD ON TH.CreatedBy = UD.User_ID
				INNER JOIN UserLeads UL ON TH.LeadId = UL.ID
				WHERE TH.IsTask = 1
			UNION
			SELECT TH.Id as [TaskHistoryId], TH.Title, TH.Description, TH.StartDate, TH.EndDate, TH.Status, UL.PersonName as [RelatedTo], (UD.FName + ' ' + UD.LName) as CreatorName,  UD.ParentID, TH.CreatedBy, TCM.User_Id 
				FROM tbl_tsk_TaskHistory TH JOIN User_Detail UD ON TH.CreatedBy = UD.User_ID 
					INNER JOIN UserLeads UL ON TH.LeadId = UL.ID
					LEFT JOIN tbl_tsk_CollaborationUserMapping TCM ON TH.Id  = TCM.TaskHistoryId
				WHERE TH.IsTask = 1
						-- AND  TCM.DeletedOn is NULL
	) A WHERE A.User_ID = @UserId
END


GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_GetTaskOutcomeByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tsk_GetTaskOutcomeByUserId](  
	@ParentId bigint  
)  
as  
begin  
  
	--declare @ParentId bigint  = 41187  

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @ParentId
  
	select * from (  
	SELECT 0 as [TaskId], id as OutcomesId, OutcomeName, Indent, id as [Sequence], 0 as ParentId from tbl_tsk_UserOutcomeMaster(nolock) uom  where ParentId = 0 and IsPredefined = 1    
	union  
	SELECT tom.TaskId as [TaskId], OutcomesId, OutcomeName, Indent, [Sequence],tom.ParentId from tbl_tsk_UserOutcomeMaster(nolock) uom   
		left join tbl_tsk_TaskOutcomeMapping(nolock) tom  ON tom.OutcomesId = UOM.Id        
		where    
	TOM.ParentId = @ParentId  
	) t order by [Sequence] asc  
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_tsk_InsertReminder]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_tsk_InsertReminder]  
@TaskHistoryId BIGINT  
AS  
BEGIN  
 DECLARE @MobileNos nvarchar(max) = '', @batchid BIGINT  
  SELECT @MobileNos = COALESCE(@MobileNos + ',', '') + STR(Mobile)      
    FROM User_Detail(nolock) where user_id in (SELECT AssignedTo AS UserId FROM tbl_tsk_TaskHistory where Id = @TaskHistoryId  
   UNION  
   select USER_ID  AS UserId from tbl_tsk_CollaborationUserMapping where TaskHistoryId = @TaskHistoryId  
 )  
  
 IF(EXISTS(SELECT 1 FROM tbl_tsk_TaskHistory where Id = @TaskHistoryId AND SmsBatchId IS NOT NULL))  
  BEGIN  
   SELECT top 1 @batchid = BatchId FROM tbl_tsk_CollaborationUserMapping where Id = @TaskHistoryId AND BatchId IS NOT NULL  
   EXEC usp_DeleteScheduledMessages @batchid  
  END  
 --[usp_sendscheduledmessage]    
 declare @u_id bigint,  @message nvarchar(2500), @sender nvarchar(6), @isunicode int=0, @priority int=2, @scheduleddate datetime=null, @LeadId bigint, @subject varchar(100)  
  
 SELECT Top 1 @u_id = ud.ParentID FROM User_Detail(nolock) ud join tbl_tsk_TaskHistory tc on ud.User_ID = tc.CreatedBy where tc.Id = @TaskHistoryId   
  
 SELECT @LeadId = tc.leadid, @message =   
 'Reminder: Your '+    
 case when tc.isappointment=1 then 'Appointment ' else 'Task ' end +   
 'titled "'+ tc.Title +  
 '" with '+ud.PersonName+  
 ' is scheduled for '+   
 cast(case when isappointment=1 then tc.StartDate else tc.EndDate end as nvarchar) +   
 case when isappointment=1 then isnull(' at '+ tc.CompleteAddress,'') else '' end   
 from Userleads(nolock) ud join tbl_tsk_TaskHistory tc on ud.ID = tc.LeadId  
  
 select top 1 @sender=Sender_Name from Default_SenderID where user_id=@u_id   
  
 declare @IsSMSReminder int , @IsMailReminder int  
  
 select top 1 @scheduleddate=Schedule, @IsSMSReminder = IsSMS, @IsMailReminder = IsEmail from tbl_tsk_Reminder t join tbl_tsk_CollaborationUserMapping tc  
 on t.CollaborationUserMappingId=tc.Id where tc.TaskHistoryId=@TaskHistoryId  
  
  
 declare @totalMobileNo int = 0, @smsbal bigint  
  
 SELECT @totalMobileNo = COUNT(*) FROM (  
  SELECT AssignedTo AS UserId FROM tbl_tsk_TaskHistory where Id = @TaskHistoryId  
  UNION  
  SELECT USER_ID  AS UserId from tbl_tsk_CollaborationUserMapping where TaskHistoryId = @TaskHistoryId  
 ) A  
  
 select @smsbal = dbo.fn_GetSMSBalance(@u_id)  
  
 IF(@totalMobileNo<=@smsbal and @IsSMSReminder = 1)  
 BEGIN  
  declare @batchIdnew bigint  
    
  exec [usp_sendscheduledmessage_returnBatchId] @u_id, @message, @MobileNos, @sender, @isunicode, @priority, @scheduleddate, @LeadId, @batchIdnew output  
  
  UPDATE tbl_tsk_TaskHistory  
   SET SmsBatchId = @batchIdnew  
    where Id = @TaskHistoryId  
 END  
  
  
 IF(@IsMailReminder = 1)  
 BEGIN  
  DECLARE @ToEmailID varchar(max), @type varchar(100) = '1'     
  
  SELECT  EMail, 0 AS IsProcessed   INTO #tempMobileIds  
    FROM  User_Detail(nolock) where user_id in (  
   SELECT AssignedTo AS UserId FROM tbl_tsk_TaskHistory where Id = @TaskHistoryId  
    UNION  
   select USER_ID  AS UserId from tbl_tsk_CollaborationUserMapping where TaskHistoryId = @TaskHistoryId  
  )  
  
  DECLARE @mailbal bigint, @TotalEmailIds BIGINT = 0  
  SELECT @mailbal = dbo.fn_GetMailBalance(@u_id)  
  
  SELECT @TotalEmailIds = COUNT(*) FROM #tempMobileIds  
  
  IF(@mailbal>= @TotalEmailIds)  
  BEGIN  
   WHILE EXISTS(SELECT * FROM #tempMobileIds where IsProcessed = 0)  
    BEGIN  
     DECLARE @EmailId VARCHAR(MAX), @SchTime varchar(10)=''  
     SELECT @EmailId = EMail FROM #tempMobileIds where IsProcessed = 0  
     Select @SchTime = CONVERT(VARCHAR, @scheduleddate, 108)  
     exec [usp_SendScheduledEmailNotification] @u_id, @message, @subject, @EmailId, @scheduleddate, @SchTime, @type   
       
     UPDATE #tempMobileIds SET IsProcessed = 1  WHERE EMail = @EmailId  
    END  
   DROP TABLE #tempMobileIds  
  END  



 END  

  --Sending notification to connected email id
  exec usp_em_SendAssignedTaskNotification @TaskHistoryId
END  
  


GO

