CREATE   PROCEDURE usp_ttc_ExistsDomainName
@Id bigint = 0,
@domainName nvarchar(500) = NULL
as
begin

if(@Id = 0)
	begin
		select * from tbl_ttc_ClientDetails where DomainName = @domainName
	end
else
	begin
		if(exists(select * from tbl_ttc_ClientDetails where Id = @Id and DomainName = @domainName))
		begin
			select * from tbl_ttc_ClientDetails  where Id < 0
		end
		else
		begin
			select * from tbl_ttc_ClientDetails where DomainName = @domainName
		end
	end
end



