/* ============================================================
   Procedure: [dbo].[usp_ttc_GenerateEnquiryAutomatically]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ttc_GenerateEnquiryAutomatically](  
	@PrechatFormDataId bigint  
)  
as  
begin  
 --declare @PrechatFormDataId bigint = 1002  
  
 declare @PrechatFormJson nvarchar(max) = '', @TtcClientId bigint = 0, @ParentId bigint = 0, @SourceCode bigint = 0,   
  @MediumCode BIGINT, @CampaignCode BIGINT, @PropertyName nvarchar(255) =  '', @SourceName nvarchar(255)  
  
 select @PrechatFormJson = PrechatFormJson, @TtcClientId = TtcClientId from tbl_ttc_PrechatFormData(nolock) where Id  = @PrechatFormDataId  
 select @ParentId = ParentId, @PropertyName = TawkTo_PropertyName from tbl_ttc_ClientDetails(nolock) where Id = @TtcClientId  
  
 select @PrechatFormJson  
  
 if(ISNULL(@PrechatFormJson, '') <> '' and @ParentId = 43823 )  
 begin  
 

  select @SourceCode = SourceID from UserSourceSettings(nolock) where UserID = @ParentId and Name = ( case @PropertyName  
   when 'Helpline Translation' then 'helplinetranslation.com'  
   when 'helplineconsulting.com' then 'helplineconsulting.com' 
   when 'newexactsolutions' then 'newexactsolutions.co'  
   when 'qatardocumentservices.com' then 'qatardocumentservices.com'  
   when 'qatarhelplinegroup.com' then 'qatarhelplinegroup.com'  
   else 'newexactsolutions.co' end )  
  
  select top 1 @MediumCode = MediumID from UserMediumSettings(nolock)   
   where Name = 'TawkTO' and UserID = @ParentId order by MediumID desc  
  
  select @CampaignCode = CampaignID from UserCampaignSettings(nolock)   
   where Name = 'TawkTO' and UserID = @ParentId  order by CampaignID desc  
    
  declare @fbLeadEnquiry as fbLeadEnquiry  
  
  insert into @fbLeadEnquiry(Id, colName, colValue)  
  select row_number() over (partition by  (select null) order by (select null) asc),  
  (case labelName   
   when 'Name' then  'PersonName'  
   when 'Email' then  'EmailID'  
   when 'Phone' then  'MobileNo'  
   when 'Location' then  'City'  
   when 'Message' then  'InitialRemarks'  
   when 'Enquiry' then  'InitialRemarks'  
   when 'Services' then  'Which_service_you_prefer'  
  end ), labelValue  
  from openjson(@PrechatFormJson) with (  
   labelName nvarchar(max) '$.label',  
   labelValue nvarchar(max) '$.answer'  
  )  
  select *  from  @fbLeadEnquiry  
  
  
  exec usp_TawToPrechatToEnquiry   
     @ModifiedLead = @fbLeadEnquiry,  
     @SourceCode = @SourceCode,  
     @MediumCode = @MediumCode,   
     @CampaignCode = @CampaignCode,  
     @ParentId = @ParentId,  
     @PrechatAutoId = @PrechatFormDataId  
  
  -- reset all declared variables  
  select @SourceCode = N'', @MediumCode = N'0', @CampaignCode = N'0'  
  
 end  
end  


GO

