/* ============================================================
   Procedure: [dbo].[usp_ttc_GetClientDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ttc_GetClientDetails @UserId BIGINT
AS
BEGIN
	DECLARE @_parentId BIGINT;

	SET @_parentId = (
			SELECT ParentId
			FROM User_Detail
			WHERE User_ID = @UserId
			);

	DECLARE @sqlQuery NVARCHAR(MAX) = '';

	SET @sqlQuery = N'SELECT cd.Id, cd.TawkTo_PropertyId, cd.TawkTo_PropertyName, cd.DomainName, cd.IsActive, cd.SavePrechatForm, cd.SaveChatData , cd.ParentId
 FROM tbl_ttc_ClientDetails cd where cd.ParentId = ' + CAST(@_parentId AS NVARCHAR) + ' and cd.IsDeleted = 0'

	PRINT @sqlQuery

	EXECUTE sp_executesql @sqlQuery;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_TwkTo_Intg'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_ttc_ClientDetails'
END



GO

