/* ============================================================
   Procedure: [dbo].[usp_ttc_GetLeadByClientId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ttc_GetLeadByClientId(  
 @UserId     BIGINT=34594,   
 @FilterText NVARCHAR(MAX) = '',   
 @OffsetValue INT    = 0,   
 @PagingSize  INT    = 10  
)  
AS  
    BEGIN 
	--declare @UserId     BIGINT=34594,   
 --@FilterText NVARCHAR(MAX) = '',   
 --@OffsetValue INT    = 0,   
 --@PagingSize  INT    = 10  
        DECLARE @_parentId BIGINT;  
        SET @_parentId =  
        (  
            SELECT ParentId  
            FROM User_Detail  
            WHERE User_ID = @UserId  
        );  
        DECLARE @sqlQuery NVARCHAR(MAX)= '';  
        SET @sqlQuery = N'SELECT count(id)
 over() as TotalRow, * FROM ( SELECT pfd.Id, pfd.TtcClientId , cd.TawkTo_PropertyId , cd.TawkTo_PropertyName , cd.DomainName , pfd.PreChatFormJson , pfd.IsProcessed , pfd.Reason , pfd.EnquiryId , Format(pfd.CreatedOn,''dd-MMM-yyyy HH:mm:ss'') CreatedOn, pfd.ProcessedOn , pfd.VisitorId , pfd.[Status] , ue.PersonName , ue.ProfileImgFileName , ue.InitialRemarks , cd.parentid , pfd.Id AS [PrechatAutoId]  
        FROM tbl_ttc_PrechatFormData AS pfd   
         LEFT JOIN tbl_ttc_ClientDetails AS cd ON pfd.TtcClientId = cd.Id  
         LEFT OUTER JOIN userenquiry AS ue ON ue.enquiryid = pfd.enquiryid  
   ) AS a WHERE ParentId = ' + STR(@_parentId);  
        IF(@FilterText = '')  
            BEGIN  
                SET @sqlQuery = @sqlQuery + ' ORDER BY CreatedOn DESC ';  
        END;  
            ELSE  
            BEGIN  
                SET @sqlQuery = @sqlQuery + '   ' + @FilterText + ' ORDER BY CreatedOn DESC  ';  
        END;  
  
  set @sqlQuery = @sqlQuery + ' OFFSET ' + str(@OffsetValue) + ' ROWS FETCH NEXT ' + str(@PagingSize) + ' ROWS ONLY '   
  
        PRINT @sqlQuery;  
        EXECUTE sp_executesql   
                @sqlQuery;  
    END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_ttc_GetPrechatDetailsByPrechatId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ttc_GetPrechatDetailsByPrechatId]
@PrechatAutoId BIGINT

AS
BEGIN
	DECLARE @_visitorId NVARCHAR(100)

	SET @_visitorId = (SELECT VisitorId FROM tbl_ttc_PrechatFormData WHERE Id = @PrechatAutoId)
	DECLARE @sqlQuery NVARCHAR(MAX)= '';

	SET @sqlQuery = N'SELECT  distinct (SELECT string_agg(chathtml, '''') FROM tbl_ttc_ChatHistories WHERE VisitorId = ''' + CAST(@_visitorId AS NVARCHAR) + ''') AS ChatHtml, pfd.TtcClientId, pfd.PreChatFormJson  FROM tbl_ttc_PrechatFormData pfd 
	inner join tbl_ttc_ChatHistories ch ON pfd.VisitorId = ch.visitorid WHERE pfd.VisitorId = ''' + CAST(@_visitorId AS NVARCHAR) + ''''
	PRINT @sqlQuery      
      
    EXECUTE sp_executesql @sqlQuery;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ttc_InsertChatHistories]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ttc_InsertChatHistories  
@ClientCode varchar(255) = Null,  
@ChatHtml nvarchar(max) = NULL,  
@VisitorId nvarchar(255) = NULL,
@SessionId nvarchar(255) = NULL
AS  
BEGIN  
Declare @ClientId bigint;  
set @ClientId = (SELECT id FROM tbl_ttc_ClientDetails where ClientCode = @ClientCode);  
  
if not exists (SELECT * FROM tbl_ttc_ChatHistories where VisitorId = @VisitorId and SessionId = @SessionId)  
 BEGIN  
	 INSERT INTO tbl_ttc_ChatHistories(TtcClientId, ChatHtml, VisitorId, SessionId) VALUES (@ClientId, @ChatHtml, @VisitorId, @SessionId)  
 END  
else
	 Begin  
		Update tbl_ttc_ChatHistories set ChatHtml = concat((SELECT ChatHtml FROM tbl_ttc_ChatHistories where VisitorId = @VisitorId and SessionId = @SessionId),' ', @ChatHtml),   ChatEndTime = getdate() where VisitorId = @VisitorId and SessionId = @SessionId
	 end  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_ttc_InsertClientDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ttc_InsertClientDetails] (
	@Id BIGINT = 0,    
	@UserId BIGINT = 0 ,   
	@TawkTo_PropertyId NVARCHAR(500) = '' ,   
	@TawkTo_PropertyName NVARCHAR(500) = '',
	@TawkTo_WidgetId NVARCHAR(500) = 'default',
	@IsActive BIT = 1 ,   
	@IsIntegrated BIT = 0  ,  
	@DomainName NVARCHAR(500) = NULL   , 
	@savePrechatForm BIT = 1,    
	@saveChatData BIT = 1 
)
AS    
BEGIN    
 DECLARE @_parentid BIGINT;    
    
 SET @_parentId = (    
   SELECT ParentId    
   FROM User_Detail    
   WHERE User_ID = @UserId    
   );    
    
 DECLARE @_clientcode NVARCHAR(255);    
    
 SET @_clientcode = (REPLACE(Lower(NEWID()), '-', ''));    
    
 IF (@Id = 0)    
 BEGIN    
  INSERT INTO tbl_ttc_ClientDetails ( TawkTo_PropertyId, TawkTo_PropertyName, IsActive, IsIntegrated, 
	DomainName, ParentId, ClientCode, CreatedOn, savePrechatForm, saveChatData, CreatedBy, WidgetId )    
  VALUES (@TawkTo_PropertyId, @TawkTo_PropertyName, @IsActive, @IsIntegrated, @DomainName, @_parentId, @_clientcode, GETDATE(), @savePrechatForm, @saveChatData, @UserId, @TawkTo_WidgetId )    
    
  SET @Id = SCOPE_IDENTITY();    
    
  SELECT @_clientcode    
    
  DECLARE @rowJson NVARCHAR(MAX) = (    
    SELECT *    
    FROM tbl_ttc_ClientDetails(NOLOCK)    
    WHERE Id = @Id    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
    
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Inst_TwkTo_Intg'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_ttc_ClientDetails'    
 END    
 ELSE    
 BEGIN    
  UPDATE tbl_ttc_ClientDetails    
  SET TawkTo_PropertyId = IIF(ISNULL(@TawkTo_PropertyId, '') = '', TawkTo_PropertyId, @TawkTo_PropertyId)    
   ,TawkTo_PropertyName = IIF(ISNULL(@TawkTo_PropertyName, '') = '', TawkTo_PropertyName, @TawkTo_PropertyName)    
   ,WidgetId = IIF(ISNULL(@TawkTo_WidgetId, '') = '', WidgetId, @TawkTo_WidgetId)    
   ,IsActive = IsActive    
   ,IsIntegrated = @IsIntegrated    
   ,DomainName = IIF(ISNULL(@DomainName, '') = '', DomainName, @DomainName)    
   ,UpdatedOn = getdate()    
   ,savePrechatForm = @savePrechatForm    
   ,saveChatData = @saveChatData    
   ,CreatedBy = @UserId    
  WHERE Id = @Id    
    
  SELECT ClientCode    
  FROM tbl_ttc_ClientDetails(NOLOCK)    
  WHERE Id = @Id    
    
  SET @rowJson = (    
    SELECT *    
    FROM tbl_ttc_ClientDetails(NOLOCK)    
    WHERE Id = @Id    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
    
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Updt_TwkTo_Intg'    
   ,@ActionType = 'U'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_ttc_ClientDetails'    
 END    
END 



