/* ============================================================
   Procedure: [dbo].[usp_ttc_InsertPrechatFormData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ttc_InsertPrechatFormData
	 @ClientCode varchar(255) = NULL,      
	 @PrechatFormJson nvarchar(MAX) = NULL,      
	 @IsProcessed nvarchar(10) = NULL,      
	 @Reason nvarchar(max) = NULL,      
	 @EnquiryId bigint = 0,      
	 @ProcessedOn datetime = NULL,      
	 @VisitorId nvarchar(255) = NULL,      
	 @Status nvarchar(100) = NULL 
AS      
BEGIN      
	declare  @ClientId bigint;    
	select @ClientId = id from tbl_ttc_ClientDetails where ClientCode = @ClientCode
 
	declare @PrechatFormDataId bigint 

	if(exists(select 1 from tbl_ttc_PrechatFormData(nolock) where VisitorId = @VisitorId and TtcClientId = @ClientId))
		begin
			select @PrechatFormDataId = id from tbl_ttc_PrechatFormData(nolock) where VisitorId = @VisitorId and TtcClientId = @ClientId
			update tbl_ttc_PrechatFormData set
				PrechatFormJson = @PrechatFormJson,
				Reason = @Reason,
				Status = @Status,
				ModifiedOn = getdate()
			where Id = @PrechatFormDataId
		end
		else
		begin
			insert into tbl_ttc_PrechatFormData(TtcClientId, PrechatFormJson, IsProcessed, Reason, EnquiryId, ProcessedOn, VisitorId, Status)      
			values (@ClientId, @PrechatFormJson, @IsProcessed, @Reason, @EnquiryId, @ProcessedOn, @VisitorId, @Status)   
		select @PrechatFormDataId = scope_identity();  
	end
      

	 if not exists (select TtcClientId from tbl_ttc_PlugInActivity where TtcClientId = @ClientId)      
	 begin      
		  insert into tbl_ttc_PlugInActivity (TtcClientId, IntegratedOn, FirstCallOn, LastCallon, CallCount)      
		  values (@ClientId, GETDATE(), GETDATE(), GETDATE(), 1)      
     
	 end      
	 if exists (select TtcClientId from tbl_ttc_PlugInActivity where   TtcClientId = @ClientId)      
	 Begin      
			 update tbl_ttc_PlugInActivity set LastCallon = GETDATE(),       
			 CallCount = (select CallCount from tbl_ttc_PlugInActivity where (TtcClientId = @ClientId)) + 1      
	 End     
   
	 if(ISNULL(@PrechatFormDataId, 0) > 0 and LEN(@PrechatFormJson) > 2)  
	 begin  
		 exec usp_ttc_GenerateEnquiryAutomatically @PrechatFormDataId  
	 end  
END



GO

