/* ============================================================
   Procedure: [dbo].[usp_ttc_SaveTawkToFeildMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- DROP TYPE TawkToMapping    
-- DROP PROCEDURE usp_ttc_SaveTawkToFeildMapping    
--CREATE TYPE TawkToMapping AS TABLE    
--(     
--  Id INT, TtcFieldName nvarchar(1000), EnFieldName nvarchar(1000), DefaultValue nvarchar(1000), IsProccessed bit DEFAULT 0    
--);    
--GO    
CREATE   PROCEDURE dbo.usp_ttc_SaveTawkToFeildMapping @TawkToMapping tawktomapping readonly    
 ,@TtcClientId BIGINT    
 ,@ParentId BIGINT    
 ,@CreatedBy BIGINT    
AS    
BEGIN    
 DECLARE @Id INT;    
    
 IF OBJECT_ID('tempdb..#tempTawkToMapping') = NULL    
 BEGIN    
  DROP TABLE #tempTawkToMapping    
 END    
    
 SELECT *    
 INTO #tempTawkToMapping    
 FROM @TawkToMapping    
    
 IF (    
   EXISTS (    
    SELECT 1    
    FROM #tempTawkToMapping    
    )    
   )    
 BEGIN    
  IF (    
    EXISTS (    
     SELECT 1    
     FROM tbl_ttc_FormFieldMapping    
     WHERE ParentId = @ParentId    
      AND TtcClientId = @TtcClientId    
     )    
    )    
  BEGIN    
   DECLARE @DeletedRow NVARCHAR(max) = (    
     SELECT *    
     FROM tbl_ttc_FormFieldMapping    
     WHERE ParentId = @ParentId    
      AND TtcClientId = @TtcClientId    
     FOR JSON AUTO    
     );    
    
   IF (ISNULL(@DeletedRow, '') <> '')    
   BEGIN    
    INSERT INTO tbl_mk_RecordHistory (    
     Action    
     ,RecordJson    
     ,TableName    
     ,User_Id    
     ,ActionDate    
     )    
    VALUES (    
     'D'    
     ,@DeletedRow    
     ,'tbl_ttc_FormFieldMapping'    
     ,@CreatedBy    
     ,GETDATE()    
     )    
    
    DELETE    
    FROM tbl_ttc_FormFieldMapping    
    WHERE ParentId = @ParentId    
     AND TtcClientId = @TtcClientId    
   END    
  END    
    
  WHILE (    
    EXISTS (    
     SELECT 1    
     FROM #tempTawkToMapping    
     WHERE IsProccessed = 0    
     )    
    )    
  BEGIN    
   SELECT TOP 1 @Id = Id    
   FROM #tempTawkToMapping    
   WHERE IsProccessed = 0;    
    
   INSERT INTO tbl_ttc_FormFieldMapping (    
    TtcFieldName    
    ,EnFieldName    
    ,CreatedOn    
    ,ParentId    
    ,DefaultValue    
    ,TtcClientId    
    ,CreatedBy    
    )    
   SELECT TtcFieldName    
    ,EnFieldName    
    ,GETDATE()    
    ,@ParentId    
    ,DefaultValue    
    ,@TtcClientId    
    ,@CreatedBy    
   FROM #tempTawkToMapping    
   WHERE Id = @Id;    
    
   UPDATE #tempTawkToMapping    
   SET IsProccessed = 1    
   WHERE Id = @Id;    
  END;    
    
  DECLARE @InsertedRow NVARCHAR(max) = (    
    SELECT *    
    FROM tbl_ttc_FormFieldMapping(NOLOCK)    
    WHERE ParentId = @ParentId    
     AND TtcClientId = @TtcClientId    
    FOR JSON AUTO    
    );    
    
  IF (ISNULL(@InsertedRow, '') <> '')    
  BEGIN    
   INSERT INTO tbl_mk_RecordHistory (    
    Action    
    ,RecordJson    
    ,TableName    
    ,User_Id    
    ,ActionDate    
    )    
   VALUES (    
    'I'    
    ,@InsertedRow    
    ,'tbl_ttc_FormFieldMapping'    
    ,@CreatedBy    
    ,GETDATE()    
    )    
  END    
 END    
    
  DECLARE @rowJson NVARCHAR(max) = (    
    SELECT *    
    FROM tbl_ttc_FormFieldMapping(NOLOCK)    
    WHERE ParentId = @ParentId    
     AND TtcClientId = @TtcClientId    
    FOR JSON AUTO    
    );    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy    
  ,@Activity_type = 'Inst_TawkTo_fdmppng'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_ttc_FormFieldMapping'    
END; 


GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByModuleCodeUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-----------------------------------------------------

CREATE   PROCEDURE [dbo].[usp_UA_GetAllPermissionByModuleCodeUserId]        
(                              
 @Mode varchar(2),                              
 @ModuleCode varchar(50) = null,                              
 @UserId bigint = 0                              
)                            
AS        
BEGIN        
     
SET NOCOUNT ON                                
BEGIN TRY                                
 --Declare @Mode varchar(2) = 'S',@ModuleCode varchar(50) = 'PAG10267',@UserId bigint = 32222      
 --Declare @Mode varchar(2) = 'S',@ModuleCode varchar(50) = 'PAG10234',@UserId bigint = 49830      
     
 drop table if exists #tbl_Permission1      
 drop table if exists #tbl_Permission2      
 drop table if exists #tbl_Permission3      
 drop table if exists #tbl_Permission4      
           
 if(@Mode = 'S')                            
 Begin      
    Declare @ParentId bigint = 0                            
    Declare @IsAdmin int = 0, @RowCnt int=0, @Url nvarchar(max), @ModuleName varchar(50)      
    Declare @ScopeCode varchar(10) = ''                            
    Declare @IsExpired bit = 1                            
    Declare @RoleCode varchar(10) = ''                            
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail(nolock) where User_Id = @UserId                            
                           
    select @IsExpired = 0      
 from Price_UserSubscriptionDetails(nolock)      
 where IsNewPlan = 1 and Userid = @ParentID      
    and Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                            
                       
 SELECT @ScopeCode = turpm.ScopeCode, @RoleCode = turpm.RoleCode          
 FROM TBL_UA_UserRoleMappingMaster(nolock) urmp INNER JOIN VW_SystemRole_RoleMaster(nolock) urmm      
 ON urmm.RoleCode = urmp.RoleCode INNER JOIN TBL_UA_RolePermissionMappingMaster(nolock) turpm      
 ON turpm.RoleCode = urmp.RoleCode LEFT JOIN TBL_UA_TeamUserMappingMaster(nolock) utumm          
 ON utumm.UserId = urmp.UserId LEFT JOIN TBL_UA_TeamMaster(nolock) uatm          
 ON uatm.TeamCode = utumm.TeamCode LEFT JOIN TBL_UA_ModuleMaster(nolock) umod          
 ON umod.ModuleCode = turpm.ModuleCode          
 WHERE urmp.UserId = @UserId OR utumm.UserId = @UserId;                      
 -- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode      
                       
 if(@ScopeCode = '' or @IsExpired = 1)                          
    Begin                        
  set @ScopeCode = 'USER'                                
    End                          
           
 if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                          
    Begin                        
  set @ScopeCode = 'TEAM'                                
    End                          
                       
 if((@RoleCode = '') and (@IsExpired = 0))                              
    Begin                                
  set @RoleCode = 'SYS_USER'                                
    End                                
 else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                              
    Begin                      
  set @RoleCode = 'SYS_GUEST'                                
    End                        
       
 print '@ModuleCode: ' + @ModuleCode          
 print '@ParentId: ' + cast(@ParentId as varchar)          
 print '@IsAdmin: ' + cast(@IsAdmin  as varchar)          
 print '@IsExpired: ' + cast(@IsExpired as varchar)          
 print '@ScopeCode: ' + @ScopeCode          
 print '@RoleCode: ' + @RoleCode          
                           
 if(@UserId = 335)                            
 Begin                            
  print '335'        
     
  select top 1 @UserId UserId, @ParentId ParentId,                            
  '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                            
  turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete],      
  1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1, 1 Standard2,      
  1 Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment,      
  1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2, 1 Special3,      
  1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument,      
  1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice, 1 AddWebform,      
  1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast, turpm.Type,      
  '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode,      
  turpm.URL      
  into #tbl_Permission1      
  from TBL_UA_ModuleMaster(nolock) turpm        
  where ModuleCode = @ModuleCode      
     
  Select @RowCnt=@@ROWCOUNT      
       
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission1      
     
  Select * From #tbl_Permission1      
 End                        
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '') and Not Exists (select distinct 1      
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm      
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm      
  on turpm.RoleCode = urmp.RoleCode   left join TBL_UA_TeamUserMappingMaster(nolock) utumm      
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm      
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod      
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                    
 Begin                            
  print 'A'      
     
  select top 1 *      
  into #tbl_Permission2      
  from (                      
  select @UserId UserId, @ParentId ParentId, '' TeamCode, '' TeamName, '' RoleCode,      
  '' RoleName, turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View],      
  1 [Delete], 1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1,      
  --CASE WHEN @UserId = 34594 THEN 1 ELSE 0 END AS Standard2
  --CASE WHEN @UserId IN (34594, 32222) THEN 1 ELSE 0 END AS Standard2
  1 Standard2
  , 1 Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 1 AddTask,      
  1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2,      
  1 Special3, 1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp,      
  1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice,      
  1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,      
  turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode,      
  '' EntitySpAction2MappingCode, IsInternal, turpm.URL      
  from TBL_UA_ModuleMaster(nolock) turpm) t      
  where t.ModuleCode = @ModuleCode and t.IsInternal = 0                      
     
  Select @RowCnt=@@ROWCOUNT      
       
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission2      
     
  Select * From #tbl_Permission2      
 End                    
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1      
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm      
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm      
  on turpm.RoleCode = urmp.RoleCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm      
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm      
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod      
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                            
 Begin                      
  --Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish                        
  print 'B'          
     
  select top 1 *      
  into #tbl_Permission3      
  from (      
  Select urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode,      
    urmm.RoleName, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, [Add], Edit,      
    [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,      
    Standard2, Standard3, Standard4, Standard5, Download, [Print], AddTask,      
    AddAppointment, AddFollowup, AddNote, SendSms, SendMail, 1 Special1, Special2,      
    Special3, Special4, Special5, SendVoice, MergeLead, SendWhatsapp, UploadDocument,      
    DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform,      
    AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type,      
    turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode,      
    tueams2.EntitySpAction2MappingCode, umod.URL      
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm      
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm      
  on turpm.RoleCode = urmp.RoleCode inner join TBL_UA_EntityActionMappingMaster(nolock) tueam      
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams      
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2      
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm      
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm      
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod      
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)t where t.UserId = @UserId and t.ParentId = @ParentId      
     
  Select @RowCnt=@@ROWCOUNT      
       
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission3      
     
  Select * From #tbl_Permission3      
 End                    
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST')))                            
 Begin          
  Print 'C'          
     
  if not Exists(select 1 from TBL_UA_RolePermissionMappingMaster turpm (nolock) inner join TBL_UA_EntityActionMappingMaster(nolock) tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock
 
   
) tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode      
    where turpm.ParentId = @ParentId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)      
  Begin            
   Print 'D'          
   set @ParentId = 335                                
  End            
  --  set @RoleCode = 'SYS_USER'      
  --  set @ModuleCode = 'PAG10002'      
  --select 'SYS_USER, SYS_Guest'      
       
  select top 1  @UserId UserId,    '' TeamCode, '' TeamName, '' RoleName, turpm.ParentId, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,Standard2, Standard3, Standard4, Standard5,  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail, 1 Special1, Special2, Special3, Special4, Special5, SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode, umod.URL      
  into #tbl_Permission4      
  from TBL_UA_RolePermissionMappingMaster turpm (nolock)                            
   --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode      
    inner join TBL_UA_EntityActionMappingMaster(nolock) tueam      
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams      
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2      
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_ModuleMaster(nolock) umod      
  on umod.ModuleCode = turpm.ModuleCode      
  where turpm.ParentId = @ParentId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode      
     
  Select @RowCnt=@@ROWCOUNT      
       
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission4      
     
  Select * From #tbl_Permission4      
       
 End      
     
 If(@RowCnt>0)      
 Begin      
  Select @Url=concat(N'{"url":"',@Url,N'","page":"',@ModuleName,'"}')      
     
     EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData        
     @User_id = @UserId,          
     @Activity_type = 'VIEW_PAGE',          
     @ActionType = 'S',          
     @RowJson = @Url,          
     @Table_name = '',          
     @ip_adress = '',          
     @device_id = '',          
     @IsImpersonation = 0,          
     @ImpersonatorId = 0;      
 End      
     
  End            
             
END TRY          
BEGIN CATCH            
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH            
     
END 

------------------------------



GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByModuleCodeUserId$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




-- exec usp_UA_GetAllPermissionByModuleCodeUserId @Mode='S',@ModuleCode='PAG10267',@UserId=42735   
CREATE   PROCEDURE [dbo].[usp_UA_GetAllPermissionByModuleCodeUserId$]    
(                          
 @Mode varchar(2),                           
 @ModuleCode varchar(50) = null,                          
 @UserId bigint = 0                           
)                        
AS    
BEGIN    
  SET NOCOUNT ON                           
  BEGIN TRY                           
-- Declare @Mode varchar(2) = 'S',@ModuleCode varchar(50) = 'PAG10267z',@UserId bigint = 32222    
      
 if(@Mode = 'S')                      
  Begin    
    Declare @ParentId bigint = 0                       
    Declare @IsAdmin int = 0                       
    Declare @ScopeCode varchar(10) = ''                       
    Declare @IsExpired bit = 1                      
    Declare @RoleCode varchar(10) = ''                      
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail(nolock) where User_Id = @UserId                       
                      
    select @IsExpired = 0 from Price_UserSubscriptionDetails(nolock) where IsNewPlan = 1 and Userid = @ParentID and                       
    Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                       
                  
 SELECT @ScopeCode = turpm.ScopeCode, @RoleCode = turpm.RoleCode    
 FROM TBL_UA_UserRoleMappingMaster urmp INNER JOIN VW_SystemRole_RoleMaster urmm     
 ON urmm.RoleCode = urmp.RoleCode INNER JOIN TBL_UA_RolePermissionMappingMaster turpm     
 ON turpm.RoleCode = urmp.RoleCode LEFT JOIN TBL_UA_TeamUserMappingMaster utumm     
 ON utumm.UserId = urmp.UserId LEFT JOIN TBL_UA_TeamMaster uatm     
 ON uatm.TeamCode = utumm.TeamCode LEFT JOIN TBL_UA_ModuleMaster umod     
 ON umod.ModuleCode = turpm.ModuleCode    
 WHERE urmp.UserId = @UserId OR utumm.UserId = @UserId;                
 -- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode                     
                 
 if(@ScopeCode = '' or @IsExpired = 1)                    
    Begin                  
    set @ScopeCode = 'USER'                           
    End                     
     
 if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                    
    Begin                  
    set @ScopeCode = 'TEAM'                           
    End                     
                  
 if((@RoleCode = '') and (@IsExpired = 0))                         
    Begin                           
    set @RoleCode = 'SYS_USER'                           
    End                           
 else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                        
    Begin                
    set @RoleCode = 'SYS_GUEST'                           
    End                  
 print '@ModuleCode: ' + @ModuleCode     
 print '@ParentId: ' + cast(@ParentId as varchar)    
 print '@IsAdmin: ' + cast(@IsAdmin  as varchar)    
 print '@IsExpired: ' + cast(@IsExpired as varchar)    
 print '@ScopeCode: ' + @ScopeCode     
 print '@RoleCode: ' + @RoleCode    
                      
 if(@UserId = 335)                      
   Begin                      
 print '335'  
 select top 1 @UserId UserId, @ParentId ParentId,                       
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                       
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast, turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode                   
 from TBL_UA_ModuleMaster turpm   
 --where ModuleCode = @ModuleCode                
                  
   End                  
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '')               
 and Not Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp               
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                       
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                   
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                       
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                       
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                       
  where urmp.UserId = @UserId or utumm.UserId = @UserId))              
   Begin                      
   print 'A'             
 select top 1 * from (                
 select @UserId UserId, @ParentId ParentId,                       
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                       
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export,                       
 1 MassUpdate, 1 MassDelete,                       
 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5,                       
 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,                       
 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5,                       
 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax,                     
 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,                    
 turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode, IsInternal                
 from TBL_UA_ModuleMaster turpm )                 
 t                
 --where t.ModuleCode = @ModuleCode and t.IsInternal = 0                
   End               
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp                       
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                       
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode    
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                       
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                       
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                       
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                      
   Begin                
--Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish                  
 print 'B'    
 select top 1 * from (      
 Select urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode, urmm.RoleName,      
  turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,Standard2, Standard3, Standard4, Standard5,  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,  Special1, Special2, Special3, Special4, Special5,  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                      
  from TBL_UA_UserRoleMappingMaster urmp  inner join VW_SystemRole_RoleMaster urmm     
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster turpm     
  on turpm.RoleCode = urmp.RoleCode inner join TBL_UA_EntityActionMappingMaster tueam     
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster tueams     
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster tueams2     
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_TeamUserMappingMaster utumm     
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster uatm     
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster umod     
  on umod.ModuleCode = turpm.ModuleCode                      
  where urmp.UserId = @UserId and turpm.ModuleCode = @ModuleCode  and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode       
    )t where t.UserId = @UserId and t.ParentId = @ParentId      
   End               
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and                 
 ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST'))                 
  )                      
   Begin    
   Print 'C'    
 if not Exists(select 1 from TBL_UA_RolePermissionMappingMaster turpm (nolock)      
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                      
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                      
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                  
  where turpm.ParentId = @ParentId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)      
  Begin      
   Print 'D'    
  set @ParentId = 335                          
  End      
--  set @RoleCode = 'SYS_USER'                
--  set @ModuleCode = 'PAG10002'                
--select 'SYS_USER, SYS_Guest'                  
 select top 1                  
  @UserId UserId,    '' TeamCode, '' TeamName, '' RoleName, turpm.ParentId, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,Standard2, Standard3, Standard4, Standard5,  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,  Special1, Special2, Special3, Special4, Special5, SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                     
  from TBL_UA_RolePermissionMappingMaster turpm (nolock)                      
  --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode                      
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                      
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                      
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                 
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                      
  where turpm.ParentId = @ParentId                 
  and turpm.ModuleCode = @ModuleCode                 
  and turpm.ScopeCode = @ScopeCode                 
  and turpm.RoleCode = @RoleCode                 
 End       
  End       
       
 END TRY    
BEGIN CATCH       
      
 DECLARE @ErrorMessage NVARCHAR(4000);       
 SELECT @ErrorMessage = ERROR_MESSAGE();       
 RAISERROR (@ErrorMessage, 16, 1);       
END CATCH       
END    


GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByModuleCodeUserIdCSV]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UA_GetAllPermissionByModuleCodeUserIdCSV]    
(                          
	@Mode varchar(2),                           
	@ModuleCode varchar(50) = null,                          
	@UserId bigint = 0                           
)                        
AS    
BEGIN    
  
SET NOCOUNT ON                             
BEGIN TRY                             

	--Declare @Mode varchar(2) = 'S', @ModuleCode varchar(50) = N'PAG10031,PAG10002,PAG10039', @UserId bigint = 41189
	-- Declare @Mode varchar(2) = 'S', @ModuleCode varchar(50) = 'PAG10031',@UserId bigint = 32222  
  
	drop table if exists #tbl_Permission1  
	drop table if exists #tbl_Permission2  
	drop table if exists #tbl_Permission3  
	drop table if exists #tbl_Permission4  

	drop table if exists #tempModuleCode
	select [value] as FilterModuleCode into #tempModuleCode from string_split(@ModuleCode, ',')

        
 if(@Mode = 'S')                        
 Begin  
    Declare @ParentId bigint = 0                         
    Declare @IsAdmin int = 0, @RowCnt int=0, @Url nvarchar(max), @ModuleName varchar(50)  
    Declare @ScopeCode varchar(10) = ''                         
    Declare @IsExpired bit = 1                        
    Declare @RoleCode varchar(10) = ''                        
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail(nolock) where User_Id = @UserId                
                        
	select @IsExpired = 0   
	from Price_UserSubscriptionDetails(nolock)   
	where IsNewPlan = 1 and Userid = @ParentID  
		and Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                         
                    
	SELECT @ScopeCode = turpm.ScopeCode, @RoleCode = turpm.RoleCode  FROM TBL_UA_UserRoleMappingMaster(nolock) urmp 
	INNER JOIN VW_SystemRole_RoleMaster(nolock) urmm ON urmm.RoleCode = urmp.RoleCode 
	INNER JOIN TBL_UA_RolePermissionMappingMaster(nolock) turpm ON turpm.RoleCode = urmp.RoleCode 
	LEFT JOIN  TBL_UA_TeamUserMappingMaster(nolock) utumm ON utumm.UserId = urmp.UserId 
	LEFT JOIN TBL_UA_TeamMaster(nolock) uatm ON uatm.TeamCode = utumm.TeamCode 
	LEFT JOIN TBL_UA_ModuleMaster(nolock) umod ON umod.ModuleCode = turpm.ModuleCode      
	WHERE urmp.UserId = @UserId OR utumm.UserId = @UserId;                  
	-- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode  
                   
	if(@ScopeCode = '' or @IsExpired = 1)                      
    Begin
		set @ScopeCode = 'USER'                             
    End                       
       
 if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                      
    Begin                    
  set @ScopeCode = 'TEAM'                             
    End                       
                    
 if((@RoleCode = '') and (@IsExpired = 0))                           
    Begin                             
  set @RoleCode = 'SYS_USER'                             
    End                             
 else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                          
    Begin                  
  set @RoleCode = 'SYS_GUEST'                             
    End                    
   
 print '@ModuleCode: ' + @ModuleCode       
 print '@ParentId: ' + cast(@ParentId as varchar)      
 print '@IsAdmin: ' + cast(@IsAdmin  as varchar)      
 print '@IsExpired: ' + cast(@IsExpired as varchar)      
 print '@ScopeCode: ' + @ScopeCode       
 print '@RoleCode: ' + @RoleCode      
                        
 if(@UserId = 335)                        
 Begin                        
  print '335'    
  
  select top 1 @UserId UserId, @ParentId ParentId,                         
  '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                         
  turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete],   
  1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1, 1 Standard2,   
  1 Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment,  
  1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2, 1 Special3,   
  1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument,   
  1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice, 1 AddWebform,   
  1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast, turpm.Type,   
  '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode,  
  turpm.URL  into #tbl_Permission1 from TBL_UA_ModuleMaster(nolock) turpm  
  inner join #tempModuleCode t on turpm.ModuleCode = t.FilterModuleCode
	--where ModuleCode = @ModuleCode  
  
  Select @RowCnt=@@ROWCOUNT  

  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission1  
  
  Select * From #tbl_Permission1  
 End                    
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '') and Not Exists (select distinct 1   
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm   
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm   
  on turpm.RoleCode = urmp.RoleCode   left join TBL_UA_TeamUserMappingMaster(nolock) utumm   
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm   
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod   
  on umod.ModuleCode = turpm.ModuleCode
  inner join #tempModuleCode t on turpm.ModuleCode = t.FilterModuleCode
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                
 Begin                        
  print 'A'  
  
  select *   
  into #tbl_Permission2  
  from (                  
  select @UserId UserId, @ParentId ParentId, '' TeamCode, '' TeamName, '' RoleCode,   
  '' RoleName, turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View],   
  1 [Delete], 1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1,   
  CASE WHEN @UserId = 34594 THEN 1 ELSE 0 END AS Standard2, CASE WHEN @UserId = 34594 THEN 1 ELSE 0 END AS Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 1 AddTask,   
  1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2,  
  1 Special3, 1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp,   
  1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice,   
  1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,  
  turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode,   
  '' EntitySpAction2MappingCode, IsInternal, turpm.URL   
  from TBL_UA_ModuleMaster(nolock) turpm) t 
   inner join #tempModuleCode ct on t.ModuleCode = ct.FilterModuleCode
	where --t.ModuleCode = @ModuleCode and 
			t.IsInternal = 0                  
  
  Select @RowCnt=@@ROWCOUNT  
    
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission2  
  
  Select * From #tbl_Permission2  
 End                 
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1  
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm   
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm   
  on turpm.RoleCode = urmp.RoleCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm   
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm   
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod   
  on umod.ModuleCode = turpm.ModuleCode 
  inner join #tempModuleCode ct on umod.ModuleCode = ct.FilterModuleCode
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                        
 Begin                  
  --Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish                    
  print 'B'      
 

  select --top 1 
  *   
  into #tbl_Permission3  
  from (  
  Select urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode,   
    urmm.RoleName, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, [Add], Edit,  
    [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,  
    Standard2, Standard3, Standard4, Standard5, Download, [Print], AddTask,  
    AddAppointment, AddFollowup, AddNote, SendSms, SendMail, Special1, Special2,  
    Special3, Special4, Special5, SendVoice, MergeLead, SendWhatsapp, UploadDocument,  
    DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform,  
    AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type,  
    turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode,  
    tueams2.EntitySpAction2MappingCode, umod.URL  
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm  
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm  
  on turpm.RoleCode = urmp.RoleCode inner join TBL_UA_EntityActionMappingMaster(nolock) tueam  
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams  
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2  
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm  
  on utumm.UserId = urmp.UserId 
  left join TBL_UA_TeamMaster(nolock) uatm on uatm.TeamCode = utumm.TeamCode 
  left join TBL_UA_ModuleMaster(nolock) umod on umod.ModuleCode = turpm.ModuleCode   
  inner join #tempModuleCode ct on umod.ModuleCode = ct.FilterModuleCode

  where urmp.UserId = @UserId --and turpm.ModuleCode = @ModuleCode 
		and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode  
  )t where t.UserId = @UserId and t.ParentId = @ParentId  
  
  Select @RowCnt=@@ROWCOUNT  
    
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission3  
  
  Select * From #tbl_Permission3  
 End                 
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST')))                        
 Begin      
  Print 'C'      
  
  if not Exists(select 1 from TBL_UA_RolePermissionMappingMaster turpm (nolock) inner join TBL_UA_EntityActionMappingMaster(nolock) tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock
) tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode 
		inner join #tempModuleCode ct on turpm.ModuleCode = ct.FilterModuleCode
    where turpm.ParentId = @ParentId and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)  
  Begin        
   Print 'D'      
   set @ParentId = 335                            
  End        
  --  set @RoleCode = 'SYS_USER'  
  --  set @ModuleCode = 'PAG10002'  
  --select 'SYS_USER, SYS_Guest'  
    
  select --top 1  
	@UserId UserId,    '' TeamCode, '' TeamName, '' RoleName, turpm.ParentId, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, Standard1,Standard2, Standard3, Standard4, Standard5,  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,  Special1, Special2, Special3, Special4, Special5, SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode, umod.URL  
  into #tbl_Permission4  
  from TBL_UA_RolePermissionMappingMaster turpm (nolock)                        
   --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode  
    inner join TBL_UA_EntityActionMappingMaster(nolock) tueam   
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams   
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2   
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_ModuleMaster(nolock) umod   
  on umod.ModuleCode = turpm.ModuleCode inner join #tempModuleCode ct on turpm.ModuleCode = ct.FilterModuleCode
  where turpm.ParentId = @ParentId and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode  
  
  Select @RowCnt=@@ROWCOUNT  
    
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission4  
  
  Select * From #tbl_Permission4  
   
 End  
  
 If(@RowCnt>0)  
 Begin  
  Select @Url=concat(N'{"url":"',@Url,N'","page":"',@ModuleName,'"}')  
  
     EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData      
     @User_id = @UserId,      
     @Activity_type = 'VIEW_PAGE',      
     @ActionType = 'S',      
     @RowJson = @Url,      
     @Table_name = '',      
     @ip_adress = '',      
     @device_id = '',      
     @IsImpersonation = 0,      
     @ImpersonatorId = 0;  
 End  
  
  End         
         
END TRY      
BEGIN CATCH         
 DECLARE @ErrorMessage NVARCHAR(4000);         
 SELECT @ErrorMessage = ERROR_MESSAGE();         
 RAISERROR (@ErrorMessage, 16, 1);         
END CATCH         
  
END    


GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByPageUrl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_UA_GetAllPermissionByPageUrl(
	@UserId bigint,
	@PageUrl nvarchar(max)
)
as
begin
	--declare 
	--	@UserId bigint = 34594,
	--	@PageUrl nvarchar(max) = N'UserCRMCampaign/LeadDetails.aspx'

	declare @tblModuleCode as table (
		ModuleCode nvarchar(255)
	)

	insert into @tblModuleCode(ModuleCode)
	exec usp_tbl_UA_ModuleMasterGetModuleCodeByURL
		 @URL = @PageUrl
	 
	declare @ModuleCode nvarchar(255)
	select top 1 @ModuleCode = ModuleCode from @tblModuleCode

	exec usp_UA_GetAllPermissionByModuleCodeUserId
		@Mode = 'S', @ModuleCode = @ModuleCode,  @UserId = @UserId

end



GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByStaticPathUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UA_GetAllPermissionByStaticPathUserId]  --'S', 'PAG10054', 34081                      
(  
 @Mode varchar(2),                       
 @StaticPath varchar(400) = null,                      
 @UserId bigint = 0                       
)                    
AS                       
  SET NOCOUNT ON                       
  BEGIN TRY                       
 if(@Mode = 'S')                  
  Begin  
  Declare @ModuleCode varchar(50) = isnull((Select top 1 ModuleCode from TBL_UA_ModuleMaster(nolock) where StaticPath like '%' + @StaticPath + ''), '')  
  if(@ModuleCode !='')  
 Begin  
 Declare @ParentId bigint = 0                   
    Declare @IsAdmin int = 0                   
    Declare @ScopeCode varchar(10) = ''                   
    Declare @IsExpired bit = 1                  
    Declare @RoleCode varchar(10) = ''                  
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail(nolock) where User_Id = @UserId       
                  
    select @IsExpired = 0 from Price_UserSubscriptionDetails where Userid = @ParentID and                   
    Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                   
   
   /*           
  select @ScopeCode = turpm.ScopeCode, @RoleCode =turpm.RoleCode from TBL_UA_UserRoleMappingMaster(nolock) urmp                       
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                       
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                       
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                       
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                       
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                
  where urmp.UserId = @UserId or utumm.UserId = @UserId  
  */

   	SELECT @ScopeCode = turpm.ScopeCode, @RoleCode = turpm.RoleCode    
	FROM TBL_UA_UserRoleMappingMaster(nolock) urmp INNER JOIN VW_SystemRole_RoleMaster(nolock) urmm
	ON urmm.RoleCode = urmp.RoleCode INNER JOIN TBL_UA_RolePermissionMappingMaster(nolock) turpm
	ON turpm.RoleCode = urmp.RoleCode LEFT JOIN TBL_UA_TeamUserMappingMaster(nolock) utumm     
	ON utumm.UserId = urmp.UserId LEFT JOIN TBL_UA_TeamMaster(nolock) uatm     
	ON uatm.TeamCode = utumm.TeamCode LEFT JOIN TBL_UA_ModuleMaster(nolock) umod     
	ON umod.ModuleCode = turpm.ModuleCode    
	WHERE urmp.UserId = @UserId OR utumm.UserId = @UserId;    


              
-- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode                 
             
  if(@ScopeCode = '' or @IsExpired = 1)                
    Begin              
    set @ScopeCode = 'USER'                       
    End                 
  if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                
    Begin              
    set @ScopeCode = 'TEAM'                       
    End                 
              
  if((@RoleCode = '') and (@IsExpired = 0))                     
    Begin                       
    set @RoleCode = 'SYS_USER'                       
    End                       
  else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                    
    Begin            
    set @RoleCode = 'SYS_GUEST'                       
    End              
-- Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'Rajnish' Rajnish              
                  
 if(@UserId = 335)                  
   Begin                  
            
 select top 1 @UserId UserId, @ParentId ParentId,                   
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                   
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export,                   
 1 MassUpdate, 1 MassDelete,                   
 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5,                   
 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,                   
 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5,                   
 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax,                 
 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,                
 turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode                   
 from TBL_UA_ModuleMaster turpm where ModuleCode = @ModuleCode
          
   End              
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '')           
 and Not Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp           
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                   
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                   
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                   
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                   
  where urmp.UserId = @UserId or utumm.UserId = @UserId))          
   Begin                  
            
 select * from (            
 select @UserId UserId, @ParentId ParentId,                   
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                   
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export,                   
 1 MassUpdate, 1 MassDelete,                   
 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5,                   
 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,                   
 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5,                   
 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax,                 
 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,                
 turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode, IsInternal            
 from TBL_UA_ModuleMaster turpm )             
 t            
 where t.ModuleCode = @ModuleCode and t.IsInternal = 0            
   End           
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp   
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                   
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                   
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                   
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                   
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                  
   Begin            
--Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish  
            
 Select top 1 urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode, urmm.RoleName,                  
  turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete,                   
  Standard1,Standard2, Standard3, Standard4, Standard5,                   
  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,                   
  1 Special1, Special2, Special3, Special4, Special5,                  
  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax,                 
  AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast,                
  umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                  
  from TBL_UA_UserRoleMappingMaster urmp                 
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                  
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                  
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                  
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                  
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                  
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                  
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                  
  where urmp.UserId = @UserId and turpm.ModuleCode = @ModuleCode  and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode            
   End           
          
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and             
 ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST'))             
  )                  
   Begin              
  set @ParentId = 335                      
--  set @RoleCode = 'SYS_USER'            
--  set @ModuleCode = 'PAG10002'            
--select 'SYS_USER, SYS_Guest'              
 select top 1              
  @UserId UserId,    '' TeamCode, '' TeamName, '' RoleName,            
  turpm.ParentId, turpm.ModuleCode, umod.ModuleName,             
  turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete,                   
  Standard1,Standard2, Standard3, Standard4, Standard5,                   
  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,                   
  1 Special1, Special2, Special3, Special4, Special5,                 
  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax,                 
  AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast,                
  umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                 
  from TBL_UA_RolePermissionMappingMaster turpm                   
  --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode                  
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                  
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                  
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                  
  --inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                  
  --left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  --left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                  
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                  
  where turpm.ParentId = @ParentId             
  and turpm.ModuleCode = @ModuleCode             
  and turpm.ScopeCode = @ScopeCode             
  and turpm.RoleCode = @RoleCode             
 End                  
  End            
  End  
 else   
  Begin  
    Select 'No Record'  
  End  
 END TRY                       
BEGIN CATCH  
  
 DECLARE @ErrorMessage NVARCHAR(4000);                                  
 SELECT @ErrorMessage = ERROR_MESSAGE();                                  
 RAISERROR (@ErrorMessage, 16, 1);                                  
END CATCH   



GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetAllPermissionByURLUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UA_GetAllPermissionByURLUserId]  --'S', 'PAG10054', 34081                      
(  
 @Mode varchar(2),                       
 @URL varchar(400) = null,                      
 @UserId bigint = 0                       
)                    
AS                       
  SET NOCOUNT ON                       
  BEGIN TRY                       
 if(@Mode = 'S')                  
  Begin  
  Declare @ModuleCode varchar(50) = isnull((Select top 1 ModuleCode from TBL_UA_ModuleMaster(nolock) where URL like '%' + @URL + ''), '')  
  if(@ModuleCode !='')  
 Begin  
 Declare @ParentId bigint = 0                   
    Declare @IsAdmin int = 0                   
    Declare @ScopeCode varchar(10) = ''                   
    Declare @IsExpired bit = 1                  
    Declare @RoleCode varchar(10) = ''                  
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail where User_Id = @UserId                   
                  
    select @IsExpired = 0 from Price_UserSubscriptionDetails where Userid = @ParentID and                   
    Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                   
              
  select @ScopeCode = turpm.ScopeCode, @RoleCode =turpm.RoleCode from TBL_UA_UserRoleMappingMaster urmp                       
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                       
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                       
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                       
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                       
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                
  where urmp.UserId = @UserId or utumm.UserId = @UserId               
              
-- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode                 
             
  if(@ScopeCode = '' or @IsExpired = 1)                
    Begin              
    set @ScopeCode = 'USER'                       
    End                 
  if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                
    Begin              
    set @ScopeCode = 'TEAM'                       
    End                 
              
  if((@RoleCode = '') and (@IsExpired = 0))                     
    Begin                       
    set @RoleCode = 'SYS_USER'                       
    End                       
  else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                    
    Begin            
    set @RoleCode = 'SYS_GUEST'                       
    End              
-- Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'Rajnish' Rajnish              
                  
 if(@UserId = 335)                  
   Begin                  
            
 select top 1 @UserId UserId, @ParentId ParentId,                   
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                   
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export,                   
 1 MassUpdate, 1 MassDelete,                   
 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5,                   
 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,                   
 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5,                   
 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax,                 
 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,                
 turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode                   
 from TBL_UA_ModuleMaster turpm where ModuleCode = @ModuleCode
          
   End              
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '')           
 and Not Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp           
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                   
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                   
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                   
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                   
  where urmp.UserId = @UserId or utumm.UserId = @UserId))          
   Begin                  
            
 select * from (            
 select @UserId UserId, @ParentId ParentId,                   
 '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                   
 turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete], 1 Search, 1 Import, 1 Export,                   
 1 MassUpdate, 1 MassDelete,                   
 1 Standard1, 1 Standard2, 1 Standard3, 1 Standard4, 1 Standard5,                   
 1 Download, 1 [Print], 1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,                   
 1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5,                   
 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax,                 
 1 AddQuotation, 1 AddInvoice, 1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,                
 turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode, IsInternal            
 from TBL_UA_ModuleMaster turpm )             
 t            
 where t.ModuleCode = @ModuleCode and t.IsInternal = 0            
   End           
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1 from TBL_UA_UserRoleMappingMaster urmp                   
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                   
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                   
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                   
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                   
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                  
   Begin            
--Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish              
            
 Select top 1 urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode, urmm.RoleName,                  
  turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete,                   
  Standard1,Standard2, Standard3, Standard4, Standard5,                   
  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,                   
  Special1, Special2, Special3, Special4, Special5,                  
  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax,                 
  AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast,                
  umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                  
  from TBL_UA_UserRoleMappingMaster urmp                 
  inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = urmp.RoleCode                  
  inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                  
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                  
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                  
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                  
  left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                  
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                  
  where urmp.UserId = @UserId and turpm.ModuleCode = @ModuleCode  and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode            
   End           
          
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and             
 ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST'))             
  )                  
   Begin              
  set @ParentId = 335                      
--  set @RoleCode = 'SYS_USER'            
--  set @ModuleCode = 'PAG10002'            
--select 'SYS_USER, SYS_Guest'              
 select top 1              
  @UserId UserId,    '' TeamCode, '' TeamName, '' RoleName,            
  turpm.ParentId, turpm.ModuleCode, umod.ModuleName,             
  turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete,                   
  Standard1,Standard2, Standard3, Standard4, Standard5,                   
  Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,                   
  Special1, Special2, Special3, Special4, Special5,                 
  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax,                 
  AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast,                
  umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode                 
  from TBL_UA_RolePermissionMappingMaster turpm                   
  --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode                  
  inner join TBL_UA_EntityActionMappingMaster tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                  
  inner join TBL_UA_EntitySpActionMappingMaster tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode                  
  inner join TBL_UA_EntitySpAction2MappingMaster tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode                  
  --inner join TBL_UA_RolePermissionMappingMaster turpm on turpm.RoleCode = urmp.RoleCode                  
  --left join TBL_UA_TeamUserMappingMaster utumm on utumm.UserId = urmp.UserId                   
  --left join TBL_UA_TeamMaster uatm on uatm.TeamCode = utumm.TeamCode                  
  left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                  
  where turpm.ParentId = @ParentId             
  and turpm.ModuleCode = @ModuleCode             
  and turpm.ScopeCode = @ScopeCode             
  and turpm.RoleCode = @RoleCode             
 End                  
  End            
  End  
 else   
  Begin  
    Select 'No Record'  
  End  
 END TRY                       
BEGIN CATCH  
  
 DECLARE @ErrorMessage NVARCHAR(4000);                                  
 SELECT @ErrorMessage = ERROR_MESSAGE();                                  
 RAISERROR (@ErrorMessage, 16, 1);                                  
END CATCH   



GO

/* ============================================================
   Procedure: [dbo].[usp_UA_GetLeadPermissionByLeadIdUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UA_GetLeadPermissionByLeadIdUserId]
(
    @LeadId BIGINT,
    @UserId BIGINT
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentID BIGINT,
            @IsAdmin BIT;

    -- Get user details
    SELECT 
        @ParentId = ParentID, 
        @IsAdmin = IsAdmin
    FROM User_Detail (NOLOCK)
    WHERE User_ID = @UserId;

    ----------------------------------------------------------------
    -- CASE 1: If user is ADMIN → return all permissions TRUE
    ----------------------------------------------------------------
    IF (@IsAdmin = 1)
    BEGIN
        SELECT  
            CAST(1 AS BIT) AS [View],
            CAST(1 AS BIT) AS [Add],
            CAST(1 AS BIT) AS [Edit],
            CAST(1 AS BIT) AS [Delete],
            CAST(1 AS BIT) AS [Search],
            CAST(1 AS BIT) AS [Import],
            CAST(1 AS BIT) AS [Export],
            CAST(1 AS BIT) AS [MassUpdate],
            CAST(1 AS BIT) AS [MassDelete],
            CAST(1 AS BIT) AS [Download],
            CAST(1 AS BIT) AS [Print],
            CAST(1 AS BIT) AS [AddTask],
            CAST(1 AS BIT) AS [AddAppointment],
            CAST(1 AS BIT) AS [AddFollowup],
            CAST(1 AS BIT) AS [AddNote],
            CAST(1 AS BIT) AS [SendSms],
            CAST(1 AS BIT) AS [SendMail],
            CAST(1 AS BIT) AS [SendVoice],
            CAST(1 AS BIT) AS [MergeLead],
            CAST(1 AS BIT) AS [SendWhatsapp],
            CAST(1 AS BIT) AS [UploadDocument],
            CAST(1 AS BIT) AS [DeleteDocument],
            CAST(1 AS BIT) AS [AddDeal],
            CAST(1 AS BIT) AS [AddTax],
            CAST(1 AS BIT) AS [AddQuotation],
            CAST(1 AS BIT) AS [AddInvoice],
            CAST(1 AS BIT) AS [AddWebform],
            CAST(1 AS BIT) AS [AddCustomField],
            CAST(1 AS BIT) AS [MassAssign],
            CAST(1 AS BIT) AS [MassSMS],
            CAST(1 AS BIT) AS [MassEmail],
            CAST(1 AS BIT) AS [MassBroadcast],
            CAST(1 AS BIT) AS [CreatingMeeting];
        RETURN;
    END;

    ----------------------------------------------------------------
    -- Fetch permissions normally
    ----------------------------------------------------------------
    SELECT 
        a.entity,
        a.action_name,
        CAST(CASE WHEN p.action_id IS NOT NULL THEN 1 ELSE 0 END AS BIT) AS HasPermission
    INTO #TempPermissions
    FROM Tbl_coll_ActionMaster a
    LEFT JOIN
    (
        SELECT DISTINCT atm.action_id
        FROM tbl_coll_Lead_collaborator_mapping lcm
        INNER JOIN tbl_coll_CollaboratorTypeMaster ctm 
            ON TRY_CAST(lcm.typeid AS INT) = ctm.id
        INNER JOIN tbl_coll_CollaboratorType_Action_mapping atm
            ON ctm.id = atm.collaborator_type_id
        WHERE lcm.entityId = @LeadId
          AND lcm.isactive = 1
          AND atm.isactive = 1
          AND (
               EXISTS (
                    SELECT 1
                    FROM tbl_coll_CollaboratorTeams t
                    INNER JOIN tbl_coll_Collaboratorteams_user_mapping tum 
                        ON t.id = tum.team_id
                    WHERE TRY_CAST(lcm.teamid AS INT) = t.id
                      AND tum.user_id = @UserId
                      AND tum.isactive = 1
                      AND t.isactive = 1
               )
               OR TRY_CAST(lcm.userid AS BIGINT) = @UserId
          )
    ) p ON a.id = p.action_id
    WHERE a.isactive = 1;

    ----------------------------------------------------------------
    -- CASE 2: If no permissions found for given lead & user → ALL TRUE
    ----------------------------------------------------------------
    IF NOT EXISTS (SELECT 1 FROM #TempPermissions)
    BEGIN
        SELECT  
            CAST(1 AS BIT) AS [View],
            CAST(1 AS BIT) AS [Add],
            CAST(1 AS BIT) AS [Edit],
            CAST(1 AS BIT) AS [Delete],
            CAST(1 AS BIT) AS [Search],
            CAST(1 AS BIT) AS [Import],
            CAST(1 AS BIT) AS [Export],
            CAST(1 AS BIT) AS [MassUpdate],
            CAST(1 AS BIT) AS [MassDelete],
            CAST(1 AS BIT) AS [Download],
            CAST(1 AS BIT) AS [Print],
            CAST(1 AS BIT) AS [AddTask],
            CAST(1 AS BIT) AS [AddAppointment],
            CAST(1 AS BIT) AS [AddFollowup],
            CAST(1 AS BIT) AS [AddNote],
            CAST(1 AS BIT) AS [SendSms],
            CAST(1 AS BIT) AS [SendMail],
            CAST(1 AS BIT) AS [SendVoice],
            CAST(1 AS BIT) AS [MergeLead],
            CAST(1 AS BIT) AS [SendWhatsapp],
            CAST(1 AS BIT) AS [UploadDocument],
            CAST(1 AS BIT) AS [DeleteDocument],
            CAST(1 AS BIT) AS [AddDeal],
            CAST(1 AS BIT) AS [AddTax],
            CAST(1 AS BIT) AS [AddQuotation],
            CAST(1 AS BIT) AS [AddInvoice],
            CAST(1 AS BIT) AS [AddWebform],
            CAST(1 AS BIT) AS [AddCustomField],
            CAST(1 AS BIT) AS [MassAssign],
            CAST(1 AS BIT) AS [MassSMS],
            CAST(1 AS BIT) AS [MassEmail],
            CAST(1 AS BIT) AS [MassBroadcast],
            CAST(1 AS BIT) AS [CreatingMeeting];
        RETURN;
    END;

    ----------------------------------------------------------------
    -- Return real permissions
    ----------------------------------------------------------------
    SELECT 
        MAX(CASE WHEN action_name = 'View' THEN HasPermission ELSE 0 END) AS [View],
        MAX(CASE WHEN action_name = 'Add' THEN HasPermission ELSE 0 END) AS [Add],
        MAX(CASE WHEN action_name = 'Edit' THEN HasPermission ELSE 0 END) AS [Edit],
        MAX(CASE WHEN action_name = 'Delete' THEN HasPermission ELSE 0 END) AS [Delete],
        MAX(CASE WHEN action_name = 'Search' THEN HasPermission ELSE 0 END) AS [Search],
        MAX(CASE WHEN action_name = 'Import' THEN HasPermission ELSE 0 END) AS [Import],
        MAX(CASE WHEN action_name = 'Export' THEN HasPermission ELSE 0 END) AS [Export],
        MAX(CASE WHEN action_name = 'MassUpdate' THEN HasPermission ELSE 0 END) AS [MassUpdate],
        MAX(CASE WHEN action_name = 'MassDelete' THEN HasPermission ELSE 0 END) AS [MassDelete],
        MAX(CASE WHEN action_name = 'Download' THEN HasPermission ELSE 0 END) AS [Download],
        MAX(CASE WHEN action_name = 'Print' THEN HasPermission ELSE 0 END) AS [Print],
        MAX(CASE WHEN action_name = 'AddTask' THEN HasPermission ELSE 0 END) AS [AddTask],
        MAX(CASE WHEN action_name = 'AddAppointment' THEN HasPermission ELSE 0 END) AS [AddAppointment],
        MAX(CASE WHEN action_name = 'AddFollowup' THEN HasPermission ELSE 0 END) AS [AddFollowup],
        MAX(CASE WHEN action_name = 'AddNote' THEN HasPermission ELSE 0 END) AS [AddNote],
        MAX(CASE WHEN action_name = 'SendSms' THEN HasPermission ELSE 0 END) AS [SendSms],
        MAX(CASE WHEN action_name = 'SendMail' THEN HasPermission ELSE 0 END) AS [SendMail],
        MAX(CASE WHEN action_name = 'SendVoice' THEN HasPermission ELSE 0 END) AS [SendVoice],
        MAX(CASE WHEN action_name = 'MergeLead' THEN HasPermission ELSE 0 END) AS [MergeLead],
        MAX(CASE WHEN action_name = 'SendWhatsapp' THEN HasPermission ELSE 0 END) AS [SendWhatsapp],
        MAX(CASE WHEN action_name = 'UploadDocument' THEN HasPermission ELSE 0 END) AS [UploadDocument],
        MAX(CASE WHEN action_name = 'DeleteDocument' THEN HasPermission ELSE 0 END) AS [DeleteDocument],
        MAX(CASE WHEN action_name = 'AddDeal' THEN HasPermission ELSE 0 END) AS [AddDeal],
        MAX(CASE WHEN action_name = 'AddTax' THEN HasPermission ELSE 0 END) AS [AddTax],
        MAX(CASE WHEN action_name = 'AddQuotation' THEN HasPermission ELSE 0 END) AS [AddQuotation],
        MAX(CASE WHEN action_name = 'AddInvoice' THEN HasPermission ELSE 0 END) AS [AddInvoice],
        MAX(CASE WHEN action_name = 'AddWebform' THEN HasPermission ELSE 0 END) AS [AddWebform],
        MAX(CASE WHEN action_name = 'AddCustomField' THEN HasPermission ELSE 0 END) AS [AddCustomField],
        MAX(CASE WHEN action_name = 'MassAssign' THEN HasPermission ELSE 0 END) AS [MassAssign],
        MAX(CASE WHEN action_name = 'MassSMS' THEN HasPermission ELSE 0 END) AS [MassSMS],
        MAX(CASE WHEN action_name = 'MassEmail' THEN HasPermission ELSE 0 END) AS [MassEmail],
        MAX(CASE WHEN action_name = 'MassBroadcast' THEN HasPermission ELSE 0 END) AS [MassBroadcast],
        MAX(CASE WHEN action_name = 'CreatingMeeting' THEN HasPermission ELSE 0 END) AS [CreatingMeeting]
    FROM #TempPermissions;

    DROP TABLE #TempPermissions;
END;


