            CAST(1 AS BIT) AS [AddFollowup],
            CAST(1 AS BIT) AS [AddNote],
            CAST(1 AS BIT) AS [SendSms],
            CAST(1 AS BIT) AS [SendMail],
            CAST(1 AS BIT) AS [SendVoice],
