        RETURN;
    END; 

IF EXISTS (
    SELECT 1
    FROM tbl_coll_Lead_collaborator_mapping WITH (NOLOCK)
    WHERE entityId = @LeadId and typeid <> 0 and teamid is not null  
)
BEGIN
    SET @HasLeadActionMapping = 1;
END

    
IF (@HasLeadActionMapping = 1)
BEGIN
print 2
    ----------------------------------------------------------------
    -- Fetch permissions normally
    ----------------------------------------------------------------
    SELECT 
        a.entity,
        a.action_name,
        CAST(CASE WHEN p.action_id IS NOT NULL THEN 1 ELSE 0 END AS BIT) AS HasPermission
    INTO #TempPermissions
    FROM Tbl_coll_ActionMaster a
    LEFT JOIN
    (
        SELECT DISTINCT atm.action_id
        FROM tbl_coll_Lead_collaborator_mapping lcm
        INNER JOIN tbl_coll_CollaboratorTypeMaster ctm 
            ON TRY_CAST(lcm.typeid AS INT) = ctm.id
        INNER JOIN tbl_coll_CollaboratorType_Action_mapping atm
            ON ctm.id = atm.collaborator_type_id
        WHERE lcm.entityId = @LeadId
          AND lcm.isactive = 1
          AND atm.isactive = 1
          AND (
               EXISTS (
                    SELECT 1
                    FROM tbl_coll_CollaboratorTeams t
                    INNER JOIN tbl_coll_Collaboratorteams_user_mapping tum 
                        ON t.id = tum.team_id
                    WHERE TRY_CAST(lcm.teamid AS INT) = t.id
                      AND tum.user_id = @UserId
                      AND tum.isactive = 1
                      AND t.isactive = 1
               )
               OR TRY_CAST(lcm.userid AS BIGINT) = @UserId
          )
    ) p ON a.id = p.action_id
    WHERE a.isactive = 1;
	----------------------------------------------------------------
    -- Return real permissions
    ----------------------------------------------------------------
    SELECT 
        MAX(CASE WHEN action_name = 'View' THEN HasPermission ELSE 0 END) AS [View],
        --MAX(CASE WHEN action_name = 'Add' THEN HasPermission ELSE 0 END) AS [Add],
        MAX(CASE WHEN action_name = 'Edit' THEN HasPermission ELSE 0 END) AS [Edit],
        MAX(CASE WHEN action_name = 'Delete' THEN HasPermission ELSE 0 END) AS [Delete],
        MAX(CASE WHEN action_name = 'Search' THEN HasPermission ELSE 0 END) AS [Search],
        --MAX(CASE WHEN action_name = 'Import' THEN HasPermission ELSE 0 END) AS [Import],
        --MAX(CASE WHEN action_name = 'Export' THEN HasPermission ELSE 0 END) AS [Export],
        MAX(CASE WHEN action_name = 'MassUpdate' THEN HasPermission ELSE 0 END) AS [MassUpdate],
        MAX(CASE WHEN action_name = 'MassDelete' THEN HasPermission ELSE 0 END) AS [MassDelete],
        --MAX(CASE WHEN action_name = 'Download' THEN HasPermission ELSE 0 END) AS [Download],
        --MAX(CASE WHEN action_name = 'Print' THEN HasPermission ELSE 0 END) AS [Print],
        MAX(CASE WHEN action_name = 'AddTask' THEN HasPermission ELSE 0 END) AS [AddTask],
        MAX(CASE WHEN action_name = 'AddAppointment' THEN HasPermission ELSE 0 END) AS [AddAppointment],
		MAX(CASE WHEN action_name = 'AddPhysicalAppointment' THEN HasPermission ELSE 0 END) AS [AddPhysicalAppointment],
        MAX(CASE WHEN action_name = 'AddFollowup' THEN HasPermission ELSE 0 END) AS [AddFollowup],
        MAX(CASE WHEN action_name = 'AddNote' THEN HasPermission ELSE 0 END) AS [AddNote],
        MAX(CASE WHEN action_name = 'SendSms' THEN HasPermission ELSE 0 END) AS [SendSms],
        MAX(CASE WHEN action_name = 'SendMail' THEN HasPermission ELSE 0 END) AS [SendMail],
        MAX(CASE WHEN action_name = 'SendVoice' THEN HasPermission ELSE 0 END) AS [SendVoice],
        MAX(CASE WHEN action_name = 'MergeLead' THEN HasPermission ELSE 0 END) AS [MergeLead],
        MAX(CASE WHEN action_name = 'SendWhatsapp' THEN HasPermission ELSE 0 END) AS [SendWhatsapp],
        MAX(CASE WHEN action_name = 'UploadDocument' THEN HasPermission ELSE 0 END) AS [UploadDocument],
        MAX(CASE WHEN action_name = 'DeleteDocument' THEN HasPermission ELSE 0 END) AS [DeleteDocument],
        MAX(CASE WHEN action_name = 'AddDeal' THEN HasPermission ELSE 0 END) AS [AddDeal],
        MAX(CASE WHEN action_name = 'AddTax' THEN HasPermission ELSE 0 END) AS [AddTax],
        MAX(CASE WHEN action_name = 'AddQuotation' THEN HasPermission ELSE 0 END) AS [AddQuotation],
        MAX(CASE WHEN action_name = 'AddInvoice' THEN HasPermission ELSE 0 END) AS [AddInvoice],
        MAX(CASE WHEN action_name = 'AddWebform' THEN HasPermission ELSE 0 END) AS [AddWebform],
        MAX(CASE WHEN action_name = 'AddCustomField' THEN HasPermission ELSE 0 END) AS [AddCustomField],
        MAX(CASE WHEN action_name = 'MassAssign' THEN HasPermission ELSE 0 END) AS [MassAssign],
        MAX(CASE WHEN action_name = 'MassSMS' THEN HasPermission ELSE 0 END) AS [MassSMS],
        MAX(CASE WHEN action_name = 'MassEmail' THEN HasPermission ELSE 0 END) AS [MassEmail],
        --MAX(CASE WHEN action_name = 'MassBroadcast' THEN HasPermission ELSE 0 END) AS [MassBroadcast],
        MAX(CASE WHEN action_name = 'CreatingMeeting' THEN HasPermission ELSE 0 END) AS [CreatingMeeting]
    FROM #TempPermissions;

end 
ELSE
BEGIN
     print 3                           
    Declare  @RowCnt int=0, @Url nvarchar(max), @ModuleName varchar(50)      
    Declare @ScopeCode varchar(10) = ''                             
    Declare @IsExpired bit = 1                            
    Declare @RoleCode varchar(10) = ''                            
    select @ParentId = ParentId, @IsAdmin = case when parentId=User_Id then 1 else IsAdmin end from User_Detail(nolock) where User_Id = @UserId                             
     Declare @Mode varchar(2) = 'S',@ModuleCode varchar(50) = 'PAG10031'
	 
    select @IsExpired = 0       
 from Price_UserSubscriptionDetails(nolock)       
 where IsNewPlan = 1 and Userid = @ParentID      
    and Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate                             
                        
 SELECT @ScopeCode = turpm.ScopeCode, @RoleCode = turpm.RoleCode          
 FROM TBL_UA_UserRoleMappingMaster(nolock) urmp INNER JOIN VW_SystemRole_RoleMaster(nolock) urmm      
 ON urmm.RoleCode = urmp.RoleCode INNER JOIN TBL_UA_RolePermissionMappingMaster(nolock) turpm      
 ON turpm.RoleCode = urmp.RoleCode LEFT JOIN TBL_UA_TeamUserMappingMaster(nolock) utumm           
 ON utumm.UserId = urmp.UserId LEFT JOIN TBL_UA_TeamMaster(nolock) uatm           
 ON uatm.TeamCode = utumm.TeamCode LEFT JOIN TBL_UA_ModuleMaster(nolock) umod           
 ON umod.ModuleCode = turpm.ModuleCode          
 WHERE urmp.UserId = @UserId OR utumm.UserId = @UserId;                      
 -- Select @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode      
                       
 if(@ScopeCode = '' or @IsExpired = 1)                          
    Begin                        
  set @ScopeCode = 'USER'                                 
    End                           
           
 if(@ScopeCode = '' and @IsExpired = 0 and @IsAdmin = 1)                          
    Begin                        
  set @ScopeCode = 'TEAM'                                 
    End                           
                        
 if((@RoleCode = '') and (@IsExpired = 0))                               
    Begin                                 
  set @RoleCode = 'SYS_USER'                                 
    End                                 
 else if((@RoleCode = '') and (@IsAdmin = 0) or (@IsExpired = 1))                              
    Begin                      
  set @RoleCode = 'SYS_GUEST'                                 
    End                        
       
 print '@ModuleCode: ' + @ModuleCode           
 print '@ParentId: ' + cast(@ParentId as varchar)          
 print '@IsAdmin: ' + cast(@IsAdmin  as varchar)          
 print '@IsExpired: ' + cast(@IsExpired as varchar)          
 print '@ScopeCode: ' + @ScopeCode           
 print '@RoleCode: ' + @RoleCode          
                            
 if(@UserId = 335)                            
 Begin                            
  print '335'        
      
  select top 1 @UserId UserId, @ParentId ParentId,                             
  '' TeamCode, '' TeamName, '' RoleCode, '' RoleName,                             
  turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View], 1 [Delete],       
  1 Search, 1 Import, 1 Export, 1 MassUpdate, 1 MassDelete, 1 Standard1, 1 Standard2,       
  1 Standard3, 1 Standard4, 1 Standard5, 1 Download,
  1 [Print],
  1 AddTask, 1 AddAppointment,      
  1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail, 1 Special1, 1 Special2, 1 Special3,       
  1 Special4, 1 Special5, 1 SendVoice, 1 MergeLead, 1 SendWhatsapp, 1 UploadDocument,       
  1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice, 1 AddWebform,       
  1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast, turpm.Type,       
  '' EntityActionMappingCode, '' EntitySpActionMappingCode, '' EntitySpAction2MappingCode,      
  turpm.URL      
  into #tbl_Permission1      
  from TBL_UA_ModuleMaster(nolock) turpm         
  where ModuleCode = @ModuleCode      
      
  Select @RowCnt=@@ROWCOUNT      
        
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission1      
      
  Select * From #tbl_Permission1      
 End                        
 else if((@IsExpired = 0 and @IsAdmin = 1 and @ParentId = @UserId) or (@ParentId != @UserId) and (@IsAdmin = 1) and @IsExpired = 0 and (@ScopeCode != '') and Not Exists (select distinct 1       
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm       
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm       
  on turpm.RoleCode = urmp.RoleCode   left join TBL_UA_TeamUserMappingMaster(nolock) utumm       
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm       
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod       
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                    
 Begin                            
  print 'A'      
      
  select top 1 *       
  into #tbl_Permission2      
  from (                      
  select @UserId UserId, @ParentId ParentId, '' TeamCode, '' TeamName, '' RoleCode,       
  '' RoleName, turpm.ModuleCode, turpm.ModuleName, '' ScopeCode, 1 [Add], 1 Edit, 1 [View],       
  1 [Delete], 1 Search,  1 MassUpdate, 1 MassDelete, 
  --1 Import, 1 Export,1 Standard1,       
  --CASE WHEN @UserId = 34594 THEN 1 ELSE 0 END AS Standard2
  --CASE WHEN @UserId IN (34594, 32222) THEN 1 ELSE 0 END AS Standard2
  --1 Standard2 , 1 Standard3, 1 Standard4, 1 Standard5, 1 Download, 1 [Print], 
  1 AddTask, 1 AddAppointment, 1 AddFollowup, 1 AddNote, 1 SendSms, 1 SendMail,
  --1 Special1, 1 Special2, 1 Special3, 1 Special4, 1 Special5, 
  1 SendVoice, 1 MergeLead, 1 SendWhatsapp,       
  1 UploadDocument, 1 DeleteDocument, 1 AddDeal, 1 AddTax, 1 AddQuotation, 1 AddInvoice,       
  1 AddWebform, 1 AddCustomField, 1 MassAssign, 1 MassSMS, 1 MassEmail, 1 MassBroadcast,      
  turpm.Type, '' EntityActionMappingCode, '' EntitySpActionMappingCode,       
  '' EntitySpAction2MappingCode, IsInternal, turpm.URL       
  from TBL_UA_ModuleMaster(nolock) turpm) t      
  where t.ModuleCode = @ModuleCode and t.IsInternal = 0                      
      
  Select @RowCnt=@@ROWCOUNT      
        
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission2      
      
  Select * From #tbl_Permission2      
 End                     
 else if((@ParentId != @UserId) and @IsExpired = 0 and (@ScopeCode != '') and Exists (select distinct 1      
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm       
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm       
  on turpm.RoleCode = urmp.RoleCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm       
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm       
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod       
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId or utumm.UserId = @UserId))                            
 Begin                      
  --Select @ModuleCode, @ParentId, @IsAdmin IsAdmin, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode, 'USER RoleMapping exist' Rajnish                        
  print 'B'          
      
  select top 1 *       
  into #tbl_Permission3      
  from (      
  Select urmp.UserId, turpm.ParentId, utumm.TeamCode, uatm.TeamName, urmp.RoleCode,       
    urmm.RoleName, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode,  Edit,      
    [View], [Delete], Search,  MassUpdate, MassDelete,
	--[Add],Import, Export, Standard1,Standard2, Standard3, Standard4, Standard5, Download, [Print],
	AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,
	--Special1, Special2,Special3, Special4, Special5,
	SendVoice, MergeLead, SendWhatsapp, UploadDocument,      
    DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform,      
    AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type,      
    turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode,      
    tueams2.EntitySpAction2MappingCode, umod.URL      
  from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm      
  on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm      
  on turpm.RoleCode = urmp.RoleCode inner join TBL_UA_EntityActionMappingMaster(nolock) tueam      
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams      
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2      
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm      
  on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm      
  on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod      
  on umod.ModuleCode = turpm.ModuleCode      
  where urmp.UserId = @UserId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)t where t.UserId = @UserId and t.ParentId = @ParentId      
      
  Select @RowCnt=@@ROWCOUNT      
        
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission3      
      
  Select * From #tbl_Permission3      
 End                     
 Else if((@ParentId != @UserId) and (@IsAdmin = 0) and @ScopeCode = 'USER' and ((@RoleCode = 'SYS_USER') or (@RoleCode = 'SYS_GUEST')))                            
 Begin          
  Print 'C'          
      
  if not Exists(select 1 from TBL_UA_RolePermissionMappingMaster turpm (nolock) inner join TBL_UA_EntityActionMappingMaster(nolock) tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock
  
    
) tueams on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2 on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode      
    where turpm.ParentId = @ParentId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode)      
  Begin            
   Print 'D'          
   set @ParentId = 335                                
  End            
  --  set @RoleCode = 'SYS_USER'      
  --  set @ModuleCode = 'PAG10002'      
  --select 'SYS_USER, SYS_Guest'      
        
  select top 1  @UserId UserId,    '' TeamCode, '' TeamName, '' RoleName, turpm.ParentId, turpm.ModuleCode, umod.ModuleName, turpm.ScopeCode, turpm.RoleCode, [Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete,
  --Standard1,Standard2, Standard3, Standard4, Standard5,  Download, [Print], 
  AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail,  
  --Special1, Special2, Special3, Special4, Special5, 
  SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast, umod.Type, turpm.EntityActionMappingCode, turpm.EntitySpActionMappingCode, tueams2.EntitySpAction2MappingCode, umod.URL      
  into #tbl_Permission4      
  from TBL_UA_RolePermissionMappingMaster turpm (nolock)                            
   --inner join SystemRoles urmm on urmm.SysRoleCode = turpm.RoleCode      
    inner join TBL_UA_EntityActionMappingMaster(nolock) tueam       
  on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode inner join TBL_UA_EntitySpActionMappingMaster(nolock) tueams       
  on tueams.EntitySpActionMappingCode = turpm.EntitySpActionMappingCode inner join TBL_UA_EntitySpAction2MappingMaster(nolock) tueams2       
  on tueams2.EntitySpAction2MappingCode = turpm.EntitySpAction2MappingCode left join TBL_UA_ModuleMaster(nolock) umod       
  on umod.ModuleCode = turpm.ModuleCode      
  where turpm.ParentId = @ParentId and turpm.ModuleCode = @ModuleCode and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode      
      
  Select @RowCnt=@@ROWCOUNT      
        
  Select @ModuleCode=ModuleCode, @Url=[URL], @ModuleName=ModuleName From #tbl_Permission4      
      
  Select * From #tbl_Permission4     
END
   end 

    
    
END;



