/* ============================================================
   Procedure: [dbo].[usp_UA_GetRoleByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_UA_GetRoleByParentId @ParentId=32222
CREATE   PROCEDURE usp_UA_GetRoleByParentId
(
	@ParentId bigint
)
AS
Begin
	-- declare @ParentId bigint=32222

	Select id as RoleId,RoleName,SysRoleCode as RoleCode,pid as ParentId
	FROM systemRoles tm WITH (NOLOCK)      
	WHERE Id IN (/*4,*/9,10)
	union
	SELECT	RoleId,RoleName,RoleCode,ParentId
    FROM	TBL_UA_RoleMaster(NOLOCK)
	WHERE	Active=1 and IsInternal=0 and ParentId=@ParentId

End



GO

