/* ============================================================
   Procedure: [dbo].[usp_ubc_CreateBatchRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ubc_CreateBatchRecord]  -- in 2nd job create  in mysms
    @Account BIGINT,
	@DLTTemplateID nvarchar(200)
AS
BEGIN
    SET NOCOUNT ON;
	BEGIN TRY 
    DECLARE @BatchID BIGINT;

    INSERT INTO GetBatchRecord ([User_id], RandNum)
    VALUES (@Account, @Account);

    SET @BatchID = SCOPE_IDENTITY();
	EXEC Usp_Save_DLTTemplateID_with_BatchID @BatchID      
      ,@DLTTemplateID   

    SELECT @BatchID AS BatchID;
	END TRY      
      
    BEGIN CATCH      
     EXEC usp_InsertErrorInfo      
    END CATCH 
END



GO

