/* ============================================================
   Procedure: [dbo].[usp_unique_field]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_unique_field]    
@parentid bigint,    
@fieldname varchar (100)    
as    
begin    
set nocount on;    
declare @p char(1);    
set @p='0';    
if exists (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'userleads' and COLUMN_NAME=@fieldname)    
begin    
 set @p='1';    
end    
if exists (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'userenquiry' and COLUMN_NAME=@fieldname)    
begin    
 set @p='1';    
end    
if exists (select fieldname from customfields where ParentID=@parentid and fieldname=@fieldname and isActive=1)    
begin    
 set @p='1';    
end    
if(@fieldname in ('enq', 'Tab2', 'RowNumber', 'rcnt', 'MobileNo3', 'EmailID3', 'ADDRESS', 'CreatedDate1', 'Leads', 'RowNumber1', 'rc1', 'CreatedOn1New', 'FollowUp', 'CreatedOn1', 'ss', 'fs', 'assigneduser','CreationDate','ModifiedDate'))    
begin    
 set @p='1';    
end    
select @p as duplicate;    
end 


GO

