SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Author:chandra prakash singh               
-- Create date: Oct 27 2014 12:20AM              
-- Description: This proc use for insert add to cart               
-- =============================================              
CREATE   PROCEDURE [dbo].[Usp_updatAdToCartafterlogin]              
                 
     @SEARCHTYPE VARCHAR(150),              
     @TotalData VARCHAR(250),      
     @userid varchar(15)             
AS              
BEGIN              
 declare @TotalDa varchar(15)       
 select @TotalDa=TotalData from AdToCart where userid=@userid and SearchType=@SEARCHTYPE and isremove=0    
 declare @Total varchar(15)       
 set @Total=@TotalData+cast(@TotalDa as bigint)  
 if(@Total<20000000)  
 begin  
 update AdToCart set TotalData=@Total where userid=@userid and SearchType=@SEARCHTYPE and isremove=0      
 SELECT 'Data updated to cart sucessfully' as Result     
 end           
END 



GO

