/* ============================================================
   Procedure: [dbo].[usp_Update_additional_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_Update_additional_details --429951,'{"Demo fixed":"July 29th, 4:01 PM IST","current_pain_point":"chatbot"}','current_pain_point,interests'
    @visitor_Id bigINT,
    @NewDataJson NVARCHAR(MAX),
    @KeysToAppendCSV NVARCHAR(MAX) -- e.g., 'notes,tags,contact_methods'
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ExistingJson NVARCHAR(MAX);
    DECLARE @UpdatedJson NVARCHAR(MAX);
    DECLARE @Key NVARCHAR(255);
    DECLARE @Value NVARCHAR(MAX);
    DECLARE @JsonType INT;

    --PRINT N'--- Starting Procedure ---';
--  PRINT N'Input @Id: ' + CAST(@lead_Id AS NVARCHAR(MAX));
--  PRINT N'Input @NewDataJson: ' + @NewDataJson;
--  PRINT N'Input @KeysToAppendCSV: ' + @KeysToAppendCSV;


    -- 1. Retrieve the existing JSON string from the table
        SELECT @ExistingJson = other_relevant_info
    FROM cw_visitor_details(nolock)
    WHERE id = @visitor_Id;
    --PRINT N'ExistingJson from DB (fetched for Id ' + CAST(@lead_Id AS NVARCHAR(MAX)) + N'): ' + ISNULL(@ExistingJson, N'[NULL]');

    -- Initialize @UpdatedJson with the existing JSON, or an empty JSON object if NULL
    SET @UpdatedJson = ISNULL(@ExistingJson, N'{}');
    --PRINT N'Initialized @UpdatedJson for processing: ' + @UpdatedJson;

    -- Create a temporary table variable to hold the keys that require appending logic
    DECLARE @AppendKeys TABLE (KeyName NVARCHAR(255) PRIMARY KEY);
    INSERT INTO @AppendKeys (KeyName)
    SELECT trim(value)
    FROM STRING_SPLIT(@KeysToAppendCSV, ',');

    --PRINT N'Keys designated for Appending (from @KeysToAppendCSV):';
    --SELECT KeyName FROM @AppendKeys;

    -- 2. Iterate through the new key-value pairs from @NewDataJson
    DECLARE NewDataCursor CURSOR LOCAL FAST_FORWARD FOR -- Added LOCAL FAST_FORWARD for performance
    SELECT [key], [value], [type]
    FROM OPENJSON(@NewDataJson);

    OPEN NewDataCursor;
    FETCH NEXT FROM NewDataCursor INTO @Key, @Value, @JsonType;

    WHILE @@FETCH_STATUS = 0
    BEGIN
    --PRINT N'' -- New line for readability
--    PRINT N'--- Processing Key: "' + @Key + N'" ---';
--    PRINT N'New Value for "' + @Key + N'": "' + @Value + N'" (Data Type (JSON): ' + CAST(@JsonType AS NVARCHAR(MAX)) + N')';

        DECLARE @CurrentExistingScalarValueAtKey NVARCHAR(MAX) = JSON_VALUE(@UpdatedJson, '$."' + @Key + '"');
        DECLARE @CurrentExistingJsonObjectAtKey NVARCHAR(MAX) = JSON_QUERY(@UpdatedJson, '$."' + @Key + '"');
        
        --PRINT N'Existing Scalar Value in @UpdatedJson for "' + @Key + N'": ' + ISNULL(@CurrentExistingScalarValueAtKey, N'[NULL]');
        --PRINT N'Existing Object/Array Value in @UpdatedJson for "' + @Key + N'": ' + ISNULL(@CurrentExistingJsonObjectAtKey, N'[NULL]');


        -- Check if the current key from @NewDataJson exists in the @UpdatedJson
        IF @CurrentExistingScalarValueAtKey IS NULL AND @CurrentExistingJsonObjectAtKey IS NULL
        BEGIN
            --PRINT N'Decision: Key "' + @Key + N'" does NOT exist in JSON. Adding new key/value.';
            SET @UpdatedJson = JSON_MODIFY(
                @UpdatedJson,
                '$."' + @Key + '"',
                CASE WHEN @JsonType IN (0, 5) THEN JSON_QUERY(@Value) ELSE @Value END
            );
        END
        ELSE
        BEGIN
            --PRINT N'Decision: Key "' + @Key + N'" ALREADY EXISTS in JSON.';
            
            -- Check if this key is designated for appending
            IF EXISTS (SELECT 1 FROM @AppendKeys WHERE KeyName = TRIM(@Key))
            BEGIN
                --PRINT N'Decision: Key "' + @Key + N'" IS in the append list.';
                
                -- Critical check for appending conditions:
                -- 1. New value must be a string (JsonType = 1)
                -- 2. Existing value must be a scalar and not NULL (JSON_VALUE must return something)
                IF @JsonType = 1 AND @CurrentExistingScalarValueAtKey IS NOT NULL
                BEGIN
                    -- Start of modified logic for unique appending
                    --PRINT N'Decision: ALL APPEND CONDITIONS MET for "' + @Key + N'". PERFORMING APPEND (with unique values).';
                    SET @CurrentExistingScalarValueAtKey = CAST(@CurrentExistingScalarValueAtKey AS NVARCHAR(MAX));

                    DECLARE @CombinedUniqueValues NVARCHAR(MAX);

                    -- Use a CTE to combine and get distinct values
                    WITH CombinedValuesCTE AS (
                        -- Select distinct trimmed values from both existing and new, excluding empty strings
                        SELECT DISTINCT TRIM(value) AS value
                        FROM (
                            SELECT value FROM STRING_SPLIT(@CurrentExistingScalarValueAtKey, ',') WHERE value IS NOT NULL AND TRIM(value) <> ''
                            UNION
                            SELECT value FROM STRING_SPLIT(@Value, ',') WHERE value IS NOT NULL AND TRIM(value) <> ''
                        ) AS SourceValues -- Alias for the inner subquery
                        WHERE TRIM(value) <> '' -- Filter out any remaining empty strings after TRIM
                    )
                    -- STRING_AGG without DISTINCT, as uniqueness is handled in the CTE
                    SELECT @CombinedUniqueValues = STRING_AGG(value, ',') WITHIN GROUP (ORDER BY value)
                    FROM CombinedValuesCTE;

                    -- If no valid values result (e.g., both existing and new are empty/null after split), ensure it's an empty string rather than NULL
                    IF @CombinedUniqueValues IS NULL
                    BEGIN
                        SET @CombinedUniqueValues = '';
                    END;
                    
                    SET @UpdatedJson = JSON_MODIFY(
                        @UpdatedJson,
                        '$."' + @Key + '"',
                        @CombinedUniqueValues
                    );
                    -- End of modified logic for unique appending
                END
                ELSE
                BEGIN
                    --PRINT N'Decision: APPEND CONDITIONS NOT MET for "' + @Key + N'". OVERWRITING instead of appending.';
                    --PRINT N'Reason: New Value Type (@JsonType) is ' + CAST(@JsonType AS NVARCHAR(MAX)) + N' (expected 1 for string).';
                    --PRINT N'Reason: Existing Scalar Value IS NULL: ' + IIF(@CurrentExistingScalarValueAtKey IS NULL, N'TRUE', N'FALSE') + N' (expected FALSE).';
                    
                    SET @UpdatedJson = JSON_MODIFY(
                        @UpdatedJson,
                        '$."' + @Key + '"',
                        CASE WHEN @JsonType IN (0, 5) THEN JSON_QUERY(@Value) ELSE @Value END
                    );
                END
            END
            ELSE
            BEGIN
                --PRINT N'Decision: Key "' + @Key + N'" IS NOT in the append list. OVERWRITING.';
                SET @UpdatedJson = JSON_MODIFY(
                    @UpdatedJson,
                    '$."' + @Key + '"',
                    CASE WHEN @JsonType IN (0, 5) THEN JSON_QUERY(@Value) ELSE @Value END
                );
            END
        END

        --PRINT N'--- Current @UpdatedJson after processing "' + @Key + N'": ' + @UpdatedJson;
        FETCH NEXT FROM NewDataCursor INTO @Key, @Value, @JsonType;
    END

    CLOSE NewDataCursor;
    DEALLOCATE NewDataCursor;

    --PRINT N'--- Final Update ---';
    PRINT N'Final @UpdatedJson before committing to DB: ' + @UpdatedJson;

    -- 3. Update the table column with the modified JSON string
    UPDATE cw_visitor_details
    SET other_relevant_info = @UpdatedJson
    WHERE id = @visitor_Id;

    --PRINT N'Procedure finished successfully.';

END;



GO

