/* ============================================================
   Procedure: [dbo].[usp_Update_AttendanceSelfi]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON








CREATE   PROCEDURE dbo.usp_Update_AttendanceSelfi
(
    @Mode VARCHAR(20),
    @AttendenceId BIGINT,
    @CreatedBy BIGINT = 0,
    @ParentId BIGINT = NULL,
    @tblStringList dbo.tblStringList readonly
)
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        IF @AttendenceId IS NULL OR @AttendenceId = 0
        BEGIN
            RAISERROR('AttendanceId is required',16,1);
            RETURN;
        END

        -- aggregate strings from TVP into a single NVARCHAR(MAX) value
        DECLARE @agg NVARCHAR(MAX) = NULL;
        IF EXISTS(SELECT 1 FROM @tblStringList)
        BEGIN
            SELECT @agg = STUFF((SELECT ';' + ISNULL(strValue,'') FROM @tblStringList FOR XML PATH(''), TYPE).value('.','nvarchar(max)'),1,1,'');
        END

        IF @Mode IN ('SIGN_IN','SI')
        BEGIN
            IF @agg IS NOT NULL
            BEGIN
                UPDATE dbo.TBL_ET_Attendance
                SET InSelfi = @agg,
                    UpdatedBy = @CreatedBy,
                    UpdatedDate = GETDATE()
                WHERE AttendanceId = @AttendenceId;
            END

        END
        ELSE IF @Mode IN ('SIGN_OUT','SO')
        BEGIN
            IF @agg IS NOT NULL
            BEGIN
                UPDATE dbo.TBL_ET_Attendance
                SET OutSelfi = @agg,
                    UpdatedBy = @CreatedBy,
                    UpdatedDate = GETDATE()
                WHERE AttendanceId = @AttendenceId;
            END

        END
        ELSE
        BEGIN
            RAISERROR('Unsupported Mode. Use ''SIGN_IN''/''SI'' or ''SIGN_OUT''/''SO''.',16,1);
            RETURN;
        END

        SELECT AttendanceId, InSelfi, OutSelfi, UpdatedBy, UpdatedDate
        FROM dbo.TBL_ET_Attendance
        WHERE AttendanceId = @AttendenceId;

    END TRY
    BEGIN CATCH
	 exec usp_InsertErrorInfo 
        DECLARE @Err NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR(@Err,16,1);
    END CATCH
END



GO

