/* ============================================================
   Procedure: [dbo].[Usp_Update_BothLinkAccountFromKit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE [dbo].[Usp_Update_BothLinkAccountFromKit19]    
as    
Begin    
  CREATE TABLE #TempLinked                      
    (                      
      Result VARCHAR(200)                      
    )        
     
  INSERT INTO #TempLinked                      
     EXEC GetStatusofLinkedServer 'CRM'                      
     IF NOT EXISTS(                      
        SELECT 'x'                      
        FROM   #TempLinked                      
    )    
        
 begin  
   
   
  select * into #Account_Info_Mid_Level  from Account_Info_Mid_Level where isprocessed=0  
       
  UPDATE [CRM].CRMDB.dbo.LinkedAccount        
            
      SET    
       
   cl.RefrenceNo   = ma.RefNo    
   ,    
   cl.Verified = 1    
    
      from [CRM].CRMDB.dbo.LinkedAccount cl inner join #Account_Info_Mid_Level Ma    
          
   on  cl.User_ID = Ma.UserLogin    
   where Ma.IsProcessed = 0  
             
  --WHERE cl.User_ID = Ma.UserLogin    
    
    
  UPDATE LinkedAccount        
      SET    
   RefrenceNo   = ma.RefNo    
   ,    
   Verified = 1    
      from LinkedAccount cl inner join #Account_Info_Mid_Level Ma    
   on  cl.User_ID = Ma.UserLogin    
   where Ma.IsProcessed = 0  
    
   UPDATE aiml  
      SET    
    IsProcessed = 1    
    
   from Account_Info_Mid_Level aiml inner join #Account_Info_Mid_Level la    
   on  aiml.ID = la.ID   
  
drop table #Account_Info_Mid_Level  
  
    select 'Data updated'    
       
    end     
     
 else    
  Begin    
    select 'Server is offline'    
  End    
    
 drop table #TempLinked;      
    
       
    
End  
  
  
  


GO

