/* ============================================================
   Procedure: [dbo].[usp_update_contact_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
--sp_helptext usp_update_contact_details  
  
  
CREATE   PROC [dbo].[usp_update_contact_details]       
@M_ID bigint,          
@User_ID int,             
@Contact_ID bigint,    -- nvarchar to bigint gaurav 17-*08-2010  
-- All change from nvarchar to varchar  
@Contact_Name varchar(50),          
@Contact_Mobile varchar(50),          
@Contact_Email varchar(50),          
@Contact_BG varchar(50),          
@Contact_DOB varchar(50),          
@Contact_Anniversary varchar(50)          
          
as        

declare @Group_ID bigint

set @Group_ID=(select Group_ID from contact_detail where contact_id=@Contact_ID)

if exists(select Contact_Email from contact_detail where contact_id not in(@Contact_ID) and  m_id=@M_ID and user_id=@User_ID and Contact_Email=@Contact_Email and Group_ID= @Group_ID and  @Contact_Email<>'')          
begin          
select 'Email ID Already Exists'          
end          
else          
if exists(select Contact_Mobile from contact_detail where contact_id not in(@Contact_ID) and  m_id=@M_ID and user_id=@User_ID and Contact_Mobile=@Contact_Mobile and Group_ID= @Group_ID and @Contact_Mobile<>'')          
begin          
select 'Mobile No. Already Exists'          
end          
else          
begin          
update contact_detail          
set Contact_Name=@Contact_Name,Contact_Mobile=@Contact_Mobile,Contact_Email=@Contact_Email,Contact_BG=@Contact_BG,Contact_DOB=@Contact_DOB,Contact_Anniversary=@Contact_Anniversary        
where  Contact_ID=@Contact_ID        
select 'Contact Updated Successfully'          
end  
  
  

  



GO

/* ============================================================
   Procedure: [dbo].[usp_update_contact_details_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_update_contact_details_New @M_ID BIGINT
	,@User_ID INT
	,@Contact_ID BIGINT
	,-- nvarchar to bigint gaurav 17-*08-2010    
	-- All change from nvarchar to varchar    
	@Contact_Name VARCHAR(50)
	,@Contact_Mobile VARCHAR(50)
	,@Contact_Email VARCHAR(50)
	,
	--@Contact_BG varchar(50),            
	@Contact_DOB VARCHAR(50)
	,@Contact_Anniversary VARCHAR(50)
	,@CompanyName VARCHAR(100)
	,@City VARCHAR(100)
	,@State VARCHAR(100)
	,@Country VARCHAR(100)
	,@Address VARCHAR(200)
AS
DECLARE @Group_ID BIGINT

SET @Group_ID = (
		SELECT Group_ID
		FROM contact_detail
		WHERE contact_id = @Contact_ID
		)

IF EXISTS (
		SELECT Contact_Email
		FROM contact_detail
		WHERE contact_id NOT IN (@Contact_ID)
			AND m_id = @M_ID
			AND user_id = @User_ID
			AND Contact_Email = @Contact_Email
			AND Group_ID = @Group_ID
			AND @Contact_Email <> ''
		)
BEGIN
	SELECT 'Email ID Already Exists'
END
ELSE IF EXISTS (
		SELECT Contact_Mobile
		FROM contact_detail
		WHERE contact_id NOT IN (@Contact_ID)
			AND m_id = @M_ID
			AND user_id = @User_ID
			AND Contact_Mobile = @Contact_Mobile
			AND Group_ID = @Group_ID
			AND @Contact_Mobile <> ''
		)
BEGIN
	SELECT 'Mobile No. Already Exists'
END
ELSE
BEGIN
	UPDATE contact_detail
	SET Contact_Name = @Contact_Name
		,Contact_Mobile = @Contact_Mobile
		,Contact_Email = @Contact_Email
		,Contact_DOB = @Contact_DOB
		,Contact_Anniversary = @Contact_Anniversary
		,CompanyName = @CompanyName
		,City = @City
		,STATE = @State
		,Country = @Country
		,Address = @Address
	WHERE Contact_ID = @Contact_ID

	SELECT 'Contact Updated Successfully'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM contact_detail(NOLOCK)
			WHERE Contact_ID = @Contact_ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID
		,@Activity_type = 'Updt_Cntct'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'contact_detail'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_update_credits_licenses]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_update_credits_licenses  
as  
begin  
declare @creditid bigint,@credits numeric(18,4)  
declare @intbalance decimal(18,4) =(select top 1 balance from IntCredit_Details(nolock) where user_id=335 order by credit_id desc),@balance bigint,@smstbs nvarchar(4000),@service nvarchar(50),@user_login nvarchar(50)='sms19'  
begin try  
if @intbalance<100000  
begin  
select top 1 @creditid= credit_id from IntCredit_Details(nolock) where user_id=335 order by credit_id desc  
select @balance  
insert into IntCredit_Details(ID,M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,dCurr_Value,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,  
EmpUpdated,MachineName,LastModified,typecredit,Remarks,Batchid,Campaignid,ICD_CreatedBy)  
