select Top 1 M_id, 1, 335, 0,1000000, (Balance + 1000000),Validity,Default_Credit, getdate(),DATEADD(year, 1, getdate()),getdate(),getdate(),EmpUpdated,MachineName,getdate(), 1, 0, 1,1   
from credit_details(nolock) where User_Id = 335 order by credit_id desc  
