/* ============================================================
   Procedure: [dbo].[USP_Update_Custom_Field]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  CREATE   PROCEDURE [dbo].[USP_Update_Custom_Field] @parentID BIGINT  
 ,@fieldID BIGINT  
 ,@fieldname VARCHAR(100)  
 ,@min SQL_VARIANT  
 ,@max SQL_VARIANT  
 ,@default SQL_VARIANT  
 ,@isactive VARCHAR(10)  
 ,@ismandat VARCHAR(10)  
 ,@quick VARCHAR(10)  
 ,@current VARCHAR(10)  
 ,@tooltip NVARCHAR(500)  
 ,@choices NVARCHAR(max) = NULL  
 ,@JSONchoices NVARCHAR(max) = NULL  
 ,@PDependencyJson nvarchar(max) =null  
 ,@CDependencyJson nvarchar(max) =null,  
    @PCFieldId bigint=0,  
 @CPFieldId bigint=0  
AS  
BEGIN  
 SET NOCOUNT ON;  
  
 DECLARE @datatype NVARCHAR(10) = (  
   SELECT datatype  
   FROM customfields(NOLOCK)  
   WHERE field_ID = @fieldID  
   )  
  
 IF (@datatype = 'd')  
 BEGIN  
  IF (  
    @min = '0'  
    OR @min = ''  
    )  
  BEGIN  
   SET @min = NULL  
  END  
  
  IF (  
    @max = '0'  
    OR @max = ''  
    )  
  BEGIN  
   SET @max = NULL  
  END  
  
  IF (  
    @default = '0'  
    OR @default = ''  
    )  
  BEGIN  
   SET @default = NULL  
  END  
 END  
  
 -- if(@quick='True')                      
 --set @isactive='True'            
 IF (@isactive = 'False')  
 BEGIN  
  SET @ismandat = 'False'  
  SET @quick = 'False'  
 END  
  
 DROP TABLE  
  
 IF EXISTS #tempChoices  
  IF (ISNULL(@JSONchoices, '') <> '')  
  BEGIN  
   SELECT *  
    ,0 AS [isProcessed]  
   INTO #tempChoices  
   FROM openjson(@JSONchoices) WITH (  
     Id BIGINT '$.Id'  
     ,OldValue NVARCHAR(500) '$.OldValue'  
     ,[Value] NVARCHAR(500) '$.Value'  
     ,[Status] NVARCHAR(500) '$.Status'  
     )  
  
   WHILE (  
     EXISTS (  
      SELECT *  
      FROM #tempChoices  
      WHERE isProcessed = 0  
      )  
     )  
   BEGIN  
    DECLARE @chId BIGINT  
     ,@OldValue NVARCHAR(500)  
     ,@NewValue NVARCHAR(500)  
     ,@chStatus NVARCHAR(100)  
  
    SELECT TOP 1 @chId = Id  
     ,@OldValue = OldValue  
     ,@NewValue = [Value]  
     ,@chStatus = [Status]  
    FROM #tempChoices  
    WHERE isProcessed = 0  
  
    IF (LTRIM(RTRIM(Lower(@chStatus))) = 'd')  
    BEGIN  
     DELETE  
     FROM customfieldEnquiryvalue  
     WHERE fieldID = @fieldID  
      AND fieldvalue = @OldValue  
  
     DELETE  
     FROM customfieldLeadvalue  
     WHERE fieldID = @fieldID  
      AND fieldvalue = @OldValue  
    END  
  
    IF (LTRIM(RTRIM(Lower(@chStatus))) = 'u')  
    BEGIN  
     UPDATE customfieldEnquiryvalue  
     SET fieldvalue = @NewValue  
     WHERE fieldID = @fieldID  
      AND fieldvalue = @OldValue  
  
     UPDATE customfieldLeadvalue  
     SET fieldvalue = @NewValue  
     WHERE fieldID = @fieldID  
      AND fieldvalue = @OldValue  
    END  
  
    UPDATE #tempChoices  
    SET isProcessed = 1  
    WHERE Id = @chId  
   END  
  END  
  
  if exists (select fieldname from customfields where ParentID=@parentid and fieldname=@fieldname  and field_ID <> @fieldID and isactive=@isactive )      
  begin  
  SELECT 'DUPLICATE' as fieldname  
  end  
  else  
  begin  
 UPDATE customfields  
 SET fieldname = @fieldname  
  ,minvalue = @min  
  ,maxvalue = @max  
  ,defaultValue = @default  
  ,isActive = @isactive  
  ,isMandatory = @ismandat  
  ,quickAdd = @quick  
  ,currentDate = @current  
  ,tooltip = @tooltip  
  ,choices = TRIM(@choices)  
    
 WHERE ParentID = @parentID  
  AND field_ID = @fieldID  
  
  --update customfields set ParentFieldId=@fieldID,DependencyJson=@PDependencyJson where field_ID=@PCFieldId  
  if(@PDependencyJson !='')  
 begin  
  drop table if exists #TempTable  
 SELECT * into #TempTable1 FROM OPENJSON(@PDependencyJson) WITH (  
 FieldId BIGINT '$.FieldId',  
 ParentChildMapping nvarchar(max) '$.ParentChildMapping' as json  
)  
   
      UPDATE y          SET y.DependencyJson = t.ParentChildMapping,          y.ParentFieldId=@fieldID          FROM customfields y          JOIN #TempTable1 t ON y.field_ID = t.FieldId   
  
     
 end  
 if(@CDependencyJson !='')  
 begin  
 update customfields set ParentFieldId=@CPFieldId,DependencyJson=@CDependencyJson where field_ID=@fieldID  
 end  
  
 SELECT 'Success'  
 end  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM customfields  
   WHERE field_ID = @fieldID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentID  
  ,@Activity_type = 'Updt_Custfld'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'customfields'  
END  


GO

