/* ============================================================
   Procedure: [dbo].[usp_update_dlr]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_update_dlr] 
as 
begin 
 update SDR set SDR.Status=left(DDR.Status,30),SDR.Mobile=DDR.Mobile from mysmstrans.dbo.Submit_Detail_Reference SDR with (nolock)join mysms.dbo.Deliver_Detail_Reference DDR with (nolock) 
 on SDR.Reference=DDR.Reference 
 
 update MDT set MessageStatus=SDR.Status from mysmstrans.dbo.MessageDeliveryStatusTemp MDT with (nolock)join mysmstrans.dbo.Submit_Detail_Reference SDR with (nolock) 
 on right(MDT.MessageID,9)=SDR.UserTag 
 
update MDS set MDS.MessageStatus=MDT.MessageStatus from mysms.dbo.MessageDeliveryStatus MDS with (nolock)join mysmstrans.dbo.MessageDeliveryStatusTemp MDT with (nolock) 
on MDS.MessageID=MDT.MessageID 
end 
 



GO

/* ============================================================
   Procedure: [dbo].[usp_update_dlr_Spice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_update_dlr_Spice] 
as 
begin 
declare @SMSDeliveryReportId bigint=isnull((select max(Receivedeliverydataid) from SMSupdatedTill where updatetable='Current'),0) 
declare @CurrentSMSDeliveryReportId bigint=(select MAX(id) from [Receivedeliverydata]) 
 
if @CurrentSMSDeliveryReportId<>@SMSDeliveryReportId 
begin 
begin try 
begin transaction 
select * into #receivedeliverydata from mysmstrans.dbo.ReceiveDeliveryData where ID>@SMSDeliveryReportId 
 
update SDR set SDR.Status=StatusWithErr,SDR.Mobile=DDR.Mobile,sdr.Error=ddr.Error from mysmstrans.dbo.Submit_Detail_Reference SDR with (nolock) 
join #receivedeliverydata DDR with (nolock) on SDR.Reference=DDR.submitrefid 
 
update MDT set MessageStatus=SDR.Status,LastError=SDR.error from mysmstrans.dbo.MessageDeliveryStatusTemp MDT with (nolock)join 
mysmstrans.dbo.Submit_Detail_Reference SDR with (nolock) on MDT.messagerefid=cast(SDR.UserTag as nvarchar) 
 
update MDS set MDS.MessageStatus=MDT.MessageStatus,MDS.LastError=MDT.LastError from mysms.dbo.MessageDeliveryStatus MDS with (nolock) 
join mysmstrans.dbo.MessageDeliveryStatusTemp MDT with (nolock) 
on MDS.MessageID=MDT.MessageID 
 
insert into MySMS.dbo.smsupdatedtill(dateupdated,Receivedeliverydataid,Updatetable) 
select GETDATE(),@CurrentSMSDeliveryReportId,'Current' 
 
drop table #receivedeliverydata 
commit transaction 
END TRY 
BEGIN CATCH 
ROLLBACK TRANSACTION 
SELECT ERROR_NUMBER() AS ErrorNumber, 
 ERROR_SEVERITY() AS ErrorSeverity, 
 ERROR_STATE() AS ErrorState, 
 ERROR_PROCEDURE() AS ErrorProcedure, 
 ERROR_LINE() AS ErrorLine, 
 ERROR_MESSAGE() AS ErrorMessage; 
 END CATCH 
end 
end 
 
--select * from smsupdatedtill 
 
 
 



GO

