/* ============================================================
   Procedure: [dbo].[usp_update_dlr_Spice1_Trans]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_update_dlr_Spice1_Trans]          
as          
begin          
declare @SMSSentReportid bigint=  isnull((select max(Receivedeliverydataid) from mysms.dbo.SMSupdatedTill where updatetable='SMSSent'),0)      
declare @CurrentSMSSentReportId bigint=(select MAX(r.id) from [MySMSTrans].dbo.[Receivedeliverydata] r (nolock) join [MySMSTrans].dbo.[Messagesent] s (nolock) on r.SubmitRefID=case when CHARINDEX(',',s.Msgref,1)>0 then left(s.Msgref,CHARINDEX(',',s.Msgref,1)-1) else s.Msgref end  join   
Mysms.dbo.MessageDeliveryStatus m (nolock) on      
s.MessageID=m.MessageID and s.BatchID=m.BatchID)      
declare @c int= (select COUNT(1)  from [MySMSTrans].dbo.[Receivedeliverydata] r (nolock) join [MySMSTrans].dbo.[Messagesent] s (nolock) on r.SubmitRefID=case when CHARINDEX(',',s.Msgref,1)>0 then left(s.Msgref,CHARINDEX(',',s.Msgref,1)-1) else s.Msgref end  join MessageDeliveryStatus m   
(nolock) on      
s.MessageID=m.MessageID and s.BatchID=m.BatchID where r.ID>@SMSSentReportid)      
--select @CurrentSMSSentReportId,@SMSSentReportid,@c      
if  @CurrentSMSSentReportId>@SMSSentReportid      
begin      
while @CurrentSMSSentReportId>@SMSSentReportid      
begin      
select top 1000 r.* into #messagesent from [MySMSTrans].dbo.ReceiveDeliveryData r (nolock) join [MySMSTrans].dbo.[Messagesent] s (nolock) on r.SubmitRefID=s.Msgref
 join Mysms.dbo.MessageDeliveryStatus m (nolock) on      
s.MessageID=m.MessageID and s.BatchID=m.BatchID where r.id>@SMSSentReportid order by r.ID       
update m set messagestatus=r.StatusWithErr from MySMS.dbo.MessageDeliveryStatus m (nolock) join [MySMSTrans].dbo.[Messagesent] s (nolock) on      
s.MessageID=m.MessageID and s.BatchID=m.BatchID join #messagesent r on r.SubmitRefID=case when CHARINDEX(',',s.Msgref,1)>0 then left(s.Msgref,CHARINDEX(',',s.Msgref,1)-1) else s.Msgref end      
where r.id between @SMSSentReportid and @SMSSentReportid+1000      
select @SMSSentReportid = MAX(r.id) from #messagesent r      
--select count(1),@CurrentSMSSentReportId,@SMSSentReportid,GETDATE() from #messagesent      
drop table #messagesent      
update s set Receivedeliverydataid=@SMSSentReportid from (select top 1 * from mysms.dbo.smsupdatedtill (nolock)       
where Updatetable='SMSSent' order by id desc) s       
end      
      
insert into MySMS.dbo.smsupdatedtill(dateupdated,Receivedeliverydataid,Updatetable)          
select GETDATE(),@CurrentSMSSentReportId,'SMSSent'       
end        
      
      
declare @SMSDeliveryReportId bigint=isnull((select max(Receivedeliverydataid) from SMSupdatedTill where updatetable='Current'),0)          
declare @CurrentSMSDeliveryReportId bigint=(select MAX(id) from [MySMSTrans].dbo.[Receivedeliverydata](nolock))          
--select  @CurrentSMSDeliveryReportId,@SMSDeliveryReportId       
if @CurrentSMSDeliveryReportId>@SMSDeliveryReportId        
begin       
while @CurrentSMSDeliveryReportId>@SMSDeliveryReportId      
begin      
begin try         
begin transaction        
select top 1000 * into #receivedeliverydata from [MySMSTrans].dbo.ReceiveDeliveryData where ID between @SMSDeliveryReportId and @SMSDeliveryReportId+1000 order by id        
declare @submitid table(SDRId bigint)      
declare @messageid table(messageId bigint)      
update SDR set SDR.Status=StatusWithErr,SDR.Mobile=DDR.Mobile,sdr.Error=ddr.Error       
output deleted.Id as SDRId into @submitid      
from mysms.dbo.Submit_Detail_Reference SDR(nolock) join #receivedeliverydata DDR(nolock)          
 on SDR.Reference=DDR.submitrefid where ddr.ID between @SMSDeliveryReportId and @SMSDeliveryReportId+1000          
       
--select * from @submitid            
update MDT set MessageStatus=SDR.Status,LastError=SDR.error       
output deleted.MessageID into @messageid      
from  [MySMSTrans].dbo.MessageDeliveryStatustemp MDT(nolock)      
join mysms.dbo.Submit_Detail_Reference SDR(nolock) on MDT.messagerefid=cast(SDR.UserTag as nvarchar)      
join @submitid s on s.SDRId=sdr.Id      
      
--select * from @messageid      
      
--select COUNT(1) as StatusToBeUpdated from  mysms.dbo.MessageDeliveryStatus MDS(nolock)      
--join mysms.dbo.[MySMSTrans].dbo.MessageDeliveryStatustemp MDT(nolock) on MDS.MessageID=MDT.MessageID          
--join @messageid m on m.messageId=mdt.MessageID      
            
update MDS set MDS.MessageStatus=MDT.MessageStatus,MDS.LastError=MDT.LastError       
from  mysms.dbo.MessageDeliveryStatus MDS(nolock)      
join [MySMSTrans].dbo.MessageDeliveryStatustemp MDT(nolock) on MDS.MessageID=MDT.MessageID          
join @messageid m on m.messageId=mdt.MessageID      
       
update s set Receivedeliverydataid=@SMSDeliveryReportId from (select top 1 * from mysms.dbo.smsupdatedtill (nolock)       
where Updatetable='Current' order by id desc) s       
        
drop table  #receivedeliverydata      
set @SMSDeliveryReportId=   @SMSDeliveryReportId+1000      
commit transaction         
END TRY            
BEGIN CATCH            
ROLLBACK TRANSACTION            
SELECT ERROR_NUMBER()     AS ErrorNumber,            
         ERROR_SEVERITY()   AS ErrorSeverity,            
         ERROR_STATE()      AS ErrorState,            
         ERROR_PROCEDURE()  AS ErrorProcedure,            
         ERROR_LINE()       AS ErrorLine,            
         ERROR_MESSAGE()    AS ErrorMessage;            
 END CATCH        
 end      
insert into MySMS.dbo.smsupdatedtill(dateupdated,Receivedeliverydataid,Updatetable)          
select GETDATE(),@CurrentSMSDeliveryReportId,'Current'         
end        
end 


GO

