/* ============================================================
   Procedure: [dbo].[Usp_Update_DLT_EntityDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Update_DLT_EntityDetails] (
	@PE_ID NVARCHAR(100)
	,@EntityName NVARCHAR(200)
	,@ActiveStatus INT
	,@ID INT
	)
AS
BEGIN
	DECLARE @m_PE_ID NVARCHAR(100)
		,@m_EntityName NVARCHAR(200)

	SELECT @m_PE_ID = pe_id
		,@m_EntityName = entityname
	FROM dltdetails
	WHERE id = @id

	UPDATE DLTdetails
	SET PE_ID = @PE_ID
		,EntityName = @EntityName
		,Activestatus = @ActiveStatus
	WHERE id = @ID

    /*
	BEGIN TRY
		DECLARE @m_ID INT

		SELECT TOP 1 @m_id = id
		FROM mysmstrans.dbo.dltdetails WITH (NOLOCK)
		WHERE pe_id = @m_pe_id
			AND entityname = @m_EntityName
		ORDER BY id DESC

		UPDATE mysmstrans.dbo.DLTdetails
		SET PE_ID = @PE_ID
			,EntityName = @EntityName
			,Activestatus = @ActiveStatus
		WHERE id = @m_ID
	END TRY

	BEGIN CATCH
		EXEC usp_inserterrorinfo
	END CATCH
	*/

	SELECT 'DLT Entity Updated'

	DECLARE @parentid BIGINT = (
			SELECT d.Parentid
			FROM DLTdetails d WITH (NOLOCK)
			WHERE d.id = @ID
			)
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM DLTdetails WITH (NOLOCK)
			WHERE id = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentid
			,@Activity_type = 'Updt_DLT_Reg'
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'DLTdetails'
	END
END




GO

