---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
--sp_helptext usp_update_contact_details  
CREATE   PROC dbo.usp_update_group_details @M_ID BIGINT
	,@User_ID INT
	,@groupid BIGINT
	,@Group_Name VARCHAR(50)
AS
IF EXISTS (
		SELECT Group_Name
		FROM group_detail
		WHERE Group_ID NOT IN (@groupid)
			AND m_id = @M_ID
			AND user_id = @User_ID
			AND Group_Name = @Group_Name
			AND Group_Name <> ''
		)
BEGIN
	SELECT 'Group Name Already Exists'
END
ELSE
BEGIN
	UPDATE group_detail
	SET Group_Name = @Group_Name
	WHERE Group_ID = @groupid

	SELECT 'Group Updated Successfully'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM group_detail
			WHERE Group_ID =@groupid
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID
		,@Activity_type = 'Updt_usrgrp'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'group_detail'
END



GO

