CREATE   PROCEDURE [dbo].[usp_update_lead_processing_flag]
    @LeadId bigINT,
    @Processing BIT
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        UPDATE tbl_ai_agent_entity_for_execution
        SET Processing = @Processing
        WHERE id = @LeadId;
        
        -- Return success
        SELECT 1 AS Success;
        
