/* ============================================================
   Procedure: [dbo].[usp_update_local_user]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--alter table [Local_User_Detail] add parentid bigint    
    
CREATE   PROC [dbo].[usp_update_local_user]                                          
as                      
begin              
/*changed credit_details_all to credit_details as the query wasn't running fast*/             
declare @c int,@user_id bigint=0          
          
drop table if exists #userid          
create table #userid(user_id bigint, lastlogin1 datetime)     
  
  
if exists (select 1 from user_detail where m_id=10043 and user_id not in (select user_id from local_user_detail(nolock)))  
begin  
Insert Into [Local_User_Detail]([M_ID],[User_ID],[User_Login],[Pwd],[FName],[LName],[EMail],[Mobile],[City],[State],[Country],[Type],[Stype],[ACType],[Status],                    
 [DateCreated],[DateUpdated],[EmpUpdated],[MachineName],[LastModified],[userfilter],[FilterMode],[Gender],[Pincode],[Address],[LoginType],parentid,LastLogin1)                                  
 Select           
[M_ID],[User_ID],[User_Login],[Pwd],[FName],[LName],[EMail],[Mobile],[City],[State],[Country],[Type],[Stype],[ACType],[Status],                    
 [DateCreated],[DateUpdated],[EmpUpdated],[MachineName],[LastModified],[userfilter],[FilterMode],[Gender],[Pincode],[Address],[LoginType],parentid ,lastlogin1  
 from user_detail(nolock) where  m_id=10043 and user_id not in (select user_id from local_user_detail(nolock))                           
end  
  
select @c=count(1) from local_user_detail(nolock) where isnull(last_updated_on,dateadd(d,-2,getdate()))<dateadd(HH,-23,getdate())   
  
  
  
  
  
        
while @c>0          
begin          
insert into #userid(user_id)          
select top 5000 user_id from local_user_detail  with (nolock) where user_id>@user_id  and isnull(last_updated_on,dateadd(d,-2,getdate()))<dateadd(HH,-23,getdate()) order by user_id          
   
update l set  
AverageLast3MonthConsumption=AVGdebits  
,SubscriptionExpiry=[dbo].[fn_parent_getsubscriptionexpiry](l.user_id)  
,TotalEngagementTime=dbo.fn_gettotalengagement(l.user_id,'I',cast(dateadd(d,-7,getdate()) as date),cast(dateadd(d,-1,getdate()) as date),'both')  
,AverageEngagementTime=dbo.fn_getaverageengagement(l.user_id,'I',cast(dateadd(d,-7,getdate()) as date),cast(dateadd(d,-1,getdate()) as date),'both')  
,last_updated_on=getdate() , lastlogin1=dbo.fn_getuser_lastlogin(l.User_ID)
from Local_User_Detail l   
join #userid u on u.user_id=l.User_ID  
left join (
SELECT sum(totalconsumption)/count(1) as avgdebits,user_id FROM [MySMS].[dbo].MonthlyConsumption a with (nolock)                       
where datediff(m,FirstDate,getdate())<=3 and exists (select 1 from #userid where user_id=a.User_id) group by user_id )a   
on a.user_id=u.user_id   
  
  
select @user_id=max(user_id) from #userid          
truncate table #userid          
set @c=@c-5000          
end   
  
end         
  



GO

