/* ============================================================
   Procedure: [dbo].[usp_update_MagicBricks_validleads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_update_MagicBricks_validleads]      
@MagicBricks_id bigint = null      
as      
begin   
/*if exists(select 1 from indiamartleads where QUERY_ID in (select query_id from indiamartleads where ID<@indiamartid )  
and id>=@indiamartid)  
begin  
delete From indiamartleads where QUERY_ID in (select query_id from indiamartleads where ID<@indiamartid )  
and id>=@indiamartid  
end  
*/  
declare @i bigint=(select max(ID) from MagicBrickLeads where isvalid=1)  
declare @c int=(select COUNT(1) from MagicBrickLeads(nolock)
 where ID>=case when @MagicBricks_id is null then @i else @MagicBricks_id end)  
declare @ii bigint=(select MIN(id) from MagicBrickLeads(nolock) 
where ID>=case when @MagicBricks_id is null then @i else @MagicBricks_id end)  
while @c>0  
begin  
update i set isvalid=1 from MagicBrickLeads i 
      where ((isnull(nullif(i.Mobile,'null'),'') <> '' and isnull(nullif(i.ISD,'null'),'') <> '')  
	       or ( isnull(nullif(i.EmailID,'null'),'') <> '' ))
		   and i.ID = @ii   

 -- left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(i.COUNTRY_ISO))    
 --where
 -- ((mob<>'' and isnumeric(case when charindex('-',mob,1)> 0 then RIGHT(mob,(len(mob)-charindex('-',mob,1)))    
 --else REPLACE(MOB,ltrim(rtrim(CountryCode)),'') end)=1) or isnull(nullif(ltrim(rtrim(senderemail)),'null'),'')<>'' or (mobile_alt<>'' and isnumeric(case when charindex('-',mobile_alt,1)> 0 then RIGHT(mobile_alt,(len(MOBILE_ALT)-charindex('-',MOBILE_ALT,1))
  
 --)    
 --else REPLACE(MOBILE_ALT,ltrim(rtrim(CountryCode)),'') end)=1) or isnull(nullif(ltrim(rtrim(EMAIL_ALT)),'null'),'')<>'')
 -- and i.ID=@ii
  
set @ii=@ii+1  
set @c=@c-1  
end  
end


