/* ============================================================
   Procedure: [dbo].[Usp_Update_MassLeadEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Update_MassLeadEnquiry]         
@userid bigint ,        
@tablename varchar(50) = null,         
@updatevalues nvarchar(max) = null,        
@HashSeparatedIDs nvarchar(max) = null,        
@batchid bigint =0,     
@scheduleleaddatetime VARCHAR(50)='',    
@mode varchar(50)        
as         
Begin        
 --declare         
 --@userid bigint =34594 ,        
 --@tablename varchar(20) = null,         
 --@updatevalues nvarchar(max) = '[{"Rowid":1,"fieldID":"PersonName","fieldName":"PersonName","tableName":"Userleads","fieldType":"Pred","fieldValue":"sdds"},{"Rowid":2,"fieldID":"State","fieldName":"State","tableName":"Userleads","fieldType":"Pred","fieldValue":"Delhi"},{"Rowid":3,"fieldID":"764","fieldName":"Whatsapp","tableName":"customfieldleadvalue","fieldType":"Cust","fieldValue":"sadnjafsd"},{"Rowid":4,"fieldID":"11876","fieldName":"rjnstest11","tableName":"customfieldleadvalue","fieldType":"Cust","fieldValue":"sdaedsad"},{"Rowid":5,"fieldID":"SourceName","fieldName":"SourceName","tableName":"Userleads","fieldType":"Pred","fieldValue":"504370"}]',        
 --@HashSeparatedIDs nvarchar(max) = '1651948,1651944',        
 --@mode varchar(50) = 'Update'        
        
 Declare @parentid bigint= (Select parentid from User_Detail where User_id=@userid)        
 Declare @updatefields nvarchar(max), @SQL nvarchar(max) ,@fieldID bigint , @fieldValue nvarchar(max)         
 DECLARE @minentity int,@maxentity int,@minvalue int,@maxvalue int, @custtablename nvarchar(50)         
  ,@FieldName NVARCHAR(500) = '',  @FilterExp NVARCHAR(MAX), @EntityID bigint,@ModuleCode nvarchar(50);          
        
 drop table if exists #temp1         
 drop table if exists #tempp        
 drop table if exists #Predtemp        
 drop table if exists #Custtemp        
 drop table if exists #LeadIdTemp        
 drop table if exists #ModulePermission         
 drop table if exists #tempUpdateLead        
 drop table if exists #tempUpdateenq        
 if @mode = 'fields'        
 begin        
        
          
   drop table if exists #ModulePermission         
   Create table  #ModulePermission (        
    MP_PageFieldId nvarchar(100)   
  ,MP_PageCode nvarchar(100)  
   ,MP_TableName  nvarchar(100)        
   ,MP_UserId   nvarchar(100)        
   ,MP_FieldName  nvarchar(100)        
   ,MP_HiddenType  nvarchar(100)        
   ,MP_IsExportAllow  nvarchar(100)        
   )        
   if @tablename='UserLeads'        
   begin        
    set @ModuleCode='PAG10031'        
   end        
   if @tablename='UserEnquiry'        
   begin        
    set @ModuleCode='PAG10002'        
   end        
   insert into #ModulePermission        
   exec usp_tbl_UA_PageFieldsList_UserId_PageCode 's',@parentid,@userid,@ModuleCode        
        
        
  Declare @ResJson NVARCHAR(max)= (Select * from  (select  FieldID, FieldName, TABLE_NAME, FieldType , FieldDetail from(        
   select  FieldID, FieldName, TABLE_NAME, FieldType , FieldDetail, MP_HiddenType from (        
   Select COLUMN_NAME FieldID, COLUMN_NAME FieldName, TABLE_NAME, 'Pred' FieldType , '' FieldDetail  from INFORMATION_SCHEMA.COLUMNS         
  where TABLE_NAME=@tablename and TABLE_CATALOG =DB_Name() and COLUMN_NAME NOT IN ('ID', 'LeadNo','MobileNo', 'MobileNo1', 'MobileNo2', 'EmailID', 'EmailID1', 'EmailID2','CountryCode', 'CountryCode1', 'CountryCode2',        
  'ParentID', 'FollowUpStatus', 'NextStatusDate','Products', 'AmountPaid', 'CreatedOn', 'CreatedBy', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName',        
  'enquirysource', 'WhatsAppNoColName', 'LastFollowupCreatedBy', 'whereAddress', 'latitude', 'longitude', 'LastFollowupCreatedOn','EnquiryID','IsduplicateEmail', 'IsduplicateMobile','AssignedTo','CreatedDate', 'IsOpen')        
  UNION ALL         
    Select cast(field_id as varchar) FieldID, fieldname FieldName,         
  CASE @tablename when 'UserEnquiry' THEN 'customfieldEnquiryvalue' when 'UserLeads' THEN 'customfieldleadvalue' END        
  TABLE_NAME, 'Cust' FieldType ,(select datatype, isnull( minvalue,'' ) minvalue, isnull(maxvalue,'') maxvalue , isnull(defaultValue,'') defaultValue,isnull(tooltip,'') tooltip,isnull(choices,'') choices from customfields cf1 where cf1.field_ID=cf2.field_ID for json auto, include_null_values  ) FieldDetail        
  from customfields cf2 (NOLOCK) where parentid = @parentid and isActive=1 and datatype!='f'        
  )A left join #ModulePermission mp on A.FieldName = mp.MP_FieldName         
   where ISNULL(MP_HiddenType,'') <> 'readonly'        
   ) B        
   ) A for json auto,include_null_values )        
        
  Select @ResJson ResJson        
 end        
 ELSE IF @mode = 'Update'        
 BEGIN         
 BEGIN TRY        
 select * into #temp1 from openjson(@updatevalues) with(        
   Rowid Nvarchar(max),        
   fieldID Nvarchar(max),        
   fieldValue Nvarchar(max),        
   fieldName nvarchar(max),        
   tableName nvarchar(max),        
   fieldType nvarchar(max)        
  )        
  select * into #Predtemp from #temp1 where fieldtype='Pred'        
  select * into #Custtemp from #temp1 where fieldtype='Cust'        
        
   --select * from #Custtemp         
   --select * from #Predtemp        
   select @updatefields=STRING_AGG(fieldID +' = '''+fieldValue+'''',', ')  from #Predtemp          
        
  set @tablename = (select  distinct tableName from  #Predtemp  )         
  set @custtablename = (select  distinct tableName from  #Custtemp  )         
  --select @updatefields = STRING_AGG(fieldID+' = '''+fieldValue+'''',',') from #Predtemp        
  --select @updatefields , @HashSeparatedIDs ,@tablename,@ParentId        
  if @batchid IS NOT NULL AND @batchid <> 0        
 BEGIN        
  --select GetDate()        
  select @HashSeparatedIDs= STRING_AGG(cast(Entityid as nvarchar(max)),',') from Tbl_MassOperationDetails (nolock) where SummaryId=@batchid         
  Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @scheduleleaddatetime  where BatchID=@batchid         
 END        
 declare @ttcount int, @sno int  =1        
 drop table if exists #LeadIdTemp      
 CREATE TABLE #LeadIdTemp       
          (         
   SNo int identity,      
              ID BIGINT      
          )      
  INSERT INTO #LeadIdTemp (ID)                 
      
  Select [value] from fn_split(@HashSeparatedIDs,',')        
  --Select * from #LeadIdTemp         
  --Select @tablename, @updatefields        
  Select @ttcount = count(1) from #LeadIdTemp       
      
print concat('Table: ',@custtablename)  
  while (@ttcount>0 AND (@tablename is not null or @custtablename is not null))      
 BEGIN      
      
  Set @SQL = case lower(@tablename) when 'userleads' then  'Update '+ @tablename+' set '+@updatefields+' where ID '+ ' in (Select ID from #LeadIdTemp  where SNo between '+ cast(@sno as varchar)+' and '+cast(@sno+100 as varchar)+') '        
            when 'userenquiry' then  'Update '+ @tablename+' set '+@updatefields+' where EnquiryID '+ ' in (Select ID from #LeadIdTemp  where SNo between '+ cast(@sno as varchar)+' and '+cast(@sno+100 as varchar)+') 'end         
           
   print ISNULL(@sql, 'SQL NULL')        
   if @tablename='userleads'      
   begin      
   SET Context_Info 0x55555        
   end      
   else      
   begin      
    SET Context_Info 0x77777      
   end      
       
  Execute sp_executesql @SQL        
   SET Context_Info 0x        
        
           
        
  select @minentity =min(rowid), @maxentity= max (Rowid) from #Custtemp         
  if LOWER(@custtablename) ='customfieldleadvalue'        
  BEGIN        
  print 'Entered custom field lead value'  
  --select * from #Custtemp  
  -- select * from #leadidtemp  
  
 --  select c.fieldid,lid.ID,cast(cast(c.fieldvalue as varchar(8000)) as sql_variant) ,getdate() from    
 --#LeadIdTemp lid join #Custtemp c on 1=1  
 --where not exists  
 --  (select 1 from customfieldLeadvalue (nolock) where LeadID=lid.ID and fieldID=c.fieldID)  
 -- and lid.SNo between @sno and @sno+100   
     
    
   update cflv set cflv.fieldvalue  = cast(cus.fieldvalue as varchar)        
   from #Custtemp cus         
   join customfieldLeadvalue cflv (nolock) on cus.fieldID = cflv.fieldid         
   join #LeadIdTemp lid on cflv.LeadID =lid.ID         
    where lid.SNo between @sno and @sno+100      
     
   insert into customfieldLeadvalue (fieldID,LeadID,fieldvalue,CreatedDate)  
 select c.fieldid,lid.ID,cast(cast(c.fieldvalue as varchar(8000)) as sql_variant) ,getdate() from    
 #LeadIdTemp lid join #Custtemp c on 1=1  
 where not exists  
   (select 1 from customfieldLeadvalue (nolock) where LeadID=lid.ID and fieldID=c.fieldID)  
  and lid.SNo between @sno and @sno+100   
     
   select cflv.LeadID into #tempUpdateLead from #Custtemp cus         
   join customfieldLeadvalue cflv (nolock) on cus.fieldID = cflv.fieldid         
   join #LeadIdTemp lid on cflv.LeadID =lid.ID      
  where lid.SNo between @sno and @sno+100      
  /*    
  while @minentity <= @maxentity         
  begin        
   select @fieldID = fieldid ,@fieldValue= fieldValue from #Custtemp where rowid=@minentity        
       
  select @fieldID fieldid, cast(@fieldValue as varchar) fieldValue, value LeadID, GETDATE()       
  from #LeadIdTemp        
  where ID not in (select LeadID from #tempUpdateLead)  and lid.SNo between @sno and @sno+100      
       
     Insert into customfieldLeadvalue (fieldID, fieldvalue, LeadID, CreatedDate)        
     select @fieldID fieldid, cast(@fieldValue as varchar) fieldValue, value LeadID, GETDATE()       
  from #LeadIdTemp        
  where ID not in (select LeadID from #tempUpdateLead)  and lid.SNo between @sno and @sno+100      
           
   select @minentity=min(rowid) from #Custtemp where rowid > @minentity        
  end    
  */  
  END        
  else if LOWER(@custtablename) ='customfieldenquiryvalue'        
  BEGIN        
   update cflv set cflv.fieldvalue  = cast(cus.fieldvalue as varchar)        
   from #Custtemp cus         
   join customfieldEnquiryvalue (nolock) cflv on cus.fieldID = cflv.fieldid         
   join #LeadIdTemp lid on cflv.enquiryid =lid.ID      
   where lid.SNo between @sno and @sno+100      
      
  insert into customfieldEnquiryvalue (fieldID,EnquiryID,fieldvalue)  
 select c.fieldid,lid.ID,cast(cast(c.fieldvalue as varchar(8000)) as sql_variant) from  #LeadIdTemp lid join #Custtemp c on 1=1 where not exists  
   (select 1 from customfieldEnquiryvalue (nolock) where EnquiryID=lid.ID and fieldID=c.fieldID)  
  and lid.SNo between @sno and @sno+100   
  
   select cflv.EnquiryID into #tempUpdateEnq  from #Custtemp cus         
   join customfieldEnquiryvalue (nolock) cflv on cus.fieldID = cflv.fieldid         
   join #LeadIdTemp lid on cflv.enquiryid =lid.ID         
  where lid.SNo between @sno and @sno+100      
    
  /*    
  while @minentity <= @maxentity         
  begin        
   select @fieldID = fieldid ,@fieldValue= fieldValue from #Custtemp where rowid=@minentity        
           
     Insert into customfieldEnquiryvalue (fieldID, fieldvalue, EnquiryID)        
     select @fieldID fieldid, cast(@fieldValue as varchar) fieldValue, value EnquiryID       
  from #LeadIdTemp        
  where id not in (select enquiryID from #tempUpdateEnq) and lid.SNo between @sno and @sno+100      
        
   select @minentity=min(rowid) from #Custtemp where rowid > @minentity        
  end      
  */  
  END        
   set @sno=@sno+100      
   set @ttcount =@ttcount-100      
   END      
  
Select 'Data Updated'        
   Declare @rowJson nvarchar(max) , @Activitytype nvarchar(100)      
   if(@tablename='userleads')      
   BEGIN      
 set @Activitytype = 'Updt_MassLead'       
 set @rowJson = '[{"Batchid"="'+@batchid+'","Entitytype":"Lead"}]'      
   END      
   ELSE if(@tablename='userenquiry')      
   BEGIN      
 Set @Activitytype='Updt_MassEnq'      
 set @rowJson = '[{"Batchid"="'+@batchid+'","Entitytype":"Enquiry"}]'      
   END      
      
    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
  ,@Activity_type = @Activitytype      
  ,@ActionType = 'U'      
  ,@RowJson = @rowJson      
  ,@Table_name = @tablename       
      
  if @batchid IS NOT NULL AND @batchid <> 0        
 BEGIN        
  Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @scheduleleaddatetime , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@batchid         
 END        
 END TRY        
 BEGIN CATCH        
   SET Context_Info 0x           
   insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)            
    SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()              
 END CATCH        
 END         
end 


GO

