  /* for debugging  
 declare  
 @userid bigint =34594 ,      
 @tablename varchar(20) = null,       
 @updatevalues nvarchar(max) = '[{"Rowid":1,"fieldID":"PersonName","fieldName":"PersonName","tableName":"Userleads","fieldType":"Pred","fieldValue":"sdds"},{"Rowid":2,"fieldID":"State","fieldName":"State","tableName":"Userleads","fieldType":"Pred","fiel  
