"fieldValue":"sdaedsad"},  
{"Rowid":5,"fieldID":"SourceName","fieldName":"SourceName","tableName":"Userleads","fieldType":"Pred","fieldValue":"504370"}]',      
 @HashSeparatedIDs nvarchar(max) = '1651948,1651944',      
 @mode varchar(50) = 'Update'      
 */     
 Declare @parentid bigint= (Select parentid from User_Detail(nolock) where User_id=@userid)      
 Declare @updatefields nvarchar(max), @SQL nvarchar(max) ,@fieldID bigint , @fieldValue nvarchar(max)       
 DECLARE @minentity int,@maxentity int,@minvalue int,@maxvalue int, @custtablename nvarchar(50)       
  ,@FieldName NVARCHAR(500) = '',  @FilterExp NVARCHAR(MAX), @EntityID bigint,@ModuleCode nvarchar(50);        
  declare @username nvarchar(100)=(select user_login from User_Detail(nolock) where user_id=@userid)  
  DECLARE @tbl1 AS LeadActivitywithid_Tbltype    
      
 drop table if exists #temp1       
 drop table if exists #tempp      
 drop table if exists #Predtemp      
 drop table if exists #Custtemp      
 drop table if exists #LeadIdTemp      
 drop table if exists #ModulePermission       
 drop table if exists #tempUpdateLead      
 drop table if exists #tempUpdateenq   
  drop table if exists #entities1   

 drop table if exists #changed_values  
   
 IF @mode = 'Update'      
 BEGIN       
 BEGIN TRY    
 create table #changed_values(entity nvarchar(20),entityid bigint,fieldname nvarchar(100),fieldtype nvarchar(20),   
old_value nvarchar(max), new_value nvarchar(max), fieldid bigint)  
 select * into #temp1 from openjson(@updatevalues) with(      
   Rowid Nvarchar(max),      
   fieldID Nvarchar(max),      
   fieldValue Nvarchar(max),      
   fieldName nvarchar(max),      
   tableName nvarchar(max),      
   fieldType nvarchar(max)      
  )
  select * from #temp1
  select * into #Predtemp from #temp1 where fieldtype='Pred'      
  select * into #Custtemp from #temp1 where fieldtype='Cust'      
 
 select * into #entities1 from @entities
select '#Predtemp',* from #Predtemp  
select '#Custtemp',* from #Custtemp  
  
      
   select @updatefields=STRING_AGG(fieldID +' = '''+fieldValue+'''',', ')  from #Predtemp        
  print concat('@updatefields: ',@updatefields    )
  set @tablename = (select  distinct tableName from  #Predtemp  )       
  set @custtablename = (select  distinct tableName from  #Custtemp  )       
    
  declare @f_n nvarchar(100),@f_c int,@m_id int=0,@sql_insert nvarchar(max),@f_v nvarchar(max),@fr_v nvarchar(max),@f_id nvarchar(10)  
  
  if exists(select 1 from #Predtemp)  
  begin  
  select @f_c=count(1) from #Predtemp  
  while @f_c>0  
  begin  
  
  select @m_id=min(rowid) from #Predtemp where rowid>@m_id  
  select @f_n=FieldName,@f_v=fieldvalue,@f_id=fieldid,@sql_insert='' from #Predtemp where rowid=@m_id  
  print 'entered predef change capture for '+ @f_n
  if @f_n in ('sourcename','mediumname','campaignname','assignedto')
  begin
  if try_cast(@f_v as bigint) is not null
  begin
    select @f_v=dbo.fn_getnamefromid(@f_n,try_cast(@f_v as bigint),null)
	print concat('@f_v: ',@f_v)
  end
  end

  select @sql_insert='insert into #changed_values(entity,entityid,fieldtype,fieldname,old_value,new_value)  
  select entity,entityid,''Predefined'','''+@f_n+''','+quotename(@f_n)+','''+@f_v+''' from #entities1 e   
  join '+quotename(@tablename)+' u on e.entityid= '+ case when @tablename='userleads' then ' u.id ' else ' u.enquiryid ' 
end   
    
  print concat('@sql_insert: ',@sql_insert)  
  begin try
  exec sp_executesql @sql_insert
  end try
  begin catch
  exec usp_inserterrorinfo
  end catch
 set @f_c=@f_c-1  
 end  
  end  
  
  
  
  if exists(select 1 from #Custtemp)  
  begin  
  select @f_c=(select count(1) from #Custtemp),@f_n='',@f_v='' ,@m_id=0,@sql_insert=''
  while @f_c>0  
  begin  

  select @m_id=min(rowid) from #Custtemp where rowid>@m_id  
  select @f_n=FieldName,@f_v=fieldvalue,@f_id=fieldid,@sql_insert='' from #Custtemp where rowid=@m_id  
    print 'entered cust change capture for '+ @f_n
  select @sql_insert='insert into #changed_values(entity,entityid,fieldtype,fieldname,old_value,new_value,  
  fieldid)  
  select entity,entityid,''Custom'','''+@f_n+''',fieldvalue,'''+@f_v+''',try_cast('''+cast(@f_id as nvarchar)  
+''' as bigint) from #entities1 e   
  join '+quotename(@custtablename)+' u on e.entityid= '+ case when @custtablename='customfieldleadvalues' then ' u.leadid ' else ' u.enquiryid '  end +  ' where fieldid= '+cast(@f_id as nvarchar)     
  
  print concat('@sql_insert: ',@sql_insert)  
  
  begin try
  exec sp_executesql @sql_insert  
    end try
  begin catch
  exec usp_inserterrorinfo
  end catch
 set @f_c=@f_c-1  
 end  
  end  
  
  select '1_#changed_values',* from #changed_values  
  drop table if exists #output_fieldupdatedid  
  create table #output_fieldupdatedid(fid bigint,entityid bigint)  
  
    
  insert into fieldupdated(tablename,FieldName,Oldvalue,NewValue,fieldid,fu_entityid,fu_entity) output inserted.id,  
  inserted.fu_entityid into #output_fieldupdatedid  
  select case when fieldtype='Predefined' then @tablename when fieldtype='Custom' then @custtablename end,  
  fieldname,old_value,new_value,isnull(fieldid,0),entityid,entity  
  from #changed_values  
  
  drop table if exists #entities  
 create table #entities(entity nvarchar(20),entityid bigint)  
 declare @entitycount int=(select count(1) from @entities),@min_id bigint=0  
  
 while @entitycount>0  
 begin  
  
 insert into #entities(entity,entityid)  
select top 500 entity,entityid from @entities where entityid>@min_id order by entityid  
    
  Set @SQL = case lower(@tablename) when 'userleads' then  'Update '+ @tablename+' set '+@updatefields+' where ID '+ ' in   
(Select entityid from #entities ) '      
            when 'userenquiry' then  'Update '+ @tablename+' set '+@updatefields+' where EnquiryID '+ ' in (Select   
entityid from #entities ) 'end       
         
   print ISNULL(@sql, 'SQL NULL')      
   if @tablename='userleads'    
   begin    
   SET Context_Info 0x55555      
   end    
   else    
   begin    
    SET Context_Info 0x77777    
 end    
     
  Execute sp_executesql @SQL      
   SET Context_Info 0x      
      
         
      
  if LOWER(@custtablename) ='customfieldleadvalue'      
  BEGIN      
   update cflv set cflv.fieldvalue  = cast(cus.fieldvalue as varchar)      
   output 'Lead', inserted.LeadID,'','Custom',cast(deleted.fieldvalue as varchar),cast(inserted.fieldvalue as varchar),inserted.fieldid   
   into #changed_values  
   from #Custtemp cus       
   join customfieldLeadvalue cflv (nolock) on cus.fieldID = cflv.fieldid       
   join #entities lid on cflv.LeadID =lid.entityid       
      
 insert into customfieldLeadvalue (fieldID,LeadID,fieldvalue,CreatedDate)  
 output 'Lead', inserted.LeadID,'','Custom','',cast(inserted.fieldvalue as varchar),cast(inserted.fieldid as varchar)   
   into #changed_values  
  
 select c.fieldid,lid.entityID,cast(cast(c.fieldvalue as varchar(8000)) as sql_variant) ,getdate() from      
 #entities lid join #Custtemp c on 1=1    
 where not exists    
   (select 1 from customfieldLeadvalue (nolock) where LeadID=lid.entityID and fieldID=c.fieldID)    
   END      
  else if LOWER(@custtablename) ='customfieldenquiryvalue'      
  BEGIN      
   update cflv set cflv.fieldvalue  = cast(cus.fieldvalue as varchar)    
   output 'Enquiry', inserted.enquiryid,'','Custom',deleted.fieldvalue,inserted.fieldvalue,'',inserted.fieldid   
   into #changed_values  
   from #Custtemp cus       
   join customfieldEnquiryvalue (nolock) cflv on cus.fieldID = cflv.fieldid       
   join #entities lid on cflv.enquiryid =lid.entityid      
      
   insert into customfieldEnquiryvalue (fieldID,enquiryID,fieldvalue)   
   output 'Enquiry', inserted.EnquiryID,'','Custom','',inserted.fieldvalue,'',inserted.fieldid   
   into #changed_values  
    select c.fieldid,lid.entityID,cast(cast(c.fieldvalue as varchar(8000)) as sql_variant) from      
 #entities lid join #Custtemp c on 1=1    
 where not exists    
   (select 1 from customfieldEnquiryvalue (nolock) where enquiryID=lid.entityID and fieldID=c.fieldID)    
     
  END      
      
 select '#changed_values',* from #changed_values   
    
   INSERT INTO @tbl1 (    
    leadid    
    ,userid    
    ,parentid    
    ,eventdescription    
    ,eventname    
    ,reftable    
    ,refid    
    )    
   SELECT l.entityid    
    ,@userid  
    ,@parentid    
 ,@username+ ' edited '+isnull(dbo.fn_getentityfullname(l.entity,l.entityid),l.entity +' with no name')+' attribute '+l.fieldname+' from "'  
 +isnull(old_value,'')+'" to "'+isnull(new_value,'')+'"'  
    ,l.entity+ ' details edited'   
    ,'fieldupdated'    
    ,o.fid    
   FROM #changed_values l    
   JOIN #output_fieldupdatedid o on o.entityid=l.entityid  
   join #entities e on e.entityid=o.entityid  
 select '@tbl',* from @tbl1    
  
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1    
  
delete from @tbl1  
select @min_id=min(entityid) from #entities  
select @entitycount=@entitycount-500  
truncate table #entities  
end  
  
   
 Select 'Data Updated'      
  
 END TRY      
 BEGIN CATCH      
   SET Context_Info 0x         
exec usp_inserterrorinfo   
 END CATCH      
 END       
       
end      
      
      


GO

