CREATE   PROCEDURE [dbo].[Usp_Update_MassLeadEnquiryFromExcel]   
@userid bigint ,    
@tablename varchar(20) = null,     
@updatevalues nvarchar(max) = null,    
@mode varchar(50) =null,  
@TotalCount int =null,  
@filename nvarchar(200) = null  
  
as  
 BEGIN  
  
 declare @jsonmin int, @jsonmax int,  @data nvarchar(max),@min int,@max int   
 declare @parentid bigint = (Select parentid from User_Detail (NOLOCK) where user_id =@userid), @ImportID bigint  
 declare @filter nvarchar(max), @fieldname nvarchar(max), @fieldvalue nvarchar(4000), @leadid bigint, @sql nvarchar(max), @custfieldid bigint , @Sno int  
		,@datatype nvarchar(5),@minvalue nvarchar(500),@maxvalue nvarchar(500),@choices nvarchar(max), @resRemarks nvarchar(max)='', @RowttlCnt bigint=0
		,@CustomfieldCnt bigint =0 ,@FilterExp nvarchar(200)
Declare @Priority numeric(18,2)=1    

drop table if exists #Jsontemp   
drop table if exists #ResTemp

Create table #ResTemp (Sno int , FieldName varchar(100), Remarks varchar(max)) 

Create table  #Jsontemp ( RowId int identity(1,1),Jsondata varchar(max))  

  
  if @mode = 'fields'    
 begin    
    Select 'SNo' FieldID,'SNo'FieldName, '' TABLE_NAME, '' FieldType  
 Union all  
 Select COLUMN_NAME FieldID, COLUMN_NAME FieldName, TABLE_NAME, 'Pred' FieldType  from INFORMATION_SCHEMA.COLUMNS     
  where TABLE_NAME=@tablename and TABLE_CATALOG =DB_Name() and COLUMN_NAME NOT IN ('ID', 'MobileNo1', 'MobileNo2',  'EmailID1', 'EmailID2', 'CountryCode1', 'CountryCode2',    
  'ParentID', 'FollowUpStatus', 'NextStatusDate','Products', 'AmountPaid', 'CreatedOn', 'CreatedBy', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName',    
  'enquirysource', 'WhatsAppNoColName', 'LastFollowupCreatedBy', 'whereAddress', 'latitude', 'longitude', 'LastFollowupCreatedOn','IsduplicateEmail', 'IsduplicateMobile')    
  UNION ALL     
  Select cast(field_id as varchar) FieldID, fieldname FieldName,     
  CASE @tablename when 'UserEnquiry' THEN 'customfieldEnquiryvalue' when 'UserLeads' THEN 'customfieldleadvalue' END    
  TABLE_NAME, 'Cust' FieldType from customfields (NOLOCK) where parentid = @parentid and isActive=1 and datatype!='f'    
    
 end   
 else if @mode ='UpdateLead'  
 begin   

   select @Priority=cast(@TotalCount as float)/100

  Insert into Tbl_Lead_LeadUpdateImportData (ImportData, User_Id,TotalRecords, ImportFilename,Priority)  
   values(@updatevalues,@userid,@TotalCount,@filename,@Priority )  
  
 
  Select 'Uploaded Successfully' [Status], @ImportID ImportID  
 end  


 else if @mode ='UpdateEnquiry'  
 begin   
  
   select @Priority=Cast(@TotalCount as float)/100
  Insert into Tbl_Enquiry_EnquiryUpdateImportData (ImportData, User_Id,TotalRecords, ImportFilename,Priority)  
   values(@updatevalues,@userid,@TotalCount,@filename,@Priority )  
 

  Select 'Uploaded Successfully' [Status], @ImportID ImportID  
 end  

 END  



