/* ============================================================
   Procedure: [dbo].[USP_UPDATE_MESSAGEDELIVERYSTATUSTEMP]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_UPDATE_MESSAGEDELIVERYSTATUSTEMP        
AS        
SELECT [MESSAGEID],[RECIPIENT],[SENDER],[SENT_ON],[RECEIVED_ON],ST.[STATUS],[REASON_OF_FAILURE],USERTAG INTO #TEMP        
FROM [MYSMS].[DBO].[SUBMIT_DETAIL_REFERENCE] SD(NOLOCK) JOIN [MYSMS].[DBO].[TBL_INSERTEXCELFILE] ST(NOLOCK)        
ON SD.[REFERENCE]=ST.MESSAGEID;        
        
WITH T1 AS (SELECT USERTAG, ROW_NUMBER()OVER (PARTITION BY [USERTAG] ORDER BY [USERTAG])        
AS NUMBER FROM #TEMP(NOLOCK) )DELETE FROM T1 WHERE NUMBER >1        
        
UPDATE MD SET MESSAGEREFID=SD.MESSAGEID,MESSAGESTATUS=SD.[STATUS] FROM [MYSMS].[DBO].MESSAGEDELIVERYSTATUSTEMP MD(NOLOCK) JOIN #TEMP SD(NOLOCK)      ON RIGHT(MD.MESSAGEID,6)=SD.USERTAG AND  MD.MOBILE=SD.[RECIPIENT]     
      
UPDATE MD SET MD.MESSAGESTATUS=TMP.MESSAGESTATUS,MD.MESSAGEREFID=TMP.MESSAGEREFID FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUS] MD(NOLOCK)       
JOIN [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP] TMP(NOLOCK)      
ON MD.MESSAGEID=TMP.MESSAGEID      
        
DROP TABLE #TEMP


GO

