/* ============================================================
   Procedure: [dbo].[usp_update_territory_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- usp_update_territory_details 'Test','Test','28331`kartikgupta`User|',22701,27701 
CREATE   PROC usp_update_territory_details
(      
@Name    varchar(100),      
@Description  varchar(500),      
@PersonDetail  varchar(max),   
@OldName    varchar(100),     
@ParentID   bigint,      
@CreatedBy   bigint      
)      
as begin      
Declare @TerritoryID bigint  
Declare @OldTerritoryID bigint      
      
if exists(select * from tbl_location_territory where Name = @OldName and ParentID = @ParentID)          
begin   
set @TerritoryID =   (select ID from tbl_location_territory where Name = @OldName and ParentID = @ParentID)      
Delete from  tbl_location_territory_mapping where Territory_Id = @TerritoryID  
end      
      
update tbl_location_territory  
set Name = @Name, Description = @Description, CreatedBy = @CreatedBy, CreatedOn = getdate()  
where Name = @OldName and ParentID = @ParentID  
      
--set @TerritoryID = SCOPE_IDENTITY()      
      
create table #temp123              
(columnname varchar(500))              
insert into #temp123              
select * from dbo.SplitString(@PersonDetail,'|')              
DECLARE @delimiter VARCHAR(50)              
SET @delimiter='`'               
;WITH CTE AS              
(               
    SELECT              
        CAST('<M>' + REPLACE(columnname, @delimiter , '</M><M>') + '</M>' AS XML)               
        AS [columnname XML]              
    FROM  #temp123              
)        
            
insert into tbl_location_territory_mapping (Territory_Id,User_ID,PersonName,Role)              
SELECT @TerritoryID as Territory_Id,      
  [columnname XML].value('/M[1]', 'bigint') As User_ID,      
     [columnname XML].value('/M[2]', 'varchar(50)') As PersonName,              
     [columnname XML].value('/M[3]', 'varchar(50)') As Role               
FROM CTE              
drop table #temp123         
delete from tbl_location_territory_mapping where User_ID = 0 and Territory_Id = @TerritoryID      
select @TerritoryID     
end      



GO

/* ============================================================
   Procedure: [dbo].[usp_update_TradeIndia_validData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_update_TradeIndia_validData] --97           
@TradeIndia_ID bigint = null            
as            
begin    
         
declare @i bigint=(select isnull(max(ID),1) from TradeIndiaData where isvalid=1)        
declare @c int=(select COUNT(1) from TradeIndiaData(nolock) where ID>=case when @TradeIndia_ID is null then @i else @TradeIndia_ID end)        
declare @ii bigint=(select isnull(MIN(id),1) from TradeIndiaData(nolock) where ID>=case when @TradeIndia_ID is null then @i else @TradeIndia_ID end)        
while @c>0        
begin        
update i set isvalid=1 from TradeIndiaData i left join m_country1 m on ltrim(rtrim(m.Country_Name))=ltrim(rtrim(i.sender_country))          
where ((i.sender_mobile <>'' and isnumeric(REPLACE(i.sender_mobile,ltrim(rtrim(m.CountryCode)),''))=1) or isnull(nullif(ltrim(rtrim(i.sender_email)),'null'),'')<>'' or (i.sender_other_mobiles<>'' and isnumeric(    
         REPLACE(i.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),''))=1) or isnull(nullif(ltrim(rtrim(i.sender_other_emails)),'null'),'')<>'') and i.ID=@ii        
set @ii=@ii+1        
set @c=@c-1        
end        
end


GO

