   Procedure: [dbo].[usp_update_user_reseller_status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_update_user_reseller_status --10043,5013,1      
(@m_id bigint,      
@userid int,            
@status int)            
as            
Begin            
Declare @type int            
Declare @Reseller bigint            
select @type=[type],@Reseller=M_ID from user_detail where user_id=@userid            
           
IF @type=0            
BEGIN            
update user_detail set status=@status where user_id=@userid            
select 'User Status Updated Successfully'            
End            
ELSE            
BEGIN            
declare @rowcount bigint            
select @Reseller=reseller_id from reseller_detail where user_id=@userid            
Declare @Tempval bigint            
set @rowcount=0            
Declare @Temptable table            
(            
reseller bigint            
)            
           
Declare @TemptableAll table            
(            
reseller bigint            
)            
           
Declare @TemptableTemp table            
(            
reseller bigint            
)            
insert into @Temptable            
select @Reseller            
insert into @TemptableAll            
select @Reseller            
           
Begin            
while @rowcount<50            
Begin            
print @rowcount            
           
insert into @TemptableAll            
select reseller_id from reseller_detail where m_id in            
( select reseller from @Temptable)            
           
insert into @TemptableTemp            
select reseller_id from reseller_detail where m_id in            
( select reseller from @Temptable)            
           
delete from @Temptable            
           
insert into @Temptable            
select * from @TemptableTemp            
set @Tempval=@@rowcount            
           
delete from @TemptableTemp            
           
set @rowcount=@rowcount+1            
if @Tempval=0            
Begin            
break            
End            
END            
-- select * from @TemptableAll order by reseller asc          
update user_detail set status=@status where user_id=@userid           
update user_detail set status=@status where M_ID IN            
(SELECT reseller FROM @TemptableAll)            
select 'User Status Updated Successfully'            
End            
END            
END



GO

