--Dependency of this usp_Update_WA_CommerceCOntactInfo

--1.MySMSConversations.dbo.channeltokens       -- called by clr
--2. MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock)  -- called by clr


-------------------------------------

CREATE   PROCEDURE [dbo].[usp_Update_WA_CommerceCOntactInfo] (    
 @WACommerceContactId BIGINT NULL = 0   
 ,@CompanyName [varchar](300)  
 ,@Address [varchar](400)  
 ,@CompanyType [varchar](50)  
 ,@CustomerCareName [varchar](50)  
 ,@CustomerCareMobileNo [varchar](30)  
 ,@CustomerCareLandLine [varchar](30)  
 ,@CustomerCareEmailId [varchar](100)  
 ,@GrievanceOfficerName [varchar](50)  
 ,@GrievanceOfficerMobileNo [varchar](30)  
 ,@GrievanceOfficerLandLine [varchar](30)  
 ,@GrievanceOfficerEmailId [varchar](100)  
 ,@UserId [bigint] NULL    
 ,@ParentId [bigint] NULL    
 ,@CreatedBy BIGINT = NULL   
 )    
AS    
SET NOCOUNT ON    
    
BEGIN TRY  
 BEGIN   
 DECLARE @existsFlag INT

DECLARE @sqlquery NVARCHAR(MAX)
  IF (@WACommerceContactId > 0)    
  BEGIN    
-- if exists(select CompanyType from MySMSConversations.dbo.channeltokens (nolock) where ParentId = @ParentId and ChannelId = 2)  
SET @sqlquery = '
    SELECT TOP 1 1 
    FROM channeltokens (NOLOCK) 
    WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ' AND ChannelId = 2
'

EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @existsFlag OUTPUT

IF @existsFlag > 0
  Begin  
   --update MySMSConversations.dbo.channeltokens set company_name = @CompanyName , address = @Address, CompanyType = @CompanyType where ChannelId = 2 and ParentId = @ParentId
   SET @sqlquery = '
    UPDATE channeltokens
    SET company_name = ''' + REPLACE(@CompanyName, '''', '''''') + '''~
        address = ''' + REPLACE(@Address, '''', '''''') + '''~
        CompanyType = ''' + REPLACE(@CompanyType, '''', '''''') + '''
    WHERE ChannelId = 2 AND ParentId = ' + CAST(@ParentId AS NVARCHAR) + '
'

EXEC usp_clr_ExecuteRemoteQuery @sqlquery
   print 'address'
  End
  
   UPDATE tbl_WA_CommerceCOntactInfo    
   SET CompanyName = @CompanyName  
,CustomerCareName = @CustomerCareName  
,CustomerCareMobileNo = @CustomerCareMobileNo  
,CustomerCareLandLine = @CustomerCareLandLine  
,CustomerCareEmailId = @CustomerCareEmailId  
,GrievanceOfficerName = @GrievanceOfficerName  
,GrievanceOfficerMobileNo = @GrievanceOfficerMobileNo  
,GrievanceOfficerLandLine = @GrievanceOfficerLandLine  
,GrievanceOfficerEmailId = @GrievanceOfficerEmailId  
,UserId = @UserId    
,ParentId = @ParentId    
,ModifiedBy = @CreatedBy  
,ModifiedDate = GETDATE()    
 WHERE WACommerceContactId = @WACommerceContactId  
    
   /*SELECT 'Updated Successfully.' STATUS, (select top 1 LifeTimeAccessToken from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) token, (select top 1 ConnType from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) ConnType, (select top 1 token from MySMSConversations.dbo.channeltokens(nolock) where parentid = @ParentId) whatsapp360token*/
  

     -- Store the query in the @sqlquery variable
     SET @sqlquery = '
     SELECT 
         ''Updated Successfully.'' AS STATUS, 
         (SELECT TOP 1 LifeTimeAccessToken 
          FROM tbl_WA_ProductCatalogeType WITH (NOLOCK) 
          WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS token, 
         (SELECT TOP 1 ConnType 
          FROM tbl_WA_ProductCatalogeType WITH (NOLOCK) 
          WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS ConnType, 
         (SELECT TOP 1 token 
          FROM channeltokens WITH (NOLOCK) 
          WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS whatsapp360token';
     
     -- Execute the SQL using CLR method to fetch the data
     EXEC usp_clr_GetRemoteData @sqlquery;

  END    
  ELSE    
  BEGIN    
 --if exists(select CompanyType from MySMSConversations.dbo.channeltokens (nolock) where ParentId = @ParentId and ChannelId = 2)  
 -- BEGIN    
 --    update MySMSConversations.dbo.channeltokens set company_name = @CompanyName , address = @Address, CompanyType = @CompanyType where ChannelId = 2 and ParentId = @ParentId  
 --  print 'address'
 -- End
  
 -- insert tbl_WA_CommerceCOntactInfo (CompanyName, CustomerCareName, CustomerCareMobileNo, CustomerCareLandLine, CustomerCareEmailId, GrievanceOfficerName, GrievanceOfficerMobileNo, GrievanceOfficerLandLine, GrievanceOfficerEmailId, UserId, ParentId, CreatedBy, ModifiedBy, CreatedDate, ModifiedDate) 
 --  values(@CompanyName, @CustomerCareName, @CustomerCareMobileNo, @CustomerCareLandLine, @CustomerCareEmailId, @GrievanceOfficerName, @GrievanceOfficerMobileNo, @GrievanceOfficerLandLine, @GrievanceOfficerEmailId, @UserId, @ParentId, @CreatedBy, @CreatedBy, GETDATE(), GETDATE())
    
 --  SELECT 'Saved Successfully.' STATUS, (select top 1 token from MySMSConversations.dbo.channeltokens(nolock) where parentid = @ParentId) token    

  /* SELECT 'Error in Update.' STATUS, (select top 1 LifeTimeAccessToken from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) token, (select top 1 ConnType from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) ConnType, (select top 1 token from MySMSConversations.dbo.channeltokens(nolock) where parentid = @ParentId) whatsapp360token*/
        SET @sqlquery = '
      SELECT 
          ''Error in Update.'' AS STATUS, 
          (SELECT TOP 1 LifeTimeAccessToken 
           FROM tbl_WA_ProductCatalogeType WITH (NOLOCK) 
           WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS token, 
          (SELECT TOP 1 ConnType 
           FROM tbl_WA_ProductCatalogeType WITH (NOLOCK) 
           WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS ConnType, 
          (SELECT TOP 1 token 
           FROM channeltokens WITH (NOLOCK) 
           WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS whatsapp360token';
      
      -- Execute the SQL using CLR method to fetch the data
      EXEC usp_clr_GetRemoteData @sqlquery;
  END    
 END    
END TRY    
    
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    
    
DECLARE @rowJson NVARCHAR(MAX) = (    
  SELECT *    
  FROM tbl_WA_CommerceCOntactInfo   WITH(NOLOCK)    
  WHERE WACommerceContactId = @WACommerceContactId  
  FOR JSON AUTO    
   ,INCLUDE_NULL_VALUES    
  )    
    
IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'updt_WA_CommerceContactInfo'    
  ,@ActionType = 'U'   
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_WA_CommerceCOntactInfo'    
END    



