/* ============================================================
   Procedure: [dbo].[usp_updateAcres99validleads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updateAcres99validleads]      
@Accres99_id bigint = null      
as      
begin   

  
declare @i bigint=(select max(ID) from Acres99_Leads where isvalid=1)  
declare @c int=(select COUNT(1) from Acres99_Leads(nolock) where ID>=case when @Accres99_id is null then @i else @Accres99_id end)  
declare @ii bigint=(select MIN(id) from Acres99_Leads(nolock) where ID>=case when @Accres99_id is null then @i else @Accres99_id end)  
while @c>0  
begin  
update i set isvalid=1 from Acres99_Leads i 
      where ((isnull(nullif(i.Phone,'null'),'') <> '')  
	       or ( isnull(nullif(i.Email,'null'),'') <> '' ))
		   and i.ID = @ii 

 set @ii=@ii+1  
 set @c=@c-1  


end  
end


GO

