   Procedure: [dbo].[Usp_UpdateAgentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
/**************************    
Created by : Santosh Kumar    
Date : 08-05-2017 04:45 PM    
        
This SP is Used to update Agent Details        
************************/        
CREATE   PROC Usp_UpdateAgentDetails   
(  
  
@AgentID Bigint,  
@AgentName nvarchar(50),  
@Password nvarchar(50),  
@UserName nvarchar(50),  
@Mobile nvarchar(20),  
@EmailID nvarchar(50),  
@IsActive tinyint,  
@ModifyBy nvarchar(50)   
  
)       
AS        
Begin   
     If not exists (select 'x' from CreditAgent where Agent = @AgentName and Id <> @AgentID)  
     Begin  
        update CreditAgent set Agent = @AgentName,Password = @Password,UserName =@UserName,mobile = @Mobile,EmailID =@EmailID,IsActive = @IsActive,ModifiedDate=GETDATE(),ModifiedBy = @ModifyBy where Id = @AgentID     
       
     select 'Updated Successfully'      
     end  
  
     Else  
       
     Begin  
          select 'Already Exists'  
     End  
       
         
End  
  
  


GO

