/* ============================================================
   Procedure: [dbo].[Usp_UpdateAllSmpp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateAllSmpp] --2,1,'TransBulk' 
@CurrentQueue varchar(2), 
@NextPush varchar(2), 
@Account nvarchar(20) 
as 
begin 
 if(@Account='PromoDemo') 
 begin 
 update MessageQueueTwo set smppid=@CurrentQueue 
 update user_detail set smppid=@NextPush where (smppid=4 or smppid=7) 
 update CloneMessageDeliveryStatus set smppid=@NextPush where (smppid=4 or smppid=7) 
 update CloneMessageDeliveryStatusLess set smppid=@NextPush where (smppid=4 or smppid=7) 
 end 
 else if(@Account='TransDemo') 
 begin 
 update MESSAGEQUEUEDEMO_TRANS set smppid=@CurrentQueue 
 update user_detail set smppid=@NextPush where (smppid=5 or smppid=8) 
 update CloneMessageDeliveryStatus set smppid=@NextPush where (smppid=5 or smppid=8) 
 update CloneMessageDeliveryStatusLess set smppid=@NextPush where (smppid=5 or smppid=8) 
 end 
 else if(@Account='TrcDemo') 
 begin 
 update MESSAGEQUEUEDEMO_TRC set smppid=@CurrentQueue 
 update user_detail set smppid=@NextPush where (smppid=6 or smppid=9) 
 update CloneMessageDeliveryStatus set smppid=@NextPush where (smppid=6 or smppid=9) 
 update CloneMessageDeliveryStatusLess set smppid=@NextPush where (smppid=6 or smppid=9) 
 end 
 else if(@Account='PromoBulk') 
 begin 
 update mysmstrans.dbo.MessageQueueProRoute set smppid=@CurrentQueue 
