/* ============================================================
   Procedure: [dbo].[usp_UpdateBankDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_UpdateBankDetails]          
@referid int,      
@BankName nvarchar(100),      
@Branch nvarchar(100),      
@IFSC_Code nvarchar(20),      
@AccountNo bigint,      
@AccountType nvarchar(20),      
@AccountName nvarchar(100),      
@password nvarchar(20)      
as          
begin       
if exists(select 1 from Referrer_Details where ID=@referid and PWD COLLATE SQL_Latin1_General_CP1_CS_AS=@password)       
begin      
if exists(select 1 from Referrer_Bank_Details where ReferrerID=@referid and status=1)      
begin      
update Referrer_Bank_Details set status=0,LastModified=getdate() where ReferrerID=@referid      
insert into Referrer_Bank_Details(ReferrerID,BankName,Branch,IFSC_Code,AccountNo,AccountType,AccountName,DateCreated,status)      
select @referid,@BankName,@Branch,@IFSC_Code,@AccountNo,@AccountType,@AccountName,DateCreated=GETDATE(),1      
exec usp_updateuseractivity @referid,'BankDetailsUpdated',0      
  
select 'Action performed succesfully'  
  
end  
else  
Begin  
insert into Referrer_Bank_Details(ReferrerID,BankName,Branch,IFSC_Code,AccountNo,AccountType,AccountName,DateCreated,status)      
select @referid,@BankName,@Branch,@IFSC_Code,@AccountNo,@AccountType,@AccountName,DateCreated=GETDATE(),1      
exec usp_updateuseractivity @referid,'BankDetailsUpdated',0      
  
select 'Action performed succesfully'      
  End      
end      
else      
begin      
select 'You have entered a wrong password, pl retry'      
end      
end


GO

