/* ============================================================
   Procedure: [dbo].[usp_UpdateBannerOnMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdateBannerOnMode](
@userId bigint,
@Id bigint,
@mode nvarchar(100),
@JsonData nvarchar(max)=null
)
as
begin
--declare @userId bigint=335,
--		@Id bigint=1008,
--		@mode nvarchar(100)='dismissable',
--		@JsonData nvarchar(max)=N'{"Id":0,"BannerName":"","Content":"","BannerType":"","BannerBg":"","DismissOption":false,"IsActive":true,"BannerBehaviour":"showalltime","Disappearafter":"","DisappearafterUnit":"","DisplayTimer":true}'

declare  @parentId bigint,@DisappearTime nvarchar(100),@DisappearTimeUnit nvarchar(100), @DismissOption bit,@IsActive bit,
@status int=0, @message nvarchar(max)='Unable to process to your request please contact admin or support team.'
begin try
select @parentId=ParentId from User_Detail where user_Id=@userId
if(@JsonData!='')
begin
	SET @DisappearTime = JSON_VALUE(@JsonData, '$.Disappearafter');
	SET @DisappearTimeUnit = JSON_VALUE(@JsonData, '$.DisappearafterUnit');
	SET @DismissOption = JSON_VALUE(@JsonData, '$.DismissOption');
		SET @IsActive = JSON_VALUE(@JsonData, '$.IsActive');

end
if(@mode='delete')
begin
if exists(select 1 from tbl_Banner_Details(nolock) where ID=@Id and ParentId=@parentId)
begin
update tbl_Banner_Details set IsDelated =1 , DeletedBy=@userId, Isactive=0 where ID=@Id and ParentId=@parentId
 return select @status=1, @message='Delete Successfully'
 end
 else
 begin
  select @status=0, @message='Invalid Request'
 end
end
if(@mode='changeTime')
begin
if exists(select 1 from tbl_Banner_Details(nolock) where ID=@Id and ParentId=@parentId)
begin
update tbl_Banner_Details set @DisappearTimeUnit=@DisappearTimeUnit,DisappearTime=@DisappearTime, LastModifiedDate=getdate() where ID=@Id and ParentId=@parentId 
 select @status=1, @message='Change Time Successfully'
 end
 else
 begin
  select @status=0, @message='Invalid Request'
 end
end
if(@mode='dismissable')
begin
print @DismissOption
if exists(select 1 from tbl_Banner_Details(nolock) where ID=@Id and ParentId=@parentId)
begin
update tbl_Banner_Details set DismissOption =@DismissOption, LastModifiedDate=getdate() where ID=@Id and ParentId=@parentId
 select @status=1, @message='Dismissable Successfully'
 end
 else
 begin
  select @status=0, @message='Invalid Request'
 end
end
if(@mode='status')
begin
print @DismissOption
if exists(select 1 from tbl_Banner_Details(nolock) where ID=@Id and ParentId=@parentId)
begin
update tbl_Banner_Details set IsActive =@IsActive, LastModifiedDate=getdate() where ID=@Id and ParentId=@parentId
 select @status=1, @message='Update status successfully'
 end
 else
 begin
  select @status=0, @message='Invalid Request'
 end
end
end try
begin catch
 select @status=0, @message='Unable to process to your request please contact admin or support team.'
end catch
select @status as status, @message as message
end


GO

