/* ============================================================
   Procedure: [dbo].[Usp_UpdateBatchInfos]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateBatchInfos
(
    @tbl1  [tbl_BatchIDs]  readonly 
   ,@tbl2  [tbl_BatchIDs]  readonly  
)
as
begin   
	
	       update b set b.TotalProcessed = isnull(b.TotalProcessed,0) + isnull(t.[Count],0) from         
                BatchEmail_Infos as B with(nolock)
	       join (select ti.[Mail_BatchID] , ti.[Count] from @tbl1 as ti)  as t
		   on B.BatchID = t.[Mail_BatchID]
          
		   update b1 set b1.IsProcess=1,b1.BatchProcessTime=GETDATE() from BatchEmail_Infos as b1 with(nolock)        
			         where b1.BatchID in ( select ti.[Mail_BatchID]  from @tbl2 as ti )
					 and b1.TotalProcessed>=b1.TotalRecords 
		
end



GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateBatchInfos_WithJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateBatchInfos_WithJson    
(    
   -- @tbl1  [tbl_BatchIDs]  readonly     
   --,@tbl2  [tbl_BatchIDs]  readonly    
     
   @tbl1_Json nvarchar(max)=null,  
   @tbl2_Json nvarchar(max)=null      
)    
as    
begin       
  
   -- DECLARE @tbl1_Json nvarchar(max)='[{"Mail_BatchID":"135987638","Count":1000}]',  
   --@tbl2_Json nvarchar(max)=null          
      
 drop table if exists  #innerTemp1   
 drop table if exists  #innerTemp2  
   
 create table #innerTemp1  
     (  
     Mail_BatchID nvarchar(50)    
        ,[Count] int  
  )  
  
    create table #innerTemp2  
     (  
     Mail_BatchID nvarchar(50)    
        ,[Count] int  
  )  
       
  
  
 if isnull(@tbl1_Json,'')<>''  
 begin  
  insert into #innerTemp1  
   (Mail_BatchID,[Count])  
     SELECT Mail_BatchID,[Count]     
      FROM OPENJSON(@tbl1_Json)  
   with(  
        Mail_BatchID nvarchar(50)    
        ,[Count] int   
   )  
     
   --SELECT * FROM #innerTemp1  
    update b set b.TotalProcessed = isnull(b.TotalProcessed,0) + isnull(t.[Count],0) from             
                BatchEmail_Infos as B with(rowlock)    
        join (select ti.[Mail_BatchID] , ti.[Count] from #innerTemp1 as ti)  as t    
     on B.BatchID = t.[Mail_BatchID]    
      
   end  
     
  
   if isnull(@tbl2_Json,'')<>''  
 begin  
  insert into #innerTemp2  
   (Mail_BatchID,[Count])  
     SELECT Mail_BatchID,[Count]     
      FROM OPENJSON(@tbl2_Json)  
   with(  
        Mail_BatchID nvarchar(50)    
        ,[Count] int   
   )  
     
   update b1 set b1.IsProcess=1,b1.BatchProcessTime=GETDATE() from BatchEmail_Infos as b1 with(rowlock)            
            where b1.BatchID in ( select ti.[Mail_BatchID]  from #innerTemp2 as ti )    
      and b1.TotalProcessed>=b1.TotalRecords     
      
  
  end  
  
              
       
 drop table if exists  #innerTemp1   
 drop table if exists  #innerTemp2  
  
end 


GO

