/* ============================================================
   Procedure: [dbo].[usp_UpdateBatchStartTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_UpdateBatchStartTime  
    @BatchID BIGINT  
   -- @BatchStartTime DATETIME  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Start a transaction  
        BEGIN TRANSACTION;  
  
        -- Update tbl_massoperationSummary  
        UPDATE tbl_massoperationSummary  
        SET BatchStartTime = GETDATE()  
        WHERE BatchID = @BatchID;  
  
        -- Commit the transaction  
        COMMIT TRANSACTION;  
    END TRY  
    BEGIN CATCH  
        -- Rollback the transaction in case of an error  
        ROLLBACK TRANSACTION;  
  
        -- Capture the error details  
        DECLARE @ErrorMessage NVARCHAR(4000), @ErrorSeverity INT, @ErrorState INT;  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
        -- Rethrow the error  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH  
END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_updateButtonDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updateButtonDetails    
(    
    @UserId bigint,   
    @UserType NVARCHAR(MAX),  
    @ButtonId bigint,    
    @ButtonName nvarchar(100),    
    @ButtonDescription nvarchar(max),    
    @PlaceOnPage nvarchar(100),    
    @ModuleCode varchar(100),    
    @ActionBePerform nvarchar(100),    
    @ActionDetails nvarchar(max),    
    @ButtonDisposition nvarchar(100) = null,    
    @WebhookId bigint = null,    
    @ErrorMessage nvarchar(max) OUTPUT    
)    
AS    
BEGIN    
    SET NOCOUNT ON;    
    
    BEGIN TRY    
        -- Update data in tbl_CB_CustomButtons table    
        UPDATE tbl_CB_CustomButtons    
        SET ButtonName = @ButtonName,    
            ButtonDescription = @ButtonDescription,    
            PlaceOnPage = @PlaceOnPage,    
            ModuleCode = @ModuleCode,    
            ActionBePerform = @ActionBePerform,    
            ActionDetails = @ActionDetails,    
            ButtonDisposition = @ButtonDisposition,    
            WebhookId = @WebhookId,  
            UserType = @UserType  
        WHERE ButtonId = @ButtonId;    
    
        -- Check if any row was updated in tbl_CB_CustomButtons    
        IF @@ROWCOUNT = 0    
        BEGIN    
            SET @ErrorMessage = 'No record found with the given ButtonId.';    
            RETURN;  -- Exit if no update in tbl_CB_CustomButtons    
        END    
    
        -- Update data in Tbl_CB_WebhookSummary if WebhookId is provided    
        IF @WebhookId IS NOT NULL    
        BEGIN    
            UPDATE Tbl_CB_WebhookSummary    
            SET ModuleCode = @ModuleCode, WebhookURL=@ActionDetails   
            WHERE WebhookId = @WebhookId;    
    
            -- Check if any row was updated in Tbl_CB_WebhookSummary    
            IF @@ROWCOUNT = 0    
            BEGIN    
                SET @ErrorMessage = 'No record found with the given WebhookId in Tbl_CB_WebhookSummary.';    
                RETURN;  -- Exit if no update in Tbl_CB_WebhookSummary    
            END    
        END    
    
        -- Set success message    
        SET @ErrorMessage = 'Data updated successfully.';    
    
    END TRY    
    BEGIN CATCH    
        -- Rollback transaction if error occurs    
        IF @@TRANCOUNT > 0    
            ROLLBACK;    
    
        -- Get error message    
        SET @ErrorMessage = ERROR_MESSAGE();    
    END CATCH    
END;


GO

