CREATE   PROCEDURE [dbo].[usp_updatecallanswered]  
(@uniqueid nvarchar(50),  
@puniqueid nvarchar(50),  
@agentno nvarchar(50),  
@id bigint  
)  
as  
begin
declare @now datetime=getdate(),@rows int,@k_id bigint
begin try
insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid,p_uniqueid)  
select 'UPDATE TOP (1) Kit19CallsDialled SET call_answer_time = cast('''+cast(getdate() as nvarchar)+''' as datetime),dialstatus=''ANSWER'',uniqueid = '''+cast(@uniqueid as nvarchar(50))+''',updateevent=''P'' WHERE puniqueid= '''+cast(@puniqueid as nvarchar(50))+''' and id=case when callerid like ''%local/%'' and exists (select top 1 id from Kit19CallsDialled where puniqueid= '''+cast(@puniqueid as nvarchar(50))+''' and dbo.fn_getagent(callerid)= '''+cast(@agentno as nvarchar(50))+''' ) then   
(select top 1 id from Kit19CallsDialled where puniqueid= '''+cast(@puniqueid as nvarchar(50))+''' and dbo.fn_getagent(callerid)= '''+cast(@agentno as nvarchar(50))+''' ) else '+cast(@id as nvarchar)+' end',@uniqueid,@puniqueid
select @k_id=SCOPE_IDENTITY()
RETRY:
begin try
UPDATE TOP (1) Kit19CallsDialled SET call_answer_time = @now,dialstatus='ANSWER',uniqueid = @uniqueid,updateevent='P' WHERE puniqueid= @puniqueid and id=case when callerid like '%local/%' then   
(select top 1 id from Kit19CallsDialled where puniqueid= @puniqueid and dbo.fn_getagent(callerid)= @agentno ) else @id end
select @rows=@@ROWCOUNT
if @rows>0
begin
update Kit19FailedIVRQuery set IsProcess=1,ProcessedTime=GETDATE() where ID=@k_id
end
end try                                  
begin catch                             
declare @errorno int=ERROR_NUMBER()                        
exec usp_inserterrorinfo                                  
IF @errorno = 1205 -- Deadlock Error Number                                               
BEGIN                                          
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                          
GOTO RETRY -- Go to Label RETRY                                          
END                                                                                     
end catch
end try
begin catch
exec usp_InsertErrorInfo
end catch
end


GO

/* ============================================================
   Procedure: [dbo].[usp_updatecallendtime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatecallendtime] --'ns-1719675570.1656248-0-0-Main' --'1614156327.86156-25-25-Sub' --'1612531119.1394532'--'1612530525.1394376' --'1606995789.3993493'-- '1'                                
(@UniqueidDurLeg nvarchar(500))                                
as                                
begin                    
--declare @UniqueidDurLeg nvarchar(500)                            
declare @cid bigint                      
insert into calldurasperuniqueid(fullexp)                      
select    @UniqueidDurLeg                      
select @cid=SCOPE_IDENTITY()                      
                          
declare @uniqueid varchar(100),@dur int,@dur0 int,@leg nvarchar(10),@agentnumber nvarchar(50),@kit19callsid bigint                            
select * into #values from dbo.fn_split(replace(@uniqueiddurleg,'ns-',''),'-')                            
select @uniqueid=case when left(@uniqueiddurleg,3)='ns-' then 'ns-'+value else value end from #values where position=1                            
select @dur=cast(value as int) from #values where position=2                            
select @dur0=cast(value as int) from #values where position=3                            
select @leg=value from #values where position=4                        
select @agentnumber=value from #values where position=5  
if @agentnumber like '00%'
begin
select top 1 @agentnumber=mobile from [dbo].[fn_separatecountrycodeandmobile](@agentnumber)
end
select @kit19callsid=id from kit19calls(nolock) where uniqueid=@uniqueid                      
update calldurasperuniqueid set duration=@dur,billduration=@dur0,uniqueid=@uniqueid,agentnumber=@agentnumber where id=@cid                      
                       
print @dur           
    
    
    
    
if @dur>0 --and @agentnumber is not null                        
begin                        
print @dur + '1'                      
declare @answered int=0                        
if @agentnumber is not null and exists(select 1 from kit19callsdialled(nolock) where puniqueid=@uniqueid and (call_answer_time is not null or dialstatus='answer') and dbo.fn_trim0prefix(agentnumber)=dbo.fn_trim0prefix(@agentnumber))                      
set @answered=1                      
                       
if @answered=1                         
begin                            
print @dur + '2'                      
end                         
end  
  
--else                        
begin                        
declare @cet datetime=getdate(),@cet1 datetime=getdate()--,@dur1 int,@dur2 int                              
update kit19calls set calleridname='b',call_end_time=@cet  where uniqueid=@uniqueid and @leg='main' --and @dur>0    
begin try    
exec usp_updatecalllog_withreftable 'kit19calls',@kit19callsid     
end try    
begin catch    
exec usp_inserterrorinfo    
end catch    
update kit19callsdialled set call_end_time=@cet where puniqueid=@uniqueid and dialstatus<>'answer' and @agentnumber is not null                                                     
end    
print 'calling usp_updatecallendtimeDur_agent'    
exec usp_updatecallendtimeDur_agent @uniqueid,@dur,@leg,@agentnumber                            
end 




--select * from calldurasperuniqueid (nolock) where uniqueid='ns-1726505537.13'
--select f.mobile from calldurasperuniqueid (nolock)
--cross apply
--[dbo].[fn_separatecountrycodeandmobile](agentnumber) f where uniqueid='ns-1726505537.13'



GO

/* ============================================================
   Procedure: [dbo].[usp_updatecallendtime_earlierrecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatecallendtime_earlierrecords] --'1614156327.86156-25-25-Sub' --'1612531119.1394532'--'1612530525.1394376' --'1606995789.3993493'-- '1'                            
(@UniqueidDurLeg nvarchar(500))                            
as                            
begin                
--declare @UniqueidDurLeg nvarchar(500)                        
declare @cid bigint                  
insert into calldurasperuniqueid(fullexp)                  
select    @UniqueidDurLeg                  
select @cid=SCOPE_IDENTITY()                  
                      
declare @uniqueid varchar(100),@dur int,@dur0 int,@leg nvarchar(10),@agentnumber nvarchar(50),@kit19callsid bigint                        
select * into #values from dbo.fn_split(replace(@uniqueiddurleg,'ns-',''),'-')                        
select @uniqueid=case when left(@uniqueiddurleg,3)='ns-' then 'ns-'+value else value end from #values where position=1                        
select @dur=cast(value as int) from #values where position=2                        
select @dur0=cast(value as int) from #values where position=3                        
select @leg=value from #values where position=4                    
select @agentnumber=value from #values where position=5                
select @kit19callsid=id from kit19calls(nolock) where uniqueid=@uniqueid                  
update calldurasperuniqueid set duration=@dur,billduration=@dur0,uniqueid=@uniqueid,agentnumber=@agentnumber where id=@cid                  
                   
print @dur                    
if @dur>0 and @agentnumber is not null                    
begin                    
print @dur + '1'                  
declare @answered int=0                    
if exists(select 1 from kit19callsdialled(nolock) where puniqueid=@uniqueid and (call_answer_time is not null or dialstatus='answer') and dbo.fn_trim0prefix(agentnumber)=dbo.fn_trim0prefix(@agentnumber))                  
set @answered=1                  
--select top 1 @answered=1 from kit19callsdialled(nolock) where puniqueid=@uniqueid and (call_answer_time is not null or dialstatus='answer')                    
if @answered=1                     
begin                        
print @dur + '2'                  
exec [usp_updatecallendtimeDur_agent_earlierRecords] @uniqueid,@dur,@leg,@agentnumber                        
end                     
end                        
else                    
begin                    
declare @cet datetime,@cet1 datetime--,@dur1 int,@dur2 int                          
--insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid)                          
--values('update kit19calls set calleridname=''b'',call_end_time='''+CONVERT(nvarchar(30),@cet, 121)+'''  where uniqueid='''+cast(@uniqueid as nvarchar(100))+'''',@uniqueid),                          
--('update kit19callsdialled set call_end_time='''+CONVERT(nvarchar(30),@cet, 121)+''' where puniqueid='''+cast(@uniqueid as nvarchar(100))+''' and dialstatus<>''answer''',@uniqueid )                          
select @cet=  
case when @leg='Main' then   
(select dateadd(ss,@dur,call_start_time) from kit19calls(nolock) where uniqueid=@uniqueid)    
else   
(select dateadd(ss,@dur,isnull(call_answer_time,call_start_time)) from kit19callsdialled(nolock) where puniqueid=@uniqueid   
and agentnumber= cast(@agentnumber as nvarchar(40))) end  
    
    
update kit19calls set calleridname='b',call_end_time=@cet  where uniqueid=@uniqueid       
exec usp_updatecalllog_withreftable 'kit19calls',@kit19callsid                        
update kit19callsdialled set call_end_time=@cet where puniqueid=@uniqueid and dialstatus<>'answer'                           
end                        
end 


GO

