/* ============================================================
   Procedure: [dbo].[usp_updatecallendtimeDur_agent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatecallendtimeDur_agent] --'1613052478.1695895',44,'main'                                    
@uniqueid varchar(100),@dur int,@leg nvarchar(20),@agentnumber nvarchar(20)=null                                    
as                                    
begin                                    
RETRY:                      
select @dur=cast(@dur as int)                                
begin try                                
declare @kit19callid bigint,@calldur int,@reco nvarchar(500),@l_activityexists bit=0,@e_activityexists bit=0  
select @kit19callid=id,@calldur=datediff(SECOND,call_start_time,isnull(call_end_time,getdate())),@reco=isnull(recordurl,'') from kit19calls  
(nolock) where uniqueid=@uniqueid                
  
Print 'finding entry in event tables'  
if exists(select 1 from tbl_LeadEventHistory(nolock) where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls')                
begin                
update tbl_LeadEventHistory set EventDescription=eventdescription+  
'. Call duration(sec): '+cast(@calldur as nvarchar) + ', Call recording: '+@reco                 
where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls' and @leg='Main'  
set @l_activityexists=1  
end                
  
if exists(select 1 from tbl_enquiryEventHistory(nolock) where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls')                
begin                
update tbl_EnquiryEventHistory set EventDescription=eventdescription+  
' Call duration(sec): '+cast(@calldur as nvarchar) + ', Call recording: '+@reco                 
where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls' and @leg='Main'                
set @e_activityexists=1  
end                
                
                
if @leg='Main'                                    
begin                                
/*  
insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid)                                      
values('update kit19calls set calleridname=''k'',call_end_time=dateadd(ss,'+CONVERT(nvarchar(30),@dur)+',call_start_time)  where uniqueid='''+cast(@uniqueid as nvarchar(100))+'''',@uniqueid)       
*/  
Print 'updating kit19calls'  
if exists(select 1 from kit19calls where id=@kit19callid and call_end_time is null )  
update kit19calls set calleridname='k',call_end_time=dateadd(ss,@dur,call_start_time)  where uniqueid=@uniqueid  
 and call_end_time is null
end                                    
else                                    
begin  
/*  
insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid)                                      
values('update kit19callsdialled set call_end_time=dateadd(ss,'+CONVERT(nvarchar(30),@dur)+',isnull(call_answer_time,call_start_time))  where agentnumber='''+ cast(@agentnumber as nvarchar(40))  
+''' and puniqueid='''+cast(@uniqueid as nvarchar(100))+'''',@uniqueid)                                      
*/  
Print 'updating kit19callsdialled'  
update kit19callsdialled set call_end_time=getdate()--dateadd(ss,@dur,isnull(call_answer_time,call_start_time))
,updateevent='K'   
where puniqueid=@uniqueid  and agentnumber= cast(@agentnumber as nvarchar(40)) and call_end_time is null                                
end  
  
declare @entityname nvarchar(20),@entityid bigint,@clino nvarchar(20),@parentid bigint,@agentname nvarchar(100)  
,@eventdescription nvarchar(1000),@eventname nvarchar(100),@user_id bigint,@kit19dialledid bigint,@user_name  
nvarchar(100)  
  
select @clino=callerid,@parentid=clientid from kit19calls(nolock) where uniqueid=@uniqueid and context='inbound'            
select @agentname=(select dbo.fn_truncateAtChar(dbo.lastagentattended(@uniqueid),'('))  
select @user_id=user_id,@user_name= dbo.fn_getentityfullname('user',user_id) from user_detail(nolock) where   
parentid=@parentid and user_login=dbo.fn_ltrimrtrim(@agentname)     
set @user_id=isnull(@user_id,@parentid)  
  
  
if not exists(select 1 from kit19callsdialled(nolock) where call_end_time is null and puniqueid=@uniqueid)                
begin                    select @agentname=(select dbo.fn_truncateAtChar(dbo.lastagentattended(@uniqueid),'('))  
select top 1 @kit19dialledid =id from Kit19CallsDialled(nolock) where puniqueid=@uniqueid and  agentnumber= cast(@agentnumber as nvarchar(40))                     
end  
  
if @clino is not null and exists(select 1 from userleads_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid)  
and @l_activityexists=0  
begin                  
Print 'lead with cli found'  
declare @leadno bigint             
select top 1 @entityname='lead',@leadno=leadno                  
 from userleads_mobile_email(nolock) where dbo.fn_trim0prefix(@clino)= dbo.fn_trim0prefix((isnull(Mobile,'')))  and   
ParentID=@parentid order by leadno desc                    
select @entityid=id from userleads(nolock) where leadno=@leadno and parentid=@parentid            
select @eventname=@entityname+case when (select dbo.fn_getcallstatus(@uniqueid))<>'Answered'  then '''s call missed' else ' calls up' end,          
@eventdescription=  
'An inbound call from phone '+cast(@clino as nvarchar(20)) +' by lead '      
+dbo.fn_getentityfullname(@entityname,@entityid) +' was received with status : '+ isnull(nullif((select dbo.fn_getcallstatus(@uniqueid)),''),'Unknown')+       
case when @kit19dialledid is not null then '. The last user attempted was ' +@agentname + ' ( '+@user_name+ ' )' else '' end                   
end                    
  
else if @clino is not null and exists(select EnquiryID from userenquiry_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid)                    
and @l_activityexists=0 and @e_activityexists=0  
begin  
Print 'enquiry with cli found'  
select top 1 @entityname='Enquiry',@entityid=enquiryid from userenquiry_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid            
 order by EnquiryID desc                    
select @eventname=@entityname+  
case when (select dbo.fn_getcallstatus(@uniqueid))<>'Answered'  then '''s call missed' else ' calls up' end,          
@eventdescription='An inbound call from phone '+cast(@clino as nvarchar(20)) +' by enquiry '+  
dbo.fn_getentityfullname(@entityname,@entityid) +' was received with status '      
+isnull(nullif((select dbo.fn_getcallstatus(@uniqueid)),''),'Unknown')+case when @kit19dialledid is not null then       
'. The last user attempted was ' +@agentname + ' ( '+@user_name+ ' )'  else '' end                 
end                    
  
else if @clino is not null  and isnull(@agentname,'')<>'' and @l_activityexists=0 and @e_activityexists=0  
begin           
Print 'lead/enquiry with cli not found'  
select @entityname='user',@entityid=@user_id,@eventname='User missed call',@eventdescription='An inbound call from                    
phone '+cast(@clino as nvarchar(20)) +' was missed by '+@agentname + ' ( '+@user_name+ ' )'  
end                
  
if @entityname is not null                    
begin              
declare @rt nvarchar(100),@rid bigint       
select @rt=case when @kit19dialledid is not null then 'Kit19callsdialled' else 'Kit19calls' end,      
@rid=case when @kit19dialledid is not null then @kit19dialledid else @kit19callid end      
--exec uspsaveentityactivity_withid @entityname,@entityid,@user_id,@parentid,@eventdescription,@eventname,@rt,@rid      
Print concat('calling event proc with details: ',' entityname: ',@entityname,', entityid: ', @entityid,', user_id: ', @user_id,', parentid: ',@parentid,', eventdescription: ',isnull(@eventdescription,''), ', eventname: ',@eventname,', reftable: Kit19calls
',', reftable: ', @kit19callid)  
exec uspsaveentityactivity_withid @entityname, @entityid, @user_id, @parentid, @eventdescription, @eventname,   
'Kit19calls', @kit19callid                    
end                    
                    
  
end try                                
begin catch                           
declare @errorno int=ERROR_NUMBER()                      
exec usp_inserterrorinfo                                
IF @errorno = 1205 -- Deadlock Error Number                                             
BEGIN                                        
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                        
GOTO RETRY -- Go to Label RETRY                                        
END                                                                                   
end catch                  
end                        
                    
                    
--select * from ActivityMaster                    
--insert into ActivityMaster(eventname,EventTemplate,eventtype,eventby,context)                    
--values ('Lead''s call missed','An inbound call from phone #mobile# by lead #leadname# was missed.                     
--The last user attempted was #username#','call','lead','lead'),                    
--('Enquiry''s call missed','An inbound call from phone #mobile# by enquiry #enquiryname# was missed.                     
--The last user attempted was #username#','call','enquiry','enquiry'),                    
--('User missed call','An inbound call from phone #mobile# was missed by #username#','call','user','user')


