begin                  
select top 1 @entityname='Enquiry',@entityid=enquiryid from userenquiry_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid          
 order by EnquiryID desc                  
select @eventname=@entityname+case when (select dbo.fn_getcallstatus(@uniqueid))<>'Answered'  then '''s call missed' else ' calls up' end,        
@eventdescription='An inbound call from                  
phone '+cast(@clino as nvarchar(20)) +' by enquiry '+dbo.fn_getentityfullname(@entityname,@entityid) +' was received with status '    
+isnull(nullif((select dbo.fn_getcallstatus(@uniqueid)),''),'Unknown')+case when @kit19dialledid is not null then     
'. The last user attempted was ' +@agentname  else '' end               
end                  
else if @clino is not null  and isnull(@kit19userid,0)<>0                
begin                  
select @entityname='user',@entityid=@user_id,@eventname='User missed call',@eventdescription='An inbound call from                  
phone '+cast(@clino as nvarchar(20)) +' was missed by '+ @agentname                  
end                  
if @entityname is not null                  
begin            
declare @rt nvarchar(100),@rid bigint     
select @rt=case when @kit19dialledid is not null then 'Kit19callsdialled' else 'Kit19calls' end,    
@rid=case when @kit19dialledid is not null then @kit19dialledid else @kit19callid end    
--exec uspsaveentityactivity_withid @entityname,@entityid,@user_id,@parentid,@eventdescription,@eventname,@rt,@rid      
exec uspsaveentityactivity_withid @entityname,@entityid,@user_id,@parentid,@eventdescription,@eventname,'Kit19calls',@kit19callid                  
end                  
end                  
end                                  
end try                              
begin catch                         
declare @errorno int=ERROR_NUMBER()                    
exec usp_inserterrorinfo                              
IF @errorno = 1205 -- Deadlock Error Number                                           
BEGIN                                      
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                      
GOTO RETRY -- Go to Label RETRY                                      
END                                                                                 
end catch                
end                      
                  
                  
--select * from ActivityMaster                  
--insert into ActivityMaster(eventname,EventTemplate,eventtype,eventby,context)                  
--values ('Lead''s call missed','An inbound call from phone #mobile# by lead #leadname# was missed.                   
--The last user attempted was #username#','call','lead','lead'),                  
--('Enquiry''s call missed','An inbound call from phone #mobile# by enquiry #enquiryname# was missed.                   
--The last user attempted was #username#','call','enquiry','enquiry'),                  
--('User missed call','An inbound call from phone #mobile# was missed by #username#','call','user','user')


GO

/* ============================================================
   Procedure: [dbo].[usp_updatecallendtimeDur_agent_earlierRecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatecallendtimeDur_agent_earlierRecords] --'1613052478.1695895',44,'main'                                    
@uniqueid varchar(100),@dur int,@leg nvarchar(20),@agentnumber nvarchar(20)--,@getdate datetime                                    
as                                    
begin                                    
RETRY:                      
select @dur=cast(@dur as int)                                
begin try                                
declare @kit19callid bigint,@calldur int,@reco nvarchar(500),@call_answer_time datetime
select @call_answer_time=
case when @leg='Main' then 
(select dateadd(ss,@dur,call_start_time) from kit19calls(nolock) where uniqueid=@uniqueid)  
else 
(select dateadd(ss,@dur,isnull(call_answer_time,call_start_time)) from kit19callsdialled(nolock) where puniqueid=@uniqueid 
and agentnumber= cast(@agentnumber as nvarchar(40))) end
select @kit19callid=id,@calldur=datediff(SECOND,call_start_time,dateadd(second,@dur,@call_answer_time))
,@reco=isnull(recordurl,'') 
from kit19calls(nolock) where uniqueid=@uniqueid                
if exists(select 1 from tbl_LeadEventHistory(nolock) where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls')                
begin                
update tbl_LeadEventHistory set EventDescription=replace(replace(eventdescription,'Call duration: 0','Call duration(sec): '+cast(@calldur as nvarchar)), 'call recording ','call recording: '+@reco)                 
where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls'                
end                
if exists(select 1 from tbl_enquiryEventHistory(nolock) where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls')                
begin                
update tbl_EnquiryEventHistory set EventDescription=replace(replace(eventdescription,'Call duration: 0','Call duration(sec): '+cast(@calldur as nvarchar)), 'call recording ','call recording: '+@reco)                 
where refids=cast(@kit19callid as nvarchar) and reftables='kit19calls'                
end                
                
                
if @leg='Main'                                    
begin                                
insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid)                                      
values('update kit19calls set calleridname=''k'',call_end_time=dateadd(ss,'+CONVERT(nvarchar(30),@dur)+',call_start_time)  where uniqueid='''+cast(@uniqueid as nvarchar(100))+'''',@uniqueid)                                      
update kit19calls set calleridname='k',call_end_time=dateadd(ss,@dur,call_start_time)  where uniqueid=@uniqueid                                        
end                                    
else                                    
begin                           
insert into Kit19FailedIVRQuery(FailedIVRQuery,uniqueid)                                      
values('update kit19callsdialled set call_end_time=dateadd(ss,'+CONVERT(nvarchar(30),@dur)+',isnull(call_answer_time,call_start_time))  where agentnumber='''+ cast(@agentnumber as nvarchar(40))+''' and puniqueid='''+cast(@uniqueid as nvarchar(100))+'''', 
 
@uniqueid)                                      
update kit19callsdialled set call_end_time=dateadd(ss,@dur,isnull(call_answer_time,call_start_time)),updateevent='K' where puniqueid=@uniqueid  and agentnumber= cast(@agentnumber as nvarchar(40))                                  
                  
if not exists(select 1 from kit19callsdialled(nolock) where call_end_time is null and puniqueid=@uniqueid)                    
begin                    
declare @entityname nvarchar(20),@entityid bigint,@clino nvarchar(20),@parentid bigint,@agentname nvarchar(100)=(select dbo.fn_truncateAtChar(dbo.lastagentattended(@uniqueid),'(')),                    
@eventdescription nvarchar(1000),@eventname nvarchar(100),@user_id bigint,@kit19dialledid bigint                    
select top 1 @kit19dialledid =id from Kit19CallsDialled(nolock) where puniqueid=@uniqueid and  agentnumber= cast(@agentnumber as nvarchar(40))                     
select @clino=callerid,@parentid=clientid from kit19calls(nolock) where uniqueid=@uniqueid and context='inbound'                    
select @user_id=user_id from user_detail(nolock) where parentid=@parentid and user_login=dbo.fn_ltrimrtrim(@agentname)                    
                    
--insert into failedinsert(uniqueid,kit19dialledid)                    
--select @uniqueid,@kit19dialledid                    
                    
if @clino is not null and exists(select 1 from userleads_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid)                    
begin                  
declare @leadno bigint             
select top 1 @entityname='lead',@leadno=leadno                  
 from userleads_mobile_email(nolock) where dbo.fn_trim0prefix(@clino)= dbo.fn_trim0prefix((isnull(Mobile,'')))  and ParentID=@parentid order by leadno desc                    
select @entityid=id from userleads(nolock) where leadno=@leadno and parentid=@parentid            
select @eventname=@entityname+case when (select dbo.fn_getcallstatus(@uniqueid))<>'Answered'  then '''s call missed' else ' calls up' end,          
@eventdescription='An inbound call from phone '+cast(@clino as nvarchar(20)) +' by lead '      
+dbo.fn_getentityfullname(@entityname,@entityid) +' was received with status : '+ isnull(nullif((select dbo.fn_getcallstatus(@uniqueid)),''),'Unknown')+       
case when @kit19dialledid is not null then '. The last user attempted was ' +@agentname  else '' end                   
end                    
else if @clino is not null and exists(select EnquiryID from userenquiry_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid)                    
begin                    
select top 1 @entityname='Enquiry',@entityid=enquiryid from userenquiry_mobile_email(nolock) where dbo.fn_trim0prefix(@clino) = dbo.fn_trim0prefix((isnull(Mobile,''))) and ParentID=@parentid            
 order by EnquiryID desc                    
select @eventname=@entityname+case when (select dbo.fn_getcallstatus(@uniqueid))<>'Answered'  then '''s call missed' else ' calls up' end,          
@eventdescription='An inbound call from                    
phone '+cast(@clino as nvarchar(20)) +' by enquiry '+dbo.fn_getentityfullname(@entityname,@entityid) +' was received with status '      
+isnull(nullif((select dbo.fn_getcallstatus(@uniqueid)),''),'Unknown')+case when @kit19dialledid is not null then       
'. The last user attempted was ' +@agentname  else '' end                 
end                    
else if @clino is not null  and isnull(@agentname,'')<>''                  
begin                    
select @entityname='user',@entityid=@user_id,@eventname='User missed call',@eventdescription='An inbound call from                    
phone '+cast(@clino as nvarchar(20)) +' was missed by '+ @agentname                    
end                    
if @entityname is not null                    
begin              
declare @rt nvarchar(100),@rid bigint       
select @rt=case when @kit19dialledid is not null then 'Kit19callsdialled' else 'Kit19calls' end,      
@rid=case when @kit19dialledid is not null then @kit19dialledid else @kit19callid end      
--exec uspsaveentityactivity_withid @entityname,@entityid,@user_id,@parentid,@eventdescription,@eventname,@rt,@rid        
exec uspsaveentityactivity_withid @entityname,@entityid,@user_id,@parentid,@eventdescription,@eventname,'Kit19calls',@kit19callid                    
end                    
end                    
end                                    
end try                                
begin catch                           
declare @errorno int=ERROR_NUMBER()                      
exec usp_inserterrorinfo                                
IF @errorno = 1205 -- Deadlock Error Number                                             
BEGIN                                        
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                        
GOTO RETRY -- Go to Label RETRY                                        
END                                                                                   
end catch                  
end                        
                    
                    
--select * from ActivityMaster                    
--insert into ActivityMaster(eventname,EventTemplate,eventtype,eventby,context)                    
--values ('Lead''s call missed','An inbound call from phone #mobile# by lead #leadname# was missed.                     
--The last user attempted was #username#','call','lead','lead'),                    
--('Enquiry''s call missed','An inbound call from phone #mobile# by enquiry #enquiryname# was missed.                     
--The last user attempted was #username#','call','enquiry','enquiry'),                    
--('User missed call','An inbound call from phone #mobile# was missed by #username#','call','user','user')


GO

/* ============================================================
   Procedure: [dbo].[usp_updatecalllog_unupdated]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_updatecalllog_unupdated
as
begin
drop table if exists #id
select k.id into #id from kit19calls(nolock) k join calllog(nolock) c on k.id=c.refid and c.reftable='kit19calls' where k.call_end_time is not null
and isnull(c.callendtime,'')='' and c.Callstarttime>dateadd(HH,-1,getdate())

declare @c int=(select count(1) from #id),@id bigint=0
while @c>0
begin
select @id=min(id) from #id where id>@id
exec usp_updatecalllog_withreftable 'kit19calls',@id                        
set @c=@c-1
end
end


GO

/* ============================================================
   Procedure: [dbo].[usp_updatecalllog_withcalllogid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from Calltypes  
CREATE   PROCEDURE [dbo].[usp_updatecalllog_withcalllogid]  --1371882 
(@calllogid bigint)    
as    
begin    
declare @CallTypeid int,@CallType nvarchar(20),@gatewayid int,@reftable nvarchar(100),@refid bigint,    
@Customernumber nvarchar(20),@customercountrycode nvarchar(10),@Agentnumber nvarchar(20),@agentcountrycode nvarchar(10),    
@Callstarttime datetime,@Callendtime datetime,@Agentpickuptime datetime,@Customerpickuptime datetime,    
@Calldurationseconds int,@Billdurationseconds int,@customerduration int,@agentduration int,    
@lastdtmf nvarchar(50),@agentmode nvarchar(20),@agentcalldisposition nvarchar(50),@agent_type nvarchar(20),@calling_agentid bigint,    
@customercalldisposition nvarchar(50),@agentuserid bigint,@outcomeid bigint,@remarks nvarchar(max),    
@customerentity nvarchar(20),@customerentityid bigint,@callcreatedby bigint,@callscheduledfor datetime,    
@callcreatedon datetime,@parentid bigint,@appid bigint,@uniqueid nvarchar(100),  
@accountcode nvarchar(50),@kit19uniqueid nvarchar(100) ,@recordurl nvarchar(1000) 
declare @batchid bigint,@createdby bigint,@createdtime datetime  
select @reftable=reftable,@refid=refid from calllog(nolock) where id=@calllogid  
  
if @reftable='Kit19calls'    
begin    
select @calllogid=ID,@CallTypeid=calltype from CallLog(nolock) where reftable='Kit19calls' and refid=@refid
select @calltype=Typename from Calltypes(nolock) where id=@calltypeid
drop table if exists #kit19calls    
select * into #kit19calls from kit19calls with (nolock) where id=@refid   
select @uniqueid=uniqueid,@parentid=clientid,@Callendtime=call_end_time  
,@Callstarttime=call_start_time,@Calldurationseconds=datediff(SS,call_start_time,call_end_time)  
,@lastdtmf=call_last_dtmf,@accountcode=accountcode,@kit19uniqueid=kit19uniqueid,@appid=appid  
 from #kit19calls   
if @CallType<>'Click2Call'  
begin  
if @CallType='OBD'  
begin  
select @batchid=k.batchid,@createdby=b.UserID,@createdtime=ISNULL(nullif(b.Scheduleddate,''),BatchInsertTime)   
from Kit19Cloudvoicefinaltbl(nolock) k   
join BatchVoiceInfo(nolock) b on b.BatchID=k.batchid  
where kit19uniqueid=@kit19uniqueid  
end  
select top 1 @Agentnumber=dbo.fn_trim0prefix(agentnumber) 
,@calling_agentid=K.kc_agentid
,@agent_type=case when kc_agentid is not null then 'Agent' else 'User' end
,@agentcountrycode=CountryCode  
,@Agentpickuptime=call_answer_time  
,@Customerpickuptime=case when @calltype='Incoming' then null else @callstarttime end  
,@Billdurationseconds=case when @calltype='Incoming' then datediff(SS,call_start_time,call_end_time)  
else datediff(SS,@callstarttime,@callendtime) + datediff(SS,call_start_time,call_end_time) end  
,@customerduration=datediff(SS,@callstarttime,@callendtime)  
,@agentduration=datediff(SS,call_start_time,call_end_time)  
,@agentmode=CASE WHEN AgentType='Mobile' then 'Mobile' else 'Extension' end  
,@agentcalldisposition=isnull(dialstatus,'NOANSWER')  
,@customercalldisposition='ANSWER'  
,@agentuserid=USER_ID  
,@callcreatedby=case when @CallType='OBD' then @createdby end  
,@callcreatedon=case when @calltype='OBD' then @createdtime else @callstarttime end  
from Kit19CallsDialled(nolock) k  
left join User_Detail(nolock) u on  
u.parentid=@parentid and dbo.fn_trim0prefix(agentnumber)=case when AgentType='User' then User_ID else STR(mobile) end  
where puniqueid=@uniqueid  
order by case when dialstatus='ANSWER' then 0 else 1 end,call_start_time desc  
--select top 10 * from kit19callsdialled(nolock) order by id desc  
end  
else if @CallType='Click2Call'  
begin  
select top 1 @Agentnumber=@accountcode  
,@agentcountrycode=CountryCode  
,@Agentpickuptime=@callstarttime  
,@Customerpickuptime=call_answer_time  
,@Billdurationseconds=ISNULL(billedtime,0)  
,@customerduration=ISNULL(billedtime,0)  
,@agentduration=datediff(SS,@callstarttime,@callendtime)  
,@agentmode='Extension'  
,@agentcalldisposition=null  
,@customercalldisposition=disposition  
,@agentuserid=k.USER_ID  
,@callcreatedby=@accountcode  
,@callcreatedon=@callstarttime  
,@customercountrycode='+'+left(dnidnowithcountrycode,LEN(dnidnowithcountrycode)-len(dnid))  
from Diallercalls(nolock) k  
left join User_Detail(nolock) u on  
u.User_ID=k.user_id  
where k.kit19callsid=@refid  
--select top 10 * from DiallerCalls(nolock) order by id desc  
end  
end  
else if @reftable='twiliocalls'    
begin    
select @calllogid=ID,@CallTypeid=calltype from CallLog(nolock) where reftable='twiliocalls' and refid=@refid
select @calltype=Typename from Calltypes(nolock) where id=@calltypeid
drop table if exists #twiliocalls    
select * into #twiliocalls from twiliocalls with (nolock) where id=@refid   
select @parentid=parentid,@Callendtime=call_end_time  
,@Callstarttime=call_start_time,@Calldurationseconds=CallDuration
,@lastdtmf=call_last_dtmf,@recordurl=recordurl
 from #twiliocalls   

end  

else if @reftable='tbl_voip_Webhook' or @reftable='tbl_voip_endpointInteraction'  
begin  
declare @interactionid bigint,@response nvarchar(max),@uniqueidentity nvarchar(100)--,@webhookid bigint  
if @reftable='tbl_voip_endpointInteraction'  
begin  
--select @interactionid=refid from calllog(nolock) where id=@callogid and reftable='tbl_voip_endpointInteraction'  
select @refid=max(id) from tbl_voip_webhook(nolock) where endpointid=@interactionid  
end  
--if @reftable='tbl_voip_Webhook'  
--begin  
--select @interactionid=refid from calllog(nolock) where id=@callogid and reftable='tbl_voip_Webhook'  
--end  
drop table if exists #tbl_voip_webhook  
select * into #tbl_voip_webhook from tbl_voip_webhook with (nolock) where id= @refid   
select @gatewayid=srv_pro_id,@response=request_body,@uniqueidentity=UniqueIdentity,@interactionid=endpointid,  
@Callendtime=created_on,@parentid=parentid  
 from #tbl_voip_webhook with (nolock) where id=@refid  
select @calllogid=ID,@CallTypeid=calltype,@gatewayid=gatewayid from CallLog(nolock) where reftable='tbl_voip_endpointInteraction'   
and refid=@interactionid  
drop table if exists #tbl_voip_endpointInteraction    
select * into #tbl_voip_endpointInteraction from tbl_voip_endpointInteraction with (nolock) where id=@interactionid   
select @Callstarttime=created_on,@createdtime=created_on,@createdby=agentid,@customerentity=EntityName,@customerentityid=EntityId  
,@parentid=(select parentid from user_detail(nolock) where user_id=AgentId)  
 from #tbl_voip_endpointInteraction   
--select * into #t from tbl_voip_Webhook(nolock) t where ISNULL(request_body,'')<>'' --and t.id = (select MAX(id) from tbl_voip_Webhook(nolock) where srv_pro_id=t.srv_pro_id) --declare @r nvarchar(max),@s int=0,@i int=0 drop table if exists #jsonwebhook  
create table #jsonwebhook([key] nvarchar(500),[value] nvarchar(max)) --while @i<3 --begin --select @s=MIN(srv_pro_id) from #t where srv_pro_id>@s --select @r=request_body from #t where srv_pro_id=@s   
insert into #jsonwebhook([key],[value])  
select [key],[value] from openjson(@response)  
  
--declare gateway variables--  
declare @g1_extension nvarchar(100),@g1_destination nvarchar(50),@g1_callerid nvarchar(50),@g1_duration int  
,@g1_status nvarchar(100),@g1_date nvarchar(100),@g1_recording_URL nvarchar(200),@g1_param1 bigint  
declare @g3_from_number nvarchar(50),@g3_from_number_answer_time int,@g3_to_number nvarchar(50)  
,@g3_to_number_answer_time int,@g3_campaignid nvarchar(10),@g3_answer_time int,@g3_status nvarchar(20)  
,@g3_extension nvarchar(100),@g3_number nvarchar(20),@g3_recording_url nvarchar(200),@g3_from_number_status nvarchar(20)  
,@g3_to_number_status nvarchar(20)  
declare @g4_status nvarchar(20),@g4_duration int,@g4_refno nvarchar(100),@g4_endtime datetime,@g4_starttime datetime  
,@g4_recordingurl nvarchar(200),@g4_from nvarchar(50),@g4_to nvarchar(50)  
  
if @gatewayid=1  
begin  
select @g1_extension =isnull(nullif(nullif([value],''),'null'),'') from #jsonwebhook where [Key]='extension'  
select @g1_destination=[value] from #jsonwebhook where [Key]='destination'  
select @g1_callerid=[value] from #jsonwebhook where [Key]='callerid'  
select @g1_duration =case when isnumeric(isnull(nullif([value],''),'0'))=1 then CAST(isnull(nullif([value],''),'0') AS int)  
 else 0 end from #jsonwebhook where [Key]='duration'  
select @g1_status =[value] from #jsonwebhook where [Key]='status'  
select @g1_date =case when isdate(replace([value],'%20',' ') )=1 then cast(replace([value],'%20',' ') AS datetime)  
else @createdtime end from #jsonwebhook where [Key]='date'  
select @g1_recording_URL =[value] from #jsonwebhook where [Key]='recording_URL'  
select @g1_param1 =[value] from #jsonwebhook where [Key]='param1'  
  
select  
@Callendtime=(select dateadd(ss,@g1_duration,@Callstarttime))  
,@Calldurationseconds=@g1_duration  
,@Billdurationseconds=@g1_duration  
,@agentmode=case when @g1_extension<>'' then 'Extension' else 'Mobile' end  
,@agentcalldisposition=case when @g1_status='ANSWERED' then 'ANSWER' else null end  
,@customercalldisposition=@g1_status  
,@agentuserid=@createdby  
,@outcomeid=null  
,@remarks=null  
,@callcreatedby=@createdby  
,@callscheduledfor=null  
,@callcreatedon=@createdtime  
,@parentid=@parentid  
,@appid  =null  
end  
if @gatewayid=3  
begin  
create table #gateway3json ([key] nvarchar(200),[value] nvarchar(max))  
declare @c int=(select COUNT(1) from #jsonwebhook),@kid int=0  
while @c>0  
begin  
select @kid=MIN([key]) from #jsonwebhook where cast([key] as int)>=@kid  
insert into #gateway3json([key],[value])  
select [key],[value] from openjson((select [value] from #jsonwebhook where [key]=@kid))  
set @kid=@kid+1  
set @c=@c-1  
end  
select @g3_from_number =isnull(nullif(nullif([value],''),'null'),'') from #gateway3json where [Key]='from_number'  
select @g3_from_number_answer_time=case when isnumeric(isnull(nullif([value],''),'0') )=1 then  
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='from_number_answer_time'  
select @g3_to_number=[value] from #gateway3json where [Key]='to_number'  
select @g3_to_number_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then  
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='to_number_answer_time'  
select @g3_campaignid =[value] from #gateway3json where [Key]='campaignid'  
select @g3_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then  
cast(isnull(nullif([value],''),'0') AS int) else 0 end  from #gateway3json where [Key]='answer_time'  
select @g3_status =[value] from #gateway3json where [Key]='status'  
select @g3_extension =[value] from #gateway3json where [Key]='extension'  
select @g3_number =[value] from #gateway3json where [Key]='number'  
select @g3_recording_url =[value] from #gateway3json where [Key]='recording_url'  
select @g3_from_number_status =[value] from #gateway3json where [Key]='from_number_status'  
select @g3_to_number_status =[value] from #gateway3json where [Key]='to_number_status'  
  
select  
@Agentnumber=(select mobile from dbo.fn_separatecountrycodeandmobile(@g3_from_number))  
,@agentcountrycode=(select countrycode from dbo.fn_separatecountrycodeandmobile(@g3_from_number))  
,@Callendtime=case when @g3_status='Answered' then DATEADD(ss,@g3_answer_time,@callstarttime) else @Callstarttime end  
,@Agentpickuptime=case when @g3_from_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time,@Callstarttime) end  
,@Customerpickuptime=case when @g3_to_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time +@g3_to_number_answer_time,@Callstarttime) end  
,@Billdurationseconds=@g3_from_number_answer_time + @g3_to_number_answer_time  
,@customerduration=@g3_to_number_answer_time  
,@agentduration=@g3_from_number_answer_time  
,@lastdtmf=null  
,@agentmode=case when @g3_extension<>'-' then 'Extension' else 'Mobile' end  
,@agentcalldisposition=@g3_from_number_status  
,@customercalldisposition=@g3_to_number_status  
,@agentuserid=@createdby  
,@outcomeid=null  
,@remarks=null  
,@callcreatedby=@createdby  
,@callscheduledfor=null  
,@callcreatedon=@createdtime  
,@parentid=@parentid  
,@appid  =null  
select @Calldurationseconds=DATEDIFF(ss,@callstarttime,@callendtime)  
end  
if @gatewayid=4  
begin  
select @g4_status=[value] from #jsonwebhook where [Key]='status'  
select @g4_duration=case when isnumeric(isnull(nullif([value],''),'0'))=1   
then cast(isnull(nullif([value],''),'0') as int) else 0 end from #jsonwebhook where [Key]='duration'  
select @g4_endtime=case when isdate([value])=1 then cast([value] as datetime)   
else dateadd(ss,@g4_duration,@callstarttime) end from #jsonwebhook where [Key]='endtime'  
select @g4_from=[value] from #jsonwebhook where [Key]='from'  
select @g4_recordingurl=[value] from #jsonwebhook where [Key]='recordingurl'  
select @g4_refno=[value] from #jsonwebhook where [Key]='refno'  
select @g4_starttime=[value] from #jsonwebhook where [Key]='starttime'  
select @g4_to=[value] from #jsonwebhook where [Key]='to'  
  
select  
@Callendtime=@g4_endtime  
,@Calldurationseconds=@g4_duration  
,@Billdurationseconds=@g4_duration  
,@agentmode='Mobile'  
,@agentcalldisposition=case when @g4_status='ANSWERED' then 'ANSWER' else null end  
,@customercalldisposition=@g4_status  
,@agentuserid=@createdby  
,@outcomeid=null  
,@remarks=null  
,@callcreatedby=@createdby  
,@callscheduledfor=null  
,@callcreatedon=@createdtime  
,@parentid=@parentid  
,@appid  =null  
end  
end  
  
/*  
select  
--,@Agentnumber=a.mobile_no  
--,@agentcountrycode=null--to be added in agent setting  
@Callendtime=  
case when @gatewayid=1   
and ISNUMERIC((select cast(isnull(nullif([value],''),'0') as int) from #jsonwebhook where [key]='duration'))=1  
then   
(select dateadd(ss,@duration,@Callstarttime) from #jsonwebhook where [key]='duration')  
when @gatewayid=3 then  
case when   
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='Status' )='Answered')  
then @Callendtime else @Callstarttime end  
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='EndTime') end  
  
,@Agentpickuptime=  
case when @gatewayid=1 then null  
when @gatewayid=3 then   
case when   
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' )<>'0')  
then dateadd(ss,  
cast(isnull(nullif((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ),''),'0') as int)  
,@Callstarttime)  
end  
when @gatewayid=4 then null end  
  
,@Customerpickuptime=  
case when @gatewayid=1 then null  
when @gatewayid=3 then   
case when   
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' )<>'0')  
then dateadd(ss,  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) as int) +  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int),  
@Callstarttime)  
end  
when @gatewayid=4 then null end  
  
,@Calldurationseconds=  
case when @gatewayid=1 then (select dateadd(ss,cast(isnull(nullif([value],''),'0') as int),@Callstarttime) from #jsonwebhook where [key]='duration')  
when @gatewayid=3 then DATEDIFF(ss,@callstarttime,@callendtime)  
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='EndTime') end  
  
,@Billdurationseconds=  
case when @gatewayid=1 then (select [value] from #jsonwebhook where [key]='duration')  
when @gatewayid=3 then  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) as int) +  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int)  
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='duration') end  
  
,@customerduration=  
case when @gatewayid=1 then null  
when @gatewayid=3 then  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int)  
when @gatewayid=4 then null end  
  
,@agentduration=  
case when @gatewayid=1 then null  
when @gatewayid=3 then  
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) AS int)  
when @gatewayid=4 then null end  
  
,@lastdtmf=null  
  
,@agentmode=  
case   
when @gatewayid=1 then   
case when isnull(nullif((select [value] from #jsonwebhook where [key]='extension'),''),'null')<>'null'  
then 'Extension' else 'Mobile' end  
when @gatewayid=3 then  
case when (select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='extension')='-'   
then 'Extension' else 'Mobile' end  
when @gatewayid=4 then  
'Mobile' end  
  
,@agentcalldisposition=  
case when @gatewayid=1 then   
case when (select [value] from #jsonwebhook where [key]='status')='ANSWERED' then 'ANSWER'  
else null end  
when @gatewayid=3 then    
(select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_status')   
when @gatewayid=4 then    
case when (select [value] from #jsonwebhook where [key]='status')='ANSWERED' then 'ANSWER'  
else null end  
end  
  
,@customercalldisposition=  
case when @gatewayid=1 then   
(select [value] from #jsonwebhook where [key]='status')  
when @gatewayid=3 then    
(select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_status')  
when @gatewayid=4 then    
(select [value] from #jsonwebhook where [key]='status')  
end  
  
,@agentuserid=@createdby  
,@outcomeid=null  
,@remarks=null  
,@callcreatedby=@createdby  
,@callscheduledfor=null  
,@callcreatedon=@createdtime  
,@parentid=@parentid  
,@appid  =null  
*/  
  
update calllog set   
customercountrycode=@customercountrycode  
,Agentnumber=@Agentnumber  
,agentcountrycode=@agentcountrycode  
,Callstarttime=@Callstarttime  
,Callendtime=@Callendtime  
,Agentpickuptime=@Agentpickuptime  
,Customerpickuptime=@Customerpickuptime  
,Calldurationseconds=@Calldurationseconds  
,Billdurationseconds=@Billdurationseconds  
,customerduration=@customerduration  
,agentduration=@agentduration  
,lastdtmf=@lastdtmf  
,agentmode=@agentmode  
,agentcalldisposition=@agentcalldisposition  
,customercalldisposition=@customercalldisposition  
,agentuserid=@agentuserid  
,callcreatedby=@callcreatedby  
,callcreatedon=@callcreatedon  
,parentid=@parentid  
,appid=@appid
,agent_type=@agent_type
,calling_agentid=@calling_agentid
,recordurl=isnull(recordurl,@recordurl)
from CallLog where id=@calllogid  
  
  
    
end    
    
    
