/* ============================================================
   Procedure: [dbo].[usp_updatecalllog_withreftable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatecalllog_withreftable] --'kit19calls',5969164 --'tbl_voip_Webhook',30919                      
(@reftable nvarchar(100),@refid bigint)                          
as                          
begin                        
--declare @reftable nvarchar(100)='tbl_voip_Webhook',@refid bigint=32773                
declare @iid bigint=case when @reftable='tbl_voip_webhook' then (select endpointid from tbl_voip_webhook                
where id=@refid) else 0 end                
if exists(select 1 from CallLog(nolock) where refid=case when @reftable='tbl_voip_webhook' then @iid else @refid                
end  and reftable=case when @reftable='tbl_voip_webhook'                  
then 'tbl_voip_endpointInteraction' else @reftable end)                  
begin                    
--declare @reftable nvarchar(100)='tbl_voip_Webhook',@refid bigint                  
declare @CallType int,@gatewayid int,@calltypename nvarchar(20),@recordurl nvarchar(500),                          
@Customernumber nvarchar(20),@customercountrycode nvarchar(10),@Agentnumber nvarchar(20),@agentcountrycode nvarchar(10),                          
@Callstarttime datetime,@Callendtime datetime,@Agentpickuptime datetime,@Customerpickuptime datetime,                          
@Calldurationseconds int,@Billdurationseconds int,@customerduration int,@agentduration int,                          
@lastdtmf nvarchar(50),@agentmode nvarchar(20),@agentcalldisposition nvarchar(50),                          
@customercalldisposition nvarchar(50),@agentuserid bigint,@outcomeid bigint,@remarks nvarchar(max),                          
@customerentity nvarchar(20),@customerentityid bigint,@callcreatedby bigint,@callscheduledfor datetime,                          
@callcreatedon datetime,@parentid bigint,@appid bigint,@calllogid bigint,@uniqueid nvarchar(100),                        
@accountcode nvarchar(50),@kit19uniqueid nvarchar(100)            ,@direction nvarchar(20),@kit19dialledid bigint            
declare @batchid bigint,@createdby bigint,@createdtime datetime                        
if @reftable='Kit19calls'                          
begin                         
select @parentid=clientid from kit19calls(nolock) where id=@refid          
select @calllogid=ID,@CallType=calltype,@customerentity=customerentity,@customerentityid=customerentityid,@customernumber=customernumber,@direction=Direction          
from CallLog(nolock) where reftable='Kit19calls' and refid=@refid                 
          
if isnull(@customerentity,'')=''          
begin          
select @customerentity=                            
case when exists(select 1 from userleads_mobile_email(nolock) where parentid=@parentid and  dbo.fn_trim0prefix(@Customernumber) =mobile)                            
then 'lead'                            
when exists(select 1 from userenquiry_mobile_email(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber) =mobile)                            
then 'enquiry'                            
end                            
select @customerentityid=                            
case when @customerentity='lead'                            
then (select top 1 id from userleads(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                            
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by id desc)                             
when @customerentity='enquiry'                            
then (select top 1 EnquiryID from userenquiry(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                            
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by EnquiryID desc)                             
end                            
          
          
end          
print 'customerentity: '+@customerentity+', Customerentityid: '+cast(@customerentityid as nvarchar)          
drop table if exists #kit19calls                          
select * into #kit19calls from kit19calls with (nolock) where id=@refid                
select @uniqueid=uniqueid,@parentid=clientid,@Callendtime=call_end_time ,@recordurl=        
case when dbo.fn_getcallstatus(uniqueid)='Answered' then recordurl else null end                       
,@Callstarttime=call_start_time,@Calldurationseconds=datediff(SS,call_start_time,call_end_time)                        
,@lastdtmf=call_last_dtmf,@accountcode=accountcode,@kit19uniqueid=kit19uniqueid,@appid=appid                  
 from #kit19calls                    
 select @calltypename=typename from calltypes where id=@CallType                         
if @calltypename<>'Click2Call'                    
begin                        
if @calltypename='OBD'                        
begin                        
select @batchid=k.batchid,@createdby=b.UserID,@createdtime=ISNULL(nullif(b.Scheduleddate,''),BatchInsertTime)                         
from Kit19Cloudvoicefinaltbl(nolock) k                         
join BatchVoiceInfo(nolock) b on b.BatchID=k.batchid                        
where kit19uniqueid=@kit19uniqueid                        
end   
  
DECLARE @p_uniqueid VARCHAR(50)  
SET @p_uniqueid = CAST(@uniqueid AS VARCHAR(50))  
SELECT * INTO #Kit19CallsDialled FROM Kit19CallsDialled (nolock)  
WHERE puniqueid=@p_uniqueid;  
  
select top 1 @kit19dialledid=k.id,@Agentnumber=dbo.fn_trim0prefix(agentnumber)                        
,@agentcountrycode=isnull(u.cloud_countrycode, u.CountryCode)                        
,@Agentpickuptime=call_answer_time                        
,@Customerpickuptime=case when @calltypename='Incoming' then null else @callstarttime end                        
,@Billdurationseconds=case when @calltypename='Incoming' then datediff(SS,call_answer_time,call_end_time)                        
else datediff(SS,@callstarttime,@callendtime) + isnull(datediff(SS,call_answer_time,call_end_time),0) end                        
,@customerduration=datediff(SS,@callstarttime,@callendtime)                        
,@agentduration=datediff(SS,isnull(call_answer_time,call_end_time),call_end_time)                        
,@agentmode=CASE WHEN AgentType='Mobile' then 'Mobile' else 'Extension' end                        
,@agentcalldisposition=case when isnull(dialstatus,'NOANSWER') ='ANSWER' then 'ANSWERED' else  upper(isnull(dialstatus,'NOANSWER')) end                      
,@customercalldisposition='ANSWERED'                      
,@agentuserid=USER_ID                        
,@callcreatedby=case when @calltypename='OBD' then @createdby end                        
,@callcreatedon=case when @calltypename='OBD' then @createdtime else @callstarttime end                        
from #Kit19CallsDialled k                        
left join (select u.*,cc.cloud_no,cc.cloud_countrycode from User_Detail(nolock) u left join cloud_call_no cc on cc.user_id=u.user_id) u on                        
u.parentid=@parentid and           
(isnull(k.kc_agentuserid,u.user_id)=u.user_id or dbo.fn_trim0prefix(agentnumber)=case when AgentType='User' then       
cast(User_ID as nvarchar) else isnull(u.cloud_no, STR(mobile)) end)                        
where puniqueid=@p_uniqueid                        
order by case when dialstatus='ANSWER' then 0 else 1 end,call_start_time desc                   
                  
select @Billdurationseconds=case when @calltypename='Incoming' and @agentcalldisposition<>'ANSWERED' then 0 else @Billdurationseconds end                       
--select top 10 * from kit19callsdialled(nolock) order by id desc                        
end                        
else if @calltypename='Click2Call'                        
begin                        
select top 1 @Agentnumber=@accountcode                        
,@agentcountrycode=CountryCode                        
,@Agentpickuptime=@callstarttime                        
,@Customerpickuptime=call_answer_time                        
,@Billdurationseconds=ISNULL(billedtime,0)                        
,@customerduration=ISNULL(billedtime,0)                        
,@agentduration=datediff(SS,@callstarttime,@callendtime)                        
,@agentmode='Extension'                        
,@agentcalldisposition='ANSWERED'                        
,@customercalldisposition=case when disposition='answer' then 'ANSWERED' else upper(disposition) end                         
,@agentuserid=k.USER_ID                        
,@callcreatedby=@accountcode                        
,@callcreatedon=@callstarttime                        
,@customercountrycode='+'+left(dnidnowithcountrycode,LEN(dnidnowithcountrycode)-len(dnid))                        
from Diallercalls(nolock) k                        
left join User_Detail(nolock) u on                        
u.User_ID=k.user_id                        
where k.kit19callsid=@refid                        
--select top 10 * from DiallerCalls(nolock) order by id desc                        
end                        
end                        
else if @reftable='twiliocalls'                          
begin    
--select top 10 * from twiliocalls (nolock) order by 1 desc
select @parentid=parentid from twiliocalls(nolock) where id=@refid          
select @calllogid=ID,@CallType=calltype,@customerentity=customerentity,@customerentityid=customerentityid,@customernumber=customernumber,@direction=Direction          
from CallLog(nolock) where reftable='twiliocalls' and refid=@refid                 
          
if isnull(@customerentity,'')=''          
begin          
select @customerentity=                            
case when exists(select 1 from userleads_mobile_email(nolock) where parentid=@parentid and  dbo.fn_trim0prefix(@Customernumber) =mobile)                            
then 'lead'                            
when exists(select 1 from userenquiry_mobile_email(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber) =mobile)                            
then 'enquiry'                            
end                            
select @customerentityid=                            
case when @customerentity='lead'                            
then (select top 1 id from userleads(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                            
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by id desc)                             
when @customerentity='enquiry'                            
then (select top 1 EnquiryID from userenquiry(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                            
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by EnquiryID desc)                             
end                            
          
          
end          
print 'customerentity: '+@customerentity+', Customerentityid: '+cast(@customerentityid as nvarchar)          
drop table if exists #twiliocalls                          
select * into #twiliocalls from twiliocalls with (nolock) where id=@refid                
select @Callendtime=call_end_time ,@recordurl=recordurl                       
,@Callstarttime=call_start_time,@Calldurationseconds=case when CallDuration IS not null then CallDuration 
 when call_end_time is not null then datediff(SS,call_start_time,call_end_time) else null end,@direction=direction                        
 from #twiliocalls                    
 select @calltypename=typename from calltypes where id=@CallType                         
if 1=1--@direction='outbound'                    
begin                        
select top 1 @Agentpickuptime=case when @direction='inbound' and agent_disposition='answered'  then isnull(nullif(call_answer_time,''),@callstarttime) else null  end,@customercountrycode=countrycode                      
,@Customerpickuptime=case when @direction='outbound' and customer_disposition ='answered' then isnull(nullif(call_answer_time,''),@callstarttime) else null  end                      
,@Billdurationseconds=case when @direction='outbound' then bill_duration else callduration end                      
,@customerduration=case when @direction='outbound' and customer_disposition ='answered' then bill_duration else 0 end                        
,@agentduration=case when @direction='inbound' and agent_disposition='answered'  then CallDuration else 0 end                        
,@agentcalldisposition=agent_disposition                      
,@customercalldisposition=customer_disposition                       
,@callcreatedby=case when @direction='outbound' then @createdby end                        
,@callcreatedon=@callstarttime,@agentmode='Bot'
from #twiliocalls k                        
                  
--select @Billdurationseconds=case when @calltypename='Incoming' and @agentcalldisposition<>'ANSWERED' then 0 else @Billdurationseconds end                       
--select top 10 * from kit19callsdialled(nolock) order by id desc                        
end                        
end                        
else if @reftable='tbl_voip_Webhook'  or @reftable='tbl_voip_endpointInteraction'                      
begin                        
declare @interactionid bigint,@response nvarchar(max),@uniqueidentity nvarchar(100)                    
declare @providername nvarchar(50)                      
if @reftable='tbl_voip_endpointInteraction'                    
begin                    
select @providername=(select providername from tbl_voip_endpointInteraction(nolock) where id=@refid)                  
declare @request_body nvarchar(max)                    
select @gatewayid=id from tbl_voip_ServiceProvider(nolock) where provider_name=@providername                    
select @request_body=request_body,@response=case when @gatewayid<>1 then response_content  else 'success' end                    
 from tbl_voip_endpointInteraction(nolock) where id=@refid                    
if @response not like '%success%'                    
begin                    
select                        
@Callendtime=created_on                    
,@Calldurationseconds=0                    
,@Billdurationseconds=0                    
,@agentmode=case when @gatewayid=1 then 'Extension' when @gatewayid=4 then 'Mobile'                    
when providername like '%_Asterisk' and (select json_value((select [value]  from openjson(@request_body)  where [key]='0'),'$.value')) like '%/%' then 'Extension'                     
else 'Mobile' end                    
,@agentnumber=case when @gatewayid=1 then  (select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value')) when @gatewayid=4 then                     
(select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value'))                    
when providername like '%_Asterisk' then (select json_value((select [value]  from openjson(@request_body)  where [key]='0'),'$.value')) else null end                    
,@agentcalldisposition='Not Connected'                    
,@customercalldisposition='Not Connected'                        
,@agentuserid=AgentId                    
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=AgentId                    
,@callscheduledfor=null                        
,@callcreatedon=created_on                    
,@parentid=dbo.ufn_GetUserParentId(AgentId)                    
,@appid  =null                    
from tbl_voip_endpointInteraction(nolock) where id=@refid                    
end                     
GOTO UPDATE_CallLOG                    
end                    
                    
drop table if exists #tbl_voip_webhook                        
select * into #tbl_voip_webhook from tbl_voip_webhook with (nolock) where id= @refid                         
select @gatewayid=srv_pro_id,@response=request_body,@uniqueidentity=UniqueIdentity,@interactionid=endpointid,                        
@Callendtime=created_on                        
 from #tbl_voip_webhook with (nolock) where id=@refid                        
select @calllogid=ID,@CallType=calltype,@gatewayid=gatewayid,@parentid=parentid,@direction=direction from CallLog(nolock) where reftable='tbl_voip_endpointInteraction'                         
and refid=@interactionid                     
select @calltypename=typename from calltypes where id=@calltype                       
drop table if exists #tbl_voip_endpointInteraction                          
select * into #tbl_voip_endpointInteraction from tbl_voip_endpointInteraction with (nolock) where id=@interactionid                         
select @Callstarttime=created_on,@createdtime=created_on,@createdby=agentid,@customerentity=isnull(EntityName,''),@customerentityid=isnull(EntityId,0)                        
,@agentuserid=agentid            
,@providername=providername from #tbl_voip_endpointInteraction                         
--select * into #t from tbl_voip_Webhook(nolock) t where ISNULL(request_body,'')<>'' --and t.id = (select MAX(id) from tbl_voip_Webhook(nolock) where srv_pro_id=t.srv_pro_id) --declare @r nvarchar(max),@s int=0,@i int=0 drop table if exists #jsonwebhook 
  
     
      
       
          
             
              
                
                  
                    
                      
create table #jsonwebhook([key] nvarchar(500),[value] nvarchar(max)) --while @i<3 --begin --select @s=MIN(srv_pro_id) from #t where srv_pro_id>@s --select @r=request_body from #t where srv_pro_id=@s                         
insert into #jsonwebhook([key],[value])                        
select [key],[value] from openjson(@response)                        
                        
--declare gateway variables--                        
declare @g1_extension nvarchar(100),@g1_destination nvarchar(50),@g1_callerid nvarchar(50),@g1_duration int                        
,@g1_status nvarchar(100),@g1_date nvarchar(100),@g1_recording_URL nvarchar(200),@g1_param1 bigint                        
declare @g3_from_number nvarchar(50),@g3_from_number_answer_time int,@g3_to_number nvarchar(50)                        
,@g3_to_number_answer_time int,@g3_campaignid nvarchar(10),@g3_answer_time int,@g3_status nvarchar(20)                        
,@g3_extension nvarchar(100),@g3_number nvarchar(20),@g3_recording_url nvarchar(200),@g3_from_number_status nvarchar(20)                        
,@g3_to_number_status nvarchar(20)                        
declare @g4_status nvarchar(20),@g4_duration int,@g4_refno nvarchar(100),@g4_endtime datetime,@g4_starttime datetime                        
,@g4_recordingurl nvarchar(200),@g4_from nvarchar(50),@g4_to nvarchar(50)                        
declare @g5_startime datetime,@g5_answertime datetime,@g5_endtime datetime,@g5_status nvarchar(20),@g5_recordingurl nvarchar(400),                    
@g5_mode nvarchar(20),@g5_dtmf nvarchar(20),@g5_duration int                       
                
if @gatewayid=1                        
begin               
/*Sample data            
{"extension":"115","destination":"919544268600","callerid":"914847136941","duration":"0","status":"CANCEL","date":"2022-05-31%2017:49:53","recording_URL":"null","param1":""}            
*/            
select @g1_extension =isnull(nullif(nullif([value],''),'null'),'') from #jsonwebhook where [Key]='extension'                        
select @g1_destination=[value] from #jsonwebhook where [Key]='destination'                        
select @g1_callerid=[value] from #jsonwebhook where [Key]='callerid'                        
select @g1_duration =case when isnumeric(isnull(nullif([value],''),'0'))=1 then CAST(isnull(nullif([value],''),'0') AS int)                        
 else 0 end from #jsonwebhook where [Key]='duration'                        
select @g1_status =[value] from #jsonwebhook where [Key]='status'                        
select @g1_date =case when isdate(replace([value],'%20',' ') )=1 then cast(replace([value],'%20',' ') AS datetime)                        
else @createdtime end from #jsonwebhook where [Key]='date'                        
select @g1_recording_URL =[value] from #jsonwebhook where [Key]='recording_URL'                        
select @g1_param1 =[value] from #jsonwebhook where [Key]='param1'                        
                        
select                      
@agentnumber=(select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value'))                    
,@Callendtime=(select dateadd(ss,@g1_duration,@Callstarttime))                        
,@Calldurationseconds=@g1_duration                        
,@Billdurationseconds=@g1_duration                        
,@agentmode=case when @g1_extension<>'' then 'Extension' else 'Mobile' end                        
,@agentcalldisposition=case when @direction='outgoing' then 'ANSWERED' else @g1_status end                        
,@customercalldisposition=case when @direction='incoming' then 'ANSWERED' else @g1_status end                     
,@agentuserid=@createdby                        
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=@createdby                        
,@callscheduledfor=null                        
,@callcreatedon=@createdtime                        
,@parentid=@parentid                        
,@appid  =null                   
,@recordurl=@g1_recording_URL                  
end                        
if @gatewayid=3                        
begin                        
create table #gateway3json ([key] nvarchar(200),[value] nvarchar(max))                        
declare @c int=(select COUNT(1) from #jsonwebhook),@kid int=0                        
while @c>0                        
begin                        
select @kid=MIN([key]) from #jsonwebhook where cast([key] as int)>=@kid                        
insert into #gateway3json([key],[value])                        
select [key],[value] from openjson((select [value] from #jsonwebhook where [key]=@kid))                        
set @kid=@kid+1                        
set @c=@c-1                        
end                        
select @g3_from_number =isnull(nullif(nullif([value],''),'null'),'') from #gateway3json where [Key]='from_number'                        
select @g3_from_number_answer_time=case when isnumeric(isnull(nullif([value],''),'0') )=1 then                        
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='from_number_answer_time'                        
select @g3_to_number=[value] from #gateway3json where [Key]='to_number'                        
select @g3_to_number_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then                        
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='to_number_answer_time'                        
select @g3_campaignid =[value] from #gateway3json where [Key]='campaignid'                        
select @g3_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then                        
cast(isnull(nullif([value],''),'0') AS int) else 0 end  from #gateway3json where [Key]='answer_time'                        
select @g3_status =[value] from #gateway3json where [Key]='status'                        
select @g3_extension =[value] from #gateway3json where [Key]='extension'                        
select @g3_number =[value] from #gateway3json where [Key]='number'                        
select @g3_recording_url =[value] from #gateway3json where [Key]='recording_url'                        
select @g3_from_number_status =[value] from #gateway3json where [Key]='from_number_status'                        
select @g3_to_number_status =[value] from #gateway3json where [Key]='to_number_status'                        
                        
select                        
@Agentnumber=(select mobile from dbo.fn_separatecountrycodeandmobile(@g3_from_number))                        
,@agentcountrycode=(select countrycode from dbo.fn_separatecountrycodeandmobile(@g3_from_number))                        
,@Callendtime=case when @g3_status='Answered' then DATEADD(ss,@g3_answer_time,@callstarttime) else @Callstarttime end                        
,@Agentpickuptime=case when @g3_from_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time,@Callstarttime) end                        
,@Customerpickuptime=case when @g3_to_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time +@g3_to_number_answer_time,@Callstarttime) end                        
,@Billdurationseconds=@g3_from_number_answer_time + @g3_to_number_answer_time                        
,@customerduration=@g3_to_number_answer_time                        
,@agentduration=@g3_from_number_answer_time                        
,@lastdtmf=null                        
,@agentmode=case when @g3_extension<>'-' then 'Extension' else 'Mobile' end                        
,@agentcalldisposition=@g3_from_number_status                        
,@customercalldisposition=@g3_to_number_status         
,@agentuserid=@createdby                        
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=@createdby                        
,@callscheduledfor=null                        
,@callcreatedon=@createdtime                        
,@parentid=@parentid                        
,@appid  =null                  
,@recordurl=@g3_recording_url                        
select @Calldurationseconds=DATEDIFF(ss,@callstarttime,@callendtime)                        
end                        
if @gatewayid=4                        
begin                      
--select * from #jsonwebhook                  
select @g4_status=[value] from #jsonwebhook where [Key]='status'                        
select @g4_duration=case when isnumeric(isnull(nullif([value],''),'0'))=1                         
then cast(isnull(nullif([value],''),'0') as int) else 0 end from #jsonwebhook where [Key]='duration'                        
select @g4_endtime=case when isdate([value])=1 then cast([value] as datetime)                         
else dateadd(ss,@g4_duration,@callstarttime) end from #jsonwebhook where [Key]='endtime'                        
select @g4_from=[value] from #jsonwebhook where [Key]='from'                        
select @g4_recordingurl=[value] from #jsonwebhook where [Key]='recordingurl'                        
select @g4_refno=[value] from #jsonwebhook where [Key]='refno'                        
select @g4_starttime=[value] from #jsonwebhook where [Key]='starttime'                        
select @g4_to=[value] from #jsonwebhook where [Key]='to'                        
                  
                   
--select @g4_duration duration                        
select                        
@Callendtime=@g4_endtime                        
,@Calldurationseconds=@g4_duration                        
,@Billdurationseconds=@g4_duration                        
,@agentmode='Mobile'                        
,@agentcalldisposition=case when @g4_status is not null then 'ANSWERED' else null end                        
,@customercalldisposition=@g4_status                        
,@agentuserid=@createdby                        
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=@createdby                        
,@callscheduledfor=null                        
,@callcreatedon=@createdtime                        
,@parentid=@parentid                        
,@appid  =null                  
,@recordurl=@g4_recordingurl                        
end                        
if @providername like '%_Asterisk'                        
begin                  
--{"refno":"40666","DateCreated":"2022-04-09 16:35:19","DateUpdated":"2022-04-09 16:36:47","Status":"ANSWER","To":" 917303590412","From":"SIP/4003-00000032","StartTime":null,"AnswerTime":"","EndTime":"2022-04-09 16:36:47","Direction":"outbound","Recording
      
        
          
            
              
--Url":"http://61.247.238.122:9090/Recordings/09Apr2022/0000_7303590412_09-Apr-2022-16-35-19.wav"                
--,"Total Price":"0.0","Mode":"Extension","Dtmfinput":"","ConversationDuration":"87"}                
select @g5_startime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'startime'                
select @g5_answertime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'answertime'                
select @g5_endtime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'endtime'                
select @g5_status =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'status'                
select @g5_recordingurl =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'recordingurl'                
select @g5_mode =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'mode'                
select @g5_dtmf =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'dtmf'                
select @g5_duration =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'duration'                
                    
select                        
@Callstarttime=Coalesce(@g5_startime,callstarttime)               
,@Customerpickuptime=coalesce(@g5_answertime,customerpickuptime)                
,@Callendtime=coalesce(@g5_endtime,callendtime)                        
,@Calldurationseconds=coalesce(@g5_duration,calldurationseconds)                        
,@Billdurationseconds=case when @g5_mode='Extension' then datediff(ss,coalesce(@g5_answertime,customerpickuptime),coalesce(@g5_endtime,callendtime))                
else isnull(datediff(ss,coalesce(@g5_answertime,customerpickuptime),coalesce(@g5_endtime,callendtime)),0)                
+isnull(datediff(ss,Coalesce(@g5_startime,callstarttime),coalesce(@g5_endtime,callendtime)),0) end                
,@agentmode=@g5_mode                 
,@agentcalldisposition='ANSWERED'                
,@customercalldisposition=coalesce(@g5_status,customercalldisposition)                
,@agentuserid=@createdby                        
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=@createdby                        
,@callscheduledfor=null                        
,@callcreatedon=@createdtime                        
,@parentid=@parentid                        
,@appid  =null                
,@recordurl=@g5_recordingurl                       
 from calllog(nolock) where id=@calllogid                
end                  
                  
                  
                  
end                        
                     
/*                        
select                        
--,@Agentnumber=a.mobile_no                        
--,@agentcountrycode=null--to be added in agent setting                        
@Callendtime=                        
case when @gatewayid=1                         
and ISNUMERIC((select cast(isnull(nullif([value],''),'0') as int) from #jsonwebhook where [key]='duration'))=1                        
then                         
(select dateadd(ss,@duration,@Callstarttime) from #jsonwebhook where [key]='duration')                        
when @gatewayid=3 then                        
case when                         
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='Status' )='Answered')                        
then @Callendtime else @Callstarttime end                        
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='EndTime') end                        
                        
,@Agentpickuptime=                 
case when @gatewayid=1 then null                        
when @gatewayid=3 then                         
case when                         
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' )<>'0')                        
then dateadd(ss,                        
cast(isnull(nullif((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ),''),'0') as int)                        
,@Callstarttime)                        
end                        
when @gatewayid=4 then null end                        
                        
,@Customerpickuptime=                        
case when @gatewayid=1 then null                        
when @gatewayid=3 then                         
case when                         
((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' )<>'0')                        
then dateadd(ss,                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) as int) +                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int),                        
@Callstarttime)                        
end                        
when @gatewayid=4 then null end                        
                        
,@Calldurationseconds=                        
case when @gatewayid=1 then (select dateadd(ss,cast(isnull(nullif([value],''),'0') as int),@Callstarttime) from #jsonwebhook where [key]='duration')                        
when @gatewayid=3 then DATEDIFF(ss,@callstarttime,@callendtime)                        
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='EndTime') end                        
                        
,@Billdurationseconds=                        
case when @gatewayid=1 then (select [value] from #jsonwebhook where [key]='duration')                        
when @gatewayid=3 then                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) as int) +                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int)                        
when @gatewayid=4 then (select [value] from #jsonwebhook where [key]='duration') end                        
                   
,@customerduration=                        
case when @gatewayid=1 then null                        
when @gatewayid=3 then                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_answer_time' ) AS int)                        
when @gatewayid=4 then null end                        
                        
,@agentduration=                        
case when @gatewayid=1 then null                        
when @gatewayid=3 then                        
cast((select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_answer_time' ) AS int)                        
when @gatewayid=4 then null end                        
                        
,@lastdtmf=null                        
                        
,@agentmode=                        
case                         
when @gatewayid=1 then                         
case when isnull(nullif((select [value] from #jsonwebhook where [key]='extension'),''),'null')<>'null'                        
then 'Extension' else 'Mobile' end                        
when @gatewayid=3 then                        
case when (select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='extension')='-'                         
then 'Extension' else 'Mobile' end                        
when @gatewayid=4 then                        
'Mobile' end                        
                        
,@agentcalldisposition=                        
case when @gatewayid=1 then                         
case when (select [value] from #jsonwebhook where [key]='status')='ANSWERED' then 'ANSWER'                        
else null end                        
when @gatewayid=3 then                          
(select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='from_number_status')                         
when @gatewayid=4 then                          
case when (select [value] from #jsonwebhook where [key]='status')='ANSWERED' then 'ANSWER'                        
else null end                        
end                        
                        
,@customercalldisposition=                        
case when @gatewayid=1 then                         
(select [value] from #jsonwebhook where [key]='status')                        
when @gatewayid=3 then                          
(select JSON_VALUE([value],'$.Value') from #jsonwebhook where JSON_VALUE([value],'$.Key')='to_number_status')                        
when @gatewayid=4 then                          
(select [value] from #jsonwebhook where [key]='status')                        
end                        
                        
,@agentuserid=@createdby                        
,@outcomeid=null                        
,@remarks=null                        
,@callcreatedby=@createdby                        
,@callscheduledfor=null                        
,@callcreatedon=@createdtime                        
,@parentid=@parentid                        
,@appid  =null                        
*/                        
                     
UPDATE_CallLOG:                    
          
select @agentcountrycode=                    
case when @agentcountrycode is null then isnull(cloud_countrycode, countrycode) else @agentcountrycode end                    
,@Agentnumber=case when @agentnumber is null then isnull(cloud_no,str(mobile)) else @Agentnumber end                    
 from   
 (select u.*,cc.cloud_countrycode,cc.cloud_no from user_detail(nolock) u left join cloud_call_no cc on cc.user_id=u.user_id) u   
   
 where user_id=@agentuserid                       
update calllog set                         
customercountrycode=case when customercountrycode is null and @customercountrycode                     
is not null then @customercountrycode when @customerentity='lead' then                     
(select coalesce(countrycode,countrycode1,countrycode2) from userleads(nolock) where id=@customerentityid)                    
when @customerentity='enquiry' then                     
(select coalesce(countrycode,countrycode1,countrycode2) from userenquiry(nolock) where EnquiryID=@customerentityid)                    
when @customerentity='' and             
@Customernumber like '% %'            
then (select countrycode from dbo.fn_separatecountrycodeandmobile(replace(@Customernumber,' ','')))            
end            
,customerentity=@customerentity          
,customerentityid=@customerentityid          
,Agentnumber=@Agentnumber                        
,agentcountrycode=@agentcountrycode                        
,Callstarttime=@Callstarttime                        
,Callendtime=@Callendtime                        
,Agentpickuptime=@Agentpickuptime                        
,Customerpickuptime=case when @calltypename='incoming' then @Callstarttime else @Customerpickuptime end                    
,Calldurationseconds=@Calldurationseconds                        
,Billdurationseconds=@Billdurationseconds                        
,customerduration=case when @calltypename='incoming' and datediff(ss,@callstarttime,@callendtime) is not null then                    
datediff(ss,@callstarttime,@callendtime) else @customerduration end                       
,agentduration=@agentduration                        
,lastdtmf=@lastdtmf                        
,agentmode=@agentmode                        
,agentcalldisposition=@agentcalldisposition                        
,customercalldisposition=case when @calltypename<>'Click2Call' then 'ANSWERED' else @customercalldisposition end                       
,agentuserid=@agentuserid                        
,callcreatedby=@callcreatedby                        
,callcreatedon=case when @callcreatedon is null then @Callstarttime else @callcreatedon end                       
,parentid=@parentid                        
,appid=@appid                   
,recordurl=case when gatewayid=7 and isnull(@recordurl,'')<>'' and @recordurl not like '%c2c_%' then replace(@recordurl,'recordings.kit19.com/','recordings.kit19.com/'+cast(@parentid as nvarchar)+'/'+format(@Callstarttime,
'ddMMMyyyy')+'/C2C_') else @recordurl end                      
from CallLog where id=@calllogid                        
           
 begin try          
 if @reftable='Kit19calls' and @direction='incoming' and not exists(select 1 from tbl_leadeventhistory(nolock) where reftables='Kit19callsdialled' and refids=isnull(@kit19dialledid,0))          begin          
declare @eventname nvarchar(50),@eventdescription nvarchar(1000)          
if isnull(@customerentity,'')<>''          
begin          
select @eventname=isnull(@customerentity,'')+case when @agentcalldisposition<>'Answered'  then '''s call missed' else ' calls up' end,                
@eventdescription='An inbound call from                          
phone '+cast(@customernumber as nvarchar(20)) +' by '+@customerentity + ' ' +dbo.fn_getentityfullname(@customerentity,@customerentityid)           
+' was '+@agentcalldisposition+'.           
The last user attempted was ' +isnull(dbo.fn_getentityfullname('user',@agentuserid),'none')                          
end                          
else if @Customernumber is not null and isnull(@agentuserid,0)<>0                         
begin                          
select @customerentity='user',@customerentityid=@agentuserid,@eventname='User missed call',@eventdescription='An inbound call from                          
phone '+cast(@customernumber as nvarchar(20)) +' was missed by '+ dbo.fn_getentityfullname('user',@agentuserid)                          
end          
/*Commented as we are generating an activity with [usp_updatecallendtime] at call end    
if isnull(@customerentity,'')<>''                   
begin                         
declare @uid bigint=isnull(@agentuserid,@parentid)        
exec uspsaveentityactivity_withid @customerentity,@customerentityid,@uid,@parentid,@eventdescription,@eventname,'Kit19callsdialled',                          
@kit19dialledid                          
end     
*/    
end           
end try          
begin catch          
exec usp_inserterrorinfo          
end catch          
                        
          
end                         
end                          


GO

/* ============================================================
   Procedure: [dbo].[usp_updatecalllog_withreftable_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from Calltypes                    
CREATE   PROCEDURE [dbo].[usp_updatecalllog_withreftable_agents]  --'tbl_voip_Webhook',30919                  
(@reftable nvarchar(100),@refid bigint)                      
as                      
begin                    
--declare @reftable nvarchar(100)='tbl_voip_Webhook',@refid bigint=32773            
declare @iid bigint=case when @reftable='tbl_voip_webhook' then (select endpointid from tbl_voip_webhook            
where id=@refid) else 0 end            
if exists(select 1 from CallLog(nolock) where refid=case when @reftable='tbl_voip_webhook' then @iid else @refid            
end  and reftable=case when @reftable='tbl_voip_webhook'              
then 'tbl_voip_endpointInteraction' else @reftable end)              
begin                
--declare @reftable nvarchar(100)='tbl_voip_Webhook',@refid bigint              
declare @CallType int,@gatewayid int,@calltypename nvarchar(20),@recordurl nvarchar(500),                      
@Customernumber nvarchar(20),@customercountrycode nvarchar(10),@Agentnumber nvarchar(20),@agentcountrycode nvarchar(10),                      
@Callstarttime datetime,@Callendtime datetime,@Agentpickuptime datetime,@Customerpickuptime datetime,                      
@Calldurationseconds int,@Billdurationseconds int,@customerduration int,@agentduration int,                      
@lastdtmf nvarchar(50),@agentmode nvarchar(20),@agentcalldisposition nvarchar(50),@agent_type nvarchar(20),@calling_agentid bigint,                          
@customercalldisposition nvarchar(50),@agentuserid bigint,@outcomeid bigint,@remarks nvarchar(max),                      
@customerentity nvarchar(20),@customerentityid bigint,@callcreatedby bigint,@callscheduledfor datetime,                      
@callcreatedon datetime,@parentid bigint,@appid bigint,@calllogid bigint,@uniqueid nvarchar(100),                    
@accountcode nvarchar(50),@kit19uniqueid nvarchar(100)            ,@direction nvarchar(20),@kit19dialledid bigint        
declare @batchid bigint,@createdby bigint,@createdtime datetime                    
if @reftable='Kit19calls'                      
begin                     
select @parentid=clientid from kit19calls(nolock) where id=@refid      
select @calllogid=ID,@CallType=calltype,@customerentity=customerentity,@customerentityid=customerentityid,@customernumber=customernumber,@direction=Direction      
from CallLog(nolock) where reftable='Kit19calls' and refid=@refid             
      
if isnull(@customerentity,'')=''      
begin      
select @customerentity=                        
case when exists(select 1 from userleads_mobile_email(nolock) where parentid=@parentid and  dbo.fn_trim0prefix(@Customernumber) =mobile)                        
then 'lead'                        
when exists(select 1 from userenquiry_mobile_email(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber) =mobile)                        
then 'enquiry'                        
end                        
select @customerentityid=                        
case when @customerentity='lead'                        
then (select top 1 id from userleads(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                        
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by id desc)                         
when @customerentity='enquiry'                        
then (select top 1 EnquiryID from userenquiry(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                        
in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by EnquiryID desc)                         
end                        
      
      
end      
print 'customerentity: '+@customerentity+', Customerentityid: '+cast(@customerentityid as nvarchar)      
drop table if exists #kit19calls                      
select * into #kit19calls from kit19calls with (nolock) where id=@refid                     
select @uniqueid=uniqueid,@parentid=clientid,@Callendtime=call_end_time ,@recordurl=  
case when dbo.fn_getcallstatus(uniqueid)='Answered' then recordurl else null end                   
,@Callstarttime=call_start_time,@Calldurationseconds=datediff(SS,call_start_time,call_end_time)          
,@lastdtmf=call_last_dtmf,@accountcode=accountcode,@kit19uniqueid=kit19uniqueid,@appid=appid              
 from #kit19calls                
 select @calltypename=typename from calltypes where id=@CallType                     
if @calltypename<>'Click2Call'                
begin                    
if @calltypename='OBD'                    
begin                    
select @batchid=k.batchid,@createdby=b.UserID,@createdtime=ISNULL(nullif(b.Scheduleddate,''),BatchInsertTime)                     
from Kit19Cloudvoicefinaltbl(nolock) k                     
join BatchVoiceInfo(nolock) b on b.BatchID=k.batchid                    
where kit19uniqueid=@kit19uniqueid                    
end                    
select top 1 @kit19dialledid=k.id,@Agentnumber=dbo.fn_trim0prefix(agentnumber)    
,@calling_agentid=K.kc_agentid  
,@agent_type=case when kc_agentid is not null then 'Agent' else 'User' end  
,@agentcountrycode=isnull(cloud_countrycode,CountryCode)                    
,@Agentpickuptime=call_answer_time                    
,@Customerpickuptime=case when @calltypename='Incoming' then null else @callstarttime end                    
,@Billdurationseconds=case when @calltypename='Incoming' then datediff(SS,call_answer_time,call_end_time)                    
else datediff(SS,@callstarttime,@callendtime) + isnull(datediff(SS,call_answer_time,call_end_time),0) end                    
,@customerduration=datediff(SS,@callstarttime,@callendtime)                    
,@agentduration=datediff(SS,isnull(call_answer_time,call_end_time),call_end_time)                    
,@agentmode=CASE WHEN AgentType='Mobile' then 'Mobile' else 'Extension' end                    
,@agentcalldisposition=case when isnull(dialstatus,'NOANSWER') ='ANSWER' then 'ANSWERED' else  upper(isnull(dialstatus,'NOANSWER')) end                  
,@customercalldisposition='ANSWERED'                  
,@agentuserid=USER_ID                    
,@callcreatedby=case when @calltypename='OBD' then @createdby end                    
,@callcreatedon=case when @calltypename='OBD' then @createdtime else @callstarttime end                    
from Kit19CallsDialled(nolock) k                    
left join (select u.*,cc.cloud_no,cc.cloud_countrycode from User_Detail(nolock) u left join cloud_call_no cc on cc.user_id=u.user_id) u on                      
u.parentid=@parentid and       
(isnull(k.kc_agentuserid,u.user_id)=u.user_id or dbo.fn_trim0prefix(agentnumber)=case when AgentType='User' then User_ID else isnull(cloud_no,STR(mobile)) end)                    
where puniqueid=@uniqueid                    
order by case when dialstatus='ANSWER' then 0 else 1 end,call_start_time desc               
              
select @Billdurationseconds=case when @calltypename='Incoming' and @agentcalldisposition<>'ANSWERED' then 0 else @Billdurationseconds end                   
--select top 10 * from kit19callsdialled(nolock) order by id desc                    
end                    
else if @calltypename='Click2Call'                    
begin                    
select top 1 @Agentnumber=@accountcode                    
,@agentcountrycode=CountryCode                    
,@Agentpickuptime=@callstarttime                    
,@Customerpickuptime=call_answer_time                    
,@Billdurationseconds=ISNULL(billedtime,0)                    
,@customerduration=ISNULL(billedtime,0)                    
,@agentduration=datediff(SS,@callstarttime,@callendtime)                    
,@agentmode='Extension'                    
,@agentcalldisposition='ANSWERED'                    
,@customercalldisposition=case when disposition='answer' then 'ANSWERED' else upper(disposition) end                     
,@agentuserid=k.USER_ID                    
,@callcreatedby=@accountcode                    
,@callcreatedon=@callstarttime                    
,@customercountrycode='+'+left(dnidnowithcountrycode,LEN(dnidnowithcountrycode)-len(dnid))                    
from Diallercalls(nolock) k                    
left join User_Detail(nolock) u on                    
u.User_ID=k.user_id                    
where k.kit19callsid=@refid                    
--select top 10 * from DiallerCalls(nolock) order by id desc                    
end                    
end                    
else if @reftable='tbl_voip_Webhook'  or @reftable='tbl_voip_endpointInteraction'                  
begin                    
declare @interactionid bigint,@response nvarchar(max),@uniqueidentity nvarchar(100)                
declare @providername nvarchar(50)                  
if @reftable='tbl_voip_endpointInteraction'                
begin                
select @providername=(select providername from tbl_voip_endpointInteraction(nolock) where id=@refid)              
declare @request_body nvarchar(max)                
select @gatewayid=id from tbl_voip_ServiceProvider(nolock) where provider_name=@providername                
select @request_body=request_body,@response=case when @gatewayid<>1 then response_content  else 'success' end                
 from tbl_voip_endpointInteraction(nolock) where id=@refid                
if @response not like '%success%'                
begin                
select                    
@Callendtime=created_on                
,@Calldurationseconds=0                
,@Billdurationseconds=0                
,@agentmode=case when @gatewayid=1 then 'Extension' when @gatewayid=4 then 'Mobile'                
when providername like '%_Asterisk' and (select json_value((select [value]  from openjson(@request_body)  where [key]='0'),'$.value')) like '%/%' then 'Extension'                 
else 'Mobile' end                
,@agentnumber=case when @gatewayid=1 then  (select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value')) when @gatewayid=4 then                 
(select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value'))                
when providername like '%_Asterisk' then (select json_value((select [value]  from openjson(@request_body)  where [key]='0'),'$.value')) else null end                
,@agentcalldisposition='Not Connected'                
,@customercalldisposition='Not Connected'                    
,@agentuserid=AgentId                
,@outcomeid=null                    
,@remarks=null                    
,@callcreatedby=AgentId                
,@callscheduledfor=null                    
,@callcreatedon=created_on                
,@parentid=dbo.ufn_GetUserParentId(AgentId)                
,@appid  =null                
from tbl_voip_endpointInteraction(nolock) where id=@refid                
end                 
GOTO UPDATE_CallLOG                
end                
                
drop table if exists #tbl_voip_webhook                    
select * into #tbl_voip_webhook from tbl_voip_webhook with (nolock) where id= @refid                     
select @gatewayid=srv_pro_id,@response=request_body,@uniqueidentity=UniqueIdentity,@interactionid=endpointid,                    
@Callendtime=created_on                    
 from #tbl_voip_webhook with (nolock) where id=@refid                    
select @calllogid=ID,@CallType=calltype,@gatewayid=gatewayid,@parentid=parentid,@direction=direction from CallLog(nolock) where reftable='tbl_voip_endpointInteraction'                     
and refid=@interactionid                 
select @calltypename=typename from calltypes where id=@calltype                   
drop table if exists #tbl_voip_endpointInteraction                      
select * into #tbl_voip_endpointInteraction from tbl_voip_endpointInteraction with (nolock) where id=@interactionid                     
select @Callstarttime=created_on,@createdtime=created_on,@createdby=agentid,@customerentity=isnull(EntityName,''),@customerentityid=isnull(EntityId,0)                    
,@agentuserid=agentid        
,@providername=providername from #tbl_voip_endpointInteraction                     
--select * into #t from tbl_voip_Webhook(nolock) t where ISNULL(request_body,'')<>'' --and t.id = (select MAX(id) from tbl_voip_Webhook(nolock) where srv_pro_id=t.srv_pro_id) --declare @r nvarchar(max),@s int=0,@i int=0 drop table if exists #jsonwebhook  
 
    
      
         
          
            
              
                
                  
create table #jsonwebhook([key] nvarchar(500),[value] nvarchar(max)) --while @i<3 --begin --select @s=MIN(srv_pro_id) from #t where srv_pro_id>@s --select @r=request_body from #t where srv_pro_id=@s                     
insert into #jsonwebhook([key],[value])                    
select [key],[value] from openjson(@response)                    
                    
--declare gateway variables--                    
declare @g1_extension nvarchar(100),@g1_destination nvarchar(50),@g1_callerid nvarchar(50),@g1_duration int                    
,@g1_status nvarchar(100),@g1_date nvarchar(100),@g1_recording_URL nvarchar(200),@g1_param1 bigint                    
declare @g3_from_number nvarchar(50),@g3_from_number_answer_time int,@g3_to_number nvarchar(50)                    
,@g3_to_number_answer_time int,@g3_campaignid nvarchar(10),@g3_answer_time int,@g3_status nvarchar(20)                    
,@g3_extension nvarchar(100),@g3_number nvarchar(20),@g3_recording_url nvarchar(200),@g3_from_number_status nvarchar(20)                    
,@g3_to_number_status nvarchar(20)                    
declare @g4_status nvarchar(20),@g4_duration int,@g4_refno nvarchar(100),@g4_endtime datetime,@g4_starttime datetime                    
,@g4_recordingurl nvarchar(200),@g4_from nvarchar(50),@g4_to nvarchar(50)                    
declare @g5_startime datetime,@g5_answertime datetime,@g5_endtime datetime,@g5_status nvarchar(20),@g5_recordingurl nvarchar(400),                
@g5_mode nvarchar(20),@g5_dtmf nvarchar(20),@g5_duration int                   
            
if @gatewayid=1                    
begin           
/*Sample data        
{"extension":"115","destination":"919544268600","callerid":"914847136941","duration":"0","status":"CANCEL","date":"2022-05-31%2017:49:53","recording_URL":"null","param1":""}        
*/        
select @g1_extension =isnull(nullif(nullif([value],''),'null'),'') from #jsonwebhook where [Key]='extension'                    
select @g1_destination=[value] from #jsonwebhook where [Key]='destination'                    
select @g1_callerid=[value] from #jsonwebhook where [Key]='callerid'                    
select @g1_duration =case when isnumeric(isnull(nullif([value],''),'0'))=1 then CAST(isnull(nullif([value],''),'0') AS int)                    
 else 0 end from #jsonwebhook where [Key]='duration'                    
select @g1_status =[value] from #jsonwebhook where [Key]='status'                    
select @g1_date =case when isdate(replace([value],'%20',' ') )=1 then cast(replace([value],'%20',' ') AS datetime)                    
else @createdtime end from #jsonwebhook where [Key]='date'                    
select @g1_recording_URL =[value] from #jsonwebhook where [Key]='recording_URL'                    
select @g1_param1 =[value] from #jsonwebhook where [Key]='param1'                    
                    
select                  
@agentnumber=(select json_value((select [value]  from openjson(@request_body)  where [key]='2'),'$.value'))                
,@Callendtime=(select dateadd(ss,@g1_duration,@Callstarttime))                    
,@Calldurationseconds=@g1_duration                    
,@Billdurationseconds=@g1_duration                    
,@agentmode=case when @g1_extension<>'' then 'Extension' else 'Mobile' end                    
,@agentcalldisposition=case when @direction='outgoing' then 'ANSWERED' else @g1_status end                    
,@customercalldisposition=case when @direction='incoming' then 'ANSWERED' else @g1_status end                 
,@agentuserid=@createdby                    
,@outcomeid=null                    
,@remarks=null                    
,@callcreatedby=@createdby                    
,@callscheduledfor=null                    
,@callcreatedon=@createdtime                    
,@parentid=@parentid                    
,@appid  =null               
,@recordurl=@g1_recording_URL                   
end                    
if @gatewayid=3                    
begin                    
create table #gateway3json ([key] nvarchar(200),[value] nvarchar(max))                    
declare @c int=(select COUNT(1) from #jsonwebhook),@kid int=0                    
while @c>0                    
begin                    
select @kid=MIN([key]) from #jsonwebhook where cast([key] as int)>=@kid                    
insert into #gateway3json([key],[value])                    
select [key],[value] from openjson((select [value] from #jsonwebhook where [key]=@kid))                    
set @kid=@kid+1                    
set @c=@c-1                    
end                    
select @g3_from_number =isnull(nullif(nullif([value],''),'null'),'') from #gateway3json where [Key]='from_number'                    
select @g3_from_number_answer_time=case when isnumeric(isnull(nullif([value],''),'0') )=1 then                    
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='from_number_answer_time'                    
select @g3_to_number=[value] from #gateway3json where [Key]='to_number'                    
select @g3_to_number_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then                    
cast(isnull(nullif([value],''),'0') AS int) else 0 end from #gateway3json where [Key]='to_number_answer_time'                    
select @g3_campaignid =[value] from #gateway3json where [Key]='campaignid'                    
select @g3_answer_time =case when isnumeric(isnull(nullif([value],''),'0') )=1 then                    
cast(isnull(nullif([value],''),'0') AS int) else 0 end  from #gateway3json where [Key]='answer_time'                    
select @g3_status =[value] from #gateway3json where [Key]='status'                    
select @g3_extension =[value] from #gateway3json where [Key]='extension'                    
select @g3_number =[value] from #gateway3json where [Key]='number'                    
select @g3_recording_url =[value] from #gateway3json where [Key]='recording_url'                    
select @g3_from_number_status =[value] from #gateway3json where [Key]='from_number_status'                    
select @g3_to_number_status =[value] from #gateway3json where [Key]='to_number_status'                    
                    
select                    
@Agentnumber=(select mobile from dbo.fn_separatecountrycodeandmobile(@g3_from_number))                    
,@agentcountrycode=(select countrycode from dbo.fn_separatecountrycodeandmobile(@g3_from_number))                    
,@Callendtime=case when @g3_status='Answered' then DATEADD(ss,@g3_answer_time,@callstarttime) else @Callstarttime end                    
,@Agentpickuptime=case when @g3_from_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time,@Callstarttime) end                    
,@Customerpickuptime=case when @g3_to_number_answer_time>0 then dateadd(ss,@g3_from_number_answer_time +@g3_to_number_answer_time,@Callstarttime) end                    
,@Billdurationseconds=@g3_from_number_answer_time + @g3_to_number_answer_time                    
,@customerduration=@g3_to_number_answer_time                    
,@agentduration=@g3_from_number_answer_time                    
,@lastdtmf=null                    
,@agentmode=case when @g3_extension<>'-' then 'Extension' else 'Mobile' end                    
,@agentcalldisposition=@g3_from_number_status                    
,@customercalldisposition=@g3_to_number_status                    
,@agentuserid=@createdby                    
,@outcomeid=null                    
,@remarks=null                    
,@callcreatedby=@createdby                    
,@callscheduledfor=null                    
,@callcreatedon=@createdtime                    
,@parentid=@parentid                    
,@appid  =null              
,@recordurl=@g3_recording_url                    
select @Calldurationseconds=DATEDIFF(ss,@callstarttime,@callendtime)                    
end                    
if @gatewayid=4                    
begin                    
--select * from #jsonwebhook              
select @g4_status=[value] from #jsonwebhook where [Key]='status'                    
select @g4_duration=case when isnumeric(isnull(nullif([value],''),'0'))=1                     
then cast(isnull(nullif([value],''),'0') as int) else 0 end from #jsonwebhook where [Key]='duration'                    
select @g4_endtime=case when isdate([value])=1 then cast([value] as datetime)                     
else dateadd(ss,@g4_duration,@callstarttime) end from #jsonwebhook where [Key]='endtime'                    
select @g4_from=[value] from #jsonwebhook where [Key]='from'                    
select @g4_recordingurl=[value] from #jsonwebhook where [Key]='recordingurl'                    
select @g4_refno=[value] from #jsonwebhook where [Key]='refno'                    
select @g4_starttime=[value] from #jsonwebhook where [Key]='starttime'                    
select @g4_to=[value] from #jsonwebhook where [Key]='to'                    
              
               
--select @g4_duration duration                    
select                    
@Callendtime=@g4_endtime                    
,@Calldurationseconds=@g4_duration                    
,@Billdurationseconds=@g4_duration                    
,@agentmode='Mobile'                    
,@agentcalldisposition=case when @g4_status is not null then 'ANSWERED' else null end                    
,@customercalldisposition=@g4_status                    
,@agentuserid=@createdby                    
,@outcomeid=null                    
,@remarks=null                    
,@callcreatedby=@createdby                    
,@callscheduledfor=null                    
,@callcreatedon=@createdtime                    
,@parentid=@parentid                    
,@appid  =null              
,@recordurl=@g4_recordingurl                    
end                    
if @providername like '%_Asterisk'                    
begin              
--{"refno":"40666","DateCreated":"2022-04-09 16:35:19","DateUpdated":"2022-04-09 16:36:47","Status":"ANSWER","To":" 917303590412","From":"SIP/4003-00000032","StartTime":null,"AnswerTime":"","EndTime":"2022-04-09 16:36:47","Direction":"outbound","Recording
  
    
      
        
          
--Url":"http://61.247.238.122:9090/Recordings/09Apr2022/0000_7303590412_09-Apr-2022-16-35-19.wav"            
--,"Total Price":"0.0","Mode":"Extension","Dtmfinput":"","ConversationDuration":"87"}            
select @g5_startime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'startime'            
select @g5_answertime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'answertime'            
select @g5_endtime =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'endtime'            
select @g5_status =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'status'            
select @g5_recordingurl =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'recordingurl'            
select @g5_mode =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'mode'            
select @g5_dtmf =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'dtmf'            
select @g5_duration =nullif(nullif([value],'null'),'') from #jsonwebhook where [key]= 'duration'            
                
select                    
@Callstarttime=Coalesce(@g5_startime,callstarttime)            
,@Customerpickuptime=coalesce(@g5_answertime,customerpickuptime)            
,@Callendtime=coalesce(@g5_endtime,callendtime)                    
,@Calldurationseconds=coalesce(@g5_duration,calldurationseconds)                    
,@Billdurationseconds=case when @g5_mode='Extension' then datediff(ss,coalesce(@g5_answertime,customerpickuptime),coalesce(@g5_endtime,callendtime))            
else isnull(datediff(ss,coalesce(@g5_answertime,customerpickuptime),coalesce(@g5_endtime,callendtime)),0)            
+isnull(datediff(ss,Coalesce(@g5_startime,callstarttime),coalesce(@g5_endtime,callendtime)),0) end            
,@agentmode=@g5_mode                    
,@agentcalldisposition='ANSWERED'            
,@customercalldisposition=coalesce(@g5_status,customercalldisposition)            
,@agentuserid=@createdby                    
,@outcomeid=null                    
,@remarks=null                    
,@callcreatedby=@createdby                    
,@callscheduledfor=null                    
,@callcreatedon=@createdtime                    
,@parentid=@parentid                    
,@appid  =null            
,@recordurl=@g5_recordingurl                   
 from calllog(nolock) where id=@calllogid            
end              
              
              
              
end                    
                 
