UPDATE_CallLOG:                
      
select @agentcountrycode=                
case when @agentcountrycode is null then isnull(cloud_countrycode, countrycode) else @agentcountrycode end                
,@Agentnumber=case when @agentnumber is null then isnull(cloud_no,str(mobile)) else @Agentnumber end                
 from  (select u.*,cc.cloud_no,cc.cloud_countrycode from User_Detail(nolock) u left join cloud_call_no cc on cc.user_id=u.user_id) u                      

 where user_id=@agentuserid                   
update calllog set                     
customercountrycode=case when customercountrycode is null and @customercountrycode                 
is not null then @customercountrycode when @customerentity='lead' then                 
(select coalesce(countrycode,countrycode1,countrycode2) from userleads(nolock) where id=@customerentityid)                
when @customerentity='enquiry' then                 
(select coalesce(countrycode,countrycode1,countrycode2) from userenquiry(nolock) where EnquiryID=@customerentityid)                
when @customerentity='' and         
@Customernumber like '% %'        
then (select countrycode from dbo.fn_separatecountrycodeandmobile(replace(@Customernumber,' ','')))        
end       
,customerentity=@customerentity      
,customerentityid=@customerentityid      
,Agentnumber=@Agentnumber                    
,agentcountrycode=@agentcountrycode                    
,Callstarttime=@Callstarttime                    
,Callendtime=@Callendtime                    
,Agentpickuptime=@Agentpickuptime                    
,Customerpickuptime=case when @calltypename='incoming' then @Callstarttime else @Customerpickuptime end                
,Calldurationseconds=@Calldurationseconds                    
,Billdurationseconds=@Billdurationseconds                    
,customerduration=case when @calltypename='incoming' and datediff(ss,@callstarttime,@callendtime) is not null then                
datediff(ss,@callstarttime,@callendtime) else @customerduration end                   
,agentduration=@agentduration                    
,lastdtmf=@lastdtmf                    
,agentmode=@agentmode                    
,agentcalldisposition=@agentcalldisposition                    
,customercalldisposition=case when @calltypename<>'Click2Call' then 'ANSWERED' else @customercalldisposition end                   
,agentuserid=@agentuserid                    
,callcreatedby=@callcreatedby                 
,callcreatedon=case when @callcreatedon is null then @Callstarttime else @callcreatedon end                   
,parentid=@parentid                    
,appid=@appid               
,recordurl=@recordurl                   
,agent_type=@agent_type  
,calling_agentid=@calling_agentid  
from CallLog where id=@calllogid                    
       
 begin try      
 if @reftable='Kit19calls' and @direction='incoming' and not exists(select 1 from tbl_leadeventhistory(nolock) where reftables='Kit19callsdialled' and refids=isnull(@kit19dialledid,0))      
begin      
declare @eventname nvarchar(50),@eventdescription nvarchar(1000)      
if isnull(@customerentity,'')<>''      
begin      
select @eventname=isnull(@customerentity,'')+case when @agentcalldisposition<>'Answered'  then '''s call missed' else ' calls up' end,            
@eventdescription='An inbound call from                      
phone '+cast(@customernumber as nvarchar(20)) +' by '+@customerentity + ' ' +dbo.fn_getentityfullname(@customerentity,@customerentityid)       
+' was '+@agentcalldisposition+'.       
The last user attempted was ' +isnull(dbo.fn_getentityfullname('agent',@calling_agentid),'none')                      
end                      
else if @Customernumber is not null and isnull(@agentuserid,0)<>0                     
begin                      
select @customerentity='user',@customerentityid=@agentuserid,@eventname='User missed call',@eventdescription='An inbound call from                      
phone '+cast(@customernumber as nvarchar(20)) +' was missed by '+ dbo.fn_getentityfullname('user',@agentuserid)                      
end                      
if isnull(@customerentity,'')<>'' and isnull(@agentuserid,0)<>0                                  
begin                     
declare @uid bigint=isnull(@agentuserid,@parentid)    
exec uspsaveentityactivity_withid @customerentity,@customerentityid,@uid,@parentid,@eventdescription,@eventname,'Kit19callsdialled',                      
@kit19dialledid                      
end             
end       
end try      
begin catch      
exec usp_inserterrorinfo      
end catch      
                    
      
end                     
end                      
                      
                      
--select top 100 * from kit19calls(nolock) where left(callerid,1) not in ('1','6','7','8','9') order by id desc                    
                    
--select top 10 * from Kit19Cloudvoicefinaltbl(nolock) order by id desc                    
                    
--select * from #jsonwebhook


