/* ============================================================
   Procedure: [dbo].[usp_updateCallsNotPlayed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[usp_updateCallsNotPlayed]                
 as                
 begin     
 create table #updated(kid bigint,voiceid bigint,retrydetails nvarchar(1000),dialstatus nvarchar(100),lastaccesstime datetime)    
  update k set processed=0,retries=isnull(retries,0)+1,    
  retrydetails= isnull(retrydetails,' ')+' Attempted at '+cast(Lastaccesstime as nvarchar(40)) +' Status: '+isnull(dialstatus,'')+'.' --,dialstatus=null            
  output inserted.id as Kid,inserted.messageid as voiceid,inserted.RetryDetails as retrydetails,    
  inserted.Dialstatus as dialstatus,inserted.LastAccessTime as lastaccesstime     
  into #updated     
  from Kit19Cloudvoicefinaltbl k                
left join kit19calls kc on k.kit19uniqueid=kc.kit19uniqueid                
 where processed=2 and DATEDIFF(mi,lastaccesstime,getdate())>case when dialstatus='CHANUNAVAIL' then 1 else 5 end and               
 datediff(MINUTE,k.ScheduleDateTime,getdate())<=60               
 and kc.id is null and isnull(Dialstatus,'') <> 'ANSWER'  and k.priority>0  and     
 isnull(retries,0)<case when dialstatus='CHANUNAVAIL' then 10 else 2 end            
      
    
 update k set dialstatus='ANSWER'      
 output inserted.id as Kid,inserted.messageid as voiceid,inserted.RetryDetails as retrydetails,    
  inserted.Dialstatus as dialstatus,inserted.LastAccessTime as lastaccesstime     
  into #updated     
 from Kit19Cloudvoicefinaltbl k                
 join kit19calls kc on k.kit19uniqueid=kc.kit19uniqueid                
 where processed=2 and DATEDIFF(mi,lastaccesstime,getdate())>5 and               
 k.ScheduleDateTime>cast(getdate() as date)      
 and dialstatus is null      
    
update v set voicestatus=dialstatus,StatusDescription=retrydetails,StatusCompletedTime=lastaccesstime,IsCompleted=1    
from Voice_DeliveryStatus v join #updated u on v.VoiceID=u.voiceid    
      
drop table #updated    
 end   
  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateCampaignDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_UpdateCampaignDetails (  
 @CampaignID BIGINT  
 ,@Name NVARCHAR(100)  
 ,@UserID INT  
 ,@IsEditable BIT  
 ,@IsActive BIT  
 ,@ModifiedBy NVARCHAR(50)  
 )  
AS  
BEGIN 

        select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')   

 IF (  
   NOT EXISTS (  
    SELECT 'x'  
    FROM UserCampaignSettings  
    WHERE NAME = @Name  
     AND CampaignID <> @CampaignID  
     AND UserID = @UserID  
    )  
   )  
 BEGIN  
  UPDATE UserCampaignSettings  
  SET NAME = @Name  
   ,UserID = @UserID  
   ,ModifiedDate = GETDATE()  
   ,ModifiedBy = @ModifiedBy  
  WHERE CampaignID = @CampaignID  
  
  SELECT 'Record Updated'  
 END  
 ELSE  
 BEGIN  
  SELECT 'Already Exist'  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM UserCampaignSettings(NOLOCK)  
   WHERE CampaignID = @CampaignID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'Updt_Cmpgn'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'UserCampaignSettings'  
END  


