	@ExclusionsNumber VARCHAR(MAX),
	@InclusionsNumber VARCHAR(MAX),
	@Exclusions VARCHAR(MAX),
	@SenderID VARCHAR(100) = NULL,
	@Message VARCHAR(750) = NULL,
	@MailReplyTo VARCHAR(MAX) = NULL,
	@MailSubject VARCHAR(MAX) = NULL,
	@MailContent VARCHAR(MAX) = NULL,
	@Accounts VARCHAR(MAX),
	@IsSequential BIT,
	@SequentialCampaign NVARCHAR(MAX),
	@ResponseList VARCHAR(MAX),
	@Time INT ,
	@TrackResponse VARCHAR(3),
	@ResponseShortURL VARCHAR(MAX),
	@UnsubscribePage VARCHAR(3),
	@UnsubscribeMicrositeURL VARCHAR(MAX),
	@Tags VARCHAR(MAX),
	@ModifiedBy BIGINT,
	@ScheduleTime DATETIME = NULL,
	@IsUnicode BIT ,
	@Expiry VARCHAR(50)
AS
BEGIN
	UPDATE CampaignMaster
	SET    Applicabilty = @Applicabilty,
	       ExclusionsNumber = @ExclusionsNumber,
	       InclusionsNumber = @InclusionsNumber,
	       Exclusions = @Exclusions,
	       SenderID = @SenderID,
	       [Message] = @Message,
	       MailReplyTo = @MailReplyTo,
	       MailSubject = @MailSubject,
	       MailContent = @MailContent,
	       Accounts = @Accounts,
	       IsSequential = @IsSequential,
	       SequentialCampaign = @SequentialCampaign,
	       ResponseList = @ResponseList,
	       [Time] = @Time,
	       TrackResponse = @TrackResponse,
	       UnsubscribePage = @UnsubscribePage,
	       Tags = @Tags,
	       ScheduleTime = @ScheduleTime,
	       ModifiedOn = GETDATE(),
	       ModifiedBy = @ModifiedBy,
	       IsUnicode = @IsUnicode,
	       ExpiryDate = @Expiry
	WHERE  ID = @ID              
	
	SELECT 'Success'
END 


