/* ============================================================
   Procedure: [dbo].[usp_UpdateCommissionSlabs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_UpdateCommissionSlabs]    
@ID int,      
@slabname nvarchar(30),      
@ServiceReferred nvarchar(50),      
@CommissionAmount numeric(18,2),      
@CommissionPercent numeric(18,2),      
@IsAmount bit,      
@userGroup int =null,      
@Description nvarchar(200),      
@ValidFrom date,      
@ValidTill date,    
@Status bit,  
@MinOrderAmount numeric(18,2)      
as          
begin      
declare @duplicatecommission int=(select id from Referrer_Payout_Rates r where @ServiceReferred=ServiceReferred and (@userGroup is null or @UserGroup=usergroup ) and status=1 and (@ValidFrom between cast(ValidFrom as DATE) and CAST(ValidTill as DATE) or  
  
    
@Validtill between cast(ValidFrom as DATE) and CAST(ValidTill as DATE) or cast(ValidFrom as date) between @ValidFrom and @validtill or cast(validtill as date) between @ValidFrom and @ValidTill) and ID<>@ID)      
if @duplicatecommission is not null      
begin      
Select 'Your values coincide with Slab ' + (select slabname from Referrer_Payout_Rates where ID=@duplicatecommission) + ' . Kindly change the service,usergroup or validity or deactive the last slab first'      
end      
else      
begin      
update Referrer_Payout_Rates set slabname = @slabname,ServiceReferred = @ServiceReferred,CommissionAmount = @CommissionAmount,    
CommissionPercent =@CommissionPercent,IsAmount = @IsAmount,[userGroup]= @userGroup,[Description] = @Description,ValidFrom = @ValidFrom,    
ValidTill = @ValidTill,status = @Status,MinimumOrderAmount = @MinOrderAmount where ID=@ID      
Select 'Slab updated successfully'      
end      
end





GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateConflictedEnquryToLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
          
          
          
          
--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 4:49:19 PM------/                
CREATE   PROCEDURE [dbo].[Usp_UpdateConflictedEnquryToLead]                
 @EnquiryID BIGINT,                
 @LeadID BIGINT,                
               
 @CountryCode nvarchar(50),              
 @CountryCode1 nvarchar(50),              
 @CountryCode2 nvarchar(50),              
               
 @MobileNo NVARCHAR(100),                
 @MobileNo1 NVARCHAR(100),                
 @MobileNo2 NVARCHAR(100),                
 @EmailID NVARCHAR(100),                
 @EmailID1 NVARCHAR(100),                
 @EmailID2 NVARCHAR(100),                
 @PersonName VARCHAR(200),                
 @CompanyName VARCHAR(200),                
 @City VARCHAR(200),                
 @State VARCHAR(200),                
 @Country VARCHAR(200),                
 @PinCode VARCHAR(200),                
 @ResidentialAddress VARCHAR(500),                
 @OfficeAddress VARCHAR(500),                
 @ModifiedBy BIGINT,                
 @ParentID BIGINT                
AS                
BEGIN                
 UPDATE UserLeads                
 SET    PersonName = @PersonName,                
        CompanyName = @CompanyName,                
        City = @City,                
        Country = @Country,                
        [State] = @State,                
        ResidentialAddress = @ResidentialAddress,                
        OfficeAddress = @OfficeAddress,                
        PinCode = @PinCode,                
                      
        CountryCode = @CountryCode,              
        CountryCode1 = @CountryCode1,              
        CountryCode2 = @CountryCode2,              
                              
        MobileNo = @MobileNo,                
        MobileNo1 = @MobileNo1,                
        MobileNo2 = @MobileNo2,                
                      
        EmailID = @EmailID,                
        EmailID1 = @EmailID1,                
        EmailID2 = @EmailID2,                
        ModifiedBy = @ModifiedBy,                
        ModifiedOn = GETDATE()                
 WHERE  ID = @LeadID                
                 
 declare @leadno int=(select leadno from userleads(nolock) where id=@leadid)                
                 
 DECLARE @FollowUpID BIGINT = (                
             SELECT TOP 1               ID                
             FROM   FollowUp_Status  AS fus                
             WHERE  fus.FollowupStatus = 'Merge lead'                
         )                
                 
                 
                 
 INSERT INTO LeadInteractionHistory                
   (                
     -- ID -- this column value is auto-generated                
                     
     LeadNo,                
     FollowUpStatus,                
     ParentID,                
     CreatedOn,                
     CreatedBy                
   )                
 VALUES                
   (                
     @leadno,                
     @FollowUpID,                
     @ParentID,                
     GETDATE(),                
     @ModifiedBy                
   )                
                 
 --DELETE                
 --FROM   UserEnquiry                
 --WHERE  EnquiryID = @EnquiryID                
 UPDATE UserEnquiry                
 SET    IsOpen = 0,LeadNo=@leadno                
 WHERE  EnquiryID = @EnquiryID                
          
 declare @mergid bigint             
  insert into  tbl_MergeLeadsEnquiry( EnquiryNo ,LeadNo,IsOpen)     
  values (@EnquiryID,@leadno,0)        
    select @mergid=SCOPE_IDENTITY()      
           
   /* Start lead activity Merge Lead (Enquiry)*/        
        
Begin try        
        
 Declare @UserID_LDACTV bigint = @ModifiedBy        
 Declare @ParentID_LDACTV bigint = @ParentID        
         
  Declare @LeadID_LDACTV bigint = @LeadID        
  Declare @EnquiryID_LDACTV bigint = @EnquiryID        
          
        
  create table #tblEventDescrb        
   (        
 EVNT_Description nvarchar(max)         
   )        
        
  if( isnull(@LeadID_LDACTV,0) > 0)        
   Begin        
            
   insert into #tblEventDescrb        
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead merged',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null        
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null        
   ,null,null,null,null,null,null,@EnquiryID_LDACTV,null,        
   0,0,0,null,null,null,0,null,null,null,0,null,null        
             
   declare @evntMessage nvarchar(max) = ''         
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb        
         
   if(@evntMessage <> '')        
   Begin        
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Lead merged from enquiry' ,'tbl_MergeLeadsEnquiry',@mergid       
   end        
        
        
   End          
        
   End try        
        
   Begin catch        
      exec usp_insertErrorInfo        
   End catch        
        
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence          
   Begin          
        DROP TABLE #tblEventDescrb          
   End          
        
        
   /* End lead activity Merge Lead (Enquiry)*/        
        
            
              
   SELECT 'Merged Successfully'     
   
    DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserLeads WITH(NOLOCK)      
   WHERE ID = @LeadID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
 IF @rowJson IS NOT NULL      
 BEGIN      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy      
  ,@Activity_type = 'Updt_ConflctdEnqToLead'      
  ,@ActionType = 'U'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserLeads'      
 END 
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateConflictedEnquryToLeadToLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------Modified By Abhishek Makkar ----------- Time: 8/19/2017 8:59:15 PM------/          
CREATE   PROCEDURE dbo.Usp_UpdateConflictedEnquryToLeadToLead @LeadID1 BIGINT  
 ,@LeadID2 BIGINT  
 ,@MobileNo NVARCHAR(100)  
 ,@MobileNo1 NVARCHAR(100)  
 ,@MobileNo2 NVARCHAR(100)  
 ,@EmailID NVARCHAR(100)  
 ,@EmailID1 NVARCHAR(100)  
 ,@EmailID2 NVARCHAR(100)  
 ,@PersonName NVARCHAR(200)  
 ,@CompanyName NVARCHAR(500)  
 ,@City VARCHAR(200)  
 ,@State VARCHAR(200)  
 ,@Country VARCHAR(200)  
 ,@PinCode VARCHAR(200)  
 ,@ResidentialAddress VARCHAR(500)  
 ,@OfficeAddress VARCHAR(500)  
 ,@ModifiedBy BIGINT  
 ,@ParentID BIGINT  
 ,@keepLead BIGINT  
 ,@CountryCode NVARCHAR(100)  
 ,@CountryCode1 NVARCHAR(100)  
 ,@CountryCode2 NVARCHAR(100)  
AS  
BEGIN  
 DECLARE @mergid BIGINT  
  
 BEGIN TRY  
  -- declare @CountryCode NVARCHAR(100)='+91',@MobileNo NVARCHAR(100)='9313943055', @CountryCode1 NVARCHAR(100)='', @MobileNo1 NVARCHAR(100)='', @CountryCode2 NVARCHAR(100)='', @MobileNo2 NVARCHAR(100)='', @EmailID NVARCHAR(100)='', @EmailID1 NVARCHAR(100
--)=  
  --'', @EmailID2 NVARCHAR(100)='', @ParentID BIGINT=32222, @LeadID1 BIGINT=0, @LeadID2 BIGINT=0      
  IF EXISTS (  
    SELECT *  
    FROM (  
     SELECT (isnull(CountryCode, '') + isnull(MobileNo, '')) AS MobileNo  
      ,isnull(EmailID, '') AS EmailID  
     FROM UserLeads(NOLOCK)  
     WHERE ParentID = @ParentID  
      AND ID NOT IN (  
       @LeadID1  
       ,@LeadID2  
       )  
       
     UNION  
       
     SELECT (isnull(CountryCode1, '') + isnull(MobileNo1, '')) AS MobileNo  
      ,isnull(EmailID1, '') AS EmailID  
     FROM UserLeads(NOLOCK)  
     WHERE ParentID = @ParentID  
      AND ID NOT IN (  
       @LeadID1  
       ,@LeadID2  
       )  
       
     UNION  
       
     SELECT (isnull(CountryCode2, '') + isnull(MobileNo2, '')) AS MobileNo  
      ,isnull(EmailID2, '') AS EmailID  
     FROM UserLeads(NOLOCK)  
     WHERE ParentID = @ParentID  
      AND ID NOT IN (  
       @LeadID1  
       ,@LeadID2  
       )  
     ) A  
    WHERE (  
      A.MobileNo != ''  
      AND A.MobileNo IN (  
       @CountryCode + @MobileNo  
       ,@CountryCode1 + @MobileNo1  
       ,@CountryCode2 + @MobileNo2  
       )  
      )  
     OR (  
      A.EmailID != ''  
      AND A.EmailID IN (  
       @EmailID  
       ,@EmailID1  
       ,@EmailID2  
       )  
      )  
    )  
  BEGIN  
   SELECT 'MobileNo or EmailID already Exists'  
  END  
  ELSE  
  BEGIN  
   UPDATE UserLeads  
   SET PersonName = @PersonName  
    ,CompanyName = @CompanyName  
    ,City = @City  
    ,Country = @Country  
    ,[State] = @State  
    ,ResidentialAddress = @ResidentialAddress  
    ,OfficeAddress = @OfficeAddress  
    ,PinCode = @PinCode  
    ,MobileNo = @MobileNo  
    ,MobileNo1 = @MobileNo1  
    ,MobileNo2 = @MobileNo2  
    ,EmailID = @EmailID  
    ,EmailID1 = @EmailID1  
    ,EmailID2 = @EmailID2  
    ,ModifiedBy = @ModifiedBy  
    ,ModifiedOn = GETDATE()  
    ,CountryCode = @CountryCode  
    ,CountryCode1 = @CountryCode1  
    ,CountryCode2 = @CountryCode2  
   WHERE ID = CASE   
     WHEN @keepLead = 1  
      THEN @LeadID1  
     ELSE @LeadID2  
     END  
  
   DECLARE @FollowUpID BIGINT = (  
     SELECT TOP 1 ID  
     FROM FollowUp_Status AS fus  
     WHERE fus.FollowupStatus = 'Merge lead'  
     )  
   DECLARE @LeadNo BIGINT = (  
     SELECT ul.LeadNo  
     FROM UserLeads AS ul  
     WHERE ul.ID = CASE   
       WHEN @keepLead = 1  
        THEN @LeadID1  
       ELSE @LeadID2  
       END  
     )  
  
   INSERT INTO LeadInteractionHistory (  
    -- ID -- this column value is auto-generated          
    LeadNo  
    ,FollowUpStatus  
    ,NextStatusDate  
    ,Remarks  
    ,Products  
    ,AmountPaid  
    ,AssignedTo  
    ,ParentID  
    ,CreatedOn  
    ,CreatedBy  
    ,FollowupDate  
    )  
   SELECT (  
     SELECT ul.LeadNo  
     FROM UserLeads AS ul  
     WHERE id = CASE   
       WHEN @keepLead = 1  
        THEN @LeadID1  
       ELSE @LeadID2  
       END  
     )  
    ,lih.FollowUpStatus  
    ,lih.NextStatusDate  
    ,lih.Remarks  
    ,lih.Products  
    ,lih.AmountPaid  
    ,lih.AssignedTo  
    ,lih.ParentID  
    ,lih.CreatedOn  
    ,lih.CreatedBy  
    ,lih.FollowupDate  
   FROM LeadInteractionHistory AS lih  
   WHERE lih.LeadNo IN (  
     SELECT ul.LeadNo  
     FROM UserLeads AS ul  
     WHERE id = CASE   
       WHEN @keepLead = 1  
        THEN @LeadID2  
       ELSE @LeadID1  
       END  
     )  
    AND lih.ParentID = @ParentID  
  
   INSERT INTO LeadInteractionHistory (  
    LeadNo  
    ,FollowUpStatus  
    ,ParentID  
    ,CreatedOn  
    ,CreatedBy  
    )  
   VALUES (  
    @LeadNo  
    ,@FollowUpID  
    ,@ParentID  
    ,GETDATE()  
    ,@ModifiedBy  
    )  
  
   IF (@keepLead = 2)  
   BEGIN  
    INSERT INTO tbl_MergeLeads (  
     LeadIDMergedFrom  
     ,LeadIDMergedIn  
     ,CreatedDate  
     ,createdby  
     )  
    VALUES (  
     @LeadID1  
     ,@LeadID2  
     ,GETDATE()  
     ,@ModifiedBy  
     )  
  
    SELECT @mergid = SCOPE_IDENTITY()  
  
    DELETE kd  
    FROM LeadInteractionHistory AS kd  
    INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo  
     AND ul.ParentID = @ParentID  
    WHERE ul.ID = @LeadID1  
     AND kd.ParentID = @ParentID  
  
    DELETE  
    FROM UserLeads  
    WHERE ID = @LeadID1  
   END  
   ELSE  
   BEGIN  
    INSERT INTO tbl_MergeLeads (  
     LeadIDMergedFrom  
     ,LeadIDMergedIn  
     ,CreatedDate  
     ,createdby  
     )  
    VALUES (  
     @LeadID2  
     ,@LeadID1  
     ,GETDATE()  
     ,@ModifiedBy  
     )  
  
    SELECT @mergid = SCOPE_IDENTITY()  
  
    DELETE kd  
    FROM LeadInteractionHistory AS kd  
    INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo  
     AND ul.ParentID = @ParentID  
    WHERE ul.ID = @LeadID2  
     AND kd.ParentID = @ParentID  
  
    DELETE  
    FROM UserLeads  
    WHERE ID = @LeadID2  
   END  
  
   DECLARE @event NVARCHAR(100)  
    ,@eventdesc NVARCHAR(1000)  
    ,@keepleadid BIGINT  
    ,@modifiedlogin NVARCHAR(100)  
  
   SELECT @modifiedlogin = user_login  
   FROM user_detail(NOLOCK)  
   WHERE user_id = @ModifiedBy  
  
   SELECT @keepleadid = CASE   
     WHEN @keepLead = 1  
      THEN @LeadID2  
     ELSE @LeadID1  
     END  
  
   SELECT @event = 'Lead merged'  
    ,@eventdesc = @PersonName + ' was merged from leadno ' + cast(@keepleadid AS NVARCHAR) + ' by ' + @modifiedlogin  
  
   BEGIN TRY  
    EXEC UspSaveLeadActivity_withid @keepleadid  
     ,@ModifiedBy  
     ,@parentid  
     ,@eventdesc  
     ,@event  
     ,'tbl_MergeLeads'  
     ,@mergid  
   END TRY  
  
   BEGIN CATCH  
    EXEC usp_InsertErrorInfo  
   END CATCH  
  
   SELECT 'Merged Successfully'  
  
   DECLARE @rowJson VARCHAR(MAX) = (  
     SELECT *  
     FROM UserLeads WITH (NOLOCK)  
     WHERE ID = CASE   
       WHEN @keepLead = 1  
        THEN @LeadID1  
       ELSE @LeadID2  
       END  
     FOR JSON AUTO  
      ,INCLUDE_NULL_VALUES  
     )  
  
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy  
    ,@Activity_type = 'Updt_ld_mrgd'  
    ,@ActionType = 'U'  
    ,@RowJson = @rowJson  
    ,@Table_name = 'UserLeads'  
  END  
 END TRY  
  
 BEGIN CATCH  
  EXEC usp_InsertErrorInfo  
 END CATCH  
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateConflictedEnquryToLeadToLead_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
--------Modified By Abhishek Makkar ----------- Time: 8/19/2017 8:59:15 PM------/  
CREATE   PROCEDURE [dbo].[Usp_UpdateConflictedEnquryToLeadToLead_INTDateTime]  
 @LeadID1 BIGINT,  
 @LeadID2 BIGINT,  
 @MobileNo NVARCHAR(100),  
 @MobileNo1 NVARCHAR(100),  
 @MobileNo2 NVARCHAR(100),  
 @EmailID NVARCHAR(100),  
 @EmailID1 NVARCHAR(100),  
 @EmailID2 NVARCHAR(100),  
 @PersonName VARCHAR(200),  
 @CompanyName VARCHAR(200),  
 @City VARCHAR(200),  
 @State VARCHAR(200),  
 @Country VARCHAR(200),  
 @PinCode VARCHAR(200),  
 @ResidentialAddress VARCHAR(500),  
 @OfficeAddress VARCHAR(500),  
 @ModifiedBy BIGINT,  
 @ParentID BIGINT,  
 @keepLead BIGINT,  
 @CountryCode NVARCHAR(100),  
 @CountryCode1 NVARCHAR(100),  
 @CountryCode2 NVARCHAR(100)  
AS  
BEGIN  
 UPDATE UserLeads  
 SET    PersonName = @PersonName,  
        CompanyName = @CompanyName,  
        City = @City,  
        Country = @Country,  
        [State] = @State,  
        ResidentialAddress = @ResidentialAddress,  
        OfficeAddress = @OfficeAddress,  
        PinCode = @PinCode,  
        MobileNo = @MobileNo,  
        MobileNo1 = @MobileNo1,  
        MobileNo2 = @MobileNo2,  
        EmailID = @EmailID,  
        EmailID1 = @EmailID1,  
        EmailID2 = @EmailID2,  
        ModifiedBy = @ModifiedBy,  
        ModifiedOn = GETDATE(),  
        CountryCode = @CountryCode,  
        CountryCode1 = @CountryCode1,  
        CountryCode2 = @CountryCode2  
 WHERE  ID = CASE   
                  WHEN @keepLead = 1 THEN @LeadID1  
                  ELSE @LeadID2  
             END   
   
 DECLARE @FollowUpID     BIGINT = (  
             SELECT TOP 1               ID  
             FROM   FollowUp_Status  AS fus  
             WHERE  fus.FollowupStatus = 'Merge lead'  
         )  
   
    
   
   
 DECLARE @LeadNo         BIGINT = (  
             SELECT ul.LeadNo  
             FROM   UserLeads AS ul  
             WHERE  ul.ID = CASE   
                                 WHEN @keepLead = 1 THEN @LeadID1  
                                 ELSE @LeadID2  
                            END  
         )  
   
   
     
   
 INSERT INTO LeadInteractionHistory  
   (  
     -- ID -- this column value is auto-generated  
       
     LeadNo,  
     FollowUpStatus,  
     NextStatusDate,  
     Remarks,  
     Products,  
     AmountPaid,  
     AssignedTo,  
     ParentID,  
     CreatedOn,  
     CreatedBy,
     FollowupDate  
   )  
SELECT (  
           SELECT ul.LeadNo  
           FROM   UserLeads AS ul  
           WHERE  id = CASE   
                            WHEN @keepLead = 1 THEN @LeadID1  
                            ELSE @LeadID2  
                       END  
       ),  
       lih.FollowUpStatus,  
       lih.NextStatusDate,  
       lih.Remarks,  
       lih.Products,  
       lih.AmountPaid,  
       lih.AssignedTo,  
       lih.ParentID,  
       lih.CreatedOn,  
       lih.CreatedBy,
       lih.FollowupDate  
FROM   LeadInteractionHistory AS lih  
WHERE  lih.LeadNo IN (SELECT ul.LeadNo  
                      FROM   UserLeads AS ul  
                      WHERE  id = CASE   
                                       WHEN @keepLead = 1 THEN @LeadID2  
                                       ELSE @LeadID1  
                                  END)  
       AND lih.ParentID = @ParentID  
   
   
   
   
 INSERT INTO LeadInteractionHistory  
   (  
     LeadNo,  
     FollowUpStatus,  
     ParentID,  
     CreatedOn,  
     CreatedBy  
   )  
 VALUES  
   (  
     @LeadNo,  
     @FollowUpID,  
     @ParentID,  
     GETDATE(),  
     @ModifiedBy  
   )   
   
   
   
 IF (@keepLead = 2)  
 BEGIN  
     DELETE kd  
     FROM   LeadInteractionHistory AS kd  
            INNER JOIN UserLeads AS ul  
                 ON  ul.LeadNo = kd.LeadNo  
                 AND ul.ParentID = @ParentID  
     WHERE  ul.ID = @LeadID1  
            AND kd.ParentID = @ParentID  
       
       
       
     DELETE   
     FROM   UserLeads  
     WHERE  ID = @LeadID1  
 END  
 ELSE  
 BEGIN  
     DELETE kd  
     FROM   LeadInteractionHistory AS kd  
            INNER JOIN UserLeads AS ul  
                 ON  ul.LeadNo = kd.LeadNo  
                 AND ul.ParentID = @ParentID  
     WHERE  ul.ID = @LeadID2  
            AND kd.ParentID = @ParentID  
       
        
       
     DELETE   
     FROM   UserLeads  
     WHERE  ID = @LeadID2  
 END  
   
 SELECT 'Merged Successfully'  
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateConflictedEnquryToLeadToLeadNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_UpdateConflictedEnquryToLeadToLeadNew]
	 @LeadID1 BIGINT
	,@LeadID2 BIGINT
	,@MobileNo NVARCHAR(100)
	,@MobileNo1 NVARCHAR(100)
	,@MobileNo2 NVARCHAR(100)
	,@EmailID NVARCHAR(100)
	,@EmailID1 NVARCHAR(100)
	,@EmailID2 NVARCHAR(100)
	,@PersonName VARCHAR(200)
	,@CompanyName VARCHAR(200)
	,@City VARCHAR(200)
	,@State VARCHAR(200)
	,@Country VARCHAR(200)
	,@PinCode VARCHAR(200)
	,@ResidentialAddress VARCHAR(500)
	,@OfficeAddress VARCHAR(500)
	,@ModifiedBy BIGINT
	,@ParentID BIGINT
	,@keepLead BIGINT
	,@CountryCode NVARCHAR(100)
	,@CountryCode1 NVARCHAR(100)
	,@CountryCode2 NVARCHAR(100)
	,@SourceName BIGINT = 0
	,@MediumName BIGINT = 0
	,@CampaignName BIGINT = 0
AS
BEGIN
	DECLARE @mergid BIGINT

	BEGIN TRY
		-- declare @CountryCode NVARCHAR(100)='+91',@MobileNo NVARCHAR(100)='9313943055', @CountryCode1 NVARCHAR(100)='', @MobileNo1 NVARCHAR(100)='', @CountryCode2 NVARCHAR(100)='', @MobileNo2 NVARCHAR(100)='', @EmailID NVARCHAR(100)='', @EmailID1 NVARCHAR(100)=
		--'', @EmailID2 NVARCHAR(100)='', @ParentID BIGINT=32222, @LeadID1 BIGINT=0, @LeadID2 BIGINT=0    
		IF EXISTS (
				SELECT *
				FROM (
					SELECT (isnull(CountryCode, '') + isnull(MobileNo, '')) AS MobileNo
						,isnull(EmailID, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					
					UNION
					
					SELECT (isnull(CountryCode1, '') + isnull(MobileNo1, '')) AS MobileNo
						,isnull(EmailID1, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					
					UNION
					
					SELECT (isnull(CountryCode2, '') + isnull(MobileNo2, '')) AS MobileNo
						,isnull(EmailID2, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					) A
				WHERE (
						A.MobileNo != ''
						AND A.MobileNo IN (
							@CountryCode + @MobileNo
							,@CountryCode1 + @MobileNo1
							,@CountryCode2 + @MobileNo2
							)
						)
					OR (
						A.EmailID != ''
						AND A.EmailID IN (
							@EmailID
							,@EmailID1
							,@EmailID2
							)
						)
				)
		BEGIN
			SELECT 'MobileNo or EmailID already Exists'
		END
		ELSE
		BEGIN
			UPDATE UserLeads
			SET PersonName = @PersonName
				,CompanyName = @CompanyName
				,City = @City
				,Country = @Country
				,[State] = @State
				,ResidentialAddress = @ResidentialAddress
				,OfficeAddress = @OfficeAddress
				,PinCode = @PinCode
				,MobileNo = @MobileNo
				,MobileNo1 = @MobileNo1
				,MobileNo2 = @MobileNo2
				,EmailID = @EmailID
				,EmailID1 = @EmailID1
				,EmailID2 = @EmailID2
				,ModifiedBy = @ModifiedBy
				,ModifiedOn = GETDATE()
				,CountryCode = @CountryCode
				,CountryCode1 = @CountryCode1
				,CountryCode2 = @CountryCode2
				,SourceName = @SourceName
				,MediumName = @MediumName
				,CampaignName = @CampaignName
			WHERE ID = CASE 
					WHEN @keepLead = 1
						THEN @LeadID1
					ELSE @LeadID2
					END

			DECLARE @FollowUpID BIGINT = (
					SELECT TOP 1 ID
					FROM FollowUp_Status AS fus
					WHERE fus.FollowupStatus = 'Merge lead'
					)
			DECLARE @LeadNo BIGINT = (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE ul.ID = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					)

			INSERT INTO LeadInteractionHistory (
				-- ID -- this column value is auto-generated        
				LeadNo
				,FollowUpStatus
				,NextStatusDate
				,Remarks
				,Products
				,AmountPaid
				,AssignedTo
				,ParentID
				,CreatedOn
				,CreatedBy
				,FollowupDate
				)
			SELECT (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE id = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					)
				,lih.FollowUpStatus
				,lih.NextStatusDate
				,lih.Remarks
				,lih.Products
				,lih.AmountPaid
				,lih.AssignedTo
				,lih.ParentID
				,lih.CreatedOn
				,lih.CreatedBy
				,lih.FollowupDate
			FROM LeadInteractionHistory AS lih
			WHERE lih.LeadNo IN (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE id = CASE 
							WHEN @keepLead = 1
								THEN @LeadID2
							ELSE @LeadID1
							END
					)
				AND lih.ParentID = @ParentID

			INSERT INTO LeadInteractionHistory (
				LeadNo
				,FollowUpStatus
				,ParentID
				,CreatedOn
				,CreatedBy
				)
			VALUES (
				@LeadNo
				,@FollowUpID
				,@ParentID
				,GETDATE()
				,@ModifiedBy
				)

			IF (@keepLead = 2)
			BEGIN
				INSERT INTO tbl_MergeLeads (
					LeadIDMergedFrom
					,LeadIDMergedIn
					,CreatedDate
					,createdby
					)
				VALUES (
					@LeadID1
					,@LeadID2
					,GETDATE()
					,@ModifiedBy
					)

				SELECT @mergid = SCOPE_IDENTITY()

				DELETE kd
				FROM LeadInteractionHistory AS kd
				INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo
					AND ul.ParentID = @ParentID
				WHERE ul.ID = @LeadID1
					AND kd.ParentID = @ParentID

				DELETE
				FROM UserLeads
				WHERE ID = @LeadID1
			END
			ELSE
			BEGIN
				INSERT INTO tbl_MergeLeads (
					LeadIDMergedFrom
					,LeadIDMergedIn
					,CreatedDate
					,createdby
					)
				VALUES (
					@LeadID2
					,@LeadID1
					,GETDATE()
					,@ModifiedBy
					)

				SELECT @mergid = SCOPE_IDENTITY()

				DELETE kd
				FROM LeadInteractionHistory AS kd
				INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo
					AND ul.ParentID = @ParentID
				WHERE ul.ID = @LeadID2
					AND kd.ParentID = @ParentID

				DELETE
				FROM UserLeads
				WHERE ID = @LeadID2
			END

			DECLARE @event NVARCHAR(100)
				,@eventdesc NVARCHAR(1000)
				,@keepleadid BIGINT
				,@modifiedlogin NVARCHAR(100)

			SELECT @modifiedlogin = user_login
			FROM user_detail(NOLOCK)
			WHERE user_id = @ModifiedBy

			SELECT @keepleadid = CASE 
					WHEN @keepLead = 1
						THEN @LeadID2
					ELSE @LeadID1
					END

			SELECT @event = 'Lead merged'
				,@eventdesc = @PersonName + ' was merged from leadno ' + cast(@keepleadid AS NVARCHAR) + ' by ' + @modifiedlogin

			BEGIN TRY
				EXEC UspSaveLeadActivity_withid @keepleadid
					,@ModifiedBy
					,@parentid
					,@eventdesc
					,@event
					,'tbl_MergeLeads'
					,@mergid
			END TRY

			BEGIN CATCH
				EXEC usp_InsertErrorInfo
			END CATCH

			SELECT 'Merged Successfully'

			DECLARE @rowJson VARCHAR(MAX) = (
					SELECT *
					FROM UserLeads WITH (NOLOCK)
					WHERE ID = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)

			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy
				,@Activity_type = 'Updt_ld_mrgd'
				,@ActionType = 'U'
				,@RowJson = @rowJson
				,@Table_name = 'UserLeads'
		END
	END TRY

	BEGIN CATCH
		EXEC usp_InsertErrorInfo
	END CATCH
END



GO

