CREATE   PROCEDURE [dbo].[Usp_UpdateConflictedEnquryToLeadToLeadNewWithLocation]
	 @LeadID1 BIGINT
	,@LeadID2 BIGINT
	,@MobileNo NVARCHAR(100)
	,@MobileNo1 NVARCHAR(100)
	,@MobileNo2 NVARCHAR(100)
	,@EmailID NVARCHAR(100)
	,@EmailID1 NVARCHAR(100)
	,@EmailID2 NVARCHAR(100)
	,@PersonName VARCHAR(200)
	,@CompanyName VARCHAR(200)
	,@City VARCHAR(200)
	,@State VARCHAR(200)
	,@Country VARCHAR(200)
	,@PinCode VARCHAR(200)
	,@ResidentialAddress VARCHAR(500)
	,@OfficeAddress VARCHAR(500)
	,@ModifiedBy BIGINT
	,@ParentID BIGINT
	,@keepLead BIGINT
	,@CountryCode NVARCHAR(100)
	,@CountryCode1 NVARCHAR(100)
	,@CountryCode2 NVARCHAR(100)
	,@SourceName BIGINT = 0
	,@MediumName BIGINT = 0
	,@CampaignName BIGINT = 0
	,@WhereLatitude NVARCHAR(100) = ''
    ,@WhereLongitude NVARCHAR(100) = ''        
AS
BEGIN
	DECLARE @mergid BIGINT

	BEGIN TRY
		-- declare @CountryCode NVARCHAR(100)='+91',@MobileNo NVARCHAR(100)='9313943055', @CountryCode1 NVARCHAR(100)='', @MobileNo1 NVARCHAR(100)='', @CountryCode2 NVARCHAR(100)='', @MobileNo2 NVARCHAR(100)='', @EmailID NVARCHAR(100)='', @EmailID1 NVARCHAR(100)=
		--'', @EmailID2 NVARCHAR(100)='', @ParentID BIGINT=32222, @LeadID1 BIGINT=0, @LeadID2 BIGINT=0    

		declare @latitude float = null;      
		if(ISNULL(@WhereLatitude, '') <> '')      
		begin      
		 set @latitude = cast(@WhereLatitude as float)      
		end      
		declare @longitude float = null;      
		if(ISNULL(@WhereLatitude, '') <> '')      
		begin      
		 set @longitude = cast(@WhereLongitude as float)       
		end      

		IF EXISTS (
				SELECT *
				FROM (
					SELECT (isnull(CountryCode, '') + isnull(MobileNo, '')) AS MobileNo
						,isnull(EmailID, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					
					UNION
					
					SELECT (isnull(CountryCode1, '') + isnull(MobileNo1, '')) AS MobileNo
						,isnull(EmailID1, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					
					UNION
					
					SELECT (isnull(CountryCode2, '') + isnull(MobileNo2, '')) AS MobileNo
						,isnull(EmailID2, '') AS EmailID
					FROM UserLeads(NOLOCK)
					WHERE ParentID = @ParentID
						AND ID NOT IN (
							@LeadID1
							,@LeadID2
							)
					) A
				WHERE (
						A.MobileNo != ''
						AND A.MobileNo IN (
							@CountryCode + @MobileNo
							,@CountryCode1 + @MobileNo1
							,@CountryCode2 + @MobileNo2
							)
						)
					OR (
						A.EmailID != ''
						AND A.EmailID IN (
							@EmailID
							,@EmailID1
							,@EmailID2
							)
						)
				)
		BEGIN
			SELECT 'MobileNo or EmailID already Exists'
		END
		ELSE
		BEGIN
			UPDATE UserLeads
			SET PersonName = @PersonName
				,CompanyName = @CompanyName
				,City = @City
				,Country = @Country
				,[State] = @State
				,ResidentialAddress = @ResidentialAddress
				,OfficeAddress = @OfficeAddress
				,PinCode = @PinCode
				,MobileNo = @MobileNo
				,MobileNo1 = @MobileNo1
				,MobileNo2 = @MobileNo2
				,EmailID = @EmailID
				,EmailID1 = @EmailID1
				,EmailID2 = @EmailID2
				,ModifiedBy = @ModifiedBy
				,ModifiedOn = GETDATE()
				,CountryCode = @CountryCode
				,CountryCode1 = @CountryCode1
				,CountryCode2 = @CountryCode2
				,SourceName = @SourceName
				,MediumName = @MediumName
				,CampaignName = @CampaignName
				,latitude = @WhereLatitude
				,longitude = @WhereLongitude
			WHERE ID = CASE 
					WHEN @keepLead = 1
						THEN @LeadID1
					ELSE @LeadID2
					END

			DECLARE @FollowUpID BIGINT = (
					SELECT TOP 1 ID
					FROM FollowUp_Status AS fus
					WHERE fus.FollowupStatus = 'Merge lead'
					)
			DECLARE @LeadNo BIGINT = (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE ul.ID = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					)

			INSERT INTO LeadInteractionHistory (
				-- ID -- this column value is auto-generated        
				LeadNo
				,FollowUpStatus
				,NextStatusDate
				,Remarks
				,Products
				,AmountPaid
				,AssignedTo
				,ParentID
				,CreatedOn
				,CreatedBy
				,FollowupDate
				)
			SELECT (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE id = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					)
				,lih.FollowUpStatus
				,lih.NextStatusDate
				,lih.Remarks
				,lih.Products
				,lih.AmountPaid
				,lih.AssignedTo
				,lih.ParentID
				,lih.CreatedOn
				,lih.CreatedBy
				,lih.FollowupDate
			FROM LeadInteractionHistory AS lih
			WHERE lih.LeadNo IN (
					SELECT ul.LeadNo
					FROM UserLeads AS ul
					WHERE id = CASE 
							WHEN @keepLead = 1
								THEN @LeadID2
							ELSE @LeadID1
							END
					)
				AND lih.ParentID = @ParentID

			INSERT INTO LeadInteractionHistory (
				LeadNo
				,FollowUpStatus
				,ParentID
				,CreatedOn
				,CreatedBy
				)
			VALUES (
				@LeadNo
				,@FollowUpID
				,@ParentID
				,GETDATE()
				,@ModifiedBy
				)

			IF (@keepLead = 2)
			BEGIN
				INSERT INTO tbl_MergeLeads (
					LeadIDMergedFrom
					,LeadIDMergedIn
					,CreatedDate
					,createdby
					)
				VALUES (
					@LeadID1
					,@LeadID2
					,GETDATE()
					,@ModifiedBy
					)

				SELECT @mergid = SCOPE_IDENTITY()

				DELETE kd
				FROM LeadInteractionHistory AS kd
				INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo
					AND ul.ParentID = @ParentID
				WHERE ul.ID = @LeadID1
					AND kd.ParentID = @ParentID

				DELETE
				FROM UserLeads
				WHERE ID = @LeadID1
			END
			ELSE
			BEGIN
				INSERT INTO tbl_MergeLeads (
					LeadIDMergedFrom
					,LeadIDMergedIn
					,CreatedDate
					,createdby
					)
				VALUES (
					@LeadID2
					,@LeadID1
					,GETDATE()
					,@ModifiedBy
					)

				SELECT @mergid = SCOPE_IDENTITY()

				DELETE kd
				FROM LeadInteractionHistory AS kd
				INNER JOIN UserLeads AS ul ON ul.LeadNo = kd.LeadNo
					AND ul.ParentID = @ParentID
				WHERE ul.ID = @LeadID2
					AND kd.ParentID = @ParentID

				DELETE
				FROM UserLeads
				WHERE ID = @LeadID2
			END

			DECLARE @event NVARCHAR(100)
				,@eventdesc NVARCHAR(1000)
				,@keepleadid BIGINT
				,@modifiedlogin NVARCHAR(100)

			SELECT @modifiedlogin = user_login
			FROM user_detail(NOLOCK)
			WHERE user_id = @ModifiedBy

			SELECT @keepleadid = CASE 
					WHEN @keepLead = 1
						THEN @LeadID2
					ELSE @LeadID1
					END

			SELECT @event = 'Lead merged'
				,@eventdesc = @PersonName + ' was merged from leadno ' + cast(@keepleadid AS NVARCHAR) + ' by ' + @modifiedlogin

			BEGIN TRY
				EXEC UspSaveLeadActivity_withid @keepleadid
					,@ModifiedBy
					,@parentid
					,@eventdesc
					,@event
					,'tbl_MergeLeads'
					,@mergid
			END TRY

			BEGIN CATCH
				EXEC usp_InsertErrorInfo
			END CATCH

			SELECT 'Merged Successfully'

			DECLARE @rowJson VARCHAR(MAX) = (
					SELECT *
					FROM UserLeads WITH (NOLOCK)
					WHERE ID = CASE 
							WHEN @keepLead = 1
								THEN @LeadID1
							ELSE @LeadID2
							END
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)

			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy
				,@Activity_type = 'Updt_ld_mrgd'
				,@ActionType = 'U'
				,@RowJson = @rowJson
				,@Table_name = 'UserLeads'
		END
	END TRY

	BEGIN CATCH
		EXEC usp_InsertErrorInfo
	END CATCH
END



GO

