CREATE   PROC [dbo].[usp_updateContactDetailnew]     
/*    
 CREATED BY: MANOJ SINGH    
 DATED:20 JAN 2010    
 PURPOSE: WHILE BULK IMPORT CHECK IF MOBILE IS ALREADY EXISTS ,IF EXISTS THEN     
 DECIDE WHETHER TO UPDATE RECORDS OR NOT     
*/    
@M_ID bigint,        
@User_ID int,-- frm bigint 17-08-2010        
@contact_mobile varchar(150),        
@contact_name varchar(150),        
@contact_email varchar(50),        
@contact_BG varchar(50),        
@contact_dob varchar(50),        
@contact_anniversary varchar(50) ,    
@flag char(1),  
@Group_id bigint    
as        
if  exists(SELECT contact_id FROM contact_detail where contact_mobile=@contact_mobile AND user_id=@user_id and Group_id=@Group_id)         
begin      
    
 IF (@flag='y')    
   BEGIN    
 Update contact_detail SET        
 contact_mobile=@contact_mobile,contact_name=@contact_name,contact_email=@contact_email,contact_BG=@contact_BG,contact_dob=@contact_dob,contact_anniversary=@contact_anniversary        
 WHERE  contact_mobile=@contact_mobile and user_id=@user_ID        
   END    
select 'true'      
end       
else     
begin      
select 'false'      
end    
  
  




