CREATE   PROC [dbo].[Usp_UpdateContactForApp] --'19650','106164747','ghazipur','8527805414','12/03/1980','10/03/2013','Update'                             
@User_ID int,                            
@Contact_Name varchar(50),                            
@Contact_Mobile varchar(15),                            
@Contact_DOB varchar(15),                            
@Contact_Anniversary varchar(20),               
@Action varchar(20) ,      
@oldmobile varchar(15),
@CountryCode varchar(10)                               
as                               
begin                             
if (@Action='Update')                            
begin                      
declare @Contact_Mobi varchar(15)                  
SELECT @Contact_Mobi=Contact_Mobile FROM  [dbo].[Contact_Detail] WHERE User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and CountryCode=@CountryCode                 
if(@Contact_Mobi=@Contact_Mobile)                  
begin              
   delete from Contact_Detail WHERE User_ID=@User_ID and Contact_Mobile=@Contact_Mobi and group_id is null          
   insert into Contact_Detail (User_ID ,Contact_Name ,Contact_Mobile,Contact_DOB,Contact_Anniversary,M_ID,CountryCode) values                
   (@User_ID,@Contact_Name,@Contact_Mobile,@Contact_DOB,@Contact_Anniversary,10043,@CountryCode)          
   declare @groupid bigint           
  select @groupid=group_id from Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and group_id is not null                 
  if (@groupid is not null)          
       begin          
        DELETE FROM Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and group_id=@groupid          
        insert into Contact_Detail (User_ID ,Contact_Name ,Contact_Mobile,Contact_DOB,Contact_Anniversary,M_ID,group_id,CountryCode) values                
   (@User_ID,@Contact_Name,@Contact_Mobile,@Contact_DOB,@Contact_Anniversary,10043,@groupid,@CountryCode)          
       end             
    --UPDATE Contact_Detail SET Contact_Name=@Contact_Name,Contact_Mobile=@Contact_Mobile,Contact_DOB=@Contact_DOB,Contact_Anniversary=@Contact_Anniversary WHERE Contact_Mobile=@Contact_Mobile  and User_ID=@User_ID and Contact_id=@Contact_id              
  
   
 select 'Record  Updated Successfully' as Msg                   
end                   
else                  
begin                  
IF NOT EXISTS(SELECT 'X' FROM  [dbo].[Contact_Detail] WHERE Contact_Mobile=@Contact_Mobile)                        
begin             
    delete from Contact_Detail WHERE User_ID=@User_ID and Contact_Mobile=@oldmobile and group_id is null             
   insert into Contact_Detail (User_ID ,Contact_Name ,Contact_Mobile,Contact_DOB,Contact_Anniversary,M_ID,CountryCode) values                
   (@User_ID,@Contact_Name,@Contact_Mobile,@Contact_DOB,@Contact_Anniversary,10043,@CountryCode)        
    declare @groupidd bigint           
  select @groupidd=group_id from Contact_Detail where User_ID=@User_ID and Contact_Mobile=@oldmobile and group_id is not null             
   if(@groupidd is not null)          
       begin          
        DELETE FROM Contact_Detail where User_ID=@User_ID and Contact_Mobile=@oldmobile and group_id=@groupidd          
        insert into Contact_Detail (User_ID ,Contact_Name ,Contact_Mobile,Contact_DOB,Contact_Anniversary,M_ID,group_id,CountryCode) values                
   (@User_ID,@Contact_Name,@Contact_Mobile,@Contact_DOB,@Contact_Anniversary,10043,@groupidd,@CountryCode)          
       end                           
--UPDATE Contact_Detail SET Contact_Name=@Contact_Name,Contact_Mobile=@Contact_Mobile,Contact_DOB=@Contact_DOB,Contact_Anniversary=@Contact_Anniversary WHERE Contact_id=@Contact_id and User_ID=@User_ID                           
 select 'Record  Updated Successfully' as Msg                     
 end                           
 ELSE                        
 BEGIN                        
 SELECT 'MobileNo Already Exists' as Error                        
 END                     
 end                  
 end                  
 end                   
                   
                   
 --SELECT 'X' FROM Contact_Detail WHERE Contact_Mobile='8527805414' and Contact_ID='106164747'              
               
