   Procedure: [dbo].[usp_UpdateConversionstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_UpdateConversionstatus]    
@referredcontactid int,
@signupstatus bit=null,
@conversionstatus bit=null,
@ConversionAmount numeric(18,2)=null,
@SignUpdate datetime=null,
@Conversiondate  datetime=null,
@PayoutEligible bit=null,
@commissionid int =null
as    
begin
update ReferredContacts set SignUpStatus=isnull(@SignUpStatus,SignUpStatus),ConversionStatus=isnull(@ConversionStatus,ConversionStatus),LastModified=GETDATE(),ConversionAmount=isnull(@ConversionAmount,ConversionAmount),SignUpdate=isnull(@SignUpdate,SignUpdate),Conversiondate=isnull(@Conversiondate,Conversiondate),PayoutEligible=isnull(@PayoutEligible,PayoutEligible) where ID=@referredcontactid
if @PayoutEligible=1 and (select conversionamount from ReferredContacts where ID=@referredcontactid)>0 and @commissionid is not null
begin
exec usp_InsertPayoutTracked @referredcontactid,@commissionid,@conversionamount
end  
declare @referid int=(select referrerid from ReferredContacts where ID=@referredcontactid) 
declare @activityname nvarchar(50) 
= (select case when @PayoutEligible=1 then 'PayoutApproved' when @PayoutEligible=0 then 'PayoutRejected' when (@ConversionAmount IS not null and @ConversionAmount >0) then 'PayoutTracked' when @SignUpdate IS not null then 'ReferredContactSignedUp' end)
exec usp_updateuseractivity @referid,@activityname,0
end







