/* ============================================================
   Procedure: [dbo].[usp_updateCurrentmaildeliveryreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updateCurrentmaildeliveryreport]           
as          
begin          
declare @MailDeliveryReportId bigint=isnull((select max(MailDeliveryReportId) from MailupdatedTill where updatetable='Current'),0)          
declare @CurrentMailDeliveryReportId bigint=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport](nolock)) ,@c bigint ,@minid bigint,@maxid bigint       
if @MailDeliveryReportId<>@CurrentMailDeliveryReportId        
begin         
select @c= count(1) from [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) where mdr.ID>@MailDeliveryReportId 
and mdr.id=(select max(id) from [PelConnectDB].[dbo].[MailDeliveryReport] MD (nolock) where APIHEADER=mdr.APIHEADER)
create table #temp(ID bigint,Datecreated datetime,event nvarchar(max),Response nvarchar(max) ,APIHEADER nvarchar(200))  
while @c>0
begin
insert into #temp(ID,Datecreated,event,Response,APIHEADER)
select top 1000 ID,Datecreated,event,Response,APIHEADER from [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) where mdr.ID>@MailDeliveryReportId 
and mdr.id=(select max(id) from [PelConnectDB].[dbo].[MailDeliveryReport] MD (nolock) where APIHEADER=mdr.APIHEADER)
set @c=@c-1000
end
select @minid=min(ID),@maxid=max(id) from #temp
while @minid>@maxid
begin
begin try          
begin transaction          
update m set SentFinalDatetime=case when SentFinalDatetime is null then mdr.DateCreated else SentFinalDatetime end,status=          
        mdr.event + ' ' + mdr.RESPONSE from 
		 ClientEmails m  join #temp MDR on MDR.APIHEADER=cast(m.GUID as nvarchar(50))          
        and MDR.ID=(select MAX(id) from #temp mm (nolock) where mm.APIHEADER=mdr.APIHEADER) and mdr.id<@minid+1000
delete from #temp where id<@minid+1000
select @minid=isnull(min(ID),@maxid) from #temp
COMMIT TRANSACTION            
END TRY            
BEGIN CATCH            
ROLLBACK TRANSACTION            
SELECT ERROR_NUMBER()     AS ErrorNumber,            
         ERROR_SEVERITY()   AS ErrorSeverity,            
         ERROR_STATE()      AS ErrorState,            
         ERROR_PROCEDURE()  AS ErrorProcedure,            
         ERROR_LINE()       AS ErrorLine,            
         ERROR_MESSAGE()    AS ErrorMessage;          
 END CATCH     
 end 
insert into mailupdatedtill(dateupdated,MailDeliveryReportId,Updatetable)          
select GETDATE(),@CurrentMailDeliveryReportId,'Current'          
drop table #temp          
end       
end 


GO

