SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updateDailyConsumption]          
as          
begin       
select * into #batchinfo     
from batchinfo b(nolock) where     
(cast(BatchInsertTime as date)= cast(dateadd(d,-1,GETDATE()) as date) and ScheduledDate='') or cast(isnull(nullif(b.ScheduledDate,''),getdate()) as date)=  cast(dateadd(d,-1,GETDATE()) as date)       
    
insert into DailyConsumption([TotalConsumption]          
      ,[Date]          
      ,[User_id]          
      ,[UserLogin])          
SELECT SUM(c.debits), cast(dateadd(d,-1,GETDATE()) as date), c.user_id,u.user_login FROM credit_details (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID     
join #batchinfo b (nolock) on c.batchid=b.batchid    
where         
FromUser_ID=c.USER_ID     
--and ((cast(c.DateCreated as date)=cast(dateadd(d,-1,GETDATE()) as date) and b.ScheduledDate='') or cast(isnull(nullif(b.ScheduledDate,''),getdate()) as date)=  cast(dateadd(d,-1,GETDATE()) as date))     
and not exists (select 1 from credit_details cd where Credits>0 and cd.batchid=c.batchid)    
group by c.user_id,u.user_login order by  SUM(c.debits) desc     
    
drop table #batchinfo        
          
insert into DailyMailConsumption([TotalMailConsumption]          
      ,[Date]          
      ,[User_id]          
      ,[UserLogin])          
SELECT SUM(c.debits), cast(dateadd(d,-1,GETDATE()) as date), c.user_id,u.user_login FROM mailcreditdetails (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID where         
FromUser_ID=c.USER_ID and cast(c.datecreated as date)=  cast(dateadd(d,-1,GETDATE()) as date) group by c.user_id,u.user_login order by  SUM(c.debits) desc      

begin try
begin tran
insert into DailyMoneyConsumption([TotalMoneyConsumption]          
      ,[Date]          
      ,[User_id]          
      ,[UserLogin])          
SELECT SUM(c.debits), cast(dateadd(d,-1,GETDATE()) as date), c.user_id,u.user_login FROM intcredit_details (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID   
where         
FromUser_ID=c.USER_ID     
and ((cast(c.DateCreated as date)=cast(dateadd(d,-1,GETDATE()) as date))) 
group by c.user_id,u.user_login order by  SUM(c.debits) desc     

delete from DailyMoneyConsumption where date<cast(dateadd(m,-1,getdate()) as date)   
commit
end try 
BEGIN CATCH
IF @@TRANCOUNT>0                                        
ROLLBACK                                        
EXECUTE USP_INSERTERRORINFO;
END CATCH

delete from dailyconsumption where date<cast(dateadd(m,-1,getdate()) as date)        
delete from dailymailconsumption where date<cast(dateadd(m,-1,getdate()) as date)        
        
end          
        




GO

/* ============================================================
   Procedure: [dbo].[usp_updateDailyConsumption1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updateDailyConsumption1]            
as            
begin
declare @date date= (select top 1 date from dailyconsumption order by id desc)
declare @days int=(select DATEDIFF(d,cast(getdate() as DATE),@date))        
select @days
select cast(dateadd(d,@days+1,GETDATE()) as date)
select sum(Credits) Credits,USER_ID,batchid into #credit_details from credit_details cd (nolock) where cd.Credits>0 and cd.batchid is not null group by USER_ID,batchid     
create table #batchinfo(batchid bigint,batchinserttime datetime)
while @days<-1
begin      
insert into #batchinfo (batchid,batchinserttime) 
select b.batchid,b.batchinserttime     
from batchinfo b(nolock) where       
(cast(BatchInsertTime as date)= cast(dateadd(d,@days+1,GETDATE()) as date) and ScheduledDate='') or cast(isnull(nullif(b.ScheduledDate,''),getdate()) as date)=  cast(dateadd(d,@days+1,GETDATE()) as date) 
insert into DailyConsumption([TotalConsumption]            
      ,[Date]            
      ,[User_id]            
      ,[UserLogin])            
SELECT SUM(c.debits)-case when cd.user_id is not null then sum(cd.credits) else 0 end, cast(dateadd(d,@days+1,GETDATE()) as date), c.user_id,u.user_login FROM credit_details (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID
join #batchinfo b (nolock) on c.batchid=b.batchid      
left join #credit_details cd (nolock) on cd.batchid=c.batchid and cd.User_ID=c.User_ID               
where 
c.FromUser_ID=c.USER_ID and cast(c.datecreated as date)=  cast(dateadd(d,@days+1,GETDATE()) as date)      
--and ((cast(c.DateCreated as date)=cast(dateadd(d,-1,GETDATE()) as date) and b.ScheduledDate='') or cast(isnull(nullif(b.ScheduledDate,''),getdate()) as date)=  cast(dateadd(d,-1,GETDATE()) as date))       
group by c.user_id,u.user_login,cd.user_id order by  SUM(c.debits) desc       
          
            
insert into DailyMailConsumption([TotalMailConsumption]            
      ,[Date]            
      ,[User_id]            
      ,[UserLogin])            
SELECT SUM(c.debits), cast(dateadd(d,@days+1,GETDATE()) as date), c.user_id,u.user_login FROM mailcreditdetails (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID 
where           
FromUser_ID=c.USER_ID and cast(c.datecreated as date)=  cast(dateadd(d,@days+1,GETDATE()) as date) group by c.user_id,u.user_login order by  SUM(c.debits) desc

insert into DailyMoneyConsumption([TotalMoneyConsumption]            
      ,[Date]            
      ,[User_id]            
      ,[UserLogin])            
SELECT SUM(c.debits), cast(dateadd(d,@days+1,GETDATE()) as date), c.user_id,u.user_login FROM intcredit_details (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID     
where           
FromUser_ID=c.USER_ID       
and cast(c.DateCreated as date)=cast(dateadd(d,@days+1,GETDATE()) as date)  
group by c.user_id,u.user_login order by  SUM(c.debits) desc

set @days=@days+1
truncate table #batchinfo
select cast(dateadd(d,@days+1,GETDATE()) as date),GETDATE()
end     

drop table #batchinfo 
drop table #credit_details

delete from DailyMoneyConsumption where date<cast(dateadd(m,-1,getdate()) as date)     
delete from dailyconsumption where date<cast(dateadd(m,-1,getdate()) as date)          
delete from dailymailconsumption where date<cast(dateadd(m,-1,getdate()) as date)          
          
end            
          
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateDealPipeline]
   ============================================================ */

