SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateDealPipeline  
(  
 @LeadID bigint,  
 @PipelineID bigint,  
 @StageID bigint,  
 @Amount numeric(18,2),  
 @ClosureDate datetime,  
 @DealOwner bigint,    
 @DealID bigint  
)  
as   
Begin  
        
  
  if(not exists(select 'x' from LeadPipelineMapping where LeadID = @LeadID and id <> @DealID))
  Begin
   update LeadPipelineMapping  
   set LeadID = @LeadID ,PipelineID = @PipelineID, PipeLineStage = @StageID  
       ,Amount = @Amount , EstimatedClosureDate = @ClosureDate ,DealOwner = @DealOwner  
      
    where ID =  @DealID  
  
  select 'Deal Updated'  
  
  end
  else
   Begin
       select 'LeadID Already Occupied'  
   End
   

End  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateDealPipeline_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateDealPipeline_New]                
(  
 @LeadID bigint,      
 @PipelineID bigint,      
 @StageID bigint,      
 @Amount numeric(18,2),      
 @ClosureDate datetime,      
 @DealOwner bigint,      
 @DealID bigint,      
 @Probability numeric(18,2),      
 @LostID bigint = null,      
 @CreatedBy bigint,
 @LostRemark nvarchar(200) = NULL      
)                
as                 
Begin                
    declare @pname nvarchar(100),@sname nvarchar(100)                                        
                
  if(not exists(select 'x' from LeadPipelineMapping where PipelineID = @PipelineID and PipeLineStage = @StageID and LeadID = @LeadID and id <> @DealID and IsDeleted = 0 ))              
  Begin             
               
   --update LeadPipelineMapping                
   --set LeadID = @LeadID ,PipelineID = @PipelineID, PipeLineStage = @StageID                
   --    ,Amount = @Amount , EstimatedClosureDate = @ClosureDate ,DealOwner = @DealOwner                
                    
   -- where ID =  @DealID                
           
   declare @lpmid bigint             
   declare @CurrentDateTime datetime  = getdate()    
  insert into LeadPipelineMapping              
      (              
       [LeadID]              
      ,[PipelineID]              
      ,[PipeLineStage]      
      ,[Probability]              
      ,[Amount]              
      ,[Remarks]              
      ,[CreatedDate]              
      ,[CreatedBy]              
      ,[EstimatedClosureDate]              
      ,[DealOwner]              
      ,[IsDeleted]
        ,[LostRemark] 
   )              
   values            
     (               
       @LeadID              
      ,@PipelineID              
      ,@StageID              
      ,@Probability              
      ,@Amount              
      ,'Deal created'              
      ,@CurrentDateTime              
      ,@CreatedBy              
      ,@ClosureDate              
      ,@DealOwner              
      ,0              
        ,@LostRemark           
   )            
   select @lpmid=SCOPE_IDENTITY()        
      --from   LeadPipelineMapping where ID = @DealID              
   if (@LostID > 0)      
   begin      
      update LeadPipelineMapping set LostID = @LostID  where ID = @lpmid      
   end      
      
      update LeadPipelineMapping set IsDeleted = 1 ,deletedon = getdate() where ID = @DealID                 
               
   begin try          
          
      Declare @LeadIDTemp bigint = 0          
   Declare @ParentID bigint = 0          
             
   select @ParentID = isnull(ParentID,0) from User_Detail where User_ID = @CreatedBy          
   select @LeadIDTemp=isnull(LeadID,0) from LeadPipelineMapping where ID = @DealID          
          
select @pname=name from Pipeline_Master(nolock) where id=@PipelineID    
 select @sname=Name from PipelineStages (nolock) where id=@StageID    
  
   declare @eventDesc nvarchar(500) =  [dbo].[fn_getentityfullname]('lead',@leadid) +'''s deal moved to pipeline:' + cast(@Pname as nvarchar)+', Stage :'+@sname    
   exec UspSaveLeadActivity_withid @LeadIDTemp,@Createdby,@ParentID,@eventDesc,'Deal Updated','LeadPipelineMapping',@lpmid           
          
   end try          
   begin catch          
       exec usp_InsertErrorInfo          
   end catch          
          
          
            
            
  select 'Deal Updated' [status], @lpmid RefId, 'LeadPipelineMapping' TblRefName, @CurrentDateTime CurrentDateTime    
                
  end              
  else              
   Begin              
       select 'LeadID Already Occupied' [status]               
   End              
                 
              
End  





GO

