/* ============================================================
   Procedure: [dbo].[Usp_UpdateDLTTemplate_New_ParentIDCheck]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateDLTTemplate_New_ParentIDCheck (
	@DLT_TemplateID NVARCHAR(200)
	,@MessageType NVARCHAR(500)
	,@TemplateText NVARCHAR(max)
	,@IsUnicode BIT
	,@ActiveStatus INT
	,@SenderIDs NVARCHAR(max)
	,@UserID BIGINT
	,@TemplateName NVARCHAR(100)
	,@Is_Stock BIT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = isnull(ParentID, User_ID)
	FROM User_Detail(NOLOCK)
	WHERE USER_ID = @UserID

	IF (
			NOT EXISTS (
				SELECT 1
				FROM UserMailTemplate(NOLOCK)
				WHERE Name = @TemplateName
					AND ParentID = @ParentID
					AND DLT_TemplateID <> @DLT_TemplateID
				)
			)
	BEGIN
		UPDATE UserMailTemplate
		SET MessageType = @MessageType
			,MailSubject = SUBSTRING(@TemplateText, 1, 30)
			,MailContent = @TemplateText
			,IsUnicode = @IsUnicode
			,ActiveStatus = @ActiveStatus
			,Name = @TemplateName
			,is_stock = @Is_Stock
		WHERE DLT_TemplateID = @DLT_TemplateID
			AND ParentID = @ParentID

		DELETE
		FROM DLT_TemplateSenderMapping
		WHERE DLT_TemplateID = @DLT_TemplateID
			AND CreatedBy = @UserID
			AND SenderID NOT IN (
				SELECT CAST(isnull(value, 0) AS BIGINT)
				FROM dbo.fn_Split(@SenderIDs, '#')
				)

		INSERT INTO DLT_TemplateSenderMapping (
			DLT_TemplateID
			,SenderID
			,CreatedOn
			,CreatedBy
			)
		SELECT @DLT_TemplateID
			,CAST(isnull(splt.value, 0) AS BIGINT)
			,getdate()
			,@UserID
		FROM dbo.fn_Split(@SenderIDs, '#') splt
		WHERE (
				CAST(isnull(splt.value, 0) AS BIGINT) NOT IN (
					SELECT SenderID
					FROM DLT_TemplateSenderMapping
					WHERE DLT_TemplateID = @DLT_TemplateID
						AND CreatedBy = @UserID
					)
				)

		SELECT 'Template Updated'
	END
	ELSE
	BEGIN
		SELECT 'Template Name Already Exists'
	END

	--  update DLT_Template set MessageType = @MessageType ,TemplateText = @TemplateText        
	--  ,IsUnicode = @IsUnicode ,ActiveStatus = @ActiveStatus         
	--  where DLT_TemplateID = @DLT_TemplateID        
	--  delete from DLT_TemplateSenderMapping        
	--   where        
	--DLT_TemplateID = @DLT_TemplateID        
	--and         
	--SenderID         
	--not in (        
	--       select CAST(isnull(value,0) as bigint)          
	--          from dbo.fn_Split(@SenderIDs,'#')        
	--       )        
	--   insert into DLT_TemplateSenderMapping        
	-- (        
	--   DLT_TemplateID        
	--     ,SenderID        
	--     ,CreatedOn        
	--     ,CreatedBy        
	-- )        
	-- select @DLT_TemplateID,CAST(isnull(splt.value,0) as bigint),getdate(),@UserID        
	-- from dbo.fn_Split(@SenderIDs,'#') splt        
	-- where (        
	--        CAST(isnull(splt.value,0) as bigint)        
	--         not in (select SenderID from DLT_TemplateSenderMapping where DLT_TemplateID = @DLT_TemplateID )        
	--       )        
	--     select 'Template Updated'   
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailTemplate(NOLOCK)
			WHERE DLT_TemplateID = @DLT_TemplateID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Updt_DLT_Tmplt'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailTemplate'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_UpdateDomainVerification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdateDomainVerification] --32222,'kitqa.sms19.com',32222,'CRM'  
    @userid BIGINT,  
    @domain NVARCHAR(200) = NULL,   
    @createdby BIGINT,  
    @domaintype NVARCHAR(50) = NULL  
AS  
BEGIN  
    -- Declare variables  
    DECLARE @rowCount INT;    
    DECLARE @domainExists BIT;  
  
    -- Start of TRY block  
    BEGIN TRY  
        -- Check if the row exists  
        IF EXISTS (  
            SELECT 1  
            FROM tbl_pt_DomainVerification  
            WHERE userid = @userid --AND domain = dbo.fn_removewww(@domain) AND domaintype = @domaintype  
        )  
        BEGIN  
            -- Perform the update  
            UPDATE tbl_pt_DomainVerification  
            SET   
                isverified = 1,   
                LastverificationAttempted = GETDATE(),   
                verifiedon = GETDATE()  
            WHERE   
                userid = @userid AND domain = @domain AND domaintype = @domaintype;  
  
            -- Update reseller_detail if domaintype is CRM  
			declare @CleanDomain nvarchar(max);
            IF @domaintype = 'CRM'  
            BEGIN  
			SET @CleanDomain = dbo.fn_removewww(@domain)
			SET @CleanDomain = 'www.' + @CleanDomain;
                UPDATE reseller_detail  
                SET   
                    domain = @CleanDomain   
                WHERE   
                    user_id = @userid;  
            END  
  
            SELECT 1 AS RowsAffected;  
        END  
        ELSE  
        BEGIN  
            -- No matching row found  
            SELECT 0 AS RowsAffected;  
        END  
  
    END TRY  
  
    -- Handle any errors  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END; 


GO

