/* ============================================================
   Procedure: [dbo].[usp_UpdateEnquiryField]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_UpdateEnquiryField] (
	@FieldId BIGINT = 0
	,@FieldName NVARCHAR(500) = ''
	,@FieldValue NVARCHAR(max)
	,@TableName NVARCHAR(500)
	,@UserId BIGINT = 0
	,@FilterExp NVARCHAR(MAX)
	)
AS
BEGIN
	--declare 
	--	@FieldId    BIGINT        = 1488, 
	--	@FieldName  NVARCHAR(500) = 'MyService', 
	--	@FieldValue NVARCHAR(500) = 'IMS', 
	--	@TableName  NVARCHAR(500) = 'customfieldLeadvalu', 
	--	@UserId     BIGINT        = 34594, 
	--	@FilterExp  NVARCHAR(MAX) = N'LeadId = 1080481'	
	DECLARE @upid BIGINT;

	INSERT INTO fieldupdated (
		Tablename
		,FieldName
		,Oldvalue
		,NewValue
		,CreatedBy
		,fieldid
		)
	SELECT @TableName
		,@FieldName
		,''
		,@FieldValue
		,@UserId
		,@fieldid;

	SELECT @upid = SCOPE_IDENTITY();

	IF NOT (
			@FieldId = 0
			AND @FieldName = ''
			)
	BEGIN
		DECLARE @SQL NVARCHAR(MAX);
		DECLARE @ParentId BIGINT;

		/*Getting ParentID By User_ID*/
		SELECT @ParentId = ParentID
		FROM User_Detail
		WHERE User_ID = @UserId;

		BEGIN TRY
			DECLARE @TableName_LDACTV NVARCHAR(200) = @TableName;

				IF (@TableName_LDACTV = 'UserEnquiry' OR @TableName_LDACTV = 'customfieldEnquiryvalue')
			BEGIN
				DECLARE @UserID_LDACTV BIGINT = @UserId
					,@ParentID_LDACTV BIGINT = @ParentId
					,@FieldName_LDACTV NVARCHAR(200) = @FieldName
					,@FieldValue_LDACTV NVARCHAR(500) = @FieldValue
					,@FilterExp_LDACTV NVARCHAR(MAX) = @FilterExp
					,@OldValue_LDACTV NVARCHAR(500) = ''
					,@NewValue_LDACTV NVARCHAR(500) = @FieldValue
					,@Query_LDACTV NVARCHAR(MAX) = ''
					,@ID NVARCHAR(50) = '0'
					,@customfieldName NVARCHAR(max)

				--SET @Query_LDACTV = ' select top 1  ' + @FieldName_LDACTV + ', ID  from UserLeads(nolock) where ParentID = ' + CAST(@ParentID_LDACTV as nvarchar) + ' and ' + (REPLACE(@FilterExp_LDACTV, 'LeadId', 'ID'));
				SELECT @ParentId = ParentID
				FROM User_Detail
				WHERE User_ID = @UserId;

				SET @customfieldName = (
						SELECT STRING_AGG(CONCAT (
									'['
									,fieldname
									,']'
									), ',')
						FROM (
							SELECT DISTINCT fieldname
							FROM customfields(NOLOCK)
							WHERE ParentID = @ParentId
							) f
						)
				SET @Query_LDACTV = CONCAT (
						' select cast('
						,@fieldName
						,' as nvarchar), EnquiryID from ( SELECT ul.* '
						,iif(isnull(@customfieldName, '') <> '', ', c.*', '')
						,'  FROM UserEnquiry(NOLOCK) ul '
						,iif(isnull(@customfieldName, '') <> '', CONCAT (
								N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.EnquiryID CFEnquiryid, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) '
								,N' cf INNER JOIN customfieldEnquiryvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID  WHERE cf.ParentID = '
								,cast(@ParentId AS NVARCHAR)
								,' ) ipc PIVOT(MAX(fieldvalue) '
								,N' FOR fieldname IN( '
								,@customfieldName
								,N' )) p ) c ON ul.EnquiryID = c.CFEnquiryid '
								,''
								), '') + N' 
								left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID 
								left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID 
								left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID 
								WHERE ul.ParentID = '
						,cast(@ParentId AS NVARCHAR)
						,' and '
						,replace(@FilterExp, 'LeadId', 'ul.ID ')
						,' ) myTab '
						)

				PRINT @Query_LDACTV
				
				DROP TABLE

				IF EXISTS #temptbl
					DROP TABLE

				IF EXISTS #tblEventDescrb
					CREATE TABLE #temptbl (
						OldValue NVARCHAR(max)
						,ID BIGINT
						);

				INSERT INTO #temptbl
				EXECUTE sp_executesql @Query_LDACTV;
				
				--select * from #temptbl

				--SELECT @OldValue_LDACTV = OldValue
				--	,@ID = ID
				--FROM #temptbl;
			SELECT @OldValue_LDACTV = Case @FieldName 
										when 'MediumName' 
										Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=OldValue  ) 
										when 'SourceName' 
										Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=OldValue  ) 
										when 'CampaignName' 
										Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=OldValue  ) 
										Else OldValue
										END 
			 ,@ID = ID FROM #temptbl;  

  SELECT @NewValue_LDACTV = Case @FieldName 
			when 'MediumName' 
			Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=@NewValue_LDACTV  ) 
			when 'SourceName' 
			Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=@NewValue_LDACTV  ) 
			when 'CampaignName' 
			Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=@NewValue_LDACTV  ) 
			Else @NewValue_LDACTV
			END 
				--select  @OldValue_LDACTV,@ID    
				CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(MAX));

				IF (ISNULL(@ID, 0) > 0)
				BEGIN
					INSERT INTO #tblEventDescrb
					EXEC Usp_EventTemplate_DynamicVarReplacement 'Enquiry details edited'
						,@UserID_LDACTV
						,''
						,''
						,@ID
						,''
						,NULL
						,0
						,0
						,''
						,''
						,0
						,''
						,0
						,NULL
						,@FieldName_LDACTV
						,@OldValue_LDACTV
						,@NewValue_LDACTV
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,0
						,0
						,0
						,NULL
						,NULL
						,NULL
						,0
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL
						,NULL;

					DECLARE @evntMessage NVARCHAR(max) = '';

					SELECT @evntMessage = (
							SELECT isnull(EVNT_Description, '')
							FROM #tblEventDescrb
							);
					--SELECT @evntMessage
					IF (@evntMessage <> '')
					BEGIN
						EXEC UspSaveEnquiryActivity_withid @ID
							,@UserID_LDACTV
							,@ParentID_LDACTV
							,@evntMessage
							,'Enquiry details edited'
							,'fieldupdated'
							,@upid;
					END
				END;
			END
	


			/* Start Lead activity User details edited */
			SET @SQL = CASE @TableName
					/* Generating query for updateing UserEnquiry table*/
					WHEN 'UserEnquiry'
						THEN 'update ' + @TableName + ' set ' + @FieldName + ' = ''' + @FieldValue + ''' where ParentID = ' + CAST(@ParentId AS NVARCHAR) + ' AND ' + @FilterExp
							/* Generating query for updateing UserLeads table*/
					WHEN 'UserLeads'
						THEN 'update ' + @TableName + ' set ModifiedOn = GETDATE() ,' + @FieldName + ' = ''' + @FieldValue + ''' where ParentID = ' + CAST(@ParentId AS NVARCHAR) + ' AND ' + REPLACE(@FilterExp, 'LeadId', 'ID')
							/* Generating query for updateing Custom Field Enquiry Value table*/
					WHEN 'customfieldEnquiryvalue'
						THEN 'if(not exists(select * from customfieldEnquiryvalue where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ')) begin INSERT INTO customfieldEnquiryvalue ( EnquiryID, fieldID, fieldvalue) VALUES ( CAST(LTRIM(RTRIM(SUBSTRING(''' + @FilterExp + ''', (CHARINDEX(''='', ''' + @FilterExp + ''') + 1), LEN(''' + @FilterExp + ''')))) AS BIGINT), ' + CAST(@FieldId AS NVARCHAR) + ', ''' + @FieldValue + ''') end else begin update customfieldEnquiryvalue set fieldvalue = ''' + @FieldValue + ''' where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' end '
							/* Generating query for updateing Custom Field Lead Value table*/
					WHEN 'customfieldLeadvalue'
						THEN 'if(not exists(select * from ' + @TableName + ' where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ')) begin INSERT INTO ' + @TableName + ' ( LeadId, fieldID, fieldvalue) VALUES ( CAST(LTRIM(RTRIM(SUBSTRING(''' + @FilterExp + ''', (CHARINDEX(''='', ''' + @FilterExp + ''') + 1), LEN(''' + @FilterExp + ''')))) AS BIGINT), ' + CAST(@FieldId AS NVARCHAR) + ', ''' + @FieldValue + ''') end else begin update ' + @TableName + ' set fieldvalue = ''' + @FieldValue + ''' where fieldID
					 = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' end '
					END;

			IF (@FilterExp <> '')
			BEGIN
				PRINT @SQL;

				EXECUTE sp_executesql @SQL;
			END

			SELECT @upid;
		END TRY

		BEGIN CATCH
			EXEC usp_insertErrorInfo;
		END CATCH
	END;

	DECLARE @rowJson NVARCHAR(MAX)
		,@rowout NVARCHAR(max)

	SET @rowJson = CASE @TableName
			WHEN 'UserEnquiry'
				THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'
			WHEN 'UserLeads'
				THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE ' + REPLACE(@FilterExp, 'LeadId', 'ID') + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'
			WHEN 'customfieldEnquiryvalue'
				THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'
			WHEN 'customfieldLeadvalue'
				THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'
			END;

	EXECUTE sp_executesql @rowJson
		,N'@rowout nvarchar(max) OUT'
		,@rowout OUT;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Updt_MassEnq'
		,@ActionType = 'U'
		,@RowJson = @rowout
		,@Table_name = @TableName
END



GO

/* ============================================================
   Procedure: [dbo].[usp_UpdateEnquiryLeadImgExt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC usp_UpdateEnquiryLeadImgExt
(
    @RowId bigint,
    @Type varchar(1), -- E(nquiry),L(ead)
    @Ext varchar(10)
)
AS
BEGIN

    If(@Type='E')
    Begin
	   Update UserEnquiry Set img_ext=@Ext Where EnquiryID=@RowId
	   Select @@ROWCOUNT
    End

    If(@Type='L')
    Begin
	   Update UserLeads Set img_ext=@Ext Where ID=@RowId
	   Select @@ROWCOUNT
    End

END



