/* ============================================================
   Procedure: [dbo].[usp_UpdateEnquiryStage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-------------------------------  
  
CREATE   PROCEDURE [dbo].[usp_UpdateEnquiryStage]    
    @ParentId BIGINT,    
    @StageId INT,    
    @IsActiveEnquiryAttributes BIT,    
    @IsActiveScore BIT,    
    @IsActiveChecklist BIT,    
    @UserId BIGINT    
AS    
BEGIN    
    -- Start TRY block    
    BEGIN TRY    
        -- Perform the update operation    
        UPDATE tbl_enquiry_stage    
        SET EnquiryAttributes = @IsActiveEnquiryAttributes,    
            BasedOnScore = @IsActiveScore,    
            CompletingChecklist = @IsActiveChecklist,    
            ModifiedBy = @UserId,    
            ModifiedDate = GETDATE()    
        WHERE StageId = @StageId AND ParentID = @ParentId;    
            
        -- Prepare the JSON data (example placeholder, adjust according to actual updated data)    
        DECLARE @rowJson NVARCHAR(MAX);    
        SET @rowJson = (SELECT * FROM tbl_enquiry_stage (nolock) WHERE StageId = @StageId AND ParentID = @ParentId FOR JSON AUTO);    
    
        -- Call the audit procedure after the update    
        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId     
            @User_id = @UserId,    
            @Activity_type = 'Enquiry Stage Update',    
            @ActionType = 'U',    
            @RowJson = @rowJson,    
            @Table_name = 'tbl_enquiry_stage';    
    END TRY    
    
    -- Start CATCH block    
    BEGIN CATCH    
        -- Handle errors by logging them using the error handling procedure    
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END;  


GO

