/* ============================================================
   Procedure: [dbo].[usp_updateExportervalidleads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updateExportervalidleads]      
@Exporterid bigint = null      
as      
begin   
/*if exists(select 1 from indiamartleads where QUERY_ID in (select query_id from indiamartleads where ID<@indiamartid )  
and id>=@indiamartid)  
begin  
delete From indiamartleads where QUERY_ID in (select query_id from indiamartleads where ID<@indiamartid )  
and id>=@indiamartid  
end  
*/  
declare @i bigint=(select max(ID) from tbl_exporterLeads(nolock) where isvalid=1)  
declare @c int=(select COUNT(1) from tbl_exporterLeads(nolock) where ID>=case when @Exporterid is null then @i else @Exporterid end)  
declare @ii bigint=(select MIN(id) from tbl_exporterLeads(nolock) where ID>=case when @Exporterid is null then @i else @Exporterid end)  
while @c>0  
begin  
update i set isvalid=1 from tbl_exporterLeads (nolock) i     
where  (   
          isnull(nullif(ltrim(rtrim(mobile)),'null'),'') <> ''
		  or isnull(nullif(ltrim(rtrim(email)),'null'),'') <>'' 
	   ) 
        and i.ID=@ii  
set @ii=@ii+1  
set @c=@c-1  
end  
end




