/* ============================================================
   Procedure: [dbo].[usp_updatefailedcallanswered]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatefailedcallanswered
as
begin
drop table if exists #id
select k.ID,k.FailedIVRQuery into #id from Kit19FailedIVRQuery(nolock) k 
--left join Kit19CallsDialled (nolock) d on
--k.p_uniqueid=d.puniqueid where k.p_uniqueid is not null and  d.id is not null and not exists
--(select 1 from Kit19CallsDialled(nolock) where puniqueid=k.p_uniqueid and call_answer_time is not null)
where IsProcess=0 and cast(FailedTime as date)=CAST(getdate() as date) and ID>847526
order by k.id 
declare @c int=(select COUNT(1) from #id),@sql nvarchar(max),@id bigint=0,@rows int
--print @c
while @c>0
begin
select @id=MIN(id) from #id where ID>@id
select @sql=FailedIVRQuery from #id where ID=@id
exec sp_executesql @sql
select @rows=@@ROWCOUNT
if @rows>0
begin
update Kit19FailedIVRQuery set IsProcess=1,ProcessedTime=GETDATE() where ID=@id
end
--print concat('Count left: ',@c,', @query: ',@sql)
set @c=@c-1
end
end



