CREATE   PROCEDURE usp_updatefailedcallend
as
begin
select v.id as ref, FailedIVRQuery into #tbe from Kit19FailedIVRQuery v (nolock) join kit19calls(nolock) k on k.uniqueid=v.uniqueid
 where v.IsProcess=0 and k.call_end_time is null  --and v.id=648
 --select * from #tbe
 declare @c int,@id int,@q nvarchar(max)
 select @c=count(1),@id=min(ref) from #tbe
 while @c>0
 begin
 select @q=failedivrquery from #tbe where ref=@id
 --select @q
 exec (@q)
 --select call_end_time,* from kit19calls where uniqueid='1606997066.3994270'
 update Kit19FailedIVRQuery set IsProcess=1,ProcessedTime=getdate() where id=@id
 --select * from Kit19FailedIVRQuery where id=@id
 delete from #tbe where ref=@id
 select @c=@c-1
 select @id=min(ref) from #tbe
  end
  drop table #tbe
end


