CREATE   PROC [dbo].[Usp_UpdateKiteverUserSearchParameter] 
(
    @SearchName NVARCHAR(250),
    @ID BIGINT,
    @LoginDateFrom VARCHAR(20) = NULL,
    @LoginDateTo VARCHAR(20) = NULL,
    @TimeSpentOnApp VARCHAR(20) = NULL,
    @TimeOperator VARCHAR(20) = NULL,
    @ConsumptionFrom VARCHAR(20) = NULL,
    @ConsumptionTo VARCHAR(20) = NULL,
    @SMSConsumptionFrom VARCHAR(20) = NULL,
    @SMSConsumptionTo VARCHAR(20) = NULL,
    @MailConsumptionFrom VARCHAR(20) = NULL,
    @MailConsumptionTo VARCHAR(20) = NULL,
    @BalanceUsed VARCHAR(50) = NULL,
    @Operator VARCHAR(10) = NULL,
    @SMSBalanceUsed VARCHAR(50) = NULL,
    @SMSOperator VARCHAR(10) = NULL,
    @MailBalanceUsed VARCHAR(50) = NULL,
    @MailOperator VARCHAR(10) = NULL,
    @OrderFrom VARCHAR(20) = NULL,
    @OrderTo VARCHAR(20) = NULL,
    @LeadsFrom VARCHAR(20) = NULL,
    @LeadsTo VARCHAR(20) = NULL,
    @TopUpFrom VARCHAR(20) = NULL,
    @TopUpTo VARCHAR(20) = NULL,
    @TopUpOperator VARCHAR(10) = NULL,
    @TopUpAmount VARCHAR(10) = NULL,
    @RegistrationDateFrom VARCHAR(20) = NULL,
    @RegistrationDateTo VARCHAR(20) = NULL,
    @IsActive BIT,
    @ModifiedBy BIGINT
)  
AS   
BEGIN
	UPDATE SearchDetails
	SET    SearchName = @SearchName,
	       IsActive = @IsActive,
	       LoginDateFrom = @LoginDateFrom,
	       LoginDateTo = @LoginDateTo,
	       TimeSpentOnApp = @TimeSpentOnApp,
	       TimeOperator = @TimeOperator,
	       ConsumptionFrom = @ConsumptionFrom,
	       ConsumptionTo = @ConsumptionTo,
	       SMSConsumptionFrom = @SMSConsumptionFrom,
	       SMSConsumptionTo = @SMSConsumptionTo,
	       MailConsumptionFrom = @MailConsumptionFrom,
	       MailConsumptionTo = @MailConsumptionTo,
	       BalanceUsed = @BalanceUsed,
	       Operator = @Operator,
	       SMSBalanceUsed = @SMSBalanceUsed,
	       SMSOperator = @SMSOperator,
	       MailBalanceUsed = @MailBalanceUsed,
	       MailOperator = @MailOperator,
	       OrderFrom = @OrderFrom,
	       OrderTo = @OrderTo,
	       LeadsFrom = @LeadsFrom,
	       LeadsTo = @LeadsTo,
	       TopUpFrom = @TopUpFrom,
	       TopUpTo = @TopUpTo,
	       TopUpOperator = @TopUpOperator,
	       TopUpAmount = @TopUpAmount,
	       RegistrationDateFrom = @RegistrationDateFrom,
	       RegistrationDateTO = @RegistrationDateTo,
	       ModifiedDate = GETDATE(),
	       ModifiedBy = @ModifiedBy
	WHERE  ID = @ID  
	
	SELECT 'Record Updated'
END  



