  CREATE   PROCEDURE usp_updatekycstatus 
  (@parentid bigint,@kycstatus int)
  as
  begin
  if exists(select 1 from telephonykyc(nolock) where parentid=@parentid)
  begin
  update telephonykyc set kycstatus=@kycstatus,lastupdatedon=getdate() where parentid=@parentid
