--sp_helptext Usp_UpdateLandingClientPageDetail        
CREATE   PROCEDURE dbo.Usp_UpdateLandingClientPageDetail @ID INT    
 ,@User_ID INT    
 ,    
 --@PageName varchar(200),                          
 @HtmlContent NTEXT = NULL    
 ,@ShortUrl VARCHAR(200) = NULL    
 ,@SiteVisits BIGINT = NULL    
 ,@SiteLeads BIGINT = NULL    
 ,@WebFromID BIGINT = NULL    
 ,@IsSms BIT    
 ,@SmsAccountName NVARCHAR(100)    
 ,@SmsSenderName NVARCHAR(100)    
 ,@SmsMessage NVARCHAR(200)    
 ,@SmsTemplateId BIGINT    
 ,@IsSmsTemplate BIT    
 ,@IsEmail BIT    
 ,@EmailAccountName NVARCHAR(100)    
 ,@EmailReplyTo NVARCHAR(100)    
 ,@EmailSubject NVARCHAR(100)    
 ,@EmailMessgae NVARCHAR(200)    
 ,@EmailTemplateId BIGINT    
 ,@IsTemplate BIT    
 ,@IsWebHook BIT    
 ,@WebHook NVARCHAR(100)    
 ,@Lead_Unsubscribe NVARCHAR(100)    
 ,@IsUniCode BIT    
 ,@recvmobile NVARCHAR(MAX) = ''    
 ,@recvemail NVARCHAR(MAX) = ''    
 ,@IsProfile BIT    
AS    
BEGIN    
 UPDATE ClientPageDetail    
 SET HtmlContent = @HtmlContent    
  ,ShortUrl = @ShortUrl    
  ,SiteVisits = @SiteVisits    
  ,SiteLeads = @SiteLeads    
  ,DateUpdated = GETDATE()    
  ,WebFromID = @WebFromID    
  ,IsSms = @IsSms    
  ,SmsAccountName = @SmsAccountName    
  ,SmsSenderName = @SmsSenderName    
  ,SmsMessage = @SmsMessage    
  ,SmsTemplateId = @SmsTemplateId    
  ,IsSmsTemplate = @IsSmsTemplate    
  ,IsEmail = @IsEmail    
  ,EmailAccountName = @EmailAccountName    
  ,EmailReplyTo = @EmailReplyTo    
  ,EmailSubject = @EmailSubject    
  ,EmailMessgae = @EmailMessgae    
  ,EmailTemplateId = @EmailTemplateId    
  ,IsTemplate = @IsTemplate    
  ,IsWebHook = @IsWebHook    
  ,WebHook = @WebHook    
  ,Lead_Unsubscribe = @Lead_Unsubscribe    
  ,IsUniCode = @IsUniCode    
  ,recvmobile = @recvmobile    
  ,recvemail = @recvemail    
  ,isprofile = @IsProfile    
 WHERE User_ID = @User_ID    
  AND ID = @ID    
    
 SELECT 'Success' AS result    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM ClientPageDetail WITH (NOLOCK)    
   WHERE ID = @ID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID    
  ,@Activity_type = 'Updt_landpg'    
  ,@ActionType = 'U'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'ClientPageDetail'    
END 


