   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatelastactivityinconvuser](    
 @entity nvarchar(20),    
 @activityid bigint    
)      
as      
begin      
 begin try      
    
  --declare  @entity nvarchar(20) = 'lead', @activityid bigint = 6280249    
  --declare  @entity nvarchar(20) = 'enquiry', @activityid bigint = 58969631    

  DECLARE @sqlquery NVARCHAR(MAX); 
  DECLARE @existsFlag BIGINT;
  declare @entityid bigint,@user_id bigint,@activitytext nvarchar(max),@activitydate datetime      
      
  if @entity='lead'      
   select @entityid=leadid,@user_id=userid,@activitytext=EventDescription,@activitydate=EventDate from mysms.dbo.tbl_LeadEventHistory(nolock) where historyid=@activityid      
      
  if @entity='enquiry'      
   select @entityid=enquiryid,@user_id=userid,@activitytext=EventDescription,@activitydate=EventDate from mysms.dbo.tbl_enquiryEventHistory(nolock) where historyid=@activityid      
  if @entity='contact'      
   select @entityid=ConversationContactID,@user_id=userid,@activitytext=EventDescription,@activitydate=EventDate from mysms.dbo.tbl_contactEventHistory(nolock) where historyid=@activityid      
      
  --if exists(select 1 from MySMSConversations.dbo.convusers(nolock) where Entity=@entity and Entityid=@entityid)   
  SElect @sqlquery = concat('
	SELECT cast(1 as bigint)
	FROM convusers (NOLOCK) 
	WHERE Entity = ''', @entity ,''' AND Entityid = ', @entityid);
	--print @sqlquery	
	-- Execute query and get count
	EXEC usp_clr_GetRemoteLongValue    @sqlquery,    @retval = @existsFlag OUT 
    

	IF @existsFlag >0
  begin      
   --update MySMSConversations.dbo.convusers  WITH (ROWLOCK) set     
   -- lastactivitytype = 'activity',     
   -- lastactivityby = @user_id,    
   -- lastactivitydate = @activitydate,    
   -- lastactivityid = @activityid,    
   -- lastactivitytext = @activitytext      
   --where Entity = @entity     
   -- and Entityid=@entityid     
   -- and @activitydate > isnull(lastactivitydate,dateadd(dd,-1,@activitydate))    
   DECLARE @updateQuery NVARCHAR(MAX);

-- Build the dynamic SQL query
SET @updateQuery = '
UPDATE convusers WITH (ROWLOCK)
SET     
    lastactivitytype = ''activity'',    
    lastactivityby = ' + CAST(@user_id AS NVARCHAR(MAX)) + ',
    lastactivitydate = ''' + CAST(@activitydate AS NVARCHAR(MAX)) + ''',
    lastactivityid = ' + CAST(@activityid AS NVARCHAR(MAX)) + ',
    lastactivitytext = ''' + @activitytext + '''      
WHERE Entity = ''' + @entity + '''     
    AND Entityid = ' + CAST(@entityid AS NVARCHAR(MAX)) + '     
    AND ''' + CAST(@activitydate AS NVARCHAR(MAX)) + ''' > ISNULL(lastactivitydate, DATEADD(dd, -1, ''' + CAST(@activitydate AS NVARCHAR(MAX)) + '''))
';
--print @updateQuery
-- Execute the dynamic SQL query
EXEC usp_clr_ExecuteRemoteQuery @updateQuery;
    
  end      
 end try      
 begin catch      
  exec mysms.dbo.usp_inserterrorinfo      
 end catch      
end



