  if @entity='lead'  
  begin  
  insert into #activityinfo(activityid,id,entityid,user_id,activitytext,activitydate)  
  select activityid,id,leadid,userid,eventdescription,eventdate from tbl_leadeventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID  
  end  
  else if @entity='enquiry'  
  begin  
  insert into #activityinfo(activityid,id,entityid,user_id,activitytext,activitydate)  
  select activityid,id,enquiryid,userid,eventdescription,eventdate from tbl_enquiryeventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID  
