   CREATE TABLE #temp1 (id BIGINT, Channelid int, Entity nvarchar(200), Entityid bigint, channelprofileid nvarchar(500),isactive bit ,createdon datetime, profilejson nvarchar(500), lastmodifiedon datetime, convuserparentid bigint,lastactivitytype nvarchar(100) ,lastactivitytext nvarchar(max),lastactivityid bigint,
	lastactivityby bigint ,astactivitydate datetime,lastactivitydirection nvarchar(5),unreadconversations int ,
	isdeactivatedon datetime,SnoozedDateTime datetime,is_blocked bit,country_iso nvarchar(5),wa_chatexpiry datetime,wa_chargesexpiry datetime);

declare @query nvarchar(max)= '
        SELECT id , Channelid , Entity , Entityid , channelprofileid ,isactive  ,createdon , profilejson , lastmodifiedon , convuserparentid ,lastactivitytype  ,lastactivitytext ,lastactivityid ,
	lastactivityby  ,astactivitydate ,lastactivitydirection ,unreadconversations  ,
	isdeactivatedon ,SnoozedDateTime ,is_blocked ,country_iso ,wa_chatexpiry ,wa_chargesexpiry 
        FROM convusers (NOLOCK) ';

    -- Execute the query using your CLR procedure
        INSERT INTO #temp1(id , Channelid , Entity , Entityid , channelprofileid ,isactive  ,createdon , profilejson , lastmodifiedon , convuserparentid ,lastactivitytype  ,lastactivitytext ,lastactivityid ,
	lastactivityby  ,astactivitydate ,lastactivitydirection ,unreadconversations  ,
	isdeactivatedon ,SnoozedDateTime ,is_blocked ,country_iso ,wa_chatexpiry ,wa_chargesexpiry )
	EXEC usp_clr_FillRemoteData @query;

update c set   
lastactivitytype = 'activity',     
    lastactivityby = user_id,    
    lastactivitydate = activitydate,    
    lastactivityid = a.activityid,    
    lastactivitytext = activitytext      
from [10.0.0.135].MySMSConversations.dbo.convusers c join   
