    lastactivityid = a.activityid~    
    lastactivitytext = ''' + @activitytext + '''      
FROM convusers c 
JOIN   
    (SELECT * FROM #activityinfo WHERE id BETWEEN ' + CAST(@id AS NVARCHAR(MAX)) + ' AND ' + CAST(@id + 500 AS NVARCHAR(MAX)) + ') a  
ON c.entity = ''' + @entity + ''' 
AND c.Entityid = a.entityid     
AND a.activitydate > ISNULL(lastactivitydate, DATEADD(dd, -1, a.activitydate))
';

-- Execute the dynamic SQL query
EXEC usp_clr_ExecuteRemoteQuery @updateQuery;*/

set @id=@id+500   
