CREATE   PROC [dbo].[Usp_UpdateLead_For_FollowupStatus_ChangeWithFollowupDate_INTDateTime]        
(        
    @ID BIGINT,        
    @AssignedTo BIGINT,        
    @FollowUpStatus INT,        
    @NextStatusDate VARCHAR(50),        
    @Products VARCHAR(1000),        
    @AmountPaid NUMERIC(18, 2),        
