    @FollowUpStatus INT,              
    @NextStatusDate VARCHAR(50),              
    @Products VARCHAR(1000),              
    @AmountPaid NUMERIC(18, 2),              
    @Remarks VARCHAR(1000),              
    @ModifiedBy BIGINT              
)              
AS              
BEGIN

      DECLARE @productsJson NVARCHAR(MAX) = (          
	   select value as ProductName    
	      from fn_split(@products,'#')    
		 FOR JSON AUTO          
		,INCLUDE_NULL_VALUES          
	   )
	 
   DECLARE @rowJson NVARCHAR(MAX)      
  declare @FollowupDate   Datetime = null, @LeadNo bigint=0      
  if(@NextStatusDate <> '')                
   Begin                
     set @FollowupDate = @NextStatusDate                
   End               
            
  if(@NextStatusDate <> '')                
   Begin           
             
 UPDATE UserLeads              
 SET    AssignedTo = @AssignedTo,              
        FollowUpStatus = @FollowUpStatus,              
        NextStatusDate = convert(nvarchar(100),dbo.[fn_getISTtimefromusertime](@ModifiedBy,@NextStatusDate),121) ,               
        --Products = @Products,              
        ProductsJson = @productsJson,
		AmountPaid = @AmountPaid,              
        Remarks = @Remarks,              
        ModifiedBy = @ModifiedBy ,             
        FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy,@FollowupDate),      
    @LeadNo = LeadNo      
 WHERE  ID = @ID              
    set @rowJson =( SELECT * FROM UserLeads WITH(NOLOCK)        
   WHERE ID = @ID        
   FOR JSON AUTO ,INCLUDE_NULL_VALUES   )        
    End        
  else        
    Begin        
            
   UPDATE UserLeads              
      SET AssignedTo = @AssignedTo,              
        FollowUpStatus = @FollowUpStatus,              
        NextStatusDate = @NextStatusDate,              
        --Products = @Products,              
        ProductsJson = @productsJson,
		AmountPaid = @AmountPaid,              
        Remarks = @Remarks,              
        ModifiedBy = @ModifiedBy ,             
        FollowupDate =  @FollowupDate,      
    @LeadNo = LeadNo      
        WHERE  ID = @ID              
         set @rowJson =( SELECT * FROM UserLeads WITH(NOLOCK)        
   WHERE ID = @ID        
   FOR JSON AUTO ,INCLUDE_NULL_VALUES   )      
            
    End             
               
               
 SELECT 'Record Updated' as msg, @LeadNo as LeadNo      
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @user_id = @ModifiedBy        
  ,@Activity_type = 'Updt_LeadForFollwupstatus'        
  ,@ActionType = 'U'        
  ,@RowJson = @rowJson        
  ,@Table_name = 'UserLeads'   
END 




