/* ============================================================
   Procedure: [dbo].[Usp_UpdateLead_For_FollowupStatus_ChangeWithFollowupDate_Replication_AppModKit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateLead_For_FollowupStatus_ChangeWithFollowupDate_Replication_AppModKit19]        
(                
    @ID BIGINT,                
    @AssignedTo BIGINT,                
    @FollowUpStatus INT,                
    @NextStatusDate VARCHAR(50),                
    @Products VARCHAR(1000),                
    @AmountPaid NUMERIC(18, 2),                
    @Remarks nVARCHAR(2000),                
    @ModifiedBy BIGINT                
)                
AS                
BEGIN          
  
     Declare @QueryProducts nvarchar(max) = ''  
     DECLARE @ProductsJson NVARCHAR(4000) = ''  
  Declare @ParentID bigint = 0  
  
  select top 1 @ParentID = ParentID from userleads with(nolock) where id = @ID  
  
   begin try   
   if(isnull(@Products,'') != '')  
   begin  
         set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (    
         select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@Products,'''') +''',''#'')) as tbl  
        join   
      tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)  
        on tbl.[value] = t.ProductID  
          
        FOR JSON AUTO            
          ,INCLUDE_NULL_VALUES    
     )','')  
    
    exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out    
         end   
      end try       
      begin catch  
      exec usp_insertErrorInfo     
   end catch  
     
  
  
   DECLARE @rowJson NVARCHAR(MAX)        
  declare @FollowupDate   Datetime = null, @LeadNo bigint=0        
  if(@NextStatusDate <> '')                  
   Begin                  
     set @FollowupDate = @NextStatusDate                  
   End                 
              
  if(@NextStatusDate <> '')                  
   Begin             
               
 UPDATE UserLeads                
 SET    AssignedTo = @AssignedTo,                
        FollowUpStatus = @FollowUpStatus,                
        NextStatusDate = convert(nvarchar(100),dbo.[fn_getISTtimefromusertime](@ModifiedBy,@NextStatusDate),121) ,                 
        ProductsJson = @ProductsJson,                
        AmountPaid = @AmountPaid,                
        Remarks = @Remarks,                
        ModifiedBy = @ModifiedBy ,               
        FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy,@FollowupDate),        
    @LeadNo = LeadNo        
 WHERE  ID = @ID                
    set @rowJson =( SELECT * FROM UserLeads WITH(NOLOCK)          
   WHERE ID = @ID          
   FOR JSON AUTO ,INCLUDE_NULL_VALUES   )          
    End          
  else          
    Begin          
              
   UPDATE UserLeads                
      SET AssignedTo = @AssignedTo,                
        FollowUpStatus = @FollowUpStatus,                
        NextStatusDate = @NextStatusDate,                
        ProductsJson = @ProductsJson,                
        AmountPaid = @AmountPaid,                
        Remarks = @Remarks,                
        ModifiedBy = @ModifiedBy ,               
        FollowupDate =  @FollowupDate,        
    @LeadNo = LeadNo        
        WHERE  ID = @ID                
         set @rowJson =( SELECT * FROM UserLeads WITH(NOLOCK)          
   WHERE ID = @ID          
   FOR JSON AUTO ,INCLUDE_NULL_VALUES   )        
              
    End               
                 
                 
 SELECT 'Record Updated' as msg, @LeadNo as LeadNo        
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @user_id = @ModifiedBy          
  ,@Activity_type = 'Updt_LeadForFollwupstatus'          
  ,@ActionType = 'U'          
  ,@RowJson = @rowJson          
  ,@Table_name = 'UserLeads'     
END 


