/* ============================================================
   Procedure: [dbo].[Usp_UpdateLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateLeadDetails (    
 @LeadNo BIGINT    
 ,@ParentID BIGINT    
 ,@PersonName VARCHAR(100)    
 ,@CompanyName VARCHAR(100)    
 ,@MobileNo VARCHAR(100)    
 ,@MobileNo1 VARCHAR(100)    
 ,@MobileNo2 VARCHAR(100)    
 ,@EmailID VARCHAR(100)    
 ,@EmailID1 VARCHAR(100)    
 ,@EmailID2 VARCHAR(100)    
 ,@City VARCHAR(100)    
 ,@State VARCHAR(100)    
 ,@Country VARCHAR(100)    
 ,@CountryCode VARCHAR(50)    
 ,@CountryCode1 VARCHAR(50)    
 ,@CountryCode2 VARCHAR(50)    
 ,@PinCode BIGINT    
 ,@ResidentialAddress VARCHAR(500)    
 ,@SourceName BIGINT    
 ,@MediumName BIGINT    
 ,@CampaignName BIGINT    
 ,@Remarks VARCHAR(1000)    
 ,@ModifiedBy BIGINT    
 )    
AS    
BEGIN    
 CREATE TABLE #temp (    
  mobile VARCHAR(100)    
  ,email VARCHAR(100)    
  )    
    
 INSERT INTO #temp (    
  mobile    
  ,email    
  )    
 SELECT (CAST(ISNULL(CountryCode, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR))    
  ,ISNULL(NULLIF(EmailID, ''), 0)    
 FROM UserLeads    
 WHERE ParentID = @PARENTID    
  AND LeadNo <> @LEADNO    
     
 UNION    
     
 SELECT (CAST(ISNULL(CountryCode1, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR))    
  ,ISNULL(NULLIF(EmailID1, ''), 0)    
 FROM UserLeads    
 WHERE ParentID = @PARENTID    
  AND LeadNo <> @LEADNO    
     
 UNION    
     
 SELECT (CAST(ISNULL(CountryCode2, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR))    
  ,ISNULL(NULLIF(EmailID2, ''), 0)    
 FROM UserLeads    
 WHERE ParentID = @PARENTID    
  AND LeadNo <> @LEADNO    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (    
      SELECT Mobile    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Mobile ' + @mobileno + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (    
      SELECT Mobile    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Mobile ' + @mobileno1 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (    
      SELECT Mobile    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Mobile ' + @mobileno2 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (    
      SELECT email    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Email ' + @EmailID + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (    
      SELECT email    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Email ' + @EmailID1 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (    
      SELECT email    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Email ' + @EmailID2 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(@EmailID1, 1) AS NVARCHAR) IN (    
      SELECT email    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Email ' + @EmailID1 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 IF EXISTS (    
   SELECT 1    
   FROM UserLeads    
   WHERE ParentID = @ParentID    
    AND (    
     CAST(ISNULL(@EmailID2, 1) AS NVARCHAR) IN (    
      SELECT email    
      FROM #temp    
      )    
     )    
   )    
 BEGIN    
  SELECT 'Lead with Email ' + @EmailID2 + ' already exists'    
    
  GOTO LeadNotInserted    
 END    
    
 UPDATE UserLeads    
 SET PersonName = @PersonName    
  ,CompanyName = @CompanyName    
  ,MobileNo = @MobileNo    
  ,MobileNo1 = @MobileNo1    
  ,MobileNo2 = @MobileNo2    
  ,EmailID = @EmailID    
  ,EmailID1 = @EmailID1    
  ,EmailID2 = @EmailID2    
  ,City = @City    
  ,STATE = @State    
  ,Country = @Country    
  ,CountryCode = @CountryCode    
  ,CountryCode1 = @CountryCode1    
  ,CountryCode2 = @CountryCode2    
  ,PinCode = @PinCode    
  ,ResidentialAddress = @ResidentialAddress    
  ,SourceName = @SourceName    
  ,MediumName = @MediumName    
  ,CampaignNAME = @CampaignName    
  ,Remarks = @Remarks    
  ,ModifiedOn = GETDATE()    
  ,ModifiedBy = @ModifiedBy    
 WHERE LeadNo = @LeadNo    
  AND ParentID = @ParentID    
    
 SELECT 'Record Updated'    
    
 DECLARE @rowJson VARCHAR(MAX) = (    
   SELECT *    
   FROM UserLeads    
   WHERE LeadNo = @LeadNo    
    AND ParentID = @ParentID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy    
   ,@Activity_type = 'Updt_lead_calRpt'    
   ,@ActionType = 'U'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'UserLeads'    
 END    
    
 LeadNotInserted:    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateLeadDetails_API]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:17:04 PM        
CREATE   PROCEDURE [dbo].[Usp_UpdateLeadDetails_API]       
(      
    @LeadNo                 BIGINT,      
    @ParentID               BIGINT,      
    @PersonName             VARCHAR(100),      
    @CompanyName            VARCHAR(100),      
    @MobileNo               VARCHAR(100),      
    @MobileNo1              VARCHAR(100),      
    @MobileNo2              VARCHAR(100),      
    @EmailID                VARCHAR(100),      
    @EmailID1               VARCHAR(100),      
    @EmailID2               VARCHAR(100),      
    @City                   VARCHAR(100),      
    @State                  VARCHAR(100),      
    @Country                VARCHAR(100),      
    @CountryCode            VARCHAR(50),      
    @CountryCode1           VARCHAR(50),      
    @CountryCode2           VARCHAR(50),      
    @PinCode                BIGINT,      
    @ResidentialAddress     VARCHAR(500),      
    @OfficeAddress          varchar(500), 
	@SourceName             BIGINT,      
    @MediumName             BIGINT,      
    @CampaignName           BIGINT,      
    @Remarks                VARCHAR(1000),      
    @ModifiedBy             BIGINT      
)      
AS      
BEGIN      
  
  Declare @LeadNoVar bigint = 0;    
  
 CREATE TABLE #temp      
 (      
  mobile     VARCHAR(100),      
  email      VARCHAR(100)      
 )        
 INSERT INTO #temp      
   (      
     mobile,      
     email      
   )      
 SELECT (      
            CAST(ISNULL(CountryCode, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR)      
        ),      
        ISNULL(NULLIF(EmailID, ''), 0)      
 FROM   UserLeads      
 WHERE  ParentID = @PARENTID      
        AND LeadNo <> @LEADNO      
 UNION      
 SELECT (      
            CAST(ISNULL(CountryCode1, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR)      
        ),      
        ISNULL(NULLIF(EmailID1, ''), 0)      
 FROM   UserLeads      
 WHERE  ParentID = @PARENTID      
        AND LeadNo <> @LEADNO      
 UNION      
 SELECT (      
          CAST(ISNULL(CountryCode2, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR)      
        ),      
        ISNULL(NULLIF(EmailID2, ''), 0)      
 FROM   UserLeads      
 WHERE  ParentID = @PARENTID      
        AND LeadNo <> @LEADNO      
       
 IF EXISTS(      
      SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (SELECT       
                                                                                                                     Mobile      
                                                                                                              FROM         
                                                                                                                     #temp)      
           )  
         
         
             
    )      
 BEGIN  
   
    SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (SELECT       
                                                                                                                     Mobile      
                                                                                                              FROM         
                                                                                                                     #temp)      
           )  
       
     SELECT 'Lead_No '+ cast(@LeadNoVar as nvarchar) +' with Mobile ' + @mobileno + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (SELECT       
                                                                                                                       Mobile      
                                                                                                                FROM         
                                                                                                                       #temp)      
                   )      
    )      
 BEGIN  
   
   SELECT  @LeadNoVar = LeadNo      
        FROM  UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (SELECT                                                                                                  Mobile      
                         FROM         
                         #temp)      
                   )    
       
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+' with Mobile ' + @mobileno1 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (SELECT       
                                                                      Mobile      
                                                                                                                FROM         
                                                                                                                  #temp)      
            )      
    )      
 BEGIN   
       
    SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (SELECT       
                                                                      Mobile      
                                                                                                                FROM         
                                                                                                                  #temp)      
            )      
                  
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+' with Mobile ' + @mobileno2 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                                    email      
                                                                             FROM         
                                                                                    #temp)      
                   )      
    )      
 BEGIN   
      
    SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                                    email      
                                                                             FROM         
                                                                                    #temp)      
                   )  
      
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+' with Email ' + @EmailID + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                        email      
                                                                              FROM         
                                                                                     #temp)      
                   )      
    )      
 BEGIN   
        SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                                     email      
                                                                              FROM         
                                                                                     #temp)      
                   )  
      
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+'  with Email ' + @EmailID1 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                                     email      
                                                                              FROM         
                                                                                     #temp)      
                   )      
    )      
 BEGIN      
       
     SELECT  @LeadNoVar = LeadNo      
      FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (SELECT       
                                                                                     email      
                                                                              FROM         
                                                                                     #temp)      
         )      
  
  
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+' with Email ' + @EmailID2 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@EmailID1, 1) AS NVARCHAR) IN (SELECT       
                                                                         email      
                                                                  FROM         
                                                                         #temp)      
                   )      
    )      
 BEGIN   
       SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@EmailID1, 1) AS NVARCHAR) IN (SELECT       
                                                                         email      
                                                                  FROM         
                                                                         #temp)      
                   )  
      
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+'  with Email ' + @EmailID1 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 IF EXISTS(      
        SELECT 1      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID      
               AND (      
                       CAST(ISNULL(@EmailID2, 1) AS NVARCHAR) IN (SELECT       
                                                                         email      
                                                                  FROM         
                                                                         #temp)      
                   )      
    )      
 BEGIN    
      SELECT  @LeadNoVar = LeadNo      
        FROM   UserLeads      
        WHERE  ParentID = @ParentID    
               AND (      
                       CAST(ISNULL(@EmailID2, 1) AS NVARCHAR) IN (SELECT       
                                                                         email      
                                                                  FROM         
                                                                         #temp)      
                   )  
  
     SELECT 'Lead_No '+cast(@LeadNoVar as nvarchar)+' with Email ' + @EmailID2 + ' already exists'       
     GOTO LeadNotInserted      
 END      
       
 UPDATE UserLeads      
 SET    PersonName = isnull(nullif(@PersonName,''),PersonName) ,      
        CompanyName = isnull(nullif(@CompanyName,''),CompanyName),      
        MobileNo = isnull(nullif(@MobileNo,''),MobileNo),      
        MobileNo1 = isnull(nullif(@MobileNo1,''),MobileNo1),      
        MobileNo2 = isnull(nullif(@MobileNo2,''),MobileNo2),      
        EmailID = isnull(nullif(@EmailID,''),EmailID),      
        EmailID1 = isnull(nullif(@EmailID1,''),EmailID1),      
        EmailID2 = isnull(nullif(@EmailID2,''),EmailID2),      
        City = isnull(nullif(@City,''),City),      
        STATE = isnull(nullif(@State,''),State),      
        Country = isnull(nullif(@Country,''),Country),      
        CountryCode = isnull(nullif(@CountryCode,''),CountryCode),      
        CountryCode1 = isnull(nullif(@CountryCode1,''),CountryCode1),      
        CountryCode2 = isnull(nullif(@CountryCode2,''),CountryCode2),      
        PinCode = isnull(nullif(@PinCode,'0'),PinCode),      
        ResidentialAddress = isnull(nullif(@ResidentialAddress,''),ResidentialAddress),      
        OfficeAddress = isnull(nullif(@OfficeAddress,''),OfficeAddress),      
		SourceName = isnull(nullif(@SourceName,0),SourceName),      
        MediumName = isnull(nullif(@MediumName,0),MediumName),      
        CampaignNAME = isnull(nullif(@CampaignName,0),CampaignNAME),      
        Remarks = isnull(nullif(@Remarks,''),Remarks),      
        ModifiedOn = GETDATE(),      
        ModifiedBy = @ModifiedBy      
 WHERE  LeadNo = @LeadNo      
        AND ParentID = @ParentID           
       
           
 insert into LeadInteractionHistory            
  (            
    LeadNo,            
    AmountPaid,  
 Remarks,            
    AssignedTo,  
 ParentID,            
    CreatedOn,  
 CreatedBy,
 FollowUpStatus            
 )            
 values            
 (    
  @LeadNo,  
  0,  
  'Lead updated',  
  0,            
  @ParentID,            
  GETDATE(),  
  @ModifiedBy,
  0            
 )  
      
 declare @LeadNoTemp nvarchar(50) = cast(@LeadNo as nvarchar)

 SELECT 'Lead_No ' + @LeadNoTemp as 'LeadNo','Success' as MSG        
 LeadNotInserted:      
  
END 


