   --  lAction, CMobile, Email, subject, Body , wmobile, wtext,P_url             
   --   from @tbl         
        
   if(@lnkct>0)        
   Begin    
      select @longurl = long_url, @short_url = short_url,            
        @lAction = lAction, @CMobile = CMobile,@Email = Email,@Subject = subject,@Body = Body        
   ,@wmobile = wmobile,@wtext = wtext,@P_url = P_url             
      from @tbl         
           
    if(exists( select 1 from Link_smsUrl_dtl where ccid = @CampaignID))  
       Begin      
     update Link_smsUrl_dtl         
      set         
   longurl = @longurl, short_url =@short_url,             
      lAction = @lAction ,CMobile = @CMobile, Email = @Email, subject = @Subject, Body = @Body        
   , wmobile = @wmobile, wtext = @wtext, P_url = @P_url            
      where ccid = @CampaignID        
       
   end  
    else  
   Begin  
        
    insert into dbo.Link_smsUrl_dtl(BatchId,ccid, longurl, short_url, parentid, page_nm,                
   lAction, CMobile, Email, subject, Body, wmobile, wtext, P_url                
     )                  
     select 0,@CampaignID, long_url, short_url,@ParentID, 'Campaign  SMS',                
     lAction, CMobile, Email, subject, Body , wmobile, wtext,P_url                 
               
      from @tbl  
  
   End  

        declare @CountVoiceBroadcast int = 0   
		select @CountVoiceBroadcast= COUNT(*) from @tblVoiceBroadcast  
		  
	  declare @IsVoice_V bit = 0                        
      Declare @AppID_V bigint = 0                        
      Declare @Duration_V int = 0                        
      Declare @DNID_V nvarchar(20) = ''                  
      Declare @Frequency_V int = 0                        
      Declare @Latency_V int = 0                        
      Declare @Route_V nvarchar(20) = ''                        
                        
  if(@CountVoiceBroadcast > 0)                        
  Begin                        
          select top 1                       
           @IsVoice_V = isVoice                         
          ,@AppID_V =  AppID                         
         ,@Duration_V =  Duration                         
         ,@DNID_V   = DNID                         
         ,@Frequency_V = Frequency                         
         ,@Latency_V = Latency                  
          ,@Route_V = Route                         
          from @tblVoiceBroadcast                        
                        
  End   

      if(@CountVoiceBroadcast > 0)                        
  Begin                        
		 if(@IsVoice_V = 1)                      
		 Begin                      
			update Link_smsUrl_dtl set isVoice = @IsVoice_V ,AppID = @AppID_V ,Duration = @Duration_V ,DNID = @DNID_V,                        
			Frequency = @Frequency_V ,Latency = @Latency_V ,Route = @Route_V                        
			where ccid = @CampaignID                        
			end                      
		 else                      
		 Begin                      
		  update Link_smsUrl_dtl set isVoice = 0                       
			where ccid = @CampaignID                        
                          
	 	 End                      
     End                        


   End
   
   select 'Data Updated'
 
End



