   Procedure: [dbo].[Usp_UpdateMailCampaign_FromTRGCmpgn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateMailCampaign_FromTRGCmpgn (
	@AccountUsed BIGINT
	,@FromMailID NVARCHAR(500)
	,@MailReplyTo NVARCHAR(500)
	,@TemplateID BIGINT
	,@MailSubject NVARCHAR(500)
	,@MailContent NVARCHAR(MAX)
	,@IsActive BIT
	,@UserID BIGINT
	,@CampaignID BIGINT
	,@TimeBeforeEvent INT
	,@TimeUnit NVARCHAR(20)
	)
AS
BEGIN
	IF (@TimeBeforeEvent = 0)
	BEGIN
		SET @TimeBeforeEvent = NULL
	END

	IF (rtrim(ltrim(@TimeUnit)) = '')
	BEGIN
		SET @TimeBeforeEvent = NULL
		SET @TimeUnit = NULL
	END

	UPDATE UserCampaignMaster
	SET AccountUsed = @AccountUsed
		,FromMailId = @FromMailID
		,MailReplyTo = @MailReplyTo
		,TemplateID = @TemplateID
		,MailSubject = @MailSubject
		,MailContent = @MailContent
		,IsActive = @IsActive
		,ModifiedOn = GETDATE()
		,ModifiedBy = @UserID
		,TimeBeforeEvent = @TimeBeforeEvent
		,TimeUnit = @TimeUnit
	WHERE id = @CampaignID

	SELECT 'Data Updated'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserCampaignMaster
			WHERE ID = @CampaignID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Updt_Mlcamp_trggrcamp'
		,@ActionType = 'U'
		,@RowJson = ''
		,@Table_name = 'UserCampaignMaster'
END



GO

