SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatemailpriority_withMailRoute  
(@batchid nvarchar(max),@priority int,@MailRoute nvarchar(20))  
as  
begin  
select value as batchid into #batchid from dbo.fn_split(@batchid,',')   
declare @count int=(select count(1) from #batchid),@minbatchid bigint=0,@bcount int,@id bigint  
update e set filterpriority=@priority,finalmailroute = @MailRoute from BatchEmail_Infos e join #batchid b on e.batchid=b.batchid  
while @count>0  
begin  
select @minbatchid=min(batchid) from #batchid where batchid>@minbatchid  
update emailsfilter set Mail_Priority=@priority where Mail_BatchID=@minbatchid   
delete from #batchid where batchid=@minbatchid  
set @count=@count-1  
end  
drop table if exists #batchid  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_updatemailstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatemailstatus] 
as 
begin 
select count(1) as Totalsent,datepart(hour,mail_delivereddate) as datehour,mail_userid,cast(dateadd(hh,-1,getdate()) as date) as maildate into #sent from mysmstrans.dbo.emailsreportsent with (nolock) where 
mail_delivereddate >=dateadd(hh,-1,getdate()) 
and mail_userid is not null 
group by mail_userid,datepart(hour,mail_delivereddate) 
select sum(case when bouncetype='Transient' then 1 else 0 end) as soft_bounces, 
sum(case when bouncetype<>'Transient' then 1 else 0 end) as hard_bounces,user_id 
into #bounces from mailbounces with (nolock) where createdon>=dateadd(hh,-1,getdate()) 
and user_id is not null 
group by user_id 
select count(1) as complaints,user_id into #complaints from mailcomplaints with (nolock) where createdon>=dateadd(hh,-1,getdate()) 
and user_id is not null 
group by user_id 
 
select distinct coalesce(s.mail_userid,b.user_id,c.user_id) parentid,datehour,totalsent,hard_bounces,soft_bounces,complaints,maildate 
into #combined from #sent s 
full outer join #bounces b on s.mail_userid=b.user_id 
full outer join #complaints c on c.user_id=b.user_id 
 
insert into mailaccountstatus(parentid,accounthealth) 
select distinct parentid,1 from #combined c where not exists(select 1 from mailaccountstatus with (nolock) where parentid =c.parentid) 
 
insert into mailsendingstats(parentid,datehour,totalsent,hard_bounces,soft_bounces,complaints,maildate) 
select parentid ,datehour,totalsent,hard_bounces,soft_bounces,complaints,maildate from #combined c where 
not exists(select 1 from mailsendingstats where parentid=c.parentid and maildate=c.maildate and datehour=c.datehour) 
 
select m.parentid,sum(totalsent) Totalsent,sum(hard_bounces+soft_bounces) as bounces,sum(complaints) complaints, 
(sum(hard_bounces+soft_bounces)/cast(sum(totalsent) as float)) *100 as bouncerate 
,(sum(complaints)/cast(sum(totalsent) as float)) *100 as complaintrate into #scorenow 
from mailaccountstatus m with (nolock) join mailsendingstats s with (nolock) on m.parentid=s.parentid 
where m.id=(select max(id) from mailaccountstatus with (nolock) where parentid=m.parentid) 
and s.createdon between m.createdon and getdate() 
group by m.parentid 
 
insert into mailaccountstatus(parentid,accounthealth,remarks,mailstotalsent,mailstotalbounced,mailstotalcomplaints,bouncerate,complaintrate) 
select parentid,case when bouncerate>=2 or complaintrate>=0.1 then 3 when bouncerate>=1 or complaintrate>=0.08 then 2 else 1 end, 
case when bouncerate>=2 or complaintrate>=0.1 then 'Critical alarm, account paused due to high bounce/complaint rate' 
 when bouncerate>=1 or complaintrate>=0.08 then 'Warning! account may be paused for reaching permitted bounce/complaint rate' 
 end,Totalsent,bounces, complaints,bouncerate ,complaintrate 
from #scorenow where bouncerate>=1 or complaintrate>=0.08 
 
select distinct s.parentid,user_login,email, 
case when bouncerate>=2 or complaintrate>=0.1 then 3 when bouncerate>=1 or complaintrate>=0.08 then 2 else 1 end ah, 
case when bouncerate>=2 or complaintrate>=0.1 then 'Critical alarm, account paused due to high bounce/complaint rate' 
 when bouncerate>=1 or complaintrate>=0.08 then 'Warning! account may be paused for reaching permitted bounce/complaint rate' 
 end as accounthealth 
 into #t 
from #scorenow s join user_detail u on s.parentid=u.user_id 
where bouncerate>=1 or complaintrate>=0.08 
 
if exists(select 1 from #t) 
begin 
declare @xml nvarchar(max),@body nvarchar(max) 
declare @c int=(select count(1) from #t),@parentid bigint=0,@emailid nvarchar(200),@user_login nvarchar(100) 
while @c>0 
begin 
select @parentid=min(parentid) from #t where parentid>@parentid 
select @user_login=user_login,@emailid=email from #t where parentid=@parentid 
SET @xml =CAST(( SELECT user_login AS 'td','',accounthealth from #t where parentid=@parentid FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX)) 
set @body='<html><H1>Dear '+@user_login +', Your mail account health has changed: Email sending is at risk - Kit19 as on '+cast (getdate() as nvarchar)+ 
'</H1><body><p><table border = 2><tr><th>user_login</th><th>accounthealth</th></tr>' 
SET @body = @body + @xml +'</table></p><p>The account health has changed due to higher than permitted bounce rate/complaint rate on the mails sent by you. For details, pl get in touch with us at contactus@kit19.com</p>' 
 
EXEC msdb.dbo.sp_send_dbmail 
@profile_name='Alerts', 
@recipients=@emailid, 
@blind_copy_recipients='contactus@pelsoftlabs.in;contactus@kit19.com;karuna@pelsoftlabs.in', 
@subject='Alert: Your mail sending may be stopped: Kit19', 
@body = @body, 
@body_format ='HTML' 
 
delete from #t where parentid=@parentid 
set @c=@c-1 
end 
end 
 
drop table if exists #t 
drop table if exists #sent 
drop table if exists #bounces 
drop table if exists #complaints 
drop table if exists #combined 
drop table if exists #scorenow 
end 



GO

