/* ============================================================
   Procedure: [dbo].[Usp_UpdateMassScheduleDateSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_UpdateMassScheduleDateSummary    
    @BatchID INT,    
 @NewSchedueDateTime varchar(max)=0    
AS    
BEGIN    
    BEGIN TRY    
        -- Begin a transaction    
        BEGIN TRANSACTION;    
    
        -- Update IsValid property to 0 in tblsummary table    
        UPDATE Tbl_MassOperationSummary SET ScheduleDateTime= @NewSchedueDateTime WHERE BatchID = @BatchID;    
    
        -- Commit the transaction if all statements are successful    
        COMMIT TRANSACTION;    
    END TRY    
    BEGIN CATCH    
        -- Rollback the transaction if an error occurs    
        ROLLBACK TRANSACTION;    
    
        -- Raise an error or handle the exception as needed    
        -- For example, you can log the error or return an error message    
        DECLARE @ErrorMessage NVARCHAR(4000);    
        DECLARE @ErrorSeverity INT;    
        DECLARE @ErrorState INT;    
    
        SELECT     
            @ErrorMessage = ERROR_MESSAGE(),    
            @ErrorSeverity = ERROR_SEVERITY(),    
            @ErrorState = ERROR_STATE();    
    
        RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);    
    END CATCH    
END  
  
  -----------------------------------------------------------------------------------------------------------------







GO

