CREATE   PROC dbo.Usp_UpdateMediumDetails (  
 @MediumID BIGINT  
 ,@Name NVARCHAR(100)  
 ,@UserID INT  
 ,@IsEditable BIT  
 ,@IsActive BIT  
 ,@ModifiedBy NVARCHAR(50)  
 )  
AS  
BEGIN  
 
          select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')       

 IF (  
   NOT EXISTS (  
    SELECT 'x'  
    FROM UserMediumSettings  
    WHERE NAME = @Name  
     AND MediumID <> @MediumID  
     AND UserID = @UserID  
    )  
   )  
 BEGIN  
  UPDATE UserMediumSettings  
  SET NAME = @Name  
   ,UserID = @UserID  
   ,ModifiedDate = GETDATE()  
   ,ModifiedBy = @ModifiedBy  
  WHERE MediumID = @MediumID  
  
  SELECT 'Record Updated'  
 END  
 ELSE  
 BEGIN  
  SELECT 'Already Exist'  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM UserMediumSettings(NOLOCK)  
   WHERE MediumID = @MediumID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'Updt_Med_Sttng'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'UserMediumSettings'  
END  


