 ,@MenuParentID int      
 ,@PageID int      
 ,@Sequence int  
 ,@MenuID int      
)      
as      
Begin      
      
  if(not exists(select 1 from Menu where MenuName = @MenuName and MenuParentID = @MenuParentID and PageID = @PageID and ID <> @MenuID ))     
