DECLARE @InsertDNDPriorityQueue NVARCHAR(MAX)                  
DECLARE @InsertDNDPriorityAirtel NVARCHAR(MAX)                     
DECLARE @InsertDNDDeleted NVARCHAR(MAX)                                      
DECLARE @sqlDelete NVARCHAR(MAX) 
DECLARE @updatednd NVARCHAR(MAX)                                          
                  
set @InsertDNDDeleted = 'insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
IsDND,Operator,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
IsDND,Operator,BatchID FROM MessageMonitor WHERE IsDnd=1  and  MessageID in '                           
SET @InsertDNDDeleted=@InsertDNDDeleted + '(' + @MsgID + ')'                          
                        
SET @InsertDNDPriority= 'insert into messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                        
IsDND,Operator,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                        
IsDND,Operator,BatchID FROM MessageMonitor WHERE IsDND=0 and Priority=0  and MessageID in '                                              
SET @InsertDNDPriority=@InsertDNDPriority + '(' + @MsgID + ')'                 
              
SET @InsertDNDPriorityQueue= 'insert into MessageQueue(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,0,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE Priority=1 and IsDND=0  and  MessageID in '   --and Operator=''UI''                                                   
SET @InsertDNDPriorityQueue=@InsertDNDPriorityQueue + '(' + @MsgID + ')'                 
              
--set @InsertDNDPriorityAirtel= 'insert into MessageQueueAirtelPri(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                
--IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,Priority,U_ID,IsUniCode,                                                
