--SET @InsertDNDPriorityAirtel=@InsertDNDPriorityAirtel + '(' + @MsgID + ')'                   
           
SET @updatednd='update messagedeliverystatus set messagestatus=3 where isdnd=1 and MessageID in (' + @MsgID + ')'           
                      
SET @sqlDelete='DELETE FROM MessageMonitor WHERE MessageID in '                                          
SET @sqlDelete=@sqlDelete + '(' + @MsgID + ')'                                          
set xact_abort on       
begin try    
           
begin distributed transaction   
exec (@updatednd)                    
exec (@InsertDNDPriority)                
exec (@InsertDNDPriorityQueue)                    
--exec (@InsertDNDPriorityAirtel)              
