CREATE   PROC [dbo].[USP_UPDATEMESSAGEDELIVERYSTATUSIFNOTALLOWForselectAll_new]    --'9990871773','f','f','335'                                             
@Mobile VARCHAR(50),                                              
@Message VARCHAR(50),                                              
@SENDerID VARCHAR(50),                                              
@U_ID VARCHAR(50)                                                      
AS                                                      
BEGIN TRANSACTION                                                     
SET NOCOUNT ON                                                   
DECLARE @UPDATE NVARCHAR(MAX)                                                
DECLARE @InsertDND NVARCHAR(MAX)                                    
DECLARE @InsertDNDPriorityQueue NVARCHAR(MAX)                  
DECLARE @InsertDNDPriorityAirtel NVARCHAR(MAX)                                    
                                
                              
DECLARE @InsertDNDDeleted NVARCHAR(MAX)                                                
DECLARE @sqlDelete NVARCHAR(MAX)                                                  
--UPDATE  FROM MessageStatus=3(IN CASE OF NOT ALLOW)                                             
DECLARE @Sqlselect NVARCHAR(MAX)  
DECLARE @updatednd NVARCHAR(MAX)                                             
DECLARE @whereClause VARCHAR(5000)                                               
SET  @whereClause='WHERE '                                              
IF(@Mobile='')                                              
BEGIN                                              
SET @whereClause=@whereClause + '1=1 and '                                              
END                                              
ELSE                                              
BEGIN                                              
SET @whereClause=@whereClause+'Mobile='''+@Mobile+''' and '                                              
END                                              
IF(@Message='')                                                                        
BEGIN                                                                         
SET @whereClause=@whereClause +'1=1 and '                                                                        
END                                                                        
ELSE                                                                        
BEGIN                                                                        
SET @whereClause=@whereClause+'Message like ''%'+@Message+'%'' and '                                                                        
END                                                                          
IF(@SENDerID='')                                                                        
BEGIN                                                           
SET @whereClause=@whereClause +'1=1 and '                                                                        
END                                                                        
ELSE                                                                  
BEGIN                                       
SET @whereClause=@whereClause+'SENDerID='''+@SENDerID+''' and '                                                                  
END                              
IF(@U_ID='')                                                                        
BEGIN                                                                    
SET @whereClause=@whereClause +'1=1  '                                                       
END                                                                        
ELSE                                                                    
BEGIN                                                                        
SET @whereClause=@whereClause+ ' U_ID = '+@U_ID                                         
END                                               
SET @Sqlselect='SELECT MessageID FROM MessageMonitor '+@whereClause                                              
                                   
                                                
  --insert record in  dbo.MessageDND                                              
SET @InsertDND= 'insert into messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE isdnd=0 and priority=0 and  MessageID in '                                                      
SET @InsertDND=@InsertDND + '(' + @Sqlselect + ')'                                                  
--END                                    
                              
SET @InsertDNDPriorityQueue= 'insert into MessageQueue(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,0,U_ID,IsUniCode,                                                
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE  isdnd=0 and priority=1 and  MessageID in '   --Operator=''UI'' and                                                   
SET @InsertDNDPriorityQueue=@InsertDNDPriorityQueue + '(' + @Sqlselect + ')'               
                              
                              
set @InsertDNDDeleted = 'insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,1,Priority,U_ID,IsUniCode,                                                
IsDND,Operator,BatchID FROM MessageMonitor WHERE isdnd=1  and  MessageID in '      
SET @InsertDNDDeleted=@InsertDNDDeleted + '(' + @Sqlselect + ')'                                    
        
--update messagedeliverystatus set messagestatus=3 where isdnd=1 and MessageID in (@Sqlselect)        
SET @updatednd='update messagedeliverystatus set messagestatus=3 where isdnd=1 and MessageID in '
SET @updatednd=@updatednd  + '(' + @Sqlselect + ')'                                                  
SET @sqlDelete='DELETE FROM MessageMonitor WHERE MessageID in '                                    
SET @sqlDelete=@sqlDelete + '(' + @Sqlselect + ')'   
                                               
exec (@updatednd)                               
exec (@InsertDNDPriorityQueue)                 
exec (@InsertDNDPriorityAirtel)                           
Exec (@InsertDNDDeleted)                                             
EXEC(@InsertDND)                                                  
EXEC(@sqlDelete)                         
                                
--print (@InsertDNDPriorityQueue)               
--print (@InsertDNDPriorityAirtel)                       
--print (@InsertDNDDeleted)                                             
--print(@InsertDND)                                                  
--print(@sqlDelete)                                                  
                                               
IF @@error<>0                                                      
BEGIN                  
  -- Rollback the TRANSACTION                                                      
    ROLLBACK                                                      
    -- Raise an error and return                                                      
    RAISERROR ('PleASe try again.', 16, 1)                                                   
    RETURN                                                      
END                                                      
IF @@error=0                                                      
BEGIN                                                      
COMMIT TRANSACTION                                                
END   
  


