/* ============================================================
   Procedure: [dbo].[USP_UPDATEMESSAGEDELIVERYSTATUSIFNOTALLOWForselectAllDNDDeletedReord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_UPDATEMESSAGEDELIVERYSTATUSIFNOTALLOWForselectAllDNDDeletedReord]   --'','','Select SenderId',''                              
@Mobile VARCHAR(50),                              
@Message VARCHAR(50),                              
@SENDerID VARCHAR(50),                              
@U_ID VARCHAR(50)                               
AS                                      
BEGIN TRANSACTION                                     
SET NOCOUNT ON                                   
DECLARE @UPDATE NVARCHAR(MAX)                                
DECLARE @InsertDND NVARCHAR(MAX)                    
DECLARE @InsertDNDPriority NVARCHAR(MAX)                    
              
DECLARE @InsertDNDDeleted NVARCHAR(MAX)                                
DECLARE @sqlDelete NVARCHAR(MAX)                                  
--UPDATE  FROM MessageStatus=3(IN CASE OF NOT ALLOW)                             
DECLARE @Sqlselect NVARCHAR(MAX)                               
DECLARE @whereClause VARCHAR(5000)                               
SET  @whereClause='WHERE '                              
IF(@Mobile='')                              
BEGIN                              
SET @whereClause=@whereClause + '1=1 and '                              
END                              
ELSE                              
BEGIN                              
SET @whereClause=@whereClause+'Mobile='''+@Mobile+''' and '                              
END                              
IF(@Message='')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +'1=1 and '                                                        
END                                                        
ELSE                                                        
BEGIN                                                        
SET @whereClause=@whereClause+'Message like ''%'+@Message+'%'' and '                                                        
END                                                          
IF(@SENDerID='Select SenderId')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +'1=1 and '                                                        
END                                                        
ELSE                                                        
BEGIN                                                        
SET @whereClause=@whereClause+'SENDerID='''+@SENDerID+''' and '                                                        
END                                                         
IF(@U_ID='')                                                        
BEGIN                                                         
SET @whereClause=@whereClause +'1=1  '                                                        
END                                                        
ELSE                                                        
BEGIN                                                        
SET @whereClause=@whereClause+ '   U_ID = '+@U_ID+' '                                                        
END                               
SET @Sqlselect='SELECT MessageID FROM MessageMonitor '+@whereClause                              
                            
    print (@Sqlselect)                 
                            
            
set @InsertDNDDeleted = 'insert into MessageStopped(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                
IsDND,messageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                
IsDND,BatchID FROM MessageMonitor  '                     
SET @InsertDNDDeleted=@InsertDNDDeleted + '' + @whereClause + ''                    
                               
SET @sqlDelete='DELETE FROM MessageMonitor '                                  
SET @sqlDelete=@sqlDelete + '' + @whereClause + ''                                  
EXEC(@UPDATE)                 
exec (@InsertDNDPriority)              
Exec (@InsertDNDDeleted)                   
EXEC(@InsertDND)                                  
EXEC(@sqlDelete)            
        
        
--print(@UPDATE)                 
--print (@InsertDNDPriority)              
--print (@InsertDNDDeleted)                             
--print(@InsertDND)                                  
--print(@sqlDelete)                                  
                              
IF @@error<>0                                      
BEGIN                                      
  -- Rollback the TRANSACTION                                      
    ROLLBACK                                      
    -- Raise an error and return                                      
    RAISERROR ('PleASe try again.', 16, 1)                                   
    RETURN                                      
END                                      
IF @@error=0                                      
BEGIN                                      
COMMIT TRANSACTION                                
END   
  


GO

/* ============================================================
   Procedure: [dbo].[usp_updatemessagestatusinqueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_updatemessagestatusinqueue]
@batchid bigint
as
begin
begin try
declare @user_id bigint,@userfilter varchar(20)
select top 1 @user_id=dbo.ufn_getuserparentid(userid)  from batchinfo with (nolock) where BatchID=@BATCHID
select @userfilter=dbo.fn_getuserfilter_real(@user_id)
if @userfilter='Critical'
begin
update [10.0.0.135].mysmstrans.dbo.messagequeuecritical  set isprocessed=0 where isprocessed=1 and batchid=@batchid
end
else if @userfilter='MTIX_TR'
begin
update [10.0.0.135].mysmstrans.dbo.messagequeuenew  set isprocessed=0 where isprocessed=1 and batchid=@batchid
end
end try
begin catch
exec usp_InsertErrorInfo
end catch

end



