/* ============================================================
   Procedure: [dbo].[usp_updateMonthlyConsumption]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updateMonthlyConsumption]      
as      
begin   

select * into #batchinfo   
from batchinfo b(nolock) where   
(cast(BatchInsertTime as date) between cast(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0)) AS date) and cast(DATEADD(month, DATEDIFF(month, 0, getdate()), 0)  as date) and ScheduledDate='') or cast(isnull(nullif(b.ScheduledDate,''),getdate()) as date) between cast(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0)) AS date) and cast(DATEADD(month, DATEDIFF(month, 0, getdate()), 0)  as date)     


   
insert into MonthlyConsumption([TotalConsumption]      
      ,[Month]      
      ,[Year]      
      ,[User_id]      
      ,[UserLogin],      
      FirstDate)      
SELECT SUM(c.debits), MONTH(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))),Year(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))),c.user_id,u.user_login,
cast(cast(Year(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))) as nvarchar) + '-' 
+ cast(MONTH(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))) as nvarchar) + '-' 
+ '01' as date) FROM credit_details (nolock) c   
join user_detail u (nolock) on u.User_ID=c.User_ID   
join #batchinfo b (nolock) on c.batchid=b.batchid  
where FromUser_ID=c.USER_ID 
--and ((c.DateCreated between dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0)) and DATEADD(month, DATEDIFF(month, 0, getdate()), 0) and b.ScheduledDate='') 
--or cast(b.ScheduledDate as date) between dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0)) 
--and DATEADD(month, DATEDIFF(month, 0, getdate()), 0))     
and not exists (select 1 from credit_details cd where Credits>0 and cd.batchid=c.batchid)    
group by c.user_id,u.user_login      
      
insert into MonthlyMailConsumption([TotalConsumption]      
      ,[Month]      
      ,[Year]      
      ,[User_id]      
      ,[UserLogin],      
      Firstdate)      
SELECT SUM(c.debits),MONTH(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))),Year(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))),c.user_id,u.user_login,cast(cast(Year(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE())
  
    
, 0))) as nvarchar) + '-' + cast(MONTH(dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0))) as nvarchar) + '-' + '01' as date) FROM mailcreditdetails (nolock) c join user_detail u (nolock) on u.User_ID=c.User_ID where FromUser_ID=c.USER_ID and 
  
    
c.datecreated between dateadd(m,-1,DATEADD(month, DATEDIFF(month, 0, GETDATE()), 0)) and DATEADD(month, DATEDIFF(month, 0, getdate()), 0)       
group by c.user_id,u.user_login      
end      
      


GO

/* ============================================================
   Procedure: [dbo].[usp_updatenotifications]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatenotifications
(@action nvarchar(100),@parentid bigint,@Eventtype nvarchar(100),@isactive int,@mode nvarchar(100),@users nvarchar(max),@usergroups nvarchar(max)=null)
as
begin
if exists(select 1 from Kit19notifications(nolock) where parentid=@parentid and mode=@mode and eventtype=@eventtype)
begin
update Kit19notifications set isactive=case when @action='Activation' then @isactive else isactive end,
users=case when @action='Update Users' then @users else users end,usergroups=case when @action='Update user groups'
then @usergroups else usergroups end where parentid=@parentid and mode=@mode and eventtype=@eventtype
select 'Record updated' as Status
end
else 
begin
insert into kit19notifications(Parentid,Eventtype,isactive,mode,users,usergroups)
select @parentid,@eventtype,@isactive,@mode,@users,@usergroups
select 'Record created' as status
end
end


GO

/* ============================================================
   Procedure: [dbo].[usp_updatenotifications_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatenotifications_New  --335,37,1,'sms','SiteOwner',0                
(      
 @parentid bigint,      
 @Eventid int,      
 @isactive int,      
 @modes nvarchar(max),      
 @roles nvarchar(max),      
 @userid bigint,      
 @TimeBeforeEvent int=0,      
 @TimeUnit nvarchar(20)='second'      
)      
as       
Begin      
      
    drop table if exists #modes      
 drop table if exists #TempRoles      
                   
    select ROW_NUMBER() OVER(ORDER BY value ASC) as RowNum, value as ModeName into #modes from dbo.fn_Split(@modes,',')        
      
 select value as Recipient into #TempRoles from dbo.fn_Split(@roles,',')        
       
      
 declare @ModeCount int = 0,@RecipientsCount int = 0       
 declare @RowCount int = 0      
 declare @ModeID int = 0, @ModeName nvarchar(200) = '', @context nvarchar(20) = '', @invalidroles nvarchar(max) = ''       
 declare @rowseffected int = 0      
      
 select @ModeCount = count(1) from #modes      
 select @RecipientsCount = count(1) from #TempRoles      
       
    while( @ModeCount > 0)        
   Begin      
        set @RowCount = @RowCount + 1      
      
     select @ModeName = ModeName from #modes where RowNum = @RowCount        
     select @ModeID = isnull(id,0) from notificationmodes(nolock) where mode=@ModeName        
      
     drop table if exists #roles                  
      
   select value as role,0 as roleid,cast(0 as bigint) as notificationid into #roles from dbo.fn_Split(@roles,',')                  
      
   update r set roleid=s.id,notificationid=m.id                  
   from #roles r join systemroles s on r.role =s.rolename                  
   join notificationsmaster m (nolock) on m.roleid=s.id and m.activityid=@eventid and m.modeid=@modeid        
                 
                  
   insert into adminnotificationsettings(parentid,roleid,notificationid,isactive,createdby,createdon,TimeBeforeEvent,TimeUnit,ans_eventid)                  
   select @parentid,r.roleid,notificationid,@isactive,@userid,getdate(),@TimeBeforeEvent,@TimeUnit,@eventid                   
   from #roles r where isnull(r.roleid,0)<>0 and isnull(r.notificationid,0)<>0                  
   and not exists                  
   (                  
   select 1 from adminnotificationsettings(nolock) as k where k.roleid=r.roleid and k.notificationid=r.notificationid and k.parentid=@parentid                  
   )       
      
   update n set isactive=@isactive from adminnotificationsettings n (nolock) join #roles m(nolock)                  
   on m.notificationid=n.notificationid and n.parentid=@parentid                 
   select @rowseffected = @rowseffected +  @@ROWCOUNT;                  
      
      
   if @eventid in (151,152,153,154)           
   begin          
   select @context=context from activitymaster(nolock) where id=@Eventid              
   if @isactive=0 and not exists(select 1 from adminnotificationsettings(nolock) where parentid=@parentid and ans_eventid=@eventid and isactive=1)          
   begin          
   update scheduledtodos set isvalid=0 where parentid=@parentid and eventid=@Eventid          
   end          
   end      
      
   select @invalidroles = coalesce(@invalidroles+', ','')+ (role + ':' + @ModeName ) from #roles where roleid=0 or notificationid=0                  
         
         
   set @ModeCount = @ModeCount - 1          
   End      
          
   if(@rowseffected>0 and @rowseffected=(@ModeCount*@RecipientsCount))                  
  begin                  
  select 1 as status,'Settings saved' as message                  
  end        
   else      
     Begin      
        -- select 1 as status,'Settings saved for '+cast(@rowseffected as nvarchar) +' roles. Notification for this event for roles '+ @invalidroles+' do not exist' as message       
   if(ltrim(rtrim(@invalidroles)) <> '')    
      Begin       
        select 1 as status,'Settings saved for '+cast(@rowseffected as nvarchar) +' roles. Notification for this event for roles '+ @invalidroles+' do not exist' as message    
      end    
    else    
      Begin    
      select 1 as status,'Settings saved for '+cast(@rowseffected as nvarchar) +' roles.' as message    
   End    
       
              
  end      
      
          
 drop table if exists #modes       
 drop table if exists #roles       
 drop table if exists #TempRoles                 
End 


GO

/* ============================================================
   Procedure: [dbo].[usp_updatenotifications_NewForUpdateOnly]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatenotifications_NewForUpdateOnly  --335,37,1,'sms','SiteOwner',0                    
(          
 @parentid bigint,          
 @Eventid int,          
 @isactive int,          
 @modes nvarchar(max),          
 @roles nvarchar(max),          
 @userid bigint,          
 @TimeBeforeEvent int=0,          
 @TimeUnit nvarchar(20)='second'          
)          
as           
Begin          

 begin try 

          
  if(not exists (select 1 from ActivityMaster(nolock) where @EventID in (151,152,153,154)))     
       Begin    
         set @TimeBeforeEvent = isnull(@TimeBeforeEvent,0) * (-1)  
       End    
  
  
    drop table if exists #modes          
    drop table if exists #TempRoles          
    drop table if exists #TotalADMN_NTFCNForCurrentEventID        
                       
   select ROW_NUMBER() OVER(ORDER BY value ASC) as RowNum, value as ModeName into #modes from dbo.fn_Split(@modes,',')            
          
   select value as Recipient into #TempRoles from dbo.fn_Split(@roles,',')            
           
   --select 0 as roleid,cast(0 as bigint) as notificationid into #TotalADMN_NTFCNForCurrentEventID from dbo.fn_Split(@roles,',')                       
        
    CREATE TABLE #TotalADMN_NTFCNForCurrentEventID        
  (        
    roleid int,        
    notificationid bigint        
     )        
        
        
          
 declare @ModeCount int = 0,@RecipientsCount int = 0           
 declare @RowCount int = 0          
 declare @ModeID int = 0, @ModeName nvarchar(200) = '', @context nvarchar(20) = '', @invalidroles nvarchar(max) = ''           
 declare @rowseffected int = 0          
          
 select @ModeCount = count(1) from #modes          
 select @RecipientsCount = count(1) from #TempRoles          
           
    while( @ModeCount > 0)            
   Begin          
        set @RowCount = @RowCount + 1          
          
     select @ModeName = ModeName from #modes where RowNum = @RowCount            
     select @ModeID = isnull(id,0) from notificationmodes(nolock) where mode=@ModeName            
          
     drop table if exists #roles                      
          
   select value as role,0 as roleid,cast(0 as bigint) as notificationid into #roles from dbo.fn_Split(@roles,',')                      
          
   update r set roleid=s.id,notificationid=m.id                      
   from #roles r join systemroles s on r.role =s.rolename                      
   join notificationsmaster m (nolock) on m.roleid=s.id and m.activityid=@eventid and m.modeid=@modeid            
           
    insert into #TotalADMN_NTFCNForCurrentEventID        
  (roleid,notificationid)        
  select roleid,notificationid from #roles        
                      
       insert into adminnotificationsettings(parentid,roleid,notificationid,isactive,createdby,createdon,TimeBeforeEvent,TimeUnit,ans_eventid)                      
   select @parentid,r.roleid,notificationid,@isactive,@userid,getdate(),@TimeBeforeEvent,@TimeUnit,@eventid                       
   from #roles r where isnull(r.roleid,0)<>0 and isnull(r.notificationid,0)<>0                      
   and not exists                      
   (                      
   select 1 from adminnotificationsettings where roleid=r.roleid and notificationid=r.notificationid and parentid=@parentid                      
   )           
          
   update n set isactive=@isactive    
    ,TimeBeforeEvent = @TimeBeforeEvent ,TimeUnit=@TimeUnit      
    from adminnotificationsettings n (nolock) join #roles m(nolock)                      
   on m.notificationid=n.notificationid and n.parentid=@parentid                     
   select @rowseffected = @rowseffected +  @@ROWCOUNT;                      
          
          
   if @eventid in (151,152,153,154)               
   begin              
   select @context=context from activitymaster(nolock) where id=@Eventid                  
   if @isactive=0 and not exists(select 1 from adminnotificationsettings(nolock) where parentid=@parentid and ans_eventid=@eventid and isactive=1)              
   begin              
   update scheduledtodos set isvalid=0 where parentid=@parentid and eventid=@Eventid              
   end              
   end          
          
   select @invalidroles = coalesce(@invalidroles+', ','')+ (role + ':' + @ModeName ) from #roles where roleid=0 or notificationid=0                      
             
             
   set @ModeCount = @ModeCount - 1              
   End          
              
   if(@rowseffected>0 and @rowseffected=(@ModeCount*@RecipientsCount))                      
  begin        
          
      delete from adminnotificationsettings          
    where parentid = @parentid and ans_eventid = @Eventid        
             and id not in (        
                 
      select  id from adminnotificationsettings(nolock) as ADM        
       join #TotalADMN_NTFCNForCurrentEventID as TempCurrentNTFCN         
       on ADM.roleid = TempCurrentNTFCN.roleid        
         and ADM.notificationid = TempCurrentNTFCN.notificationid        
          where ADM.parentid = @parentid and Adm.ans_eventid = @Eventid         
    )                 
                      
       select 1 as status,'Settings saved' as message                      
  end            
      else          
     Begin          
        
     if(@rowseffected>0)         
     Begin        
        
        delete from adminnotificationsettings          
            where parentid = @parentid and ans_eventid = @Eventid        
             and id not in (        
                 
      select  id from adminnotificationsettings(nolock) as ADM        
       join #TotalADMN_NTFCNForCurrentEventID as TempCurrentNTFCN         
       on ADM.roleid = TempCurrentNTFCN.roleid        
         and ADM.notificationid = TempCurrentNTFCN.notificationid        
          where ADM.parentid = @parentid and Adm.ans_eventid = @Eventid         
    )             
        
     End        
        
       if(ltrim(rtrim(@invalidroles)) <> '')        
      Begin           
        select 1 as status,'Settings saved partially for '+cast(@rowseffected as nvarchar) +' roles. Notification for this event for roles '+ @invalidroles+' do not exist' as message        
      end        
    else        
      Begin        
      select 1 as status,'Settings saved for '+cast(@rowseffected as nvarchar) +' roles.' as message        
   End        
        
        
        
                    
  end          
   end try
  begin catch
    exec usp_InsertErrorInfo 
  end catch

          
 drop table if exists #modes           
 drop table if exists #roles           
 drop table if exists #TempRoles                     
 drop table if exists #TotalADMN_NTFCNForCurrentEventID         
        
End 


GO

/* ============================================================
   Procedure: [dbo].[usp_updatenotifications1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_updatenotifications1  --335,37,1,'sms','SiteOwner',0        
(@parentid bigint,@Eventid int,@isactive int,@mode nvarchar(100),@roles nvarchar(max),@userid bigint,@TimeBeforeEvent int=0,@TimeUnit nvarchar(20)='second')          
as          
begin          
if not exists(select 1 from notificationmodes where mode=@mode and isactive=1)          
begin          
Select 0 as status, 'Mode does not exist' as Message          
GOTO ENDP          
end          
if not exists(select 1 from ActivityMaster where id=@Eventid)          
