select @invalidroles=coalesce(@invalidroles+', ','')+role from #roles where roleid=0 or notificationid=0          
select 1 as status,'Settings saved for '+cast(@rowseffected as nvarchar) +' roles. Notification for this event for roles '+ @invalidroles+' do not exist' as message          
