/* ============================================================
   Procedure: [dbo].[Usp_UpdateOfflineEnquiryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_UpdateOfflineEnquiryDetails]
(
    @EnquiryUpdates dbo.OfflineEnquiryType READONLY,
    @Custom customEnquiry2 READONLY
)
AS
BEGIN
    SET NOCOUNT ON;

    PRINT '--- START: Usp_UpdateOfflineEnquiryDetails ---';

    ----------------------------------------------------------------
    -- 1. Update Enquiry Master in bulk
    ----------------------------------------------------------------
    PRINT 'Step 1: Updating Enquiry Master...';

    ;WITH CTE AS
    (
        SELECT *,
               TRY_CAST(NULLIF(WhereLatitude,'') AS FLOAT) AS latitude,
               TRY_CAST(NULLIF(WhereLongitude,'') AS FLOAT) AS longitude
        FROM @EnquiryUpdates
    )
    UPDATE UE
    SET
        PersonName          = C.PersonName,
        CompanyName         = C.CompanyName,
        MobileNo            = C.MobileNo,
        MobileNo1           = C.MobileNo1,
        MobileNo2           = C.MobileNo2,
        EmailID             = C.EmailID,
        EmailID1            = C.EmailID1,
        EmailID2            = C.EmailID2,
        City                = C.City,
        State               = C.State,
        Country             = C.CountryName,
        CountryCode         = C.CountryCode,
        CountryCode1        = C.CountryCode1,
        CountryCode2        = C.CountryCode2,
        ResidentialAddress  = C.ResidentialAddress,
        OfficeAddress       = C.OfficeAddress,
        PinCode             = C.PinCode,
        SourceName          = C.SourceName,
        MediumName          = C.Medium,
        CampaignName        = C.Campaign,
        InitialRemarks      = C.InitialRemarks,
        ParentID            = C.ParentID,
        WhereAddress        = C.WhereAddress,
        Latitude            = C.latitude,
        Longitude           = C.longitude
    FROM UserEnquiry UE
    INNER JOIN CTE C ON UE.EnquiryID = C.EnquiryID;

    PRINT 'Step 1 Completed. Rows affected in UserEnquiry = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    ----------------------------------------------------------------
    -- 2. Custom Field Updates + Inserts (set-based)
    ----------------------------------------------------------------
    PRINT 'Step 2: Processing Custom Fields...';

    SELECT *--, C.EnquiryID
    INTO #customTemp
    FROM @Custom C;

    PRINT 'Temp custom field rows loaded = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    -- update existing
    UPDATE CF
    SET fieldvalue = CT.fieldvalue
    FROM customfieldEnquiryvalue CF
    INNER JOIN #customTemp CT 
        ON CF.EnquiryID = CT.EnquiryID 
       AND CF.fieldID   = CT.fieldID;

    PRINT 'Custom Field Updates Completed. Rows affected = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    -- insert missing
    INSERT INTO customfieldEnquiryvalue (EnquiryID, fieldID, fieldvalue)
    SELECT CT.EnquiryID, CT.fieldID, CT.fieldvalue
    FROM #customTemp CT
    WHERE NOT EXISTS (
        SELECT 1 
        FROM customfieldEnquiryvalue CF
        WHERE CF.EnquiryID = CT.EnquiryID
          AND CF.fieldID   = CT.fieldID
    );

    PRINT 'Custom Field Inserts Completed. Rows inserted = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    DROP TABLE #customTemp;

    ----------------------------------------------------------------
    -- 3. Tags Processing (Set-based, NO WHILE)
    ----------------------------------------------------------------
    PRINT 'Step 3: Processing Tags...';

    IF EXISTS (SELECT 1 FROM @EnquiryUpdates WHERE ISNULL(EnquiryTags,'') <> '')
    BEGIN
        PRINT 'Tag data found. Splitting tags...';

        SELECT EU.EnquiryID, EU.ParentID,
               LTRIM(RTRIM(
                   IIF(CHARINDEX(':', F.value, 1) = 0, F.value,
                       SUBSTRING(F.value, 1, CHARINDEX(':', F.value, 1) - 1)
                   )
               )) AS TagName
        INTO #TagData
        FROM @EnquiryUpdates EU
        CROSS APPLY dbo.fn_Split(EU.EnquiryTags, ',') F
        WHERE ISNULL(EU.EnquiryTags,'') <> '';

        PRINT 'Tag rows prepared = ' + CAST(@@ROWCOUNT AS NVARCHAR);

        -- Insert missing tags into TagMaster
        INSERT INTO TagMaster(Tag, ParentID, CreatedDate, CreatedBy)
        SELECT DISTINCT TD.TagName, TD.ParentID, GETDATE(), TD.ParentID
        FROM #TagData TD
        LEFT JOIN TagMaster TM ON TM.ParentID = TD.ParentID AND LOWER(TM.Tag) = LOWER(TD.TagName)
        WHERE TM.ID IS NULL;

        PRINT 'New Tags inserted into TagMaster = ' + CAST(@@ROWCOUNT AS NVARCHAR);

        -- Refresh with Tag IDs
        SELECT TD.EnquiryID, TD.ParentID, TM.ID AS TagID
        INTO #TagMapping
        FROM #TagData TD
        INNER JOIN TagMaster TM ON TM.ParentID = TD.ParentID AND LOWER(TM.Tag) = LOWER(TD.TagName);

        PRINT 'Tag mapping prepared = ' + CAST(@@ROWCOUNT AS NVARCHAR);

        -- Remove old mappings
        DELETE ETM
        FROM EntityTagMapping ETM
        INNER JOIN @EnquiryUpdates EU ON ETM.EntityID = EU.EnquiryID
        WHERE LOWER(ETM.Entity) = 'enquiry';

        PRINT 'Old Tag Mappings Deleted = ' + CAST(@@ROWCOUNT AS NVARCHAR);

        -- Insert new mappings
        INSERT INTO EntityTagMapping(EntityID, Entity, TagID, CreatedDate)
        SELECT TM.EnquiryID, 'Enquiry', TM.TagID, GETDATE()
        FROM #TagMapping TM;

        PRINT 'New Tag Mappings Inserted = ' + CAST(@@ROWCOUNT AS NVARCHAR);

        DROP TABLE #TagData;
        DROP TABLE #TagMapping;
    END
    ELSE
    BEGIN
        PRINT 'No tags found in @EnquiryUpdates. Skipping Tag Processing.';
    END

    ----------------------------------------------------------------
    -- 4. Final Message
    ----------------------------------------------------------------
    PRINT '--- END: Usp_UpdateOfflineEnquiryDetails ---';
    SELECT 'Bulk Update Completed Successfully' AS Message;
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateOfflineLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


            
CREATE   PROCEDURE [dbo].[Usp_UpdateOfflineLeadDetails]
(
    @LeadEdits dbo.OfflineLeadType READONLY, 
    @Custom dbo.CustomLeads3 READONLY
)
AS
BEGIN
    SET NOCOUNT ON;

    /* === Normalize lat/long into temp table === */
    IF OBJECT_ID('tempdb..#Norm') IS NOT NULL DROP TABLE #Norm;

    SELECT *,
           TRY_CAST(NULLIF(WhereLatitude,'') AS FLOAT)  AS Latitude,
           TRY_CAST(NULLIF(WhereLongitude,'') AS FLOAT) AS Longitude
    INTO #Norm
    FROM @LeadEdits;

    /* === Check duplicates === */
    IF EXISTS (
        SELECT 1
        FROM #Norm n
        JOIN UserLeads u
          ON u.ParentID = n.ParentID
         AND u.ID  <> n.LeadID
         AND (
                (ISNULL(u.CountryCode,'')  + ISNULL(u.MobileNo,'')  = ISNULL(n.CountryCode,'')  + ISNULL(n.MobileNo,'')  AND ISNULL(n.MobileNo,'')  <> '')
             OR (ISNULL(u.CountryCode1,'') + ISNULL(u.MobileNo1,'') = ISNULL(n.CountryCode1,'') + ISNULL(n.MobileNo1,'') AND ISNULL(n.MobileNo1,'') <> '')
             OR (ISNULL(u.CountryCode2,'') + ISNULL(u.MobileNo2,'') = ISNULL(n.CountryCode2,'') + ISNULL(n.MobileNo2,'') AND ISNULL(n.MobileNo2,'') <> '')
             OR (ISNULL(u.EmailID,'')  = ISNULL(n.EmailID,'')   AND ISNULL(n.EmailID,'')  <> '')
             OR (ISNULL(u.EmailID1,'') = ISNULL(n.EmailID1,'')  AND ISNULL(n.EmailID1,'') <> '')
             OR (ISNULL(u.EmailID2,'') = ISNULL(n.EmailID2,'')  AND ISNULL(n.EmailID2,'') <> '')
             )
    )
    BEGIN
        SELECT 'Duplicate mobile/email found. Record not updated' AS Msg;
        RETURN;
    END;

    /* === Update UserLeads === */
    UPDATE u
    SET u.PersonName   = n.PersonName,
        u.CompanyName  = n.CompanyName,
        u.MobileNo     = n.MobileNo,
        u.MobileNo1    = n.MobileNo1,
        u.MobileNo2    = n.MobileNo2,
        u.EmailID      = n.EmailID,
        u.EmailID1     = n.EmailID1,
        u.EmailID2     = n.EmailID2,
        u.City         = n.City,
        u.State        = n.State,
        u.Country      = n.Country,
        u.SourceName   = n.SourceName,
        u.MediumName   = n.MediumName,
        u.CampaignName = n.CampaignName,
        u.CountryCode  = n.CountryCode,
        u.CountryCode1 = n.CountryCode1,
        u.CountryCode2 = n.CountryCode2,
        u.PinCode      = n.PinCode,
        --u.InitialRemarks = COALESCE(n.InitialRemarks, u.InitialRemarks),
        u.ResidentialAddress = NULLIF(n.ResidentialAddress,''),
        u.OfficeAddress      = NULLIF(n.OfficialAddress,''),
        u.ModifiedOn   = GETDATE(),
        --u.ModifiedBy   = n.ModifiedBy,
        u.WhereAddress = n.WhereAddress,
        u.Latitude     = n.Latitude,
        u.Longitude    = n.Longitude
    FROM UserLeads u
    JOIN #Norm n ON u.Id = n.Leadid AND u.ParentID = n.ParentID;

    /* === Handle Tags === */
    ;WITH Tags AS (
        SELECT n.Leadid, n.ParentID,
               LTRIM(RTRIM(
                   IIF(CHARINDEX(':', v.value, 1) = 0,
                       v.value,
                       SUBSTRING(v.value,1,CHARINDEX(':',v.value,1)-1)
                   )
               )) AS TagName
        FROM #Norm n
        CROSS APPLY fn_Split(n.LeadTags, ',') v
        WHERE n.LeadTags IS NOT NULL AND n.LeadTags <> ''
    )
    MERGE TagMaster AS tm
    USING (SELECT DISTINCT ParentID, LOWER(TagName) AS TagName FROM Tags) AS t
       ON tm.ParentID = t.ParentID AND LOWER(tm.Tag) = t.TagName
    WHEN NOT MATCHED THEN
        INSERT (Tag, ParentID, CreatedDate, CreatedBy)
        VALUES (t.TagName, t.ParentID, GETDATE(), t.ParentID);

    DELETE etm
    FROM EntityTagMapping etm
    JOIN #Norm n ON etm.EntityID = (SELECT TOP 1 ID FROM UserLeads WHERE LeadNo = n.Leadid AND ParentID = n.ParentID)
                AND LOWER(etm.Entity) = 'lead';

    INSERT INTO EntityTagMapping(EntityID, Entity, TagID, CreatedDate)
    SELECT ul.ID, 'lead', tm.ID, GETDATE()
    FROM (
        SELECT n.Leadid, n.ParentID,
               LTRIM(RTRIM(
                   IIF(CHARINDEX(':', v.value, 1) = 0,
                       v.value,
                       SUBSTRING(v.value,1,CHARINDEX(':',v.value,1)-1)
                   )
               )) AS TagName
        FROM #Norm n
        CROSS APPLY fn_Split(n.LeadTags, ',') v
        WHERE n.LeadTags IS NOT NULL AND n.LeadTags <> ''
    ) t
    JOIN UserLeads ul ON ul.LeadNo = t.LeadId AND ul.ParentID = t.ParentID
    JOIN TagMaster tm ON tm.ParentID = t.ParentID AND LOWER(tm.Tag) = LOWER(t.TagName);

    /* === Handle Custom Fields === */
    MERGE customfieldLeadvalue AS target
    USING @Custom AS src
       ON target.LeadID = src.LeadID AND target.fieldID = src.fieldID
    WHEN MATCHED THEN
        UPDATE SET target.fieldvalue = src.fieldvalue
    WHEN NOT MATCHED BY TARGET THEN
        INSERT (LeadID, EnquiryID, fieldID, fieldvalue)
        VALUES (src.LeadID, src.EnquiryID, src.fieldID, src.fieldvalue);

    SELECT 'Record(s) Updated' AS Msg;
END;




GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateOfflineTaskOrAppointmentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_UpdateOfflineTaskOrAppointmentDetails]
    @TaskTable dbo.OfflineTaskType READONLY
AS
BEGIN
    SET NOCOUNT ON;

    --------------------------------------------------------
    -- Update Task History (set-based, no loop)
    --------------------------------------------------------
    UPDATE TH
    SET TH.Title            = T.Title,
        TH.Description      = T.Description,
        TH.Address          = T.Address,
        TH.StartDate        = T.StartDate,
        TH.EndDate          = T.EndDate,
        TH.LeadId           = T.LeadId,
        TH.AssignedTo       = T.AssignedTo,
        TH.IsActive         = T.IsActive,
        TH.TaskId           = T.TaskId,
        TH.OutcomesId       = T.OutcomesId,
        TH.Status           = T.Status,
        TH.IsTask           = T.IsTask,
        TH.IsAppointment    = T.IsAppointment,
        TH.TaskType         = T.TaskType,
        TH.CompleteAddress  = T.CompleteAddress,
        TH.Latitude         = T.Latitude,
        TH.Longitude        = T.Longitude,
        TH.CompletedOn      = IIF(T.Status = 'completed', GETDATE(), NULL),
        TH.UpdatedOn        = GETDATE()
    FROM tbl_tsk_TaskHistory TH
    INNER JOIN @TaskTable T ON TH.Id = T.Id; -- <- use T.Id (task-history id), not T.TaskId

    --------------------------------------------------------
    -- Handle Collaborators (mark old deleted, re-insert new)
    --------------------------------------------------------
    UPDATE CM
    SET CM.DeletedOn = GETDATE()
    FROM tbl_tsk_CollaborationUserMapping CM
    INNER JOIN @TaskTable T ON CM.TaskHistoryId = T.Id; -- <- use T.Id

    ;WITH SplitCollab AS
    (
        SELECT 
            T.Id AS TaskHistoryId,                -- <- use T.Id
            LTRIM(RTRIM([value])) AS UserId,
            T.CreatedBy,
            T.Title,
            T.TaskType,
            T.LeadId,
            T.EndDate,
            T.IsSMS,
            T.IsEmail,
            T.SmsSchedule,
            T.EmailSchedule,
            T.NotifyMe,
            T.IsAppointment,
            T.CollabratoerUserIds
        FROM @TaskTable T
        CROSS APPLY STRING_SPLIT(T.CollabratoerUserIds, '#')
        WHERE LTRIM(RTRIM([value])) <> ''
    )
    MERGE tbl_tsk_CollaborationUserMapping AS Target
    USING SplitCollab AS Src
        ON Target.User_Id = TRY_CAST(Src.UserId AS BIGINT)
       AND Target.TaskHistoryId = Src.TaskHistoryId
    WHEN MATCHED THEN
        UPDATE SET Target.DeletedOn = NULL
    WHEN NOT MATCHED THEN
        INSERT (User_Id, CreatedOn, CreatedBy, TaskHistoryId)
        VALUES (TRY_CAST(Src.UserId AS BIGINT), GETDATE(), Src.CreatedBy, Src.TaskHistoryId);

    --------------------------------------------------------
    -- Insert Reminders (only for new/active collaborators)
    --------------------------------------------------------
    INSERT INTO tbl_tsk_Reminder (Description, Status, Schedule, CreatedOn, CreatedBy, IsSMS, IsEmail, CollaborationUserMappingId)
    SELECT 
        'You are now a Collaborator of task of type ' + S.TaskType +
        ' with title ' + S.Title +
        ' for Lead no. ' + CAST(S.LeadId AS VARCHAR) +
        ' scheduled at ' + CONVERT(VARCHAR(50), S.EndDate),
        'open',
        CASE WHEN S.IsSMS = 1 THEN S.SmsSchedule ELSE S.EmailSchedule END,
        GETDATE(),
        S.CreatedBy,
        S.IsSMS,
        S.IsEmail,
        C.Id
    FROM SplitCollab S
    INNER JOIN tbl_tsk_CollaborationUserMapping C
        ON C.User_Id = TRY_CAST(S.UserId AS BIGINT)
       AND C.TaskHistoryId = S.TaskHistoryId
       AND C.DeletedOn IS NULL;

    --------------------------------------------------------
    -- Fire Notifications (still requires EXEC per row)
    --------------------------------------------------------
    DECLARE @TaskId BIGINT, @Msg NVARCHAR(MAX), @CollabIds VARCHAR(1000), @Title VARCHAR(255), @CreatedBy BIGINT, @NotifyMe BIT, @IsAppointment BIT;

    DECLARE cur CURSOR FAST_FORWARD FOR
        SELECT Id, CollabratoerUserIds, Title, CreatedBy, NotifyMe, IsAppointment -- <- use Id (task-history id)
        FROM @TaskTable
        WHERE NotifyMe = 1;

    OPEN cur;
    FETCH NEXT FROM cur INTO @TaskId, @CollabIds, @Title, @CreatedBy, @NotifyMe, @IsAppointment;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @Msg = (CASE WHEN @IsAppointment=1 THEN 'Appointment ' ELSE 'Task ' END) 
                 + 'Edited notification: Dear Collaborator, with title ' + @Title
                 + ' edited on ' + CAST(GETDATE() AS NVARCHAR);
        DECLARE @Schedule DATETIME = DATEADD(MINUTE, 10, GETDATE());
        DECLARE @CutOff   DATETIME = DATEADD(HOUR,   6,  GETDATE());

        EXEC usp_SaveNotification
             @CollabIds,
             @Title,
             @Msg,
             'https://kit19.com/IndexNew1/images/logo.png',
             '',
             @Schedule,
             @CutOff,
             @CreatedBy;

        FETCH NEXT FROM cur INTO @TaskId, @CollabIds, @Title, @CreatedBy, @NotifyMe, @IsAppointment;
    END;
    CLOSE cur;
    DEALLOCATE cur;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_updateOldmaildeliveryreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updateOldmaildeliveryreport]         
as        
begin        
declare @MailDeliveryReportId bigint=isnull((select max(MailDeliveryReportId) from MailupdatedTill where updatetable='Old'),0)        
declare @CurrentMailDeliveryReportId bigint=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport](nolock))       
if @MailDeliveryReportId<>@CurrentMailDeliveryReportId      
begin       
select * into #temp from [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) where mdr.ID>@MailDeliveryReportId
declare @c bigint=(select COUNT(distinct cast(MDR.DateCreated as DATE)) from #temp mdr)
declare @DATE DATE
select  @MailDeliveryReportId=(select MAX(id) from #temp)        
while @c>0
begin
RETRY1:
begin try        
begin transaction  
SELECT @DATE=MIN(CAST(DATECREATED AS DATE) ) FROM #temp     
update m set SentFinalDatetime=case when SentFinalDatetime is null then mdr.DateCreated else SentFinalDatetime end,status=mdr.event + ' ' + mdr.RESPONSE from thirtydaysClientEmails m join #temp MDR on MDR.APIHEADER=cast(m.GUID as nvarchar(50)) and mdr.EMAIL collate SQL_Latin1_General_CP1_CI_AS =m.Email_Id and MDR.ID=(select MAX(id) from #temp mm (nolock) where mm.APIHEADER=mdr.APIHEADER AND CAST(MM.DateCreated AS DATE)=@DATE)         
DELETE mm From #TEMP MM WHERE CAST(MM.DateCreated AS DATE)=@DATE
select @c=COUNT(distinct cast(MDR.DateCreated as DATE)) from #temp mdr
COMMIT                                          
END TRY                                          
BEGIN CATCH                                                                                              
IF @@TRANCOUNT>0                                          
ROLLBACK                                          
EXECUTE USP_INSERTERRORINFO;     
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number    
BEGIN    
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms    
GOTO RETRY1 -- Go to Label RETRY    
END                                               
END CATCH
eND   

insert into mailupdatedtill(dateupdated,MailDeliveryReportId,Updatetable)        
select GETDATE(),@CurrentMailDeliveryReportId,'Old'        
drop table #temp        
end     
end 






GO

