/* ============================================================
   Procedure: [dbo].[Usp_UpdateParallelRinging]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateParallelRinging
(
 @ParentID bigint,
 @Status nvarchar(10),
 @AppID nvarchar(50)

)
as
Begin

   if(exists(select 'x' from Cloud_flow_api where Parentid = @ParentID and Appid = @AppID))
     Begin
	     
		 if(@Status = 'false')
		    begin
			 
			  update  Cloud_flow_api set ActivateParallelRinging = 1 where Parentid = @ParentID and Appid = @AppID
             
			  select 'Activated'

			end
          else
		    begin
			 
			 update  Cloud_flow_api set ActivateParallelRinging = 0 where Parentid = @ParentID and Appid = @AppID
             
			  select 'Deactivated'

			end


	 End   
    else
	  Begin
	      select 'Please create IVR flow first then toggle status'
	  End

End


