/* ============================================================
   Procedure: [dbo].[usp_updateparentsuperresellerid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_updateparentsuperresellerid  
@usercreated bigint  
as  
begin  
declare @userresellerrelation bigint  
if not exists(select 1 from userresellerrelation where USER_ID=@usercreated)  
begin  
insert into userresellerrelation  
select u.user_login,u.User_ID,r.reseller_id,rr.user_login as resellerlogin,rr.user_id as resellerid --into userresellerrelation1    
from reseller_detail r join user_detail u on u.M_ID=r.Reseller_ID join (select user_login,USER_ID from user_detail) RR on rr.User_ID=r.user_id where u.User_ID=28788--@usercreated  
set @userresellerrelation=scope_identity()  
end  
;with     
descendants as  
  ( select resellerid, user_id as descendant, 1 as level  
    from userresellerrelation   
  union all  
    select d.resellerid, s.user_id, d.level + 1  
    from descendants as d  
   join userresellerrelation s  
    on d.descendant = s.resellerid  
  )   
  insert into SuperResellerIds  
select resellerid,descendant,level --into SuperResellerIds--select * from superresellerids where level=7  
from descendants where descendant=@usercreated  
order by resellerid, level, descendant ;  
  
update u set ParentSuperResellerId=s.resellerid from user_detail u join superresellerids s on u.user_id=s.resellerid where resellerid<>1 and resellerid<>335 and user_id =@usercreated and level=(select MAX(level) from superresellerids s1 where s1.descendant=s.descendant and resellerid<>1 and resellerid<>335)  
update u set ParentSuperResellerId=335 from user_detail u where (u.ParentSuperResellerId is null or u.ParentSuperResellerId=0) and user_id =@usercreated   
end



GO

