        -- @ismail  bit    ,           
        --- @isIntsms bit ,             
         --@mailBalance1 bigint,              
         --@mailBalance2 bigint          
         --@balanceAfterActualCredit1 bigint,            
         --@balanceAfterActualCredit2 bigint,            
         --@balanceAfterActualMailCredit1 bigint,            
         --@balanceAfterActualMailCredit2 bigint                     
            
 SELECT @UserFilter = ud.userfilter,@m_ID = ud.M_ID FROM   User_Detail AS ud(nolock) WHERE  ud.[User_ID] = @ParentID       
                     SELECT @ToM_ID = ud.M_ID FROM   User_Detail AS ud WHERE  ud.[User_ID] = '335'                                    
 --SELECT @Amount = Price,@Credits= Quantity,@issms=issms ,@ismail=ismail,          
 --@isIntsms = isintsms FROM PlanMaster WHERE  ID  = @PlanID                    
          
--SELECT TOP 1 @Balance1 = cd.Balance FROM   Credit_Details AS cd(nolock) WHERE  cd.[User_ID] = @UserID ORDER BY cd.Credit_ID DESC            
-- SELECT TOP 1 @Balance2 = cd.Balance FROM   Credit_Details AS cd(nolock) WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC            
-- SELECT TOP 1 @mailBalance1 = isnull(cd.Balance,0) FROM mailCreditDetails AS cd(nolock) WHERE  cd.[User_ID] = @UserID ORDER BY cd.Credit_ID DESC            
-- SELECT TOP 1 @mailBalance2 = cd.Balance FROM mailCreditDetails AS cd(nolock) WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC                            
 SELECT TOP 1 @Balanceint1 = cd.Balance FROM   IntCredit_Details AS cd(nolock) WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC            
 SELECT TOP 1 @Balanceint2 = cd.Balance FROM   IntCredit_Details AS cd(nolock) WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC            
          
                   
--select @freesmscredits = case when issmscredit=1 then SMSCredits else SMSCredits*@Credits/100 end ,          
--  @freemailcredits=case when IsMailCredit =1 then MailCredits else 0 end,          
