--from M_Coupon where CouponCode=@coupon_code              
              
INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,issms,ismail,IntCredit,CreatedBy,tax_amount, ACD_CreatedBy)     
VALUES(@ParentID,@UserFilter,'Unlimited',@Amount,@Actual_Amount,'NR','10','Purchase','Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,0,GETDATE(),0,0,1,@UserID,(@Amount - @Actual_Amount),@UserID)             
                     
INSERT INTO IntCredit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,  DateUpdated,EmpUpdated,LastModified,typecredit,Remarks,ICD_CreatedBy)                    
VALUES(NEWID(),@MIDP,335,@ParentID,0,@Credits,ISNULL(@Balanceint1, 0) + @Credits,'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),0,    
  'Purchase made by user online via Bank Transaction ID :' + @TransactionID+' . Amount paid: Total: '+cast(@Amount as nvarchar)+', Credited: '+      
cast(@actual_amount as nvarchar)+ ', Tax: '+ cast((@amount-@actual_amount) as nvarchar),@UserID)       
declare @intCreditId bigint = scope_identity()    
exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId    
    
                     
INSERT INTO IntCredit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,typecredit,Remarks,ICD_CreatedBy)                    
VALUES(NEWID(),@ToM_ID,@ParentID,335,@Credits,0,ISNULL(@Balanceint2, 0) -(@Credits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),0,'Purchase made by user online via Bank Transaction ID :' + @TransactionID+' . Amount paid: Total: ' 
 
+    
cast(@Amount as nvarchar)+', Credited: '+      
cast(@actual_amount as nvarchar)+ ', Tax: '+ cast((@amount-@actual_amount) as nvarchar),@UserID)               
    
declare @intCreditId_1 bigint = scope_identity()    
exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId_1    
    
          
            
update Payment_Detail               
    set                   
    TotalAmount = @Amount,                    
    InvoiceNo = NEWID(),                    
    [Status] = 'Success',                    
    PaymentThrough = 1,                    
    PaymentMode = 'RazorPay',                    
    BankTransactionId = @TransactionID,                    
