    --OldSmsBalance = ISNULL(@Balance1, 0),                    
    --NewSmsBalance = ISNULL(@Balance1, 0),             
    --OldMailBalance = ISNULL(@mailBalance1, 0),            
    --NewMailBalance = ISNULL(@mailBalance1, 0) ,                
    Actual_Amount = @Actual_Amount ,          
 OldIntBalance=   ISNULL(@Balanceint1, 0),            
 NewIntBalance=    ISNULL(@Balanceint1, 0)+@Actual_Amount,      
   Tax       =  abs(@Amount - @Actual_Amount)      
    where ID=@PaymentTBLID                  
             
         
    commit transaction;
  
        
 ------------------ Commented By Develoment only  --------------------    
   
 begin try    
      
 INSERT INTO [CRM].[CRMDB].[dbo].[Payment_Detail_FromKit19]          
    (    
     Kit19_PaymentTBLID,     
     UserID,          
     CustomerName,          
     CustomerNumber,        
     BillingAddress,        
     ShippingAddress,          
     PlanID,          
     [Status],          
     PaymentDate,          
     CreatedDate,      
 TotalAmount ,                    
    InvoiceNo ,                    
    [Status] ,                    
    PaymentThrough ,          
    PaymentMode ,                    
    BankTransactionId ,                    
    AmountWithoutTax ,       
    Quantity ,                    
    CouponCode ,                    
    DiscountAmount ,                    
   Actual_Amount  ,          
   OldIntBalance,            
   NewIntBalance,      
   Tax   ,              
   ServiceType,    
   PricePerUnit    
   )          
 SELECT     
    ID ,     
    UserID,          
    CustomerName,          
    CustomerNumber,        
    BillingAddress,        
    ShippingAddress,          
    PlanID,          
    [Status],          
    PaymentDate,          
    CreatedDate,      
 TotalAmount ,                    
    InvoiceNo ,                    
    [Status] ,                    
    PaymentThrough ,                    
    PaymentMode ,                    
    BankTransactionId ,                    
    AmountWithoutTax ,       
    Quantity ,                    
    CouponCode ,                    
    DiscountAmount ,                    
   Actual_Amount  ,          
   OldIntBalance,            
   NewIntBalance,      
   Tax ,    
 'Money' as ServiceType,    
 1 as PricePerUnit    
 from Payment_Detail with(nolock)      
 where ID=@PaymentTBLID    
    
   end try     
 begin catch    
    exec usp_insertErrorInfo      
 end catch    
        
        
 SELECT 'Success'      
  

 end

 end try      
  Begin catch      
   
   rollback transaction
   exec usp_InsertErrorInfo      
   
  End catch      
      
      
                     
END 


