 @PaymentTBLID bigint      
AS      
BEGIN    

       Declare @ParentID bigint = (select top 1 ParentID from User_Detail with(nolock) where User_ID = @UserID)
	   Declare @MIDP bigint = (select top 1 M_ID from User_Detail with(nolock) where User_ID = @ParentID)          
  
 DECLARE @Amount         DECIMAL,      
         @Credits        DECIMAL,      
         @UserFilter     VARCHAR(50),      
         @M_ID           BIGINT,      
         @ToM_ID         BIGINT,      
         @Balance1       DECIMAL,      
