 SELECT TOP 1 @Balance1 = cd.Balance      
 FROM   Credit_Details AS cd with(nolock)     
 WHERE 
  --cd.[User_ID] = @UserID      
   cd.[User_ID] = @ParentID      
 ORDER BY      
        cd.Credit_ID DESC          
       
 SELECT TOP 1 @Balance2 = cd.Balance      
 FROM   Credit_Details AS cd with(nolock)     
 WHERE  cd.[User_ID] = 335      
 ORDER BY      
        cd.Credit_ID DESC              
       
       
       
 INSERT INTO AddCreditDetails      
   (      
