     FromDate,      
     ToDate,      
     DateCreated,      
     DateUpdated,      
     EmpUpdated,      
     LastModified,
	 CD_CreatedBy      
   )      
 VALUES      
   (      
     NEWID(),      
     @MIDP,      
     335,      
     @ParentID,      
     0,      
     @Credits,      
     ISNULL(@Balance1, 0) + @Credits,      
     '999999',      
     GETDATE(),      
     GETDATE(),      
     GETDATE(),      
     GETDATE(),      
     GETDATE(),      
     GETDATE(),
	 @UserID      
   )                      
       
       
 INSERT INTO Credit_Details      
   (      
     ID,      
     M_ID,      
     FromUser_ID,      
     [User_ID],      
     Debits,      
