/* ============================================================
   Procedure: [dbo].[usp_UpdatePaymentDetailsAfterSuccess_NEW]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdatePaymentDetailsAfterSuccess_NEW]            
 @UserID bigINT ,            
 @PlanID INT ,            
 @TransactionID VARCHAR(550),            
 @Actual_Amount NUMERIC(18, 2),            
 @Coupon_Code NVARCHAR(100),          
 @PaymentTBLID bigint            
AS            
BEGIN  

    Declare @ParentID bigint = (select top 1 isnull(ParentID,0) from User_Detail with(nolock)  where User_ID = @UserID )
      
   if(not exists(select 1 from addcreditDetails where dbo.ufn_getuserParentID(@UserId) = @ParentID and remarks like '%'+ @TransactionID +'%' and  createddate > dateadd(HH,-4,getdate())))
      begin
              
       Declare @MIDP bigint = (select top 1 isnull(M_ID,0) from User_Detail with(nolock)  where User_ID = @ParentID )            
            
 DECLARE @Amount         DECIMAL,            
         @Credits        DECIMAL,            
         @UserFilter     VARCHAR(50),            
         @M_ID           BIGINT,            
         @ToM_ID         BIGINT,            
         @Balance1       DECIMAL,            
         @Balance2       DECIMAL ,      
         @issms          bit,      
         @freesmscredits bigint,      
         @freemailcredits bigint,      
         @ismail  bit    ,      
         @mailBalance1 bigint,      
         @mailBalance2 bigint,    
         @balanceAfterActualCredit1 bigint,    
         @balanceAfterActualCredit2 bigint,    
         @balanceAfterActualMailCredit1 bigint,    
         @balanceAfterActualMailCredit2 bigint             
     
 SELECT top 1 @UserFilter = ud.userfilter,@m_ID = ud.M_ID FROM   User_Detail AS ud (nolock) WHERE  ud.[User_ID] = @ParentID      
  SELECT @ToM_ID = ud.M_ID FROM   User_Detail AS ud WHERE  ud.[User_ID] = '335'                            
 SELECT @Amount = Price,@Credits= Quantity,@issms=issms ,@ismail=ismail FROM PlanMaster(nolock) WHERE  ID           = @PlanID          SELECT TOP 1 @Balance1 = cd.Balance FROM   Credit_Details AS cd (nolock) WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC    
 SELECT TOP 1 @Balance2 = cd.Balance FROM   Credit_Details AS cd WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC    
 SELECT TOP 1 @mailBalance1 = isnull(cd.Balance,0) FROM mailCreditDetails AS cd WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC    
 SELECT TOP 1 @mailBalance2 = cd.Balance FROM mailCreditDetails AS cd WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC                    
       
if @issms=1 and @ismail=0      
begin           
select @freesmscredits = case when issmscredit=1 then SMSCredits else SMSCredits*@Credits/100 end ,@freemailcredits=case when IsMailCredit =1 then MailCredits else 0 end       
from M_Coupon where CouponCode=@coupon_code      
      
 INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,issms,ismail,ACD_CreatedBy)            
VALUES(@ParentID,@UserFilter,'Unlimited',@Amount,@Credits,'NR','10','Purchase','Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,CAST(@Amount / @Credits AS DECIMAL(18, 4)),GETDATE(),1,0,@UserID)     
             
INSERT INTO Credit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,  DateUpdated,EmpUpdated,LastModified,CD_CreatedBy)            
VALUES(NEWID(),@MIDP,335,@ParentID,0,@Credits,ISNULL(@Balance1, 0) + @Credits,'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)                            
             
INSERT INTO Credit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,CD_CreatedBy)            
VALUES(NEWID(),@ToM_ID,@ParentID,335,@Credits,0,ISNULL(@Balance2, 0) -(@Credits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)       
end    
    
if @issms=0 and @ismail=1      
begin           
select @freesmscredits = case when issmscredit=1 then SMSCredits else 0 end,@freemailcredits=case when IsMailCredit =1 then MailCredits else MailCredits*@Credits/100 end from M_Coupon where CouponCode=@coupon_code      
      
INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,issms,ismail,ACD_CreatedBy)            
VALUES(@ParentID,@UserFilter,'Unlimited',@Amount,@Credits,'NR','10','Purchase','Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,CAST(@Amount / @Credits AS DECIMAL(18, 4)),GETDATE(),0,1,@UserID)     
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,  DateUpdated,EmpUpdated,LastModified,CreatedBy)            
VALUES(NEWID(),@MIDP,335,@ParentID,0,@Credits,ISNULL(@mailBalance1, 0) + @Credits,'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)                            
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,CreatedBy)            
VALUES(NEWID(),@ToM_ID,@ParentID,335,@Credits,0,ISNULL(@mailBalance2, 0) -(@Credits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)       
    
end    
    
    
SELECT TOP 1 @balanceAfterActualCredit1 = cd.Balance FROM   Credit_Details AS cd with(nolock) WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC    
SELECT TOP 1 @balanceAfterActualCredit2 = cd.Balance FROM   Credit_Details AS cd with(nolock) WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC    
SELECT TOP 1 @balanceAfterActualMailCredit1 = isnull(cd.Balance,0) FROM mailCreditDetails AS cd with(nolock) WHERE  cd.[User_ID] = @ParentID ORDER BY cd.Credit_ID DESC    
SELECT TOP 1 @balanceAfterActualMAilCredit2 = cd.Balance FROM mailCreditDetails AS cd with(nolock) WHERE  cd.[User_ID] = 335 ORDER BY cd.Credit_ID DESC        
    
    
if isnull(@freesmscredits,0)<>0    
begin    
INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,issms,ismail,ACD_CreatedBy)            
VALUES(@ParentID,@UserFilter,'Unlimited',0,@freesmscredits,'NR','10','Other','Free Coupon ' +@Coupon_Code + ' credits against Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,0,GETDATE(),1,0,@UserID)        
    
INSERT INTO Credit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,  DateUpdated,EmpUpdated,LastModified,CD_CreatedBy)            
VALUES(NEWID(),@MIDP,335,@ParentID,0,@freesmscredits,ISNULL(@balanceAfterActualCredit1, 0) + @freesmscredits,'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)                            
             
INSERT INTO Credit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,CD_CreatedBy)            
VALUES(NEWID(),@ToM_ID,@ParentID,335,@freesmscredits,0,ISNULL(@balanceAfterActualCredit2, 0) -(@freesmscredits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)                         
end    
            
if isnull(@freemailcredits,0)<>0  and (@UserFilter='MTIX_TR' or @UserFilter='Critical')    
begin      
INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,IsMail,ACD_CreatedBy)            
VALUES(@ParentID,@UserFilter,'Unlimited',0,@freemailcredits,'NR','10','Other','Free Coupon ' +@Coupon_Code + ' credits against Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,0,GETDATE(),1,@UserID)                          
  
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,CreatedBy)            
VALUES(NEWID(),@MIDP,335,@ParentID,0,@freemailcredits,ISNULL(@balanceAfterActualMailCredit1, 0) + @freemailCredits,'999999',0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)                            
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified,CreatedBy)            
VALUES(NEWID(),@ToM_ID,@ParentID,335,@freemailCredits,0,ISNULL(@balanceAfterActualMailCredit2, 0) -(@freemailcredits),'999999',0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),@UserID)          
end      
else    
begin    
set @freemailcredits=0    
end    
    
    
if @issms=1    
begin    
update Payment_Detail          
    set           
    TotalAmount = @Amount,            
    InvoiceNo = NEWID(),            
    [Status] = 'Success',            
    PaymentThrough = 1,            
    PaymentMode = 'RazorPay',            
    BankTransactionId = @TransactionID,            
    AmountWithoutTax = @Actual_Amount,            
    Quantity = @Credits,            
    CouponCode = @Coupon_Code,            
    DiscountAmount =  CASE             
            WHEN @Coupon_Code <> '' THEN (            
                    SELECT TOP 1 mc.Discount            
                      FROM   M_Coupon AS mc            
                    WHERE  mc.CouponCode = @Coupon_Code            
                 )            
           ELSE NULL            
       END ,            
    OldSmsBalance = ISNULL(@Balance1, 0),            
    NewSmsBalance = ISNULL(@Balance1, 0) + @Credits + isnull(@freesmscredits,0),     
    OldMailBalance = ISNULL(@mailBalance1, 0),    
    NewMailBalance = ISNULL(@mailBalance1, 0) + isnull(@freemailcredits,0),        
    Actual_Amount = @Actual_Amount ,
	Tax = abs(@Amount - @Actual_Amount )
    where ID=@PaymentTBLID          
 end            
if @ismail=1    
begin    
update Payment_Detail          
    set           
    TotalAmount = @Amount,            
    InvoiceNo = NEWID(),            
    [Status] = 'Success',            
    PaymentThrough = 1,            
    PaymentMode = 'RazorPay',            
    BankTransactionId = @TransactionID,            
    AmountWithoutTax = @Actual_Amount,            
    Quantity = @Credits,            
    CouponCode = @Coupon_Code,            
    DiscountAmount =  CASE             
            WHEN @Coupon_Code <> '' THEN (            
                    SELECT TOP 1 mc.Discount            
                      FROM   M_Coupon AS mc            
                    WHERE  mc.CouponCode = @Coupon_Code            
                 )            
           ELSE NULL            
       END ,            
    OldSmsBalance = ISNULL(@Balance1, 0),            
    NewSmsBalance = ISNULL(@Balance1, 0) + isnull(@freesmscredits,0),     
    OldMailBalance = ISNULL(@mailBalance1, 0),    
    NewMailBalance = ISNULL(@mailBalance1, 0) + @Credits + isnull(@freemailcredits,0),        
    Actual_Amount = @Actual_Amount  ,
	Tax = abs(@Amount - @Actual_Amount )
    where ID=@PaymentTBLID          
 end             
   
   begin try
	  
  INSERT INTO [CRM].[CRMDB].[dbo].[Payment_Detail_FromKit19]      
    (
     Kit19_PaymentTBLID, 
     UserID,      
     CustomerName,      
     CustomerNumber,    
     BillingAddress,    
     ShippingAddress,      
     PlanID,      
     [Status],      
     PaymentDate,      
     CreatedDate,  
	TotalAmount ,            
    InvoiceNo,            
    [Status] ,            
    PaymentThrough ,            
    PaymentMode ,            
    BankTransactionId ,            
    AmountWithoutTax ,            
    Quantity  ,            
    CouponCode ,            
    DiscountAmount ,            
    OldSmsBalance ,            
    NewSmsBalance ,     
    OldMailBalance ,    
    NewMailBalance ,        
    Actual_Amount,              
    ServiceType,
	Tax,
	PricePerUnit
   )      
 SELECT 
     ID , 
     UserID,      
     CustomerName,      
     CustomerNumber,    
     BillingAddress,    
     ShippingAddress,      
     PlanID,      
     [Status],      
     PaymentDate,      
     CreatedDate,  
	TotalAmount ,            
    InvoiceNo,            
    [Status] ,            
    PaymentThrough ,            
    PaymentMode ,            
    BankTransactionId ,            
    AmountWithoutTax ,            
    Quantity  ,            
    CouponCode ,            
    DiscountAmount ,            
    OldSmsBalance ,            
    NewSmsBalance ,     
    OldMailBalance ,    
    NewMailBalance ,        
    Actual_Amount,
	(case when @issms=1
	         then  'SMS'
           else 
		    'Mail'
		 end) as ServiceType
	,Tax
	,CAST(@Amount / @Credits AS DECIMAL(18, 4)) as PricePerUnit
	from Payment_Detail with(nolock)  
	where ID=@PaymentTBLID

   end try 
	begin catch
	   exec usp_insertErrorInfo  
	end catch




 SELECT 'Success'            
  end
  else
   begin
         select 'Transaction already processed'
   end 

  END       
      
      
      


GO

