CREATE   PROCEDURE [dbo].[usp_UpdatePaymentDetailsAfterSuccess_NEW1]              
 @UserID INT ,              
 @PlanID INT ,              
 @TransactionID VARCHAR(550),              
 @Actual_Amount NUMERIC(18, 2),              
 @Coupon_Code NVARCHAR(100),            
 @PaymentTBLID bigint ,    
 @PlanType int =0              
AS              
BEGIN 
      Declare @ParentID bigint = ( select top 1 ParentID from User_Detail with(nolock) where User_ID =  @UserID )     
	  Declare @MIDP bigint = ( select top 1 M_ID from User_Detail with(nolock) where User_ID =  @ParentID )     

             
 DECLARE @Amount         DECIMAL,              
         @Credits        DECIMAL,              
         @UserFilter     VARCHAR(50),              
         @M_ID           BIGINT,              
         @ToM_ID         BIGINT,              
         @Balance1       DECIMAL,              
         @Balance2       DECIMAL ,        
         @issms          bit,        
         @freesmscredits bigint,        
         @freemailcredits bigint,        
         @ismail  bit    ,        
         @mailBalance1 bigint,        
         @mailBalance2 bigint,      
         @balanceAfterActualCredit1 bigint,      
         @balanceAfterActualCredit2 bigint,      
         @balanceAfterActualMailCredit1 bigint,      
         @balanceAfterActualMailCredit2 bigint               
       
 SELECT @UserFilter = ud.userfilter,@m_ID = ud.M_ID FROM   User_Detail AS ud with(nolock) WHERE  ud.[User_ID] = @UserID                        
