INSERT INTO Credit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified)            
VALUES(NEWID(),@ToM_ID,@UserID,335,@freesmscredits,0,ISNULL(@balanceAfterActualCredit2, 0) -(@freesmscredits),'999999',GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE())                         
end    
            
if @freemailcredits<>0  and (@UserFilter='MTIX_TR' or @UserFilter='Critical')    
begin      
INSERT INTO AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,CreatedDate,IsMail)            
VALUES(@UserID,@UserFilter,'Unlimited',0,@freemailcredits,'NR','10','Other','Free Coupon ' +@Coupon_Code + ' credits against Bank Transaction ID :' + @TransactionID +' ,  Payment Done By : Razor Pay ',335,0,GETDATE(),1)                            
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified)            
VALUES(NEWID(),@M_ID,335,@UserID,0,@freemailcredits,ISNULL(@balanceAfterActualMailCredit1, 0) + @freemailCredits,'999999',0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE())                            
             
INSERT INTO MailcreditDetails(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,LastModified)            
VALUES(NEWID(),@ToM_ID,@UserID,335,@freemailCredits,0,ISNULL(@balanceAfterActualMailCredit2, 0) -(@freemailcredits),'999999',0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE()  )          
end      
else    
begin    
set @freemailcredits=0    
end    
    
    
if @issms=1    
begin    
update Payment_Detail          
    set           
    TotalAmount = @Amount,            
    InvoiceNo = NEWID(),            
    [Status] = 'Success',            
    PaymentThrough = 1,            
    PaymentMode = 'RazorPay',            
    BankTransactionId = @TransactionID,            
    AmountWithoutTax = @Actual_Amount,            
    Quantity = @Credits,            
    CouponCode = @Coupon_Code,            
    DiscountAmount =  CASE             
            WHEN @Coupon_Code <> '' THEN (            
                    SELECT TOP 1 mc.Discount            
                      FROM   M_Coupon AS mc            
                    WHERE  mc.CouponCode = @Coupon_Code            
                 )            
           ELSE NULL            
       END ,            
    OldSmsBalance = ISNULL(@Balance1, 0),            
    NewSmsBalance = ISNULL(@Balance1, 0) + @Credits + @freesmscredits,     
    OldMailBalance = ISNULL(@mailBalance1, 0),    
    NewMailBalance = ISNULL(@mailBalance1, 0) + @freemailcredits,        
    Actual_Amount = @Actual_Amount              
    where ID=@PaymentTBLID          
 end            
if @ismail=1    
begin    
update Payment_Detail          
    set           
    TotalAmount = @Amount,            
    InvoiceNo = NEWID(),            
    [Status] = 'Success',            
    PaymentThrough = 1,            
    PaymentMode = 'RazorPay',            
    BankTransactionId = @TransactionID,            
    AmountWithoutTax = @Actual_Amount,            
    Quantity = @Credits,            
    CouponCode = @Coupon_Code,            
    DiscountAmount =  CASE             
            WHEN @Coupon_Code <> '' THEN (            
                    SELECT TOP 1 mc.Discount            
                      FROM   M_Coupon AS mc            
                    WHERE  mc.CouponCode = @Coupon_Code            
                 )            
           ELSE NULL            
       END ,            
    OldSmsBalance = ISNULL(@Balance1, 0),            
    NewSmsBalance = ISNULL(@Balance1, 0) + @freesmscredits,     
    OldMailBalance = ISNULL(@mailBalance1, 0),    
    NewMailBalance = ISNULL(@mailBalance1, 0) + @freemailcredits,        
    Actual_Amount = @Actual_Amount              
    where ID=@PaymentTBLID          
 end             
             
 SELECT 'Success'            
  END       
      
      
      


GO

