declare @isamount int=(select isamount from Referrer_Payout_Rates where ID=@commissionid)  
declare @commissionamount numeric(18,2)=(select case when isamount=1 then CommissionAmount else (CommissionPercent*@Amount/100) end from Referrer_Payout_Rates where ID=@commissionid)  
insert into PayoutTracking(Referrerid,Commissionid,ReferredContactId,CommissionAmount,DateCreated,Status)  
select @referrerid,@commissionid,@referredContactid,@commissionamount,GETDATE(),'Payout Tracked'  
exec usp_UpdateUserActivity @referrerid,'PayoutTracked',0  
end  
end              
         
 INSERT INTO Credit_Details        
