/* ============================================================
   Procedure: [dbo].[Usp_UpdatePipeline]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdatePipeline (        
 @PipelineID BIGINT        
 ,@PipelineName NVARCHAR(500)        
 ,@DealExpiry INT        
 ,@IsDefault BIT        
 ,@ParentID BIGINT        
 ,@CreatedBy BIGINT        
 ,        
 --@Owner bigint,            
 @tbl [pipelineTbl_type_ForUpdate] readonly        
 ,@tblLostRe pipelinelostreasonTbl_types readonly        
 )        
AS        
BEGIN        
 -- declare @PipeLineID bigint = 0;            
 IF (        
   NOT EXISTS (        
    SELECT 1        
    FROM Pipeline_Master        
    WHERE ParentID = @ParentID        
     AND Name = @PipelineName        
     AND ID <> @PipelineID  and IsDeleted = 0      
    )        
   )        
 BEGIN        
  IF (@IsDefault = 1)        
  BEGIN        
   UPDATE Pipeline_Master        
   SET IsDefault = 0        
   WHERE ID <> @PipeLineID        
        
   UPDATE Pipeline_Master        
   SET IsDefault = 1        
   WHERE ID = @PipelineID        
  END        
        
  UPDATE Pipeline_Master        
  SET Name = @PipelineName        
   ,DealExpiry = @DealExpiry        
   ,@IsDefault = @IsDefault        
  WHERE ID = @PipelineID        
        
  SELECT ROW_NUMBER() OVER (        
    ORDER BY [StageID] ASC        
    ) row_num        
   ,[Name]        
   ,[Probability]        
   ,[Sequence]        
   ,[IsDefault]        
   ,[IsEditable]        
   ,[StageID]        
  INTO #tempOldStage        
  FROM @tbl        
  WHERE isnull(StageID, 0) <> 0        
        
  SELECT ROW_NUMBER() OVER (        
    ORDER BY [StageID] ASC        
    ) row_num        
   ,[Name]        
   ,[Probability]        
   ,[Sequence]        
   ,[IsDefault]        
   ,[IsEditable]        
   ,[StageID]        
  INTO #tempNewStage        
  FROM @tbl        
  WHERE isnull(StageID, 0) = 0        
        
  DECLARE @CountOldStage INT = 1;        
  DECLARE @CountNewStage INT = 1;        
  DECLARE @TotalCountOldStage INT = 1;        
  DECLARE @TotalCountNewStage INT = 1;        
  DECLARE @StageID_Var BIGINT = 0;        
        
  SELECT @TotalCountOldStage = ISNULL(Count(1), 0)        
  FROM #tempOldStage;        
        
  SELECT @TotalCountNewStage = isnull(Count(1), 0)        
  FROM #tempNewStage;        
        
  WHILE (@CountOldStage <= @TotalCountOldStage)        
  BEGIN        
   DECLARE @Name_var NVARCHAR(500) = ''        
   DECLARE @Probability_var NUMERIC(5, 2) = 0        
   DECLARE @Sequence_var INT = 0        
   DECLARE @IsDefault_var BIT = 0        
   DECLARE @IsEditable_var BIT = 0        
        
   SELECT @StageID_Var = isnull(StageID, 0)        
    ,@Name_var = isnull(Name, '')        
    ,@Probability_var = isnull(Probability, 0)        
    ,@Sequence_var = isnull(Sequence, 0)        
    ,@IsDefault_var = isnull(IsDefault, 0)        
    ,@IsEditable_var = isnull(IsEditable, 0)        
   FROM #tempOldStage        
   WHERE row_num = @CountOldStage        
        
   UPDATE PipelineStages        
   SET [Name] = @Name_var        
    ,[Probability] = @Probability_var        
    ,[Sequence] = @Sequence_var        
    ,[IsDefault] = @IsDefault_var        
    ,[IsEditable] = @IsEditable_var        
   WHERE ID = @StageID_Var        
        
   SET @CountOldStage = @CountOldStage + 1        
  END        
        
  UPDATE PipelineStages        
  SET IsDeleted = 1        
   ,DeletedDate = getdate()        
  WHERE PipelineID = @PipelineID        
   AND id NOT IN (        
    SELECT isnull(StageID, 0)        
    FROM #tempOldStage        
    )   and isnull(isdeleted,0)<>1     
        
  WHILE (@CountNewStage <= @TotalCountNewStage)        
  BEGIN        
   INSERT INTO PipelineStages (        
    [PipelineID]        
    ,[Name]        
    ,[Probability]        
    ,[CreatedDate]        
    ,[Createdby]        
    ,[IsDefault]        
    ,[IsDeleted]        
    ,[Sequence]        
    ,[IsEditable]        
    ,[DeletedDate]        
    )        
   SELECT @PipelineID        
    ,[Name]        
    ,Probability        
    ,getdate()        
    ,@CreatedBy        
    ,IsDefault        
    ,0        
    ,[Sequence]        
    ,IsEditable        
    ,NULL        
   FROM #tempNewStage        
   WHERE row_num = @CountNewStage        
        
   SET @CountNewStage = @CountNewStage + 1        
  END        
        
  DROP TABLE #tempOldStage        
        
  DROP TABLE #tempNewStage        
        
  --Stage Lost reason        
  SELECT ROW_NUMBER() OVER (        
    ORDER BY [ID] ASC        
    ) row_num        
   ,[ID]        
   ,[Reason]        
  INTO #tempOldLostReason        
  FROM @tblLostRe        
  WHERE isnull(ID, 0) <> 0        
        
  SELECT ROW_NUMBER() OVER (        
    ORDER BY [ID] ASC        
    ) row_num        
   ,[ID]        
   ,[Reason]        
  INTO #tempNewLostReason        
  FROM @tblLostRe        
  WHERE isnull(ID, 0) = 0        
        
  DECLARE @CountOldLostReason INT = 1;        
  DECLARE @CountNewLostReason INT = 1;        
  DECLARE @TotalCountOldLostReason INT = 1;        
  DECLARE @TotalCountNewLostReason INT = 1;        
  DECLARE @ID_Var BIGINT = 0;        
        
  SELECT @TotalCountOldLostReason = ISNULL(Count(1), 0)        
  FROM #tempOldLostReason;        
        
  SELECT @TotalCountNewLostReason = isnull(Count(1), 0)        
  FROM #tempNewLostReason;        
        
  WHILE (@CountOldLostReason <= @TotalCountOldLostReason)        
  BEGIN        
   DECLARE @Reason_var NVARCHAR(150) = ''        
        
   SELECT @ID_Var = isnull(ID, 0)        
    ,@Reason_var = isnull(Reason, '')        
   FROM #tempOldLostReason        
   WHERE row_num = @CountOldLostReason        
        
   UPDATE PipelineStages_Reason        
   SET [Reason] = @Reason_var        
   WHERE ID = @ID_Var        
        
   SET @CountOldLostReason = @CountOldLostReason + 1        
  END        
        
  UPDATE PipelineStages_Reason        
  SET IsActive = 0        
   ,ModifiedDate = getdate()        
   ,ModifiedBy = @ParentID        
  WHERE PipelineID = @PipelineID        
   AND id NOT IN (        
    SELECT isnull(ID, 0)        
    FROM #tempOldLostReason        
    )        
        
  WHILE (@CountNewLostReason <= @TotalCountNewLostReason)        
  BEGIN        
   INSERT INTO PipelineStages_Reason (        
    [PipelineID]        
    ,[Reason]        
    ,[ParentID]        
    ,[IsActive]        
    ,[CreatedDate]        
    ,[Createdby]        
    )        
   SELECT @PipeLineID        
    ,Reason        
    ,@ParentID        
    ,1        
    ,getdate()        
    ,@ParentID        
   FROM #tempNewLostReason        
   WHERE row_num = @CountNewLostReason        
        
   SET @CountNewLostReason = @CountNewLostReason + 1        
  END        
        
  SELECT 'Record Updated'        
 END        
 ELSE        
 BEGIN        
  SELECT 'Pipeline already exists'        
 END        
        
 DECLARE @rowJson NVARCHAR(MAX) = (        
   SELECT *        
   FROM Pipeline_Master        
   WHERE ID = @PipelineID        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )        
        
 IF @rowJson IS NOT NULL        
 BEGIN        
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy        
   ,@Activity_type = 'Updt_PipelnStge'        
   ,@ActionType = 'U'        
   ,@RowJson = @rowJson        
   ,@Table_name = 'Pipeline_Master'        
 END        
END 


GO

