/* ============================================================
   Procedure: [dbo].[usp_UpdatePlanMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


       
CREATE   PROCEDURE [dbo].[usp_UpdatePlanMaster]
	@ID BIGINT,
	@PlanName VARCHAR(100),
	@Price DECIMAL,
	@IsActive BIT,
	@CreatedBy BIGINT,
	@UserFilter VARCHAR(50),
	@PlanDescription VARCHAR(750),
	@Quantity BIGINT,
	@IsSMS BIT,
	@ISMail BIT
AS
BEGIN
	IF NOT EXISTS (
	       SELECT 'x'
	       FROM   PlanMaster
	       WHERE  PlanName           = @PlanName
	              AND UserFilter     = @UserFilter
	              AND ID <> @ID
	   )
	BEGIN
	    UPDATE PlanMaster
	    SET    -- ID = ? -- this column value is auto-generated          
	           PlanName = @PlanName,
	           Price = @Price,
	           PlanDescription = @PlanDescription,
	           IsActive = @IsActive,
	           ModifiedOn = GETDATE(),
	           ModifiedBy = @CreatedBy,
	           UserFilter = @UserFilter,
	           Quantity = @Quantity,
	           IsSMS = @IsSMS,
	           ISMail = @ISMail
	    WHERE  ID = @ID          
	    
	    SELECT 'Record Updated'
	END
	ELSE
	BEGIN
	    SELECT 'Already Exists'
	END
END



