SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_UpdatePostRequestQueueLogError
    @Id BIGINT,
    @ErrorMessage NVARCHAR(MAX),
    @ErrorDate DATETIME
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE tbl_Ai_PostRequestLog
    SET 
        ErrorMessage = @ErrorMessage,
        ProcessedAt = @ErrorDate,
        IsProcessed = 0 -- keep unprocessed, but mark error
    WHERE Id = @Id;
END


