CREATE   PROCEDURE dbo.Usp_UpdatePreDefinedUserCampaignMaster                            
(                            
@ParentID Bigint,                            
@PageName varchar(200),                            
@SmsMessage nvarchar(200),                        
@IsUniCode bit,                        
@EmailReplyTo nvarchar(100),                        
@EmailSubject nvarchar(100),                        
@EmailMessgae nvarchar(200),                        
                        
@SmsSenderName nvarchar(100),                        
@IsSms bit,                         
@IsEmail bit,                      
@SmsAccountName nvarchar(100),                      
@EmailAccountName nvarchar(100),      
@SMStemplateid bigint,      
@Mailtemplateid bigint             
)              
as            
--Begin      
    
        
declare @C_uid bigint    
declare @SmsCampaignId bigint    
declare @EmailCampaignId bigint    
declare @PageName22  varchar(200)   
set @PageName22 = @PageName                              
 select @C_uid = User_ID, @SmsCampaignId = SmsCampaignId,    
 @EmailCampaignId= EmailCampaignId  from ClientPageDetail where PageName = @PageName              
set @PageName = 'Microsite-'+@PageName              
                             
 BEGIN                         
 if(@IsSms !='' )                        
 begin    
  if (@SmsCampaignId > 0)  
  begin                   
   Update UserCampaignMaster set                            
   IsEventBased=1,IsScheduled=0,                          
   ExclusionsNumber='', Exclusions='',InclusionsNumber='',AccountUsed=@SmsAccountName,                         
   SenderID=@SmsSenderName,                            
   [Message]=@SmsMessage, TemplateID=case when     
   isnull(@smstemplateid,0)<>0 then @smstemplateid else 0 end, TemplateGroupID=0,     
   IsUnicode=@IsUniCode,Medium='SMS',                        
   TrackResponse='',TrackShortURL='',                        
   UnsubscribePage='',UnsubscribeShortURL='',Tags='',IsRunAfter=0,                        
   IsSchedule=0, ScheduleID=0,ExecutedDateTime=GETDATE(),NextExecuteDateTime=GETDATE(),                        
   IsActive=1,CreatedOn=GETDATE(),Createdby=@C_uid,ModifiedOn=GETDATE(),ModifiedBy=0,StartDate=GETDATE()-1,                        
   ExpiryDate=GETDATE(),EventsName='ENQADD',ApplicabiltyGroupList='',ExclusionsGroupList='',                        
   NotificationMail='',SuccessNotificationEmail='',FailureNotificationEmail='',                        
   IsRecurring=0, IsEnding=0, TemplateGroupSequence=0, IsNeverExpire=1,    
   RunAtHours='',RunAtMin='',IsSurplusExclusions=0 where ID = @SmsCampaignId  
  -- ParentID=@ParentID and CampaignName=@PageName    
  --and Medium='SMS'   
  end    
else    
 begin  
  insert into UserCampaignMaster    
  (IsEventBased,IsScheduled,                          
  ExclusionsNumber, Exclusions,InclusionsNumber,AccountUsed,SenderID,                            
  [Message], TemplateID, TemplateGroupID,IsUnicode,Medium,TrackResponse    
  ,TrackShortURL,UnsubscribePage,UnsubscribeShortURL,Tags,IsRunAfter,IsSchedule,    
   ScheduleID,ExecutedDateTime,NextExecuteDateTime,IsActive,CreatedOn,    
   Createdby,ModifiedOn,ModifiedBy,StartDate,ExpiryDate,EventsName,    
       
   ApplicabiltyGroupList,ExclusionsGroupList,NotificationMail,SuccessNotificationEmail,    
   FailureNotificationEmail,IsRecurring, IsEnding, TemplateGroupSequence, IsNeverExpire,    
   RunAtHours,RunAtMin,IsSurplusExclusions,ParentID,CampaignName)     
  select 1,0,    
  '', '','',@SmsAccountName,@SmsSenderName,    
  @SmsMessage,    
  case when isnull(@smstemplateid,0)<>0 then @smstemplateid else 0 end,0,@IsUniCode,'SMS',                        
  '',    
  '','','','',0,0,    
  0,GETDATE(),GETDATE(),1,GETDATE(),    
  @C_uid,GETDATE(),    
  0,GETDATE()-1,GETDATE(),'ENQADD',    
  '','','','',    
  '',0,0, 0,1,    
  '','',0, @ParentID, @PageName  
 update ClientPageDetail set SmsCampaignId=scope_identity() where PageName = @PageName22   
 end                 
end    
else    
begin    
if (@SmsCampaignId > 0)    
 Update UserCampaignMaster set IsActive=0  where  ID = @SmsCampaignId  
 --@ParentID and CampaignName=@PageName   and Medium='SMS'       
end                        
if(@IsEmail! = '')                        
 begin                        
  if (@EmailCampaignId > 0)  
   begin                   
   update UserCampaignMaster set                            
  ParentID=@ParentID, CampaignName=@PageName, IsEventBased=1,IsScheduled=0,                          
  ExclusionsNumber='', Exclusions='',InclusionsNumber='',AccountUsed=@EmailAccountName,                         
   TemplateID =ISNULL(@mailtemplateid,0), TemplateGroupID=0, IsUnicode=0,Medium='Mail',                        
  MailReplyTo=@EmailReplyTo,MailSubject=@EmailSubject,  
   MailContent=case when isnull(@mailtemplateid,0)=0 then @EmailMessgae else '' end,  
   TrackResponse='',TrackShortURL='',                       
  UnsubscribePage='',UnsubscribeShortURL='',Tags='',IsRunAfter=0,                        
   IsSchedule=0, ScheduleID=0,NextExecuteDateTime=GETDATE(),                        
   IsActive=1,CreatedOn=GETDATE(),Createdby=@ParentID,ModifiedOn=GETDATE(),  
   ModifiedBy=@ParentID,StartDate=GETDATE()-1,                        
   ExpiryDate=GETDATE(),EventsName='ENQADD',ApplicabiltyGroupList='',ExclusionsGroupList='',                        
   NotificationMail='',SuccessNotificationEmail='',FailureNotificationEmail='',                        
   IsRecurring=0, IsEnding=0, TemplateGroupSequence=0, IsNeverExpire=1,                             
  RunAtHours='',RunAtMin='',IsSurplusExclusions=0   
  where  ID= @EmailCampaignId  
  
  end  
  --ParentID=@ParentID and CampaignName=@PageName and Medium='Mail'              
 else   
  begin  
  insert into UserCampaignMaster(                            
  ParentID, CampaignName, IsEventBased,IsScheduled,                          
  ExclusionsNumber, Exclusions,InclusionsNumber,AccountUsed,                         
   TemplateID, TemplateGroupID, IsUnicode,Medium,                        
  MailReplyTo,MailSubject,MailContent,TrackResponse,TrackShortURL,                        
  UnsubscribePage,UnsubscribeShortURL,Tags,IsRunAfter,                        
   IsSchedule, ScheduleID,ExecutedDateTime,NextExecuteDateTime,                        
   IsActive,CreatedOn,Createdby,ModifiedOn,ModifiedBy,StartDate,                        
   ExpiryDate,EventsName,ApplicabiltyGroupList,ExclusionsGroupList,                        
   NotificationMail,SuccessNotificationEmail,FailureNotificationEmail,                        
   IsRecurring, IsEnding, TemplateGroupSequence, IsNeverExpire,                             
  RunAtHours,RunAtMin,IsSurplusExclusions                            
  )                            
  values                            
  (                            
   @ParentID,@PageName,1,0,                        
   '','','',@EmailAccountName                        
   ,case when ISNULL(@mailtemplateid,0)<>0 then @Mailtemplateid else 0 end,0,0,                        
  'Mail',@EmailReplyTo,@EmailSubject,case when isnull(@mailtemplateid,0)=0 then @EmailMessgae else '' end,        
   '','','','','',0,0,                        
   0,NULL,GETDATE(),1,GETDATE(),@ParentID ,                        
   GETDATE(),@ParentID,GETDATE()-1,GETDATE(),'ENQADD','','','',                        
   '','',0,0,0,1,'','',0     
  )  
  
  update ClientPageDetail set EmailCampaignId=scope_identity() where PageName = @PageName22     
  end  
  ----   insert into UserCampaignMaster    
  ----(ParentID, CampaignName, IsEventBased,IsScheduled,ExclusionsNumber, Exclusions,InclusionsNumber    
  ----,AccountUsed,TemplateID, TemplateGroupID, IsUnicode,Medium,MailReplyTo,MailSubject,    
  ----MailContent,TrackResponse,TrackShortURL,UnsubscribePage,UnsubscribeShortURL,Tags,IsRunAfter,    
  ----IsSchedule, ScheduleID,ExecutedDateTime,NextExecuteDateTime,IsActive,CreatedOn,Createdby,    
  ----ModifiedOn,ModifiedBy,StartDate,ExpiryDate,EventsName,ApplicabiltyGroupList,ExclusionsGroupList,    
  ----NotificationMail,SuccessNotificationEmail,FailureNotificationEmail, IsRecurring,    
  ----IsEnding, TemplateGroupSequence, IsNeverExpire,RunAtHours,RunAtMin,IsSurplusExclusions)    
  ----select @ParentID,@PageName,1,0,'', '','',@EmailAccountName,    
  ----case when isnull(@mailtemplateid,0)=0 then @EmailMessgae else '' end,0,@IsUniCode,'Mail',    
  ----@EmailReplyTo,@EmailSubject,@EmailMessgae,'','','','','',0,0, 0,GETDATE(),GETDATE(),                        
  ----1,GETDATE(),@C_uid,GETDATE(),0,GETDATE()-1,GETDATE(),'','','','','','',0,0,0,1,                             
  ----'','',0   
              
 end    
else    
begin    
if (@EmailCampaignId > 0)    
 Update UserCampaignMaster set IsActive=0  where  ID = @EmailCampaignId  
 --ParentID=@ParentID and CampaignName=@PageName    
 --and Medium='SMS'       
end   
                        
select 'Success'                            
END 


