CREATE   PROC [dbo].[Usp_UpdatePreEnquiryDetailsToSearchDetails] 
(
    @ID BIGINT,
    @SearchName VARCHAR(250),
    @PreEnquirySelectStatusName VARCHAR(MAX),
    @PreEnquirySelectStatusIsLastStatus BIT,
    @PreEnquirySelectService VARCHAR(MAX),
    @PreEnquirySelectExecutive VARCHAR(MAX),
    @PreEnquirySelectExecutiveIsLast BIT,
    @PreEnquirySelectLeadStatus VARCHAR(MAX),
    @PreEnquirySelectLeadStatusIsLastStatus BIT,
    @IsActive BIT,
    @IsEnrolled BIT,
    @SpecificDatesFrom VARCHAR(50),
    @SpecificDateTo VARCHAR(50),
    @SpecificDaysFrom VARCHAR(50),
    @SpecificDaysTo VARCHAR(50),
    @TotalBusinessFrom NUMERIC(18, 0),
    @TotalBusinessTo NUMERIC(18, 0),
    @SingleBusinessFrom NUMERIC(18, 0),
    @SingleBusinessTo NUMERIC(18, 0),
    @RetentionExecutive VARCHAR(MAX),
    @IsCurrentRetention BIT,
    @EnrollName VARCHAR(50),
    @EnrollCompany VARCHAR(50),
    @EnrollOfficeAddress VARCHAR(50),
    @EnrollResidenceAddress VARCHAR(50),
    @State VARCHAR(50),
    @City VARCHAR(50),
    @PinCode VARCHAR(50),
    @EnrollMobile VARCHAR(50),
    @EnrollEmailID VARCHAR(50),
    @IsSpecificCheck BIT,
    @IsEnrollCheck BIT,
    @IsFollowUpCheck BIT,
    @IsRetentionCheck BIT,
    @EnrollExecutive NVARCHAR(MAX),
    @CreatedBy BIGINT,
    @EnquiryDateDaysFrom INT,
    @EnquiryDateDaysTo INT,
    @NextStatusDateDaysFrom INT,
    @NextStatusDateDaysTo INT
)              
AS               
BEGIN
	UPDATE SearchDetails
	SET    SearchName = @SearchName,
	       PreEnquirySelectStatusName = @PreEnquirySelectStatusName,
	       PreEnquirySelectStatusIsLastStatus = @PreEnquirySelectStatusIsLastStatus,
	       PreEnquirySelectService = @PreEnquirySelectService,
	       PreEnquirySelectExecutive = @PreEnquirySelectExecutive,
	       PreEnquirySelectExecutiveIsLast = @PreEnquirySelectExecutiveIsLast,
	       PreEnquirySelectLeadStatus = @PreEnquirySelectLeadStatus,
	       PreEnquirySelectLeadStatusIsLastStatus = @PreEnquirySelectLeadStatusIsLastStatus,
	       IsActive = @IsActive,
	       IsEnrolled = @IsEnrolled,
	       SpecificDatesFrom = @SpecificDatesFrom,
	       SpecificDateTo = @SpecificDateTo,
	       SpecificDaysFrom = @SpecificDaysFrom,
	       SpecificDaysTo = @SpecificDaysTo,
	       TotalBusinessFrom = @TotalBusinessFrom,
	       TotalBusinessTo = @TotalBusinessTo,
	       SingleBusinessFrom = @SingleBusinessFrom,
	       SingleBusinessTo = @SingleBusinessTo,
	       RetentionExecutive = @RetentionExecutive,
	       IsCurrentRetention = @IsCurrentRetention,
	       EnrollName = @EnrollName,
	       EnrollCompany = @EnrollCompany,
	       EnrollOfficeAddress = @EnrollOfficeAddress,
	       EnrollResidenceAddress = @EnrollResidenceAddress,
	       STATE = @State,
	       City = @City,
	       PinCode = @PinCode,
	       EnrollMobile = @EnrollMobile,
	       EnrollEmailID = @EnrollEmailID,
	       IsSpecificCheck = @IsSpecificCheck,
	       IsEnrollCheck = @IsEnrollCheck,
	       IsFollowUpCheck = @IsFollowUpCheck,
	       IsRetentionCheck = @IsRetentionCheck,
	       EnrollExecutive = @EnrollExecutive,
	       EnquiryDateDaysFrom = @EnquiryDateDaysFrom,
	       EnquiryDateDaysTo = @EnquiryDateDaysTo,
	       NextStatusDateDaysFrom = @NextStatusDateDaysFrom,
	       NextStatusDateDaysTo = @NextStatusDateDaysTo
	WHERE  ID = @ID            
	
	SELECT 'Record Updated'
END   


