/* ============================================================
   Procedure: [dbo].[usp_updatepriority]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_updatepriority] --'messagequeue','1572643','Start'          
@tablename varchar(100),          
@batchid varchar(30),          
@status varchar(30)          
as          
declare @priority char(5)          
if @status='Pause'          
begin          
set @priority='7'          
end          
else          
begin          
set @priority='0'          
end          
declare @sql varchar(max)      
if @tablename<>'ALL TABLE'      
begin          
set @sql='update '+@tablename+' set priority='+@priority+' where batchid='+@batchid+''          
end      
else      
begin      
update messagequeue set priority=@priority where batchid=@batchid      
update messagequeuetwo set priority=@priority where batchid=@batchid      
update messagequeuethree set priority=@priority where batchid=@batchid      
update messagequeuefour set priority=@priority where batchid=@batchid      
update messagequeueairtel set priority=@priority where batchid=@batchid      
update messagequeueairteltwo set priority=@priority where batchid=@batchid      
update messagequeueairtelthree set priority=@priority where batchid=@batchid      
update messagequeueairtelpri set priority=@priority where batchid=@batchid     
update MessageQueueVoda set priority=@priority where batchid=@batchid     
end      
exec(@sql)



GO

