   Procedure: [dbo].[Usp_UpdateProductDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_UpdateProductDetails]  --178,'abcerwe','','Desc',10,'',335,335,'',''  
 @ProductID BIGINT,    
 @Name NVARCHAR(100),    
 @Image NVARCHAR(100),    
 @Description NVARCHAR(200),    
 @Price NUMERIC(18, 2),    
 @IsPublished BIT,    
 @UserID INT,    
 @CreatedBy BIGINT,    
 @FullPath VARCHAR(MAX),    
 @IsFeatured BIT    
AS    
BEGIN    
 IF (EXISTS (SELECT 'x' FROM   ProductMaster WHERE  NAME= @Name AND UserID= @UserID AND ProductID =@ProductID))    
 BEGIN    
     UPDATE ProductMaster    
     SET    NAME = @Name,    
            [Image] = @Image,    
            [Description] = @Description,    
            Price = @Price,    
            IsPublished = @IsPublished,    
            UserID = @UserID,    
            CreatedBy = @CreatedBy,    
            FullPath = @FullPath,    
            IsFeatured = @IsFeatured    
     WHERE  ProductID = @ProductID    
    SELECT 'Record Updated'    
 END    
 ELSE    
 BEGIN    
     SELECT 'Record Already Exists'    
 END    
END  



