    --)                        
    --   select @ProductID = SCOPE_IDENTITY()              
    SET @sqls = 'update ' + @tableName + '                   
    set  Description = ''' + @Description + '''                        
    , [Name] = ''' + @ProductName + '''                        
    , price = ' + cast(@SalesPrice AS VARCHAR) + '                        
    , IsPublished =  ' + cast(@IsPublished AS VARCHAR) + '                        
    , isactive = ' + cast(@IsActive AS VARCHAR) + '                        
    , IsFeatured = ' + cast(@IsFeatured AS VARCHAR) + '                        
    , sku = ''' + @sku + '''                        
    , DecimalRateItemQuantity = ' + cast(@DecimalRateQuantity AS VARCHAR) + '                        
    , category_id = ' + cast(@CategoryID AS VARCHAR) + '                        
    , HomeTaxIDs =  ''' + cast(@HomeStateTaxIDs AS VARCHAR) + '''                       
    , OtherTaxIDs = ''' + cast(@OtherTaxIDs AS VARCHAR) + '''                        
    , UpdatedAt = ''' + cast(getdate() AS VARCHAR) + '''                        
    , SellingAccount = ' + cast(@SalesAccount AS VARCHAR) + '                   
    , CostPrice = ' + cast(@CastPrice AS VARCHAR) + '                        
    , Cast_Account = ' + cast(@CastAccount AS VARCHAR) + '                        
    , IsDigitalService = ' + cast(@IsDigitalService AS VARCHAR) + '                        
    , IsGoods = ' + cast(@IsGoods AS VARCHAR) + '                        
    , IsServices =  ' + cast(@IsServices AS VARCHAR) + '                        
    , SACCode = ''' + @SACCode + '''                        
    , HSNCode = ''' + @HSNCode + '''                        
    , IsTaxable = ' + cast(@IsTaxable AS VARCHAR) + '                        
    , UnitID = ' + cast(@UnitID AS VARCHAR) + '                
    , IsSaleable = ' + cast(@IsSaleable AS VARCHAR) + '  
 , ThumbnailUrl ='''+ @ThumbnailUrl +'''  
    where ProductID = ' + cast(@ProductID AS VARCHAR) + ''      
      
    PRINT @sqls      
      
    EXECUTE sp_executesql @sqls      
      
    INSERT INTO #temp (      
     lbltxt      
     ,value      
     )      
    SELECT lbltxt      
     ,value      
    FROM OPENJSON(@CustomFieldValueJson) WITH (      
      lbltxt NVARCHAR(max) '$.lbltxt'      
      ,value NVARCHAR(Max) '$.value '      
      )      
      
    --select * from #temp              
    SELECT ROW_NUMBER() OVER (      
      ORDER BY tt.id      
      ) Row      
     ,*      
    INTO #temp2      
    FROM #temp tt      
    JOIN (      
     SELECT COLUMN_NAME      
     FROM INFORMATION_SCHEMA.COLUMNS      
     WHERE TABLE_NAME = @tablename      
     ) tbl ON tbl.COLUMN_NAME = tt.lbltxt      
      
    SELECT @min = min(row)      
     ,@max = max(row)      
    FROM #temp2      
      
    WHILE (@min <= @max)      
    BEGIN      
     SELECT @fieldName = lbltxt      
      ,@value = value      
     FROM #temp2      
     WHERE Row = @min      
      
     IF @value IS NULL      
     BEGIN      
      SET @sqls = 'Update ' + @tableName + ' set ' + @fieldName + ' =  ' + @value + ' where ProductID=' + cast(@ProductID AS VARCHAR) + ''      
       -- SELECT @sqls            
     END      
     ELSE      
     BEGIN      
      SET @sqls = 'Update ' + @tableName + ' set ' + @fieldName + ' =  ''' + @value + ''' where ProductID=' + cast(@ProductID AS VARCHAR) + ''      
     END      
      
     PRINT @sqls      
      
     EXECUTE sp_executesql @sqls      
      
     SET @min = @min + 1      
    END      
      
    SELECT @Count = Count(1)      
    FROM @ProductFileURL_Type_TBL      
      
    IF (@Count > 0)      
    BEGIN      
     DECLARE @ImagePart NVARCHAR(100) = ''      
     DECLARE @FullPath NVARCHAR(max) = ''      
      
     SELECT @FullPath = FileURL      
     FROM @ProductFileURL_Type_TBL      
     WHERE ID = 1      
      
     DECLARE @index INT = 0      
      
     SELECT @index = charindex('ProductImages', @FullPath)      
      
     IF (@index <> 0)      
     BEGIN      
      SELECT @ImagePart = SUBSTRING(@FullPath, @index, len(@FullPath) - @index + 1)      
      
      SET @sqls = 'UPDATE ' + @tableName + '            
      SET IMAGE = ''' + @ImagePart + '''            
       ,FullPath = ''' + @FullPath + '''            
      WHERE ProductID = ' + cast(@ProductID AS VARCHAR) + ''      
      
      EXECUTE sp_executesql @sqls      
     END      
      
     DELETE      
     FROM ProductImageMapping      
     WHERE ProductID = @ProductID      
      AND ImageURL NOT IN (      
       SELECT FileURL      
       FROM @ProductFileURL_Type_TBL      
       )      
      
     INSERT INTO ProductImageMapping (      
      ProductID      
      ,ImageURL      
      ,CreatedDate      
      )      
     SELECT @ProductID      
      ,FileUrl      
      ,getdate()      
     FROM @ProductFileURL_Type_TBL      
     WHERE FileURL NOT IN (      
       SELECT ImageURL      
       FROM ProductImageMapping(NOLOCK)      
       WHERE ProductID = @ProductID      
       )      
    END      
      
    IF (@Count = 0)      
    BEGIN      
     SET @sqls = '            
     UPDATE ' + @tableName + '            
     SET IMAGE = ''''            
      ,FullPath = ''''            
     WHERE ProductID = ' + cast(@ProductID AS VARCHAR) + '            
            
     DELETE            
     FROM ProductImageMapping            
     WHERE ProductID = ' + cast(@ProductID AS VARCHAR) + ''      
      
     PRINT @sqls      
      
     EXECUTE sp_executesql @sqls      
    END      
      
    IF (rtrim(ltrim(@ProductTagsIDs)) <> '')      
    BEGIN      
     DELETE      
     FROM EntityTagMapping      
     WHERE EntityID = @ProductID      
      AND Entity = 'Product'      
      AND TagID NOT IN (      
       SELECT cast(value AS BIGINT)      
       FROM fn_Split(@ProductTagsIDs, '#')      
       )      
      
     INSERT INTO EntityTagMapping (      
      EntityID      
      ,Entity      
      ,CreatedDate      
      ,TagID      
      )      
     SELECT ProductID      
      ,Entity      
      ,Createddate      
      ,tagID      
     FROM (      
      SELECT @ProductID AS ProductID      
       ,'Product' AS Entity      
       ,getdate() AS Createddate      
       ,cast(value AS BIGINT) AS tagID      
      FROM fn_Split(@ProductTagsIDs, '#')      
      ) AS tbl      
     WHERE tbl.tagID NOT IN (      
       SELECT Tagid      
       FROM EntityTagMapping      
       WHERE EntityID = @ProductID      
        AND Entity = 'Product'      
       )      
    END      
      
    IF (rtrim(ltrim(@ProductTagsIDs)) = '')      
    BEGIN      
     DELETE      
     FROM EntityTagMapping      
     WHERE EntityID = @ProductID      
      AND Entity = 'Product'      
    END      
      
    SELECT 'Data Saved Successfully' AS MSG      
     ,'Success' AS STATUS      
      
    SET @sqls = ' select *,                     
         MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) as [HomeTaxJson],                    
         MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) as [OtherTaxJson]                    
        from (                    
        select top 10                    
         ProductID as Id,                    
         Name,                     
         Image,                     
         Description,                     
         CostPrice as [PurchasePrice],                     
         Price as SalePrice,                    
         HomeTaxIDs,                    
         OtherTaxIDs,              
         Sku,    
  '''' as [ItemJSON]     
          from ' + @tableName + ' (nolock) where ProductID = ' + cast(@ProductID AS VARCHAR) + '                          order by Name asc                    
         ) products'      
      
    PRINT @sqls      
      
    EXECUTE sp_executesql @sqls      
   END      
   ELSE      
   BEGIN      
    SELECT 'Product Name Already Exists' AS MSG      
     ,'Faillure' AS STATUS      
      
    SELECT 'IMP'      
    WHERE 1 = 0      
   END      
  END      
  ELSE      
  BEGIN      
   SELECT 'Shop Keeping Unit Already Exists' AS MSG      
    ,'Faillure' AS STATUS      
      
   SELECT 'IMP'      
   WHERE 1 = 0      
  END      
 END      
      
 IF @check2 = 0      
 BEGIN      
  DECLARE @rowJson NVARCHAR(MAX) = 'Select @rowJson =(SELECT * FROM ' + @tableName + ' WHERE ProductId=' + cast(@ProductID AS VARCHAR) + '      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )'      
      
  PRINT @rowJson      
      
  EXECUTE sp_executesql @rowJson      
   ,N'@rowJson Varchar(max) OUTPUT'      
   ,@rowJson OUTPUT      
      
  IF @rowJson IS NOT NULL      
  BEGIN      
   EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
    ,@Activity_type = 'Updt_Prdct'      
    ,@ActionType = 'U'      
    ,@RowJson = @rowJson      
    ,@Table_name = @tableName      
  END      
 END      
END 


GO

