  ,@max INT      
  ,@fieldName VARCHAR(200)      
  ,@value NVARCHAR(max)      
      
 DROP TABLE      
      
 IF EXISTS #temp      
  DROP TABLE      
      
 IF EXISTS #temp2      
  CREATE TABLE #temp (      
   id INT identity(1, 1)      
   ,lbltxt NVARCHAR(max)      
   ,value NVARCHAR(Max)      
   )      
      
 EXEC @status = Usp_CreateProductTableByParentID @UserID      
  ,@tableName OUTPUT      
      
 IF (@status = 1)      
 BEGIN      
  SET @sqls = 'select @check=1 from ' + @tablename + '(nolock) where sku = ''' + @SKU + ''' and ProductID <> ' + cast(@ProductID AS VARCHAR) + ''      
      
  PRINT @sqls      
      
  EXECUTE sp_executesql @sqls      
   ,N'@check int out'      
   ,@check OUT      
      
  SET @sqls = 'select @check2=1 from ' + @tablename + '(nolock) where UserID = ' + cast(@UserID AS VARCHAR) + ' and Name = ''' + @ProductName + ''' and ProductID <> ' + cast(@ProductID AS VARCHAR) + ''      
      
  PRINT @sqls      
      
  EXECUTE sp_executesql @sqls      
   ,N'@check2 int out'      
   ,@check2 OUT      
      
  IF @check = 0      
  BEGIN      
   IF @check2 = 0      
   BEGIN      
    --insert into ProductMaster                        
    -- (                        
    --   [Name]                        
    --    ,[UserID]                        
    --    ,[Image]                        
    --    ,[Description]                        
    --    ,[Price]                        
    --    ,[IsPublished]                        
    --    ,[IsActive]                        
    --    ,[CreatedOn]                        
    --    ,[CreatedBy]                        
    --    ,[FullPath]                        
    --    ,[IsFeatured]                        
    --    ,[sku]                        
    --    ,[quantity]                        
    --    ,[category_id]                        
    --    ,[HomeTaxIDs]                        
    --    ,[OtherTaxIDs]                        
    --    ,[UpdatedAt]                        
    --    ,[DeletedAt]                        
    --    ,[SellingAccount]                        
    --    ,[Cast_Price]                        
    --    ,[Cast_Account]                        
    --    ,[IsDigitalService]                        
    --    ,[IsGoods]                        
    --    ,[IsServices]                        
    --    ,[SACCode]                        
    --    ,[HSNCode]                        
    --    ,[IsTaxable]                        
    --    ,[DecimalRateItemQuantity]                        
    --    ,[UnitID]                        
    --   )                        
    --values                        
    --  (                        
    --  @ProductName                        
    --    ,@UserID                        
    --    ,''                        
    --    ,@Description                        
    --    ,@SalesPrice                        
    --    ,@IsPublished                        
    --    ,@IsActive                        
    --   ,getdate()                        
    --    ,@UserID                        
    --    ,''                        
    --    ,@IsFeatured                        
    --    ,@sku                        
    --    ,@DecimalRateQuantity                        
    --    ,@categoryid                      
    --    ,@HomeStateTaxIDs                        
    --    ,@OtherTaxIDs                        
    --    ,getdate()                        
    --    ,null                        
    --    ,@SalesAccount                        
    --    ,@CastPrice                        
    --    ,@CastAccount                        
    --    ,@IsDigitalService                        
    --    ,@IsGoods                        
    --    ,@IsServices                        
    --    ,@SACCode                        
    --    ,@HSNCode                        
    --    ,@IsTaxable                        
    --    ,@DecimalRateQuantity                        
    --    ,@UnitID                        
    --)                        
    --   select @ProductID = SCOPE_IDENTITY()              
    SET @sqls = 'update ' + @tableName + '                   
    set  Description = ''' + @Description + '''                        
    , [Name] = ''' + @ProductName + '''                        
    , price = ' + cast(@SalesPrice AS VARCHAR) + '                        
    , IsPublished =  ' + cast(@IsPublished AS VARCHAR) + '                        
    , isactive = ' + cast(@IsActive AS VARCHAR) + '                        
    , IsFeatured = ' + cast(@IsFeatured AS VARCHAR) + '                        
    , sku = ''' + @sku + '''                        
    , DecimalRateItemQuantity = ' + cast(@DecimalRateQuantity AS VARCHAR) + '                        
    , category_id = ' + cast(@CategoryID AS VARCHAR) + '                        
    , HomeTaxIDs =  ''' + cast(@HomeStateTaxIDs AS VARCHAR) + '''                       
    , OtherTaxIDs = ''' + cast(@OtherTaxIDs AS VARCHAR) + '''                        
    , UpdatedAt = ''' + cast(getdate() AS VARCHAR) + '''                        
    , SellingAccount = ' + cast(@SalesAccount AS VARCHAR) + '                   
    , CostPrice = ' + cast(@CastPrice AS VARCHAR) + '                        
    , Cast_Account = ' + cast(@CastAccount AS VARCHAR) + '                        
    , IsDigitalService = ' + cast(@IsDigitalService AS VARCHAR) + '                        
    , IsGoods = ' + cast(@IsGoods AS VARCHAR) + '                        
    , IsServices =  ' + cast(@IsServices AS VARCHAR) + '                        
    , SACCode = ''' + @SACCode + '''                        
    , HSNCode = ''' + @HSNCode + '''                        
    , IsTaxable = ' + cast(@IsTaxable AS VARCHAR) + '                        
    , UnitID = ' + cast(@UnitID AS VARCHAR) + '                
    , IsSaleable = ' + cast(@IsSaleable AS VARCHAR) + '  
 , ThumbnailUrl ='''+ @ThumbnailUrl +''' 
 , VariantsJson = ''' + @VariantsJson + '''                        
    , VCombinationJson = ''' + @VCombinationJson + '''  
    where ProductID = ' + cast(@ProductID AS VARCHAR) + ''      
      
