     ) tbl ON tbl.COLUMN_NAME = tt.lbltxt      
      
    SELECT @min = min(row)      
     ,@max = max(row)      
    FROM #temp2      
      
    WHILE (@min <= @max)      
    BEGIN      
     SELECT @fieldName = lbltxt      
      ,@value = value      
     FROM #temp2      
     WHERE Row = @min      
      
     IF @value IS NULL      
     BEGIN      
      SET @sqls = 'Update ' + @tableName + ' set ' + @fieldName + ' =  ' + @value + ' where ProductID=' + cast(@ProductID AS VARCHAR) + ''      
       -- SELECT @sqls            
     END      
     ELSE      
     BEGIN      
      SET @sqls = 'Update ' + @tableName + ' set ' + @fieldName + ' =  ''' + @value + ''' where ProductID=' + cast(@ProductID AS VARCHAR) + ''      
     END      
      
     PRINT @sqls      
      
     EXECUTE sp_executesql @sqls      
      
     SET @min = @min + 1      
    END      
      
    SELECT @Count = Count(1)      
