     WHERE ID = 1      
      
     DECLARE @index INT = 0      
      
     SELECT @index = charindex('ProductImages', @FullPath)      
      
     IF (@index <> 0)      
     BEGIN      
      SELECT @ImagePart = SUBSTRING(@FullPath, @index, len(@FullPath) - @index + 1)      
      
      SET @sqls = 'UPDATE ' + @tableName + '            
      SET IMAGE = ''' + @ImagePart + '''            
       ,FullPath = ''' + @FullPath + '''            
      WHERE ProductID = ' + cast(@ProductID AS VARCHAR) 
	   + ' '      
                 
      EXECUTE sp_executesql @sqls      
     END      
      
     DELETE      
     FROM ProductImageMapping      
     WHERE ProductID = @ProductID  and ParentID = @ParentID     
      AND ImageURL NOT IN (      
       SELECT FileURL      
       FROM @ProductFileURL_Type_TBL      
       )      
      
     INSERT INTO ProductImageMapping (      
