     INSERT INTO TagMaster (            
      [Tag]            
      ,[ParentID]            
      ,[CreatedDate]            
      ,[CreatedBy]            
      )            
     VALUES (            
      @tTagName            
      ,@ParentID            
      ,GETDATE()            
      ,@UserID            
      );            
            
     DECLARE @sId BIGINT = SCOPE_IDENTITY();            
            
     UPDATE #tempTagName            
     SET [tagId] = @sId            
     WHERE [id] = @tId;            
    END;            
            
    UPDATE #tempTagName            
    SET [isProcess] = 1            
    WHERE [id] = @tId;            
   END;            

   DELETE EntityTagMapping            
   WHERE [EntityID] = @ProductID and TM_ParentID = @ParentID             
    AND LOWER([Entity]) = 'Product';            
            
   INSERT INTO EntityTagMapping (            
    [EntityID]            
    ,[Entity]            
    ,[TagID]            
    ,[CreatedDate] 
	,TM_ParentID
    )            
   SELECT @ProductID            
    ,'Product'            
    ,[tagId]            
    ,GETDATE()
	,@ParentID
   FROM #tempTagName;            
  END;
  
     drop table if exists #tempTagName
	 

	/*
    IF (rtrim(ltrim(@ProductTagsIDs)) <> '')      
    BEGIN      
     DELETE      
     FROM EntityTagMapping      
     WHERE EntityID = @ProductID      
      AND Entity = 'Product'      
      AND TagID NOT IN (      
       SELECT cast(value AS BIGINT)      
       FROM fn_Split(@ProductTagsIDs, '#')      
       )      
      
     INSERT INTO EntityTagMapping (      
      EntityID      
      ,Entity      
      ,CreatedDate      
      ,TagID      
      )      
     SELECT ProductID      
      ,Entity      
      ,Createddate      
      ,tagID      
     FROM (      
      SELECT @ProductID AS ProductID      
       ,'Product' AS Entity      
       ,getdate() AS Createddate      
       ,cast(value AS BIGINT) AS tagID      
      FROM fn_Split(@ProductTagsIDs, '#')      
      ) AS tbl      
     WHERE tbl.tagID NOT IN (      
       SELECT Tagid      
       FROM EntityTagMapping      
       WHERE EntityID = @ProductID      
        AND Entity = 'Product'      
       )      
    END      
      
    IF (rtrim(ltrim(@ProductTagsIDs)) = '')      
    BEGIN      
     DELETE      
     FROM EntityTagMapping      
     WHERE EntityID = @ProductID      
      AND Entity = 'Product'      
    END  
	*/
	
	
    SELECT 'Data Saved Successfully' AS MSG      
     ,'Success' AS STATUS      
      
    SET @sqls = ' select *,                     
         MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) as [HomeTaxJson],                    
         MySMSInvoicing.dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) as [OtherTaxJson]                    
        from (                    
        select top 10                    
         ProductID as Id,                    
         Name,                     
         Image,                     
         Description,                     
         CostPrice as [PurchasePrice],                     
         Price as SalePrice,                    
         HomeTaxIDs,                    
         OtherTaxIDs,              
         Sku, 
		  VariantsJson,VCombinationJson,
  '''' as [ItemJSON]     , '''' as [ProjectJSON]  
          from ' + @tableName + ' (nolock) where ProductID = ' + cast(@ProductID AS VARCHAR) + '                          order by Name asc                    
         ) products'      
      
    PRINT @sqls      
      
    EXECUTE sp_executesql @sqls      
   END      
   ELSE      
   BEGIN      
    SELECT 'Product Name Already Exists' AS MSG      
     ,'Faillure' AS STATUS      
      
    SELECT 'IMP'      
    WHERE 1 = 0      
   END      
  END      
  ELSE      
  BEGIN      
   SELECT 'Shop Keeping Unit Already Exists' AS MSG      
    ,'Faillure' AS STATUS      
      
   SELECT 'IMP'      
   WHERE 1 = 0      
  END      
 END      
      
 IF @check2 = 0      
 BEGIN      
  DECLARE @rowJson NVARCHAR(MAX) = 'Select @rowJson =(SELECT * FROM ' + @tableName + ' WHERE ProductId=' + cast(@ProductID AS VARCHAR) + '      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )'      
      
  PRINT @rowJson      
      
  EXECUTE sp_executesql @rowJson      
   ,N'@rowJson Varchar(max) OUTPUT'      
   ,@rowJson OUTPUT      
      
  IF @rowJson IS NOT NULL      
  BEGIN      
   EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
    ,@Activity_type = 'Updt_Prdct'      
    ,@ActionType = 'U'      
    ,@RowJson = @rowJson      
    ,@Table_name = @tableName      
  END      
 END      
END 


