CREATE   PROCEDURE [dbo].[Usp_UpdateProfileDetails]   --  21752,'Rockstar',9654469384,'tabc@pelsoftlabs.in','','','','Update','','','31-8-2015','1'      

@User_ID int,          
@FName varchar(50),           
@Mobile float,          
@EMail varchar(50),           
