@Merchant_Url varchar(50) = NULL,  -- ADDED BY RATNA ON 16-07-15
@User_DOB nvarchar(50) = NULL,     -- ADDED BY RATNA ON 16-07-15
@LoginType varchar(6) = NULL       -- ADDED BY RATNA ON 16-07-15
  
AS          
BEGIN          
SET NOCOUNT ON;       
   
	if(@Action='Update')       
	begin    
		declare @Contact_Mobi float,@EMa varchar(50)      
