		end  
		else   
		begin    
			SELECT 'EMail Already Exists' as Error    
		end   
	end   
	else if(@EMa=@EMail)    
	begin  
		IF not EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE Mobile=@Mobile)  
		begin  
			update [User_Detail] set FName=@FName,Mobile=@Mobile,EMail=@EMail,pincode=@pincode,Gender=@Gender	,Address=@Address,	Merchant_Code=@Merchant_Code, Merchant_Url=@Merchant_Url, User_DOB=@User_DOB, LoginType=@LoginType    -- ADDED BY RATNA ON 16-07-15 FOR Merchant_Code, Merchant_Url, User_DOB, LoginType.
		where User_ID=@User_ID        
			select 'Update Profile Successfully' as Msg     
		end  
		else   
		begin    
			SELECT 'Mobile Already Exists1' as Error   
		end   
	end   
	else IF not EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE Mobile=@Mobile)    
	begin  
		IF not EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE EMail=@EMail)  
		begin  
			update [User_Detail] set FName=@FName,Mobile=@Mobile,EMail=@EMail,pincode=@pincode,Gender=@Gender	,Address=@Address,	Merchant_Code=@Merchant_Code, Merchant_Url=@Merchant_Url, User_DOB=@User_DOB, LoginType=@LoginType    -- ADDED BY RATNA ON 16-07-15 FOR Merchant_Code, Merchant_Url, User_DOB, LoginType.
