/* ============================================================
   Procedure: [dbo].[usp_updatequotationstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select top 10 * from userevent(nolock) order by id desc

CREATE   PROCEDURE [dbo].[usp_updatequotationstatus]        
(@authid nvarchar(100),@draftid int,@status bit,@remarks nvarchar(max)=null)        
as        
begin        
if exists(select 1 from Draft_details(nolock) where sno=@draftid and authid=@authid)        
begin        
update Draft_details set accepted=@status,revisionremarks=@remarks,remarksdate=getdate() where sno=@draftid and authid=@authid        
declare @enqno bigint=(select reference_no from Draft_details(nolock)  where sno=@draftid and authid=@authid)        
--if exists(select 1 from LinkedAccount (nolock) where RefrenceNo=@enqno)        
--begin        
declare @date datetime,@amount numeric(18,2),@mapping nvarchar(20)        
select @date= convert(datetime,posted_date,104),@amount=quote_amount from Draft_details    where sno=@draftid and authid=@authid        
declare @event nvarchar(500),@description nvarchar(max)         
declare @userid bigint=(select top 1 USER_ID from LinkedAccount(nolock) where RefrenceNo=@enqno and Verified=1 order by LastLogin1 desc)  
if @userid is null
set @mapping='Enqno'
      
select @event=case when @status=1 then 'User accepted quotation' else 'User requested revision on quotation' end--amounting '+cast(@amount as nvarchar)+' sent on '+cast(@date as nvarchar)    
,@description=        
case when @status=1 then 'Congrats! ' else 'Attention! ' end + 'User with enqno '+cast(@enqno as nvarchar)+' has ' +
case when @status=1 then 'accepted ' else 'asked for revision on ' end+'your quotation sent on '+cast(@date as nvarchar) + 
' amounting Rs.'+ cast(@amount as nvarchar)+ '.'+ 
case when @status=1 then '' else 'The revision details provided by customer are: ' +isnull(@remarks,'none') end +
'. This action was performed at '+ cast(getdate() as nvarchar(50))        
        
insert into UserEvent ([Event],[UserID],[Description],[RefTable],[RefID],Mapping,MappingValue )        
values (@event,@userid,@description,'Draft_details',@draftid,'Enqno',@enqno)        
--exec Usp_InsertUserEventDetails @event,@userid,@description,'Draft_details',@draftid        
--end        
end        
else        
begin        
select 'Invalid Request. Please reload the link and try again'        
end        
end 


GO

/* ============================================================
   Procedure: [dbo].[Usp_updateReason]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_updateReason      
(      
  @BatchNotificationDetail_ID bigint,      
  @Reason nvarchar(500),      
  @SubReason nvarchar(500),    
  @RawReason nvarchar(max)    
        
)      
as      
Begin   

	If(@Reason = 'NotRegistered')
	Begin
		declare @DeviceId nvarchar(1000)='',@UserId bigint=0,@AppVersion varchar(100),@OSVersion varchar(100),@OSName varchar(100),@ModelName varchar(100), @BatchNotification_Id bigint

		Select	@UserId=USER_ID, @BatchNotification_Id=BatchNotification_Id
		From	[MK_BatchNotificationDetail] 
		where	 BatchNotificationDetail_Id =  @BatchNotificationDetail_ID
	
		select	@DeviceId=DeviceID,@AppVersion=AppVersion,@OSVersion=OSVersion,@OSName=OSName,@ModelName=ModelName
		from	User_Detail 
		Where	User_Id=@UserId

		exec usp_insertloginhistory @UserId, null, null, @DeviceId, 'Logout', null, @AppVersion,@OSVersion,@OSName,@ModelName

		Update	User_Detail 
		Set		DeviceID='', OTP='', AppVersion='', OSVersion='', OSName='', ModelName=''
				, OnField=0, Presence = case when isnull(MACAddress,'') != '' then Presence else 0 end
		Where	User_Id=@UserId

		update	[MK_BatchNotificationDetail] 
		set		[Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1
				,IsProcessed=1
		where	BatchNotificationDetail_Id =  @BatchNotificationDetail_ID

		If not exists(Select * from [MK_BatchNotificationDetail] Where BatchNotification_Id=@BatchNotification_Id and IsProcessed=0)
		Begin
			update	[MK_BatchNotification] set IsProcessed=1 Where BatchNotification_Id=@BatchNotification_Id
		End
	End
	Else
	Begin
		update	[MK_BatchNotificationDetail] 
		set		[Reason] = @Reason ,[SubReason] = @SubReason , [RawReason] = @RawReason, LastAttemptedTime = getdate(), Retries = isnull(Retries,0)+1
		where	BatchNotificationDetail_Id =  @BatchNotificationDetail_ID
	End

End 



GO

