/* ============================================================
   Procedure: [dbo].[usp_UpdateReportSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdateReportSummary]  
    @reportdate date, @ParentID BIGINT,@ScheduleId BIGINT=null,@summary nvarchar(max) =null,@error nvarchar(max)=null  
AS  
BEGIN  
begin try  
    UPDATE ReportSummaryStatus  
    SET IsProcessed = case when isnull(@scheduleid,0)>0 then 1 else IsProcessed end,
	Whatsappsendid = case when isnull(@scheduleid,0)>0 then @ScheduleId else Whatsappsendid end, 
	ProcessedDate=GETDATE(),
	summary= case when @summary is not null then @summary else summary end,
	error=case when @error is not null then @error else error end
    WHERE ParentID = @ParentID and reportdate =@reportdate-->= cast (DATEADD(d,-1,getdate()) as date) --and @ScheduleId<>0;  
 end try  
 begin catch  
  exec usp_InsertErrorInfo     
 end catch  
END;  


--alter table ReportSummaryStatus add urs_createdon datetime default getdate()


GO

/* ============================================================
   Procedure: [dbo].[usp_UpdateReportSummaryStatusIsProcessed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdateReportSummaryStatusIsProcessed]  
    @ParentID BIGINT,@ScheduleId BIGINT   
AS  
BEGIN  
begin try  
    UPDATE ReportSummaryStatus  
    SET IsProcessed = 1,Whatsappsendid = @ScheduleId, ProcessedDate=GETDATE()  
    WHERE ParentID = @ParentID and reportdate >= cast (DATEADD(d,-1,getdate()) as date) and @ScheduleId<>0;  
 end try  
 begin catch  
  exec usp_InsertErrorInfo     
 end catch  
END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_UpdateSalesTargetSettingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_UpdateSalesTargetSettingMaster (    
 @SalesTargetId BIGINT    
 ,@TargetType VARCHAR(30)    
 ,@Conversions BIT = NULL    
 ,@Pipelines BIT = NULL    
 ,@Invoices BIT = NULL    
 ,@iInvoiceRaised BIT = NULL    
 ,@iInvoicePaid BIT = NULL    
 ,@TargetFor VARCHAR(30)    
 ,@TeamCodes VARCHAR(4000) = NULL    
 ,@UserIds NVARCHAR(max) = NULL    
 ,@TargetPeriodId INT = NULL    
 ,@TargetFromDate DATETIME = NULL    
 ,@TargetToDate DATETIME = NULL    
 ,@TargetProductIds NVARCHAR(MAX) = NULL    
 ,@TargetPipelineIds NVARCHAR(MAX) = NULL    
 ,@TotalTarget NUMERIC(18, 2) = NULL    
 ,@TargetUnit VARCHAR(30) = NULL    
 ,@Currency VARCHAR(30) = NULL    
 ,@UserId BIGINT = NULL    
 ,@ParentId BIGINT = NULL    
 ,@Status BIT = NULL    
 ,@IsActive BIT = NULL    
 ,@CreatedBy BIGINT = NULL    
 ,@dtChildMaster NVARCHAR(max) = NULL    
 )    
AS    
BEGIN    
 SET NOCOUNT ON    
    
 BEGIN TRY    
  BEGIN    
   UPDATE TBL_ST_SalesTargetSettingMaster    
   SET TargetType = @TargetType    
    ,Conversions = @Conversions    
    ,Pipelines = @Pipelines    
    ,Invoices = @Invoices    
    ,iInvoiceRaised = @iInvoiceRaised    
    ,iInvoicePaid = @iInvoicePaid    
    ,TargetFor = @TargetFor    
    ,TeamCodes = @TeamCodes    
    ,UserIds = @UserIds    
    ,TargetPeriodId = @TargetPeriodId    
    ,TargetFromDate = @TargetFromDate    
    ,TargetToDate = @TargetToDate    
    ,TargetProductIds = @TargetProductIds    
    ,TargetPipelineIds = @TargetPipelineIds    
    ,TotalTarget = @TotalTarget    
    ,TargetUnit = @TargetUnit    
    ,Currency = @Currency    
    ,UserId = @UserId    
    ,ParentId = @ParentId    
    ,[Status] = @Status    
    ,IsActive = @IsActive    
    ,ModifiedBy = @CreatedBy    
    ,ModifiedDate = GETDATE()    
   WHERE SalesTargetId = @SalesTargetId    
    
   DELETE TBL_ST_SalesTargetSettingChild    
   WHERE SalesTargetId = @SalesTargetId    
    
   INSERT INTO TBL_ST_SalesTargetSettingChild (    
    SalesTargetId    
    ,TeamCode    
    ,UserId    
    ,[Target]    
    ,IsActive    
    )    
   SELECT @SalesTargetId    
    ,TeamCode    
    ,UserId    
    ,[Target]    
    ,IsActive    
   FROM openjson(@dtChildMaster) WITH (    
     [TeamCode] NVARCHAR(50) '$.TeamCode'    
     ,[UserId] BIGINT '$.UserId'    
     ,[Target] FLOAT '$.Target'    
     ,[IsActive] BIT '$.IsActive'    
     ) t    
    
   SELECT 'Updated Successfully'    
  END /*End here for details*/    
 END TRY    
    
 BEGIN CATCH    
  DECLARE @ErrorMessage NVARCHAR(4000);    
    
  SELECT @ErrorMessage = ERROR_MESSAGE();    
    
  RAISERROR (    
    @ErrorMessage    
    ,16    
    ,1    
    );    
 END CATCH    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM TBL_ST_SalesTargetSettingMaster(NOLOCK)    
   WHERE SalesTargetId = @SalesTargetId    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
   ,@Activity_type = 'Updt_SaleTrgt'    
   ,@ActionType = 'U'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'TBL_ST_SalesTargetSettingMaster'    
 END    
END 


GO

