    @UserName NVARCHAR(50),  
    @UserFilter NVARCHAR(50),  
    @BalanceFrom VARCHAR(50),  
    @BalanceTo VARCHAR(50),  
    @TotalCreditPurchasedFrom VARCHAR(50),  
    @TotalCreditPurchasedTo VARCHAR(50),  
    @TotalCreditConsumedFrom VARCHAR(50),  
    @TotalCreditConsumedTo VARCHAR(50),  
    @CreatedBetweenFrom VARCHAR(50),  
    @CreatedBetweenTo VARCHAR(50), 
    
    @MailBalanceFrom VARCHAR(50),  
    @MailBalanceTo VARCHAR(50),  
    @MailTotalCreditPurchasedFrom VARCHAR(50),  
    @MailTotalCreditPurchasedTo VARCHAR(50),  
    @MailTotalCreditConsumedFrom VARCHAR(50),  
    @MailTotalCreditConsumedTo VARCHAR(50),
     
    @HasMicrosite BIT,  
    @IsActive BIT,  
    @ModifiedBy BIGINT,  
    @IsNewUser BIT,  
    @UserStatus BIT,  
    @MobileNo VARCHAR(100),  
    @EmailID VARCHAR(100),  
    @UserType VARCHAR(100),  
    @LastLoginBeforeFrom VARCHAR(50),  
    @LastLoginBeforeTo VARCHAR(50),  
    @LastPurchaseDaysFrom VARCHAR(50),  
    @LastPurchaseDaysTo VARCHAR(50),  
    @LastPurchasePriceFrom VARCHAR(50),  
    @LastPurchasePriceTo VARCHAR(50) ,
    
    @LastCreditPurchaseFrom VARCHAR(50),  
    @LastCreditPurchaseTo VARCHAR(50)
     
)          
AS          
BEGIN  
 UPDATE SearchDetails  
 SET    SearchName = @SearchName,  
        UserName = @UserName,  
        UserFilter = @UserFilter,  
        BalanceFrom = @BalanceFrom,  
        UserStatus = @UserStatus,  
        BalanceTo = @Balanceto,  
        TotalCreditPurchasedFrom = @TotalCreditPurchasedFrom,  
        TotalCreditPurchasedTo = @TotalCreditPurchasedTo,  
        TotalCreditConsumedFrom = @TotalCreditConsumedFrom,  
        TotalCreditConsumedTo = @TotalCreditConsumedTo,  
        CreatedBetweenFrom = @CreatedBetweenFrom,  
        CreatedBetweenTo = @CreatedBetweenTo, 
        
      MailBalanceFrom = @MailBalanceFrom,
      MailBalanceTo = @MailBalanceTo,
      TotalMailCreditPurchasedFrom = @MailTotalCreditPurchasedFrom,
      TotalMailCreditPurchasedTo = @MailTotalCreditPurchasedTo,
      TotalMailCreditConsumedFrom = @MailTotalCreditConsumedFrom,
      TotalMailCreditConsumedTo  = @MailTotalCreditConsumedTo,
         
        HasMicrosite = @HasMicrosite,  
        IsActive = @IsActive,  
        IsNewUser = @IsNewUser,  
        ModifiedBy = @ModifiedBy,  
        ModifiedDate = GETDATE(),  
        Mobile = @MobileNo,  
        EmailID = @EmailID,  
        UserType = @UserType,  
        LastLoginBeforeFrom = @LastLoginBeforeFrom,  
        LastLoginBeforeTo = @LastLoginBeforeTo,  
        LastPurchaseDaysFrom = @LastPurchaseDaysFrom,  
        LastPurchaseDaysTo = @LastPurchaseDaysTo,  
        LastPurchasePriceFrom = @LastPurchasePriceFrom,  
        LastPurchasePriceTo = @LastPurchasePriceTo,
        LastCreditPurchaseFrom = @LastCreditPurchaseFrom,
        LastCreditPurchaseTo = @LastCreditPurchaseTo
          
 WHERE  ID = @ID          
   
 SELECT 'Record Updated'  
END



