/* ============================================================
   Procedure: [dbo].[usp_UpdateSequence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_UpdateSequence]
	@ParentID BIGINT,
	@GroupID BIGINT
AS
BEGIN
	SELECT ugtm.TemplateID,
	       ugtm.OrderNo,
	       utgd.GroupName,
	       umt.Name AS TemplateName
	FROM   UserGroupTemplateMix ugtm
	       INNER JOIN UserTemplateGroupDetails utgd
	            ON  utgd.ID = ugtm.GroupID
	            AND utgd.ParentID = @ParentID
	       INNER JOIN UserMailTemplate umt
	            ON  umt.ID = ugtm.TemplateID
	            AND umt.ParentID = @ParentID
	WHERE  ugtm.ParentID = @ParentID
	       AND ugtm.GroupID = @GroupID
END



GO

