/* ============================================================
   Procedure: [dbo].[Usp_UpdateSMSAPI_Status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateSMSAPI_Status]        
(        
 @ID bigint,        
 @Status int,      
 @Response nvarchar(200)      
)        
as        
begin        
    update sms_api_urls set isprocessed = @Status,Response =@Response,  
  processedon = getdate(),first_processed_on=case when @Status =2 then first_processed_on when  first_processed_on is null then getdate() else processedon end,  
  processed_times =case when @Status=2 then processed_times when isprocessed=1 and @status=1 then isnull(processed_times,0)+1 else processed_times end ,consolename=null 
    
  where id = @ID         
 select 'Status updated'          
end   
  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateSMSAPI_Status_withname]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateSMSAPI_Status_withname]          
(          
 @ID bigint,          
 @Status int,        
 @Response nvarchar(200),@consolename nvarchar(100)  =null      
)          
as          
begin      
set @consolename=coalesce(@consolename,'')    
insert into trace_updatems(p_id,Status,Response,consolename)    
select @id,@status,@response,@consolename    
    
begin try    
    update sms_api_urls set isprocessed = @Status,Response =@Response,    
  processedon = getdate(),first_processed_on=case when @Status =2 then first_processed_on when  first_processed_on is null then getdate() else processedon end,    
  processed_times =case when @Status=2 then processed_times when isprocessed=1 and @status=1 then isnull(processed_times,0)+1 when isprocessed<>1 and @status=1 then 1 else processed_times end,    
  consolename=case when @status=2 then consolename else isnull(consolename+',','')+@consolename end    
      
  where id = @ID           
 select 'Status updated'       
 end try    
 begin catch    
 exec usp_inserterrorinfo    
 end catch    
end 


GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateSMSCamPaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UpdateSMSCamPaign (
	@SenderID NVARCHAR(100)
	,@DLTTemplateID NVARCHAR(200)
	,@Message NVARCHAR(max)
	,@IsUnicode BIT
	,@IsActive BIT
	,@UserID BIGINT
	,@CampignID BIGINT
	,@TimeBeforeEvent INT
	,@TimeUnit NVARCHAR(20)
	)
AS
BEGIN
	IF (@TimeBeforeEvent = 0)
	BEGIN
		SET @TimeBeforeEvent = NULL
	END

	IF (rtrim(ltrim(@TimeUnit)) = '')
	BEGIN
		SET @TimeBeforeEvent = NULL
		SET @TimeUnit = NULL
	END

	UPDATE UserCampaignMaster
	SET SenderID = @SenderID
		,DLTTemplateID = @DLTTemplateID
		,Message = @Message
		,IsUnicode = @IsUnicode
		,IsActive = @IsActive
		,ModifiedOn = GETDATE()
		,ModifiedBy = @UserID
		,TimeBeforeEvent = @TimeBeforeEvent
		,TimeUnit = @TimeUnit
	WHERE id = @CampignID

	SELECT 'Data Updated'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserCampaignMaster
			WHERE ID = @CampignID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Updt_smscamp_trggrcamp'
		,@ActionType = 'U'
		,@RowJson = ''
		,@Table_name = 'UserCampaignMaster'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateSMSCamPaign_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------

CREATE   PROCEDURE [dbo].[Usp_UpdateSMSCamPaign_1]      
(      
  @SenderID nvarchar(100),      
  @DLTTemplateID nvarchar(200),      
  @Message nvarchar(max),      
  @IsUnicode bit,      
  @IsActive bit,      
  @UserID bigint,      
  @CampignID bigint,    
  @TimeBeforeEvent int,    
  @TimeUnit nvarchar(20),  
  @MaxLimit int  
)      
AS      
BEGIN      
    -- Start TRY block  
    BEGIN TRY  
        -- If TimeBeforeEvent is 0, set it to NULL  
        IF(@TimeBeforeEvent = 0)    
        BEGIN    
            SET @TimeBeforeEvent = NULL;    
        END    
  
        -- Update the UserCampaignMaster table  
        UPDATE UserCampaignMaster  
        SET   
            SenderID = @SenderID,   
            DLTTemplateID = @DLTTemplateID,   
            Message = @Message,  
            IsUnicode = @IsUnicode,   
            IsActive = @IsActive,   
            ModifiedOn = GETDATE(),   
            ModifiedBy = @UserID,   
            TimeBeforeEvent = @TimeBeforeEvent,  
            TimeUnit = @TimeUnit,  
            MaxLimit = @MaxLimit      
        WHERE ID = @CampignID;  
  
        -- Return success message  
        SELECT 'Data Updated' AS Status;  
    END TRY  
    -- Start CATCH block  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END;




GO

