/* ============================================================
   Procedure: [dbo].[usp_updatesmsdelivery_xml]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updatesmsdelivery_xml]          
@txnid bigint,          
@mobile nvarchar(20),          
@senderid nvarchar(10),          
@err_description nvarchar(200),          
@deliverystatus nvarchar(100),          
@deliverydt nvarchar(50),          
@tbl_qs_id bigint          
as          
begin          
      
begin try        
      
declare @dlrd datetime,@messageid bigint,@x_id bigint          
select @dlrd=isnull(try_cast(try_convert(datetime,@deliverydt,120) as datetime),getdate())          
      
update tbl_SMS_QueryString      
      set       
       txid = @txnid ,      
    [to]  = @mobile,      
   [from] = rtrim(ltrim(@senderid)),      
   [description] = @err_description,      
   deliverystatus = @deliverystatus,      
   deliverydt =   @dlrd      
     where ID = @tbl_qs_id      
      
      
      
select top 1 @messageid=corelationId,@x_id=id from MSG_XMLAPI_Resp (nolock) where transactionid=@txnid and isnull(DLR_Processed,0) = 0        
        order by id desc            
     --and ltrim(rtrim(senderid))=@senderid          
if exists (select 1 from messagedeliverystatus(nolock) where messageid=@messageid)          
begin          
update MSG_XMLAPI_Resp set dlr_processed=1,dlr_processedat=getdate() where id=@x_id          
update messagedeliverystatus set MessageStatus=case when @deliverystatus='Delivery_success' then 'Delivered' else @deliverystatus end,          
StatusDescription=@err_description,StatusCompletedTime=format(@dlrd,'dd-MMM-yyyy H:mm.sss ttt'),StatusCompletedTimeSecs=datediff(ss,messageinsertdate
,@dlrd),          
ProviderReference=@tbl_qs_id          
where messageid=@messageid  and ltrim(rtrim(senderid))=rtrim(ltrim(@senderid))          
update tbl_SMS_QueryString set dlr_updated=1,dlr_updateattempted=1 where id=@tbl_qs_id      
end          
else if exists (select 1 from thirtydayshistory(nolock) where messageid=@messageid and ltrim(rtrim(senderid))=rtrim(ltrim(@senderid)) and MessageStatus is null)          
begin          
update MSG_XMLAPI_Resp set dlr_processed=1,dlr_processedat=getdate() where id=@x_id          
update thirtydayshistory set MessageStatus=case when @deliverystatus='Delivery_success' then 'Delivered' else @deliverystatus end,          
StatusDescription=@err_description,StatusCompletedTime=@dlrd,StatusCompletedTimeSecs=datediff(ss,messageinsertdate,@dlrd),          
ProviderReference=@tbl_qs_id          
where messagestatus is null and messageid=@messageid and ltrim(rtrim(senderid))= rtrim(ltrim(@senderid))          
update tbl_SMS_QueryString set dlr_updated=1,dlr_updateattempted=1 where id=@tbl_qs_id      
end          
    
update tbl_SMS_QueryString set dlr_updateattempted=1 where id=@tbl_qs_id          

 end try
 begin catch
   exec usp_insertErrorInfo
 end catch

          
end     
    
--select * from sms_errorcodes



--exec usp_updatesmsdelivery_xml @txnid=22858943707,@mobile=N'917978330414',@senderid=N'NEEPCO',@err_description=N'Message delivered successfully',@deliverystatus=N'DELIVERY_SUCCESS',@deliverydt=N'2025-03-01 00:24:09',@tbl_qs_id=66682691



--select format(try_cast(try_convert(datetime,'2025-03-01 00:24:09',120) as datetime),'dd-MMM-yyyy H:mm.sss ttt')


GO

/* ============================================================
   Procedure: [dbo].[usp_updateSMSdlr]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC  [dbo].[usp_updateSMSdlr]                
as                
begin                
declare @SMSSentReportid bigint=  dbo.fn_max_no(isnull((select max(Receivedeliverydataid) from MySMS.dbo.SMSupdatedTill with (nolock)    
 where updatetable='SMSSent'),0),(select min(r.id) from [mysmstrans].dbo.[Receivedeliverydata] r with (nolock) where cast(CreatedDate as date)=cast(getdate() as date)))            
declare @CurrentSMSSentReportId bigint=(select MAX(r.id) from [mysmstrans].dbo.[Receivedeliverydata] r with (nolock))   
,@cnt bigint,@rowupdated int           
/*    
declare @c int= (select COUNT(1)  from [mysmstrans].dbo.[Receivedeliverydata] r (nolock) join [mysmstrans].dbo.Messagesent s (nolock)       
on r.SubmitRefID=(select top 1 value from dbo.fn_split(s.Msgref,',') order by position)    
--case when CHARINDEX(',',s.Msgref,1)>0 then left(s.Msgref,CHARINDEX(',',s.Msgref,1)-1) else s.Msgref end      
join MessageDeliveryStatus m         
(nolock) on            
s.MessageID=m.MessageID and s.BatchID=m.BatchID where r.ID>@SMSSentReportid)            
*/    
--select @CurrentSMSSentReportId,@SMSSentReportid--,@cnt            
if  @CurrentSMSSentReportId>@SMSSentReportid   and exists (select 1 from [mysmstrans].dbo.Messagesent where reportupdated=0)         
begin            
while @CurrentSMSSentReportId>@SMSSentReportid            
begin     
RETRY:    
begin try  
print '@currentsmsreportid: '+ cast(@CurrentSMSSentReportId as nvarchar)+', @SMSSentReportid: '+ cast(@SMSSentReportid as nvarchar)

drop table if exists #messagesent1
select top 1000 id as messagesentid,messageid,batchid,f.value as MsgR into #messagesent1 
from [mysmstrans].dbo.Messagesent s with (nolock) cross apply dbo.fn_split(s.Msgref,',') f
where reportupdated=0 and cast(sentdate as date)=cast(getdate() as date) order by id

print '#messagesent1 insertion completed with @SMSSentReportid: '+ cast(@SMSSentReportid as nvarchar)

drop table if exists #messagesent
select r.* into #messagesent from 
(select r.*,s.*,row_number() over (partition by messageid,batchid order by case when r.statuswitherr='DELIVRD' then 0 else 1 end) rn 
from [mysmstrans].dbo.ReceiveDeliveryData r with (nolock) join       
#Messagesent1 s with (nolock) on r.SubmitRefID=s.Msgr where cast(r.createddate as date)=cast(getdate() as date) and r.id<= @CurrentSMSSentReportId ) r    
where r.rn=1
             

print '#messagesent insertion completed with @SMSSentReportid: '+ cast(@SMSSentReportid as nvarchar)



update m set messagestatus=r.StatusWithErr from MySMS.dbo.MessageDeliveryStatus m with (nolock)     
join #messagesent r  on r.MessageID=m.MessageID and r.BatchID=m.BatchID           

set @rowupdated=@@ROWCOUNT

print 'Messagedeliverystatus updated. Rows: '+ cast(@rowupdated as nvarchar)

update m set reportupdated=1 from [mysmstrans].dbo.Messagesent m join #messagesent s on s.messagesentid=m.id
set @rowupdated=@@ROWCOUNT

print 'Messagesent updated. Rows: '+ cast(@rowupdated as nvarchar)

set @cnt=isnull((select max(id) from #messagesent),@SMSSentReportid)
print '@SMSSentReportid: '+cast(@cnt as nvarchar)

select @SMSSentReportid = @cnt   
--select @CurrentSMSSentReportId,@SMSSentReportid,@cnt  
--select count(1),@CurrentSMSSentReportId,@SMSSentReportid,GETDATE() from #messagesent            
drop table #messagesent1
drop table #messagesent    
if exists(select 1 from MySMS.dbo.smsupdatedtill with (nolock)             
where Updatetable='SMSSent' )    
begin            
