/* ============================================================
   Procedure: [dbo].[usp_updateSMSdlr_revised]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC  [dbo].[usp_updateSMSdlr_revised]                  
as                  
begin                  
declare @cnt bigint,@rowupdated int,@SMSSentReportid bigint             
select @cnt=count(1) from [mysmstrans].dbo.Messagesent where (reportupdated=0 or   
(reportupdated=2 and datediff(hh,reportupdatedon,getdate())>=1))  
and cast(sentdate as date)=cast(getdate() as date)  
if @cnt>0  
begin              
while @cnt>0  
begin       
RETRY:      
begin try    
print '@cnt: '+ cast(@cnt as nvarchar)  
  
drop table if exists #messagesent1  
select top 1000 id as messagesentid,messageid,batchid,f.value as MsgR into #messagesent1   
from [mysmstrans].dbo.Messagesent s with (nolock) cross apply dbo.fn_split(s.Msgref,',') f  
where (reportupdated=0 or (reportupdated=2 and datediff(hh,reportupdatedon,getdate())>=1 ))   
and cast(sentdate as date)=cast(getdate() as date) order by id  
  
print '#messagesent1 insertion completed with @SMSSentReportid: '+ cast(@SMSSentReportid as nvarchar)  
  
drop table if exists #messagesent  
select r.* into #messagesent from   
(select r.*,s.*,row_number() over (partition by messageid,batchid order by case when r.statuswitherr='DELIVRD' then 0 else 1 end) rn   
from [mysmstrans].dbo.ReceiveDeliveryData r with (nolock) join         
#Messagesent1 s with (nolock) on r.SubmitRefID=s.Msgr where cast(r.createddate as date)=cast(getdate() as date)) r      
where r.rn=1  
               
  
print '#messagesent insertion completed with @SMSSentReportid: '+ cast(@SMSSentReportid as nvarchar)  
  
update m set messagestatus=r.StatusWithErr from MySMS.dbo.MessageDeliveryStatus m with (nolock)       
join #messagesent r  on r.MessageID=m.MessageID and r.BatchID=m.BatchID             
  
set @rowupdated=@@ROWCOUNT  
  
print 'Messagedeliverystatus updated. Rows: '+ cast(@rowupdated as nvarchar)  
  
update m set reportupdated=1,reportupdatedon=getdate() from [mysmstrans].dbo.Messagesent m join #messagesent s on s.messagesentid=m.id  
set @rowupdated=@@ROWCOUNT  
  
print 'Messagesent updated. Rows: '+ cast(@rowupdated as nvarchar)  
  
update m set reportupdated=2,reportupdatedon=getdate() from [mysmstrans].dbo.Messagesent m join #messagesent1 s on s.messagesentid=m.id  
where reportupdated=0 or reportupdated=2  
set @rowupdated=@@ROWCOUNT  
  
print 'Messagesent updated as 2. Delivery report not updated. Rows: '+ cast(@rowupdated as nvarchar)  
  
select @cnt=@cnt-1000  
  
select @SMSSentReportid = max(id) from #messagesent     
--select @CurrentSMSSentReportId,@SMSSentReportid,@cnt    
--select count(1),@CurrentSMSSentReportId,@SMSSentReportid,GETDATE() from #messagesent              
drop table #messagesent1  
drop table #messagesent      
if exists(select 1 from MySMS.dbo.smsupdatedtill with (nolock)               
where Updatetable='SMSSent' )      
begin              
update s set Receivedeliverydataid=@SMSSentReportid,dateupdated=getdate() from (select top 1 * from MySMS.dbo.smsupdatedtill with (nolock)               
where Updatetable='SMSSent' order by id desc) s               
end      
else      
begin      
insert into MySMS.dbo.smsupdatedtill(dateupdated,Receivedeliverydataid,Updatetable)                  
select GETDATE(),@SMSSentReportId,'SMSSent'               
end      
end try      
begin catch      
exec usp_InsertErrorInfo      
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number              
BEGIN              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms              
GOTO RETRY -- Go to Label RETRY                
end           
end catch      
end              
end                
end         


GO

