/* ============================================================
   Procedure: [dbo].[Usp_UpdateSourceDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_UpdateSourceDetails (  
 @SourceID BIGINT  
 ,@Name NVARCHAR(100)  
 ,@UserID INT  
 ,@IsEditable BIT  
 ,@IsActive BIT  
 ,@ModifiedBy NVARCHAR(50)  
 )  
AS  
BEGIN  

      select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')   

 SELECT @UserID = Parentid  
 FROM user_detail(NOLOCK)  
 WHERE USER_ID = @userid  
  
 IF (  
   NOT EXISTS (  
    SELECT 'x'  
    FROM UserSourceSettings  
    WHERE NAME = @Name  
     AND SourceID <> @SourceID  
     AND UserID = @UserID  
    )  
   )  
 BEGIN  
  UPDATE UserSourceSettings  
  SET NAME = @Name  
   ,UserID = @UserID  
   ,ModifiedDate = GETDATE()  
   ,ModifiedBy = @ModifiedBy  
  WHERE SourceID = @SourceID  
  
  SELECT 'Record Updated'  
 END  
 ELSE  
 BEGIN  
  SELECT 'Already Exist'  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM UserSourceSettings(NOLOCK)  
   WHERE SourceID = @SourceID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'Updt_Srce_Sttng'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'UserSourceSettings'  
END  


GO

