/* ============================================================
   Procedure: [dbo].[Usp_UpdateTrgCampaignCloumnWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateTrgCampaignCloumnWise] (
	@ColumnName NVARCHAR(200)
	,@ColumnValue NVARCHAR(max)
	,@TrgCmpgnID BIGINT
	,@UserID BIGINT
	,@eventid int 
	,@datefield nvarchar(100) = null
,@datefieldtype varchar(20) = null
,@dateformattomatch varchar(50)= null
,@tc_timeafterevent int=null
,@tc_timeunit varchar(20)=null
,@fixedtime time=null
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
	DECLARE @rowJson NVARCHAR(MAX) = NULL

	SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF (@ColumnName = 'cname')
	BEGIN
		IF (
				NOT EXISTS (
					SELECT 1
					FROM triggeredcampaigns(NOLOCK)
					WHERE cname = @ColumnValue
						AND parentid = @ParentID
						AND id <> @TrgCmpgnID
					)
				)
		BEGIN
			UPDATE triggeredcampaigns
			SET cname = @ColumnValue
			WHERE id = @TrgCmpgnID

			SELECT 'Data Updated'

			SET @rowJson = (
					SELECT *
					FROM triggeredcampaigns
					WHERE id = @TrgCmpgnID
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)
		END
		ELSE
		BEGIN
			SELECT 'Triggered Campaign Name Already Exists'
		END
	END
	ELSE IF (@ColumnName = 'eventid')
	BEGIN
		UPDATE triggeredcampaigns
		SET eventid = CAST(@ColumnValue AS INT)
		WHERE id = @TrgCmpgnID

		UPDATE UserCampaignMaster
		SET eventid = CAST(@ColumnValue AS INT)
		WHERE id IN (
				SELECT isnull(smscampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET eventid = CAST(@ColumnValue AS INT)
		WHERE id IN (
				SELECT isnull(mailcampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET eventid = CAST(@ColumnValue AS INT)
		WHERE id IN (
				SELECT isnull(voicecampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET eventid = CAST(@ColumnValue AS INT)
		WHERE id IN (
				SELECT isnull(whatsappcampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		SELECT 'Data Updated'

		SET @rowJson = (
				SELECT *
				FROM triggeredcampaigns
				WHERE id = @TrgCmpgnID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
	END
	ELSE IF (@ColumnName = 'Audience')
	BEGIN
		UPDATE triggeredcampaigns
		SET Audience = @ColumnValue,
		 eventid = CAST(@eventid AS INT)
		,[datefield]=@datefield
		,[datefieldtype]=@datefieldtype
		,[dateformattomatch]=@dateformattomatch
		,[tc_timeafterevent]=@tc_timeafterevent
		,[tc_timeunit]=@tc_timeunit
		,[fixedtime]=@fixedtime
		WHERE id = @TrgCmpgnID

		UPDATE UserCampaignMaster
		SET Applicabilty = @ColumnValue
		WHERE id IN (
				SELECT isnull(smscampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET Applicabilty = @ColumnValue
		WHERE id IN (
				SELECT isnull(mailcampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET Applicabilty = @ColumnValue
		WHERE id IN (
				SELECT isnull(voicecampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		UPDATE UserCampaignMaster
		SET Applicabilty = @ColumnValue
		WHERE id IN (
				SELECT isnull(whatsappcampaignid, 0)
				FROM triggeredcampaigns(NOLOCK)
				WHERE id = @TrgCmpgnID
				)

		SELECT 'Data Updated'

		SET @rowJson = (
				SELECT *
				FROM triggeredcampaigns
				WHERE id = @TrgCmpgnID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
	END

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Updt_trggrcamp_clmws'
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'triggeredcampaigns'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateTriggerCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UpdateTriggerCampaign]
(
    @Cname              NVARCHAR(100),
    --@EventID            INT,
    @UserID             BIGINT,
	@botCampaignId      BIGINT		  =0
)
AS
BEGIN
--declare
-- @Cname              NVARCHAR(100)='rt1233',
--    @UserID             BIGINT=32222,
--  @botCampaignId      BIGINT		  =0
    DECLARE @ParenID BIGINT = 0;
    SELECT TOP 1 @ParenID = ISNULL(ParentID, User_ID)
    FROM User_Detail (NOLOCK)
    WHERE User_ID = @UserID;
    IF  EXISTS (
        SELECT 1
        FROM triggeredcampaigns (NOLOCK)
        WHERE cname = @Cname AND parentid = @ParenID
    )
    BEGIN
 
	update triggeredcampaigns  set bot_campaignid=@botCampaignId  WHERE cname = @Cname AND parentid = @ParenID

        SELECT 'Trigger Campaign updated';
    END
    ELSE
    BEGIN
        SELECT 'Trigger Campaign Name Already Exists';
    END
END


GO

