CREATE   PROCEDURE [dbo].[usp_UpdateTriggerSequenceByEventId]            
(          
 @Id bigint,  
 @SequenceId bigint,        
 @issequenceactive bit  
)          
AS          
  SET NOCOUNT ON          
  BEGIN TRY          
  begin          
if exists(select top 1 * from Triggeredcampaigns(nolock) where Id = @Id)  
Begin  
  Update Triggeredcampaigns set sequenceId = @SequenceId, issequenceactive = @issequenceactive where Id = @Id        
        
  Select 'Updated Successfully.' Status              
  End  
  Else  
  Begin  
  Select 'Not Update.' Status              
  End  
 end                     
 END TRY                       
BEGIN CATCH                       
 DECLARE @ErrorMessage NVARCHAR(4000);                       
 SELECT @ErrorMessage = ERROR_MESSAGE();                       
 RAISERROR (@ErrorMessage, 16, 1);                       
END CATCH          





