/* ============================================================
   Procedure: [dbo].[Usp_UpdateUnsubscribeDetailsToSearchDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*      
  Created By : Santosh Kumar      
  Created Date: 05/06/2017 07:52 PM      
  SP For : Updation for Unsubscribe Details      
  Alter By:      
  Alter Date:       
        
*/      
CREATE   PROC [dbo].[Usp_UpdateUnsubscribeDetailsToSearchDetails] 
(
    @SearchName NVARCHAR(250),
    @ID BIGINT,
    @PhoneNumber NVARCHAR(MAX),
    @FromDate NVARCHAR(100),
    @ToDate NVARCHAR(100),
    @IsActive BIT,
    @CRMUnsubscribeType NVARCHAR(3),
    @ModifiedBy BIGINT
)      
AS       
BEGIN
	UPDATE SearchDetails
	SET    SearchName = @SearchName,
	       PhoneNumber = @PhoneNumber,
	       FromDate = @FromDate,
	       ToDate = @ToDate,
	       IsActive = @IsActive,
	       CRMUnsubscribeType = @CRMUnsubscribeType,
	       ModifiedDate = GETDATE(),
	       ModifiedBy = @ModifiedBy
	WHERE  ID = @ID      
	
