 @SenderID VARCHAR(500),                        
 @Message nVARCHAR(2000),                        
 @TemplateID BIGINT,                        
 @TemplateGroupID BIGINT,                        
 @IsUnicode BIT,                        
 @MailReplyTo nVARCHAR(500),                        
 @MailSubject nVARCHAR(500),                        
 @MailContent nVARCHAR(MAX),                        
 @TrackResponse nVARCHAR(500),                        
 @TrackShortURL NVARCHAR(100),                        
 @UnsubscribePage nVARCHAR(500),                        
 @UnsubscribeShortURL NVARCHAR(100),                        
 @Tags VARCHAR(500),                        
 @IsRunAfter BIT,                        
 @IsSchedule BIT,                        
 @ScheduleID BIGINT,                        
 @NextExecuteDateTime VARCHAR(50),                        
 @ModifiedBy BIGINT,                        
 @ExpiryDate VARCHAR(50),                        
 @EventsName VARCHAR(500),                        
 @ApplicabiltyGroupList VARCHAR(500),                        
 @ExclusionsGroupList VARCHAR(500),                        
 @NotificationEmail VARCHAR(250),                        
 @SuccessNotificationEmail VARCHAR(250),                        
 @FailureNotificationEmail VARCHAR(250),                        
 @IsEnding BIT,                        
 @IsRecurring BIT,                        
 @TemplateGroupSequence INT,                        
 @IsNeverExpire BIT,                    
 @IsSurplusExclusions Bit,                  
 @MediumSMSOrMail varchar(50),            
 @FromMailID nvarchar(500),
 @templatePrimaryIDFromDLTGrouplist bigint                          
AS                        
BEGIN                        
                      
if(@ExpiryDate='')                      
     Begin                      
      set @ExpiryDate = null                      
     End     
                     
     Declare @DLTTemplateID nvarchar(200) = ''       
  
     if(@MediumSMSORMail = 'SMS' and @TemplateID <> 0 )  
    Begin  
     select top 1 @DLTTemplateID = isnull(DLT_TemplateID,'') from UserMailTemplate(nolock) where ID = @TemplateID        
    End   
     else if(@MediumSMSORMail = 'SMS' and @templatePrimaryIDFromDLTGrouplist <> 0)
     Begin
	    select top 1 @DLTTemplateID = isnull(DLT_TemplateID,'') from UserMailTemplate(nolock) where ID = @templatePrimaryIDFromDLTGrouplist 
	 End
    
                
 UPDATE UserCampaignMaster                        
 SET    CampaignName = @CampaignName,                        
        IsEventBased = @IsEventBased,                        
        IsScheduled = @IsScheduled,                        
        Applicabilty = @Applicabilty,                        
        ExclusionsNumber = @ExclusionsNumber,                        
        Exclusions = @Exclusions,                        
        InclusionsNumber = @InclusionsNumber,                        
        AccountUsed = @AccountUsed,                        
        SenderID = @SenderID,                        
        [Message] = @Message,                        
        TemplateID = @TemplateID,                        
        TemplateGroupID = @TemplateGroupID,                        
        IsUnicode = @IsUnicode,                        
        MailReplyTo = @MailReplyTo,                        
        MailSubject = @MailSubject,                        
        MailContent = @MailContent,                        
        TrackResponse = @TrackResponse,                        
        TrackShortURL = @TrackShortURL,                        
        UnsubscribePage = @UnsubscribePage,                        
        UnsubscribeShortURL = @UnsubscribeShortURL,                        
        Tags = @Tags,                        
        IsRunAfter = @IsRunAfter,              
        IsSchedule = @IsSchedule,                        
        ScheduleID = @ScheduleID,                        
              
        --NextExecuteDateTime =  @NextExecuteDateTime,                        
        NextExecuteDateTime =  dbo.[fn_getISTtimefromusertime](ParentID,@NextExecuteDateTime),                        
        ModifiedOn = GETDATE(),                        
        ModifiedBy = @ModifiedBy,              
              
        --ExpiryDate = @ExpiryDate,                        
        ExpiryDate = dbo.[fn_getISTtimefromusertime](ParentID,@ExpiryDate),      
       
        EventsName = @EventsName,                        
        ApplicabiltyGroupList = @ApplicabiltyGroupList,                        
        ExclusionsGroupList = @ExclusionsGroupList,                        
        NotificationMail = @NotificationEmail,                        
        SuccessNotificationEmail = @SuccessNotificationEmail,                        
        FailureNotificationEmail = @FailureNotificationEmail,                        
        IsRecurring = @IsRecurring,                        
        IsEnding = @IsEnding,                        
        TemplateGroupSequence = @TemplateGroupSequence,                        
        IsNeverExpire = @IsNeverExpire,                    
        IsSurplusExclusions = @IsSurplusExclusions,                  
        Medium = @MediumSMSOrMail,              
        FromMailID = @FromMailID,  
  DLTTemplateID = @DLTTemplateID                      
 WHERE  ID = @ID                              
                         
         
exec usp_updatevoicecampaignroute @ID                    
                         
 UPDATE UserCampaignSettings                        
 SET    NAME = @CampaignName                        
 WHERE  UserCampaignMasterID = @ID         
       
 if (select isschedule from UserCampaignMaster where id=@id)=1      
  begin      
  create table #temp(campaignid bigint,nextexecution datetime)      
  insert into #temp(campaignid,nextexecution)      
  exec usp_getNextScheduleDate @id      
  update u set NextExecuteDateTime=dbo.fn_getISTtimefromusertime(Createdby,isnull(nextexecution,getdate())) from UserCampaignMaster u join #temp t on u.id=t.campaignid      
  where u.id=@ID      
  drop table #temp      
  end                      
                 
 SELECT 'Success'                        
END 


GO

