   Procedure: [dbo].[usp_UpdateUserEnquiryStages]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------------------------------

CREATE   PROCEDURE [dbo].[usp_UpdateUserEnquiryStages]
    @EnquiryID BIGINT,
    @StageID NVARCHAR(40),
    @Remark NVARCHAR(MAX) = NULL,
    @ReminderDate NVARCHAR(MAX) = NULL
AS
BEGIN
    -- Declare variables
    DECLARE @UpdateCount INT;

    -- Begin TRY block
    BEGIN TRY
        -- Update the UserEnquiry table
        UPDATE UserEnquiry
        SET 
            StagesId = @StageID,
            Stages = @StageID,
            Remark = @Remark,
            ReminderDate = @ReminderDate
        WHERE 
            EnquiryID = @EnquiryID;

        -- Get the count of updated rows
        SET @UpdateCount = @@ROWCOUNT;

        -- Return the update count as a result set
        SELECT @UpdateCount AS UpdateCount;
    END TRY

    -- Begin CATCH block to handle errors
    BEGIN CATCH
        exec usp_InsertErrorInfo   
    END CATCH;
END;



GO

/* ============================================================
   Procedure: [dbo].[Usp_UpdateUserfilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_UpdateUserfilter] --5013,3       
(@userid int,        
@userfilter int)        
as        
Begin        
Declare @type int        
Declare @Reseller bigint        
select @type=[type],@Reseller=M_ID from user_detail where user_id=@userid        
        
IF @type=0        
BEGIN        
update user_detail set filtermode=@userfilter where user_id=@userid        
select 'UserFilter Updated Successfully'        
End        
ELSE        
BEGIN        
declare @rowcount bigint        
select @Reseller=reseller_id from reseller_detail where user_id=@userid        
Declare @Tempval bigint        
set @rowcount=0        
Declare @Temptable table        
(        
reseller bigint        
)        
        
Declare @TemptableAll table        
(        
reseller bigint        
)        
        
Declare @TemptableTemp table        
(        
reseller bigint        
)        
insert into @Temptable        
select @Reseller        
insert into @TemptableAll        
select @Reseller        
        
Begin        
while @rowcount<50        
Begin        
print @rowcount        
        
insert into @TemptableAll        
select reseller_id from reseller_detail where m_id in        
( select reseller from @Temptable)        
        
insert into @TemptableTemp        
select reseller_id from reseller_detail where m_id in        
( select reseller from @Temptable)        
        
delete from @Temptable        
        
insert into @Temptable        
select * from @TemptableTemp        
set @Tempval=@@rowcount        
        
delete from @TemptableTemp        
        
set @rowcount=@rowcount+1        
if @Tempval=0        
Begin        
break        
End        
END        
-- select * from @TemptableAll order by reseller asc       
update user_detail set filtermode=@userfilter where user_id=@userid        
---     
----update user_detail set filtermode=@userfilter where M_ID IN        
----(SELECT reseller FROM @TemptableAll)        
select 'UserFilter Updated Successfully'        
End        
END        
END   
  
  


GO

