CREATE   PROCEDURE dbo.usp_UpdateUserGroupDetails  

 @ID BIGINT,  

 @GroupName VARCHAR(50),  

 @CreatedBy BIGINT  

AS  

BEGIN 

 Declare @ParenID Bigint = 0;

 select @ParenID = ParentID  from UserTemplateGroupDetails where ID = @ID;

 if(not exists(select 'x' from UserTemplateGroupDetails where ParentID = @ParenID and GroupName = @GroupName and ID <> @ID))

  Begin

		 UPDATE UserTemplateGroupDetails  

		 SET    -- ID -- this column value is auto-generated  

				GroupName = @GroupName,  

				CreatedOn = GETDATE(),  

				CreatedBy = @CreatedBy  

		 WHERE  ID = @ID  

		   

		 SELECT 'Success'

   End

  Else

    Begin

       select 'Already Exists'

    End 

END 


GO

