/* ============================================================
   Procedure: [dbo].[usp_updateuseridinusermails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_updateuseridinusermails]  
as  
begin  
    declare @count int=(select count(1) from usermails(nolock) u join  UserMailbox (nolock) 
   AS um on u.toemail=um.ForwadingEmail OR u.ToEmail = um.EmailID  
   join Price_UserSubscriptionDetails p on p.userid=um.parentid
  where u.userid=0 and p.planenddate>=GETDATE() and isnewplan=1)  
  while @count>0  
  begin  
  RETRY:  
  begin try  
  begin tran  
  update u1 set userid=parentid,isfiltered=0 from (select top 100 u.userid,u.isfiltered,um.parentid from usermails(nolock) u join  UserMailbox(nolock) AS um on u.toemail=um.ForwadingEmail  
  OR u.ToEmail = um.EmailID 
   join Price_UserSubscriptionDetails p on p.userid=um.parentid
  where u.userid=0 and p.planenddate>=GETDATE() and isnewplan=1 order by u.id desc) u1  
  set @count=@count-100  
  --select @count,getdate()  
  commit  
  end try  
  begin catch  
  IF @@TRANCOUNT>0                                          
ROLLBACK                                          
--EXECUTE USP_INSERTERRORINFO;     
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number    
BEGIN    
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms    
GOTO RETRY -- Go to Label RETRY    
END                                               
  end catch  
  
  end  
  end 


GO

