/* ============================================================
   Procedure: [dbo].[usp_UpdateUserMailsSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_UpdateUserMailsSettings]
	@ParentID BIGINT,
	@ID BIGINT,
	@MailName VARCHAR(50),
	@EmailAddress VARCHAR(250),
	@ModifiedBy BIGINT
AS
BEGIN
	IF (
	       NOT EXISTS(
	           SELECT 'x'
	           FROM   UserMailsSettings
	           WHERE  (MailName = @MailName OR EmailAddress = @EmailAddress)
	                  AND ID <> @ID
	                  AND ParentID = @ParentID
	       )
	   )
	BEGIN
	    UPDATE UserMailsSettings
	    SET    MailName = @MailName,
	           EmailAddress = @EmailAddress,
	           ModifiedOn = GETDATE(),
	           ModifiedBy = @ModifiedBy
	    WHERE  ID = @ID    
	    
	    SELECT 'Success'
	END
	ELSE
	BEGIN
	    SELECT 'Already Exists'
	END
END



