CREATE   PROCEDURE dbo.usp_UpdateUserMailTemplates @ID BIGINT
	,@MailContent NVARCHAR(MAX)
	,@CreatedBy BIGINT
	,@MailContentEditable NVARCHAR(MAX)
	,@IsUnicode BIT
AS
BEGIN
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = ParentID
	FROM UserMailTemplate
	WHERE ID = @ID

	UPDATE UserMailTemplate
	SET MailContent = @MailContent
		,CreatedOn = GETDATE()
		,CreatedBy = @CreatedBy
		,MailContentEditable = @MailContentEditable
		,IsUnicode = @IsUnicode
		,body_disp = @MailContentEditable
	WHERE ID = @ID

	SELECT 'Success'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailTemplate(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
