/* ============================================================
   Procedure: [dbo].[usp_UpdateUserMailTemplates_DLT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
CREATE   PROCEDURE [dbo].[usp_UpdateUserMailTemplates_DLT]              
 @ID BIGINT,              
 @MailContent NVARCHAR(MAX),              
 @CreatedBy BIGINT,          
 @MailContentEditable NVARCHAR(MAX),          
 @IsUnicode bit,  
 @SenderIDs nvarchar(max),  
 @MessageType nvarchar(500)              
AS              
BEGIN              
 DECLARE @ParentID BIGINT = 0  
 Declare @DLTTemplateID nvarchar(200) = ''                 
               
 SELECT @ParentID = ParentID , @DLTTemplateID = ISNULL(DLT_TemplateID,'')            
 FROM   UserMailTemplate              
 WHERE  ID = @ID                   
               
               
               
 UPDATE UserMailTemplate              
 SET    MailContent = @MailContent,              
        CreatedOn = GETDATE(),              
        CreatedBy = @CreatedBy,              
        MailContentEditable = @MailContentEditable ,          
        IsUnicode = @IsUnicode,       
        body_disp = @MailContentEditable,  
  MessageType = @MessageType              
 WHERE  ID = @ID                    
               
  if(rtrim(ltrim(@DLTTemplateID)) <> '')  
    Begin  
    delete from DLT_TemplateSenderMapping      
     where      
     DLT_TemplateID = @DLTTemplateID and CreatedBy = @CreatedBy      
      and       
    SenderID       
     not in    
     (      
   select CAST(isnull(value,0) as bigint)        
      from dbo.fn_Split(@SenderIDs,'#')      
   )      
      
  insert into DLT_TemplateSenderMapping      
    (      
  DLT_TemplateID      
    ,SenderID      
    ,CreatedOn      
    ,CreatedBy      
   )      
   select @DLTTemplateID,CAST(isnull(splt.value,0) as bigint),getdate(),@CreatedBy      
   from dbo.fn_Split(@SenderIDs,'#') splt      
   where (      
    CAST(isnull(splt.value,0) as bigint)      
     not in (select SenderID from DLT_TemplateSenderMapping where DLT_TemplateID = @DLTTemplateID  and CreatedBy = @CreatedBy )      
   )       
               
    End        
               
               
 SELECT 'Success'             
END 


GO

