/* ============================================================
   Procedure: [dbo].[usp_UpdateUserPriority]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  /****************************************************************************  
  
SP_Name        : [usp_UpdateUserPriority]                     
Author         : Mukesh 
Created ON     : 25/12/2009 04:30 PM        
Version        : 1  
Alter BY       :          
Alter Date     :   
Location       :    
SP Description : Proc is used to update records into Messagestorage Based 
                 onto different flag condition
***************************************************************************/
  
  
CREATE   PROC [dbo].[usp_UpdateUserPriority]      
@UserId int=0,                                                       
@SenderId nchar(20)='' ,  
@Priority tinyint=0 ,  
@BatchId Bigint=0 ,  
@mobile varchar(50) ='',  
@Flag tinyint=0  
As  
Begin  
SET NOCOUNT ON  
Begin Try  
if @flag=1  
  Update Messagestorage with (Rowlock) SET Priority=@Priority Where U_ID=@UserId  
ELSE if @flag=2  
  Update Messagestorage with (Rowlock)  SET Priority=@Priority Where U_ID=@UserId and senderId=@senderId  
ELSE if @flag=3  
  Update Messagestorage with (Rowlock) SET Priority=@Priority Where U_ID=@UserId and senderId=@senderId and MessageBatchID=@BatchId  
ELSE if @flag=4  
  Update Messagestorage with (Rowlock) SET Priority=@Priority Where U_ID=@UserId and senderId=@senderId and MessageBatchID=@BatchId AND Mobile=@Mobile  
End Try  
Begin Catch  
if @@trancount>0  
Rollback  
End Catch  
End  



GO

