   Procedure: [dbo].[usp_UpdateUserSchedules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_UpdateUserSchedules @ID BIGINT    
 ,@SceduleName VARCHAR(200)    
 ,@IsOnce BIT    
 ,@OnceHours VARCHAR(200)    
 ,@OnceMins VARCHAR(200)    
 ,@IsDaily BIT    
 ,@DailyHours VARCHAR(200)    
 ,@DailyMins VARCHAR(200)    
 ,@IsWeekly BIT    
 ,@WeeklyDayNo VARCHAR(200)    
 ,@WeeklyHours VARCHAR(200)    
 ,@WeeklyMins VARCHAR(200)    
 ,@IsMonthly BIT    
 ,@MonthlyHours VARCHAR(200)    
 ,@MonthlyMins VARCHAR(200)    
 ,@MonthNo VARCHAR(200)    
 ,@MonthlyDayNo VARCHAR(400)    
 ,@ModifiedBy VARCHAR(200)    
AS    
BEGIN    
 UPDATE UserSchedules    
 SET SceduleName = @SceduleName    
  ,IsOnce = @IsOnce    
  ,OnceHours = @OnceHours    
  ,OnceMins = @OnceMins    
  ,IsDaily = @IsDaily    
  ,DailyHours = @DailyHours    
  ,DailyMins = @DailyMins    
  ,IsWeekly = @IsWeekly    
  ,WeeklyDayNo = @WeeklyDayNo    
  ,WeeklyHours = @WeeklyHours    
  ,WeeklyMins = @WeeklyMins    
  ,IsMonthly = @IsMonthly    
  ,MonthlyHours = @MonthlyHours    
  ,MonthlyMins = @MonthlyMins    
  ,MonthNo = @MonthNo    
  ,MonthlyDayNo = @MonthlyDayNo    
  ,ModifiedOn = GETDATE()    
  ,ModifiedBy = @ModifiedBy    
 WHERE ID = @ID    
    
 DECLARE @CreatedBy BIGINT = (    
   SELECT CreatedBy    
   FROM UserSchedules    
   WHERE ID = @ID    
   )    
 --Rescheduling           
 DECLARE @ScheduleID BIGINT    
 DECLARE @NextExecutionDate DATETIME    
 DECLARE @MyTable AS TABLE (    
  ScheduleID BIGINT    
  ,NextExecutionDate DATETIME    
  )    
    
 INSERT INTO @MyTable    
 EXEC usp_getNextScheduleDateSchedules @ID    
    
 SELECT @ScheduleID = ScheduleID    
  ,@NextExecutionDate = NextExecutionDate    
 FROM @MyTable    
    
 UPDATE UserCampaignMaster    
 SET NextExecuteDateTime = @NextExecutionDate    
 WHERE ScheduleID = @ScheduleID    
    
 SELECT 'Success'    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *     
   FROM UserSchedules(NOLOCK)    
   WHERE ID = @ID    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy    
  ,@Activity_type = 'Updt_Cmpgn_Schdls'    
  ,@ActionType = 'U'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'UserSchedules'    
END 


