SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_UpdateUserSegmentOnMode](
    @userId BIGINT,
    @Id BIGINT,
    @mode NVARCHAR(100),
    @JsonData NVARCHAR(MAX) = NULL
)
AS
BEGIN
    DECLARE @parentId BIGINT,
            @Status NVARCHAR(50),
            @SegmentName NVARCHAR(255),
            @LogicalOperator NVARCHAR(50);

    SELECT @parentId = ParentId
    FROM User_Detail
    WHERE user_Id = @userId;

    IF (@JsonData IS NOT NULL AND @JsonData != '')
    BEGIN
        SET @Status = JSON_VALUE(@JsonData, '$.Status');
        SET @SegmentName = JSON_VALUE(@JsonData, '$.SegmentName');
        SET @LogicalOperator = JSON_VALUE(@JsonData, '$.LogicalOperator');
    END
IF (@mode = 'updateStatus')
    BEGIN
        UPDATE tbl_UserSegments
        SET Status = @Status, 
            UpdatedAt = GETDATE(),
			UpdatedBy=@userId
        WHERE Id = @Id AND ParentId = @parentId;
    END
   
END;



