            --        and Isnumeric(uere.CountryCode) = 1            
            --        AND ISNULL(uere.CountryCode, '') <> ''           
            --                       )            
        )             
        and  (ISNULL(uere.EmailID, '') <> '')    
        union    
SELECT uere.EnquiryID         
FROM   UserEnquiryRawEntries  AS uere            
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) = 10 and ISNUMERIC(uere.MobileNo) = 1          
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)       
                        --AND (PATINDEX('%[a-zA-Z0-9]%',MobileNo)=1)       
            -- and uere.CountryCode in (select CountryCode from M_Country)         
                    
            --AND (            
            --        ISNULL(uere.MobileNo, '') <> ''           
            --        and Isnumeric(uere.CountryCode) = 1            
            --        AND ISNULL(uere.CountryCode, '') <> ''           
            --                       )            
        )     
        and  (ISNULL(uere.EmailID, '') = '')    
        union    
SELECT uere.EnquiryID       
FROM   UserEnquiryRawEntries  AS uere            
 WHERE  isnull(uere.Mobileno,'') ='' and uere.EmailID<> '') as tbl    
            
            
            
            
               
 select enquiryid into  #TempInvalidData from (select enquiryid from UserEnquiryRawEntries where enquiryid not in(SELECT uere.EnquiryID           
FROM   UserEnquiryRawEntries  AS uere            
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) = 10 and ISNUMERIC(uere.MobileNo) = 1          
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)       
             )             
        and  (ISNULL(uere.EmailID, '') <> '')    
        union    
SELECT uere.EnquiryID         
FROM   UserEnquiryRawEntries  AS uere            
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) = 10 and ISNUMERIC(uere.MobileNo) = 1          
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)       
                              )     
        and  (ISNULL(uere.EmailID, '') = '')    
        union    
SELECT uere.EnquiryID       
FROM   UserEnquiryRawEntries  AS uere            
 WHERE  isnull(uere.Mobileno,'') ='' and uere.EmailID<> '')) as tbl        
         
 --SELECT uere.EnquiryID, (ISNULL(uere.CountryCode,'')+' '+ ISNULL(uere.MobileNo,'') +' '+ ISNULL(uere.EmailID,'')) as CauseInvalid INTO                 
 --#TempInvalidData            
 --FROM   UserEnquiryRawEntries  AS uere            
 -- WHERE  (            
 --           LEN(uere.MobileNo) <> 10            
 --           OR LEN(uere.MobileNo1) <> 10            
 --           OR LEN(uere.MobileNo2) <> 10            
 --       )            
 --       or (            
 --               ISNULL(uere.MobileNo, '') = ''            
 --               AND ISNULL(uere.EmailID, '') = ''        
                        
                            
 --           )            
 --       AND (            
 --               (            
 --                   ISNULL(uere.MobileNo, '') = ''            
 --                   AND ISNULL(uere.CountryCode, '') = ''            
 --               )            
 --               AND (            
 --                       ISNULL(uere.MobileNo1, '') = ''            
--                       AND ISNULL(uere.CountryCode1, '') = ''            
 --                   )            
 --               AND (            
 --                       ISNULL(uere.MobileNo2, '') = ''            
 --                       AND ISNULL(uere.CountryCode2, '') = ''            
 --                   )            
 --           )             
             
          
               
             
 UPDATE kd            
 SET    kd.IsValid = 1          
 FROM   UserEnquiryRawEntries AS kd            
        INNER JOIN #TempvalidData tt            
             ON  kd.EnquiryID = tt.EnquiryID            
             
             
             
             
             
 UPDATE kd            
 SET    kd.IsInValid = 1 --,kd.CauseInvalid =tt.CauseInvalid            
 FROM   UserEnquiryRawEntries AS kd            
        INNER JOIN #TempInvalidData tt            
             ON  kd.EnquiryID = tt.EnquiryID            
             
             
             
             
             
             
             
 DROP TABLE #TempvalidData            
             
 DROP TABLE #TempInvalidData            
END       
      
      
      
