/* ============================================================
   Procedure: [dbo].[usp_UpdateValidInvalidDataNew1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_UpdateValidInvalidDataNew1   
@MinId bigint =null,  
@MaxId bigint=null                   
AS                    
BEGIN       
declare @enqid bigint=(select max(enquiryid) from  UserEnquiryRawEntries(nolock) where userenquiryid is not null)           
      
select enquiryid into  #TempvalidData from (SELECT uere.EnquiryID                   
FROM   UserEnquiryRawEntries(nolock)  AS uere                    
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) >= 5 and LEN(uere.MobileNo) <= 15  and ISNUMERIC(uere.MobileNo) = 1                  
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)               
                        --AND (PATINDEX('%[a-zA-Z0-9]%',MobileNo)=1)               
            -- and uere.CountryCode in (select CountryCode from M_Country)                 
                            
            --AND (                    
            --        ISNULL(uere.MobileNo, '') <> ''                   
            --        and Isnumeric(uere.CountryCode) = 1                    
            --        AND ISNULL(uere.CountryCode, '') <> ''                   
            --                       )                    
        )                     
        and  (ISNULL(uere.EmailID, '') <> '') and EnquiryID>@enqid           
        union            
SELECT uere.EnquiryID                 
FROM   UserEnquiryRawEntries(nolock)  AS uere                    
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) >= 5 and LEN(uere.MobileNo) <= 15 and ISNUMERIC(uere.MobileNo) = 1                  
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)               
                        --AND (PATINDEX('%[a-zA-Z0-9]%',MobileNo)=1)               
            -- and uere.CountryCode in (select CountryCode from M_Country)                 
                            
            --AND (                    
            --        ISNULL(uere.MobileNo, '') <> ''                   
            --        and Isnumeric(uere.CountryCode) = 1                    
            --        AND ISNULL(uere.CountryCode, '') <> ''                   
            --                       )                    
        )             
        and  (ISNULL(uere.EmailID, '') = '')  and EnquiryID>@enqid             
        union            
SELECT uere.EnquiryID               
FROM   UserEnquiryRawEntries  AS uere                    
 WHERE  isnull(uere.Mobileno,'') ='' and uere.EmailID<> ''  and EnquiryID>@enqid ) as tbl            
                    
 --select * from #TempvalidData                   
                    
                    
                       
 select enquiryid into  #TempInvalidData from (select enquiryid from UserEnquiryRawEntries where enquiryid not in(SELECT uere.EnquiryID                   
FROM   UserEnquiryRawEntries  AS uere                    
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) >= 5 and LEN(uere.MobileNo) <= 15 and ISNUMERIC(uere.MobileNo) = 1                  
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)               
             )                     
        and  (ISNULL(uere.EmailID, '') <> '')   and EnquiryID>@enqid            
        union            
SELECT uere.EnquiryID                 
FROM   UserEnquiryRawEntries  AS uere                    
 WHERE  (   uere.Mobileno <>'' and LEN(uere.MobileNo) >= 5 and LEN(uere.MobileNo) <= 15 and ISNUMERIC(uere.MobileNo) = 1                  
            and REPLACE(uere.CountryCode,'+','')  in (select CountryCode from M_Country)               
                              )             
        and  (ISNULL(uere.EmailID, '') = '')   and EnquiryID>@enqid            
        union            
SELECT uere.EnquiryID               
FROM   UserEnquiryRawEntries  AS uere                    
 WHERE  isnull(uere.Mobileno,'') ='' and uere.EmailID<> '')  and EnquiryID>@enqid  ) as tbl       
       
       
 --select * from #TempvalidData               
                 
 --SELECT uere.EnquiryID, (ISNULL(uere.CountryCode,'')+' '+ ISNULL(uere.MobileNo,'') +' '+ ISNULL(uere.EmailID,'')) as CauseInvalid INTO                         
 --#TempInvalidData                    
 --FROM   UserEnquiryRawEntries  AS uere                    
 -- WHERE  (                    
 --       LEN(uere.MobileNo) <> 10                    
 --           OR LEN(uere.MobileNo1) <> 10                    
 --           OR LEN(uere.MobileNo2) <> 10       
 --       )                    
 --       or (                    
 --               ISNULL(uere.MobileNo, '') = ''                    
 --               AND ISNULL(uere.EmailID, '') = ''                
                                
                                    
 --           )                    
 --       AND (                    
 --               (                    
 --                   ISNULL(uere.MobileNo, '') = ''                    
 --                   AND ISNULL(uere.CountryCode, '') = ''                    
 --               )                    
 --               AND (                    
 --                       ISNULL(uere.MobileNo1, '') = ''                    
--                       AND ISNULL(uere.CountryCode1, '') = ''                    
 --                   )                    
 --               AND (                    
 --                       ISNULL(uere.MobileNo2, '') = ''                    
 --                       AND ISNULL(uere.CountryCode2, '') = ''                    
 --                   )                    
 --           )                     
                     
                  
 declare @c int=(select COUNT(1) from #TempvalidData)                      
      
while @c>0      
begin                     
 UPDATE kd                    
 SET    kd.IsValid = 1                  
 FROM   UserEnquiryRawEntries AS kd                    
        INNER JOIN (select top 1000 enquiryid from #TempvalidData order by enquiryid) tt                    
             ON  kd.EnquiryID = tt.EnquiryID  OPTION (MAXDOP 1)                
 delete tt From (select top 1000 enquiryid from #TempvalidData order by enquiryid) tt      
 set @c=@c-1000      
 end                   
                     
set @c= (select COUNT(1) from #TempInvalidData)                     
                     
 while @c>0      
begin                    
 UPDATE kd                    
 SET    kd.IsInValid = 1 --,kd.CauseInvalid =tt.CauseInvalid                    
 FROM   UserEnquiryRawEntries AS kd                    
        INNER JOIN (select top 1000 enquiryid from #TempInvalidData  order by enquiryid) tt                    
             ON  kd.EnquiryID = tt.EnquiryID  OPTION (MAXDOP 1)        
 delete tt From (select top 1000 enquiryid from #TempinvalidData order by enquiryid) tt      
 set @c=@c-1000                
 end                    
                     
                     
                     
                     
                     
                     
 DROP TABLE #TempvalidData                    
                     
 DROP TABLE #TempInvalidData                    
END               
              
              
              
--SELECT PATINDEX('%[a-zA-Z0-9]%',MobileNo),MobileNo,EmailID FROM UserEnquiryRawEntries              
              
              
--select  LEN(ltrim(rtrim(uere.MobileNo))) = 10    FROM UserEnquiryRawEntries


GO

