/* ============================================================
   Procedure: [dbo].[usp_UpdateWBatchInfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UpdateWBatchInfo](
	@batchId bigint = 0,
	@status int = 0,
	@error_description nvarchar(max) = ''
)
as
begin
	
	--declare 
	--	@batchId bigint = 163857426,
	--	@status int = 3,
	--	@error_description nvarchar(max) = 'No Recepient Found'

	update wbatchinfo set 
		IsProcess = @status,
		BatchProcessTime = case when @status = 2 then getdate() else BatchProcessTime end,
		BatchProcessComplete = case when @status <> 2 then getdate() else BatchProcessComplete end,
		wb_error_description = @error_description
	where batchId = @batchId

	if(isnull(@error_description, '') <> '')
	begin
		begin try
			declare @entityName nvarchar(25), @entityId bigint, @eventName nvarchar(255), @context nvarchar(25), 
				@activityid bigint, @campaignid bigint, @contacttype nvarchar(255), @parentid bigint, @templateId bigint, @templateName nvarchar(255),
				@eventDescription nvarchar(max) = '', @scheduleDateTime datetime = getdate(), @ActivityJson nvarchar(max) = '{}'

			select @activityid = trigerringactivityid, @campaignid = campaignid, @templateId = templateid, @scheduleDateTime = BatchInsertTime
				from mysms.dbo.WBatchInfo where batchid=@BatchId          

			select @entityname = a.context, @contacttype = u.ContactType, @parentid = u.ParentID 
				from activitymaster(nolock) a join UserCampaignMaster(nolock) u on u.eventid=a.ID  where u.ID =  @campaignid 
			
			select @templateName = templatename from [10.0.0.135].[MySMSConversations].[dbo].convtemplates with (nolock) where id = @templateId
		
			if @entityname='enquiry'
			begin
				select @entityid=enquiryid from mysms.dbo.tbl_enquiryEventHistory(nolock) where HistoryID=@activityid
				select @eventName = 'WhatsApp message failed for enquiry'
				select @eventDescription = concat('WhatsApp template message failed which is sent on ', format(@scheduleDateTime, 'dd-MMM-yyyy HH:mm:ss'), 
						' with reason (', @error_description, ')')

					
			end

			if @entityname='lead'
			begin
				select @entityid=LeadID from mysms.dbo.tbl_LeadEventHistory(nolock) where HistoryID=@activityid    
				select @eventName = 'WhatsApp message failed for lead'
				select @eventDescription = concat('WhatsApp template message failed which is sent on ', format(@scheduleDateTime, 'dd-MMM-yyyy HH:mm:ss'), 
						' with reason (', @error_description, ')')
			end

			print concat('@entityname => ', @entityname)
			print concat('@entityId => ', @entityId)

			exec UspSaveEntityActivity_withid
				@entityname = @entityName,    
				@EntityID = @entityId,
				@UserID = @parentid,
				@ParentID = @parentid,
				@EventDescription = @eventDescription,
				@EventName = @eventName,
				@reftables = 'WBatchInfo', 
				@refid = @BatchId
     

		end try
		begin catch
			exec usp_insertErrorInfo
		end catch

	end

end



GO

