/* ============================================================
   Procedure: [dbo].[usp_updateWebhookDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------

CREATE   PROCEDURE usp_updateWebhookDetails  
(  
    @UserId bigint,  
    @WebhookId bigint,  
    @WebhookURL nvarchar(max),  
    @Method varchar(50),  
    @ContentType nvarchar(max),  
    @Params nvarchar(max),  
    @ModuleCode varchar(100),  
    @ErrorMessage nvarchar(max) OUTPUT  
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Update data in Tbl_CB_WebhookSummary table  
        UPDATE Tbl_CB_WebhookSummary  
        SET WebhookURL = @WebhookURL,  
            Method = @Method,  
            ContentType = @ContentType,  
            Params = @Params,  
            ModuleCode = @ModuleCode,  
            ModifiedDate = GETDATE(),  
            ModifiedBy = @UserId  
        WHERE WebhookID = @WebhookId;  
  
        -- Check if any row was updated  
        IF @@ROWCOUNT = 0  
        BEGIN  
            SET @ErrorMessage = 'No record found with the given WebhookId.';  
        END  
        ELSE  
        BEGIN  
            -- Set success message  
            SET @ErrorMessage = 'Data updated successfully.';  
        END  
    END TRY  
    BEGIN CATCH  
        -- Rollback transaction if error occurs  
        IF @@TRANCOUNT > 0  
            ROLLBACK;  
  
        -- Get error message  
        SET @ErrorMessage = ERROR_MESSAGE();  
    END CATCH  
END;  




GO

/* ============================================================
   Procedure: [dbo].[usp_UpdateWebhookRestbl_CustomButton]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------

CREATE   PROCEDURE usp_UpdateWebhookRestbl_CustomButton  
    @JsonData NVARCHAR(MAX)  
AS  
BEGIN  
    SET NOCOUNT ON;  
    BEGIN TRY  
        -- Declare variables to hold parsed values  
        DECLARE @EntityID BIGINT;  
        DECLARE @BatchID BIGINT;  
        DECLARE @WebhookURL NVARCHAR(MAX);  
  DECLARE @EntityType NVARCHAR(MAX);  
  
        -- Parse JSON data and extract values  
        SELECT   
            @EntityID = JSON_VALUE(@JsonData, '$.EntityID'),  
            @BatchID = JSON_VALUE(@JsonData, '$.BatchID'),  
            @WebhookURL = JSON_VALUE(@JsonData, '$.url'),  
    @EntityType = JSON_VALUE(@JsonData, '$.EntityType');  
  
        -- Update the IsProcessed field to 1 based on the extracted values  
        UPDATE tbl_cb_webhook_restbl  
        SET IsProcessed = 1  
        WHERE   
            EntityID = @EntityID   
            AND BatchID = @BatchID  
            AND WebhookURL = @WebhookURL  
   AND Entitytype = @EntityType;  
  
        -- Check if any rows were affected  
        IF @@ROWCOUNT = 0  
        BEGIN  
            RAISERROR('No rows updated. Please check the input parameters.', 16, 1);  
        END  
        ELSE  
        BEGIN  
            PRINT 'Update successful';  
        END  
    END TRY  
    BEGIN CATCH  
        -- Handle any errors that occur during the update  
        DECLARE @ErrorMessage NVARCHAR(4000);  
        DECLARE @ErrorSeverity INT;  
        DECLARE @ErrorState INT;  
  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH  
END  




GO

