  @IsActive bit,          
  @UserID bigint,             
  @CampaignID bigint,           
  @TimeBeforeEvent int,        
  @TimeUnit nvarchar(20),
  @MaxLimit int 
)          
as          
Begin      
begin try
 if(@TimeBeforeEvent = 0)    
 begin    
  set @TimeBeforeEvent = null    
    end    
            
    update UserCampaignMaster set AccountUsed = @AccountUsed,TemplateID = @TemplateID,      
          ContactType = @ContactType,IsActive = @IsActive           
             , ModifiedOn = GETDATE(),ModifiedBy = @UserID,TimeBeforeEvent = @TimeBeforeEvent , TimeUnit = @TimeUnit ,maxlimit=@MaxLimit where id = @CampaignID          
      
    --  update brdcst set brdcst.FieldValue = temptbl.FieldValue from       
    --[MySMSConversations].[dbo].[tbl_wsap_BroadcastFieldsValue](nolock)   as brdcst         
    --    join       
    --@TBL_BroadcastFieldValues  as temptbl  on brdcst.TemplateFieldId = temptbl.TemplateFieldId          
    --where brdcst.Cmpgn_ID = @CampaignID      
      
    --delete from [MySMSConversations].[dbo].[tbl_wsap_BroadcastFieldsValue] where Cmpgn_ID = @CampaignID 
	DECLARE @deleteQuery NVARCHAR(MAX);

      SET @deleteQuery = '
      DELETE FROM [tbl_wsap_BroadcastFieldsValue] 
      WHERE Cmpgn_ID = ' + CAST(@CampaignID AS NVARCHAR(MAX)) + ';
      ';
      
      EXEC usp_clr_ExecuteRemoteQuery @deleteQuery;

   insert into [10.0.0.135].[MySMSConversations].[dbo].[tbl_wsap_BroadcastFieldsValue]  
  ( [BroadcastId], [TemplateFieldId], [FieldValue], [Cmpgn_ID], [FileName], mediaId )       
    select 0, [TemplateFieldId],[FieldValue],@CampaignID, [FileName], [MediaId] from @TBL_BroadcastFieldValues
        DECLARE @Query NVARCHAR(MAX);

  select 'Data Updated'           
          
END TRY
    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH

END; 



GO

