/* ============================================================
   Procedure: [dbo].[usp_upodateuseridiusermails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_upodateuseridiusermails
as
begin
    declare @count int=(select count(1) from usermails(nolock) u join  UserMailbox AS um on u.toemail=um.ForwadingEmail OR u.ToEmail = um.EmailID
  where u.userid=0)
  while @count>0
  begin
  update u1 set userid=parentid from (select top 1000 u.*,um.parentid from usermails(nolock) u join  UserMailbox AS um on u.toemail=um.ForwadingEmail
  OR u.ToEmail = um.EmailID
  where u.userid=0 order by id desc) u1
  set @count=@count-1000
  select @count,getdate()
  end
  end


GO

