/* ============================================================
   Procedure: [dbo].[usp_us_GetUserIdsBySegmentIds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_us_GetUserIdsBySegmentIds](
	@userSegmentIds nvarchar(255),
	@onlyParentId int  = 0
)
AS
begin
	
	--declare 
	--	@userSegmentIds nvarchar(255) = '4',
	--	@onlyParentId int  = 0

	declare 
		@ParentId bigint = 0

	drop table if exists #tblSegment
	create table #tblSegment (
		Id bigint,
		ParentId bigint, 
		UserId bigint,
		SegmentName nvarchar(255),
		ApplyTo nvarchar(25),
		IsProcess int default 0
	)

	insert into #tblSegment(Id, ParentId, UserId, SegmentName, ApplyTo)
	select Id, ParentId, UserId, SegmentName, ApplyTo from tbl_UserSegments(nolock) 
		where Status = 'active' and ID in (select [value] from string_split(@userSegmentIds, '#'))

	declare @Id bigint = 0, @fResellerId bigint = 0, @fParentId bigint = 0,  @UserId bigint = 0, @SegmentName nvarchar(255) = '', 
			@ApplyTo nvarchar(25) = '', @IsProcess int = '', @isRuleMatched bit = 0, @filterConditions nvarchar(max) = N'', @userIdsSql nvarchar(max) = N''

	drop table if exists #filterUser
	create table #filterUser(
		UserId bigint
	)

	while(exists(select 1 from #tblSegment(nolock) where IsProcess = 0))
	begin
		select top 1 @Id = Id, @fParentId = ParentId, @UserId = UserId, @SegmentName = SegmentName, @ApplyTo = ApplyTo 
			from #tblSegment where IsProcess = 0 

		SELECT @fResellerId = reseller_id FROM reseller_detail(nolock) where User_ID = @fParentId

		print concat('@fParentId => ',  @fParentId)
		print concat('@fResellerId => ', @fResellerId)

		begin try
		
		select @filterConditions = concat(  
				(CASE WHEN LEN(ISNULL(@filterConditions, '')) > 2 THEN CONCAT(' ', @ApplyTo, ' ') ELSE '' END),
                (CASE
                    WHEN c.TableName = 'MySMS.dbo.User_Detail'
                        THEN CONCAT('[ud].[', c.ColumnName, '] ', sc.OperatorSymbol, ' ', REPLACE(sc.ValuePlaceHolder, 'value', sc.FieldValue))
					WHEN c.TableName = 'MySMS.dbo.ve_UserSubscriptionDetails'
                       THEN CONCAT('[us].[', c.ColumnName, '] ', sc.OperatorSymbol, ' ', REPLACE(sc.ValuePlaceHolder, 'value', sc.FieldValue))
					WHEN c.TableName = 'MySMS.dbo.reseller_detail'
                       THEN CONCAT('[rd].[', c.ColumnName, '] ', sc.OperatorSymbol, ' ', REPLACE(sc.ValuePlaceHolder, 'value', sc.FieldValue))
                    ELSE '' END
				) ) 
		from tbl_SegmentConditions(nolock) sc
			inner join tbl_us_FilterColumnDetail(nolock) c on sc.FieldId = c.Id where SegmentID = @Id

		drop table if exists #filterQuery
		create table #filterQuery(
			TableName nvarchar(255),
			ColumnName nvarchar(255),
			OperatorSymbol nvarchar(255),
			ValuePlaceHolder nvarchar(255),
			FieldValue nvarchar(255)
		)
		insert into #filterQuery(TableName, ColumnName, OperatorSymbol, ValuePlaceHolder, FieldValue)
		select c.TableName, c.ColumnName, sc.OperatorSymbol, sc.ValuePlaceHolder, sc.FieldValue
			FROM tbl_SegmentConditions AS sc WITH (NOLOCK)  INNER JOIN tbl_us_FilterColumnDetail AS c WITH (NOLOCK) 
            ON sc.FieldId = c.Id WHERE sc.SegmentID = @Id;
		
		declare @IsViewUsed bit = 0
		if(exists(select 1 from #filterQuery where TableName = 'MySMS.dbo.ve_UserSubscriptionDetails'))
		begin
			set @IsViewUsed = 1
		end

		set @userIdsSql = concat( N'insert into #filterUser (UserId) ',
			N'select ud.User_ID from User_Detail(nolock) ud ',
				(case when @IsViewUsed = 1
								then  N'left join ve_UserSubscriptionDetails us on ud.User_ID = us.User_ID ' else  '' end),
				N'left join reseller_detail(NOLOCK) rd on ud.User_ID = rd.User_ID ',
				N'WHERE ud.M_ID = ', @fResellerId, N' AND 1 = (case when ', @onlyParentId, N' = 0 then 1 ',
				N'when ', @onlyParentId, N' = 1 and ud.User_ID = ud.ParentID then 1 else 0 end)', 
				( CASE WHEN isnull(@filterConditions, '') <> '' THEN CONCAT (' AND ', @filterConditions) ELSE '' END)
			);

		--insert into #filterUser (UserId)
		--select ud.User_ID from User_Detail(nolock) ud
		--	where [ud].[City] like '%New Delhi%'

		print concat('@filterConditions => ', @filterConditions)
		print concat('@userIdsSql => ', @userIdsSql)

		execute sp_executesql @userIdsSql

		end try
		begin catch
			exec usp_InsertErrorInfo
		end catch

		update #tblSegment set IsProcess = 1 where Id = @Id
		select @Id = 0, @fParentId = 0,  @UserId = 0, @SegmentName = '', @ApplyTo  = '', @IsProcess = '', @filterConditions = ''

	end

	select * from #filterUser

end



GO

