CREATE   PROCEDURE [dbo].[Usp_User_Top_Transaction_details] --24560           
          
@User_ID varchar(20)            
            
            
AS            
 SET NOCOUNT ON            
               
BEGIN            
 declare @query varchar(max)            
 declare @where varchar(max)   
 declare @ParentID nvarchar(50) = ( select top 1 cast(isnull(ParentID,0) as nvarchar(50) ) from User_Detail with(nolock) where User_ID = @User_ID )
          
            
 set @query=''            
 set @where=''            
   if(@User_ID='' )            
   begin            
   set @where = '1=1  '            
   end            
   else             
   begin             
   set @where = @where+'cd.User_ID =''' +@ParentID+''' ';            
   end            
               
  set @QUERY= ' select top(1)  cd.user_id,cd.credits,CAST(CAST(us.Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile, cd.m_id,cd.credit_id,cd.balance,    
  cd.debits,cd.fromdate,cd.todate,cd.datecreated from User_Detail us (nolock) inner join   Credit_details cd (nolock) on us.user_id=cd.user_id and us.m_id=cd.m_id where '+  @WHERE+'  order by credit_id desc'             
              
              
 print(@QUERY);            
exec(@QUERY)            
SET NOCOUNT OFF;            
END            
