SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================          
-- Author:  <vinay kumar upadhyay,chandra prakash singh>          
-- Create date: <20/03/2015>          
-- Description: <This sp used for getuser user trasaction details used for sms19 apps>          
-- =============================================          
CREATE   PROCEDURE [dbo].[Usp_User_Transaction_details] --'9643853169','19762'          
@Mobile varchar(12),          
@User_ID varchar(20)          
          
          
AS          
 SET NOCOUNT ON          
             
BEGIN 
     Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @User_ID )       
         
--  declare @query varchar(max)          
-- declare @where varchar(max)          
          
-- set @query=''          
-- set @where=''          
--      if(@Mobile='' )          
--   begin          
--   set @where = '1=1 and '          
--   end          
--   else           
--   begin           
--   set @where = @where+'us.Mobile =''' +@Mobile+'''and  ';          
--   end          
--     if(@User_ID='' )          
--   begin          
--   set @where = '1=1  '          
--   end          
--   else           
--   begin           
--   set @where = @where+'cd.User_ID =''' +@User_ID+''' ';          
--   end          
             
--  set @QUERY= ' select  cd.user_id,cd.credits,CAST(CAST(us.Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile, cd.m_id,cd.credit_id,cd.balance,cd.debits,cd.fromdate,cd.todate,cd.datecreated from User_Detail us inner join   Credit_details cd on us.user_id=cd.      
--user_id and us.m_id=cd.m_id where '+  @WHERE+'  '           
            
            
-- print(@QUERY);          
--exec(@QUERY)          
      
select convert(nvarchar,cd.datecreated,112) DATE , sum(isnull(cd.credits,0))CREDITS,sum(isnull(cd.debits,0))DEBITS   
into #temp from User_Detail us (nolock) inner join Credit_details cd (nolock) on us.user_id=cd.user_id and us.m_id=cd.m_id   
where us.Mobile =@Mobile and cd.User_ID =@ParentID   
group by convert(nvarchar,cd.datecreated,112) order by DATE desc      
  
select convert(nvarchar,cd.datecreated,112) date2,cd.balance balance into #temp2 from credit_details cd (nolock) join #temp t   
on convert(nvarchar,cd.datecreated,112)=t.DATE where credit_id in(select max(credit_id) from credit_details (nolock) where User_ID=@ParentID group by convert(nvarchar,datecreated,112))  
  
select convert(nvarchar,convert(datetime,date,100),106) DATE,CREDITS,DEBITS,t2.BALANCE from #temp t join #temp2 t2  
on t.date=t2.date2  
  
drop table #temp  
drop table #temp2  
SET NOCOUNT OFF;          
END          
