/* ============================================================
   Procedure: [dbo].[Usp_usercouponsettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_usercouponsettings  -- 335      
 @ParentID BIGINT        
AS        
BEGIN        
 SELECT   (        
            '<p><b>Coupon Code : </b>' + ISNULL(ucs.couponcode,'') + '</p>' +        
            CASE         
                 WHEN ISNULL(nullif(ucs.coupondescription,''), '') <> '' THEN         
                      '<p><b>Coupon Description : </b>' + ISNULL(ucs.coupondescription, '')         
                      + '</p>'        
                      else ''      
            END +        
            CASE         
                 WHEN ucs.ismobile = 1 THEN         
                      '<p><b>Check Values in : </b>Mobiles Only</p>'        
                 WHEN ucs.isemail = 1 THEN         
                      '<p><b>Check Values in : </b>Emails Only</p>'        
                 WHEN ucs.isboth = 1 THEN         
                      '<p><b>Check Values in : </b>Both Mobiles and Emails</p>'        
            END         
        )                   AS Coupons,        
        (        
          case when ucs.IsProductApplicable=1 then  '<p><b>Products: </b>' +  (        
                SELECT STUFF(        
                           (        
                               SELECT N', ' + ss.NAME +(        
                                          SELECT ' (Min Value :' + CAST(upc.minvalue AS VARCHAR(50))         
                                                 + ', Max Value :' + CAST(upc.maxvalue AS VARCHAR(50))         
                                                 + ')<br />'        
                                          FROM   userproductscoupon AS upc        
                                          WHERE  upc.productid = fs.[value]        
                                                 AND upc.couponid = ucs.id        
                                      )        
                               FROM   productmaster AS ss        
                                      INNER JOIN dbo.Fn_split(ucs.productid, '#') AS         
                                           fs        
                                           ON  ss.productid = fs.[value] FOR         
                                               XML PATH(''),        
                                      TYPE        
                           ) .value('text()[1]', 'nvarchar(max)'),        
                           1,        
                           2,        
                           N''        
                       )        
            )        
         + '</p>' else '  
<b>  
No Product Applicability</b>  
' end)  AS          Products,        
        (case when ucs.SearchApplicability = 1 OR  ucs.ListApplicability = 1 or ucs.BillApplicability=1 then  CASE         
              WHEN ucs.SearchApplicability = 1 THEN         
                   '<p><u><b>Search Applicability : </b></u></p><p><b>Include :</b>' + ISNULL(        
                       (        
                           SELECT STUFF(        
                                      (        
                                          SELECT N', ' + usl.searchname        
                                          FROM   usersearchlist AS usl        
                                                 OUTER APPLY dbo.Fn_split(ucs.listid, '#') AS         
                                          fs        
                                          WHERE  usl.id = fs.[value] FOR XML         
                                                 PATH(''),        
                                                 TYPE        
                                      ) .value('text()[1]', 'nvarchar(max)'),        
                                      1,        
                                      2,        
                                      N''        
                                  )        
                       ),        
                       ''        
                   )        
                   + '</p><p><b>Exclude :</b>' + ISNULL(        
                       (        
    SELECT STUFF(        
                                      (        
                                          SELECT N', ' + usl.searchname        
                                          FROM   usersearchlist AS usl        
                                                 OUTER APPLY dbo.Fn_split(ucs.ListIDExclude, '#') AS         
                                          fs        
                                          WHERE  usl.id = fs.[value] FOR XML         
                                                 PATH(''),        
                                                 TYPE        
                                      ) .value('text()[1]', 'nvarchar(max)'),        
                                      1,        
                                      2,        
                                      N''        
                                  )        
                       ),        
                       ''        
                   )        
                   + '</p>'        
              ELSE ''        
         END +CASE         
                   WHEN ucs.ListApplicability = 1 THEN         
                        '<p><u><b>List Applicability : </b></u></p><p><b>Include :</b>' + ISNULL(        
                            (        
                                SELECT STUFF(        
                                       (        
                                               SELECT N', ' + A.importname        
                                               FROM   (        
      SELECT usl.importname         
                                                                 + '(List)' AS         
                                                                 ImportName        
                                  FROM           
                                                                 userimportedlistcolumn AS         
                                                                 usl        
                                                                 OUTER APPLY         
                                                          dbo.Fn_split(ucs.listgroupid, '#') AS         
                                                          fs        
                                                          WHERE  usl.id = fs.[value]        
                                                          UNION ALL        
                                                          SELECT gd.group_name         
                                                                 + '(Group)'        
                                                          FROM   group_detail AS         
                                                                 gd        
                                                                 OUTER APPLY         
                                                          dbo.Fn_split(ucs.listgroupid, '#') AS         
                                                          fs        
                                                          WHERE  gd.group_id =         
                                                                 fs.[value]        
                                                      )A FOR XML PATH(''),        
                                                      TYPE        
                                           ) .value('text()[1]', 'nvarchar(max)'),        
                                           1,        
                                           2,        
                                           N''        
                                       )        
                            ),        
                            ''        
                        ) + '</p><p><b>Exclude :</b>' + ISNULL(        
                            (        
                                SELECT STUFF(        
                                       (        
                                               SELECT N', ' + A.importname        
                                               FROM   (    
      SELECT usl.importname         
                                                                 + '(List)' AS         
                                                                 ImportName        
                                  FROM           
                                                                 userimportedlistcolumn AS         
                                                                 usl        
                                                                 OUTER APPLY         
                                                          dbo.Fn_split(ucs.ListGroupIDExclude, '#') AS         
                                                          fs        
                                                          WHERE  usl.id = fs.[value]        
                                                          UNION ALL        
                                                          SELECT gd.group_name         
                                                                 + '(Group)'        
                                                          FROM   group_detail AS         
                                                                 gd        
                                                                 OUTER APPLY         
                                                          dbo.Fn_split(ucs.ListGroupIDExclude, '#') AS         
                                                          fs        
                                                          WHERE  gd.group_id =         
                                                                 fs.[value]        
                                                      )A FOR XML PATH(''),        
                                                      TYPE        
                                           ) .value('text()[1]', 'nvarchar(max)'),        
                                           1,        
                                           2,        
                                           N''        
                                       )        
                            ),        
                            ''        
                        ) + '</p>'        
                   ELSE ''        
              END+ '</p>' +CASE WHEN ucs.BillApplicability=1 THEN  '<p><u><b>Bill Applicability : </b></u> Min :'+ISNULL( ucs.minBillAmount,        
            ''        
        )+' / max :' + ISNULL( ucs.BillAmount,        
            ''        
        ) + '</p>' ELSE '' END else '  
<b>  
No Segment Applicability</b>  
' end  ) AS          Segments,        
        '' AS                  SearchValue,        
        (        
             +        
            CASE         
                 WHEN ucs.isdiscount = 1 THEN '<p><b>Discount with </b>' +        
                      CASE         
                           WHEN ISNULL(ucs.discountamount, '') < > '' THEN         
                                'Amount of ' + CAST(ucs.discountamount AS VARCHAR(50))+ '</p>'        
                           ELSE '%age of ' + CAST(ucs.discountpercentage AS VARCHAR(50))+ '</p>'        
                      END        
                 ELSE ''        
            END  +          
            CASE         
                 WHEN ucs.isfreebee = 1 THEN '<p><b>Free-bee from  </b>' +(        
                SELECT STUFF(        
                           (        
                               SELECT N', ' + ss.NAME +(        
                                          SELECT ' (Min Value :' + CAST(upc.minvalue AS VARCHAR(50))            
                                                 + ')<br />'        
                                          FROM   UserProductsFreebeeCoupon  AS upc        
                                          WHERE  upc.productid = fs.[value]        
                                                 AND upc.couponid = ucs.id        
                        )        
                               FROM   productmaster AS ss        
                   INNER JOIN dbo.Fn_split(ucs.FreebeeProducts, '#') AS         
                                           fs        
                                           ON  ss.productid = fs.[value] FOR         
                                               XML PATH(''),        
                                     TYPE        
                           ) .value('text()[1]', 'nvarchar(max)'),        
                           1,        
                           2,        
                           N''        
                       )        
            )        
                + '</p>' ELSE ''        
            END  +          
            CASE         
                 WHEN ucs.isothers = 1 THEN '<p><b>Other Discounts of</b> ' + ucs.othersdiscount + '</p>'        
                 ELSE ''        
            END        
        )                   AS Discounts,  ( '<p><b>Start Date : </b>' + ISNULL(ucs.StartDate, '') +         
            '</p>' + '<p><b>Expiry Date : </b>' + ISNULL(ucs.expirydate, '') +         
            '</p>')    as Validity,  
        ucs.createdon,        
        ucs.ID,ucs.IsActive        
 FROM   usercouponsettings  AS ucs        
 WHERE  ucs.parentid = @ParentID      
 ORDER BY        
        ucs.createdon DESC        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_UserDailyReportAlert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_UserDailyReportAlert] --'2018-04-12','0'
@reportdate date =null, 
@users nvarchar(max)='0'
as 
begin
		SET NOCOUNT ON;
	   --Get report dates
	   --declare @reportdate date 
	   set @reportdate=coalesce(@reportdate,cast(dateadd(d,-1,getdate()) as date))
	   
	   declare @reportmonth int = month(@reportdate)
	   declare @reportyear int = year(@reportdate)
	   declare @reportfirstdate date=cast(cast(@reportyear as nvarchar) + '-' + cast(@reportmonth as nvarchar) + '-' + '01' as date)
	   --Get user set for report--
	   --declare @users nvarchar(max)
	   
	   set @users=coalesce(@users,'0') 
	   --select @users,@reportdate,@reportfirstdate
	   --Create & populate tables for reportdate's consumption, month consumption and average consumption--
	   
	   create table #ReportdaySMSconsumption(user_id bigint,DaySMSConsumption bigint)
	   create clustered index ix_#ReportdaySMSconsumption on #ReportdaySMSconsumption(User_id,DaySMSConsumption)
	   
	   create table #ReportdayMailconsumption(user_id bigint,DayMailConsumption bigint)
	   create clustered index ix_#ReportdayMailconsumption on #ReportdayMailconsumption(User_id,DayMailConsumption)

	   create table #ReportMonthSMSconsumption(user_id bigint,MonthSMSConsumption bigint)
	   create clustered index ix_#ReportMonthSMSconsumption on #ReportMonthSMSconsumption(User_id,MonthSMSConsumption)

	   create table #ReportMonthMailconsumption(user_id bigint,MonthMailConsumption bigint)
	   create clustered index ix_#ReportMonthMailconsumption on #ReportMonthMailconsumption(User_id,MonthMailConsumption)

	   create table #AverageSMSconsumption(user_id bigint,AverageSMSConsumption bigint,CurrentSMSBalance bigint)
	   create clustered index ix_#AverageSMSconsumption on #AverageSMSconsumption(User_id,AverageSMSConsumption,CurrentSMSBalance)

	   create table #AverageMailconsumption(user_id bigint,AverageMailConsumption bigint,CurrentMailBalance bigint)
	   create clustered index ix_#AverageMailconsumption on #AverageMailconsumption(User_id,AverageMailConsumption,CurrentMailBalance)
    
    if @users <>'0'
	   begin
		  --select 1
		  insert into #AverageSMSconsumption
		  select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance from user_detail u (nolock) left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID in (select value from dbo.fn_Split(@users,',')) group by u.user_id
		  insert into #AverageMailconsumption
		  select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID in (select value from dbo.fn_Split(@users,',')) group by u.user_id

		  insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)
		  select c.user_id,COUNT(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id
		  insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)
		  select c.user_id,COUNT(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id

		  insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)
		  select c.user_id,COUNT(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id
		  insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)
		  select c.user_id,COUNT(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id

	   end
    else
	   begin
		  --select 2
		  insert into #AverageSMSconsumption
		  select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance from user_detail u (nolock) left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 group by u.user_id
		  --select * from #AverageSMSconsumption
		  insert into #AverageMailconsumption
		  select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 group by u.user_id

		  insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)
		  select c.user_id,COUNT(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id
		  insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)
		  select c.user_id,COUNT(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id

		  insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)
		  select c.user_id,COUNT(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id
		  insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)
		  select c.user_id,COUNT(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id
	   end

	   --Create & populate tables for lead management
	   create table #NewEnquiries(user_id bigint,NewEnquiries int)
	   create clustered index ix_#NewEnquiries on #NewEnquiries(user_id,NewEnquiries)
	   
	   create table #NewLeads(user_id bigint,NewLeads int)
	   create clustered index ix_#NewLeads on #NewLeads(user_id,NewLeads)

	   create table #NewConversions(user_id bigint,NewConversions int,dayorderamount money)
	   create clustered index ix_#NewConversions on #NewConversions(user_id,NewConversions,dayorderamount)

	   create table #MonthEnquiries(user_id bigint,MonthEnquiries int)
	   create clustered index ix_#MonthEnquiries on #MonthEnquiries(user_id,MonthEnquiries)
	   
	   create table #MonthLeads(user_id bigint,MonthLeads int)
	   create clustered index ix_#MonthLeads on #MonthLeads(user_id,MonthLeads)

	   create table #MonthConversions(user_id bigint,MonthConversions int,orderamount money)
	   create clustered index ix_#MonthConversions on #MonthConversions(user_id,MonthConversions,orderamount)

	   insert into #NewEnquiries
	   select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID where cast(Createddate as DATE)=@reportdate group by user_id 
	   insert into #NewLeads
	   select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where cast(Createdon as DATE)=@reportdate group by user_id
	   insert into #NewConversions
	   select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID where cast(l.CreatedOn as DATE)=@reportdate and l.FollowUpStatus=5 group by user_id

	   insert into #monthEnquiries
	   select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID  where month(Createddate)=@reportmonth and YEAR(CreatedDate)=@reportyear group by user_id
	   insert into #MonthLeads
	   select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where month(Createdon)=@reportmonth and year(Createdon)=@reportyear  group by user_id
	   insert into #monthConversions
	   select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID where month(l.CreatedOn)=@reportmonth and YEAR(l.CreatedOn)=@reportyear and l.FollowUpStatus=5 group by user_id

	   --Create & populate tables for campaigns

	   create table #Campaigns(user_id bigint,TotalSMSCampaigns int,TotalMailCampaigns int)
	   create clustered index IX_#Campaigns on #Campaigns(user_id,TotalSMSCampaigns,TotalMailCampaigns)

	   insert into #Campaigns
	   select a.user_id,sum(case when c.medium='SMS' and isactive=1 then 1 else 0 end) as SMSCampaigns,sum(case when c.medium<>'SMS' and isactive=1 then 1 else 0 end) as MailCampaigns from #AverageSMSconsumption a left join UserCampaignMaster c on c.ParentID=a.user_id group by user_id

	   --Create & populate table for landingpages & webform

	   create table #landingpages(user_id bigint,TotalLandingPages int)
	   create table #landingpageLeads(user_id bigint,LDayLeads int,LMonthLeads int)
	   create table #Webforms(user_id bigint,TotalWebforms int)
	   create table #WebformLeads(user_id bigint,WDayLeads int,WMonthLeads int)

	   insert into #landingpages
	   select a.user_id,COUNT(id) from #AverageSMSconsumption a left join ClientPageDetail c on a.user_id=c.User_ID group by a.user_id
	   insert into #landingpageLeads
	   select a.user_id,SUM(case when CAST(l.DateCreated as date) = @reportdate then 1 else 0 end),SUM(case when month(l.DateCreated) = @reportmonth and YEAR(l.datecreated)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join clientpagedetail c on c.User_ID=a.user_id join ClientLeadDetails l on l.cname=right(pagename,len(pagename)-CHARINDEX(pagename,'/',1)) group by a.user_id
	   insert into #webforms
	   select a.user_id,COUNT(FormId) from #AverageSMSconsumption a left join webformtbl c on a.user_id=c.parentID group by a.user_id
	   insert into #webformLeads
	   select a.user_id,SUM(case when CAST(l.EntryDate as date) = @reportdate then 1 else 0 end),SUM(case when month(l.EntryDate) = @reportmonth and YEAR(l.EntryDate)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join webformtbl c on a.user_id=c.parentID left join WebEntryTbl l on l.formid=c.formID group by user_id

	   --Create & populate onlineorders table

	   Create table #Onlineorders(user_id bigint,DayOrders int,DayOrderAmount money,MonthOrders int,MonthOrderAmount money)

	   insert into #Onlineorders
	   select b.user_id,SUM(case when CAST(a.CreatedOn as date)=@reportdate then 1 else 0 end) as DayOrders,SUM(case when CAST(a.CreatedOn as date)=@reportdate then a.totalamount else 0 end) as DayOrderAmount,SUM(case when month(a.CreatedOn)=@reportmonth and YEAR(a.createdon)=@reportyear then 1 else 0 end) as MonthOrders,SUM(case when month(a.CreatedOn)=@reportmonth and YEAR(a.createdon)=@reportyear then a.totalamount else 0 end) as MonthOrderAmount from #AverageSMSconsumption b left join UserOrders a on a.parentid=b.user_id group by b.user_id

begin tran
truncate table Alertsdata

	   insert into Alertsdata(ReportDate,user_id,DaySMSConsumption,DayMailConsumption,MonthSMSConsumption,MonthMailConsumption,AverageSMSConsumption,AverageMailConsumption,CurrentSMSBalance,CurrentMailBalance,NewEnquiries,NewLeads,NewConversions,Dayorderamount,MonthEnquiries,MonthLeads,MonthConversions,OrderAmount,TotalSMSCampaigns,TotalMailCampaigns,TotalLandingPages,
	   LandingPageDayLeads,LandingPageMonthLeads,TotalWebforms,WebformDayLeads,WebformMonthLeads,DayEshopOrders,DayEshopOrderAmount,EshopMonthOrders,EshopMonthOrderAmount)
	   select @ReportDate as ReportDate,isnull(a.user_id,0) as User_id,isnull(rds.DaySMSConsumption,0) as DaySMSConsumption ,isnull(rdm.DayMailConsumption,0) as DayMailConsumption,isnull(rms.MonthSMSConsumption,0) as MonthSMSConsumption,isnull(rmm.MonthMailConsumption,0) as MonthMailConsumption
	   ,isnull(a.AverageSMSConsumption,0) as AverageSMSConsumption,isnull(am.AverageMailConsumption,0) as AverageMailConsumption,a.CurrentSMSBalance,am.CurrentMailBalance,isnull(nw.NewEnquiries,0) as NewEnquiries,isnull(nl.NewLeads,0) as NewLeads,isnull(nc.NewConversions,0) as NewConversions,isnull(nc.dayorderamount,0) as Dayorderamount
	   ,isnull(me.MonthEnquiries,0) as MonthEnquiries,isnull(ml.MonthLeads,0) as MonthLeads,isnull(mc.MonthConversions,0) as MonthConversions,isnull(mc.orderamount,0) as OrderAmount,isnull(c.TotalSMSCampaigns,0) as TotalSMSCampaigns
	   ,isnull(c.TotalMailCampaigns,0) as TotalMailCampaigns,isnull(lp.TotalLandingPages,0) as TotalLandingPages,isnull(lpl.LDayLeads,0) as LandingPageDayLeads,isnull(lpl.LMonthLeads,0) as LandingPageMonthLeads,isnull(wf.TotalWebforms,0) as TotalWebforms
	   ,isnull(wfl.WDayLeads,0) as WebformDayLeads,isnull(wfl.WMonthLeads,0) as WebformMonthLeads,isnull(oo.DayOrders,0) as DayEshopOrders,isnull(oo.DayOrderAmount,0) as DayEshopOrderAmount,isnull(oo.MonthOrders,0) as EshopMonthOrders,isnull(oo.MonthOrderAmount,0) as EshopMonthOrderAmount --into #AlertsData
	   from 
	   #AverageSMSconsumption a left join #AverageMailconsumption am on a.user_id=am.user_id
	   left join #ReportdaySMSconsumption rds on rds.user_id=a.user_id
	   left join #ReportdayMailconsumption rdm on rdm.user_id=a.user_id
	   left join #ReportMonthSMSconsumption rms on rms.user_id=a.user_id
	   left join #ReportMonthMailconsumption rmm on rmm.user_id=a.user_id
	   left join #NewEnquiries nw on nw.user_id=a.user_id
	   left join #NewLeads nl on nl.user_id=a.user_id
	   left join #NewConversions nc on nc.user_id=a.user_id
	   left join #MonthEnquiries me on me.user_id=a.user_id
	   left join #MonthLeads ml on ml.user_id=a.user_id
	   left join #MonthConversions mc on mc.user_id=a.user_id
	   left join #Campaigns c on c.user_id=a.user_id
	   left join #landingpages lp on lp.user_id=a.user_id
	   left join #landingpageLeads lpl on lpl.user_id=a.user_id
	   left join #Webforms wf on wf.user_id=a.user_id
	   left join #WebformLeads wfl on wfl.user_id=a.user_id
	   left join #Onlineorders oo on oo.user_id=a.user_id
	   commit

    --Replace dynamic values within 
    create table #final(user_id bigint,content text)
    insert into #final
    exec usp_ReplaceAttributes 1

    select * from #final

end


GO

/* ============================================================
   Procedure: [dbo].[usp_UserDailyReportAlertNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_UserDailyReportAlertNew] --null,'335' --'2018-04-12','0'  
@reportdate date =null,   
@users nvarchar(max)='0'  
as   
begin  
--select 'ProcStarted',GETDATE()  
--declare @reportdate date =null   
--declare @users nvarchar(max)='335'  
  SET NOCOUNT ON;  
    --Get report dates  
    --declare @reportdate date   
    set @reportdate=coalesce(@reportdate,cast(dateadd(d,-1,getdate()) as date))  
      
    declare @reportmonth int = month(@reportdate)  
    declare @reportyear int = year(@reportdate)  
    declare @reportfirstdate date=cast(cast(@reportyear as nvarchar) + '-' + cast(@reportmonth as nvarchar) + '-' + '01' as date)  
    --Get user set for report--  
    --declare @users nvarchar(max)  
      
    set @users=coalesce(@users,'0')   
    --select @users,@reportdate,@reportfirstdate  
    --Create & populate tables for reportdate's consumption, month consumption and average consumption--  
declare @body1 nvarchar(max),@subject1 nvarchar(200)  
set @body1 = (select 'User Alerts proc started at ' + cast(GETDATE() as nvarchar) + ' for users ' + @users + '.')  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
@copy_recipients='csshukla@pelsoftlabs.in',  
@subject='Alert mails started on live',  
@body = @body1  
      
      
      
    create table #ReportdaySMSconsumption(user_id bigint,DaySMSConsumption bigint)  
    create clustered index ix_#ReportdaySMSconsumption on #ReportdaySMSconsumption(User_id,DaySMSConsumption)  
      
    create table #ReportdayMailconsumption(user_id bigint,DayMailConsumption bigint)  
    create clustered index ix_#ReportdayMailconsumption on #ReportdayMailconsumption(User_id,DayMailConsumption)  
  
    create table #ReportMonthSMSconsumption(user_id bigint,MonthSMSConsumption bigint)  
    create clustered index ix_#ReportMonthSMSconsumption on #ReportMonthSMSconsumption(User_id,MonthSMSConsumption)  
  
    create table #ReportMonthMailconsumption(user_id bigint,MonthMailConsumption bigint)  
    create clustered index ix_#ReportMonthMailconsumption on #ReportMonthMailconsumption(User_id,MonthMailConsumption)  
  
    create table #AverageSMSconsumption(user_id bigint,AverageSMSConsumption bigint,CurrentSMSBalance bigint,resellerdomain varchar(100),UEmail varchar(100),User_login varchar(100))  
    create clustered index ix_#AverageSMSconsumption on #AverageSMSconsumption(User_id,AverageSMSConsumption,CurrentSMSBalance)  
  
    create table #AverageMailconsumption(user_id bigint,AverageMailConsumption bigint,CurrentMailBalance bigint)  
    create clustered index ix_#AverageMailconsumption on #AverageMailconsumption(User_id,AverageMailConsumption,CurrentMailBalance)  
      
    if @users <>'0'  
    begin  
    --select 1  
    insert into #AverageSMSconsumption  
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,case when r.domain='www.sms19.com' then 'www.kit19.com' else r.domain end as resellerdomain,email as UEmail,User_login as
 User_login from user_detail u (nolock) left join reseller_detail r (nolock) on u.m_id=r.reseller_id left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u
.USER_ID in (select value from dbo.fn_Split(@users,',')) group by u.user_id,r.Domain,email,user_login  
    insert into #AverageMailconsumption  
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID in (select value from dbo.fn_Split(@users,',')) group by u.user_id  
  
    insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)  
    select c.user_id,COUNT(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id  
    insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)  
    select c.user_id,COUNT(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id  
  
    insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)  
    select c.user_id,COUNT(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id  
    insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)  
    select c.user_id,COUNT(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id  
  
    end  
    else  
    begin  
    --select 2  
    insert into #AverageSMSconsumption  
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,case when r.domain='www.sms19.com' then 'www.kit19.com' else r.domain end as resellerdomain,Email as Uemail,User_login as
 User_login from user_detail u (nolock) left join reseller_detail r (nolock) on u.m_id=r.reseller_id left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,GETDATE()), 0))<=3 where u.USER_ID not in (select USER_ID from user_detail where m_id<>10043 and Status=0 ) and u.email not like '%pelsoftlabs.in' group by u.user_id,r.Domain,email,User_Login
 union 
select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,r.domain as resellerdomain,Email as Uemail,User_login as User_login from user_detail u (nolock) left join reseller_detail r (nolock) on u.m_id=r.reseller_id left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,GETDATE()), 0))<=3 where u.email in ('karuna@pelsoftlabs.in','csshukla@pelsoftlabs.in') group by u.user_id,r.Domain,email,User_Login 
    --select * from #AverageSMSconsumption  
    insert into #AverageMailconsumption  
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID not in (select USER_ID from user_detail where m_id<>10043 and Status=0 ) group by u.user_id  
  
    insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)  
    select c.user_id,COUNT(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id  
    insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)  
    select c.user_id,COUNT(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id  
  
    insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)  
    select c.user_id,COUNT(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id  
    insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)  
    select c.user_id,COUNT(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id  
    end  
  
    --Create & populate tables for lead management  
    create table #NewEnquiries(user_id bigint,NewEnquiries int)  
    create clustered index ix_#NewEnquiries on #NewEnquiries(user_id,NewEnquiries)  
      
    create table #NewLeads(user_id bigint,NewLeads int)  
    create clustered index ix_#NewLeads on #NewLeads(user_id,NewLeads)  
  
    create table #NewConversions(user_id bigint,NewConversions int,dayorderamount money)  
    create clustered index ix_#NewConversions on #NewConversions(user_id,NewConversions,dayorderamount)  
  
    create table #MonthEnquiries(user_id bigint,MonthEnquiries int)  
    create clustered index ix_#MonthEnquiries on #MonthEnquiries(user_id,MonthEnquiries)  
      
    create table #MonthLeads(user_id bigint,MonthLeads int)  
    create clustered index ix_#MonthLeads on #MonthLeads(user_id,MonthLeads)  
  
    create table #MonthConversions(user_id bigint,MonthConversions int,orderamount money)  
    create clustered index ix_#MonthConversions on #MonthConversions(user_id,MonthConversions,orderamount)  
  
    insert into #NewEnquiries  
    select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID where cast(Createddate as DATE)=@reportdate group by user_id   
    insert into #NewLeads  
    select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where cast(Createdon as DATE)=@reportdate group by user_id  
    insert into #NewConversions  
    select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID where cast(l.CreatedOn as DATE)=@reportdate and l.FollowUpStatus=5 group by user_id  
  
    insert into #monthEnquiries  
    select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID  where month(Createddate)=@reportmonth and YEAR(CreatedDate)=@reportyear group by user_id  
    insert into #MonthLeads  
    select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where month(Createdon)=@reportmonth and year(Createdon)=@reportyear  group by user_id  
    insert into #monthConversions  
    select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID where month(l.CreatedOn)=@reportmonth and 
YEAR(l.CreatedOn)=@reportyear and l.FollowUpStatus=5 group by user_id  
  
    --Create & populate tables for campaigns  
  
    create table #Campaigns(user_id bigint,TotalSMSCampaigns int,TotalMailCampaigns int)  
    create clustered index IX_#Campaigns on #Campaigns(user_id,TotalSMSCampaigns,TotalMailCampaigns)  
  
    insert into #Campaigns  
    select a.user_id,sum(case when c.medium='SMS' and isactive=1 then 1 else 0 end) as SMSCampaigns,sum(case when c.medium<>'SMS' and isactive=1 then 1 else 0 end) as MailCampaigns from #AverageSMSconsumption a left join UserCampaignMaster c on c.ParentID
=a.user_id group by user_id  
  
    --Create & populate table for landingpages & webform  
  
    create table #landingpages(user_id bigint,TotalLandingPages int)  
    create table #landingpageLeads(user_id bigint,LDayLeads int,LMonthLeads int)  
    create table #Webforms(user_id bigint,TotalWebforms int)  
    create table #WebformLeads(user_id bigint,WDayLeads int,WMonthLeads int)  
  
    insert into #landingpages  
    select a.user_id,COUNT(id) from #AverageSMSconsumption a left join ClientPageDetail c on a.user_id=c.User_ID group by a.user_id  
    insert into #landingpageLeads  
    select a.user_id,SUM(case when CAST(l.DateCreated as date) = @reportdate then 1 else 0 end),SUM(case when month(l.DateCreated) = @reportmonth and YEAR(l.datecreated)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join 
    clientpagedetail c on c.User_ID=a.user_id join ClientLeadDetails l on l.cname=right(pagename,len(pagename)-CHARINDEX(pagename,'/',1)) group by a.user_id  
    insert into #webforms  
    select a.user_id,COUNT(FormId) from #AverageSMSconsumption a left join webformtbl c on a.user_id=c.parentID group by a.user_id  
    insert into #webformLeads  
    select a.user_id,SUM(case when CAST(l.EntryDate as date) = @reportdate then 1 else 0 end),SUM(case when month(l.EntryDate) = @reportmonth and YEAR(l.EntryDate)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join webformtbl c 
    on a.user_id=c.parentID left join WebEntryTbl l on l.formid=c.formID group by user_id  
  
    --Create & populate onlineorders table  
  
    Create table #Onlineorders(user_id bigint,DayOrders int,DayOrderAmount money,MonthOrders int,MonthOrderAmount money)  
  
    insert into #Onlineorders  
    select b.user_id,SUM(case when CAST(a.CreatedOn as date)=@reportdate then 1 else 0 end) as DayOrders,SUM(case when CAST(a.CreatedOn as date)=@reportdate then a.totalamount else 0 end) as DayOrderAmount,SUM(case when month(a.CreatedOn)=@reportmonth and
 YEAR(a.createdon)=@reportyear then 1 else 0 end) as MonthOrders,SUM(case when month(a.CreatedOn)=@reportmonth and YEAR(a.createdon)=@reportyear then a.totalamount else 0 end) as MonthOrderAmount from #AverageSMSconsumption b left join UserOrders a on 
 a.parentid=b.user_id group by b.user_id  
  
begin tran  
truncate table Alertsdata1  
    insert into Alertsdata1(ReportDate,user_id,DaySMSConsumption,DayMailConsumption,MonthSMSConsumption,MonthMailConsumption,AverageSMSConsumption,AverageMailConsumption,CurrentSMSBalance,CurrentMailBalance,NewEnquiries,NewLeads,NewConversions,
    Dayorderamount,MonthEnquiries,MonthLeads,MonthConversions,OrderAmount,TotalSMSCampaigns,TotalMailCampaigns,TotalLandingPages,  
    LandingPageDayLeads,LandingPageMonthLeads,TotalWebforms,WebformDayLeads,WebformMonthLeads,DayEshopOrders,DayEshopOrderAmount,EshopMonthOrders,EshopMonthOrderAmount,resellerdomain,Uemail,User_login)  
    select @ReportDate as ReportDate,isnull(a.user_id,0) as User_id,isnull(rds.DaySMSConsumption,0) as DaySMSConsumption ,isnull(rdm.DayMailConsumption,0) as DayMailConsumption,isnull(rms.MonthSMSConsumption,0) as MonthSMSConsumption,
    isnull(rmm.MonthMailConsumption,0) as MonthMailConsumption  
    ,isnull(a.AverageSMSConsumption,0) as AverageSMSConsumption,isnull(am.AverageMailConsumption,0) as AverageMailConsumption,a.CurrentSMSBalance,am.CurrentMailBalance,isnull(nw.NewEnquiries,0) as NewEnquiries,isnull(nl.NewLeads,0) as NewLeads,
    isnull(nc.NewConversions,0) as NewConversions,isnull(nc.dayorderamount,0) as Dayorderamount  
    ,isnull(me.MonthEnquiries,0) as MonthEnquiries,isnull(ml.MonthLeads,0) as MonthLeads,isnull(mc.MonthConversions,0) as MonthConversions,isnull(mc.orderamount,0) as OrderAmount,isnull(c.TotalSMSCampaigns,0) as TotalSMSCampaigns  
    ,isnull(c.TotalMailCampaigns,0) as TotalMailCampaigns,isnull(lp.TotalLandingPages,0) as TotalLandingPages,isnull(lpl.LDayLeads,0) as LandingPageDayLeads,isnull(lpl.LMonthLeads,0) as LandingPageMonthLeads,isnull(wf.TotalWebforms,0) as TotalWebforms  
    ,isnull(wfl.WDayLeads,0) as WebformDayLeads,isnull(wfl.WMonthLeads,0) as WebformMonthLeads,isnull(oo.DayOrders,0) as DayEshopOrders,isnull(oo.DayOrderAmount,0) as DayEshopOrderAmount,isnull(oo.MonthOrders,0) as EshopMonthOrders,
    isnull(oo.MonthOrderAmount,0) as EshopMonthOrderAmount,isnull(resellerdomain,'www.kit19.com') as resellerdomain,Uemail,User_login --into #AlertsData  
    from   
    #AverageSMSconsumption a left join #AverageMailconsumption am on a.user_id=am.user_id  
    left join #ReportdaySMSconsumption rds on rds.user_id=a.user_id  
    left join #ReportdayMailconsumption rdm on rdm.user_id=a.user_id  
    left join #ReportMonthSMSconsumption rms on rms.user_id=a.user_id  
    left join #ReportMonthMailconsumption rmm on rmm.user_id=a.user_id  
    left join #NewEnquiries nw on nw.user_id=a.user_id  
    left join #NewLeads nl on nl.user_id=a.user_id  
    left join #NewConversions nc on nc.user_id=a.user_id  
    left join #MonthEnquiries me on me.user_id=a.user_id  
    left join #MonthLeads ml on ml.user_id=a.user_id  
    left join #MonthConversions mc on mc.user_id=a.user_id  
    left join #Campaigns c on c.user_id=a.user_id  
    left join #landingpages lp on lp.user_id=a.user_id  
    left join #landingpageLeads lpl on lpl.user_id=a.user_id  
    left join #Webforms wf on wf.user_id=a.user_id  
    left join #WebformLeads wfl on wfl.user_id=a.user_id  
    left join #Onlineorders oo on oo.user_id=a.user_id  
    where UEmail is not null and UEmail <>''  
    commit  
--select COUNT(1) from Alertsdata1  
--select 'unpivotStart',GETDATE()  
  
begin tran  
--truncate table ReplaceableRecords   
--insert into ReplaceableRecords  
select u.User_ID,u.UEmail as Email, case u.ColumnName when 'resellerdomain' then 'kit19.com' else u.columnname end as ColumnName, cast(u.ColumnValue as nvarchar(100)) as ColumnValue  
into #ReplaceableRecords   
from Alertsdata1 s  
unpivot  
(  
  ColumnValue  
  for ColumnName in (ReportDate,  
DaySMSConsumption,  
DayMailConsumption,  
--MonthSMSConsumption,  
--MonthMailConsumption,  
--AverageSMSConsumption,  
--AverageMailConsumption,  
CurrentSMSBalance,  
CurrentMailBalance,  
NewEnquiries,  
NewLeads,  
NewConversions,  
--Dayorderamount,  
MonthEnquiries,  
MonthLeads,  
MonthConversions,  
OrderAmount,  
TotalSMSCampaigns,  
TotalMailCampaigns,  
TotalLandingPages,  
LandingPageDayLeads,  
LandingPageMonthLeads,  
TotalWebforms,  
WebformDayLeads,  
WebformMonthLeads,  
DayEshopOrders,  
DayEshopOrderAmount,  
EshopMonthOrders,  
EshopMonthOrderAmount,  
resellerdomain,  
User_login  
)  
) u;  
commit  
declare @email varchar(100),@tcount int=(select COUNT(distinct user_id) from #ReplaceableRecords)  
--select 'RecordReplaceStart',GETDATE()  
declare @user_id bigint,@ucount int=(select COUNT(distinct user_id) from #ReplaceableRecords),@content nvarchar(max)=(select content from notifications where id=1)  
  
set @body1 = (select 'User Alert Mails replace started at ' + cast(GETDATE() as nvarchar) + ' for total no. of users ' + cast(@tcount as varchar(10)) + '.')  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
--@copy_recipients='csshukla@pelsoftlabs.in',  
@subject='Alert mails replace started on live',  
@body = @body1  
  
  
INSERT INTO Getbatchrecord                                        
([User_id],RandNum)                                        
SELECT 335,10043  
declare @batchid bigint=(select dbo.fn_CreateBatchID(10043,335))  
delete From GetBatchRecord where BatchID=@batchid  
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,
Tablename)  
SELECT @BatchID,335,'contactus@email19.in' as SenderName,@content,@tcount,0,0,0,0,Getdate(),NULL,dateadd(day, datediff(day, 0, getdate()), 0) + '10:00',dateadd(day, datediff(day, 0, getdate()), 0) + '10:00',0,0,0,0,'Your business as on ' + 
cast(@reportdate as nvarchar(20)),'contactus@email19.in',  
'UserAlertMails'  
truncate table UserAlertMails  
declare @insertedguid varchar(200)  
while @ucount>0  
 begin  
    select @user_id=MIN(USER_ID) from #ReplaceableRecords  
    select top 1 @email=Email from #ReplaceableRecords where user_id=@user_id  
    select @content=REPLACE(@content,'#'+ColumnName+'#',Columnvalue) from #ReplaceableRecords where user_id=@user_id  
      
    insert into UserAlertMails(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,
    IsMonitor,TemplateID,Count,Source)  
    select 'contactus@email19.in',@email,'Your business as on ' + cast(@reportdate as nvarchar(20)),0,@content,GETDATE(),335,335,'contactus@email19.in',@batchid,0,dateadd(day, datediff(day, 0, getdate()), 0) + '10:00',dateadd(day, datediff(day, 0, getdate
()), 0) + '10:00','',@content,1,0,@tcount,'Alerts'  
    set @content=(select content from notifications where id=1)  
    delete From #ReplaceableRecords where USER_ID=@user_id  
    set @ucount=@ucount-1  
    if @ucount%2000=0  
    begin  
set @body1 = (select 'User Alert Mails replaced for ' +cast((@tcount-@ucount) as varchar(10)) + ' no. of records')  
set @subject1='Alert mails replace completed '+cast(cast((@tcount-@ucount)*100 as money)/cast(@tcount as money) as varchar(10)) + '% on live'  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
--@copy_recipients='csshukla@pelsoftlabs.in',  
@subject=@subject1,  
@body = @body1  
    end  
    end  
declare @ccount int=(select COUNT(1) from UserAlertMails)  
set @body1 = (select 'User Alert Mails completed and schedule for ' +cast(@reportdate as varchar(30)) + ' for ' +CAST(@ccount as varchar(10))+ ' no. of records')  
set @subject1='Alert mails replace completed at '+cast(GETDATE() as varchar(30)) + ' on live'  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='karuna@pelsoftlabs.in',  
--@copy_recipients='csshukla@pelsoftlabs.in',  
@subject=@subject1,  
@body = @body1  
 end     
    
    
    



GO

/* ============================================================
   Procedure: [dbo].[usp_UserDailyReportAlertNew1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_UserDailyReportAlertNew1] --null,'335' --'2018-04-12','0'        
@reportdate date =null,         
@users nvarchar(max)='0'        
as         
begin        
--select 'ProcStarted',GETDATE()        
--declare @reportdate date =null         
--declare @users nvarchar(max)='335'        
  SET NOCOUNT ON;        
    --Get report dates        
    --declare @reportdate date         
    set @reportdate=coalesce(@reportdate,cast(dateadd(d,-1,getdate()) as date))        
            
    declare @reportmonth int = month(@reportdate)        
    declare @reportyear int = year(@reportdate)        
    declare @reportfirstdate date=cast(cast(@reportyear as nvarchar) + '-' + cast(@reportmonth as nvarchar) + '-' + '01' as date)        
    --Get user set for report--        
    --declare @users nvarchar(max)        
            
    set @users=coalesce(@users,'0')         
    --select @users,@reportdate,@reportfirstdate        
    --Create & populate tables for reportdate's consumption, month consumption and average consumption--        
declare @body1 nvarchar(max),@subject1 nvarchar(200)        
set @body1 = (select 'User Alerts proc started at ' + cast(GETDATE() as nvarchar) + ' for users ' + @users + '.')        
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='karuna@pelsoftlabs.in',        
@copy_recipients='csshukla@pelsoftlabs.in',        
@subject='Alert mails started on live',        
@body = @body1        
            
            
            
    create table #ReportdaySMSconsumption(user_id bigint,DaySMSConsumption bigint)        
    create clustered index ix_#ReportdaySMSconsumption on #ReportdaySMSconsumption(User_id,DaySMSConsumption)        
            
    create table #ReportdayMailconsumption(user_id bigint,DayMailConsumption bigint)        
    create clustered index ix_#ReportdayMailconsumption on #ReportdayMailconsumption(User_id,DayMailConsumption)        
        
    create table #ReportMonthSMSconsumption(user_id bigint,MonthSMSConsumption bigint)        
    create clustered index ix_#ReportMonthSMSconsumption on #ReportMonthSMSconsumption(User_id,MonthSMSConsumption)        
        
    create table #ReportMonthMailconsumption(user_id bigint,MonthMailConsumption bigint)        
    create clustered index ix_#ReportMonthMailconsumption on #ReportMonthMailconsumption(User_id,MonthMailConsumption)        
        
    create table #AverageSMSconsumption(user_id bigint,AverageSMSConsumption bigint,CurrentSMSBalance bigint,resellerdomain varchar(100),UEmail varchar(100),User_login varchar(100))        
    create clustered index ix_#AverageSMSconsumption on #AverageSMSconsumption(User_id,AverageSMSConsumption,CurrentSMSBalance)        
        
    create table #AverageMailconsumption(user_id bigint,AverageMailConsumption bigint,CurrentMailBalance bigint)        
    create clustered index ix_#AverageMailconsumption on #AverageMailconsumption(User_id,AverageMailConsumption,CurrentMailBalance)      
          
          
            
    if @users <>'0'        
    begin        
    --select 1        
    insert into #AverageSMSconsumption        
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,case when r.domain='www.sms19.com' then 'www.kit19.com' 
     
else r.domain end as resellerdomain,email as UEmail,User_login as      
 User_login from user_detail u (nolock) 
 left join reseller_detail r (nolock) on u.m_id=r.reseller_id 
 left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 
 where  u.USER_ID in (select value from dbo.fn_Split(@users,','))      
and not exists(select 1 from tbl_subscription (nolock) t where t.status<>'Subscribed' and t.userid=335 and t.emails=u.email)    
 group by u.user_id,r.Domain,email,user_login  
    insert into #AverageMailconsumption        
  select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join     
 MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID in (select value from dbo.fn_Split(@users,',')) group by u.user_id        
        
    insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)        
    select c.user_id,sum(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id        
    insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)        
    select c.user_id,sum(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id        
        
    insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)        
    select c.user_id,sum(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id        
    insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)        
    select c.user_id,sum(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear and c.USER_ID in (select value from dbo.fn_Split(@users,',')) group by c.user_id        
        
    end        
    else        
    begin        
    --select 2        
    insert into #AverageSMSconsumption        
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,case when r.domain='www.sms19.com' then 'www.kit19.com' 
  
    
else r.domain end as resellerdomain,Email as Uemail,User_login as      
 User_login from user_detail u (nolock) 
 left join reseller_detail r (nolock) on u.m_id=r.reseller_id 
 left join MonthlyConsumption a (nolock) on a.User_id=u.user_id 
 and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,GETDATE()), 0))<=3 
 where     
 u.USER_ID not in (select USER_ID from user_detail where m_id<>10043 or Status=0 ) and u.email not like '%pelsoftlabs.in'   
 and not exists(select 1 from tbl_subscription (nolock) t where t.status<>'Subscribed' and t.userid=335 and t.emails=u.email)    
 group by u.user_id,r.Domain,email,User_Login      
 union       
select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from credit_details where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentSMSBalance,r.domain as resellerdomain,Email as Uemail,User_login as    
 
User_login from user_detail u (nolock) left join reseller_detail r (nolock) on u.m_id=r.reseller_id left join MonthlyConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,GETDATE()), 0))<=3 where 
u.email in (    
'karuna@pelsoftlabs.in','csshukla@pelsoftlabs.in')   
and not exists(select 1 from tbl_subscription (nolock) t where t.status<>'Subscribed' and t.userid=335 and t.emails=u.email)    
group by u.user_id,r.Domain,email,User_Login       
    --select * from #AverageSMSconsumption        
    insert into #AverageMailconsumption        
    select u.user_id,isnull(Avg(a.TotalConsumption),0) as AverageConsumption,ISNULL((select top 1 balance from mailcreditdetails where USER_ID=u.User_ID order by Credit_ID desc),0) as CurrentMailBalance from user_detail u (nolock) left join     
 MonthlyMailConsumption a (nolock) on a.User_id=u.user_id and DATEDIFF(m,firstdate,DATEADD(month, DATEDIFF(month, 0,@reportfirstdate), 0))<=3 where u.USER_ID not in (select USER_ID from user_detail where m_id<>10043 and Status=0 ) group by u.user_id      
  
        
    insert into #ReportdaySMSconsumption(user_id ,DaySMSConsumption)        
    select c.user_id,sum(debits) as DaySMSConsumption from credit_details c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id        
    insert into #ReportdayMailconsumption(user_id ,DayMailConsumption)        
    select c.user_id,sum(debits) as DayMailConsumption from mailcreditdetails c (nolock) where FromUser_ID=c.USER_ID and cast(DateCreated as DATE)=@reportdate group by c.user_id        
        
    insert into #ReportMonthSMSconsumption(user_id ,MonthSMSConsumption)        
    select c.user_id,sum(debits) from credit_details c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id        
    insert into #ReportMonthMailconsumption(user_id ,MonthMailConsumption)        
    select c.user_id,sum(debits) from MailCreditDetails c (nolock) where FromUser_ID=c.USER_ID and month(DateCreated)=@reportmonth and year(datecreated)=@reportyear group by c.user_id        
    end        
        
    --Create & populate tables for lead management        
    create table #NewEnquiries(user_id bigint,NewEnquiries int)        
    create clustered index ix_#NewEnquiries on #NewEnquiries(user_id,NewEnquiries)        
            
    create table #NewLeads(user_id bigint,NewLeads int)        
    create clustered index ix_#NewLeads on #NewLeads(user_id,NewLeads)        
        
    create table #NewConversions(user_id bigint,NewConversions int,dayorderamount money)        
    create clustered index ix_#NewConversions on #NewConversions(user_id,NewConversions,dayorderamount)        
        
    create table #MonthEnquiries(user_id bigint,MonthEnquiries int)        
    create clustered index ix_#MonthEnquiries on #MonthEnquiries(user_id,MonthEnquiries)        
            
    create table #MonthLeads(user_id bigint,MonthLeads int)        
    create clustered index ix_#MonthLeads on #MonthLeads(user_id,MonthLeads)        
        
    create table #MonthConversions(user_id bigint,MonthConversions int,orderamount money)        
    create clustered index ix_#MonthConversions on #MonthConversions(user_id,MonthConversions,orderamount)        
        
    insert into #NewEnquiries        
    select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID where cast(Createddate as DATE)=@reportdate group by user_id         
    insert into #NewLeads        
    select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where cast(Createdon as DATE)=@reportdate group by user_id        
    insert into #NewConversions        
    select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID     
 where cast(l.CreatedOn as DATE)=@reportdate and l.FollowUpStatus=5 group by user_id        
        
    insert into #monthEnquiries        
    select user_id,COUNT(1) from #AverageSMSconsumption a left join userenquiry u(nolock) on a.user_id=u.ParentID  where month(Createddate)=@reportmonth and YEAR(CreatedDate)=@reportyear group by user_id        
    insert into #MonthLeads        
    select user_id,COUNT(1) from #AverageSMSconsumption a left join  userleads u (nolock) on a.user_id=u.ParentID  where month(Createdon)=@reportmonth and year(Createdon)=@reportyear  group by user_id        
    insert into #monthConversions        
    select user_id,COUNT(1),sum(l.AmountPaid) from #AverageSMSconsumption a left join  userleads ul (nolock) on a.user_id=ul.ParentID join LeadInteractionHistory l on l.LeadNo=ul.LeadNo and ul.ParentID=l.ParentID where month(l.CreatedOn)=@reportmonth and 
  
    
      
YEAR(l.CreatedOn)=@reportyear and l.FollowUpStatus=5 group by user_id        
        
    --Create & populate tables for campaigns        
        
    create table #Campaigns(user_id bigint,TotalSMSCampaigns int,TotalMailCampaigns int)        
    create clustered index IX_#Campaigns on #Campaigns(user_id,TotalSMSCampaigns,TotalMailCampaigns)        
        
    insert into #Campaigns        
    select a.user_id,sum(case when c.medium='SMS' and isactive=1 then 1 else 0 end) as SMSCampaigns,sum(case when c.medium<>'SMS' and isactive=1 then 1 else 0 end) as MailCampaigns from #AverageSMSconsumption a left join UserCampaignMaster c on c.ParentID
  
    
      
=a.user_id group by user_id        
        
    --Create & populate table for landingpages & webform        
        
    create table #landingpages(user_id bigint,TotalLandingPages int)        
    create table #landingpageLeads(user_id bigint,LDayLeads int,LMonthLeads int)        
    create table #Webforms(user_id bigint,TotalWebforms int)        
    create table #WebformLeads(user_id bigint,WDayLeads int,WMonthLeads int)        
        
    insert into #landingpages        
    select a.user_id,COUNT(id) from #AverageSMSconsumption a left join ClientPageDetail c on a.user_id=c.User_ID group by a.user_id        
    insert into #landingpageLeads        
    select a.user_id,SUM(case when CAST(l.DateCreated as date) = @reportdate then 1 else 0 end),SUM(case when month(l.DateCreated) = @reportmonth and YEAR(l.datecreated)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join       
    clientpagedetail c on c.User_ID=a.user_id join ClientLeadDetails l on l.cname=right(pagename,len(pagename)-CHARINDEX(pagename,'/',1)) group by a.user_id        
    insert into #webforms        
    select a.user_id,COUNT(FormId) from #AverageSMSconsumption a left join webformtbl c on a.user_id=c.parentID group by a.user_id        
    insert into #webformLeads        
    select a.user_id,SUM(case when CAST(l.EntryDate as date) = @reportdate then 1 else 0 end),SUM(case when month(l.EntryDate) = @reportmonth and YEAR(l.EntryDate)=@reportyear then 1 else 0 end) from #AverageSMSconsumption a left join webformtbl c       
    on a.user_id=c.parentID left join WebEntryTbl l on l.formid=c.formID group by user_id        
        
    --Create & populate onlineorders table        
        
    Create table #Onlineorders(user_id bigint,DayOrders int,DayOrderAmount money,MonthOrders int,MonthOrderAmount money)        
        
    insert into #Onlineorders        
    select b.user_id,SUM(case when CAST(a.CreatedOn as date)=@reportdate then 1 else 0 end) as DayOrders,SUM(case when CAST(a.CreatedOn as date)=@reportdate then a.totalamount else 0 end) as DayOrderAmount,SUM(case when month(a.CreatedOn)=@reportmonth and
  
    
      
 YEAR(a.createdon)=@reportyear then 1 else 0 end) as MonthOrders,SUM(case when month(a.CreatedOn)=@reportmonth and YEAR(a.createdon)=@reportyear then a.totalamount else 0 end) as MonthOrderAmount from #AverageSMSconsumption b left join UserOrders a on    
  
   
 a.parentid=b.user_id group by b.user_id       
       
 create table #ServiceTicketUsage(user_id bigint,Ticketsgeneratedthismonth int,ticketsreceivedyesterday int,Ticketsresolvedyesterday int,Ticketsresolvedthismonth int,TicketsExceedingSLA int, TicketsUnresolvedtilldate int)         
        
 insert into #ServiceTicketUsage(user_id,Ticketsgeneratedthismonth,ticketsreceivedyesterday,Ticketsresolvedyesterday,Ticketsresolvedthismonth,TicketsExceedingSLA, TicketsUnresolvedtilldate)      
 select b.user_id,SUM(case when month(a.date_created)=@reportmonth and      
 YEAR(a.date_created)=@reportyear then 1 else 0 end) as Ticketsgeneratedthismonth,SUM(case when CAST(a.date_created as date)=@reportdate then 1 else 0 end) as ticketsreceivedyesterday,SUM(case when a1.status=0 and CAST(a1.historydate as date)=@reportdate 
  
    
then 1 else 0 end) as Ticketsresolvedyesterday,SUM(case when a1.status=0 and month(a1.historydate)=@reportmonth and YEAR(a1.historydate)=@reportyear then 1 else 0 end) as Ticketsresolvedthismonth,0,0      
  from #AverageSMSconsumption b left join Serv_TicketMaster a on       
 a.parentid=b.user_id left join serv_tickethistory a1 on a.ticketid=a1.ticketid      
  group by b.user_id         
        
begin tran        
truncate table Alertsdata1        
    insert into Alertsdata1(ReportDate,user_id,DaySMSConsumption,DayMailConsumption,MonthSMSConsumption,MonthMailConsumption,AverageSMSConsumption,AverageMailConsumption,CurrentSMSBalance,CurrentMailBalance,NewEnquiries,NewLeads,NewConversions,      
    Dayorderamount,MonthEnquiries,MonthLeads,MonthConversions,OrderAmount,TotalSMSCampaigns,TotalMailCampaigns,TotalLandingPages,        
    LandingPageDayLeads,LandingPageMonthLeads,TotalWebforms,WebformDayLeads,WebformMonthLeads,DayEshopOrders,DayEshopOrderAmount,EshopMonthOrders,EshopMonthOrderAmount,resellerdomain,Uemail,User_login,Ticketsgeneratedthismonth,ticketsreceivedyesterday,   
 
 Ticketsresolvedyesterday,Ticketsresolvedthismonth,TicketsExceedingSLA, TicketsUnresolvedtilldate)        
    select @ReportDate as ReportDate,isnull(a.user_id,0) as User_id,isnull(rds.DaySMSConsumption,0) as DaySMSConsumption ,isnull(rdm.DayMailConsumption,0) as DayMailConsumption,isnull(rms.MonthSMSConsumption,0) as MonthSMSConsumption,      
    isnull(rmm.MonthMailConsumption,0) as MonthMailConsumption        
    ,isnull(a.AverageSMSConsumption,0) as AverageSMSConsumption,isnull(am.AverageMailConsumption,0) as AverageMailConsumption,a.CurrentSMSBalance,am.CurrentMailBalance,isnull(nw.NewEnquiries,0) as NewEnquiries,isnull(nl.NewLeads,0) as NewLeads,      
    isnull(nc.NewConversions,0) as NewConversions,isnull(nc.dayorderamount,0) as Dayorderamount        
    ,isnull(me.MonthEnquiries,0) as MonthEnquiries,isnull(ml.MonthLeads,0) as MonthLeads,isnull(mc.MonthConversions,0) as MonthConversions,isnull(mc.orderamount,0) as OrderAmount,isnull(c.TotalSMSCampaigns,0) as TotalSMSCampaigns        
    ,isnull(c.TotalMailCampaigns,0) as TotalMailCampaigns,isnull(lp.TotalLandingPages,0) as TotalLandingPages,isnull(lpl.LDayLeads,0) as LandingPageDayLeads,isnull(lpl.LMonthLeads,0) as LandingPageMonthLeads,isnull(wf.TotalWebforms,0) as TotalWebforms    
  
    
    ,isnull(wfl.WDayLeads,0) as WebformDayLeads,isnull(wfl.WMonthLeads,0) as WebformMonthLeads,isnull(oo.DayOrders,0) as DayEshopOrders,isnull(oo.DayOrderAmount,0) as DayEshopOrderAmount,isnull(oo.MonthOrders,0) as EshopMonthOrders,      
    isnull(oo.MonthOrderAmount,0) as EshopMonthOrderAmount,isnull(resellerdomain,'www.kit19.com') as resellerdomain,Uemail,User_login,Ticketsgeneratedthismonth,ticketsreceivedyesterday,Ticketsresolvedyesterday,Ticketsresolvedthismonth,TicketsExceedingSLA,
  
    
 TicketsUnresolvedtilldate --into #AlertsData        
    from         
    #AverageSMSconsumption a left join #AverageMailconsumption am on a.user_id=am.user_id        
    left join #ReportdaySMSconsumption rds on rds.user_id=a.user_id        
    left join #ReportdayMailconsumption rdm on rdm.user_id=a.user_id        
    left join #ReportMonthSMSconsumption rms on rms.user_id=a.user_id        
    left join #ReportMonthMailconsumption rmm on rmm.user_id=a.user_id        
    left join #NewEnquiries nw on nw.user_id=a.user_id        
    left join #NewLeads nl on nl.user_id=a.user_id        
    left join #NewConversions nc on nc.user_id=a.user_id        
    left join #MonthEnquiries me on me.user_id=a.user_id        
    left join #MonthLeads ml on ml.user_id=a.user_id        
    left join #MonthConversions mc on mc.user_id=a.user_id        
    left join #Campaigns c on c.user_id=a.user_id        
    left join #landingpages lp on lp.user_id=a.user_id        
    left join #landingpageLeads lpl on lpl.user_id=a.user_id        
    left join #Webforms wf on wf.user_id=a.user_id        
    left join #WebformLeads wfl on wfl.user_id=a.user_id        
    left join #Onlineorders oo on oo.user_id=a.user_id        
    left join #ServiceTicketUsage so on so.user_id=a.user_id      
    where UEmail is not null and UEmail <>''        
    commit        
--select COUNT(1) from Alertsdata1        
--select 'unpivotStart',GETDATE()        
        
begin tran        
--truncate table ReplaceableRecords         
--insert into ReplaceableRecords        
select u.User_ID,u.UEmail as Email, case u.ColumnName when 'resellerdomain' then 'kit19.com' else u.columnname end as ColumnName, cast(u.ColumnValue as nvarchar(100)) as ColumnValue        
into #ReplaceableRecords         
from Alertsdata1 s        
unpivot        
(        
  ColumnValue        
  for ColumnName in (ReportDate,        
DaySMSConsumption,        
DayMailConsumption,        
--MonthSMSConsumption,        
--MonthMailConsumption,        
--AverageSMSConsumption,        
--AverageMailConsumption,        
CurrentSMSBalance,        
CurrentMailBalance,        
NewEnquiries,        
NewLeads,        
NewConversions,        
--Dayorderamount,        
MonthEnquiries,        
MonthLeads,        
MonthConversions,        
OrderAmount,        
TotalSMSCampaigns,        
TotalMailCampaigns,        
TotalLandingPages,        
LandingPageDayLeads,        
LandingPageMonthLeads,        
TotalWebforms,        
WebformDayLeads,        
WebformMonthLeads,        
DayEshopOrders,        
DayEshopOrderAmount,        
EshopMonthOrders,        
EshopMonthOrderAmount,        
resellerdomain,        
User_login,      
Ticketsgeneratedthismonth,      
ticketsreceivedyesterday,      
Ticketsresolvedyesterday,      
Ticketsresolvedthismonth,      
TicketsExceedingSLA,       
TicketsUnresolvedtilldate        
)        
) u;        
commit        
declare @email varchar(100),@tcount int=(select COUNT(distinct user_id) from #ReplaceableRecords)        
--select 'RecordReplaceStart',GETDATE()        
declare @user_id bigint,@ucount int=(select COUNT(distinct user_id) from #ReplaceableRecords),@content nvarchar(max)=(select content from notifications where id=3)        
        
set @body1 = (select 'User Alert Mails replace started at ' + cast(GETDATE() as nvarchar) + ' for total no. of users ' + cast(@tcount as varchar(10)) + '.')        
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='karuna@pelsoftlabs.in',        
--@copy_recipients='csshukla@pelsoftlabs.in',        
@subject='Alert mails replace started on live',        
@body = @body1        
        
  
  
declare @batchid bigint  
begin tran  
INSERT INTO Getbatchrecord                                              
([User_id],RandNum)                                              
SELECT 335,10043        
select @batchid =SCOPE_IDENTITY()       
delete From GetBatchRecord where BatchID=@batchid        
commit  
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo, 
  
    
     
Tablename)        
SELECT @BatchID,335,'noreply@email19.in' as SenderName,@content,@tcount,0,0,0,0,Getdate(),NULL,dateadd(day, datediff(day, 0, getdate()), 0) + '9:00',dateadd(day, datediff(day, 0, getdate()), 0) + '9:00',0,0,0,0,'Your business as on ' +       
cast(@reportdate as nvarchar(20)),'noreply@email19.in',        
'UserAlertMails'        
truncate table UserAlertMails        
declare @insertedguid varchar(200)        
while @ucount>0        
 begin        
    select @user_id=MIN(USER_ID) from #ReplaceableRecords        
    select top 1 @email=Email from #ReplaceableRecords where user_id=@user_id        
    select @content=REPLACE(@content,'#'+ColumnName+'#',Columnvalue) from #ReplaceableRecords where user_id=@user_id        
            
    insert into UserAlertMails(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,     
 
    IsMonitor,TemplateID,Count,Source)        
    select 'noreply@email19.in',@email,'Your business as on ' + cast(@reportdate as nvarchar(20)),0,@content,GETDATE(),335,335,'noreply@email19.in',@batchid,0,dateadd(day, datediff(day, 0, getdate()), 0) + '9:00',dateadd(day, datediff(day, 0, getdate  
    
      
()), 0) + '9:00','',@content,1,0,@tcount,'Alerts'        
    set @content=(select content from notifications where id=3)        
    delete From #ReplaceableRecords where USER_ID=@user_id        
    set @ucount=@ucount-1        
    if @ucount%2000=0        
    begin        
set @body1 = (select 'User Alert Mails replaced for ' +cast((@tcount-@ucount) as varchar(10)) + ' no. of records')        
set @subject1='Alert mails replace completed '+cast(cast((@tcount-@ucount)*100 as money)/cast(@tcount as money) as varchar(10)) + '% on live'        
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='karuna@pelsoftlabs.in',        
--@copy_recipients='csshukla@pelsoftlabs.in',        
@subject=@subject1,        
@body = @body1        
    end        
    end        
declare @ccount int=(select COUNT(1) from UserAlertMails)        
set @body1 = (select 'User Alert Mails completed and schedule for ' +cast(@reportdate as varchar(30)) + ' for ' +CAST(@ccount as varchar(10))+ ' no. of records')        
set @subject1='Alert mails replace completed at '+cast(GETDATE() as varchar(30)) + ' on live'        
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='karuna@pelsoftlabs.in',        
--@copy_recipients='csshukla@pelsoftlabs.in',        
@subject=@subject1,        
@body = @body1        
 end           



GO

/* ============================================================
   Procedure: [dbo].[usp_UserEnquiry_MobileNoByIDS_MobileColumn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UserEnquiry_MobileNoByIDS_MobileColumn]    
 @ID VARCHAR(Max),                                
 @Account BIGINT,                                
 @Mobile BIT,                                
 @mobile1 BIT,                                
 @Mobile2 BIT,
 @massbatchid bigint=0  
AS                                
BEGIN                                
 declare @parentid bigint = (select Parentid from user_detail with(nolock) where USER_ID=@Account)
   
       if @massbatchid IS NOT NULL AND @massbatchid <> 0  
		BEGIN  
		 select @ID= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails with(nolock) where SummaryId=@massbatchid   
		END  

--drop table if exists #tempTable            
          
--select * into #tempTable from (                  
 select * from (    
 select         
 *        
  FROM   (                                
            SELECT CASE                                 
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), 0)                                
                        ELSE 0                                
                   END         AS Mobile  , ue.EnquiryID  
            FROM   UserEnquiry   AS ue with(nolock)   
   WHERE  ue.EnquiryId IN (SELECT [value]                                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                  
                   AND ISNULL(NULLIF(CAST(ue.MobileNo AS BIGINT), ''), '') <>                                 
                       ''                                 
                    AND not exists                           
                   (select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock) where parentid=@parentid 
				   and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))                          
                  -- where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))                          
                                            
                                            
                    
                                            
                                            
                                            
            UNION                                  
                                            
            SELECT CASE                                 
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), 0)                                
                        ELSE 0                                
                   END    AS Mobile  , ue.EnquiryID  
            FROM   UserEnquiry  AS ue with(nolock)                               
            WHERE  ue.EnquiryId IN (SELECT [value]                                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo1 AS BIGINT), ''), '') <                                
                       > ''                            
                        AND not exists(select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock) where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))                               
                                          
            UNION                                  
                                            
            SELECT CASE                                 
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), 0)                                
                        ELSE 0                                
                   END    AS Mobile  , ue.EnquiryID  
            FROM   UserEnquiry  AS ue with(nolock)                                
            WHERE  ue.EnquiryId IN (SELECT [value]                                
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                                
                   AND ISNULL(NULLIF(CAST(ue.MobileNo2 AS BIGINT), ''), '') <                      
                       > ''                           
                       AND not exists(select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock) 
					   where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))    
        ) A                                
 WHERE  A.Mobile <> 0) B          
    
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_UserEventTransferToCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_UserEventTransferToCRM
as
Begin
     
  CREATE TABLE #TempLinked                                
     (                                
        Result VARCHAR(200)                                
      )  

	

    INSERT INTO #TempLinked                                
    EXEC GetStatusofLinkedServer 'CRM'                                
    IF NOT EXISTS(                                
       SELECT 'x'                                
       FROM   #TempLinked                                
   )                     
   begin

   Select * into #tempUserEvent From (select row_number() OVER (order by id asc) AS ROWINDEX,* 
     from userEvent where CRMEntry = 0 ) as tb

	 declare @Count bigint = 0;

	 select @Count = count(1) from #tempUserEvent 
	 declare @RowNum bigint = 1;
	 Declare @ID bigint = 0;
	 Declare @RefNo bigint = 0;
	 Declare @UserID bigint = 0;
	 Declare @AccntMGR nvarchar(200) = ''
	 Declare @Mobileno nvarchar(50) = ''
	 declare @MSG nvarchar = ''
	 Declare @UID bigint = 0;
	 while(@Count >= @RowNum)
	 Begin
	   Select @UserID = UserID From #tempUserEvent where ROWINDEX = @RowNum
	 
	   select top 1  @RefNo =  isnull(RefrenceNo,0) From CRM.CRMDB.dbo.LinkedAccount where USER_ID = @UserID    

	   if(@RefNo > 0)
	     Begin
		
		 if(exists(select 1 from CRM.CRMDB.dbo.Assign_AccountManager where Refrence_No = @RefNo ))
		     Begin
			      
			      select top 1 @AccntMGR = isnull(Am_Name,'') from CRM.CRMDB.dbo.Assign_AccountManager where Refrence_No = @RefNo order by AM_ID desc
			      select @UID = User_ID From CRM.CRMDB.dbo.User_Login where USER_NAME = @AccntMGR

		if(exists(select 1 From CRM.CRMDB.dbo.LoginHistory where ID in (select max(Id) from CRM.CRMDB.dbo.LoginHistory where UserID = @UID) and  LogoutDate is null ))
			    Begin
				if( exists(select 1 From CRM.CRMDB.dbo.User_Login where User_ID = @UID and isnull(DeviceID,'') = ''))
					Begin
					
						 insert into CRM.CRMDB.dbo.CustomerNotification
						  (
						   [Event]
						  ,[RefNo]
						  ,[Description]
						  ,[URL]
						  ,[Executive]
						  )
						  select
						   [Event]
						  ,@RefNo
						  ,[Description]
						  ,'http://pelcti:81/User/PreSales/FindEnquiry.aspx'
						  ,@AccntMGR from #tempUserEvent where ROWINDEX = @RowNum									     
					  
				     end
					else
					 Begin

					 select @Mobileno = isnull(Mobile_No,'') from CRM.CRMDB.dbo.Pre_Enquiry where EnqNo = @RefNo
					 if(@Mobileno <> '')
					   Begin
					    --select 'Send msg' 
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						   exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
						       
					    end

					 End
					 
					End
					else
					 Begin
					    --select 'Send MSG1'
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						 exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
					 
				      End
				
		 end
		   else
		     Begin
			      if(exists(select 1 From CRM.CRMDB.dbo.user_login where User_Name in (select Executive from CRM.CRMDB.dbo.Pre_Enquiry where EnqNo = @RefNo) and Jobstatus = 'On Job'))
			         Begin
					   select @UID = isnull(USER_ID,0) From CRM.CRMDB.dbo.user_login where User_Name in (select Executive from CRM.CRMDB.dbo.Pre_Enquiry where EnqNo = @RefNo) and Jobstatus = 'On Job'  
					   if(exists(select 1 From CRM.CRMDB.dbo.LoginHistory where ID in (select max(Id) from CRM.CRMDB.dbo.LoginHistory where UserID = @UID) and  LogoutDate is null ))
			    Begin
				if( exists(select 1 From CRM.CRMDB.dbo.User_Login where User_ID = @UID and isnull(DeviceID,'') = ''))
					Begin
					
						 insert into CRM.CRMDB.dbo.CustomerNotification
						  (
						   [Event]
						  ,[RefNo]
						  ,[Description]
						  ,[URL]
						  ,[Executive]
						  )
						  select
						   [Event]
						  ,@RefNo
						  ,[Description]
						  ,'http://pelcti:81/User/PreSales/FindEnquiry.aspx'
						  ,@AccntMGR from #tempUserEvent where ROWINDEX = @RowNum									     
					  
				     end
					else
					 Begin

					 select @Mobileno = isnull(Mobile_No,'') from CRM.CRMDB.dbo.Pre_Enquiry where EnqNo = @RefNo
					 if(@Mobileno <> '')
					   Begin
					    --select 'Send msg' 
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						   exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
						       
					    end

					 End
					 
					End
					else
					 Begin
					    --select 'Send MSG1'
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						 exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
					 
				      End


					 End
			      else
				   Begin
				       goto abc
				   End
			 
			 End


			   
		 End 
       

	   else
	     Begin
		   
		   abc:

		  select top 1 @UID = isnull(USER_ID,0) from CRM.CRMDB.dbo.M_Permission where PermissionType = 'SignalR' order by CreatedDate desc
		 
		     if(exists(select 1 From CRM.CRMDB.dbo.LoginHistory where ID in (select max(Id) from CRM.CRMDB.dbo.LoginHistory where UserID = @UID) and  LogoutDate is null ))
			    Begin
				if( exists(select 1 From CRM.CRMDB.dbo.User_Login where User_ID = @UID and isnull(DeviceID,'') = ''))
					Begin
					
						 insert into CRM.CRMDB.dbo.CustomerNotification
						  (
						   [Event]
						  ,[RefNo]
						  ,[Description]
						  ,[URL]
						  ,[Executive]
						  )
						  select
						   [Event]
						  ,@RefNo
						  ,[Description]
						  ,'http://pelcti:81/User/PreSales/FindEnquiry.aspx'
						  ,@AccntMGR from #tempUserEvent where ROWINDEX = @RowNum									     
					  
				     end
					else
					 Begin

					 select @Mobileno = isnull(Mobile_No,'') from CRM.CRMDB.dbo.Pre_Enquiry where EnqNo = @RefNo
					 if(@Mobileno <> '')
					   Begin
					    --select 'Send msg' 
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						   exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
						       
					    end

					 End
					 
					End
					else
					 Begin
					    --select 'Send MSG1'
						  select  @MSG = [Event] + ' ref No ' + cast(@RefNo as nvarchar) + ' Desc: ' + [Description]
						  from #tempUserEvent where ROWINDEX = @RowNum
						   
						 exec [wserver142-ind].Mysms.dbo.usp_sendmessage 335,@MSG,@Mobileno,'KITAPP',0,1  
					 
				      End
		

		 
		 
		 End
		 -- end of first begin after loop


		select @ID = isnull(ID,0) From #tempUserEvent where ROWINDEX = @RowNum
		update UserEvent set CRMEntry = 1 where ID = @ID
	
	    set @RowNum = @RowNum + 1;
	 end
	 -- end while loop
	 drop table #tempUserEvent
	          
   end 

  
  drop table #TempLinked;  
	 	        
End


GO

/* ============================================================
   Procedure: [dbo].[Usp_UserEventTransferToCRM_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_UserEventTransferToCRM_New]                                    
as                                    
Begin                                    
                  
--select * from Price_UserSubscriptionDetails where IsNewPlan=1 and datediff(d,cast(getdate() as date),PlanEndDate) between -7 and 7                   
insert into Userevent(Event,UserID,Description,RefTable,RefID)                  
select case when cast(planenddate as date)>=cast(getdate() as date) then 'Subscription due for Expiry' else            
'Subscription expired' end,UserID, 'User '+cast(user_login as nvarchar) +' ''s Subscription '+ case when p.planenddate<getdate() then 'has expired on ' else 'will expire on ' end + cast(planenddate as nvarchar)                  
,'Price_UserSubscriptionDetails',p.id from Price_UserSubscriptionDetails p(nolock) join User_Detail u (nolock) on p.UserID=u.User_ID                  
where u.user_id=u.parentid and IsNewPlan=1 and datediff(d,cast(getdate() as date),PlanEndDate) between -7 and 7 and not exists                  
(select 1 from userevent(nolock) where event=case when cast(p.planenddate as date)>=cast(getdate() as date) then 'Subscription due for Expiry' else            
'Subscription expired' end and userid=p.userid and createdon>cast(getdate() as date))                  
                  
                                   
 CREATE TABLE #TempLinked                                                                    
   (                                                                    
        Result VARCHAR(200)                                                                    
   )                                      
                                   
  begin try                                
                                
                                
                                
    INSERT INTO #TempLinked                                                                    
    EXEC GetStatusofLinkedServer 'CRM'                                                                    
    IF NOT EXISTS(                                                                    
       SELECT 'x'                                                                    
       FROM   #TempLinked                                                                    
   )                                                         
 begin                                    
 declare @max bigint=isnull((select MAX(id) from userevent where CRMEntry=1),0)                                  
                                   
 --insert into CRM.CRMDB.dbo.UserEvent()                                  
 --Select isnull(RefrenceNo,0) as Refno,null as executive,0 as isprocessed,* from userEvent u left join LinkedAccount l                                  
 --on u.userid=l.user_id                                  
 --where CRMEntry = 0                                  
                                   
 insert into CRM.CRMDB.dbo.UserEvent                                  
      (                                  
    [ReferenceNo]                                  
   ,[ExecutiveName]                                  
   ,[IsProcessed]                                  
   ,[Event]                                  
      ,[UserID]                                  
      ,[Description]                                  
      ,[CreatedOn]                      
   ,eventdate                                
      ,[RefTable]                                  
      ,[RefID]                
   ,Mapping                
   ,MappingValue                                  
   )                                  
 Select                                  
    case when Mapping='Enqno' then MappingValue             
 else isnull(RefrenceNo,0) end as Refno,                                  
    null as executive,                                  
    0 as isprocessed,                                  
    [Event]                                  
      ,[UserID]        
      ,[Description]                                  
      ,getdate()                    
    ,[CreatedOn]                          
      ,[RefTable]                                  
      ,[RefID]                                  
   ,Mapping                
   ,MappingValue                
 from userEvent u(nolock) left join LinkedAccount(nolock) l                                  
  on u.userid=l.user_id                                  
  where CRMEntry = 0  -- and u.id <= 18                        
  and u.id>459084    
                      
                           
                                   
                          
   update userevent set CRMEntry=1 where ID >= @max                   
                          
   --update  userevent set CRMEntry=1 where ID <= 18                                  
                          
                                   
 --exec CRM.CRMDB.dbo.usp_insertfromusereventtocustNotification              
             
 -- exec CRM.CRMDB.dbo.usp_insertscheduledcampaigns                                
                                   
 end                                  
                                  
  end try                                
  begin catch                                
       exec Usp_inserterrorinfo                                  
  end catch                     
                                
                                
   drop table #TempLinked                                  
                                  
 end 


 --select top 100 * from UserEvent order by id desc


GO

/* ============================================================
   Procedure: [dbo].[Usp_userexecutecampaignmessages]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
CREATE   PROCEDURE [dbo].[Usp_userexecutecampaignmessages]              
AS              
BEGIN              
 CREATE TABLE #tempgroups              
 (              
  CampaignID         BIGINT,              
  ParentID           BIGINT,              
  MessageContent     VARCHAR(2000),              
  Mobile             VARCHAR(50),              
  SenderID           VARCHAR(50),              
  AccountUsed        VARCHAR(50),              
  IsUnicode          BIT              
 )              
               
 INSERT INTO #tempgroups              
   (              
     CampaignID,              
     ParentID,              
     MessageContent,              
     Mobile,              
     SenderID,              
     AccountUsed,              
     IsUnicode              
   )              
 EXEC Fn_getgroupmessage              
               
 SELECT A.CampaignID,              
        A.ParentID,              
        A.[Message],              
        A.Mobile,              
        A.SenderID,              
        A.AccountUsed,              
        A.IsUnicode              
        INTO     #temptable              
 FROM   (              
            SELECT Uceh.CampaignID,              
                   Uceh.ParentID,              
                   Ucm.[Message],              
                   Ucerm.Mobile,              
                   Ucm.SenderID,              
                   Ucm.AccountUsed,              
                   Ucm.IsUnicode              
            FROM   Usercampaignexecutionhistory Uceh  (nolock)            
                   INNER JOIN Usercampaignmaster Ucm (nolock)              
                        ON  Ucm.ID = Uceh.CampaignID              
                   OUTER APPLY Usercampaignexecutionrecipientsmessage Ucerm  (nolock)             
            WHERE  Uceh.IsRecipients = 1              
                   AND Ucm.[Message] <> ''              
            UNION              
            SELECT Uceh.CampaignID,              
                   Uceh.ParentID,              
                   Dbo.Fn_getenquirymessage(Ucm.ParentID, Umt.MailContent, Ucerm.Mobile),              
                   Ucerm.Mobile,              
                   Ucm.SenderID,              
                   Ucm.AccountUsed,              
                   Ucm.IsUnicode              
            FROM   Usercampaignexecutionhistory Uceh   (nolock)            
                   INNER JOIN Usercampaignmaster Ucm    (nolock)           
                        ON  Ucm.ID = Uceh.CampaignID              
                   INNER JOIN Usermailtemplate Umt   (nolock)            
                        ON  Ucm.TemplateID = Umt.ID              
                   INNER JOIN Usercampaignexecutionrecipientsmessage Ucerm   (nolock)            
                        ON  Ucerm.CampaignID = Uceh.CampaignID              
                        AND Ucerm.ParentID = Umt.ParentID              
            WHERE  Uceh.IsRecipients = 1              
                   AND Umt.IsEnquiry = 1              
            UNION              
            SELECT Uceh.CampaignID,              
                   Uceh.ParentID,              
                   Dbo.Fn_getleadsmessage(Ucm.ParentID, Umt.MailContent, Ucerm.Mobile),              
                   Ucerm.Mobile,              
                   Ucm.SenderID,              
                   Ucm.AccountUsed,              
                   Ucm.IsUnicode              
            FROM   Usercampaignexecutionhistory Uceh   (nolock)            
                   INNER JOIN Usercampaignmaster Ucm (nolock)              
                        ON  Ucm.ID = Uceh.CampaignID              
                   INNER JOIN Usermailtemplate Umt              
                        ON  Ucm.TemplateID = Umt.ID              
                   INNER JOIN Usercampaignexecutionrecipientsmessage Ucerm              
                        ON  Ucerm.CampaignID = Uceh.CampaignID              
                        AND Ucerm.ParentID = Umt.ParentID              
            WHERE  Uceh.IsRecipients = 1              
             AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1)              
            UNION              
            SELECT Uceh.CampaignID,              
                   Uceh.ParentID,              
                   Dbo.Fn_getlistmessage(Umt.MailContent, Umt.ListID, Uceh.ParentID, Ucerm.Mobile),              
                   Ucerm.Mobile,              
                 Ucm.SenderID,              
                   Ucm.AccountUsed,              
                   Ucm.IsUnicode              
            FROM   Usercampaignexecutionhistory Uceh  (nolock)                          INNER JOIN Usercampaignmaster Ucm              
                        ON  Ucm.ID = Uceh.CampaignID              
                   INNER JOIN Usermailtemplate Umt  (nolock)             
         ON  Ucm.TemplateID = Umt.ID              
                   INNER JOIN Usercampaignexecutionrecipientsmessage Ucerm (nolock)              
                        ON  Ucerm.CampaignID = Uceh.CampaignID              
              AND Ucerm.ParentID = Umt.ParentID              
            WHERE  Uceh.IsRecipients = 1              
                   AND Umt.IsList = 1              
            UNION              
            SELECT CampaignID,              
                   ParentID,              
                   CAST(              
                       CAST(MessageContent AS VARCHAR(MAX)) COLLATE              
                       Latin1_general_ci_ai              
                       AS              
                       VARCHAR(MAX)              
                   ),              
                   CAST(              
                       CAST(Mobile AS VARCHAR(MAX)) COLLATE              
                       Latin1_general_ci_ai AS              
                       VARCHAR(MAX)              
                   ),              
                   CAST(              
                       CAST(SenderID AS VARCHAR(MAX)) COLLATE              
                       Latin1_general_ci_ai              
                       AS              
                       VARCHAR(MAX)              
                   ),              
                   AccountUsed,              
                   IsUnicode              
            FROM   #tempgroups              
        )        A              
               
 DROP TABLE #tempgroups              
               
 UPDATE Kd              
 SET    Kd.[Message] = CAST(              
            CAST(A.[Message] AS VARCHAR(MAX)) COLLATE              
            Latin1_general_ci_ai AS VARCHAR(MAX)              
        ),              
        Kd.SenderID = CAST(              
            CAST(A.SenderID AS VARCHAR(MAX)) COLLATE              
            Latin1_general_ci_ai              
            AS VARCHAR(MAX)              
        ),              
        Kd.U_ID = A.AccountUsed,              
        Kd.IsCompleted = 1,              
        Kd.IsUniCode = A.IsUnicode              
 FROM   Usercampaignexecutionrecipientsmessage Kd  (nolock)             
        INNER JOIN #temptable A              
             ON  Kd.CampaignID = A.CampaignID              
             AND Kd.ParentID = A.ParentID              
             AND Kd.Mobile = CAST(              
                     CAST(A.Mobile AS VARCHAR(MAX))              
                     COLLATE              
                     Latin1_general_ci_ai AS              
                     VARCHAR(MAX)              
                 )              
               
 --UPDATE Kd              
 --SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()            
 --FROM   Usercampaignhistory Kd              
 --       INNER JOIN #temptable A              
 --            ON  Kd.CampaignID = A.CampaignID              
 --            AND Kd.ParentID = A.ParentID            
           
 UPDATE Kd              
 SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE(), Step2Recipients=isnull(A.Step2Recipients,0)           
 FROM   Usercampaignhistory Kd (nolock)              
        INNER JOIN           
        (select campaignid,count(campaignid) as Step2Recipients,parentid from #temptable group by Parentid,campaignid) A              
             ON  Kd.CampaignID = A.CampaignID join ##campaignrun c on Kd.ID=c.campaignrunid        
                   
--UPDATE Kd  SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()     FROM   Usercampaignhistory Kd          
--        INNER JOIN  ##campaignrun c on Kd.ID=c.campaignrunid               
                       
                         
               
 DROP TABLE #temptable              
END           
          
--select top 40 * from UserCampaignHistory where campaignid=240 order by ID desc        
--select * from Usercampaignexecutionrecipientsmessage


GO

/* ============================================================
   Procedure: [dbo].[usp_UserExecuteCampaignMessages_New1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
  
CREATE   PROCEDURE [dbo].[usp_UserExecuteCampaignMessages_New1]  
  
AS  
  
BEGIN  
  
 CREATE TABLE #tempGroups  
  
 (  
  
  CampaignID         BIGINT,  
  
  ParentID           BIGINT,  
  
  MessageContent     VARCHAR(2000),  
  
  Mobile             VARCHAR(50),  
  
  SenderID           VARCHAR(50),  
  
  AccountUsed        VARCHAR(50),  
  
  IsUnicode          BIT  
  
 )  
  
      
  
   
  
 INSERT INTO #tempGroups  
  
   (  
  
     CampaignID,  
  
     ParentID,  
  
     MessageContent,  
  
     Mobile,  
  
     SenderID,  
  
     AccountUsed,  
  
     IsUnicode  
  
   )  
  
 EXEC fn_GetGroupMessage  
  
     
   
  
 SELECT A.CampaignID,  
  
        A.ParentID,  
  
        A.[Message],  
  
        A.Mobile,  
  
        A.SenderID,  
  
        A.AccountUsed,  
  
        A.IsUnicode INTO     #TempTable  
  
 FROM   (  
  
            SELECT uceh.CampaignID,  
  
                   uceh.ParentID,  
  
                   ucm.[Message],  
  
                   ucerm.Mobile,  
  
                   ucm.SenderID,  
  
                   ucm.AccountUsed,  
  
                   ucm.IsUnicode  
  
            FROM   UserCampaignExecutionHistory uceh  
  
                   INNER JOIN UserCampaignMaster ucm  
  
                        ON  ucm.ID = uceh.CampaignID  
  
                   OUTER APPLY UserCampaignExecutionRecipientsMessage ucerm  
  
            WHERE  uceh.IsRecipients = 1  
  
                   AND ucm.[Message] <> ''   
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            UNION     
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            SELECT uceh.CampaignID,  
  
                   uceh.ParentID,  
  
                   dbo.fn_getEnquiryMessage(ucm.ParentID, umt.MailContent, ucerm.Mobile),  
  
                   ucerm.Mobile,  
  
                   ucm.SenderID,  
  
                   ucm.AccountUsed,  
  
                   ucm.IsUnicode  
  
            FROM   UserCampaignExecutionHistory uceh  
  
                   INNER JOIN UserCampaignMaster ucm  
  
                        ON  ucm.ID = uceh.CampaignID  
  
                   INNER JOIN UserMailTemplate umt  
  
                        ON  ucm.TemplateID = umt.ID  
  
                   INNER JOIN UserCampaignExecutionRecipientsMessage   
  
                          
           
  
                          
  
                          
  
                          
  
                          
  
                          
  
                        ucerm  
  
                        ON  ucerm.CampaignID = uceh.CampaignID  
  
                        AND ucerm.ParentID = umt.ParentID  
  
            WHERE  uceh.IsRecipients = 1  
  
                   AND umt.IsEnquiry = 1   
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            UNION     
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            SELECT uceh.CampaignID,  
  
                   uceh.ParentID,  
  
                   dbo.fn_getLeadsMessage(ucm.ParentID, umt.MailContent, ucerm.Mobile),  
  
                   ucerm.Mobile,  
  
                   ucm.SenderID,  
  
                   ucm.AccountUsed,  
  
                   ucm.IsUnicode  
  
            FROM   UserCampaignExecutionHistory uceh  
  
                   INNER JOIN UserCampaignMaster ucm  
  
                        ON  ucm.ID = uceh.CampaignID  
  
                   INNER JOIN UserMailTemplate umt  
  
                        ON  ucm.TemplateID = umt.ID  
  
                   INNER JOIN UserCampaignExecutionRecipientsMessage   
  
                          
  
                          
  
                          
  
                          
  
                          
  
                          
  
                          
  
                        ucerm  
  
                        ON  ucerm.CampaignID = uceh.CampaignID  
  
                        AND ucerm.ParentID = umt.ParentID  
  
            WHERE  uceh.IsRecipients = 1  
  
                   AND (umt.IsLeads = 1 OR umt.IsConversion = 1)   
  
              
  
              
  
              
  
              
  
              
  
              
  
       
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            UNION     
  
              
  
              
  
              
  
              
  
              
  
              
  
              
  
            SELECT uceh.CampaignID,  
  
                   uceh.ParentID,  
  
                   dbo.fn_GetListMessage(umt.MailContent, umt.ListID, uceh.ParentID, ucerm.Mobile),  
  
                   ucerm.Mobile,  
  
                   ucm.SenderID,  
  
                   ucm.AccountUsed,  
  
                   ucm.IsUnicode  
  
            FROM   UserCampaignExecutionHistory uceh  
  
                   INNER JOIN UserCampaignMaster ucm  
  
                        ON  ucm.ID = uceh.CampaignID  
  
                   INNER JOIN UserMailTemplate umt  
  
                        ON  ucm.TemplateID = umt.ID  
  
                   INNER JOIN UserCampaignExecutionRecipientsMessage   
  
                          
  
                          
  
                          
  
                          
  
                          
  
                          
  
                          
  
                        ucerm  
  
                        ON  ucerm.CampaignID = uceh.CampaignID  
  
                        AND ucerm.ParentID = umt.ParentID  
  
            WHERE  uceh.IsRecipients = 1  
  
                   AND umt.IsList = 1  
  
              
  
              
  
              
  
            UNION   
  
              
  
            SELECT CampaignID,  
  
                   ParentID,  
  
                   CAST(  
  
                       CAST(MessageContent AS VARCHAR(MAX)) COLLATE   
  
                         
  
                       Latin1_General_CI_AI AS  
  
                         
  
                       VARCHAR(MAX)  
  
                   ),  
  
                   CAST(  
  
                       CAST(Mobile AS VARCHAR(MAX)) COLLATE   
  
                         
  
                       Latin1_General_CI_AI AS VARCHAR(MAX)  
  
                   ),  
  
                   CAST(  
  
                       CAST(SenderID AS VARCHAR(MAX)) COLLATE   
  
                         
  
                       Latin1_General_CI_AI AS  
  
                         
  
                       VARCHAR(MAX)  
  
                   ),  
  
                   AccountUsed,  
  
                   IsUnicode  
  
            FROM   #tempGroups  
  
        )                    A   
  
   
  
   
  
   
  
   
  
   
  
 DROP TABLE #tempGroups  
  
   
  
   
  
   
  
   
  
   
  
   
  
   
  
   
  
   
  
 UPDATE kd  
  
 SET    kd.[Message] = CAST(  
  
            CAST(A.[Message] AS VARCHAR(MAX)) COLLATE   
  
              
  
            Latin1_General_CI_AI AS VARCHAR(MAX)  
  
        ),  
  
        kd.SenderID = CAST(  
  
            CAST(A.SenderID AS VARCHAR(MAX)) COLLATE   
  
              
  
            Latin1_General_CI_AI AS VARCHAR(MAX)  
  
        ),  
  
        kd.U_ID = A.AccountUsed,  
  
        kd.IsCompleted = 1,  
  
        kd.IsUniCode = A.IsUnicode  
  
 FROM   UserCampaignExecutionRecipientsMessage kd  
  
        INNER JOIN #TempTable A  
  
             ON  kd.CampaignID = A.CampaignID  
  
             AND kd.ParentID = A.ParentID  
  
             AND kd.Mobile = CAST(  
  
                     CAST(A.Mobile AS VARCHAR(MAX)) COLLATE   
  
                       
  
                     Latin1_General_CI_AI AS VARCHAR(MAX)  
  
                 )  
   
   
  
 DROP TABLE #TempTable  
  
END  
  



GO

/* ============================================================
   Procedure: [dbo].[Usp_userexecutecampaignmessagesCorrected]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                          
CREATE   PROCEDURE [dbo].[Usp_userexecutecampaignmessagesCorrected]            
@Jobid  bigint                      
AS                          
BEGIN                          
           
 create table #TempTable                                            
   (                                            
   CampaignID bigint,ParentID bigint,[Message] nvarchar(2000),Mobile varchar(50),SenderID varchar(10),AccountUsed bigint,                                            
   IsUnicode bit                                           
   )                                            
                        
Select Distinct EC.CampaignID,EC.ParentID into #usercampaignexecutionrecipientsmessageTest2                  from usercampaignexecutionrecipientsmessageTest2 EC With(nolock) where jobid=@jobid         
        
CREATE TABLE #tempgroups                          
 (          
  CampaignID         BIGINT,                          
  templategroupid    BIGINT,                          
  templateid         bigint,                          
  orderno            int,                          
  isending           BIT                          
 )          
        
if exists(select '1' from UserCampaignMaster ucm   
 join #usercampaignexecutionrecipientsmessageTest2 uc on uc.CampaignID=ucm.ID   
 where TemplateGroupID<>0)         
begin          
 INSERT INTO #tempgroups                          
   (                          
     campaignid,        
     templategroupid,        
     templateid,        
     orderno,        
     isending        
   )                          
 exec [GetnextTemplate] @jobid        
   
 select * from #tempgroups          
end         
          
if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm  (nolock)    
 Inner Join #usercampaignexecutionrecipientsmessageTest2 EC on EC.CampaignId = Ucm.ID     
 --OUTER APPLY EmailsfiltercampaignexecutionTest2 AS Ucerm   (nolock)                                  WHERE  isnull(Ucm.MailReplyTo,'') = ''                                              
               AND ucm.TemplateID=0  )  
begin   
                                        
   insert into #TempTable                                            
   (CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )   
   SELECT distinct Ucm.ID,                                              
                   Ucm.ParentID,     
     case when isnull(Ucerm.Message,'')='' then Ucm.Message else Ucerm.Message end message,      
                  -- Ucm.Message,                                              
                   Ucerm.Mobile,                                              
                   Ucm.SenderID,                                              
                   Ucm.AccountUsed AS AccountUsed,                                              
                   Ucm.IsUnicode                                            
            FROM   Usercampaignmaster Ucm  (nolock)                                           
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)      
                   ON ucm.ID=Ucerm.CampaignID                                                                
            WHERE  Ucerm.IsCompleted = 0                                              
                   AND Ucm.MailReplyTo = ''                                              
                   AND ucm.TemplateID=0 and jobid=@jobid    
                   and ucm.ID not in (select distinct CampaignID from #tempgroups)                                                   
end                                              
  
        
if exists (select top 1 'x'   FROM  Usercampaignmaster Ucm  (nolock)  
join UserMailTemplate umt on umt.ID=ucm.TemplateID    
Inner Join #usercampaignexecutionrecipientsmessageTest2 EC on EC.CampaignId = Ucm.ID        
   WHERE  Ucm.MailReplyTo = '' and TemplateID<>0 and umt.IsEnquiry=0 and   
   umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0        
   union        
   select top 1 'x' from #tempgroups tg INNER JOIN #usercampaignexecutionrecipientsmessageTest2   
   Ucerm  (nolock) ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt   
 on tg.templateid=umt.ID where umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0      )        
   begin  
    
   insert into #TempTable    
      (CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )  
      SELECT Ucm.ID as CampaignID,                                              
           Ucm.ParentID as ParentID,                                              
           umt.mailcontent as mailcontent,                                              
           Ucerm.mobile as Mobile,                                              
           Ucm.SenderID Senderid,                                              
           Ucm.AccountUsed AS AccountUsed,                                         
           umt.IsUnicode  IsUnicode          
           FROM   Usercampaignmaster Ucm  (nolock)                      
           join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                      
           INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)                         
           ON ucm.ID=Ucerm.CampaignID                                                    
           WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo = '' and ucm.TemplateID<>0                                        and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0   
    and umt.IsConversion=0 and jobid=@jobid            
   union        
   SELECT Ucm.ID as CampaignID,                                              
           Ucm.ParentID as ParentID,                                              
           umt.mailcontent as mailcontent,                                              
           Ucerm.mobile as Mobile,                                              
           Ucm.SenderID Senderid,                                              
           Ucm.AccountUsed AS AccountUsed,                                         
           umt.IsUnicode  IsUnicode          
           FROM  #tempgroups tg join Usercampaignmaster Ucm  (nolock)                      
           on tg.CampaignID =ucm.id      
           join UserMailTemplate umt (nolock) on umt.ID=tg.TemplateID   
           INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)   
           ON ucm.ID=Ucerm.CampaignID                                                    
           WHERE Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo = '' and tg.TemplateID<>0      
           and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0    
      and jobid=@jobid             
  
 select * from #TempTable                            
end        
                                     
if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm (nolock)          
           INNER JOIN Usermailtemplate Umt (nolock) ON  Ucm.TemplateID = Umt.ID          
           INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock) ON          
           Ucerm.CampaignID = Ucm.ID WHERE  Umt.IsEnquiry = 1        
           union        
           select top 1 'x' from #tempgroups tg INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)         
           ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt on tg.templateid=umt.ID         
     where Umt.IsEnquiry = 1 )        
                   
begin  
  
                                            
insert into #TempTable                                            
(CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )   
 SELECT Ucm.ID CampaignID,                                              
   Ucm.ParentID,                                              
           dbo.[fn_getEnquiryMessageMail_NewAbdulTestSMS]( Ucm.ParentID,          
               Umt.MailContent,          
               Ucerm.Mobile  ,                        
               ue.personname,                        
              ue.companyname,                        
               ue.mobileno,                        
               ue.MobileNo1,                        
               ue.MobileNo2,                        
               ue.EmailID,                        
               ue.EmailID1,                        
               ue.EmailID2,                        
               uss.NAME,                        
               ums.Name,                        
               Ucs.Name,                        
               ue.initialremarks,                        
               ue.CreatedDate,                        
               ud.fname,                        
               ud.LName,        
               ue.City,        
               ue.State,        
               case when isnull(ue.CompanyName,'')<>'' then ue.OfficeAddress else ue.ResidentialAddress end,   
               ue.PinCode,          
               ue.country                                           
           ),                                                       
           Ucerm.Mobile,                                              
           Ucm.Senderid,                                              
           Ucm.AccountUsed AS AccountUsed,                                              
           Umt.Isunicode                                      
            FROM   Usercampaignmaster Ucm  (nolock) INNER JOIN Usermailtemplate Umt (nolock)   
            ON  Ucm.TemplateID = Umt.ID INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)  
            ON  Ucerm.CampaignID = Ucm.ID                               
    Left Join  userenquiry ue ON  ue.parentid = Ucm.ParentID AND (                        
                Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 ) )                        
       LEFT JOIN usermediumsettings ums                        
      ON  ums.mediumid = ue.mediumname                        
       LEFT JOIN usercampaignsettings ucs                        
      ON  ue.campaignname = ucs.campaignid                        
       LEFT JOIN usersourcesettings uss                        
      ON  ue.sourcename = uss.sourceid                        
       LEFT JOIN user_detail ud                        
      ON  ud.[user_id] = ue.createdby                           
            WHERE  Ucerm.IsCompleted = 0                        
                   AND Umt.IsEnquiry = 1  and jobid=@jobid                          
      union        
      SELECT Ucm.ID CampaignID,                                              
                   Ucm.ParentID,                                              
                   dbo.[fn_getEnquiryMessageMail_NewAbdulTESTSMS](                                              
                       Ucm.ParentID,          
                       Umt.MailContent,          
                       Ucerm.Mobile  ,                        
                       ue.personname,                        
                       ue.companyname,                        
                       ue.mobileno,                        
                       ue.MobileNo1,                        
                       ue.MobileNo2,                        
                       ue.EmailID,                        
                       ue.EmailID1,                        
                       ue.EmailID2,                        
                       uss.NAME,                        
                       ums.Name,                        
                       Ucs.Name,                        
               ue.initialremarks,                        
                       ue.CreatedDate,                        
                       ud.fname,                        
                       ud.LName,        
               ue.City,        
               ue.State,        
               case when isnull(ue.CompanyName,'')<>'' then ue.OfficeAddress else ue.ResidentialAddress end,   
               ue.PinCode,          
               ue.country                                              
                   ),                                                       
                   Ucerm.Mobile,            
                   Ucm.Senderid,                                              
                   Ucm.AccountUsed AS AccountUsed,                                              
                   Umt.Isunicode                                      
            FROM  #tempgroups tg join Usercampaignmaster Ucm  (nolock)                                 
            on tg.CampaignID=ucm.ID         
            INNER JOIN Usermailtemplate Umt  (nolock)                        
            ON  tg.TemplateID = Umt.ID                                  
            INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)             
            ON  Ucerm.CampaignID = Ucm.ID                               
            Left Join  userenquiry ue ON  ue.parentid = Ucm.ParentID AND (                        
            Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 ) )                        
            LEFT JOIN usermediumsettings ums                        
      ON  ums.mediumid = ue.mediumname                        
       LEFT JOIN usercampaignsettings ucs                        
      ON  ue.campaignname = ucs.campaignid                        
       LEFT JOIN usersourcesettings uss                        
      ON  ue.sourcename = uss.sourceid                        
       LEFT JOIN user_detail ud                        
      ON  ud.[user_id] = ue.createdby                           
            WHERE  Ucerm.IsCompleted = 0                        
                   AND Umt.IsEnquiry = 1   and jobid=@jobid                         
            
        
            end                                              
          
if exists (select top 1  'x'   FROM   Usercampaignmaster Ucm  (nolock)   
 INNER JOIN Usermailtemplate Umt  (nolock) ON  Ucm.TemplateID = Umt.ID   
 INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)    
 ON  Ucerm.CampaignID = Ucm.ID                                              
 WHERE  (Umt.IsLeads = 1 OR Umt.IsConversion = 1)        
 union        
 select top 1 'x' from #tempgroups tg   
 INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)         
    ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt on tg.templateid=umt.ID         
    where (Umt.IsLeads = 1 OR Umt.IsConversion = 1)        
 )                  
 begin   
                                          
   insert into #TempTable                                       
   (CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,Isunicode )                                       
 SELECT Ucm.ID,Ucm.ParentID,   
 dbo.[fn_getLeadsMailMessage_NewAbdul](Ucm.ParentID,Umt.MailContent,Ucerm.Mobile,ue.personname ,   
 ue.companyname  ,ue.mobileno ,ue.mobileno1 ,ue.mobileno2 ,ue.emailid       ,ue.emailid1 ,  
 ue.emailid2 ,                        
 ue.LeadNo ,                         
 ue.NextStatusDate ,                        
 ud2.fName ,                        
 ud2.LName ,                        
 ue.Remarks ,                        
 ue.CreatedOn,                        
 ud.FName ,                        
 ud.LName ,              
 uss.NAME,                        
 ums.Name,                        
 Ucs.Name                                              
                   ),                                              
                   Ucerm.Mobile,                                              
                   Ucm.Senderid,                                              
                   Ucm.AccountUsed AS AccountUsed,                                              
                   Umt.Isunicode                                      
            FROM    Usercampaignmaster Ucm  (nolock)                                            
                   INNER JOIN Usermailtemplate Umt  (nolock)                        
                        ON  Ucm.TemplateID = Umt.ID                                              
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)                                           ON  Ucerm.CampaignID = Ucm.ID                        
                     LEFT JOIN  userleads ue ON ue.parentid = Ucm.ParentID AND (                        
                 Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 )    )               
                 LEFT JOIN usermediumsettings ums                        
      ON  ums.mediumid = ue.mediumname                        
       LEFT JOIN usercampaignsettings ucs                        
      ON  ue.campaignname = ucs.campaignid                        
       LEFT JOIN usersourcesettings uss                        
      ON  ue.sourcename = uss.sourceid                               
        LEFT JOIN user_detail ud                        
             ON  ud.[user_id] = ue.createdby             
        LEFT JOIN user_detail ud2                        
             ON  ud2.[user_id] = ue.assignedto                        
            WHERE  Ucerm.IsCompleted = 0                                           
                   AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1) and jobid=@jobid                           
union        
SELECT Ucm.ID,Ucm.ParentID, dbo.[fn_getLeadsMailMessage_NewAbdul](Ucm.ParentID,Umt.MailContent,Ucerm.Mobile,ue.personname  ,                        
 ue.companyname  ,                        
 ue.mobileno ,ue.mobileno1 ,ue.mobileno2 ,ue.emailid       ,ue.emailid1 ,                        
 ue.emailid2 ,                        
 ue.LeadNo ,                         
 ue.NextStatusDate ,                        
 ud2.fName ,                        
 ud2.LName ,                        
 ue.Remarks ,                        
 ue.CreatedOn,                        
 ud.FName ,                        
 ud.LName ,              
 uss.NAME,                        
 ums.Name,                        
 Ucs.Name                                              
                   ),                                              
                   Ucerm.Mobile,                                              
                   Ucm.Senderid,                                              
                   Ucm.AccountUsed AS AccountUsed,                                              
                   Umt.Isunicode                                      
            FROM   #tempgroups tg join Usercampaignmaster Ucm  (nolock)                                            
                   on tg.CampaignID=ucm.id        
                   INNER JOIN Usermailtemplate Umt  (nolock)                                            
                        ON  tg.TemplateID = Umt.ID                                              
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)                                     
                        ON  Ucerm.CampaignID = Ucm.ID                        
                     LEFT JOIN  userleads ue ON ue.parentid = Ucm.ParentID AND (                        
                 Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 )    )               
                 LEFT JOIN usermediumsettings ums                        
      ON  ums.mediumid = ue.mediumname                        
       LEFT JOIN usercampaignsettings ucs                      
      ON  ue.campaignname = ucs.campaignid                        
       LEFT JOIN usersourcesettings uss                        
      ON  ue.sourcename = uss.sourceid                               
        LEFT JOIN user_detail ud                        
             ON  ud.[user_id] = ue.createdby             
        LEFT JOIN user_detail ud2                        
             ON  ud2.[user_id] = ue.assignedto                        
            WHERE  Ucerm.IsCompleted = 0                                           
                   AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1)   and jobid=@jobid                         
            end                                         
        
if exists (select top 1 'x'  FROM  Usercampaignmaster Ucm  (nolock)                                            
                  INNER JOIN Usermailtemplate Umt (nolock)                        ON  Ucm.TemplateID = Umt.ID                       INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)    ON  Ucerm.CampaignID = Ucm.ID         
         WHERE   Umt.IsList = 1          
         union        
         select top 1 'x'     FROM  #tempgroups tg  (nolock)        
         INNER JOIN Usermailtemplate Umt (nolock) ON  tg.TemplateID = Umt.ID                                  
         INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)    ON  Ucerm.CampaignID = tg.CampaignID         
         WHERE   Umt.IsList = 1        
            )        
                    
begin  
  
                       
insert into #TempTable                                            
(CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )                                            
            SELECT Ucm.ID,          
                   Ucm.ParentID,                                              
          REPLACE(                      
            REPLACE(                      
                REPLACE(                      
                    REPLACE(                      
                        REPLACE(                      
                            REPLACE(                      
REPLACE(                      
                                    REPLACE(                      
                                        REPLACE(                      
                                            REPLACE(                      
                                                Umt.MailContent,                      
                                                '#' + ISNULL(uilc.column1,'') +                      
                                                '#',                      
                                                ISNULL(usd.mobilenumber, '')                      
                                            ),                      
                                            '#' + ISNULL(uilc.column2,'') + '#',                      
                                            ISNULL(usd.emailid, '')                      
                                        ),                      
                                        '#' + ISNULL(uilc.column3,'') + '#',                      
                                        ISNULL(usd.column1, '')                      
                                    ),                      
                                    '#' + ISNULL(uilc.column4,'') +                      
                                    '#',                      
                                    ISNULL(usd.column2, '')                      
                                ),                      
                                '#' + ISNULL(uilc.column5,'') + '#',                      
                                ISNULL(usd.column3, '')                      
                            ),                      
                            '#' + ISNULL(uilc.column6 ,'')+ '#',                      
                            ISNULL(usd.column4, '')                      
                        ),                      
                        '#' + ISNULL(uilc.column7,'') + '#',                      
    ISNULL(usd.column5, '')                      
                    ),                      
                    '#' + ISNULL(uilc.column8,'') + '#',                      
                    ISNULL(usd.column6, '')                      
                ),                      
                '#' + ISNULL(uilc.column9,'') + '#',                      
                ISNULL(usd.column7, '')                      
            ),                      
            '#' + ISNULL(uilc.column10,'') + '#',                      
            ISNULL(usd.column8, '')                      
        )                      
 ,Ucerm.Mobile,                                              
                   Ucm.Senderid,                                              
                   Ucm.AccountUsed AS AccountUsed,                                                                 Umt.IsUnicode                                             
FROM   Usercampaignmaster Ucm  (nolock)                        
INNER JOIN Usermailtemplate Umt (nolock) ON  Ucm.TemplateID = Umt.ID                                              
INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock) ON  Ucerm.CampaignID = Ucm.ID and Ucerm.ParentID = Ucm.ParentID                    
INNER JOIN userimportedlistcolumn uilc ON uilc.id = Umt.ListID                        
INNER JOIN usersearchdata usd    ON  uilc.id = usd.importedlistid                        
       AND usd.MobileNumber = Ucerm.Mobile            
       WHERE  Ucerm.IsCompleted = 0                        
                   AND Umt.IsList = 1  and jobid=@jobid                       
union        
SELECT Ucm.ID,          
                   Ucm.ParentID,                                              
          REPLACE(                      
       REPLACE(                      
                REPLACE(                      
                    REPLACE(                      
                        REPLACE(                      
                            REPLACE(                      
REPLACE(                      
                                    REPLACE(                      
                                        REPLACE(                      
                                            REPLACE(                      
                                                Umt.MailContent,                      
                                                '#' + ISNULL(uilc.column1,'') +                      
                                                '#',                      
                                                ISNULL(usd.mobilenumber, '')                      
                                            ),                      
                                            '#' + ISNULL(uilc.column2,'') + '#',                      
                                            ISNULL(usd.emailid, '')                      
                                        ),                      
                                        '#' + ISNULL(uilc.column3,'') + '#',                      
                                        ISNULL(usd.column1, '')                      
                                    ),                      
                                    '#' + ISNULL(uilc.column4,'') +                      
                                    '#',                      
                                    ISNULL(usd.column2, '')                      
                                ),                      
                                '#' + ISNULL(uilc.column5,'') + '#',                      
                                ISNULL(usd.column3, '')                      
                            ),                      
                            '#' + ISNULL(uilc.column6 ,'')+ '#',                      
                            ISNULL(usd.column4, '')                      
                        ),                      
                        '#' + ISNULL(uilc.column7,'') + '#',                      
                        ISNULL(usd.column5, '')                      
                    ),                      
                    '#' + ISNULL(uilc.column8,'') + '#',                      
                    ISNULL(usd.column6, '')                      
                ),                      
                '#' + ISNULL(uilc.column9,'') + '#',                      
                ISNULL(usd.column7, '')                      
            ),                      
            '#' + ISNULL(uilc.column10,'') + '#',                      
            ISNULL(usd.column8, '')                      
        )                      
 ,Ucerm.Mobile,                                              
                   Ucm.Senderid,                                              
                   Ucm.AccountUsed AS AccountUsed,                                              
                 Umt.IsUnicode                                             
FROM   #tempgroups tg join Usercampaignmaster Ucm  (nolock)                        
on tg.CampaignID=ucm.ID        
INNER JOIN Usermailtemplate Umt (nolock) ON  tg.TemplateID = Umt.ID                                              
INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock) ON  Ucerm.CampaignID = Ucm.ID and Ucerm.ParentID = Ucm.ParentID                    
INNER JOIN userimportedlistcolumn uilc ON uilc.id = Umt.ListID                        
INNER JOIN usersearchdata usd    ON  uilc.id = usd.importedlistid                        
       AND usd.MobileNumber = Ucerm.Mobile            
       WHERE  Ucerm.IsCompleted = 0                        
                   AND Umt.IsList = 1  and jobid=@jobid                       
 end                                              
                
                     
                           
 UPDATE Kd                          
 SET              
 Kd.[Message] = CAST(CAST(A.[Message] AS NVARCHAR(MAX)) COLLATE Latin1_general_ci_ai AS NVARCHAR(MAX)),        
 Kd.SenderID = CAST(CAST(A.SenderID AS NVARCHAR(MAX))         
 COLLATE  Latin1_general_ci_ai AS NVARCHAR(MAX)),        
 Kd.U_ID = A.AccountUsed,                          
 Kd.IsCompleted = 1,                          
 Kd.IsUniCode = A.IsUnicode,        
 kd.len=len(A.message),        
 kd.credits=case when A.isunicode=0 and len(A.message)<=160  then 1 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN(A.message)/cast(153 as float)) when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message)/cast(67 as float)) 
  
    
      
end         
 FROM   usercampaignexecutionrecipientsmessageTest2 Kd  (nolock)                         
        INNER JOIN #temptable A                          
             ON  Kd.CampaignID = A.CampaignID                          
             AND Kd.ParentID = A.ParentID                          
             AND Kd.Mobile = CAST(                          
                     CAST(A.Mobile AS VARCHAR(MAX))                          
                     COLLATE                          
                     Latin1_general_ci_ai AS                          
                     VARCHAR(MAX)                          
                 )          
             and kd.jobid=@jobid                        
                           
 --UPDATE Kd                          
 --SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()                        
 --FROM   Usercampaignhistory Kd                          
 --       INNER JOIN #temptable A                          
 --            ON  Kd.CampaignID = A.CampaignID                          
 --            AND Kd.ParentID = A.ParentID                        
  UPDATE Kd                                                  
      SET    Ismessages = 1,                                                  
             templatesequence=tg.orderno,        
             templateid =tg.templateid                                           
             FROM   Usercampaignexecutionhistory Kd                
             inner join #temptable A                    
             ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid          
             left join #tempgroups tg        
             on tg.CampaignID=kd.CampaignID                          
                       
 UPDATE Kd                         
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE(), Step2Recipients=isnull(A.Step2Recipients,0)                                         
   FROM   Usercampaignhistory Kd  (nolock)                                          
    Inner JOIN                                         
    (select campaignid,count(campaignid) as Step2Recipients,parentid                         
    from #temptable group by Parentid,campaignid) A                                            
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid            
      
--UPDATE Kd  SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()     FROM   Usercampaignhistory Kd                      
--        INNER JOIN  ##campaignrun c on Kd.ID=c.campaignrunid                           
                                   
  UPDATE Kd                                            
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE() FROM   Usercampaignhistory Kd where JobId=@jobid                                     
                           
 DROP TABLE #temptable        
 exec [Usp_insertclonedeliverycampaignCorrected]  @jobid                          
END                       
                      
