/* ============================================================
   Procedure: [dbo].[Usp_userexecutecampaignmessagesCorrected_withid21102020]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                                  
CREATE   PROCEDURE [dbo].[Usp_userexecutecampaignmessagesCorrected_withid21102020]                    
@Jobid  bigint                              
AS                                  
BEGIN                                  
                   
 create table #TempTable                                                    
   (                                                    
   EntityName nvarchar(50),Entityid bigint,CampaignID bigint,ParentID bigint,[Message] nvarchar(2000),Mobile varchar(50),SenderID varchar(10),AccountUsed bigint,                                                    
   IsUnicode bit                                                   
   )                                                    
                                
Select Distinct EC.CampaignID,EC.ParentID into #usercampaignexecutionrecipientsmessageTest2  from usercampaignexecutionrecipientsmessageTest2 EC With(nolock) where jobid=@jobid                 
                
CREATE TABLE #tempgroups                                  
 (                  
  CampaignID         BIGINT,                                  
  templategroupid    BIGINT,                                  
  templateid         bigint,                                  
  orderno            int,                                  
  isending           BIT                                  
 )                  
                
if exists(select '1' from UserCampaignMaster ucm           
 join #usercampaignexecutionrecipientsmessageTest2 uc on uc.CampaignID=ucm.ID           
 where TemplateGroupID<>0)                 
begin                  
 INSERT INTO #tempgroups                                  
   (                                  
     campaignid,                
     templategroupid,                
     templateid,                
     orderno,                
     isending                
   )                                  
 exec [GetnextTemplate] @jobid                
           
 --select * from #tempgroups                  
end                 
                  
if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm  (nolock)            
 Inner Join #usercampaignexecutionrecipientsmessageTest2 EC on EC.CampaignId = Ucm.ID             
 --OUTER APPLY EmailsfiltercampaignexecutionTest2 AS Ucerm   (nolock)                                  WHERE  isnull(Ucm.MailReplyTo,'') = ''                                                      
               AND ucm.TemplateID=0  )          
begin           
                                                
   insert into #TempTable                                                    
   (EntityName,Entityid,CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )           
   SELECT distinct EntityName,Entityid,Ucm.ID,                                                      
                   Ucm.ParentID,             
     case when isnull(Ucerm.Message,'')='' then Ucm.Message else Ucerm.Message end message,              
                  -- Ucm.Message,                                                      
                   Ucerm.Mobile,                                                      
                   Ucm.SenderID,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                      
                   Ucm.IsUnicode                                                    
            FROM   Usercampaignmaster Ucm  (nolock)                                                   
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)              
                   ON ucm.ID=Ucerm.CampaignID                                                                        
            WHERE  Ucerm.IsCompleted = 0                                                      
                   AND Ucm.MailReplyTo = ''                                                      
                   AND ucm.TemplateID=0 and jobid=@jobid            
           and ucm.ID not in (select distinct CampaignID from #tempgroups)        
end                                                      
          
                
if exists (select top 1 'x'   FROM  Usercampaignmaster Ucm  (nolock)          
join UserMailTemplate umt on umt.ID=ucm.TemplateID            
Inner Join #usercampaignexecutionrecipientsmessageTest2 EC on EC.CampaignId = Ucm.ID                
   WHERE  Ucm.MailReplyTo = '' and TemplateID<>0 and umt.IsEnquiry=0 and           
   umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0                
   union                
   select top 1 'x' from #tempgroups tg INNER JOIN #usercampaignexecutionrecipientsmessageTest2           
   Ucerm  (nolock) ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt           
 on tg.templateid=umt.ID where umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0      )                
   begin          
            
   insert into #TempTable            
      (EntityName,Entityid,CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )          
      SELECT EntityName,Entityid,Ucm.ID as CampaignID,                                                      
           Ucm.ParentID as ParentID,                                                      
           umt.mailcontent as mailcontent,                                                      
           Ucerm.mobile as Mobile,                                                      
           Ucm.SenderID Senderid,                                                      
           Ucm.AccountUsed AS AccountUsed,                                                 
           umt.IsUnicode  IsUnicode                  
           FROM   Usercampaignmaster Ucm  (nolock)                              
           join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                              
           INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)                                 
           ON ucm.ID=Ucerm.CampaignID                                                            
           WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo = '' and ucm.TemplateID<>0                                        and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0           
    and umt.IsConversion=0 and jobid=@jobid                    
   union                
   SELECT EntityName,Entityid,Ucm.ID as CampaignID,                                                      
           Ucm.ParentID as ParentID,                                                      
           umt.mailcontent as mailcontent,                                                      
           Ucerm.mobile as Mobile,                                                      
           Ucm.SenderID Senderid,                                                      
           Ucm.AccountUsed AS AccountUsed,                                                 
           umt.IsUnicode  IsUnicode                  
           FROM  #tempgroups tg join Usercampaignmaster Ucm  (nolock)                              
           on tg.CampaignID =ucm.id              
           join UserMailTemplate umt (nolock) on umt.ID=tg.TemplateID           
           INNER JOIN usercampaignexecutionrecipientsmessageTest2 AS Ucerm  (nolock)           
           ON ucm.ID=Ucerm.CampaignID                                                            
           WHERE Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo = '' and tg.TemplateID<>0              
           and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0            
      and jobid=@jobid                     
          
 --select * from #TempTable                                    
end                
                                             
if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm (nolock)                  
           INNER JOIN Usermailtemplate Umt (nolock) ON  Ucm.TemplateID = Umt.ID                  
           INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock) ON                  
           Ucerm.CampaignID = Ucm.ID WHERE  Umt.IsEnquiry = 1                
           union                
       select top 1 'x' from #tempgroups tg INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)                 
           ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt on tg.templateid=umt.ID        
     where Umt.IsEnquiry = 1 )                
                           
begin          
          
                                                    
insert into #TempTable                                                    
(EntityName,Entityid,CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )           
 SELECT EntityName,Entityid,Ucm.ID CampaignID,                                                      
   Ucm.ParentID,   case when ucerm.entityname='Enquiry' then                             
           dbo.[fn_getEnquiryMessageMail_withid]( Ucm.ParentID,                  
               Umt.MailContent, entityid                                                   
           )      
     else umt.MailContent end,                                                               
           Ucerm.Mobile,                                                      
           Ucm.Senderid,                                                      
           Ucm.AccountUsed AS AccountUsed,                                                      
           Umt.Isunicode                                              
            FROM   Usercampaignmaster Ucm  (nolock) INNER JOIN Usermailtemplate Umt (nolock)           
            ON  Ucm.TemplateID = Umt.ID INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)          
            ON  Ucerm.CampaignID = Ucm.ID --and (ucerm.entityname='Enquiry' or ucerm.entityname='Explicit')                                      
    Left Join  userenquiry ue ON  ue.EnquiryID=Ucerm.entityid and ucerm.entityname='Enquiry'      
         WHERE  Ucerm.IsCompleted = 0   --and (ucerm.entityname='Enquiry' or ucerm.entityname='Explicit')      
                   AND Umt.IsEnquiry = 1  and jobid=@jobid                                  
      union                
      SELECT EntityName,Entityid,Ucm.ID CampaignID,                                                      
                   Ucm.ParentID,                                                      
       case when ucerm.entityname='enquiry' then      
                   dbo.[fn_getEnquiryMessageMail_withid]( Ucm.ParentID,                  
               Umt.MailContent, entityid                                                   
           ) else umt.MailContent end ,                                                               
                   Ucerm.Mobile,                    
                   Ucm.Senderid,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                      
                   Umt.Isunicode                                              
            FROM  #tempgroups tg join Usercampaignmaster Ucm  (nolock)                                         
            on tg.CampaignID=ucm.ID                 
            INNER JOIN Usermailtemplate Umt  (nolock)                                
            ON  tg.TemplateID = Umt.ID                                          
            INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)                     
            ON  Ucerm.CampaignID = Ucm.ID   --and (ucerm.entityname='Enquiry' or ucerm.entityname='Explicit')                                    
            Left Join  userenquiry ue ON  ue.EnquiryID=ucerm.entityid and ucerm.entityname='Enquiry'      
   --ue.parentid = Ucm.ParentID AND ( Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 ) )                                
             WHERE  Ucerm.IsCompleted = 0    -- and (ucerm.entityname='Enquiry' or ucerm.entityname='Explicit')                           
                   AND Umt.IsEnquiry = 1   and jobid=@jobid                                 
                    
                
            end                                                      
                  
if exists (select top 1  'x'   FROM   Usercampaignmaster Ucm  (nolock)           
 INNER JOIN Usermailtemplate Umt  (nolock) ON  Ucm.TemplateID = Umt.ID           
 INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)            
 ON  Ucerm.CampaignID = Ucm.ID                                                      
 WHERE  (Umt.IsLeads = 1 OR Umt.IsConversion = 1)             
 union                
 select top 1 'x' from #tempgroups tg           
 INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)                 
    ON Ucerm.CampaignID = tg.CampaignID join UserMailTemplate umt on tg.templateid=umt.ID                 
    where (Umt.IsLeads = 1 OR Umt.IsConversion = 1)                
 )                          
 begin           
                                                  
   insert into #TempTable                                               
   (EntityName,Entityid,CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,Isunicode )                                               
 SELECT EntityName,Entityid,Ucm.ID,Ucm.ParentID, case when ucerm.entityname='Lead' then          
 dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,Ucerm.entityid) else umt.MailContent end,                                                      
                   Ucerm.Mobile,                  
                   Ucm.Senderid,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                      
                   Umt.Isunicode                                              
            FROM    Usercampaignmaster Ucm  (nolock)                                                    
                   INNER JOIN Usermailtemplate Umt  (nolock)                                
                        ON  Ucm.TemplateID = Umt.ID                                                      
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)    ON  Ucerm.CampaignID = Ucm.ID   -- and (ucerm.entityname='Lead' or ucerm.entityname='Explicit')      
                     LEFT JOIN  userleads ue ON ue.id=ucerm.entityid  and ucerm.entityname='lead'      
      --ue.parentid = Ucm.ParentID AND (Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 )    )                       
                 WHERE  Ucerm.IsCompleted = 0  --and (ucerm.entityname='Lead' or ucerm.entityname='Explicit')      
                   AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1) and jobid=@jobid                                   
union                
SELECT EntityName,Entityid,Ucm.ID,Ucm.ParentID, case when ucerm.entityname='lead' then      
dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,Ucerm.entityid) else umt.mailcontent end,                                                      
                   Ucerm.Mobile,                                                      
                   Ucm.Senderid,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                      
                   Umt.Isunicode                                              
            FROM   #tempgroups tg join Usercampaignmaster Ucm  (nolock)                                                    
                   on tg.CampaignID=ucm.id                
                   INNER JOIN Usermailtemplate Umt  (nolock)                                                    
                        ON  tg.TemplateID = Umt.ID                                                      
                   INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)                                             
                        ON  Ucerm.CampaignID = Ucm.ID  -- and (ucerm.entityname='Lead' or ucerm.entityname='Explicit')      
                     LEFT JOIN  userleads ue ON ue.id=ucerm.entityid  and ucerm.entityname='lead'      
      --ue.parentid = Ucm.ParentID AND (Ucerm.Mobile IN(ue.MobileNo,ue.MobileNo1,ue.MobileNo2 )    )                       
                 WHERE  Ucerm.IsCompleted = 0  --and (ucerm.entityname='Lead' or ucerm.entityname='Explicit')                                                 
                   AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1)   and jobid=@jobid                                 
            end                                                 
                
if exists (select top 1 'x'  FROM  Usercampaignmaster Ucm  (nolock)                                                    
                  INNER JOIN Usermailtemplate Umt (nolock)                        ON  Ucm.TemplateID = Umt.ID                       INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)    ON  Ucerm.CampaignID = Ucm.ID                 
         WHERE   Umt.IsList = 1                  
         union                
         select top 1 'x'     FROM  #tempgroups tg  (nolock)                
         INNER JOIN Usermailtemplate Umt (nolock) ON  tg.TemplateID = Umt.ID                                          
         INNER JOIN #usercampaignexecutionrecipientsmessageTest2 Ucerm  (nolock)    ON  Ucerm.CampaignID = tg.CampaignID                 
         WHERE   Umt.IsList = 1                
            )                
                            
begin          
          
                               
insert into #TempTable                                                    
(EntityName,Entityid,CampaignID,ParentID,Message,Mobile,SenderID,AccountUsed,IsUnicode )                                                    
            SELECT EntityName,Entityid,Ucm.ID,                  
                   Ucm.ParentID, case when ucerm.entityname='ImportedList' then                                                      
          REPLACE(                              
            REPLACE(                              
                REPLACE(                              
                    REPLACE(                              
                        REPLACE(                              
                            REPLACE(                              
REPLACE(                              
                                    REPLACE(                              
                                        REPLACE(                              
                                            REPLACE(                              
                                                Umt.MailContent,                              
                                                '#' + ISNULL(uilc.column1,'') +                              
                                                '#',                              
                                                ISNULL(usd.mobilenumber, '')                              
                                            ),                              
                                            '#' + ISNULL(uilc.column2,'') + '#',                              
                                            ISNULL(usd.emailid, '')                              
                                        ),                              
                                        '#' + ISNULL(uilc.column3,'') + '#',                              
                                        ISNULL(usd.column1, '')                              
                                    ),                              
                                    '#' + ISNULL(uilc.column4,'') +                              
                                    '#',                              
                                    ISNULL(usd.column2, '')                              
                                ),                              
                                '#' + ISNULL(uilc.column5,'') + '#',                              
                                ISNULL(usd.column3, '')                              
                            ),                              
                            '#' + ISNULL(uilc.column6 ,'')+ '#',                              
                            ISNULL(usd.column4, '')                 
                        ),                              
                        '#' + ISNULL(uilc.column7,'') + '#',                              
    ISNULL(usd.column5, '')                              
                    ),                              
                    '#' + ISNULL(uilc.column8,'') + '#',                              
                    ISNULL(usd.column6, '')                              
                ),                              
                '#' + ISNULL(uilc.column9,'') + '#',                              
                ISNULL(usd.column7, '')                              
            ),                              
       '#' + ISNULL(uilc.column10,'') + '#',                              
            ISNULL(usd.column8, '')                              
        ) else umt.mailcontent end                             
 ,Ucerm.Mobile,                                                      
                   Ucm.Senderid,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                                 
				   Umt.IsUnicode                                                     
FROM   Usercampaignmaster Ucm  (nolock)                                
INNER JOIN Usermailtemplate Umt (nolock) ON  Ucm.TemplateID = Umt.ID                                                      
INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock) ON  Ucerm.CampaignID = Ucm.ID and Ucerm.ParentID = Ucm.ParentID --and  (ucerm.entityname='ImportedList'   or ucerm.entityname='Explicit')                                             
left JOIN userimportedlistcolumn uilc ON uilc.id = Umt.ListID                                
left JOIN usersearchdata usd    ON  uilc.id = usd.importedlistid and usd.id=ucerm.entityid and ucerm.entityname='importedlist'                               
       --AND usd.MobileNumber = Ucerm.Mobile                    
       WHERE  Ucerm.IsCompleted = 0    --and  (ucerm.entityname='ImportedList'   or ucerm.entityname='Explicit')                        
                   AND Umt.IsList = 1  and jobid=@jobid                               
union                
SELECT EntityName,Entityid,Ucm.ID,                  
                   Ucm.ParentID, case when ucerm.entityname='ImportedList' then       
          REPLACE(                              
       REPLACE(                              
                REPLACE(                              
                    REPLACE(                              
                        REPLACE(                              
                            REPLACE(                              
REPLACE(                              
                                    REPLACE(                              
                                        REPLACE(                              
                                            REPLACE(                              
                                                Umt.MailContent,                              
                                                '#' + ISNULL(uilc.column1,'') +                              
                                                '#',                              
                                                ISNULL(usd.mobilenumber, '')                              
                                            ),                              
                                            '#' + ISNULL(uilc.column2,'') + '#',                              
                                            ISNULL(usd.emailid, '')                              
                   ),                              
                                        '#' + ISNULL(uilc.column3,'') + '#',                              
                                        ISNULL(usd.column1, '')                              
                                    ),                              
                                    '#' + ISNULL(uilc.column4,'') +                              
                                    '#',                              
                                    ISNULL(usd.column2, '')                              
                               ),                              
                                '#' + ISNULL(uilc.column5,'') + '#',                              
                                ISNULL(usd.column3, '')                              
                            ),                              
                            '#' + ISNULL(uilc.column6 ,'')+ '#',                              
                            ISNULL(usd.column4, '')                              
                        ),                              
                        '#' + ISNULL(uilc.column7,'') + '#',                              
                        ISNULL(usd.column5, '')                              
                    ),                              
                    '#' + ISNULL(uilc.column8,'') + '#',                              
                    ISNULL(usd.column6, '')                              
                ),                              
                '#' + ISNULL(uilc.column9,'') + '#',                              
                ISNULL(usd.column7, '')                              
            ),                              
            '#' + ISNULL(uilc.column10,'') + '#',                              
            ISNULL(usd.column8, '')                              
        ) else umt.MailContent  end                            
 ,Ucerm.Mobile,                                                      
                   Ucm.Senderid,                                                      
                   Ucm.AccountUsed AS AccountUsed,                                                      
                 Umt.IsUnicode                                                     
FROM   #tempgroups tg join Usercampaignmaster Ucm  (nolock)                                
on tg.CampaignID=ucm.ID                
INNER JOIN Usermailtemplate Umt (nolock) ON  tg.TemplateID = Umt.ID                                                      
INNER JOIN usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock) ON  Ucerm.CampaignID = Ucm.ID and Ucerm.ParentID = Ucm.ParentID --  and  (ucerm.entityname='ImportedList'   or ucerm.entityname='Explicit')                                           
  
    
                     
left JOIN userimportedlistcolumn uilc ON uilc.id = Umt.ListID                                
left JOIN usersearchdata usd    ON  uilc.id = usd.importedlistid  and  (ucerm.entityname='ImportedList'   and ucerm.entityid=usd.ID)                                             
       --AND usd.MobileNumber = Ucerm.Mobile                    
       WHERE  Ucerm.IsCompleted = 0 --  and  (ucerm.entityname='ImportedList'   or ucerm.entityname='Explicit')                                             
                   AND Umt.IsList = 1  and jobid=@jobid                               
 end                                                      
                        
                             
                                   
 UPDATE Kd                                  
 SET                      
 Kd.[Message] = CAST(CAST(A.[Message] AS NVARCHAR(MAX)) COLLATE Latin1_general_ci_ai AS NVARCHAR(MAX)),                
 Kd.SenderID = CAST(CAST(A.SenderID AS NVARCHAR(MAX))                 
 COLLATE  Latin1_general_ci_ai AS NVARCHAR(MAX)),                
 Kd.U_ID = A.AccountUsed,                                  
 Kd.IsCompleted = 1,                                  
 Kd.IsUniCode = A.IsUnicode,                
 kd.len=len(A.message),                
 kd.credits=case   
 when A.isunicode=0 and len(A.message)<=160  then 1   
 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN(A.message)/cast(153 as float))   
 when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message)/cast(67 as float))    
 end                 
 FROM   usercampaignexecutionrecipientsmessageTest2 Kd    
        INNER JOIN #temptable A                                  
             ON  Kd.CampaignID = A.CampaignID                                  
             AND Kd.ParentID = A.ParentID                                  
             AND kd.entityid=A.Entityid and kd.entityname=A.EntityName  COLLATE  Latin1_general_ci_ai    
    --Kd.Mobile = CAST(CAST(A.Mobile AS VARCHAR(MAX)) COLLATE  Latin1_general_ci_ai AS VARCHAR(MAX))                  
             and kd.jobid=@jobid                                
                                   
 --UPDATE Kd                                  
 --SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()                                
 --FROM   Usercampaignhistory Kd                                  
 --       INNER JOIN #temptable A                                  
 --            ON  Kd.CampaignID = A.CampaignID                                  
 --            AND Kd.ParentID = A.ParentID                                
  UPDATE Kd                               
      SET    Ismessages = 1,                                                          
             templatesequence=tg.orderno,                
             templateid =tg.templateid                                                   
             FROM   Usercampaignexecutionhistory Kd                        
             inner join #temptable A                            
             ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid                  
             left join #tempgroups tg                
             on tg.CampaignID=kd.CampaignID                                  
                               
 UPDATE Kd                                 
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE(), Step2Recipients=isnull(A.Step2Recipients,0)                                                 
   FROM   Usercampaignhistory Kd  (nolock)                                                  
    left JOIN                                                 
    (select campaignid,count(campaignid) as Step2Recipients,parentid                                 
    from #temptable group by Parentid,campaignid) A                                                    
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID and Kd.JobId = @Jobid
	where Kd.JobId = @Jobid                    
              
--UPDATE Kd  SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE()     FROM   Usercampaignhistory Kd                              
--        INNER JOIN  ##campaignrun c on Kd.ID=c.campaignrunid                                   
                                           
  UPDATE Kd                                                    
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE() FROM   Usercampaignhistory Kd where JobId=@jobid                                             
                                   
 DROP TABLE #temptable                
 exec [Usp_insertclonedeliverycampaignCorrected_withid21102020]  @jobid                                  
END                               
                              
