SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail_withid] @Jobid bigint                                  
AS                                      
BEGIN                                      
   create table #TempTable                                    
   (                                    
   Entityid bigint,entityname nvarchar(20),CampaignID bigint,ParentID bigint,MailContent NVARCHAR(Max),Mail_ToEmail varchar(500),MailReplyTo NVARCHAR(500),AccountUsed bigint,                                    
   MailSubject NVARCHAR(1000) ,Mail_Id bigint,templateid bigint,frommailid nvarchar(250),ispersonalized bit default 0                                   
   )                                    
                
Select Distinct EC.CampaignID,EC.ParentID into #EmailsfiltercampaignexecutionTEST2                
from EmailsfiltercampaignexecutionTEST2 EC With(nolock) where jobid=@jobid                   
                                    
   if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm  (nolock)                                    
              Inner Join #EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID                                     
                   WHERE  Ucm.MailReplyTo <> ''                                      
                   AND Ucm.MailContent <> ''                                      
            )begin                                    
   insert into #TempTable                                    
   (Entityid,entityname,CampaignID,ParentID,Mail_ToEmail,MailReplyTo,AccountUsed,Mail_Id,templateid,frommailid ,ispersonalized)                                    
            SELECT distinct Entityid,entityname,  
          Ucm.ID,                                      
                   Ucm.ParentID,                                      
                   Ucerm.Mail_ToEmail,                                      
                   Ucm.MailReplyTo,                                      
                   Ucm.AccountUsed AS AccountUsed,                                      
                   Ucerm.Mail_ID,    
                   0,isnull(ucm.FromMailId,'contactus@email19.in'),0    
            FROM   Usercampaignmaster Ucm  (nolock)                                   
                   INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                 
      ON ucm.ID=Ucerm.CampaignID                                                        
            WHERE  Ucerm.IsCompleted = 0                                      
                   AND Ucm.MailReplyTo <> ''                                      
                   AND Ucm.MailContent <> '' and jobid=@jobid                                                 
    
  insert into campaignmessages                                    
   (CampaignID,ParentID,messages,Mail_Subject,Createddate,Jobid )                                    
            SELECT distinct Ucm.ID,                                      
                   Ucm.ParentID,                                      
                   cast(Ucm.MailContent as nvarchar(max)),                                      
                   Ucm.MailSubject  ,              
                   getdate(),@Jobid    
            FROM   Usercampaignmaster Ucm  (nolock)                                   
                   INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                 
      ON ucm.ID=Ucerm.CampaignID                                                        
            WHERE  Ucerm.IsCompleted = 0                                      
                   AND Ucm.MailReplyTo <> ''                                      
                   AND Ucm.MailContent <> '' and jobid=@jobid                                                 
            end                                      
----- Newly added code below to include templates without dynamic values----                                          
            if exists (select top 1 'x'   FROM  Usercampaignmaster Ucm  (nolock)                                    
                   join UserMailTemplate umt on umt.ID=ucm.TemplateID                                     
                   Inner Join #EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID                                   
            WHERE  Ucm.MailReplyTo <> ''                                      
                   and isnull(ucm.TemplateID,0)<>0                              
                   and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0                              
            )begin                                    
   insert into #TempTable                                    
   (Entityid,entityname,CampaignID,ParentID,Mail_ToEmail,MailReplyTo,AccountUsed,Mail_Id,templateid,frommailid,ispersonalized )                                    
            SELECT Entityid,entityname,Ucm.ID as CampaignID,                                      
                   Ucm.ParentID as ParentID,                                      
                   --umt.mailcontent as mailcontent,                                      
                   Ucerm.Mail_ToEmail as Mail_ToEmail,                                      
                   Ucm.MailReplyTo MailReplyTo,                                      
                   Ucm.AccountUsed AS AccountUsed,                                 
                   --Umt.MailSubject  MailSubject ,              
  Ucerm.Mail_ID ,umt.ID,isnull(ucm.FromMailId,'contactus@email19.in')  ,0                    
            FROM   Usercampaignmaster Ucm  (nolock)              
                   join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                              
                INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                 
      ON ucm.ID=Ucerm.CampaignID                                            
            WHERE  Ucerm.IsCompleted = 0                                       
                   AND Ucm.MailReplyTo <> ''                                      
                   and isnull(ucm.TemplateID,0)<>0                              
                   and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0   and jobid=@jobid      
                                              
insert into campaignmessages                                    
   (CampaignID,ParentID,Messages,Mail_Subject,Createddate,jobid,templateid )                                    
            SELECT distinct Ucm.ID as CampaignID,                                      
                   Ucm.ParentID as ParentID,                                      
                   umt.mailcontent as mailcontent,                                      
                   Umt.MailSubject  MailSubject ,              
  getdate(),@Jobid,ucm.TemplateID    
            FROM   Usercampaignmaster Ucm  (nolock)              
                   join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                              
                INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                 
      ON ucm.ID=Ucerm.CampaignID                                            
            WHERE  Ucerm.IsCompleted = 0                                       
                   AND Ucm.MailReplyTo <> ''                                      
                   and isnull(ucm.TemplateID,0)<>0                              
                   and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0   and jobid=@jobid                                         
                                                 
            end                               
---- Newly addecd code above to include templates without dynamic values----                                  
   if exists (select top 1 'x'   FROM   Usercampaignmaster Ucm (nolock)                                     
                   INNER JOIN Usermailtemplate Umt (nolock)                                     
                        ON  Ucm.TemplateID = Umt.ID                                      
                   INNER JOIN #EmailsfiltercampaignexecutionTEST2 Ucerm  (nolock)                                    
                        ON  Ucerm.CampaignID = Ucm.ID                                                              
            WHERE  Umt.IsEnquiry = 1                                  
         )begin                                    
   insert into #TempTable                                    
   (Entityid,entityname,CampaignID,ParentID,MailContent,Mail_ToEmail,MailReplyTo,AccountUsed,MailSubject,Mail_Id,templateid,frommailid,ispersonalized )                                    
            SELECT Entityid,entityname,Ucm.ID CampaignID,                                      
                   Ucm.ParentID,                                      
                   dbo.[fn_getEnquiryMessageMail_NewAbdulTestSMS](                                      
                       Ucm.ParentID,                                      
                       Umt.MailContent,                                      
                       Ucerm.Mail_ToEmail  ,                
                       ue.personname,                
                       ue.companyname,                
                       ue.mobileno,                
                       ue.MobileNo1,                
                       ue.MobileNo2,                
                       ue.EmailID,                
                       ue.EmailID1,                
                       ue.EmailID2,                
                       uss.NAME,                
                       ums.Name,                
                       Ucs.Name,                
                       ue.initialremarks,                
                       ue.CreatedDate,                
                       ud.fname,                
                       ud.LName,    
                       ue.City,    
                       ue.State,    
                       case when isnull(ue.CompanyName,'')<>'' then ue.OfficeAddress else ue.ResidentialAddress end,    
                       ue.PinCode,      
                       ue.country                                      
                   ),                                               
                   Ucerm.Mail_ToEmail,                                      
                   Ucm.MailReplyTo,                                      
                   Ucm.AccountUsed AS AccountUsed,                                      
                   Umt.MailSubject   ,                  
                   Ucerm.Mail_ID ,    
                   umt.ID,isnull(ucm.FromMailId,'contactus@email19.in')   ,1                          
            FROM   Usercampaignmaster Ucm  (nolock)                                    
                  INNER JOIN Usermailtemplate Umt  (nolock)                                    
                        ON  Ucm.TemplateID = Umt.ID                                      
                   INNER JOIN EmailsfiltercampaignexecutionTEST2 Ucerm (nolock)                                     
                        ON  Ucerm.CampaignID = Ucm.ID                                      
                    Left Join  userenquiry ue ON  ue.parentid = Ucm.ParentID AND                
                 isnull(Ucerm.entityid,0)=ue.EnquiryID and ucerm.entityname='Enquiry'                
       LEFT JOIN usermediumsettings ums                
      ON  ums.mediumid = ue.mediumname                
       LEFT JOIN usercampaignsettings ucs                
      ON  ue.campaignname = ucs.campaignid                
       LEFT JOIN usersourcesettings uss                
      ON  ue.sourcename = uss.sourceid                
       LEFT JOIN user_detail ud                
      ON  ud.[user_id] = ue.createdby                   
            WHERE  Ucerm.IsCompleted = 0                
                   AND Umt.IsEnquiry = 1  and jobid=@jobid                  
            end                                      
            
if exists (select 'x'   FROM   Usercampaignmaster Ucm  (nolock)                                    
                INNER JOIN Usermailtemplate Umt  (nolock)                                    
                        ON  Ucm.TemplateID = Umt.ID                                      
               INNER JOIN #EmailsfiltercampaignexecutionTEST2 Ucerm  (nolock)                                    
                        ON  Ucerm.CampaignID = Ucm.ID                                  
 WHERE  (Umt.IsLeads = 1 OR Umt.IsConversion = 1))          
 begin                                    
   insert into #TempTable                               
   (entityname,Entityid,CampaignID,ParentID,MailContent,Mail_ToEmail,MailReplyTo,AccountUsed,MailSubject,Mail_Id,templateid,frommailid,ispersonalized )                               
           SELECT entityname,entityid,Ucm.ID,                                      
                   Ucm.ParentID,                                      
                   dbo.[fn_getLeadsMailMessage_NewAbdul](                                      
                       Ucm.ParentID,                                      
                       Umt.MailContent,                                      
                       Ucerm.Mail_ToEmail  ,                
                       ue.personname  ,                
 ue.companyname  ,                
 ue.mobileno ,ue.mobileno1 ,ue.mobileno2 ,ue.emailid                
 ,ue.emailid1 ,                
 ue.emailid2 ,                
 ue.LeadNo ,                 
 ue.NextStatusDate ,                
 ud2.fName ,                
 ud2.LName ,                
 ue.Remarks ,                
 ue.CreatedOn,                
 ud.FName ,                
 ud.LName ,      
 uss.NAME,                
 ums.Name,                
 Ucs.Name                                      
                   ),                                      
                   Ucerm.Mail_ToEmail,                                      
                   Ucm.MailReplyTo,                                      
                   Ucm.AccountUsed AS AccountUsed,                                      
                   Umt.MailSubject        ,              
                   Ucerm.Mail_ID ,    
                   umt.ID,isnull(ucm.FromMailId,'contactus@email19.in')  ,1                           
            FROM    Usercampaignmaster Ucm  (nolock)                                    
                   INNER JOIN Usermailtemplate Umt  (nolock)                                    
                        ON  Ucm.TemplateID = Umt.ID                                      
                   INNER JOIN EmailsfiltercampaignexecutionTEST2 Ucerm   (nolock)                             
                        ON  Ucerm.CampaignID = Ucm.ID                
                     LEFT JOIN  userleads ue ON ue.parentid = Ucm.ParentID AND isnull(Ucerm.entityid,0)=ue.ID   and ucerm.entityname='Lead'     
                 LEFT JOIN usermediumsettings ums                
      ON  ums.mediumid = ue.mediumname                
       LEFT JOIN usercampaignsettings ucs                
      ON  ue.campaignname = ucs.campaignid                
       LEFT JOIN usersourcesettings uss                
      ON  ue.sourcename = uss.sourceid                       
        LEFT JOIN user_detail ud                
             ON  ud.[user_id] = ue.createdby                
        LEFT JOIN user_detail ud2                
             ON  ud2.[user_id] = ue.assignedto                
            WHERE  Ucerm.IsCompleted = 0                                   
                   AND (Umt.IsLeads = 1 OR Umt.IsConversion = 1) and jobid=@jobid                   
                                                                   
            end                                 
                                                  
   if exists (select top 1 'x'     FROM  Usercampaignmaster Ucm  (nolock)                                    
                  INNER JOIN Usermailtemplate Umt (nolock)        
                        ON  Ucm.TemplateID = Umt.ID                                      
                   INNER JOIN #EmailsfiltercampaignexecutionTEST2 Ucerm  (nolock)                                    
                        ON  Ucerm.CampaignID = Ucm.ID                                       
            WHERE   Umt.IsList = 1                                      
                                                  
            )begin                
   insert into #TempTable                                    
   (entityname,Entityid,CampaignID,ParentID,MailContent,Mail_ToEmail,MailReplyTo,AccountUsed,MailSubject,Mail_Id,templateid,frommailid,ispersonalized )                                    
            SELECT entityname,entityid,Ucm.ID,                                      
                   Ucm.ParentID,                                      
          REPLACE(              
            REPLACE(              
                REPLACE(              
                    REPLACE(              
                        REPLACE(              
                            REPLACE(              
REPLACE(              
                                    REPLACE(              
                                        REPLACE(              
                                            REPLACE(              
                                                Umt.MailContent,              
                                                '#' + ISNULL(uilc.column1,'') +              
                                                '#',              
                                                ISNULL(usd.mobilenumber, '')              
                                            ),              
                                            '#' + ISNULL(uilc.column2,'') + '#',              
                                            ISNULL(usd.emailid, '')              
                                        ),              
                                        '#' + ISNULL(uilc.column3,'') + '#',              
                                        ISNULL(usd.column1, '')              
                                    ),              
                                    '#' + ISNULL(uilc.column4,'') +              
                                    '#',              
                                    ISNULL(usd.column2, '')              
                                ),              
                                '#' + ISNULL(uilc.column5,'') + '#',              
                                ISNULL(usd.column3, '')              
                            ),              
                            '#' + ISNULL(uilc.column6 ,'')+ '#',              
                            ISNULL(usd.column4, '')              
                        ),              
                        '#' + ISNULL(uilc.column7,'') + '#',              
                        ISNULL(usd.column5, '')              
                    ),              
                    '#' + ISNULL(uilc.column8,'') + '#',              
                    ISNULL(usd.column6, '')              
                ),              
                '#' + ISNULL(uilc.column9,'') + '#',              
                ISNULL(usd.column7, '')              
            ),              
            '#' + ISNULL(uilc.column10,'') + '#',              
            ISNULL(usd.column8, '')              
        )              
 ,Ucerm.Mail_ToEmail,                                      
                   Ucm.MailReplyTo,                                      
                   Ucm.AccountUsed AS AccountUsed,                                      
                   Umt.MailSubject ,              
                   Ucerm.Mail_ID ,umt.ID ,isnull(ucm.FromMailId,'contactus@email19.in'),1                                   
   FROM   Usercampaignmaster Ucm  (nolock)                
INNER JOIN Usermailtemplate Umt (nolock) ON  Ucm.TemplateID = Umt.ID                                      
INNER JOIN EmailsfiltercampaignexecutionTEST2 Ucerm   (nolock) ON  Ucerm.CampaignID = Ucm.ID and Ucerm.ParentID = Ucm.ParentID            
INNER JOIN userimportedlistcolumn uilc ON uilc.id = Umt.ListID                
INNER JOIN usersearchdata usd    ON  uilc.id = usd.importedlistid                
       AND usd.emailid = Ucerm.Mail_ToEmail                  
       WHERE  Ucerm.IsCompleted = 0                
                   AND Umt.IsList = 1  and jobid=@jobid       
       end                                      
                                                  
   if exists (select top 1 'x'    FROM   Usercampaignmaster Ucm  (nolock)                                
                   INNER JOIN #EmailsfiltercampaignexecutionTEST2 Ucerm  (nolock)                   
                        ON  Ucerm.CampaignID = Ucm.ID                                    
            WHERE  ucm.TemplateGroupID<>0                                    
                                                  
            )begin                                    
                                                
    CREATE TABLE #tempGroups                                      
    (                         
	EntityName nvarchar(20),EntityID bigint,             
     CampaignID         BIGINT,                                      
     ParentID           BIGINT,                                      
     messageContent     NVARCHAR(MAX),                                      
     Mail_ToEmail       NVARCHAR(500),                                      
     MailReplyTo        NVARCHAR(500),                                      
     AccountUsed        NVARCHAR(500),                             
     MailSubject        NVARCHAR(500),    
     templateid bigint,    
     frommailid nvarchar(250)                                                    
    )                                      
                                           
    INSERT INTO #tempGroups              
      (
	  EntityName,EntityID,                                      
     CampaignID,                                      
     ParentID,                                      
     messageContent,                                      
     Mail_ToEmail,                                      
     MailReplyTo,                                      
     AccountUsed,                                      
     MailSubject,    
     templateid ,    
     frommailid                                                   
      )                                      
    EXEC Fn_getgroupmessagemailsnew2_withid                                      
                                       
     insert into #TempTable                                    
     (EntityName,EntityID,CampaignID,ParentID,MailContent,Mail_ToEmail,MailReplyTo,AccountUsed,MailSubject,templateid,frommailid,ispersonalized )                                    
   SELECT EntityName,EntityID,CampaignID,                                      
         ParentID,                                      
         CAST(                                      
          messageContent COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                                      
         CAST(Mail_ToEmail COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                
         CAST(MailReplyTo COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                                      
         AccountUsed,                                      
         CAST(MailSubject COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),    
         templateid ,isnull(cast(FromMailId collate Latin1_General_CI_AI AS NVARCHAR(250)) ,'contactus@email19.in'),1                                     
     FROM   #tempGroups                                      
     END                                    
                                         
   UPDATE Kd                                      
   SET    
   kd.entityname=a.entityname,
   kd.entityid=a.entityid,
   Kd.Mail_FromEmail = ISNULL(CAST(nullif(A.FromMailId COLLATE Latin1_General_CI_AI,'') AS NVARCHAR(250)),'contactus@email19.in'),    
   Kd.Mail_Subject = case when isnull(A.mailsubject,'')<>'' then CAST(A.MailSubject COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)) end,         
    Kd.Messages = case when isnull(A.MailContent,'')<>'' then (select CAST(dbo.build_mailContent(A.templateid,A.campaignid,A.parentid,A.MailContent COLLATE Latin1_General_CI_AI,A.Mail_ToEmail)   
 AS NVARCHAR(MAX))) end, --CAST(A.MailContent COLLATE Latin1_General_CI_AI AS VARCHAR(MAX)),           
    Kd.Mail_UserID = A.AccountUsed,                                      
    Kd.ReplyTo = CAST(A.MailReplyTo COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                                      
    Kd.Mail_Priority = 0,                                      
    Kd.Mail_ScheduleDate = GETDATE(),                                      
    Kd.Mail_Attechement = NULL,                                      
    Kd.Mail_TempleteBody = case when isnull(A.MailContent,'')<>'' then (select CAST(dbo.build_mailContent(A.templateid,A.campaignid,A.parentid,A.MailContent COLLATE Latin1_General_CI_AI,A.Mail_ToEmail) AS NVARCHAR(MAX))) end,                             
   
        
    Kd.Mail_InsertedDate = GETDATE(),                                      
    Kd.Mail_GUID = NEWID(),                                      
    Kd.IsCompleted = 1 ,    
 kd.ispersonalized=A.ispersonalized                            
   FROM   EmailsfiltercampaignexecutionTEST2 Kd    (nolock)                                  
    INNER JOIN #TempTable A                                     
      ON kd.Mail_ID = A.Mail_Id  and kd.jobid=@jobid            
                                          
           
   UPDATE Kd                                          
      SET    Ismessages = 1                                          
      FROM   Usercampaignexecutionhistory Kd        
      inner join #temptable A                 
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid                                      
                            
   UPDATE Kd                                    
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE(), Step2Recipients=isnull(A.Step2Recipients,0)                                 
   FROM   Usercampaignhistory Kd  (nolock)                                  
    Inner JOIN                                 
    (select campaignid,count(campaignid) as Step2Recipients,parentid                 
    from #temptable group by Parentid,campaignid) A                                    
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid                           
                     
   UPDATE Kd                                    
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE() FROM   Usercampaignhistory Kd where JobId=@jobid    
                         
 DROP TABLE #TempTable             
 exec [Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid] @jobid                                     
END 


