/* ============================================================
   Procedure: [dbo].[Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail_withid21102020_n]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail_withid21102020_n]  --12404393  
@Jobid bigint                                        
AS                                            
BEGIN                                            
   create table #TempTable                                          
   (                                          
   Entityid bigint,entityname nvarchar(20),CampaignID bigint,ParentID bigint,MailContent NVARCHAR(Max),Mail_ToEmail varchar(500),MailReplyTo NVARCHAR(500),AccountUsed bigint,                                          
   MailSubject NVARCHAR(1000) ,Mail_Id bigint,templateid bigint,frommailid nvarchar(250),ispersonalized bit default 0                                         
   )                                          
                      
Select Distinct EC.CampaignID,EC.ParentID into #EmailsfiltercampaignexecutionTEST2                      
from EmailsfiltercampaignexecutionTEST2 EC With(nolock) where jobid=@jobid                         
  
declare @b int,@e_c bigint  
  
insert into campaignmessages(CampaignID,ParentID,messages,Mail_Subject,Createddate,Jobid )                                          
SELECT distinct Ucm.ID,Ucm.ParentID,cast(Ucm.MailContent as nvarchar(max)),Ucm.MailSubject  ,getdate(),@Jobid          
FROM   Usercampaignmaster Ucm  (nolock) INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock)                       
ON ucm.ID=Ucerm.CampaignID WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo <> '' AND Ucm.MailContent <> '' and jobid=@jobid                                                       
    
insert into campaignmessages(CampaignID,ParentID,Messages,Mail_Subject,Createddate,jobid,templateid )                                          
SELECT distinct Ucm.ID as CampaignID,Ucm.ParentID as ParentID,umt.mailcontent as mailcontent,Umt.MailSubject  MailSubject ,                    
getdate(),@Jobid,ucm.TemplateID FROM   Usercampaignmaster Ucm  (nolock) join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID   
INNER JOIN EmailsfiltercampaignexecutionTEST2 AS Ucerm  (nolock) ON ucm.ID=Ucerm.CampaignID                                                  
WHERE  Ucerm.IsCompleted = 0 AND Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0   and jobid=@jobid                                               
  
select @e_c=count(1) from EmailsfiltercampaignexecutionTEST2 EC (nolock) join Usercampaignmaster Ucm  (nolock)   
   on EC.CampaignId = Ucm.ID  WHERE  Ucm.MailReplyTo <> '' AND Ucm.MailContent <> ''  and jobid=@jobid and iscompleted=0   
   and isnull(ucm.TemplateID,0)=0  
  
while @e_c>0  
begin  
UPDATE Kd                                            
   SET          
    Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'),          
    Kd.Mail_UserID = ucm.AccountUsed,                                            
    Kd.ReplyTo = ucm.MailReplyTo,                                            
    Kd.Mail_Priority = 0,                                            
    Kd.Mail_ScheduleDate = GETDATE(),                                            
    Kd.Mail_Attechement = NULL,                                            
    Kd.Mail_InsertedDate = GETDATE(),                                            
    Kd.Mail_GUID = NEWID(),                     
    Kd.IsCompleted = 1 ,          
    kd.ispersonalized=0                                  
   FROM   
(select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd                                      
join   Usercampaignmaster Ucm  (nolock)  ON ucm.ID=kd.CampaignID                                                              
WHERE Ucm.MailReplyTo <> ''AND Ucm.MailContent <> '' and jobid=@jobid                                                       
select @b=@@ROWCOUNT  
set @e_c=@e_c-@b  
end      
  
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID    
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                    
and ec.jobid=@jobid and ec.iscompleted=0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0    
while @e_c>0  
begin  
UPDATE Kd                                            
   SET          
    Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'),          
    Kd.Mail_UserID = ucm.AccountUsed,                                            
    Kd.ReplyTo = ucm.MailReplyTo,                                            
    Kd.Mail_Priority = 0,                                            
    Kd.Mail_ScheduleDate = GETDATE(),                                            
    Kd.Mail_Attechement = NULL,                                            
    Kd.Mail_InsertedDate = GETDATE(),                                            
    Kd.Mail_GUID = NEWID(),                     
    Kd.IsCompleted = 1 ,          
    kd.ispersonalized=0,  
 kd.templateid=umt.id  
   FROM   
   (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd                                      
join Usercampaignmaster Ucm  (nolock)   ON ucm.ID=kd.CampaignID                  
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                    
WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=0 and umt.IsLeads=0 and umt.IsList=0 and umt.IsConversion=0  
  
select @b=@@ROWCOUNT  
set @e_c=@e_c-@b  
end      
  
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID    
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                    
and ec.jobid=@jobid and ec.iscompleted=0 and umt.IsEnquiry=1  --and ec.entityname='enquiry'  
while @e_c>0  
begin  
UPDATE Kd                                            
   SET          
    Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'),          
    Kd.Mail_Subject = case when kd.entityname='enquiry' then   
 dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.mailsubject,kd.entityid) else umt.mailsubject end,               
    Kd.Messages = case when kd.entityname='enquiry'   
 then (select CAST(dbo.build_mailContent(umt.id,kd.campaignid,kd.parentid,  
 dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.MailContent,kd.entityid),kd.Mail_ToEmail)          
 AS NVARCHAR(MAX))) else umt.mailcontent  end,   
    Kd.Mail_UserID = ucm.AccountUsed,                                            
    Kd.ReplyTo = ucm.MailReplyTo,                                            
    Kd.Mail_Priority = 0,                                            
    Kd.Mail_ScheduleDate = GETDATE(),                                            
    Kd.Mail_Attechement = NULL,                                            
    Kd.Mail_TempleteBody = case when kd.entityname='enquiry'  
 then (select CAST(dbo.build_mailContent(kd.templateid,kd.campaignid,kd.parentid,  
 dbo.[fn_getEnquiryMessageMail_withid](Ucm.ParentID,Umt.MailContent,kd.entityid),kd.Mail_ToEmail)         
 AS NVARCHAR(MAX))) else umt.mailcontent end,  
    Kd.Mail_InsertedDate = GETDATE(),                                            
    Kd.Mail_GUID = NEWID(),                     
    Kd.IsCompleted = 1 ,          
    kd.ispersonalized=1                                  
   FROM   
   (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd                                      
join Usercampaignmaster Ucm  (nolock)   ON ucm.ID=kd.CampaignID                  
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID    
--Left Join  userenquiry ue(nolock) ON  ue.parentid = Ucm.ParentID AND isnull(kd.entityid,0)=ue.EnquiryID and kd.entityname='Enquiry'    
WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and umt.IsEnquiry=1  
  
select @b=@@ROWCOUNT  
set @e_c=@e_c-@b  
end   
  
select @e_c=count(1) from Usercampaignmaster Ucm  (nolock)  join UserMailTemplate umt on umt.ID=ucm.TemplateID    
Join EmailsfiltercampaignexecutionTEST2 EC on EC.CampaignId = Ucm.ID WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0                                    
and ec.jobid=@jobid and ec.iscompleted=0 and (umt.IsLeads=1 or umt.IsConversion=1)    
while @e_c>0  
begin  
UPDATE Kd                                            
   SET          
    Kd.Mail_FromEmail = isnull(ucm.FromMailId,'contactus@email19.in'),          
    Kd.Mail_Subject = case when kd.entityname='lead' then   dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailSubject,kd.entityid)   
 else umt.mailcontent end,               
    Kd.Messages = case when kd.entityname='lead' then   dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,kd.entityid)   
 else umt.mailcontent end ,   
    Kd.Mail_UserID = ucm.AccountUsed,                                            
    Kd.ReplyTo = ucm.MailReplyTo,                                            
    Kd.Mail_Priority = 0,                                            
    Kd.Mail_ScheduleDate = GETDATE(),                                            
    Kd.Mail_Attechement = NULL,                                            
    Kd.Mail_TempleteBody = case when kd.entityname='lead' then   dbo.[fn_getLeadsMailMessage_withid](Ucm.ParentID,Umt.MailContent,kd.entityid)   
 else umt.mailcontent end ,  
    Kd.Mail_InsertedDate = GETDATE(),                                            
    Kd.Mail_GUID = NEWID(),                     
    Kd.IsCompleted = 1 ,          
 kd.ispersonalized=1                                  
   FROM   
   (select top 500 * from EmailsfiltercampaignexecutionTEST2 EC (nolock) where jobid=@jobid and iscompleted=0 order by mail_id) kd                                      
join Usercampaignmaster Ucm  (nolock)   ON ucm.ID=kd.CampaignID                  
join UserMailTemplate umt (nolock) on umt.ID=ucm.TemplateID                                    
WHERE  Ucm.MailReplyTo <> '' and isnull(ucm.TemplateID,0)<>0 and (umt.IsLeads=1 or umt.IsConversion=1)
  
select @b=@@ROWCOUNT  
set @e_c=@e_c-@b  
end      
/*  
if exists (select top 1 'x'    FROM   Usercampaignmaster Ucm  (nolock)                                      
                   INNER JOIN #EmailsfiltercampaignexecutionTEST2 Ucerm  (nolock)                         
                        ON  Ucerm.CampaignID = Ucm.ID                                          
            WHERE  ucm.TemplateGroupID<>0                                          
                                                        
            )begin                                          
                                                      
    CREATE TABLE #tempGroups                                            
    (                               
 EntityName nvarchar(20),EntityID bigint,                   
     CampaignID         BIGINT,                                            
     ParentID           BIGINT,                                            
     messageContent     NVARCHAR(MAX),                                            
     Mail_ToEmail       NVARCHAR(500),                                            
     MailReplyTo        NVARCHAR(500),                                            
     AccountUsed        NVARCHAR(500),                                   
     MailSubject        NVARCHAR(500),          
     templateid bigint,          
     frommailid nvarchar(250)                                                          
    )                                            
                                                 
    INSERT INTO #tempGroups                    
      (      
   EntityName,EntityID,                                            
     CampaignID,                                            
 ParentID,                                            
     messageContent,                                            
     Mail_ToEmail,                                            
     MailReplyTo,                                            
     AccountUsed,                                            
     MailSubject,          
     templateid ,          
     frommailid                                                         
      )                                            
    EXEC Fn_getgroupmessagemailsnew2_withid                                            
                                             
     insert into #TempTable                                          
     (EntityName,EntityID,CampaignID,ParentID,MailContent,Mail_ToEmail,MailReplyTo,AccountUsed,MailSubject,templateid,frommailid,ispersonalized )                                          
   SELECT EntityName,EntityID,CampaignID,                                            
         ParentID,                                            
         CAST(                                            
          messageContent COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                                            
         CAST(Mail_ToEmail COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                      
         CAST(MailReplyTo COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),                                            
         AccountUsed,                               
         CAST(MailSubject COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)),          
         templateid ,isnull(cast(FromMailId collate Latin1_General_CI_AI AS NVARCHAR(250)) ,'contactus@email19.in'),1                                           
     FROM   #tempGroups                                            
     END                                          
  */                                     
                 
   UPDATE Kd                                                
      SET    Ismessages = 1                                                
      FROM   Usercampaignexecutionhistory Kd              
      inner join #EmailsfiltercampaignexecutionTEST2 A                       
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid                                            
                                  
   UPDATE Kd                                          
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE(), Step2Recipients=isnull(A.Step2Recipients,0)                                       
   FROM   Usercampaignhistory Kd  (nolock)                                        
    Inner JOIN                                       
    (select campaignid,count(campaignid) as Step2Recipients,parentid                       
    from EmailsfiltercampaignexecutionTEST2 where iscompleted=1 group by Parentid,campaignid) A                                          
    ON  Kd.CampaignID = A.CampaignID AND A.ParentID = Kd.ParentID AND Kd.JobId = @Jobid                                 
                           
   UPDATE Kd                                          
   SET    Kd.Step2 = 1  ,Step2DateTime=GETDATE() FROM   Usercampaignhistory Kd where JobId=@jobid          
                               
 DROP TABLE #TempTable                   
 exec [Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020] @jobid                                           
END 


