CREATE   PROC [dbo].[Usp_UserFilterMoveProcessTableTosource] --6735647,0,0,4,'ON'
@BATCHID BIGINT,-- frm int 17-08-2010
@PRIORITY TINYINT,
@ALLOWDND BIT,
@PROCESSTABLE INT,
@USERFILTERFLAG VARCHAR(20)
AS
BEGIN                                                                                    
SET XACT_ABORT ON            
BEGIN TRY
BEGIN DISTRIBUTED TRANSACTION                                       
	IF (@PROCESSTABLE = 1)
	BEGIN
		IF (@ALLOWDND = 1)
		BEGIN
			IF @PRIORITY=0
				BEGIN
					INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,							PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID
				END
			ELSE 
				BEGIN
					INSERT INTO MESSAGEQUEUE(MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,									PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID
				END
			DELETE FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID
		END
		ELSE IF (@ALLOWDND = 0)
		BEGIN
			INSERT INTO MESSAGEDELIVERYSTATUS(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,				MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,
			OPERATOR,ISALLOWDND FROM PROCESSTABLEFIRST WHERE BATCHID=@BATCHID
		
			DELETE PROCESSTABLEFIRST FROM PROCESSTABLEFIRST JOIN INVALIDNUMBER INNUM 
			ON PROCESSTABLEFIRST.MOBILE=INNUM.MOBILE WHERE BATCHID = @BATCHID
			
			--UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=9,LASTERROR=001 FROM 
			--MESSAGEDELIVERYSTATUS MDS JOIN INVALIDNUMBER INNUM ON				MDS.MOBILE=INNUM.MOBILE	WHERE BATCHID = @BATCHID
			
			INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,				ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,OPERATOR,				ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID AND ISDND = 0

			--DND FILTER
			INSERT INTO MESSAGEDND(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,
			ISDND,OPERATOR,BATCHID) SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID, @PRIORITY ,U_ID,ISUNICODE,				ISDND,OPERATOR,BATCHID FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID AND ISDND = 1

			UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=3 WHERE BATCHID = @BATCHID AND				ISDND = 1
			
			DELETE FROM PROCESSTABLEFIRST WHERE BATCHID = @BATCHID
		END
	END
	ELSE IF (@PROCESSTABLE = 2)
	BEGIN
		
		
		IF (@ALLOWDND = 1)
		BEGIN
			IF @PRIORITY=0
				BEGIN
					INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,							PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID
				END
			ELSE 
				BEGIN
					INSERT INTO MESSAGEQUEUE(MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,									PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID
				END
			DELETE FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID
		END
		ELSE IF (@ALLOWDND = 0)
		BEGIN
			INSERT INTO MESSAGEDELIVERYSTATUS(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,				MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,
			OPERATOR,ISALLOWDND FROM PROCESSTABLETWO WHERE BATCHID=@BATCHID
		
			DELETE PROCESSTABLETWO FROM PROCESSTABLETWO JOIN INVALIDNUMBER INNUM 
			ON PROCESSTABLETWO.MOBILE=INNUM.MOBILE WHERE BATCHID = @BATCHID
			
			--UPDATE MESSAGEDELIVERYSTATUS  SET MESSAGESTATUS=9,LASTERROR=001 FROM 
			--MESSAGEDELIVERYSTATUS MDS JOIN INVALIDNUMBER INNUM ON				MDS.MOBILE=INNUM.MOBILE	WHERE BATCHID = @BATCHID
			
			INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,				ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,OPERATOR,				ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID AND ISDND = 0

			--DND FILTER
			INSERT INTO MESSAGEDND(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,
			ISDND,OPERATOR,BATCHID) SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID, @PRIORITY ,U_ID,ISUNICODE,				ISDND,OPERATOR,BATCHID FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID AND ISDND = 1
			
			UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=3 WHERE BATCHID = @BATCHID AND				ISDND = 1
			
			DELETE FROM PROCESSTABLETWO WHERE BATCHID = @BATCHID
		END
	END
	ELSE IF (@PROCESSTABLE = 3)
	BEGIN
		
		
		IF (@ALLOWDND = 1)
		BEGIN
			IF @PRIORITY=0
				BEGIN
					INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,							PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID
				END
			ELSE 
				BEGIN
					INSERT INTO MESSAGEQUEUE(MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,									PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID
				END
			DELETE FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID
		END
		ELSE IF (@ALLOWDND = 0)
		BEGIN
			INSERT INTO MESSAGEDELIVERYSTATUS(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,				MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,
			OPERATOR,ISALLOWDND FROM PROCESSTABLETHREE WHERE BATCHID=@BATCHID
		
			DELETE PROCESSTABLETHREE FROM PROCESSTABLETHREE JOIN INVALIDNUMBER INNUM 
			ON PROCESSTABLETHREE.MOBILE=INNUM.MOBILE WHERE BATCHID = @BATCHID
			
			--UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=9,LASTERROR=001 FROM 
			--MESSAGEDELIVERYSTATUS MDS JOIN INVALIDNUMBER INNUM ON				MDS.MOBILE=INNUM.MOBILE	WHERE BATCHID = @BATCHID
			
			INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,				ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,OPERATOR,				ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID AND ISDND = 0

			--DND FILTER
			INSERT INTO MESSAGEDND(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,
			ISDND,OPERATOR,BATCHID) SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID, @PRIORITY ,U_ID,ISUNICODE,				ISDND,OPERATOR,BATCHID FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID AND ISDND = 1
			
			UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=3 WHERE BATCHID = @BATCHID AND				ISDND = 1
			
			DELETE FROM PROCESSTABLETHREE WHERE BATCHID = @BATCHID
		END
	END
	ELSE IF (@PROCESSTABLE = 4)
	BEGIN
		
		
		IF (@ALLOWDND = 1)
		BEGIN
			IF @PRIORITY=0
				BEGIN
					INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,							PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID
				END
			ELSE 
				BEGIN
					INSERT INTO MESSAGEQUEUE(MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID,									PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
					SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,							OPERATOR,ISALLOWDND FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID
				END
			DELETE FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID
		END
		ELSE IF (@ALLOWDND = 0)
		BEGIN
			INSERT INTO MESSAGEDELIVERYSTATUS(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,				MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,ISALLOWDND)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,
			OPERATOR,ISALLOWDND FROM PROCESSTABLEFOUR WHERE BATCHID=@BATCHID
		
			DELETE PROCESSTABLEFOUR FROM PROCESSTABLEFOUR JOIN  INVALIDNUMBER INNUM 
			ON PROCESSTABLEFOUR.MOBILE=INNUM.MOBILE WHERE BATCHID = @BATCHID 
			
			--UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=9,LASTERROR=001 FROM 
			--MESSAGEDELIVERYSTATUS MDS JOIN INVALIDNUMBER INNUM ON				MDS.MOBILE=INNUM.MOBILE WHERE BATCHID = @BATCHID
			
			INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,				ISUNICODE,ISDND,OPERATOR,ISALLOWDND,USERFILTER)
			SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID, @PRIORITY ,ISUNICODE,ISDND,OPERATOR,				ISALLOWDND,@USERFILTERFLAG FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID AND ISDND = 0

			--DND FILTER
			INSERT INTO MESSAGEDND(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,
			ISDND,OPERATOR,BATCHID) SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID, @PRIORITY ,U_ID,ISUNICODE,				ISDND,OPERATOR,BATCHID FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID AND ISDND = 1

			UPDATE MESSAGEDELIVERYSTATUS SET MESSAGESTATUS=3 WHERE BATCHID = @BATCHID AND				ISDND = 1
			
			DELETE FROM PROCESSTABLEFOUR WHERE BATCHID = @BATCHID
		END
	END
	IF @@TRANCOUNT > 0     
 COMMIT      
END TRY     
BEGIN CATCH      
IF @@TRANCOUNT > 0     
 ROLLBACK ;      
  EXECUTE USP_INSERTERRORINFO;        
END CATCH   
SET XACT_ABORT OFF       
END




