/* ============================================================
   Procedure: [dbo].[usp_UserLeads_MobileNoByIDS_MobileColumn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_UserLeads_MobileNoByIDS_MobileColumn]      
 @ID VARCHAR(Max)='',                                  
 @Account BIGINT,                                  
 @Mobile BIT,                                  
 @mobile1 BIT,                                  
 @Mobile2 BIT     ,  
 @massbatchid bigint=0  
AS                                  
BEGIN                                  
 declare @parentid bigint = (select Parentid from user_detail with(nolock) where USER_ID=@Account)     
   
      if @massbatchid IS NOT NULL AND @massbatchid <> 0  
BEGIN  
 select @ID= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails with(nolock) where SummaryId=@massbatchid   
END  
--drop table if exists #tempTable              
            
--select * into #tempTable from (                    
 select * from (      
 select           
 distinct *          
  FROM   (                                  
            SELECT CASE                                   
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '')                                  
                        ELSE ''                                  
                   END         AS Mobile, Id, 1 chkM     
            FROM   UserLeads   AS ue with(nolock)     
   WHERE  ue.ID IN (SELECT [value]                                  
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                    
                   AND ISNULL(NULLIF(ue.MobileNo, ''), '') <>                                   
                       ''                                   
                    AND not exists                             
                   (select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock) 
				   where parentid=@parentid and (Ue.MobileNo=C_UDTemp.Mobile and UE.CountryCode = C_UDTemp.CountryCode))                            
                  -- where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs ))                                                      
            UNION                                    
                                              
            SELECT CASE                                   
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '')                                  
                        ELSE ''                                  
                   END         AS Mobile, Id, 2 chkM      
            FROM   UserLeads  AS ue                                  
            WHERE  ue.ID IN (SELECT [value]                                  
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                                  
                   AND ISNULL(NULLIF(ue.MobileNo1, ''), '') <> ''                              
                        AND not exists(select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock) where parentid=@parentid and (Ue.MobileNo1=C_UDTemp.Mobile and UE.CountryCode1 = C_UDTemp.CountryCode))                                 
                                            
            UNION                                    
                                              
            SELECT CASE                                   
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '')                                  
                        ELSE ''                                
                   END         AS Mobile, Id, 3 chkM      
            FROM   UserLeads  AS ue                                  
            WHERE  ue.ID IN (SELECT [value]                                  
                             FROM   dbo.fn_Split(@ID, '#') AS fs)                                  
                   AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                             
                       AND not exists(select 1 from  Client_UnSubscribeDetails as C_UDTemp with(nolock)
					   where parentid=@parentid and (Ue.MobileNo2=C_UDTemp.Mobile and UE.CountryCode2 = C_UDTemp.CountryCode))      
  
) A                                  
 WHERE  A.Mobile != '') B            
      
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_UserLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================                              
-- Author:  <vinay kumar upadhyay,chandra prakash singh, Ratna Kumari>                              
-- Create date: <19 march 2015>                              
-- Description: <This  Sp used To login User>                              
-- =============================================                              
CREATE   PROCEDURE [dbo].[USP_UserLogin] --'+919910025912','16881','','1.0'                        
@Mobile varchar(20),                              
@Pwd varchar(20),           
@DeviceID varchar(150),            
@Version  varchar(20)                                               
AS                              
BEGIN                              
 set nocount on;         
 declare @User_ID int,@PASSWORD varchar(20),@UserCategory varchar(30),@Currency varchar(30),@Country varchar(100),@Plan varchar(100),    
 @ExpiryDate varchar(20),@DBDeviceID nvarchar(200);                      
 select @User_ID = User_ID from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd                
 select @UserCategory=UserCategory from User_Detail where User_ID=@User_ID          
 select @Currency =[Currency],@Country=Country_Name FROM [KITEVER].[dbo].[M_Country]     
 where [CountryCode]=(select CountryCode from user_detail(nolock) where User_ID=@User_ID)           
 if(@UserCategory='Company')          
  begin          
   select @Plan=[PlanName] FROM [KITEVER].[dbo].[PlanMaster] PM(nolock) where id=1          
  end          
 else          
  begin          
   select @Plan=[PlanName],@ExpiryDate=[ExpiryDate] FROM [KITEVER].[dbo].[PlanMaster] PM(nolock) join     
   [KITEVER].[dbo].[MerchantSubscription] MS(nolock)          
   on PM.id=MS.[PlanID]          
  end                            
 IF((@Mobile<>'')AND(@Pwd<>''))                               
  BEGIN                    
   select @DBDeviceID=isnull(DeviceID,0) from DBO.User_Detail(NOLOCK) WHERE user_login=@Mobile and Pwd=@Pwd          
   IF ((@DBDeviceID<>'0' and @DBDeviceID<>'') and (@DeviceID<>@DBDeviceID))    
    BEGIN           
     SELECT 'False' as Status ,'Already Loggedin' as Message      ,2 as 'QueryStatusValue'
    END                  
   ELSE                  
    BEGIN                  
     IF EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE user_login=@Mobile)                               
      BEGIN                                
       select @PASSWORD=Pwd from User_Detail WHERE user_login=@Mobile                              
        if(@PASSWORD=@Pwd)                              
         begin                           
          declare @merchant_User_ID varchar(30),@merchant_code varchar(30),@merchant_name varchar(30),    
          @merchant_website varchar(30);                        
              
          select @merchant_User_ID = merchant_code,@merchant_code = merchant_code from User_Detail     
          WHERE user_login=@Mobile and  Pwd=@Pwd      
              
          select @merchant_name = CompnayName,@merchant_website = Merchant_Url  from User_Detail     
          WHERE user_id=@merchant_code                  
          update User_Detail set Status=1 where user_login=@Mobile  and User_ID= @User_ID                              
    
          declare @ProfilePicturePath varchar(100),@MerchantProfilePicturePath varchar(100);                          
              
          select @ProfilePicturePath = isnull(ProfilePicturePath,'') from User_Detail     
          WHERE user_login=@Mobile and  Pwd=@Pwd                               
              
          select @MerchantProfilePicturePath = isnull(ProfilePicturePath,'') from User_Detail     
          WHERE user_id=@merchant_code     
              
          select @merchant_User_ID as MerchantUserID, @merchant_name as MerchantName,     
          @merchant_website as MerchantWebsite,@ProfilePicturePath as ProfilePicturePath,    
          @MerchantProfilePicturePath as MerchantProfilePicturePath,User_ID,Pwd,    
          CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile,Status,'True' as QueryStatus,    
          'Login Successful' as UserMessage, UserType, user_login, Userfilter,@Currency as Currency,    
          UserCategory,EMail,pincode,Gender,Address,Merchant_Code, Merchant_Url, User_DOB,@Plan as [Plan],    
          @ExpiryDate as ExpiryDate,@Country as Country,CompnayName,DOE  from User_Detail(nolock)                  
          WHERE user_login=@Mobile and User_ID=@User_ID                         
    
          update User_Detail set  OnlineStatus=1,DeviceID=@DeviceID,Version=@Version     
          WHERE user_login=@Mobile and Pwd=@Pwd     
         end                              
       else                              
        begin                              
         select 'False' as QueryStatus ,'Mobile and Password does not Match' as UserMessage                              
        end                          
      END                               
     ELSE                              
      begin                               
       SELECT  'False' as QueryStatus ,'Mobile No  does not Exist' as UserMessage                                
      end                      
    end                    
   END                            
 ELSE                              
  BEGIN                              
   Select 'False' as QueryStatus ,'Plz Enter Mobile no and password' as UserMessage                             
  END                    
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_UserLogin2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- =============================================                    
-- Author:  <vinay kumar upadhyay,chandra prakash singh, Ratna Kumari>                    
-- Create date: <19 march 2015>                    
-- Description: <This  Sp used To login User>                    
-- =============================================                    
CREATE   PROCEDURE [dbo].[USP_UserLogin2] --'9911430178','35026','a','2.gf'              
@Mobile varchar(20),                    
@Pwd varchar(20), 
@DeviceID varchar(20),  
@Version  varchar(20)                                     
AS                    
 BEGIN                    
  set nocount on;                     
  IF((@Mobile<>'')AND(@Pwd<>''))                     
   BEGIN          
    declare @OnlineStatus int        
    select @OnlineStatus=OnlineStatus from DBO.User_Detail(NOLOCK) WHERE user_login=@Mobile
    if (@OnlineStatus=1)        
     BEGIN        
      SELECT 'Already Loggedin'         
     END        
    ELSE        
     BEGIN        
      IF  EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE user_login=@Mobile)                     
      BEGIN                      
       declare @PASSWORD varchar(20);                         
       select @PASSWORD=Pwd from User_Detail WHERE user_login=@Mobile                    
       if(@PASSWORD=@Pwd)                    
        begin                 
        declare @merchant_User_ID varchar(30);              
        select @merchant_User_ID = merchant_code from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd   --                 
        
        
  declare @Currency varchar(30);              
        select @Currency =[Currency] FROM [KITEVER].[dbo].[M_Country] where [CountryCode]=(select CountryCode from user_detail(nolock) where user_login=@Mobile and  Pwd=@Pwd)   --                 
        
        declare @merchant_code varchar(30);              
        select @merchant_code = merchant_code from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd       --                 
        
        declare @merchant_name varchar(30);              
        select @merchant_name = CompnayName from User_Detail WHERE user_id=@merchant_code                    --              
        
        declare @merchant_website varchar(30);              
        select @merchant_website = Merchant_Url from User_Detail WHERE user_id=@merchant_code        --              
        
        declare @User_ID int;                   
        select @User_ID = User_ID from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd                       
        update User_Detail set Status=1 where user_login=@Mobile  and User_ID= @User_ID                    
        
        declare @ProfilePicturePath varchar(100),@MerchantProfilePicturePath varchar(100);                
        select @ProfilePicturePath = isnull(ProfilePicturePath,'') from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd                     
        --if(@ProfilePicturePath='')                
        --begin                
        select @MerchantProfilePicturePath = isnull(ProfilePicturePath,'') from User_Detail WHERE user_id=@merchant_code           
        --end                 
            
        select @merchant_User_ID as MerchantUserID, @merchant_name as MerchantName, @merchant_website as MerchantWebsite         
        ,@ProfilePicturePath as ProfilePicturePath,@MerchantProfilePicturePath as MerchantProfilePicturePath, User_ID,Pwd,CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20))         
        as Mobile,Status,'Login Successful' as Msg, UserType, user_login, Userfilter,@Currency as Currency,UserCategory from User_Detail(nolock)        
        WHERE user_login=@Mobile and User_ID=@User_ID               
                
        update User_Detail set  OnlineStatus=1,DeviceID=@DeviceID,Version=@Version WHERE user_login=@Mobile and Pwd=@Pwd           
                 
        end                    
        else                    
        begin                    
        select 'Mobile and Password does not Match' as Error                    
        end                
        end                     
        else                    
        begin                     
        SELECT  'Mobile No  does not Exist' as Error                    
        end            
        end          
        END                  
        else                    
        begin                    
        Select 'Plz Enter Mobile no and password' as Error                    
        end          
 END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_UserLoginPermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
    
CREATE   PROCEDURE [dbo].[Usp_UserLoginPermission]     
@id bigint =0,    
@Device nvarchar(max) = null,    
@IpAddress nvarchar(max) = null,    
@UserCsv nvarchar(max) =null,    
@isactive bit=null,    
@userid bigint=null,     
@sequencejson nvarchar(max)=null,    
@mode varchar(15)    
as    
begin      
 declare @Activity_type nvarchar(20), @ActionType char(1) ,@RowJson nvarchar(max)     
    
 Declare @parentid bigint= (Select ParentId from User_Detail (NOLOCK) where User_ID=@userid)    
 Declare @sequence int = (select ISNULL( max(Sequence),0) +1 from Tbl_userLoginPermission where Parentid=@parentid)    
    
 if @mode= 'insert'    
 begin    
  if @Device IS NOT NULL AND @IpAddress IS NOT NULL AND @UserCsv IS NOT NULL    
  begin    
   IF  @id<>0    
   begin     
    Update Tbl_userLoginPermission  set Device=@Device,IpAddress=@IpAddress,UserCsv = @UserCsv where id=@id     
        
    Select 'Permission Updated'     
        
    set @Activity_type ='Updt_usrlgnperm'    
    set @ActionType='U'    
    Set @RowJson =(SELECT * FROM Tbl_userLoginPermission WHERE ID = @id FOR JSON AUTO, INCLUDE_NULL_VALUES )     
   end    
   else     
   begin    
    Insert into Tbl_userLoginPermission (Device,IpAddress,UserCsv,Sequence,Parentid,CreatedOn,Isactive)     
    values(@Device,@IpAddress,@UserCsv,@sequence,@parentid,GETDATE(),1)    
    set @id= SCOPE_IDENTITY()    
    Select 'Permission Saved'    
    
    set @Activity_type ='Inst_usrlgnperm'    
    set @ActionType='I'    
    Set @RowJson =(SELECT * FROM Tbl_userLoginPermission WHERE ID = @id FOR JSON AUTO, INCLUDE_NULL_VALUES )     
   end    
  end    
 end    
 else if @mode='updtsqnce'    
 begin    
  drop table if exists #temp    
  select * into #temp from openjson(@sequencejson) with(    
   permissionID nvarchar(max),    
   Sequence nvarchar(max) )     
    
   Update ulp     
   set ulp.Sequence=tm.Sequence    
   from Tbl_userLoginPermission ulp join #temp tm on ulp.ID=tm.permissionID     
    
   Select 'Sequence Updated'    
   set @Activity_type ='Updt_usrlgnpermseqnce'    
    set @ActionType='U'    
    Set @RowJson =(SELECT * FROM Tbl_userLoginPermission WHERE ParentId = @parentid FOR JSON AUTO, INCLUDE_NULL_VALUES )     
 end    
 else if @mode= 'select'    
 begin     
  Select ID, Device, IpAddress ,
	Case UserCsv when 'All' then UserCsv 
	Else (select STRING_AGG( ud.User_login+' ('+ud.FName+' '+ud.LName +')',', ') from fn_Split(UserCsv,',') fn join user_detail ud on cast( ud.user_id as varchar) = fn.value) END UserCsv, Sequence,    
  Parentid, CreatedOn, Isactive    
  from Tbl_userLoginPermission    
  where Parentid= @parentid and Device IS NOT NULL    
  Order by Sequence     
    
  set @Activity_type ='View_usrlgnperm'    
    set @ActionType='S'    
    Set @RowJson =''    
    
 end    
 else if @mode= 'delete'    
 begin     
  set @Activity_type ='Delt_usrlgnperm'    
    set @ActionType='D'    
    Set @RowJson =(SELECT * FROM Tbl_userLoginPermission WHERE ID = @id FOR JSON AUTO, INCLUDE_NULL_VALUES )    
  delete from Tbl_userLoginPermission where ID= @id     
    
  Select 'Permission Deleted'    
 end    
 else if @mode= 'edit'    
 begin    
  Select ID, Device, IpAddress , UserCsv , Sequence, Parentid, CreatedOn, Isactive    
  from Tbl_userLoginPermission    
  where id= @id    
 end     
 else if @mode= 'togglestatus'    
 begin    
     
  Update Tbl_userLoginPermission  set Isactive=@isactive where ID=@id     
  Select case @isactive when 1 then 'Permission Status Changed to Active' else 'Permission Status Changed to Inactive' end     
      
  set @Activity_type ='Updt_usrlgnpermtglsts'    
    set @ActionType='U'    
    Set @RowJson =(SELECT * FROM Tbl_userLoginPermission WHERE ID = @id FOR JSON AUTO, INCLUDE_NULL_VALUES )    
 end    
    
 drop table if exists #temp    
    
 IF @Rowjson IS NOT NULL     
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
  ,@Activity_type = 'Inst_Sms_enqry'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'Tbl_userLoginPermission'        
 END    
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_userlookup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_userlookup @Parent_id BIGINT = 0
	,@User_id BIGINT
	,@IsImpersonation BIT = 0
	,@ImpersonatorId BIGINT = 0
	,@mac_address VARCHAR(100) = ''
	,@ip_adress VARCHAR(100) = ''
	,@device_id VARCHAR(500) = ''
	,@platform VARCHAR(10) = ''
	,@token VARCHAR(max) = ''
	,@mode VARCHAR(10) = ''
AS
BEGIN
	DECLARE @Activity_type VARCHAR(max)
		,@ActionType VARCHAR(1)

	IF @mode = 'login'
	BEGIN
		IF @User_id <> 0
		BEGIN
		--------------Changed by rajneesh 12122022
			IF EXISTS (
					SELECT 1
					FROM tbl_loginlookup tl
					WHERE tl.User_id = @User_id
						AND Last_Activity < DATEADD(HOUR, - 12, GETDATE())
					)
			BEGIN
				DELETE
				FROM tbl_loginlookup
				WHERE User_id = @User_id
					AND ip_adress = @ip_adress
					AND Last_Activity < DATEADD(HOUR, - 12, GETDATE())

				DELETE
				FROM tbl_loginlookup
				WHERE User_id = @User_id
					AND ip_adress <> @ip_adress
					AND Last_Activity < DATEADD(HOUR, - 12, GETDATE())

				EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
					,@Activity_type = 'frc_lgout'
					,@ActionType = ''
					,@RowJson = ''
					,@Table_name = ''
			END

			IF  EXISTS (
					SELECT 1
					FROM tbl_loginlookup
					WHERE user_id = @User_id
					and IsImpersonation=@IsImpersonation
					and user_id not in (39832, 32222, 34594, 33819, 37540,335)
					and @IsImpersonation=0
					)
			BEGIN
			Delete from tbl_loginlookup where User_id=@User_id and IsImpersonation=@IsImpersonation
			END
				INSERT INTO tbl_loginlookup (
					Parent_id
					,sp_id
					,User_id
					,IsImpersonation
					,ImpersonatorId
					,mac_address
					,ip_adress
					,device_id
					,platform
					,token
					)
				VALUES (
					@Parent_id
					,@@SPID
					,@User_id
					,@IsImpersonation
					,@ImpersonatorId
					,@mac_address
					,@ip_adress
					,@device_id
					,@platform
					,@token
					)

				SET @Activity_type = 'View_lgin'
				SET @ActionType = 'I'

				SELECT @@spid

				EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
					,@Activity_type = @Activity_type
					,@ActionType = @ActionType
					,@RowJson = ''
					,@Table_name = 'tbl_loginlookup'
		
			
		END
	END
	ELSE IF @mode = 'logout'
	BEGIN
		SET @Activity_type = 'View_lgout'
		SET @ActionType = 'D'

		IF @@spid <> (
				SELECT tl.sp_id
				FROM tbl_loginlookup tl
				WHERE tl.User_id = @User_id
					AND tl.token = @token
				)
		BEGIN
			UPDATE tbl_loginlookup
			SET sp_id = @@spid
			WHERE User_id = @User_id
				AND token = @token
		END

		EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
			,@Activity_type = @Activity_type
			,@ActionType = @ActionType
			,@RowJson = ''
			,@Table_name = 'tbl_loginlookup'

		IF @IsImpersonation = 1
		BEGIN
			DELETE
			FROM tbl_loginlookup
			WHERE User_id = @User_id
				AND IsImpersonation = @IsImpersonation
				--AND mac_address = @mac_address            
				AND device_id = @device_id
				AND token = @token
		END
		ELSE
		BEGIN
			DELETE
			FROM tbl_loginlookup
			WHERE User_id = @User_id
				-- AND mac_address = @mac_address            
				AND device_id = @device_id
				AND token = @token
		END
	END
END



GO

