/* ============================================================
   Procedure: [dbo].[usp_UserMenuByModuleCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_UserMenuByModuleCode]
(
    @UserID BIGINT,
    @ParentModuleId NVARCHAR(MAX) = N''
)
AS
BEGIN

    --DECLARE 
    --    @UserID BIGINT = 34594,
    --    @ParentModuleId NVARCHAR(MAX) = N'110,407'
  
   --Declare @UserID bigint = 47894
   DECLARE @DomainURL NVARCHAR(500) = ''
   SELECT @DomainURL = [dbo].[fn_userdomain](@UserID)
      	     
             
  Declare @IsSiteOwner bit = 0                 
  Declare @ParentId bigint = 0                 
  Declare @IsAdmin int = 0                 
  Declare @IsInternal bit = 0                 
  Declare @ScopeCode varchar(10) = ''                 
  Declare @M_ID bigint = 0                
  Declare @IsClassic bigint = 0                
  Declare @IsExpired bit = 0                
   --47866 --34081  
    DECLARE @HiddenModules VARCHAR(100)

  --IF @UserID IN (32222,34594)
  --    SET @HiddenModules = '296, 297, 299, 300,379,380,390,391'

  --ELSE
  --    SET @HiddenModules = '296, 297, 299, 300,379,380,390,391'
 

  Declare @RoleCode varchar(10) = ''   
  
 declare @mid bigint,@partner_userid bigint,@displayname nvarchar(1000),@r_id bigint,@partner_type int,@type int

    



  select @IsAdmin = isnull(IsAdmin, 0), @ParentId = isnull(ud.ParentId, 0), @M_ID = isnull(M_ID, 0),@mid=m_id,@type=type from User_Detail(nolock) ud where ud.USER_ID = @UserID     
  
  select @partner_type= partner_type,@partner_userid=user_id from reseller_detail(nolock) where reseller_id=@mid

if @mid=10001 or @userid=335
begin
select @displayname='Kit19'
end
else if @partner_type in (2,3) and @type in (0) --Silver and Gold (white labelled partner)
begin
select @r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
select @displayname=JSON_VALUE(jsonMobileData, '$.DisplayNmae')  from tbl_pt_CustomizationMetadata(nolock) where userid=@partner_userid
select @displayname=coalesce(@displayname,CompnayName,'CRM') from user_detail(nolock) where user_id=@partner_userid
end
else if @partner_type in (2,3) or @type=3 or @UserId=335 
begin
select @r_id=reseller_id,@partner_userid=user_id from reseller_detail(nolock) where user_ID=@UserId
select @displayname=JSON_VALUE(jsonMobileData, '$.DisplayNmae')  from tbl_pt_CustomizationMetadata(nolock) where userid=@partner_userid
select @displayname=coalesce(@displayname,CompnayName,'CRM')  from user_detail(nolock) where user_id=@partner_userid
end
else if  @partner_type=1--Bronze (Non white labelled partner)
begin
select @mid=m_id from user_detail(nolock) where user_id=@partner_userid
--Partner_userid and @r_id will be the reseller_id of the immediate white labelled partner above bronze partner whose branding will apply
select @partner_userid=user_id ,@r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
select @displayname=JSON_VALUE(jsonMobileData, '$.DisplayNmae')  from tbl_pt_CustomizationMetadata(nolock) where userid=@partner_userid
select @displayname=coalesce(@displayname,CompnayName,'CRM')  from user_detail(nolock) where user_id=@partner_userid
end
else if  isnull(@partner_type,0)=0
begin
select @r_id=10043,@partner_userid=335 from reseller_detail(nolock) where user_ID=@UserId
select @displayname=JSON_VALUE(jsonMobileData, '$.DisplayNmae')  from tbl_pt_CustomizationMetadata(nolock) where userid=@partner_userid

select @displayname=coalesce(@displayname,CompnayName,'CRM') from user_detail(nolock) where user_id=@partner_userid


end


                
  select @IsInternal = isnull(sysrole.IsInternal,0) from User_Detail(nolock) ud                 
  inner join TBL_UA_UserRoleMappingMaster(nolock) turmm on turmm.UserId = ud.User_Id                 
  inner join VW_SystemRole_RoleMaster sysrole on sysrole.RoleCode = turmm.RoleCode                 
   where ud.USER_ID = @UserID                 
             
     print 'isInternal ' + cast(@isInternal as nvarchar);  
	   
 if(@M_ID = '10043' or @M_ID = '10001')                
   Begin                
   set @IsClassic = 0                
   End                
   else                 
   Begin                
   set @IsClassic = 0                
   End  
 set @IsExpired =  isnull((select top 1 0 from Price_UserSubscriptionDetails(nolock) where Userid = @ParentID and                 
 Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate), 1)            
          
 select top 1 @ScopeCode = turpm.ScopeCode, @RoleCode =turpm.RoleCode  
 from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm  
 on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm  
 on turpm.RoleCode = urmp.RoleCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm  
 on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm  
 on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod  
 on umod.ModuleCode = turpm.ModuleCode  
 where urmp.UserId = @UserId or utumm.UserId = @UserId and isnull(umod.Active,0) = 1  
 AND  ( umod.ModuleId IN (SELECT value FROM STRING_SPLIT(@ParentModuleId, ','))
