/* ============================================================
   Procedure: [dbo].[Usp_userproductcouponsettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_userproductcouponsettings] --24307                 
 @ParentID BIGINT                      
AS                      
BEGIN              
               
 DECLARE @couponId bigint                              
                     
 SELECT TOP 1 @couponId = couponId                    
 FROM   usercouponsettings1 WITH (NOLOCK)                    
 WHERE  ParentID = @ParentID           
 order by couponId desc                   
                     
 SELECT   (                      
    '<p><b>Coupon Code : </b>' + ISNULL(ucs.CouponName,'') + '</p>' +                      
    CASE                       
      WHEN ISNULL(nullif(ucs.coupondescription,''), '') <> '' THEN                       
        '<p><b>Coupon Description : </b>' + ISNULL(ucs.coupondescription, '')                       
        + '</p>'                      
        else ''                    
    END                      
                        
         )      AS Coupons,            
          (                      
           CASE WHEN ucs.ISProductApplicability=1 then  '<p><b>Products: </b>' +                      
                                    
                           (                      
                               select 'Product Applicability: ' + (SELECT  'Product :' + prdmaster.Name,' (Min Value :' + CAST(prd.MinQty AS VARCHAR(50))            
                                         + ', Max Value :' + CAST(prd.MaxQty AS VARCHAR(50))                       
                                                 + '), '              
FROM   usercouponsettings1 upc INNER JOIN                
                                          productapplicability prd ON upc.CouponID = prd.CouponID             
                                          inner join productmaster prdmaster            
                                          ON prd.ProductId = prdmaster.ProductID and upc.CouponID=@couponId and prd.ParentID=@ParentID
                                           and upc.CouponID=prd.CouponID    --where upc.CouponID=1            
                                       --   ON prd.ProductId = prdmaster.ProductID and upc.CouponID=prd.CouponID and prd.ParentID=@ParentID    --where upc.CouponID=1            
                                         -- ORDER BY 1, 2            
                                          FOR XML PATH('')            
        )            
                                      
            )                      
         + '</p>' ELSE '<b>No Product Applicability</b>' end)  AS Products,(CASE WHEN ucs.ISSearchApplicability = 1  or ucs.IsBillApplicability=1 then                  
   CASE WHEN ucs.ISSearchApplicability = 1 THEN                       
                   '<p><u><b>Search Applicability : </b></u></p><p><b>Include :</b>' + ISNULL(                      
                       (                      
                           SELECT STUFF(                      
                                      (                      
                                          SELECT N', ' + usl.searchname                      
                                          FROM   usersearchlist AS usl with(nolock)                     
                                                 OUTER APPLY dbo.Fn_split(ucs.IncludeSearches, '#') AS                       
                                          fs                      
                                          WHERE  usl.id = fs.[value] FOR XML                       
                                                 PATH(''),                      
                                                 TYPE                      
                                      ) .value('text()[1]', 'nvarchar(max)'),                      
                                      1,                      
                                      2,                      
                                      N''                      
                                  )                      
                       ),                      
      ''                      
                   )                      
                   + '</p><p><b>Exclude :</b>' + ISNULL(                      
                       (                      
    SELECT STUFF(                      
                (                      
                              SELECT N', ' + usl.searchname                      
                                          FROM   usersearchlist AS usl with(nolock)                     
                                                 OUTER APPLY dbo.Fn_split(ucs.ExcludeSearch, '#') AS                       
                                          fs                      
                                          WHERE  usl.id = fs.[value] FOR XML                       
                                                 PATH(''),                      
                                                 TYPE                      
                                      ) .value('text()[1]', 'nvarchar(max)'),                      
                                      1,                      
                                      2,                      
                                      N''               
                                  )                      
                       ),                      
                       ''                      
                   )                      
                   + '</p>'                      
              ELSE ''                      
         END       
                            
             + '</p>'              
          ELSE '                
<b>                
No Segment Applicability</b>                
' end  ) AS          Segments,                      
        '' AS                  SearchValue,            
                       
             ('<p><b>Status : </b>' + (Case WHEN (ucs.Status=1)  THEN 'Active'              
         ELSE 'Inactive'              
      END ) +                       
            '</p>') as Status ,            
        
       --ucs.CreatedDate,                      
        dbo.[fn_getusertimefromindiantime](ucs.parentid,ucs.CreatedDate) as CreatedDate,
        
        ucs.CouponID,
        
        Convert(varchar(10),CONVERT(date,dbo.[fn_getusertimefromindiantime](ucs.parentid,StartDate),106),103) StartDate,
        
        Convert(varchar(10),CONVERT(date,dbo.[fn_getusertimefromindiantime](ucs.parentid,ExpiryDate),106),103) ExpiryDate
        
                             
 FROM   usercouponsettings1  AS ucs with(nolock)                      
 WHERE  ucs.parentid = @ParentID   and ExpiryDate>=GETDATE()                 
 ORDER BY                      
        ucs.CreatedDate DESC                      
END        
      



GO

