CREATE   PROCEDURE [dbo].[USP_Usersendsms]   --    'mtixt',anything19,17626,SMSSMS,28              
@Mobile varchar(50),                
@Pwd varchar(20),            
@userid bigint ,            
@senderid varchar(100),            
@tempid bigint                
AS                
BEGIN                
set nocount on;                 
IF((@Mobile<>'')AND(@Pwd<>''))                 
BEGIN                      
IF  EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE User_ID=@userid)                 
BEGIN                  
declare @PASSWORD varchar(20)                     
select @PASSWORD=Pwd from User_Detail WHERE User_ID=@userid               
if(@PASSWORD=@Pwd)                
begin                
declare @stat char(5)                
select @stat=Status from User_Detail WHERE user_login=@Mobile and  Pwd=@Pwd                
if(@stat=1)            
begin 
select Template,template_id as Msg from Template_Detail WHERE Template_ID=@tempid            
end             
else            
begin            
select 'User Not Login' as Msg               
end              
end                
else                
begin                
select 'Mobile and Password does not Match' as Msg                
end                 
end                 
else                
begin                 
SELECT  'MobileNo  does not Exist' as Msg                
end                
end                
                
else                
begin                
Select 'Plz Enter Mobile no and password' as Msg                
end                
end                
            
                
