	union
	select count(user_id),userfilter,1,'I','Resellers' from user_detail (nolock) where type=1 and status = 0 and m_id=10043 group by userfilter
	union
	select count(user_id),userfilter,0,'I','Resellers' from user_detail (nolock) where type=1 and status = 0 and m_id<>10043 group by userfilter
	union
    select count(user_id),userfilter,1,'A','Subresellers' from user_detail (nolock) where type=2 and status = 1 and m_id=10043 group by userfilter
	union
	select count(user_id),userfilter,0,'A','Subresellers' from user_detail (nolock) where type=2 and status = 1 and m_id<>10043 group by userfilter
