   Procedure: [dbo].[Usp_ValidateCreditAgent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_ValidateCreditAgent @username VARCHAR(MAX)      
 ,@Pass VARCHAR(MAX)      
AS      
BEGIN      
 IF EXISTS (      
   SELECT 1      
   FROM CreditAgent as ca with(nolock)     
   WHERE ca.UserName = @username      
    AND ca.Password = @Pass and IsActive=1     
   )      
 BEGIN      
  SELECT 'Valid'      
 END      
 ELSE      
 BEGIN      
  SELECT 'InValid'      
 END      
END 


GO

