CREATE   PROCEDURE dbo.usp_ValidateGUID    
(    
 @GUID nvarchar(200)    
)    
as    
Begin    
     Declare @UserID bigint = 0    
     if(exists(select 'x' from User_Detail where resetguid = @GUID))    
     Begin    
     select @UserID = USER_ID from User_Detail where resetguid = @GUID    
     if(exists(select 'x' from User_Detail where USER_ID = @UserID and resetexpired = 1 ))    
                begin    
                    select 'Expired'    
                End    
     else    
                Begin    
                    select 'Valid'    
                End       
     End    
     else    
     Begin    
            select 'NotExists'    
     End      
           
End


