/* ============================================================
   Procedure: [dbo].[Usp_ValidateUserLoginPermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Usp_ValidateUserLoginPermission @username=N'abhi01',@ipaddress=N'::1',@logindevice=N'Desktop',@isimpersonator=0            
CREATE   PROCEDURE [dbo].[Usp_ValidateUserLoginPermission]           
(          
  @username NVARCHAR(max)          
 ,@ipaddress NVARCHAR(max)                
 ,@logindevice NVARCHAR(max)                
 ,@isimpersonator bit                
)          
AS                
BEGIN                
 -- declare @username NVARCHAR(max) ='34594-user1' ,@ipaddress NVARCHAR(max)='182.75.38.28'  ,@logindevice NVARCHAR(max)= 'Desktop',  @isimpersonator bit =0              
  DECLARE @check INT = 1          
  /* Whenever there is DML operation in tbl_UA_ModuleMaster then increment @MenuVersion variable */          
  declare @MenuVersion int=6            
 IF @isimpersonator = 0                 
 BEGIN                
  DECLARE @parentId BIGINT,@userid bigint                
                
    SELECT @parentId= parentid ,@userid=User_ID                
    FROM User_Detail   (NOLOCK)             
    WHERE User_login = @username --and isverify = 1               
                    
                   
  DROP TABLE IF EXISTS #temp                
                
   SELECT ROW_NUMBER() OVER (ORDER BY sequence) row_no, * INTO #temp                
   FROM Tbl_userLoginPermission    (NOLOCK)            
   WHERE parentid = @parentId                
    AND isactive = 1                
    AND Device IS NOT NULL                
                
  DECLARE @max INT                
   ,@min INT                
   ,@Devices NVARCHAR(max)                
   ,@ipaddresses NVARCHAR(max)                
   ,@usercsv NVARCHAR(max)                
                   
                
  SELECT @min = min(row_no)                
   ,@max = max(row_no)                
  FROM #temp                
                
  --select * from #temp                
                
  WHILE @min <= @max                
  BEGIN                
   SELECT @Devices = Device, @ipaddresses = IpAddress, @usercsv = UserCsv                
   FROM #temp                
   WHERE row_no = @min                
                
   --select @Devices  , @ipaddresses , @usercsv                
                
   IF EXISTS (SELECT 1 FROM fn_split(@usercsv, ',') WHERE value = cast(@userid as nvarchar))                
   BEGIN              
   --select 'user'            
    IF EXISTS (SELECT 1 FROM fn_split(@Devices, ',') WHERE trim(value) = @logindevice)                
    BEGIN                
     IF EXISTS (SELECT 1 FROM fn_split(@ipaddresses, ',') WHERE trim(value) = @ipaddress)                
     BEGIN                 
      --select 'ip address check for ' + @logindevice                
      SET @check = 1                
      Set @min=@max+1                
     END                
     ELSE IF @ipaddresses = 'All'                
     BEGIN                
                      
      --select 'ip address check All for ' + @logindevice                
      SET @check = 1                
      Set @min=@max+1                
     END                
     ELSE                
     BEGIN                
                     
      --select 'ip address check fail for ' + @logindevice                
      SET @check = 0                
     END                
    END                
    ELSE IF @Devices = 'All'                
    BEGIN                
     IF EXISTS (SELECT 1 FROM fn_split(@ipaddresses, ',') WHERE trim(value) = @ipaddress)                
     BEGIN                
                      
      --select 'ip address check for All device'                
      SET @check = 1                
      Set @min=@max +1               
     END                
     ELSE IF @ipaddresses = 'All'                
     BEGIN                
                     
      --select 'ip address check All for All device'                
      SET @check = 1                
      Set @min=@max    +1            
     END                
     ELSE                
     BEGIN                
                      
      --select 'ip address check fail for All device'                
      SET @check = 0                
     END                
                
     --SET @check = 1                
    END                
    ELSE                
    BEGIN                                   
      select 'fail for '+@logindevice                
     SET @check = 0                
    END                 
   END                
   ELSE IF @usercsv='All'                
   BEGIN                
    IF EXISTS (SELECT 1 FROM fn_split(@Devices, ',') WHERE trim(value) = @logindevice)                
    BEGIN                
     IF EXISTS (SELECT 1 FROM fn_split(@ipaddresses, ',') WHERE trim(value) = @ipaddress)                
     BEGIN                 
      --select 'ip address check for ' + @logindevice                
      SET @check = 1                
      Set @min=@max+1                
     END                
     ELSE IF @ipaddresses = 'All'                
     BEGIN                
                      
      --select 'ip address check All for ' + @logindevice                
      SET @check = 1                
      Set @min=@max    +1            
     END                
     ELSE                
     BEGIN                
                     
      --select 'ip address check fail for ' + @logindevice                
      SET @check = 0                
     END                
    END                
    ELSE IF @Devices = 'All'                
    BEGIN                
     IF EXISTS (SELECT 1 FROM fn_split(@ipaddresses, ',') WHERE trim(value) = @ipaddress)                
     BEGIN                  
      SET @check = 1                
    --select 'ip address check for All device for all users' , @check            
      Set @min=@max   +1            
     END                
     ELSE IF @ipaddresses = 'All'                
     BEGIN                
                     
                 
      SET @check = 1                
    --select 'ip address check All for All device for all users' ,@check               
      Set @min=@max +1            
     END                
     ELSE                
     BEGIN                
                  
      SET @check = 0                
   ----select 'ip address check fail for All device'    , @check            
     END                
                
    END                
    ELSE                
    BEGIN                
                     
      --select 'fail for '+@logindevice                
     SET @check = 0                
    END                 
   END                
                  
                
   SET @min = @min + 1                
  END                
 END                
 SELECT @check as [check], @MenuVersion as MenuVersion          
END 



