/* ============================================================
   Procedure: [dbo].[usp_vb_botcallend_twilio]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_botcallend_twilio]
    @CallSid NVARCHAR(100),
    @Duration INT,
    @CallStatus NVARCHAR(50),
    @RecordUrl NVARCHAR(500) = NULL,
	@callsummary nvarchar(4000) =null,
	@additional_details nvarchar(max)=null,@call_quality nvarchar(max)=null
AS
BEGIN
begin try
exec [usp_vb_botcallend_twilio_outbound] 
@CallSid,@Duration,@CallStatus,@RecordUrl,@callsummary,@additional_details,@call_quality
return;
end try
begin catch
exec usp_inserterrorinfo
end catch


    
    DECLARE @tid BIGINT

    -- Update TwilioCalls with recording URL
    UPDATE twilioCalls 
    SET call_end_time = GETDATE(),
        CallStatus = @CallStatus,
        CallDuration = @Duration,
        RecordUrl = ISNULL(@RecordUrl, RecordUrl)  -- Update only if provided
    WHERE CallSid = @CallSid
    
    SELECT @tid = SCOPE_IDENTITY()
      SELECT @tid = id from twilioCalls (nolock)   WHERE CallSid = @CallSid  
  
    -- Update call log
    DECLARE @calllogid BIGINT,@entityname varchar(20),@entityid bigint,@callerid nvarchar(20)
    SELECT @calllogid = id ,@entityid=customerentityid,@entityname=customerentity,@callerid=Customernumber
    FROM calllog(NOLOCK) 
    WHERE reftable = 'twiliocalls' AND refid = @tid
    
    IF @calllogid IS NOT NULL
    BEGIN
        EXEC usp_updatecalllog_withcalllogid @calllogid
		insert into call_summaries(calllog_id,entityname,entityid,call_summary,callerid,additional_details,
        call_quality)
		select @calllogid,@entityname,@entityid,@callsummary,@callerid,@additional_details,
        @call_quality
    END
END



