/* ============================================================
   Procedure: [dbo].[usp_vb_botcallend_twilio_deduction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_vb_botcallend_twilio_deduction
    @CallSid NVARCHAR(100)AS
BEGIN
    SET NOCOUNT ON;
    declare @Duration INT,
    @CallStatus NVARCHAR(50),
    @RecordUrl NVARCHAR(500) = NULL

    DECLARE @tid BIGINT,@direction varchar(20),@call_start_time datetime,@call_end_time datetime,@unitcost numeric(18,4),@cost numeric(18,4)
    ,@parentid bigint,@m_id bigint,@remarks nvarchar(2000),@campaign nvarchar(200),@toNumber nvarchar(20),
    @calllogid bigint,@campaignid bigint,@entityname varchar(20),@entityid bigint,@callerid nvarchar(20)

    select @Duration= bill_duration,@RecordUrl=recordurl,@tid = id From TwilioCalls(nolock) where CallSid=@callsid

    select top 1 @calllogid =id,@parentid=parentid,@campaignid=campaignid,@toNumber=Customernumber
    ,@entityid=customerentityid,@entityname=customerentity,@callerid=Customernumber
    from CallLog(nolock) where callsid=@callsid order by id desc
    select @campaign=campaign_name from voice_bot_campaigns(nolock) where id=@campaignid
    --,@duration int
    select @m_id=m_id from user_Detail(nolock) where user_id=@parentid
    if @Duration>0--@CallStatus='completed'
    begin
    select top 1 @unitcost=priceperunit from Price_Base_AICredits_Rate(nolock) where type='VoiceBot' and 
    parentid in (@parentid,0)
    order by parentid desc
    select @cost=ceiling(@duration/cast(60 as float))*@unitcost
    select @remarks=concat('Amount deducted against Voicebot call to Number ',@toNumber, ' called under campaign name ',@campaign, ', Call_logid: ',@calllogid)
  
    exec [dbo].[usp_remote_deduct_or_refund_int_bal] @parentid,@m_id,0,@cost,23,@remarks
    end
    END



