/* ============================================================
   Procedure: [dbo].[usp_vb_calllog_exists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_calllog_exists] --'h3.03-1766734847.180','+917965092405','+917840002738'  
@callsid nvarchar(100),@fromnumber nvarchar(20)=null,@tonumber nvarchar(20) null 
as  
begin  
declare @recordedcallsid nvarchar(100),@telephony_provider varchar(50),@direction nvarchar(20),@dnid nvarchar(20)  
if @fromnumber is not null and @tonumber is not null
begin
select @fromnumber=replace(@fromnumber,'+',''),@tonumber=replace(@tonumber,'+','')  
end
select top 1 @recordedcallsid=callsid,@direction=direction,@dnid=dnid from TwilioCalls(nolock)   
where --StreamStatus='ready' and   
call_end_time is null and  
call_start_time >=dateadd(mi,-2,getdate()) and   
(@callsid=callsid or   
1=
case when direction='inbound' and   
(dnid =right(rtrim(@tonumber),len(dnid)))   
and (callerid = right(rtrim(@fromnumber),len(callerid)))  
then 1  
when direction='outbound' and  
(callerid =right(rtrim(@tonumber),len(dnid)))   
and (dnid = right(rtrim(@fromnumber),len(callerid))) 
then 1  
else 0 end)
order by id desc  
  
select @dnid=replace(@dnid,'+','')  
if @dnid like '91%' and len(@dnid)>10  
begin  
select @dnid=mobile from dbo.fn_separatecountrycodeandmobile(@dnid)  
end  
if @dnid is not null  
begin  
select @telephony_provider=dbo.fn_getsipname(@dnid)  
end  

if @telephony_provider='Jio'
begin
select @telephony_provider='VCON',@recordedcallsid=null,@direction=null
end
  
select @recordedcallsid as callsid,@direction as direction,isnull(@telephony_provider,'VCon') as telephony_provider   
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_connect_and_load_outbound]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_connect_and_load_outbound]
@callsid nvarchar(100),@fromnumber nvarchar(20)=null,@tonumber nvarchar(20) null,@StreamSid NVARCHAR(100)
as
begin
declare @recordedcallsid nvarchar(100),@telephony_provider varchar(50),@direction nvarchar(20),@dnid nvarchar(20),
@TwilioCallsId bigint

if @fromnumber is not null and @tonumber is not null
begin
select @fromnumber=replace(@fromnumber,'+',''),@tonumber=replace(@tonumber,'+','')  
end

select top 1 @recordedcallsid=callsid,@direction=direction,@dnid=dnid,@TwilioCallsId=id from TwilioCalls(nolock)   
where --StreamStatus='ready' and   
call_end_time is null and  
call_start_time >=dateadd(mi,-2,getdate()) and   
(@callsid=callsid or   
1=
case when direction='inbound' and   
(dnid =right(rtrim(@tonumber),len(dnid)))   
and (callerid = right(rtrim(@fromnumber),len(callerid)))  
then 1  
when direction='outbound' and  
(callerid =right(rtrim(@tonumber),len(dnid)))   
and (dnid = right(rtrim(@fromnumber),len(callerid))) 
then 1  
else 0 end)
order by id desc  
  
select @dnid=replace(@dnid,'+','')  
if @dnid like '91%' and len(@dnid)>10  
begin  
select @dnid=mobile from dbo.fn_separatecountrycodeandmobile(@dnid)  
end  
if @dnid is not null  
begin  
select @telephony_provider=dbo.fn_getsipname(@dnid)  
end  

if @telephony_provider='Jio'
begin
select @telephony_provider='VCON',@recordedcallsid=null,@direction=null
return;
end
  
--select @recordedcallsid as callsid,@direction as direction,isnull(@telephony_provider,'VCon') as telephony_provider  

UPDATE TwilioCalls 
    SET CallSid = @CallSid,
    StreamSid = @StreamSid,
        StreamStatus = 'Connected',
        call_last_update = GETDATE()
    WHERE id = @TwilioCallsId;
    
    -- Update CallLog with real CallSid
    UPDATE CallLog
    SET CallSid = @CallSid,
    StreamSid = @StreamSid,
        last_updated = GETDATE()
    WHERE reftable = 'twiliocalls'
      AND refid = @TwilioCallsId;

if @direction='outbound'
begin
--Exec usp_vb_get_active_stream_outbound @callsid
exec usp_vb_get_active_stream_outbound_opt @callsid
end
else if @direction='inbound'
begin
EXEC usp_vb_get_active_stream @callsid
end

end



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_generate_incoming_bot_call]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_vb_generate_incoming_bot_call
(@UniqueId nvarchar(50),@CallerId nvarchar(50), @Context nvarchar(50),@Channel nvarchar(50),@Dnid nvarchar(50),@Extension nvarchar(50),@call_logid bigint output,@botid bigint output,
    @parentid bigint output)
as
begin
declare @kitcallid bigint,@Channelid int,@calllogid bigint--,@parentid bigint
select @callerid=mobile from dbo.fn_separatecountrycodeandmobile(@CallerId)
select @Dnid=mobile from dbo.fn_separatecountrycodeandmobile(@Dnid)

select @botid=voice_bot_id,@parentid=parentid from Cloud_User_Phone(nolock) c where phoneno=@Dnid and exists(select 1 from voice_bot_details(nolock) where id=c.voice_bot_id
and isactive=1
)

select @botid=coalesce(@botid,0)

SELECT TOP 1 @Channelid=id FROM Kit19Channels WHERE ISNULL(channel_inuse, 'N') = 'N' ORDER BY ISNULL(channel_lastaccesstime, getdate()) DESC

INSERT INTO Kit19Calls(call_start_time, UniqueId,AccountCode, CallerId, CallerIdName, CallingAni2,CallingPres, CallingTns, CallingTon, Channel,
Context, Dnid, Enhanced, Extension, Language, Priority, RequestURL, channel_id,clientid)
VALUES(getdate(), @UniqueId, null, @CallerId, '', '','','','',@Channel,@Context,@Dnid,'False',
@Extension,'En',28,'',@ChannelId,@parentid)
SELECT @kitcallid=scope_identity()

drop table if exists #call_logid 
create table #call_logid(call_logid bigint)



insert into #call_logid(call_logid)
exec usp_createcalllog 'kit19calls','id',@kitcallid,'Incoming'
select top 1 @calllogid=call_logid from #call_logid
select @call_logid=@calllogid
select @botid as Botid,@call_logid as CallLogId,@parentid as Parentid
update calllog set bot_id =@botid where id=@calllogid

end



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_generate_incoming_bot_call_twilio]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_vb_generate_incoming_bot_call_twilio (
  @CallSId nvarchar(50), 
  @CallerId nvarchar(50), 
  @Streamsid nvarchar(50), 
  @Dnid nvarchar(50), 
  @AccountSid nvarchar(50), 
  @streamstatus nvarchar(50), 
  @call_logid bigint output, 
  @botid bigint output, 
  @parentid bigint output
) as 
begin 
declare @twiliocallid bigint, 
@calllogid bigint, 
@countrycode varchar(5), 
@telephonyprovider varchar(50) 
select 
  @Dnid = replace(
    dbo.fn_trim0prefix(@Dnid), 
    '+', 
    ''
  ) if @dnid like '91%' 
  and len(@dnid)> 10 begin 
select 
  @dnid = mobile 
from 
  dbo.fn_separatecountrycodeandmobile(@dnid) end if @dnid = '8037091588' 
select 
  @Dnid = '9513886363' 
select 
  @telephonyprovider = dbo.fn_getsipname(@Dnid) if @telephonyprovider = 'twilio' begin 
select 
  @countrycode = countrycode 
from 
  dbo.fn_separatecountrycodeandmobile(@CallerId) end else begin 
select 
  @countrycode = '+91' 
select 
  @callerid = replace(
    dbo.fn_trim0prefix(@callerid), 
    '+', 
    ''
  ) end 
  --select @Dnid=mobile from dbo.fn_separatecountrycodeandmobile(@Dnid)    
  select @botid=voice_bot_id,@parentid=parentid from Cloud_User_Phone(nolock) c where phoneno=replace(@Dnid,'+','') and exists(select 1 from voice_bot_details(nolock) where id=c.voice_bot_id  and isactive=1  )    select @botid=coalesce(@botid,0)      
  INSERT INTO TwilioCalls(botid,call_start_time, callsid,StreamSid, CallerId,countrycode, Dnid,parentid,AccountSid,StreamStatus,direction)  VALUES(@botid,getdate(), @CallSId, @streamsid, @CallerId,@countrycode,@dnid,@parentid,@AccountSid,@streamstatus,'inbound')  
  SELECT @twiliocallid=scope_identity()    
  drop table if exists #call_logid   
  create table #call_logid(call_logid bigint)        
  insert into #call_logid(call_logid)  
  exec usp_createcalllog 'twiliocalls','id',@twiliocallid,'Incoming'  select top 1 @calllogid=call_logid from #call_logid  select @call_logid=@calllogid  select @botid as Botid,@call_logid as CallLogId,@parentid as Parentid,@telephonyprovider as telephonyProvider,telephony_config from sip_telephony_providers(nolock)  where ph_sipname=@telephonyprovider  update calllog set bot_id =@botid where id=@calllogid
  end



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_generate_outgoing_bot_call_twilio]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--alter table calllog add campaignid bigint  --Go    
CREATE   PROCEDURE [dbo].[usp_vb_generate_outgoing_bot_call_twilio] (
  @CallSId nvarchar(50), 
  @ToNumber nvarchar(50), 
  @Streamsid nvarchar(50), 
  @Dnid nvarchar(50), 
  @AccountSid nvarchar(50), 
  @streamstatus nvarchar(50), 
  @parentid bigint, 
  @botid bigint, 
  @audienceid bigint, 
  @telephonyprovider varchar(50), 
  @campaignid bigINT = NULL
) as 
begin 
declare @twiliocallid bigint, 
@calllogid bigint, 
@countrycode varchar(5), 
@entity varchar(20), 
@entityid bigint, 
@callerid nvarchar(50), 
@call_logid bigint, 
@cost numeric(18, 4), 
@execution_id bigint 
select 
  @entity = entity, 
  @entityid = entityid, 
  @execution_id = execution_batchid 
from 
  voice_bot_campaign_audience(nolock) 
where 
  id = @audienceid 
select 
  top 1 @cost = priceperunit 
from 
  Price_Base_AICredits_Rate(nolock) 
where 
  Type = 'VoiceBot' 
  and ParentID in (@parentid, 0) 
order by 
  ParentID desc if dbo.GetAvailableBalanceForService(@parentid, 23)> @cost begin 
select 
  @callerid = @ToNumber 
select 
  @Dnid = replace(
    dbo.fn_trim0prefix(@Dnid), 
    '+', 
    ''
  ) if @dnid like '91%' 
  and len(@dnid)> 10 begin 
select 
  @dnid = mobile 
from 
  dbo.fn_separatecountrycodeandmobile(@dnid) end if @telephonyprovider = 'twilio' begin 
select 
  @countrycode = countrycode, 
  @callerid = mobile 
from 
  dbo.fn_separatecountrycodeandmobile(@CallerId) 
  --select @countrycode=countrycode from dbo.fn_separatecountrycodeandmobile(@CallerId)    
  end  
  else  
  begin  
  select @countrycode='+91'  
  select @callerid=replace(dbo.fn_trim0prefix(@callerid),'+','')  
  end        
  --select @Dnid=mobile from dbo.fn_separatecountrycodeandmobile(@Dnid)        
  INSERT INTO TwilioCalls(botid,call_start_time, callsid,StreamSid, CallerId,countrycode, Dnid,parentid,AccountSid,StreamStatus,direction)  
  VALUES(@botid,getdate(), @CallSId, @streamsid, @CallerId,@countrycode,@dnid,@parentid,@AccountSid,@streamstatus,'outbound')  
  SELECT @twiliocallid=scope_identity()    
  drop table if exists #call_logid   
  create table #call_logid(call_logid bigint)        
  insert into #call_logid(call_logid)  
  exec usp_createcalllog 'twiliocalls','id',@twiliocallid,'Outgoing'  
  select top 1 @calllogid=call_logid from #call_logid  
  select @calllogid as CallLogId  
  update calllog set bot_id =@botid,campaignid=@campaignid,audienceid=@audienceid where id=@calllogid  
  update voice_bot_campaign_audience set executed_on=getdate() where id=@audienceid  
  update v set executions_attempted=executions_attempted+1 from voice_bot_campaign_execution v where id=@execution_id    
  end  
  else   
  begin  
  update voice_bot_campaign_audience 
  set last_error='Omitted due to low balance',executed_on=getdate() 
  where id=@audienceid  
  end    
  end



