   Procedure: [dbo].[usp_vb_get_active_stream]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_get_active_stream] --'CA35b045454c864cd05323d2354ed1a234'
    @CallSid NVARCHAR(100)
AS
BEGIN
    SELECT 'inbound' AS Direction,
        c.id AS KitCallId,
        c.CallSid AS CallSid,
        c.StreamSid AS StreamSid,
        c.CallerId AS CallerId,
        c.Dnid AS ToNumber,
        cl.id AS CallLogId,
        cl.bot_id AS BotId,
        cl.parentid AS ParentId,
        vbs.sessionid AS BedrockSessionId,
        vbs.bot_sp AS BotSP,
		isnull(dbo.fn_getsipname(c.Dnid),'Twilio') AS TelephonyProvider , -- ? NEW FIELD
		telephony_config
    FROM twilioCalls c(NOLOCK)
    INNER JOIN calllog cl(NOLOCK) ON reftable='twiliocalls' and cl.refid = c.id
	left join sip_telephony_providers s (nolock) on s.ph_sipname=isnull(dbo.fn_getsipname(c.Dnid),'Twilio')
    LEFT JOIN voice_bot_sessions vbs(NOLOCK) 
        ON vbs.parentid = cl.parentid 
        AND vbs.callerid = c.CallerId
        AND vbs.isactive = 1
   
    WHERE c.CallSid = @CallSid
    AND c.call_end_time IS NULL
END



