CREATE   PROCEDURE [dbo].[usp_vb_get_active_stream_outbound] --'h3.03-1767271575.51'--'h3.03-1766744277.291'--'CA35b045454c864cd05323d2354ed1a234'
    @CallSid NVARCHAR(100)
AS
BEGIN
declare @campaign_settings nvarchar(max),@campaignid bigint,@audienceid bigint,@botid bigint
,@telephony_provider nvarchar(50),@entity nvarchar(50),@entityid bigint,@activeprompt nvarchar(max)
declare @bot_config nvarchar(max),@caller_context nvarchar(max),@outbound_context_json nvarchar(max)
declare @cd nvarchar(max)

if json_value(@campaign_settings,'$.segment_Type')<>'csv'
begin
select @entity =customerentity,@entityid=customerentityid from calllog(nolock) where callsid=@callsid
end

select @campaignid=campaignid,@audienceid=audienceid,@botid=bot_id
from calllog(nolock) where callsid=@callsid
--select @activeprompt=activeprompts from voice_bot_details (nolock) where id=@botid

select @campaign_settings=campaign_settings from voice_bot_campaigns(nolock) where id=@campaignid
-- ? No need to build @bot_config - we'll return individual columns from voice_bot_details
drop table if exists #entitydata 
create table #entitydata([key] nvarchar(200),[value] nvarchar(max),id int identity(1,1))

if isnull(@entity,'')=''
begin
select @caller_context=entity_context from voice_bot_campaign_audience(nolock) where id=@audienceid
select @cd=@caller_context

end
else
begin
select @cd=(select dbo.fn_getentityfullname('user',@entityid) as PersonName for json path,without_array_wrapper)
--select @caller_context=@cd
exec usp_replaceentityplaceholders_allfields_insert @entityid,@entity

select @caller_context=entitydetails from entity_details_transition(nolock) where entity=@entity and entityid=@entityid
select @caller_context=replace(@caller_context,'+','')
end
insert into #entitydata([key],[value])
select [key],[value] from openjson(@caller_context)
declare @c int,@id int=0
select @c=count(1) from #entitydata

while @c>0
begin
select @id=min(id) from #entitydata where id>@id
select @campaign_settings=replace(@campaign_settings,'{'+[key]+'}',[value])
--,@activeprompt=replace (@activeprompt,'{'+[key]+'}',[value])
from #entitydata where id=@id
set @c=@c-1
end
-- ? SIMPLIFIED: Return ALL individual columns - no JSON assembly
-- Let C# parse each JSON column separately
    SELECT 
    'outbound' AS Direction,
        c.id AS KitCallId,
        c.CallSid AS CallSid,
        c.StreamSid AS StreamSid,
        c.CallerId AS CallerId,
        c.Dnid AS ToNumber,
        cl.id AS CallLogId,
        cl.bot_id AS BotId,
        cl.parentid AS ParentId,
        vbs.sessionid AS BedrockSessionId,
        vbs.bot_sp AS BotSP,
		isnull(dbo.fn_getsipname(c.Dnid),'Twilio') AS TelephonyProvider,
		s.telephony_config, -- Telephony config (JSON string)
        @campaign_settings as campaign_settings, -- Campaign settings with placeholders replaced (JSON string)
        @cd as caller_context, -- Caller context (JSON string)
		-- Individual bot config fields from voice_bot_details
		vbd.VoiceConfig,
		vbd.LanguageConfig,
		vbd.HandoffRules,
        --@activeprompt as ActivePrompts,
		vbd.ActivePrompts,
		vbd.BusinessRules,
		vbd.bot_settings,
		vbd.CallTerminationSettings,
		vbd.SystemPrompt,
		vbd.moh_path,
		vbd.assistant_id,
        vbd.alias_id,vbd.summary_prompt,vbd.use_deepgram_voice_agent,vbd.universal_fillers,
        1000 as wait_before_greeting_ms,vbd.greetings as greeting,vbd.greeting_path as greeting_audio_path,
        vbd.STT_Config,
        vbd.WelcomeMessagePath, 
        vbd.bot_sp, 
        vbd.use_webhooks
    FROM twilioCalls c(NOLOCK)
    INNER JOIN calllog cl(NOLOCK) ON reftable='twiliocalls' and cl.refid = c.id
	join sip_telephony_providers s (nolock) on s.ph_sipname=isnull(dbo.fn_getsipname(c.Dnid),'Twilio')
	LEFT JOIN voice_bot_details vbd(NOLOCK) ON vbd.id = @botid
    LEFT JOIN voice_bot_sessions vbs(NOLOCK) 
        ON vbs.parentid = cl.parentid 
        AND vbs.callerid = c.CallerId
        AND vbs.isactive = 1
   
    WHERE c.CallSid = @CallSid
    AND c.call_end_time IS NULL
END



