--select @activeprompt=activeprompts from voice_bot_details (nolock) where id=@botid  
  
select @campaign_settings=campaign_settings from voice_bot_campaigns(nolock) where id=@campaignid  
-- ? No need to build @bot_config - we'll return individual columns from voice_bot_details  
drop table if exists #entitydata   
create table #entitydata([key] nvarchar(200),[value] nvarchar(max),id int identity(1,1))  
  
if isnull(@entity,'')=''  
begin  
select @caller_context=entity_context from voice_bot_campaign_audience(nolock) where id=@audienceid  
select @cd=@caller_context  
  
end  
else  
begin  
select @cd=(select dbo.fn_getentityfullname('user',@entityid) as PersonName for json path,without_array_wrapper)  
--select @caller_context=@cd  
exec usp_replaceentityplaceholders_allfields_insert @entityid,@entity  
  
select @caller_context=entitydetails from entity_details_transition(nolock) where entity=@entity and entityid=@entityid  
select @caller_context=replace(@caller_context,'+','')  
end  
insert into #entitydata([key],[value])  
select [key],[value] from openjson(@caller_context)  
declare @c int,@id int=0  
select @c=count(1) from #entitydata  
  
while @c>0  
begin  
select @id=min(id) from #entitydata where id>@id  
select @campaign_settings=replace(@campaign_settings,'{'+[key]+'}',[value])  
--,@activeprompt=replace (@activeprompt,'{'+[key]+'}',[value])  
from #entitydata where id=@id  
set @c=@c-1  
end  
-- ? SIMPLIFIED: Return ALL individual columns - no JSON assembly  
-- Let C# parse each JSON column separately  
    SELECT   
    'outbound' AS Direction,  
        c.id AS KitCallId,  
        c.CallSid AS CallSid,  
        c.StreamSid AS StreamSid,  
        c.CallerId AS CallerId,  
