        vbs.bot_sp AS BotSP,  
  isnull(dbo.fn_getsipname(c.Dnid),'Twilio') AS TelephonyProvider,  
  s.telephony_config, -- Telephony config (JSON string)  
        @campaign_settings as campaign_settings, -- Campaign settings with placeholders replaced (JSON string)  
        @cd as caller_context, -- Caller context (JSON string)  
  -- Individual bot config fields from voice_bot_details  
  vbd.VoiceConfig,  
  vbd.LanguageConfig,  
  vbd.HandoffRules,  
        --@activeprompt as ActivePrompts,  
  vbd.ActivePrompts,  
  vbd.BusinessRules,  
  vbd.bot_settings,  
  vbd.CallTerminationSettings,  
  vbd.SystemPrompt,  
  vbd.moh_path,  
  vbd.assistant_id,  
        vbd.alias_id,vbd.summary_prompt,vbd.use_deepgram_voice_agent,vbd.universal_fillers,  
        1000 as wait_before_greeting_ms,vbd.greetings as greeting,vbd.greeting_path as greeting_audio_path,  
        vbd.STT_Config,  
