/* ============================================================
   Procedure: [dbo].[usp_vb_get_customer_monthly_bill]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Query to get monthly bill for a customer
CREATE   PROCEDURE usp_vb_get_customer_monthly_bill
    @ParentId INT,
    @Year INT,
    @Month INT
AS
BEGIN
    SELECT 
        @ParentId AS CustomerId,
        @Year AS Year,
        @Month AS Month,
        COUNT(DISTINCT cl.Id) AS TotalCalls,
        SUM(DATEDIFF(SECOND, cl.Callstarttime, cl.callendtime)) AS TotalCallSeconds,
        SUM(tu.ChatAgentInputTokens) AS TotalChatAgentInputTokens,
        SUM(tu.ChatAgentOutputTokens) AS TotalChatAgentOutputTokens,
        SUM(tu.TTSCharacters) AS TotalTTSCharacters,
        SUM(tu.STTDurationSeconds) AS TotalSTTSeconds,
        SUM(tu.ChatAgentCostUSD) AS ChatAgentCost,
        SUM(tu.TTSCostUSD) AS TTSCost,
        SUM(tu.STTCostUSD) AS STTCost,
        SUM(tu.TotalCostUSD) AS TotalCost
    FROM calllog cl
    LEFT JOIN vb_token_usage tu ON cl.Id = tu.CallLogId
    WHERE cl.ParentId = @ParentId
        AND YEAR(cl.callstarttime) = @Year
        AND MONTH(cl.callstarttime) = @Month
    GROUP BY cl.ParentId, YEAR(cl.callstarttime), MONTH(cl.callstarttime);
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_get_voice_bot_audience]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_get_voice_bot_audience] --5,24981
@campaignid bigint,@execution_id bigint
as
begin

declare @segments nvarchar(max),@segment_type nvarchar(20),@campaign_settings nvarchar(max),@botid bigint,@from nvarchar(20),
@telephony_provider nvarchar(50),@batchsize int,@parentid bigint

select @batchsize=json_value(campaign_settings,'$.max_execution')-isnull(executions_attempted,0),@parentid=parentid
from  voice_bot_campaigns c(nolock) 
left join
(select campaignid,sum(executions_attempted) as executions_attempted from voice_bot_campaign_execution(nolock) 
where cast(start_time as date)=cast(getdate() as date) and campaignid=@campaignid group by campaignid
) e on c.id=e.campaignid
where id=@campaignid


if @batchsize>0
begin
select @segment_type=json_value(campaign_settings,'$.segment_Type'),@botid=json_value(campaign_settings,'$.botId'),
@segments=json_value(campaign_settings,'$.segments'),@from= json_value(campaign_settings,'$.fromNumber')
from  voice_bot_campaigns c(nolock) where id=@campaignid
select @telephony_provider=dbo.fn_getsipname(@from)

drop table if exists #batch
if (@segment_type='Segment')
begin
print 'segment'
end
else 
begin
select top (@batchsize) * into #batch from voice_bot_campaign_audience(nolock) where picked_on is null and vb_campaignid=@campaignid and isnull(is_dnd,0)=0
order by isnull(priority,0) desc
if exists (select 1 from #batch)
begin
update b set is_dnd=1 from #batch b join 
(select customernumber from do_not_call_list(nolock) where isnull(nullif(parentid,0),@parentid)=@parentid and isactive=1) d on d.customernumber= 
case when b.recipient_has_countrycode=0 then recipient_mobile else (select top 1 mobile from
[dbo].[fn_separatecountrycodeandmobile](recipient_mobile)) end

update v set picked_on =getdate(),v.execution_batchid=@execution_id,is_dnd=b.is_dnd from voice_bot_campaign_audience v join #batch b on b.id=v.id

delete From #batch where is_dnd=1

insert into tbl_ai_agent_execution_outbox(queuename,agentid,asstt_id,payload,createdon,priority)
select top (@batchsize)
  'voice_bot_obd' as queuename,
  @botid as agentid,
  '' as asstt_id,
  j.payload,
  getutcdate() as createdon,isnull(priority,0)
from #batch b
cross apply (
  select
    b.id as audienceId,
    @botid as botid,
    b.parentid,
    @campaignid as campaignId,
    @from as fromNumber,
    b.recipient_mobile as toNumber,
    @telephony_provider as telephonyProvider,
    case when b.recipient_mobile in ('7840002738','8077370768','7053553901') then cast(1 as bit) else cast(0 as bit) end as isTest
  for json path, without_array_wrapper
) j (payload) 
order by isnull(priority,0) desc;
end
end
end
end



--alter table voice_bot_campaign_audience add is_dnd bit default 0


GO

/* ============================================================
   Procedure: [dbo].[usp_vb_get_voice_bot_campaigns]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_get_voice_bot_campaigns]
as
begin
DECLARE @NowTime TIME = CONVERT(TIME, GETDATE());
DECLARE @Today   VARCHAR(10) = DATENAME(WEEKDAY, GETDATE());
drop table if exists #campaigns_executed
select campaignid,sum(executions_attempted) as executions_attempted into #campaigns_executed from voice_bot_campaign_execution(nolock) where cast(start_time as date)=cast(getdate() as date) group by campaignid
SELECT DISTINCT c.id,
       c.parentid,
       c.campaign_name,
       c.campaign_settings, 
       case when dbo.GetAvailableBalanceForService(parentid,23)>20
       --(json_value(campaign_settings,'$.max_execution')-e.executions_attempted)*
       --(select top 1 priceperunit from Price_Base_AICredits_Rate(nolock) a where type='Voicebot' and
       --parentid in (c.parentid,0) order by parentid desc) 
       then 'Eligible' else 'Ineligible: Low Balance' end as Eligibility,
       cast(0 as bigint) as execution_id
       into #eligible_campaigns
FROM voice_bot_campaigns c(nolock)
left join #campaigns_executed e(nolock) on c.id=e.campaignid
CROSS APPLY OPENJSON(c.campaign_settings, '$.days')
WITH (
    day      VARCHAR(10) '$.day',
    fromtime TIME        '$.fromtime',
    totime   TIME        '$.totime'
) d
WHERE isactive=1 and ISNULL(is_eventbased,0)=0 and
isnull(campaign_end_date,dateadd(d,1,getdate()))>getdate()
and (json_value(campaign_settings,'$.max_execution')-isnull(e.executions_attempted,0))>0
and d.day = @Today
  AND @NowTime >= d.fromtime
  AND @NowTime <= d.totime
  and exists
  (select 1 from voice_bot_campaign_audience(nolock) where vb_campaignid=c.id and picked_on is null);

  drop table if exists #execution_id
  create table #execution_id(executionid bigint,campaignid bigint)
  insert into voice_bot_campaign_execution(campaignid,last_error) output inserted.id,inserted.campaignid into #execution_id
  select id,case when eligibility='Eligible' then null else eligibility end from #eligible_campaigns

  update e set execution_id=executionid from #eligible_campaigns e join #execution_id i on e.id=i.campaignid
  select * from #eligible_campaigns where eligibility='Eligible'
end



GO

