  HandoffRules, 
  ActivePrompts, 
  BusinessRules, 
  SystemPrompt, 
  WelcomeMessagePath, 
  parentid, 
  bot_settings, 
  isactive, 
  bot_sp as Bot_sp, 
  moh_path, 
  assistant_id, 
  alias_id, 
  summary_prompt, 
  use_deepgram_voice_agent ,CallTerminationSettings,
   --CAST(
   --             CASE WHEN EXISTS (
   --                 SELECT 1 FROM bot_webhook_mapping m
   --                 INNER JOIN webhook_definition d ON d.webhook_id = m.webhook_id
   --                 WHERE m.bot_type = 'voice'
   --                   AND m.bot_id = @botid
   --                   AND m.is_enabled = 1
   --                   AND m.deleted_on IS NULL
   --                   AND d.deleted_on IS NULL
   --             ) THEN 1 ELSE 0 END
   --             AS BIT
   --         ) AS 
            cast(use_webhooks as bit) as use_webhooks

FROM 
  voice_bot_details 
WHERE 
  id = @botid END ELSE BEGIN 
SELECT 
  0 AS id, 
  'No active Bot for this number' AS Status
  END 
  END



