/* ============================================================
   Procedure: [dbo].[usp_vb_GetCallerContext]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_vb_GetCallerContext --'917840049991',34594      
@CallerId varchar(50), 
@parentid bigint AS BEGIN 
select 
  @callerid = replace(@callerid, '+', '') if left(@CallerId, 1)= '0' begin 
select 
  @callerid = dbo.fn_trim0prefix(@CallerId) end else if len(@callerid)> 10 begin 
select 
  @callerid = mobile 
from 
  dbo.fn_separatecountrycodeandmobile(@CallerId) end --if @callerid='9910048877'  --set @CallerId='7840002738'      
  declare @entity varchar(20), 
  @entityid bigint, 
  @callerdetails nvarchar(max), 
  @is_converted bit = 0, 
  @followupdata nvarchar(max)= '', 
  @calldata nvarchar(max)= '', 
  @opentickets nvarchar(max)= '', 
  @recentactivities nvarchar(max), 
  @additionaldetails nvarchar(max)= '', 
  @bot_sp nvarchar(200), 
  @sessionid nvarchar(200) declare @cd nvarchar(max) if exists (
    select 
      1 
    from 
      UserLeads(nolock) 
    where 
      parentid = @parentid 
      and @callerid in (
        isnull(
          nullif(mobileno, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno1, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno2, '0'), 
          ''
        )
      )
  ) begin 
select 
  top 1 @entity = 'lead', 
  @entityid = id 
from 
  UserLeads(nolock) 
where 
  parentid = @parentid 
  and @callerid in (
    isnull(
      nullif(mobileno, '0'), 
      ''
    ), 
    isnull(
      nullif(mobileno1, '0'), 
      ''
    ), 
    isnull(
      nullif(mobileno2, '0'), 
      ''
    )
  ) 
order by 
  id desc 
select 
  @is_converted = case when exists(
    select 
      1 
    from 
      LeadInteractionHistory l(nolock) 
      join FollowUp_Status f(nolock) on l.FollowUpStatus = f.id 
      and f.isconvert = 1
  ) then 1 else 0 end 
select 
  @cd =(
    select 
      personname as PersonName 
    from 
      userleads(nolock) 
    where 
      id = @entityid FOR JSON PATH, 
      INCLUDE_NULL_VALUES, 
      WITHOUT_ARRAY_WRAPPER
  ) 
select 
  @followupdata =(
    select 
      top 3 l.CreatedOn, 
      u.user_login as FollowupBy, 
      f.FollowupStatus, 
      d.User_Login as AssignedTo, 
      l.FollowupDate as NextFollowupdate, 
      l.Remarks 
    from 
      LeadInteractionHistory l(nolock) 
      join FollowUp_Status f(nolock) on l.FollowUpStatus = f.id 
      join user_detail u on u.user_id = f.createdby 
      left join user_detail d on d.user_id = l.AssignedTo 
    order by 
      l.id desc FOR JSON PATH, 
      INCLUDE_NULL_VALUES, 
      WITHOUT_ARRAY_WRAPPER
  ) 
select 
  @recentactivities =(
    select 
      top 3 eventdate, 
      u.User_Login as EventBy, 
      a.EventName, 
      t.eventdescription 
    from 
      tbl_LeadEventHistory(nolock) t 
      join User_Detail u on t.userid = u.user_id 
      join ActivityMaster(nolock) a on a.id = t.EventID 
    where 
      t.leadid = @entityid 
    order by 
      t.historyid desc FOR JSON PATH, 
      INCLUDE_NULL_VALUES
  ) end else if exists (
    select 
      1 
    from 
      Userenquiry(nolock) 
    where 
      parentid = @parentid 
      and @callerid in (
        isnull(
          nullif(mobileno, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno1, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno2, '0'), 
          ''
        )
      )
  ) begin 
select 
  top 1 @entity = 'enquiry', 
  @entityid = EnquiryID 
from 
  Userenquiry(nolock) 
where 
  parentid = @parentid 
  and @callerid in (
    isnull(
      nullif(mobileno, '0'), 
      ''
    ), 
    isnull(
      nullif(mobileno1, '0'), 
      ''
    ), 
    isnull(
      nullif(mobileno2, '0'), 
      ''
    )
  ) 
order by 
  EnquiryID desc 
select 
  @recentactivities =(
    select 
      top 5 eventdate, 
      u.User_Login as EventBy, 
      a.EventName, 
      t.eventdescription 
    from 
      tbl_enquiryEventHistory(nolock) t 
      join User_Detail u on t.userid = u.user_id 
      join ActivityMaster(nolock) a on a.id = t.EventID 
    where 
      enquiryid = @entityid 
    order by 
      t.historyid desc FOR JSON PATH, 
      INCLUDE_NULL_VALUES
  ) 
select 
  @cd =(
    select 
      personname as PersonName 
    from 
      userenquiry(nolock) 
    where 
      enquiryid = @entityid FOR JSON PATH, 
      INCLUDE_NULL_VALUES, 
      WITHOUT_ARRAY_WRAPPER
  ) end else if exists (
    select 
      1 
    from 
      UserLeads(nolock) 
    where 
      parentid = @parentid 
      and @callerid in (
        isnull(
          nullif(mobileno, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno1, '0'), 
          ''
        ), 
        isnull(
          nullif(mobileno2, '0'), 
          ''
        )
      )
  ) begin 
select 
  top 1 @entity = 'user', 
  @entityid = user_id 
from 
  User_detail(nolock) 
where 
  parentid = @parentid 
  and @callerid = str(mobile) 
order by 
  user_id desc end else begin 
select 
  @entity = 'Unknown', 
  @entityid = 0 end if exists(
    select 
      1 
    from 
      voice_bot_sessions(nolock) 
    where 
      parentid = @parentid 
      and callerid = @callerid 
      and isactive = 1
  ) begin 
select 
  @bot_sp = bot_sp, 
  @sessionid = sessionid 
from 
  voice_bot_sessions(nolock) 
where 
  parentid = @parentid 
  and callerid = @callerid 
  and isactive = 1 end else if exists(
    select 
      1 
    from 
      voice_bot_sessions(nolock) 
    where 
      parentid = @parentid 
      and entity = @entity 
      and entityid = @entityid 
      and isactive = 1
  ) begin 
select 
  @bot_sp = bot_sp, 
  @sessionid = sessionid 
from 
  voice_bot_sessions(nolock) 
where 
  parentid = @parentid 
  and entity = @entity 
  and entityid = @entityid 
  and isactive = 1 end else begin 
select 
  @bot_sp = '', 
  @sessionid = '' end print concat(
    'entity: ', @entity, ', entityid: ', 
    @entityid
  ) if isnull(@entity, '')<> '' begin --drop table if exists #caller_details  
  --create table #caller_details(fieldnameexposed varchar(250),fieldnameactual varchar(250),fieldtype varchar(50),fieldvalue nvarchar(max))    
  --insert into #caller_details  exec usp_replaceentityplaceholders_allfields_insert @entityid,@entity    
select 
  @callerdetails = entitydetails 
from 
  entity_details_transition(nolock) 
where 
  entity = @entity 
  and entityid = @entityid end 
select 
  @calldata =(
    select 
      top 3 c.direction as Calldirection, 
      callstarttime, 
      callendtime, 
      customercalldisposition, 
      agentcalldisposition, 
      u.User_Login as AgentLastAttempted, 
      o.outcomename as CallOutcome, 
      remarks as Callremarks, 
      s.call_summary 
    from 
      calllog(nolock) c 
      left join user_detail u (nolock) on u.user_id = c.agentuserid 
      left join calloutcomes (nolock) o on o.id = c.outcomeid 
      left join call_summaries(nolock) s on c.id = s.calllog_id 
    where 
      Customernumber = @callerid 
      and c.parentid = @parentid 
    order by 
      c.id desc for json path, 
      include_null_values
  ) 
select 
  top 1 @additionaldetails = additional_details 
from 
  call_summaries(nolock) 
where 
  entityname = @entity 
  and entityid = @entityid 
order by 
  id desc 
select 
  @additionaldetails = isnull(@additionaldetails, '{}') 
select 
  case when @entity = 'Enquiry' then 'Raw Enquiry' when @entity = 'lead' 
  and @is_converted = 1 then 'Customer' when @entity = 'lead' then 'lead' when @entity = 'User' then 'Team Member' else @entity end as Caller_Profile, 
  --@callerdetails as Caller_Details,  
  @cd as Caller_Details, 
  @calldata as Recent_Calls, 
  @recentactivities as Recent_Activities, 
  @followupdata as Recent_FollowUps, 
  @opentickets as Recent_Tickets, 
  @additionaldetails as Additional_Details, 
  @bot_sp as Bot_sp, 
  @sessionid as sessionid 
 END



