CREATE   PROCEDURE usp_vb_insertvoicebotaction
@voice_bot_id bigint,@bot_conversation_id bigint, @call_logid bigint,@action_name varchar(50),@isprocessed int
as
begin
declare @parentid bigint,@action_id int
select @parentid=parentid from calllog(nolock) where id=@call_logid
select @action_id=id from voice_bot_action_master where action_name=@action_name
insert into voice_bot_actions_taken(parentid,voice_bot_id,createdon,bot_conversation_id,call_logid,action_name,action_id,isprocessed)
select @parentid,@voice_bot_id,getdate(),@bot_conversation_id,@call_logid,@action_name,@action_id,0
select scope_identity() as action_taken_id
end



