/* ============================================================
   Procedure: [dbo].[usp_vb_insertvoicebotaction_webhook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- -----------------------------------------------------------------------------
-- 4) usp_vb_insertvoicebotaction_webhook - audit a webhook invocation.
--    Mirrors usp_vb_insertvoicebotaction but writes the webhook audit columns
--    that MIGRATION_WEBHOOKS.sql added to voice_bot_actions_taken.
--
--    parentid is derived from calllog (matching the existing SP pattern).
--    @action_id is accepted from the caller but if 0/NULL, falls back to
--    looking up 'Webhook' in voice_bot_action_master.
--
--    Returns: action_taken_id (single-row resultset, ExecuteScalar-friendly).
-- -----------------------------------------------------------------------------
CREATE   PROCEDURE usp_vb_insertvoicebotaction_webhook
    @voice_bot_id            BIGINT,
    @bot_conversation_id     BIGINT,
    @call_logid              BIGINT,
    @action_name             VARCHAR(50),
    @action_id               INT,
    @isprocessed             INT,
    @webhook_id              BIGINT          = NULL,
    @webhook_version         INT             = NULL,
    @webhook_slug            VARCHAR(100)    = NULL,
    @http_method             VARCHAR(10)     = NULL,
    @http_url_sanitized      NVARCHAR(1000)  = NULL,
    @http_status             INT             = NULL,
    @latency_ms              INT             = NULL,
    @request_payload         NVARCHAR(MAX)   = NULL,
    @response_body           NVARCHAR(MAX)   = NULL,
    @response_truncated      BIT             = 0,
    @response_size_bytes     INT             = NULL,
    @iteration_in_turn       INT             = NULL,
    @circuit_breaker_tripped BIT             = 0,
    @error_description       NVARCHAR(MAX)   = NULL,
    @internal_error          BIT             = 0
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @parentid BIGINT;
    SELECT @parentid = parentid FROM calllog (NOLOCK) WHERE id = @call_logid;

    -- Fall back to master table lookup if caller didn't pass action_id
    IF (@action_id IS NULL OR @action_id = 0)
    BEGIN
        SELECT @action_id = id
        FROM voice_bot_action_master
        WHERE action_name = ISNULL(@action_name, 'Webhook');
    END

    INSERT INTO voice_bot_actions_taken
    (
        parentid, voice_bot_id, createdon, bot_conversation_id, call_logid,
        action_name, action_id, isprocessed,
        webhook_id, webhook_version, webhook_slug,
        http_method, http_url_sanitized, http_status, latency_ms,
        request_payload, response_body,
        response_truncated, response_size_bytes,
        iteration_in_turn, circuit_breaker_tripped,
        error_description, internal_error
    )
    VALUES
    (
        @parentid, @voice_bot_id, GETDATE(), @bot_conversation_id, @call_logid,
        @action_name, @action_id, @isprocessed,
        @webhook_id, @webhook_version, @webhook_slug,
        @http_method, @http_url_sanitized, @http_status, @latency_ms,
        @request_payload, @response_body,
        @response_truncated, @response_size_bytes,
        @iteration_in_turn, @circuit_breaker_tripped,
        @error_description, @internal_error
    );

    SELECT SCOPE_IDENTITY() AS action_taken_id;
END



GO

