   Procedure: [dbo].[usp_vb_log_conversation_turn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_vb_log_conversation_turn] @calllogid BIGINT, 
@turnNumber INT, 
@userInput NVARCHAR(MAX), 
@botResponse NVARCHAR(MAX), 
@sttLatency INT, 
@llmLatency INT, 
@ttsLatency INT, 
@totalLatency INT, 
@sentiment DECIMAL(5, 2) = NULL, 
@chatAgentInputTokens INT = 0, 
@chatAgentOutputTokens INT = 0, 
@ttsCharacters INT = 0, 
@ttsCostUsd DECIMAL(10, 6) = 0, 
@llmCostUsd DECIMAL(10, 6) = 0, 
@wasBargedIn BIT = 0, 
@sessionId NVARCHAR(100) = NULL, 
-- AWS Bedrock session ID   
@ttsModel NVARCHAR(100) = NULL, 
-- ? NEW: TTS model used      
@ttsProvider NVARCHAR(50) = NULL, 
-- ? NEW: TTS provider (ElevenLabs, AWS Polly)     
@ttsStreaming BIT = NULL, 
@timeToFirstAudioMs int = null ,@bot_full_response NVARCHAR(MAX) = NULL
AS 
BEGIN 
SET 
  NOCOUNT ON;
INSERT INTO voice_bot_conversation_turns(
  calllog_id, turn_number, user_input, 
  bot_response, stt_latency_ms, llm_latency_ms, 
  tts_latency_ms, total_latency_ms, 
  sentiment_score, ChatAgentInputTokens, 
  ChatAgentOutputTokens, TTSCharacters, 
  TtsCostUsd, WasBargedIn, llmcostusd, 
  created_at, tts_model, tts_provider, 
  tts_streaming, time_to_first_audio_ms,bot_full_response
) 
VALUES 
  (
    @calllogid, 
    @turnNumber, 
    @userInput, 
    @botResponse, 
    @sttLatency, 
    @llmLatency, 
    @ttsLatency, 
    @totalLatency, 
    @sentiment, 
    @chatAgentInputTokens, 
    @chatAgentOutputTokens, 
    @ttsCharacters, 
    @ttsCostUsd, 
    @wasBargedIn, 
    @llmCostUsd, 
    GETDATE(), 
    @ttsmodel, 
    @ttsprovider, 
    @ttsStreaming, 
    @timeToFirstAudioMs,@bot_full_response
  ) -- If this is turn 1 and sessionId is provided, update the conversation record      
  IF @turnNumber = 1 
  AND @sessionId IS NOT NULL BEGIN declare @bot_sp nvarchar(100), 
  @bot_id bigint 
select 
  @bot_id = bot_id 
from 
  calllog(nolock) 
where 
  id = @calllogid 
select 
  bot_sp = bot_sp 
from 
  voice_bot_details(nolock) 
where 
  id = @bot_id insert into voice_bot_sessions(
    callerid, parentid, entity, entityid, 
    bot_sp, isactive, sessionid, streamsid, 
    last_updated, callerid_countrycode
  ) 
select 
  Customernumber, 
  parentid, 
  customerentity, 
  customerentityid, 
  @bot_sp, 
  1, 
  @sessionid, 
  StreamSid, 
  getdate(), 
  customercountrycode 
from 
  calllog(nolock) 
where 
  id = @calllogid 
UPDATE 
  voice_bot_conversations 
SET 
  sessionid = @sessionId 
WHERE 
  call_logid = @calllogid 
  END
  END



