/* ============================================================
   Procedure: [dbo].[usp_vb_log_token_usage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Stored Procedure to log token usage (calculates cost based on current pricing config)  
CREATE   PROCEDURE usp_vb_log_token_usage 
@CallLogId INT, 
@TurnNumber INT, 
@ChatAgentInputTokens INT = 0, 
@ChatAgentOutputTokens INT = 0, 
@ChatAgentProvider NVARCHAR(50) = NULL, 
@ChatAgentModelId NVARCHAR(100) = NULL, 
@TTSCharacters INT = 0, 
@TTSProvider NVARCHAR(50) = NULL, 
@TTSVoiceId NVARCHAR(50) = NULL, 
@STTDurationSeconds DECIMAL(10, 2) = 0, 
@STTProvider NVARCHAR(50) = NULL, 
@STTModel NVARCHAR(50) = NULL AS BEGIN DECLARE @ChatAgentCost DECIMAL(10, 6) = 0;
DECLARE @TTSCost DECIMAL(10, 6) = 0;
DECLARE @STTCost DECIMAL(10, 6) = 0;
DECLARE @TotalCost DECIMAL(10, 6) = 0;
-- Calculate ChatAgent cost from pricing config      
IF @ChatAgentProvider IS NOT NULL 
AND (
  @ChatAgentInputTokens > 0 
  OR @ChatAgentOutputTokens > 0
) BEGIN 
SELECT 
  TOP 1 @ChatAgentCost = (
    (
      @ChatAgentInputTokens / 1000.0 * ISNULL(InputTokenCostPer1K, 0)
    ) + (
      @ChatAgentOutputTokens / 1000.0 * ISNULL(OutputTokenCostPer1K, 0)
    )
  ) 
FROM 
  vb_pricing_config 
WHERE 
  ServiceType = 'ChatAgent' 
  AND ProviderName = @ChatAgentProvider 
  AND (
    ModelId = @ChatAgentModelId 
    OR ModelId IS NULL
  ) 
  AND IsActive = 1 
ORDER BY 
  CASE WHEN ModelId = @ChatAgentModelId THEN 0 ELSE 1 END, 
  EffectiveFrom DESC;
END -- Calculate TTS cost from pricing config      
IF @TTSProvider IS NOT NULL 
AND @TTSCharacters > 0 BEGIN 
SELECT 
  TOP 1 @TTSCost = (
    @TTSCharacters / 1000000.0 * ISNULL(CharacterCostPer1M, 0)
  ) 
FROM 
  vb_pricing_config 
WHERE 
  ServiceType = 'TTS' 
  AND ProviderName = @TTSProvider 
  AND (
    ModelId = @TTSVoiceId 
    OR ModelId IS NULL
  ) 
  AND IsActive = 1 
ORDER BY 
  CASE WHEN ModelId = @TTSVoiceId THEN 0 ELSE 1 END, 
  EffectiveFrom DESC;
END -- Calculate STT cost from pricing config     
IF @STTProvider IS NOT NULL 
AND @STTDurationSeconds > 0 BEGIN 
SELECT 
  TOP 1 @STTCost = (
    @STTDurationSeconds * ISNULL(DurationCostPerSecond, 0)
  ) 
FROM 
  vb_pricing_config 
WHERE 
  ServiceType = 'STT' 
  AND ProviderName = @STTProvider 
  AND (
    ModelId = @STTModel 
    OR ModelId IS NULL
  ) 
  AND IsActive = 1 
ORDER BY 
  CASE WHEN ModelId = @STTModel THEN 0 ELSE 1 END, 
  EffectiveFrom DESC;
END 
SET 
  @TotalCost = @ChatAgentCost + @TTSCost + @STTCost;
INSERT INTO vb_token_usage (
  CallLogId, TurnNumber, ChatAgentInputTokens, 
  ChatAgentOutputTokens, ChatAgentProvider, 
  ChatAgentModelId, TTSCharacters, 
  TTSProvider, TTSVoiceId, STTDurationSeconds, 
  STTProvider, STTModel, ChatAgentCostUSD, 
  TTSCostUSD, STTCostUSD, TotalCostUSD
) 
VALUES 
  (
    @CallLogId, @TurnNumber, @ChatAgentInputTokens, 
    @ChatAgentOutputTokens, @ChatAgentProvider, 
    @ChatAgentModelId, @TTSCharacters, 
    @TTSProvider, @TTSVoiceId, @STTDurationSeconds, 
    @STTProvider, @STTModel, @ChatAgentCost, 
    @TTSCost, @STTCost, @TotalCost
  );
END;



GO

