/* ============================================================
   Procedure: [dbo].[usp_vb_update_callsid_by_numbers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_vb_update_callsid_by_numbers-- 'h3.03-1766743317.279','SFc195bf2d8733405fbd5128725f3d20a3','+917965092405','+9178400002738' --'h3.03-1766426314.869',	'917965092405',	'7840002738'
    @RealCallSid NVARCHAR(100),   -- Real call_id from SmartFlo WebSocket (e.g., h3.03-1766409560.452)
    @recordedcallsid nvarchar(100),
    @FromNumber NVARCHAR(50),     -- DID used for call
    @ToNumber NVARCHAR(50)        -- Customer number
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @TempCallSid NVARCHAR(100) = NULL;
    DECLARE @TwilioCallsId BIGINT = NULL;
    
    if exists (select 1 from TwilioCalls(nolock) where 
    --call_end_time IS NULL AND 
    callsid=@recordedcallsid --and streamstatus='pending' 
    --and call_start_time>=dateadd(mi,-2,getdate())
    )
    begin
    select top 1 @TempCallSid=callsid, @TwilioCallsId = id from TwilioCalls(nolock) where 
    --call_end_time IS NULL 
    --AND 
    callsid=@recordedcallsid --and streamstatus='pending' 
    --and call_start_time>=dateadd(mi,-2,getdate()) 
    order by id desc
    end
    else
    begin
    select @FromNumber=replace(@fromnumber,'+',''),@ToNumber=replace(@tonumber,'+','')

    if @fromnumber like '91%' and len(@FromNumber)>10
    begin
    select @FromNumber=mobile from dbo.fn_separatecountrycodeandmobile(@FromNumber)
    end
    if @ToNumber like '91%' and len(@ToNumber)>10
    begin
    select @ToNumber=mobile from dbo.fn_separatecountrycodeandmobile(@ToNumber)
    end
    
    -- Find most recent outbound call with temp CallSid (SF*) matching From/To numbers
    SELECT TOP 1 
        @TempCallSid = c.CallSid,
        @TwilioCallsId = c.id
    FROM TwilioCalls c (NOLOCK)
    WHERE --c.StreamStatus='pending' and 
    c.call_end_time IS NULL
      AND c.CallerId = REPLACE(@ToNumber, '+', '')  -- Customer number
      AND c.Dnid = REPLACE(@FromNumber, '+', '')    -- DID
      AND c.call_start_time > DATEADD(minute, -2, GETDATE())  -- Within last 2 minutes
    ORDER BY c.call_start_time DESC;
    end
    IF @TempCallSid IS NULL
    BEGIN
        -- No matching temp record found
        SELECT 0 AS Success, 'No matching temp outbound call found for From=' + @FromNumber + ', To=' + @ToNumber AS Error;
        RETURN;
    END
    
    -- Update TwilioCalls with real CallSid
    UPDATE TwilioCalls 
    SET CallSid = @RealCallSid
    WHERE id = @TwilioCallsId;
    
    -- Update CallLog with real CallSid
    UPDATE CallLog
    SET CallSid = @RealCallSid
    WHERE reftable = 'twiliocalls'
      AND refid = @TwilioCallsId;


    
    -- Return success with temp CallSid for logging
    SELECT 1 AS Success, @RealCallSid AS UpdatedCallSid, @TempCallSid AS OriginalTempCallSid;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_update_outbound_callsid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_vb_update_outbound_callsid
    @TempCallSid NVARCHAR(100),  -- Temporary GUID (e.g., SF12345...)
    @RealCallSid NVARCHAR(100)   -- Real call_id from provider (e.g., h3.03-1766409560.452)
AS
BEGIN
    SET NOCOUNT ON;
    
    -- Update TwilioCalls with real CallSid
    UPDATE TwilioCalls 
    SET CallSid = @RealCallSid
    WHERE CallSid = @TempCallSid
    AND direction = 'outbound'
    AND call_end_time IS NULL;
    
    -- Update CallLog with real CallSid
    UPDATE CallLog
    SET CallSid = @RealCallSid
    WHERE CallSid = @TempCallSid
    AND reftable = 'twiliocalls';
    
    -- Return success if at least one row updated
    IF @@ROWCOUNT > 0
    BEGIN
        SELECT 1 AS Success, @RealCallSid AS UpdatedCallSid;
    END
    ELSE
    BEGIN
        SELECT 0 AS Success, 'No matching record found for temp CallSid: ' + @TempCallSid AS Error;
    END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_update_outbound_callsid_by_numbers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE usp_vb_update_outbound_callsid_by_numbers --'h3.03-1766426314.869',	'917965092405',	'7840002738'
    @RealCallSid NVARCHAR(100),   -- Real call_id from SmartFlo WebSocket (e.g., h3.03-1766409560.452)
    @FromNumber NVARCHAR(50),     -- DID used for call
    @ToNumber NVARCHAR(50)        -- Customer number
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @TempCallSid NVARCHAR(100) = NULL;
    DECLARE @TwilioCallsId BIGINT = NULL;
    select @FromNumber=replace(@fromnumber,'+',''),@ToNumber=replace(@tonumber,'+','')

    if @fromnumber like '91%' and len(@FromNumber)>10
    begin
    select @FromNumber=mobile from dbo.fn_separatecountrycodeandmobile(@FromNumber)
    end
    if @ToNumber like '91%' and len(@ToNumber)>10
    begin
    select @ToNumber=mobile from dbo.fn_separatecountrycodeandmobile(@ToNumber)
    end
    
    -- Find most recent outbound call with temp CallSid (SF*) matching From/To numbers
    SELECT TOP 1 
        @TempCallSid = c.CallSid,
        @TwilioCallsId = c.id
    FROM TwilioCalls c (NOLOCK)
    WHERE c.direction = 'outbound'
      AND c.call_end_time IS NULL
      AND c.CallSid LIKE 'SF%'  -- Temp GUID pattern
      AND c.CallerId = REPLACE(@ToNumber, '+', '')  -- Customer number
      AND c.Dnid = REPLACE(@FromNumber, '+', '')    -- DID
      AND c.call_start_time > DATEADD(minute, -2, GETDATE())  -- Within last 2 minutes
    ORDER BY c.call_start_time DESC;
    
    IF @TempCallSid IS NULL
    BEGIN
        -- No matching temp record found
        SELECT 0 AS Success, 'No matching temp outbound call found for From=' + @FromNumber + ', To=' + @ToNumber AS Error;
        RETURN;
    END
    
    -- Update TwilioCalls with real CallSid
    UPDATE TwilioCalls 
    SET CallSid = @RealCallSid
    WHERE id = @TwilioCallsId;
    
    -- Update CallLog with real CallSid
    UPDATE CallLog
    SET CallSid = @RealCallSid
    WHERE reftable = 'twiliocalls'
      AND refid = @TwilioCallsId;
    
    -- Return success with temp CallSid for logging
    SELECT 1 AS Success, @RealCallSid AS UpdatedCallSid, @TempCallSid AS OriginalTempCallSid;
END



