/* ============================================================
   Procedure: [dbo].[usp_vb_update_pricing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Helper procedure to update pricing (when rates change)
CREATE   PROCEDURE usp_vb_update_pricing
    @ServiceType NVARCHAR(50),
    @ProviderName NVARCHAR(50),
    @ModelId NVARCHAR(100) = NULL,
    @InputTokenCostPer1K DECIMAL(10,6) = NULL,
    @OutputTokenCostPer1K DECIMAL(10,6) = NULL,
    @CharacterCostPer1M DECIMAL(10,6) = NULL,
    @DurationCostPerSecond DECIMAL(10,6) = NULL
AS
BEGIN
    -- Deactivate old pricing
    UPDATE vb_pricing_config 
    SET IsActive = 0, ModifiedOn = GETDATE()
    WHERE ServiceType = @ServiceType 
        AND ProviderName = @ProviderName
        AND (ModelId = @ModelId OR (ModelId IS NULL AND @ModelId IS NULL));
    
    -- Insert new pricing
    INSERT INTO vb_pricing_config (
        ServiceType, ProviderName, ModelId,
        InputTokenCostPer1K, OutputTokenCostPer1K,
        CharacterCostPer1M, DurationCostPerSecond,
        IsActive, EffectiveFrom
    )
    VALUES (
        @ServiceType, @ProviderName, @ModelId,
        @InputTokenCostPer1K, @OutputTokenCostPer1K,
        @CharacterCostPer1M, @DurationCostPerSecond,
        1, GETDATE()
    );
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_vb_update_stream_status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




-- 4. Update Call with Stream Status
CREATE   PROCEDURE usp_vb_update_stream_status
    @CallSid NVARCHAR(100),
    @StreamSid NVARCHAR(100),
    @Status NVARCHAR(50)
AS
BEGIN
declare @tid bigint
    UPDATE TwilioCalls
    SET StreamSid = @StreamSid,
        StreamStatus = @Status,
        call_last_update = GETDATE()
    WHERE CallSid = @CallSid
	select @tid=SCOPE_IDENTITY()
    
    -- Also update call log
    UPDATE calllog
    SET StreamSid = @StreamSid,
        last_updated = GETDATE()
