/* ============================================================
   Procedure: [dbo].[Usp_VerificationStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 


CREATE   PROC [dbo].[Usp_VerificationStatus]       
AS      
BEGIN
	SELECT DISTINCT cs.LeadStatusName  AS VerificationStatus
	FROM   CRMLeadStatus               AS cs
END 

 



GO

/* ============================================================
   Procedure: [dbo].[Usp_VerificationStatusInsertCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 

CREATE   PROCEDURE [dbo].[Usp_VerificationStatusInsertCRM]
AS
BEGIN
	SELECT DISTINCT VerificationStatus INTO #TempTable
	FROM   [CRM].CRMDB.dbo.FollowUp_Details
	WHERE  STATUS = 'lead'
	       AND VerificationStatus IS NOT NULL
	
	DELETE 
	FROM   CRMLeadStatus
	WHERE  LeadStatusName NOT IN (SELECT tt.VerificationStatus
	                              FROM   #TempTable tt)
	
	INSERT INTO CRMLeadStatus
	  (
	    -- ID -- this column value is auto-generated
	    LeadStatusName,
	    CreatedOn
	  )
	SELECT tt.VerificationStatus,
	       GETDATE()
	FROM   #TempTable tt
	       LEFT JOIN CRMLeadStatus AS cs
	            ON  cs.LeadStatusName = tt.VerificationStatus
	WHERE  cs.LeadStatusName IS NULL
	
	DROP TABLE #TempTable
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_VerifyUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_VerifyUser --32222,'abhishek.kumar@pelsoftlabs.in'         
(          
  --@ID nvarchar(200)          
  @UserID nvarchar(20),      
  @EmailID nvarchar(200)      
      
)          
as          
Begin          
        
  if(exists(select 1 from User_Detail where User_ID = @UserID and EMail = @EmailID))  
  Begin     
         
 if(not exists(select 1 from User_Detail where isverify = 1 and User_ID = @UserID and EMail = @EmailID))        
 begin        
     update  User_Detail set isverify = 1 where  User_ID = @UserID and EMail = @EmailID         
            
      select 'Verified'           
    end        
 else        
  Begin   
     -- update  User_Detail set isverify = 1 where  User_ID = @UserID and EMail = @EmailID   
     select 'Already Verified'        
  End        
        
   end  
 else  
   Begin  
        
  select 'No details found for given credentials'  
  
  End  
        
End


