/* ============================================================
   Procedure: [dbo].[Usp_View_Acres99Details_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_View_Acres99Details_New --335  
	(@ParentID BIGINT)
AS
BEGIN
	IF (@ParentID <> 335)
	BEGIN
		SELECT TIM.ID
			,TIM.Acres_UserName
			,TIM.Acres_PWD
			,TIM.Kit19ParentID
			,isnull((
					SELECT TOP 1 User_Login
					FROM User_Detail
					WHERE USER_ID = TIM.Kit19ParentID
					), '') AS User_Login
			,dbo.Func_toGetTotalRecordsCountWithDateForAcres99(TIM.Acres_UserName) AS Records
			,TIM.LastAPIHit
			,TIM.LastDateFetched
			,TIM.ExpiredOn
			,TIM.STATUS
			,TIM.CreatedOn
			,TIM.CreatedBy
			,UD.User_Login AS CreatedByName
		FROM Acres99_Mapping TIM
		INNER JOIN User_Detail UD ON TIM.Createdby = UD.User_ID
		WHERE TIM.Kit19ParentID = @ParentID
		ORDER BY TIM.CreatedOn DESC
	END
	ELSE
	BEGIN
		SELECT TIM.ID
			,TIM.Acres_UserName
			,TIM.Acres_PWD
			,TIM.Kit19ParentID
			,isnull((
					SELECT TOP 1 User_Login
					FROM User_Detail
					WHERE USER_ID = TIM.Kit19ParentID
					), '') AS User_Login
			,dbo.Func_toGetTotalRecordsCountWithDateForAcres99(TIM.Acres_UserName) AS Records
			,TIM.LastAPIHit
			,TIM.LastDateFetched
			,TIM.ExpiredOn
			,TIM.STATUS
			,TIM.CreatedOn
			,TIM.CreatedBy
			,UD.User_Login AS CreatedByName
		FROM Acres99_Mapping TIM
		INNER JOIN User_Detail UD ON TIM.Createdby = UD.User_ID
		ORDER BY TIM.CreatedOn DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
		,@Activity_type = 'View_99acrsMppng'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Acres99_Mapping'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_View_DLT_Entity_Details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_View_DLT_Entity_Details --32222
	(@ParentID BIGINT)
AS
BEGIN
	SELECT DLT.id
		,DLT.PE_ID
		,DLT.createdon
		,DLT.createdby
		,DLT.Activestatus
		,DLT.expirydate
		,DLT.remarks
		,DLT.EntityName
		,Ud.User_Login
	FROM DLTdetails(NOLOCK) DLT
	JOIN User_Detail(NOLOCK) UD ON DLT.Parentid = Ud.User_ID
	WHERE DLT.Parentid = CASE 
			WHEN @ParentID = 335
				THEN DLT.Parentid
			ELSE @ParentID
			END
		AND DLT.Activestatus = 1
	ORDER BY id DESC

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @parentid = @ParentID
		,@Activity_type = 'View_DLT_Reg'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'DLTdetails'
END



