CREATE   PROCEDURE [dbo].[Usp_View_DsBoardMailSettingParentwise] --'enquiryReport',34594  --'maindashboard',34594                
 (  
 @DashboardType NVARCHAR(200)  
 ,@UserID BIGINT  
 )  
AS  
BEGIN  
 DECLARE @ParentID BIGINT = (  
   SELECT TOP 1 isnull(ParentID, User_ID)  
   FROM User_Detail(NOLOCK)  
   WHERE User_ID = @UserID  
   )  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''  
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''  
 DECLARE @IsAdmin BIT = 0  
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)          
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
 DECLARE @activity VARCHAR(MAX) = ''  
  
 SELECT @IsAdmin = isnull(IsAdmin, 0)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserID  
 END  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 -- select @UserIdTeamLst      
 IF (@DashboardType = 'MainDashboard')  
 BEGIN  
  SELECT tbl_ds.[ID]  
   ,tbl_ds.[DashboardType]  
   ,tbl_ds.[Sections]  
   ,tbl_ds.[DashboardID]  
   ,tbl_ds.[ReportID]  
   ,tbl_ds.[DataDateRange]  
   ,tbl_ds.[SendAtPeriod]  
   ,tbl_ds.[SendAtWhichDay]  
   ,(  
    SELECT CASE   
      WHEN tbl_ds.[SendAtPeriod] = 'weekly'  
       THEN CASE   
         WHEN tbl_ds.SendAtWhichDay = 1  
          THEN 'Mon'  
         WHEN tbl_ds.SendAtWhichDay = 2  
          THEN 'Tue'  
         WHEN tbl_ds.SendAtWhichDay = 3  
          THEN 'Wed'  
         WHEN tbl_ds.SendAtWhichDay = 4  
          THEN 'Thur'  
         WHEN tbl_ds.SendAtWhichDay = 5  
          THEN 'Fri'  
         WHEN tbl_ds.SendAtWhichDay = 6  
          THEN 'Sat'  
         WHEN tbl_ds.SendAtWhichDay = 7  
          THEN 'Sun'  
         ELSE tbl_ds.SendAtWhichDay  
         END  
      ELSE tbl_ds.SendAtWhichDay  
      END  
    ) AS SendAtWhichDayByName  
   ,tbl_ds.[SendAtTime]  
   ,tbl_ds.[ParentID]  
   ,tbl_ds.[UserCollections]  
   ,(  
    SELECT stuff((  
       SELECT ', ' + ud.User_Login  
       FROM (  
        SELECT value  
        FROM fn_split(tbl_ds.UserCollections, ',')  
        ) AS tbl  
       JOIN User_Detail(NOLOCK) AS ud ON tbl.value = ud.User_ID  
       FOR XML PATH('')  
       ), 1, 1, '')  
    ) AS [UserCollectionsByName]  
   ,isnull((  
     SELECT stuff((  
        SELECT ', ' + tbl.value  
        FROM (  
         SELECT value  
         FROM fn_split(tbl_ds.EmailIDs, ',')  
         ) AS tbl  
        FOR XML PATH('')  
        ), 1, 1, '')  
     ), '') AS EmailIDs  
   ,tbl_ds.[EmailIDs] AS EmailIDs1  
   ,tbl_ds.[Scope]  
   ,tbl_ds.[IsActive]  
   ,tbl_ds.[CreatedOn]  
   ,tbl_ds.[ModifiedOn]  
   ,tbl_ds.[CreatedBy]  
   ,ud1.User_Login AS CreatedByName  
   ,tbl_ds.[LastDeliveredAt]  
  FROM [tbl_dsboardMailSetting](NOLOCK) AS tbl_ds  
  JOIN User_Detail(NOLOCK) AS ud1 ON tbl_ds.CreatedBy = ud1.User_ID  
  WHERE DashboardType = @DashboardType  
   AND tbl_ds.ParentID = @ParentID  
  
  SET @activity = 'View_Dsbrd'  
 END -- end of maindashboard                     
 ELSE IF (@DashboardType = 'BIDashboard')  
 BEGIN  
  SELECT [ID]  
