   ,tbl_ds.[EmailIDs] AS EmailIDs1  
   ,tbl_ds.[Scope]  
   ,tbl_ds.[IsActive]  
   ,tbl_ds.[CreatedOn]  
   ,tbl_ds.[ModifiedOn]  
   ,tbl_ds.[CreatedBy]  
   ,ud1.User_Login AS CreatedByName  
   ,tbl_ds.[LastDeliveredAt]  
  FROM [tbl_dsboardMailSetting](NOLOCK) AS tbl_ds  
  JOIN User_Detail(NOLOCK) AS ud1 ON tbl_ds.CreatedBy = ud1.User_ID  
  WHERE DashboardType = @DashboardType  
   AND tbl_ds.ParentID = @ParentID  
   AND tbl_ds.CreatedBy IN (  
    SELECT value  
    FROM fn_Split(@UserIdTeamLst, ',')  
    )  
  
  --  and tbl_ds.CreatedBy in ( case when @UserIdTeamLst <> '' then @UserIdTeamLst          
  --                            else  @UserID            
  --       end             
  --     )          
  SET @activity = 'View_Dsbrd_flwup'  
 END  
