   ,tbl_ds.[ReportID]  
   ,tbl_ds.[DataDateRange]  
   ,tbl_ds.[SendAtPeriod]  
   ,tbl_ds.[SendAtWhichDay]  
   ,(  
    SELECT CASE   
      WHEN tbl_ds.[SendAtPeriod] = 'weekly'  
       THEN CASE   
         WHEN tbl_ds.SendAtWhichDay = 1  
          THEN 'Mon'  
         WHEN tbl_ds.SendAtWhichDay = 2  
          THEN 'Tue'  
         WHEN tbl_ds.SendAtWhichDay = 3  
          THEN 'Wed'  
