/* ============================================================
   Procedure: [dbo].[Usp_View_MagicBricksDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_View_MagicBricksDetails  --35218    
(        
 @ParentID Bigint        
)         
as        
Begin     
       
   if(@ParentID <> 335)    
    Begin       
    Select        
       MB.ID        
      ,MB.MagicBrickKey        
      ,MB.Kit19ParentID   
          
      ,isnull((Select top 1 User_Login from User_Detail where USER_ID = MB.Kit19ParentID ),'') as User_Login    
       ,dbo.Func_toGetTotalRecordsCountWithDateForMagicBricks(MB.MagicBrickKey) as Records  
      ,MB.LastAPIHit        
      ,MB.LastDateFetched        
      ,MB.ExpiredOn        
      ,MB.Status        
      ,MB.CreatedOn        
      ,MB.ModifiedOn        
      ,MB.CreatedBy,        
    UD.User_Login as CreatedByName        
   from MagicBricks MB        
   inner join User_Detail UD on MB.Createdby = UD.User_ID        
        
   where  MB.Kit19ParentID = @ParentID order by MB.CreatedOn desc        
         
    end    
 else    
  Begin    
    Select        
       MB.ID        
      ,MB.MagicBrickKey        
      ,MB.Kit19ParentID    
   ,isnull((Select top 1 User_Login from User_Detail where USER_ID = MB.Kit19ParentID ),'')  as User_Login        
      ,dbo.Func_toGetTotalRecordsCountWithDateForMagicBricks(MB.MagicBrickKey) as Records         
      ,MB.LastAPIHit        
      ,MB.LastDateFetched        
      ,MB.ExpiredOn        
      ,MB.Status        
      ,MB.CreatedOn        
      ,MB.ModifiedOn        
      ,MB.CreatedBy
	  ,
   UD.User_Login as CreatedByName        
    from MagicBricks MB        
    inner join User_Detail UD on MB.Createdby = UD.User_ID        
    order by MB.CreatedOn desc        
    
    
  End    
    
    
End


GO

