/* ============================================================
   Procedure: [dbo].[Usp_ViewCampaignDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_ViewCampaignDetails --''                   
 (  
 @SearchText NVARCHAR(max)=null  
 ,@IsActive BIT  
 ,@IsInActive BIT  
 ,@UserID INT  
 )  
AS  
BEGIN  
 DECLARE @ParentId BIGINT = 0;  
 DECLARE @IsAdmin BIT = 0;  
 DECLARE @RoleType VARCHAR(10);  
 DECLARE @TeamCode VARCHAR(20)  
  
 SELECT @ParentId = ParentID  
  ,@IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserId;  
  
 IF object_id('tempdb..#tblUserIds') IS NOT NULL  
 BEGIN  
  DROP TABLE #tblUserIds  
 END  
  
 CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)  
  
 SELECT @TeamCode = tum.TeamCode  
 FROM TBL_UA_TeamUserMappingMaster tum(NOLOCK)  
 INNER JOIN TBL_UA_TeamMaster tm(NOLOCK) ON tm.TeamCode = tum.TeamCode  
 WHERE tum.UserId = @UserId  
  
 IF (  
   (@TeamCode IS NULL)  
   AND (  
    @ParentId = @UserId  
    OR @IsAdmin = 1  
    )  
   )  
 BEGIN  
  --set @RoleType = 'Global'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT User_Id UserId  
  FROM User_Detail(NOLOCK)  
  WHERE ParentId = @ParentId  
 END  
 ELSE IF (@TeamCode != NULL)  
 BEGIN  
  ---set @RoleType = 'Team'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT UserId  
  FROM TBL_UA_TeamUserMappingMaster(NOLOCK)  
  WHERE TeamCode = @TeamCode  
 END  
 ELSE  
 BEGIN  
  --set @RoleType = 'User'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT @UserId  
 END  
  
 IF (  
   @IsActive = 1  
   AND @IsInActive = 1  
   )  
 BEGIN  
  SELECT CampaignID  
   ,NAME  
   ,UserID  
   ,IsEditable  
   ,IsActive  
   ,ud.User_Login  
  FROM UserCampaignSettings AS ucs(NOLOCK)  
  LEFT JOIN User_Detail ud(NOLOCK) ON ucs.ModifiedBy = ud.User_ID  
  WHERE UserID IN (  
    SELECT UserId  
    FROM #tblUserIds  
    )  
   AND (  
    ISNULL(@SearchText, '') = ''  
    OR NAME LIKE '%' + @SearchText + '%'  
    )  
  ORDER BY CampaignID DESC  
 END  
 ELSE IF (  
   @IsActive = 1  
   AND @IsInActive = 0  
   )  
 BEGIN  
  SELECT CampaignID  
   ,NAME  
   ,UserID  
   ,IsEditable  
   ,IsActive  
   ,ud.User_Login  
  FROM UserCampaignSettings AS ucs(NOLOCK)  
  LEFT JOIN User_Detail ud(NOLOCK) ON ucs.ModifiedBy = ud.User_ID  
  WHERE UserID IN (  
    SELECT UserId  
    FROM #tblUserIds  
    )  
   AND IsActive = 1  
   AND (  
    ISNULL(@SearchText, '') = ''  
    OR NAME LIKE '%' + @SearchText + '%'  
    )  
  ORDER BY CampaignID DESC  
 END  
 ELSE IF (  
   @IsActive = 0  
   AND @IsInActive = 1  
   )  
 BEGIN  
  SELECT CampaignID  
   ,NAME  
   ,UserID  
   ,IsEditable  
   ,IsActive  
   ,ud.User_Login  
  FROM UserCampaignSettings AS ucs(NOLOCK)  
  LEFT JOIN User_Detail ud(NOLOCK) ON ucs.ModifiedBy = ud.User_ID  
  WHERE UserID IN (  
    SELECT UserId  
    FROM #tblUserIds  
    )  
   AND IsActive = 0  
   AND (  
    ISNULL(@SearchText, '') = ''  
    OR NAME LIKE '%' + @SearchText + '%'  
    )  
  ORDER BY CampaignID DESC  
 END  
 ELSE IF (  
   @IsActive = 0  
   AND @IsInActive = 0  
   )  
 BEGIN  
  SELECT CampaignID  
   ,NAME  
   ,UserID  
   ,IsEditable  
   ,IsActive  
   ,ud.User_Login  
  FROM UserCampaignSettings AS ucs(NOLOCK)  
  LEFT JOIN User_Detail ud(NOLOCK) ON ucs.ModifiedBy = ud.User_ID  
  WHERE UserID IN (  
    SELECT UserId  
    FROM #tblUserIds  
    )  
   AND IsActive <> 1  
   AND IsActive <> 0  
   AND (  
    ISNULL(@SearchText, '') = ''  
    OR NAME LIKE '%' + @SearchText + '%'  
    )  
   AND (  
    (  
     IsActive = CASE @IsActive  
      WHEN 0  
       THEN NULL  
      ELSE @IsActive  
      END  
     )  
    OR (  
     IsActive = CASE @IsInactive  
      WHEN 1  
       THEN 0  
      ELSE NULL  
      END  
     )  
    )  
  ORDER BY CampaignID DESC  
 END  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'View_Cmpn_Lst'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserCampaignSettings'  
END  


GO

