/* ============================================================
   Procedure: [dbo].[Usp_ViewCreditAgentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**************************      
Created by : Santosh Kumar      
Date : 08-05-2017 12:31 PM      
          
This SP is Used to view Credit Agent Details          
************************/          
CREATE   PROC Usp_ViewCreditAgentDetails   
@Search VARCHAR(250)          
AS          
BEGIN
	SELECT *
	FROM   CreditAgent
	WHERE  ISNULL(@Search, '') = ''
	       OR  Agent LIKE '%' + @Search + '%'
	       OR  UserName LIKE '%' + @Search + '%'
	       OR  mobile LIKE '%' + @Search + '%'
	       OR  EmailID LIKE '%' + @Search + '%'
	ORDER BY
	       ID DESC
END    
    


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewCRMCampaignSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ViewCRMCampaignSetting   --335              
 (@UserID INT)        
AS        
BEGIN        
 DECLARE @ParentID BIGINT = 0        
        
 SELECT @ParentID = isnull(ParentID, 0)        
 FROM user_detail with(nolock)        
 WHERE USER_ID = @UserID        
        
          
    if(exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID))      
    begin      
     if(exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID and isnull(AdminRight,0) = 0 ))      
      begin      
       DECLARE @IsAdmin BIT = 0       
       SELECT @IsAdmin = IsAdmin      
    FROM User_Detail(NOLOCK)      
    WHERE User_ID = @Userid      
      
       IF(@IsAdmin = 1)      
     BEGIN      
        declare @UserCollectionString nvarchar(max) = ''      
      select @UserCollectionString = STRING_AGG(USER_ID,'#')      
           from User_Detail with(nolock) where ParentID = @ParentID and ISNULL(IsAdmin,0) = 1      
           
          if(trim(@UserCollectionString) <> '')      
          begin      
            update CRMCampaignSettings set AdminRight = 1 , UserAdmin = trim(@UserCollectionString) where UserID = @UserID       
         end      
       END      
     end       
    
  if( exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID and isnull(AutoLeadFollowup,0) = 0) and 1=2 )       
      begin    
       declare @FlpId bigint = 0    
         if(exists(SELECT top 1 ID FROM FollowUp_Status AS fus  with(nolock) WHERE fus.IsActive = 1 and ParentId is null and fus.IsCallback = 1 ))        
             begin    
                 
       SELECT top 1 @FlpId = ID FROM FollowUp_Status AS fus with(nolock)  WHERE fus.IsActive = 1 and ParentId is null and fus.IsCallback = 1     
       ORDER BY fus.OrderNumber Asc     
    
           update CRMCampaignSettings set AutoLeadFollowup = 1 ,FollowupStatus = @FlpId, NextStatusDateAddUnit = '00:00:00'  where UserID = @UserID      
    
       end    
                else if(exists(SELECT top 1 ID FROM FollowUp_Status AS fus with(nolock)  WHERE     
                  fus.IsActive = 1 and IsDisabled = 0 and fus.ParentId = @ParentId and fus.IsCallback = 1 ))    
       begin    
              SELECT top 1 @FlpId = ID FROM FollowUp_Status AS fus with(nolock) WHERE fus.IsActive = 1 and IsDisabled = 0     
                 and fus.ParentId = @ParentId and fus.IsCallback = 1  ORDER BY fus.OrderNumber Asc     
           update CRMCampaignSettings set AutoLeadFollowup = 1 ,FollowupStatus = @FlpId, NextStatusDateAddUnit = '00:00:00'  where UserID = @UserID      
    
       end    
                
   end    
    
    
     end      
         
      
 SELECT [SettingID]        
  ,[UserID]        
  ,[AutoLeadDistribution]        
  ,[LastUserAssigned]        
  ,[Agents]        
  ,[IsStickyAgents]        
  ,[ActiveUsers]        
  ,[AdminRight]        
  ,[UserAdmin]        
  ,[IsActive]        
  --,[CreateDate]              
  ,dbo.[fn_getusertimefromindiantime](@ParentID, CreateDate) AS CreateDate        
  --,[ModifiedDate]              
  ,dbo.[fn_getusertimefromindiantime](@ParentID, ModifiedDate) AS ModifiedDate        
  ,[ModifiedBy]        
  ,isnull(AutoLeadFollowup, 0) AS AutoLeadFollowup        
  ,isnull(FollowupStatus, 0) AS FollowupStatus        
  ,(        
   SELECT isnull(FollowupStatus, '')        
   FROM Followup_Status(NOLOCK)        
   WHERE Id = CRC.FollowupStatus        
   ) FollowupStatusName        
  ,isnull(NextStatusDateAddUnit, '') AS NextStatusDateAddUnit        
  ,isnull(FollowupRemarks, '') AS FollowupRemarks        
 FROM CRMCampaignSettings(NOLOCK) CRC        
 WHERE UserID = @UserID        
        
      
      
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId        
  ,@Activity_type = 'View_CRM_Sttng'        
  ,@ActionType = 'S'        
  ,@RowJson = ''        
  ,@Table_name = 'CRMCampaignSettings'      
        
      
END 


GO

