/* ============================================================
   Procedure: [dbo].[Usp_ViewCRMCampaignSetting_leadapi]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewCRMCampaignSetting_leadapi] --34594--34149      
(@UserID INT)        
AS         
BEGIN        
   declare @ParentID bigint = 0,@autolead int =0     
   select @ParentID = isnull(ParentID,0) from user_detail(nolock) where USER_ID = @UserID 
   
   
        
declare @followupstatus nvarchar(100),@iscallback int,@isconvert bit,@fudate datetime,@day int,@hour int,@min int,@nxdu nvarchar(50),@remarks nvarchar(2000),@agent nvarchar(max)=@parentid,@la bigint=0
select @followupstatus=FollowupStatus,@nxdu=isnull(nextstatusdateaddunit,'0:0:0'),@remarks=FollowupRemarks,@agent=Agents,@autolead=
AutoLeadDistribution,
@la=LastUserAssigned 
from CRMCampaignSettings CRC(nolock) WHERE  UserID = @ParentID

if @autolead=1
begin

select position,value as unit into #t from fn_split(@nxdu,':') 
select @day=unit  from #t where position=1
select @hour=unit  from #t where position=2
select @min=unit  from #t where position=3
select @fudate=dateadd(mi,@min,(dateadd(hh,@hour,dateadd(d,@day,getdate()))))


if ((@followupstatus is null) or (@followupstatus = 0)) 
select top 1 @followupstatus=id,@fudate=case when iscallback=1 then getdate() else null end,@remarks=''
from Followup_Status(nolock) where (parentid =@parentid or parentid is null) and isactive=1 and isdisabled=0
order by parentid desc,
case when followupstatus='Call-Back' then 0 else 1 end
end

SELECT @autolead [AutoLeadDistribution]      
      ,@la [LastUserAssigned]      
      ,@agent [Agents]      
      ,0 [IsStickyAgents]      
      ,1 [ActiveUsers]      
      ,1 [AdminRight]      
      ,1 [UserAdmin]      
      ,1 [IsActive]      
      ,getdate() as CreateDate      
      ,getdate() as ModifiedDate      
      ,@parentid [ModifiedBy]    
      ,1 as AutoLeadFollowup    
     ,@followupstatus as FollowupStatus
	 , (select isnull(FollowupStatus,'') from Followup_Status(nolock) where Id = @followupstatus) FollowupStatusName  
       ,@fudate as  NextStatusDateAddUnit    
       ,isnull(@remarks,'') as FollowupRemarks    
             
END     


GO

