	FROM   CRMServices AS c
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewCRMPreEnquiryServicesInsertCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 

       
CREATE   PROC [dbo].[Usp_ViewCRMPreEnquiryServicesInsertCRM]       
AS      
BEGIN
	SELECT DISTINCT SERVICE_NAME INTO #TempTable
	FROM   [CRM].CRMDB.dbo.M_Services 
	
	DELETE 
	FROM   CRMServices
	WHERE  ServiceName NOT IN (SELECT tt.SERVICE_NAME
	                           FROM   #TempTable tt)
	
	
	INSERT INTO CRMServices
	  (
	    ServiceName,
	    CreatedOn
	  )
	SELECT tt.[SERVICE_NAME],
	       GETDATE()
	FROM   #TempTable tt
	       LEFT JOIN CRMServices AS c
	            ON  c.ServiceName = tt.[SERVICE_NAME]
	WHERE  c.ServiceName IS NULL
	
	DROP TABLE #TempTable
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewCRMPreEnquiryStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
    
CREATE   PROC [dbo].[Usp_ViewCRMPreEnquiryStatus]
@Search VARCHAR(50) = ''       
AS      
BEGIN
	SELECT DISTINCT cs.StatusName
	FROM   CRM_Status AS cs
	WHERE  ISNULL(@Search, '') = ''
	       OR  cs.StatusName LIKE '%' + @Search + '%'
END   


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewCRMPreEnquiryStatusInsertCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



     
CREATE   PROC [dbo].[Usp_ViewCRMPreEnquiryStatusInsertCRM]     
AS    
BEGIN
	SELECT DISTINCT tbl.StatusName INTO     #TempTable
	FROM   (
	           (
	               SELECT DISTINCT StatusName,
	                      DateCreated
	               FROM   [CRM].CRMDB.dbo.M_Data_Status
	           ) 
	           UNION 
	           (
	               SELECT DISTINCT StatusName,
	                      DateCreated
	               FROM   [CRM].CRMDB.dbo.M_Status
	           ) 
	           UNION 
	           (
	               SELECT DISTINCT VStatus_Name AS StatusName,
	                      DateCreated
	               FROM   [CRM].CRMDB.dbo.M_VisitStatus
	           )
	       )                             AS tbl
	
	DELETE 
	FROM   CRM_Status
	WHERE  StatusName NOT IN (SELECT tt.StatusName
	                          FROM   #TempTable tt)
	
	INSERT INTO CRM_Status
	  (
	    -- ID -- this column value is auto-generated
	    StatusName,
	    CreatedOn
	  )
	SELECT tt.StatusName,
	       GETDATE()
	FROM   #TempTable tt
	       LEFT JOIN CRM_Status AS cs
	            ON  cs.StatusName = tt.StatusName
	WHERE  cs.StatusName IS NULL
	
	DROP TABLE #TempTable
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewCustomAndPredefinedFilterBySearchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec Usp_ViewLeadDetailsBySearchCriteria @srno=N'1',@enno=N'20',@CriteriaName=N'All Leads',@UserID=39042,@CriteriaID=0,@SearchByMode=N'Name'
-- exec  [dbo].[Usp_ViewCustomAndPredefinedFilterBySearchCriteria]  '',34594,231745,'id'
-- exec  [dbo].[Usp_ViewCustomAndPredefinedFilterBySearchCriteria]  'testingflp',34594,0,'Name'
CREATE   PROCEDURE [dbo].[Usp_ViewCustomAndPredefinedFilterBySearchCriteria]  --'',34594,231745,'id'    
(    
	@CriteriaName nvarchar(500),
	@UserID bigint,
	@CriteriaID bigint,
	@SearchByMode nvarchar(50)
)    
as    
Begin
	-- declare @srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@CriteriaName nvarchar(500)=N'All Leads',@UserID bigint=39042,@CriteriaID bigint=0,@SearchByMode nvarchar(50)=N'Name'

	declare @ParentID bigint = 0    
	declare @IsAdmin bit = 0     
    
	select @ParentID = ISNULL(ParentID,User_ID) , @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID
    
	if(@SearchByMode = 'Name')    
	Begin    
		select top 1 @CriteriaID = isnull(ID,0) from tbl_SearchCriteria(nolock) where CriteriaName = @CriteriaName and ParentID = @ParentID      
	end

    Declare @ApplyTo nvarchar(50) = 'applyall'                       
	Declare @AndorOR nvarchar(10) = 'and'                      
	Declare @SearchType nvarchar(200) = 'Enquiry'                      
                      
   --select top 1 @ParentID = isnull(ParentID,USER_ID),@IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID                      
	select @ApplyTo = isnull(ApplyTo,'') , @SearchType = CriteriaType from tbl_SearchCriteria(nolock) where ID = @CriteriaID  
                         
	if(@ApplyTo = 'applyall')
	Begin
		set @AndorOR = 'and';
	End
	else
	Begin
		set @AndorOR = 'or'
	End
                      
	declare @tempConditions table(RowNum int,FieldName nvarchar(200),[FieldType] nvarchar(200),[Operator] nvarchar(200),Value nvarchar(max))      
      
  --SELECT ROW_NUMBER() over(order by id asc) as RowNum,                      
  --    [FieldName]                      
  --    ,[FieldType]                      
  --    ,[Operator]                      
  --    ,[Value] into #tempConditions                            
  --FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                       
	insert into @tempConditions(RowNum,[FieldName],[FieldType],[Operator],[Value])    
	SELECT ROW_NUMBER() over(order by id asc) as RowNum,[FieldName],[FieldType],[Operator],[Value]                            
	FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                       

	Declare @InvertedComma nvarchar(10) = '''';                      
  --select @InvertedComma+'a'                      
	declare @Count int = 0                      
	declare @RowIndex int = 0                      
	Declare @FieldName nvarchar(200) = ''                      
	Declare @FieldOperator nvarchar(200) = ''                      
	Declare @Value nvarchar(max) = ''                      
	Declare @FieldType nvarchar(200) = ''                      
	Declare @DataType nvarchar(200)= ''                            
	--select @Count = count(1) from #tempConditions     
	select @Count = count(1) from @tempConditions      
                        
	Declare @FilterQuery nvarchar(max) = ' ('                      
                          
	if(@Count = 0)                      
    Begin                      
		set @FilterQuery = @FilterQuery + '1=1'                        
	end                      
                      
	while(@Count > 0)                      
    Begin                      
		set @RowIndex = @RowIndex + 1                       
		select @FieldName = FieldName,@FieldOperator = Operator,@Value = Value ,@FieldType = FieldType 
		from  @tempConditions where RowNum = @RowIndex                      
                      
		select @DataType = dbo.ufn_FetchDataType(@FieldName,@FieldType,@ParentID);                        
		-- select @DataType                      
           
		   
     if(@FieldName = 'IsOpen' and @FieldType = 'Enquiry')              
       Begin              
        set @FieldName = 'IsOpen'  
		if(@Value = 'True')
		  Begin
		     set @Value = '''open'''
		  End 
		 else
		   Begin
		     set @Value = '''lead''' 
		   end            
     End    
	  
	  if(@FieldName = 'LeadNo' and @FieldType = 'Enquiry')              
     Begin              
        set @FieldName = ' cast( isnull(nullif(Leads,''''),''0'') as bigint ) '   
     End   
		   
		         
		if(@FieldName = 'LastFollowupCreatedBy')          
		 Begin          
		 set @FieldName =  'LastFollowupCreatedByName'          
	  end          
                   
		if(@FieldName = 'CreatedOn' and @FieldType = 'Lead')                      
		 Begin                      
			set @FieldName = 'CreatedOn1'                      
		 End                       
                      
		if(@FieldName = 'CreatedBy')           
		 Begin                      
			set @FieldName = 'User_Login'                      
		 End               
                
		if(@FieldName = 'AssignedTo' and @FieldType = 'Lead')                      
		 Begin                      
			--set @FieldName = 'assigneduser'
			set @FieldName = 'assignedUserloginOnly'                      
		 End                  
              
		if(@FieldName = 'GoogleLocation')                      
		 Begin                      
			set @FieldName = 'whereAddress'                      
		 End              
              
		if(@FieldOperator = '%[A]%')                      
		 Begin                      
			set @FieldOperator = ' like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                        
		End                             
		else if(@FieldOperator = '[A]%')                      
		 Begin                      
			set @FieldOperator = ' like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma;                        
		 End                           
			else if(@FieldOperator = '%[A]')                      
		 Begin                      
			set @FieldOperator = ' like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                        
		 End                          
     		else if(@FieldOperator = '[A]' and @FieldName = 'tag')
		begin
			set @FieldOperator = ''
			set @FieldName = ''
			set @Value = ' 1 = iif(exists(select 1 from fn_Split(T.Tags, '','') where [value] = '+@Value+'), 1, 0) '
		end
		else if(@FieldOperator = 'not [A]' and @FieldName = 'tag')
		begin
			set @FieldOperator = ''
			set @FieldName = ''
			set @Value = ' 1 = iif(exists(select 1 from fn_Split(T.Tags, '','') where [value] <> '+@Value+'), 1, 0) '
		end
		else if(@FieldOperator = '[A]')                      
		 Begin                      
			--set @FieldOperator = ' like '  
			 set @FieldOperator = ' = '	
			                    
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma;                        
		 End                         
			else if(@FieldOperator = 'not %[A]%')                      
		 Begin                      
			set @FieldOperator = ' not like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                        
		 End                      
		 else if(@FieldOperator = 'not [A]%')                      
		 Begin                      
			set @FieldOperator = ' not like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma ;                        
		 End                      
	  else if(@FieldOperator = 'not %[A]')                      
		 Begin                      
			set @FieldOperator = ' not like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                        
		 End                         
	  else if(@FieldOperator = 'not [A]')                      
		 Begin                      
			set @FieldOperator = ' not like '                      
	set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma ;                        
		 End              
	  else if(@FieldOperator = 'in [A]' and @FieldName <> 'pipeline')                      
		 Begin                      
			set @FieldOperator = ' in '                      
		 --set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = REPLACE('in [A]','in [A]',@Value) ;                        
		 End                
		else if(@FieldOperator = 'in [A]' and @FieldName = 'pipeline')                  
		 Begin                  
			 set @FieldOperator = ''    
	   set @FieldName = ''                  
			 --set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
			 -- set @Value = REPLACE('in [A]','in [A]',@Value) ; 
			 select @Value = dbo.fn_getPipelineExpForSQL(@Value,@ParentID)  
			 set @Value = '( ID in ( select LeadID from LeadPipelineMapping_latest(nolock) where ( '+ @Value +' ) )) '
			 set @Value = REPLACE(@Value,'PipelineStageID','PipelineStage');
		                    
		 End                       
                      
		if(@DataType = 'datetime' and @FieldOperator = 'between')                      
			Begin                      
                            
				 --set @FieldName = ' DATEDIFF(DAY,'+@FieldName+',getdate()) '                    
		set @FieldName = ' DATEDIFF(DAY,getdate(),'+@FieldName+') '                        
                      
		 end                      
                          
		if(@RowIndex = 1)                      
	  Begin                  
		  if(@FieldName = 'MobileNo')                  
		 Begin                  
		 set @FilterQuery = @FilterQuery + ' ( ' + '('+'MobileNo3' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'MobileNo1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'MobileNo2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';                  
		 End                
	 else if(@FieldName = 'EmailID')                  
		 Begin                  
		 set @FilterQuery = @FilterQuery + ' ( ' + '('+'EmailID' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'EmailID1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'EmailID2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';                  
		 End                  
		else                  
		 Begin                              
			  set @FilterQuery = @FilterQuery + ' ( ' + @FieldName +' '+ @FieldOperator+' '+ @Value + ' ) ';                      
		  end                    
	  end                      
	  else                       
	   Begin                   
			if(@FieldName = 'MobileNo')                  
		 Begin                  
		 set @FilterQuery = @FilterQuery + @AndorOR + ' ( ' + '('+'MobileNo3' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'MobileNo1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'MobileNo2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';       
  
    
     
        
          
            
		 End                
	 else if(@FieldName = 'EmailID')                  
		 Begin                  
		 set @FilterQuery = @FilterQuery + @AndorOR + ' ( ' + '('+'EmailID' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'EmailID1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'EmailID2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';          
  
    
      
        
		 End                  
		else                  
		 Begin                
		 set @FilterQuery = @FilterQuery + @AndorOR + ' ( ' + @FieldName +' '+ @FieldOperator+' '+ @Value + ' ) ';                      
		 end                
	   End                      
                      
		set @Count = @Count - 1                         
