/* ============================================================
   Procedure: [dbo].[Usp_ViewDLTTemplates]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ViewDLTTemplates --34594              
 (@UserID BIGINT)  
AS  
BEGIN  

  --Declare @UserID BIGINT = 34594
 
  DECLARE @ParentID BIGINT = (  
   SELECT TOP 1 ParentID  
   FROM User_Detail WITH (NOLOCK)  
   WHERE User_ID = @UserID  
   )  
  
 SELECT UML.ID  
  ,UML.Name  
  ,UML.DLT_TemplateID  
  ,UML.MessageType  
  ,UML.MailContent AS TemplateText  
  ,isnull(UML.IsUnicode, 0) AS IsUnicode  
  ,UML.ParentID  
  ,UML.ActiveStatus  
  ,UML.CreatedOn  
  ,UML.CreatedBy  
  ,isnull(UML.is_stock, 0) AS Is_Stock  
  , (select isnull(STRING_AGG(Sender_Name,', '),'')
	    from DLT_TemplateSenderMapping as DTL with(nolock) 
		  join SenderID_Detail as sndr with(nolock)
		  on DTL.SenderId = sndr.Sender_ID
		where DTL.DLT_TemplateID = UML.DLT_TemplateID) as SenderIDs
 
 FROM UserMailTemplate(NOLOCK) UML  
 WHERE (  
   (CreatedBy = @UserID)  
   OR (ParentID = @ParentID)  
   )  
  AND IsSMS = 1  
  AND ISNULL(DLT_TemplateID, '') <> ''  
  
 --SELECT              
 --     ID              
 --    ,DLT_TemplateID              
 --    ,MessageType              
 --    ,TemplateText              
 --    ,IsUnicode              
 --    ,ParentID              
 --    ,ActiveStatus              
 --    ,CreatedOn              
 --    ,CreatedBy              
 -- FROM DLT_Template where CreatedBy = @UserID      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'View_DLT_TmpltLst '  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserMailTemplate'  
END  


GO

