/* ============================================================
   Procedure: [dbo].[Usp_ViewEmailDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--update tbl_subscription set userid=34594        
        
        
--exec Usp_ViewEmailDetails null,null,null,34594,null  
        
CREATE   PROC dbo.Usp_ViewEmailDetails         
 (          
 @SearchText NVARCHAR(max) =null             
 ,@fromdate datetime = null            
 ,@todate datetime = null          
 ,@UserID BIGINT = NULL    
 ,@status nvarchar(50)= null        
 )          
AS          
BEGIN    
   
 --declare @SearchText NVARCHAR(max)=null,@fromdate datetime=null,@todate datetime=null,@UserID BIGINT=34594,@status nvarchar(50)=null  
  
 select * From   
 (  
 SELECT ROW_NUMBER()over(partition by emails order by id desc) sno,  
 id,        
 userid,        
 emails,            
 status,        
 createdon,    
 es_createdby,    
 case     
 when ISNULL(es_createdby,'')='' then 'self'    
 else  (select concat(us.user_login,' (',us.fname,' ',us.lname,')') from user_detail us where us.user_id= es_createdby)    
END AS createdby    
 from tbl_subscription(nolock)  
 WHERE     
 USERID=@UserID AND    
 ( ISNULL(@SearchText, '') = ''          
   OR emails LIKE '%' + @SearchText + '%'          
   )          
   and ( @fromdate IS NULL OR CreatedOn >  @fromdate)           
  AND (@todate IS NULL OR CreatedOn < @todate)               
  AND (@status IS NULL OR status = @status)         
  --order by id desc      
  ) T     
  Where T.sno=1  
          
END          
        
--alter table tbl_subscription add createdby bigint default null        
        
--update tbl_subscription set createdby=34594    
    


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewEnquiryCategoryThresholds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------  
  
CREATE   PROCEDURE [dbo].[Usp_ViewEnquiryCategoryThresholds] --335          
(          
    @ParentID Bigint          
)          
AS          
BEGIN          
    SET NOCOUNT ON;  -- Prevents extra result sets from interfering with SELECT statements      
      
    BEGIN TRY      
        IF EXISTS (SELECT 1 FROM enquiry_cateogy_thresholds (NOLOCK) WHERE parentid = @ParentID)           
        BEGIN          
            SELECT            
                id,          
                ISNULL(Hot, 0) AS Hot,           
                ISNULL(Warm, 0) AS Warm,          
                ISNULL(Cold, 0) AS Cold,          
                isdefault,          
                updatedon,          
                updatedby          
            FROM enquiry_cateogy_thresholds (NOLOCK)          
            WHERE parentid = @ParentID;          
        END          
        ELSE          
        BEGIN          
            SELECT            
                id,          
                ISNULL(Hot, 0) AS Hot,           
                ISNULL(Warm, 0) AS Warm,          
                ISNULL(Cold, 0) AS Cold,          
                isdefault,          
                updatedon,          
                updatedby          
            FROM enquiry_cateogy_thresholds (NOLOCK)          
            WHERE parentid = 0;          
        END          
      
        -- Audit log for viewing enquiry category thresholds      
        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId       
            @User_id = @ParentID,          
            @Activity_type = 'View_EnquiryScore_Sttng',          
            @ActionType = 'S',          
            @RowJson = '',          
            @Table_name = 'enquiry_cateogy_thresholds';           
    END TRY      
    BEGIN CATCH      
        exec usp_InsertErrorInfo       
    END CATCH      
END;   
  


GO

