	   if(@SearchType = 'Conversion')
	    Begin
		    set  @FilterQuery = '( ( FollowupStatus = ''Converted'' ) and  ' + '('+@FilterQuery +')'+ ')'  
		End
	
     if(@IsAdmin = 0)    
     Begin    
     exec Usp_ViewUserEnquriyDetails_Changedss21 --@FilterQueryCustom,@ParentID,@UserID,@FilterQuery,@srno,@enno,'',0     
			@Txtsearch = @FilterQueryCustom,  
