CREATE   PROCEDURE dbo.Usp_ViewFloaterActionSettings --'test_new'    
(    
   @PageNameOnly nvarchar(200),  
   @ParentID bigint     
)    
as    
Begin    
      Declare @ClientPageID bigint = isnull((select top 1 isnull(id,0) from ClientPageDetail with(nolock) where PageName = 'www.kit19.com/'+ @PageNameOnly),0 )       
       
  SELECT     
        t_fas.[ID]    
   --   ,t_fas.[Logo]    
   --   ,t_fas.[ActionID]    
   --,t_fam.FloaterAction as ActionName      
   --   ,t_fas.[CountryCode]    
   --   ,t_fas.[MobileNo]    
   --   ,t_fas.[EmailID]    
   --   ,t_fas.[DIDNo]    
   --   ,t_fas.[IVRNo]    
   --   ,t_fas.[Media]    
   --   ,t_fas.[Title]    
   --   ,t_fas.[Subject]    
   --   ,t_fas.[Message]    
      ,t_fas.[TotalityMessage_JSON]    
      ,t_fas.[CreatedOn]    
      ,t_fas.[ModifiedOn]    
      ,t_fas.Isactive  
   ,t_fas.ParentID    
  FROM [tbl_FloaterActionSettings] as t_fas with(nolock)     
     --join tbl_FloaterActionMaster as t_fam with(nolock)    
     --on t_fas.ActionID = t_fam.ID     
   where t_fas.ClientPageID = @ClientPageID    
        
End    


