/* ============================================================
   Procedure: [dbo].[Usp_ViewKiteverUserSearchParameter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*        
  Created By : Santosh Kumar        
  Created date : 02/06/2107 03:14 PM        
  SP For : View kitever user search parameters in searchdetail        
  Alter Date :        
  Alter by :        
        
*/        
        
CREATE   PROC [dbo].[Usp_ViewKiteverUserSearchParameter]-- 1 --62       
@IsActive BIT      
AS         
BEGIN
	SELECT A.ID,
	       A.SearchName,
	       A.LoginDateFrom,
	       A.LoginDateTo,
	       A.TimeSpentOnApp,
	       A.TimeOperator,
	       A.ConsumptionFrom,
	       A.ConsumptionTo,
	       A.SMSConsumptionFrom,
	       A.SMSConsumptionTo,
	       A.MailConsumptionFrom,
	       A.MailConsumptionTo,
	       A.BalanceUsed,
	       A.Operator,
	       A.SMSBalanceUsed,
	       A.SMSOperator,
	       A.MailBalanceUsed,
	       A.MailOperator,
	       A.OrderFrom,
	       A.OrderTo,
	       A.LeadsFrom,
	       A.LeadsTo,
	       A.TopUpFrom,
	       A.TopUpTo,
	       A.TopUpOperator,
	       A.TopUpAmount,
	       A.RegistrationDateFrom,
	       A.RegistrationDateTo,
	       A.IsActive,
	       (
	           CASE 
	                WHEN A.LoginDateFrom <> ''
	           OR A.LoginDateTo <> '' THEN '<p><b>Last Login:</b>' +
	              CAST(A.LoginDateFrom AS VARCHAR(50)) + ' - ' + CAST(A.LoginDateTo AS VARCHAR(50)) 
	              + '</p>' 
	              ELSE '' 
	              END +
	              CASE 
	                   WHEN A.TimeSpentOnApp <> '' THEN 
	                        '<p><b>TimeSpentOnApp:</b>' + A.TimeSpentOnApp 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.TimeOperator <> '' THEN '<p><b>TimeOperator:</b>' 
	                        + A.TimeOperator 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.ConsumptionFrom <> ''
	           OR A.ConsumptionTo <> '' THEN '<p><b>Consumption:</b>' +
	              CAST(A.ConsumptionFrom AS VARCHAR(50)) + ' - ' + CAST(A.ConsumptionTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.SMSConsumptionFrom <> ''
	           OR A.SMSConsumptionTo <> '' THEN '<p><b>SMS Consumption:</b>' +
	              CAST(A.SMSConsumptionFrom AS VARCHAR(50)) + ' - ' + CAST(A.SMSConsumptionTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.MailConsumptionFrom <> ''
	           OR A.MailConsumptionTo <> '' THEN '<p><b>Mail Consumption:</b>' +
	              CAST(A.MailConsumptionFrom AS VARCHAR(50)) + ' - ' + CAST(A.MailConsumptionTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.BalanceUsed <> '' THEN '<p><b>BalanceUsed:</b>' +
	                        A.BalanceUsed 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.Operator <> '' THEN '<p><b>Operator:</b>' + A.Operator 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.SMSBalanceUsed <> '' THEN 
	                        '<p><b>SMSBalanceUsed:</b>' + A.SMSBalanceUsed 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.SMSOperator <> '' THEN '<p><b>SMSOperator:</b>' +
	                        A.SMSOperator 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.MailBalanceUsed <> '' THEN 
	                        '<p><b>MailBalanceUsed:</b>' + A.MailBalanceUsed 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.MailOperator <> '' THEN '<p><b>MailOperator:</b>' 
	                        + A.MailOperator 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.OrderFrom <> ''
	           OR A.OrderTo <> '' THEN '<p><b>Order:</b>' +
	              CAST(A.OrderFrom AS VARCHAR(50)) + ' - ' + CAST(A.OrderTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.LeadsFrom <> ''
	           OR A.LeadsTo <> '' THEN '<p><b>Leads:</b>' +
	              CAST(A.LeadsFrom AS VARCHAR(50)) + ' - ' + CAST(A.LeadsTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.TopUpFrom <> ''
	           OR A.TopUpTo <> '' THEN '<p><b>Top Up:</b>' +
	              CAST(A.TopUpFrom AS VARCHAR(50)) + ' - ' + CAST(A.TopUpTo AS VARCHAR(50)) 
	              + '</p>'
	              ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.TopUpOperator <> '' THEN 
	                        '<p><b>TopUpOperator:</b>' + A.TopUpOperator 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.TopUpAmount <> '' THEN '<p><b>TopUpAmount:</b>' +
	                        A.TopUpAmount 
	                        + '</p>'
	                   ELSE ''
	              END +
	              
	              CASE 
	                   WHEN A.RegistrationDateFrom <> ''
	           OR A.RegistrationDateTo <> '' THEN '<p><b>Registration:</b>' +
	              CAST(A.RegistrationDateFrom AS VARCHAR(50)) + ' - ' + CAST(A.RegistrationDateTo AS VARCHAR(50)) 
	              + '</p>' 
	              ELSE '' 
	              END
	       )              AS SearchCriteria
	FROM   SearchDetails     A
	WHERE  IsKitever = 1
	       AND IsUsers = 1
	       AND IsActive = @IsActive
END 



