/* ============================================================
   Procedure: [dbo].[Usp_ViewLeadCategoryThresholds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewLeadCategoryThresholds] --335
(
  @ParentID Bigint
)
as
Begin

   if(exists (select 1 from lead_cateogy_thresholds(nolock) where parentid = @ParentID )) 
   Begin
      SELECT  
 	   id
      ,ISNULL(Hot,0) as Hot 
      ,isnull(Warm,0) as Warm
      ,isnull(Cold,0) as Cold
      ,isdefault
      ,updatedon
      ,updatedby
	  ,ScoreSettingType
   FROM lead_cateogy_thresholds(nolock)
      where parentid = @ParentID
   End
   else
     Begin
		 SELECT  
 		   id
		  ,ISNULL(Hot,0) as Hot 
		  ,isnull(Warm,0) as Warm
		  ,isnull(Cold,0) as Cold
		  ,isdefault
		  ,updatedon
		  ,updatedby
		  ,ScoreSettingType
	   FROM lead_cateogy_thresholds(nolock)
		  where parentid = 0

	 End
    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
			,@Activity_type = 'View_LeadScore_Sttng'
			,@ActionType = 'S'
			,@RowJson = ''
			,@Table_name = 'lead_cateogy_thresholds' 
End




