/*      
  Created by : Santosh Kumar      
  Created Date: 24/05/2017 01:07 PM      
  sp For : To view client lead details      
         
*/      
      
CREATE   PROC [dbo].[Usp_ViewLeadDetails]      
@cname VARCHAR(200)                  
AS                    
BEGIN  
 --SELECT *  
 --FROM   ClientLeadDetails  
 --WHERE  cname = @cname  
 --ORDER BY  
 --       Id DESC 
 SELECT ClientLeadDetails.* FROM [ClientPageDetail] inner join ClientLeadDetails
on REPLACE(ClientPageDetail.PageName,'www.kit19.com/','')=ClientLeadDetails.cname and ClientPageDetail.USER_ID = @cname 
ORDER BY ClientLeadDetails.Id DESC 
END 


