-- exec Usp_ViewLeadDetailsBySearchCriteria @srno=N'1',@enno=N'20',@CriteriaName=N'All Leads',@UserID=39042,@CriteriaID=0,@SearchByMode=N'Name'
CREATE   PROCEDURE [dbo].[Usp_ViewLeadDetailsBySearchCriteria] --'1','20','',34594,231745,'id'    
(    
	--@txtSearch NVARCHAR(max),
	--@FilterText NVARCHAR(MAX) = '',
	@srno NVARCHAR(100),
	@enno NVARCHAR(100),
	--@ordstr nvarchar(Max)='' ,
	--@notfollowedup int=null,
	@CriteriaName nvarchar(500),
	@UserID bigint,
	@CriteriaID bigint,
	@SearchByMode nvarchar(50)
)    
as    
Begin
	-- declare @srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@CriteriaName nvarchar(500)=N'All Leads',@UserID bigint=39042,@CriteriaID bigint=0,@SearchByMode nvarchar(50)=N'Name'

	declare @ParentID bigint = 0    
	declare @IsAdmin bit = 0     
    
	select @ParentID = ISNULL(ParentID,User_ID) , @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID
    
	if(@SearchByMode = 'Name')    
	Begin    
		select top 1 @CriteriaID = isnull(ID,0) from tbl_SearchCriteria(nolock) where CriteriaName = @CriteriaName and ParentID = @ParentID      
	end

    Declare @ApplyTo nvarchar(50) = 'applyall'                       
	Declare @AndorOR nvarchar(10) = 'and'                      
