	Declare @FilterQuery nvarchar(max) = ' ('                      
                          
	if(@Count = 0)                      
    Begin                      
		set @FilterQuery = @FilterQuery + '1=1'                        
	end                      
                      
	while(@Count > 0)                      
    Begin                      
		set @RowIndex = @RowIndex + 1                       
		select @FieldName = FieldName,@FieldOperator = Operator,@Value = Value ,@FieldType = FieldType 
		from  @tempConditions where RowNum = @RowIndex                      
                      
		select @DataType = dbo.ufn_FetchDataType(@FieldName,@FieldType,@ParentID);                        
		-- select @DataType                      
           
		 if( @FieldName = 'LeadID' and @FieldType = 'Lead' and @CriteriaNameTemp = 'All Leads' )
	     Begin
		    set @FieldName = 'ID'
		 end

		   
     if(@FieldName = 'IsOpen' and @FieldType = 'Enquiry')              
       Begin              
        set @FieldName = 'IsOpen'  
