		else if(@FieldOperator = 'not [A]%')                      
		Begin
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma ;                        
		End                      
		else if(@FieldOperator = 'not %[A]')                      
		Begin                      
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                        
		End                         
		else if(@FieldOperator = 'not [A]')                      
		Begin                      
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma ;                        
		End                         
		else if(@FieldOperator = 'in [A]')                      
		Begin                      
			set @FieldOperator = ' in '                      
			--set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = REPLACE('in [A]','in [A]',@Value) ;                        
		End                
                      
     --if(@DataType = 'datetime' and @FieldOperator = 'between')                      
     -- Begin                      
        --   set @FieldName = ' DATEDIFF(DAY,'+@FieldName+',getdate()) '                      
     -- end                      
                           
		declare @FieldColumnText nvarchar(500) = ' cast( '+ @FieldName +'  as varchar(100)) '                       
		if(@DataType = 'varchar' or @DataType = 'nvarchar')                      
        begin                      
			set @FieldColumnText = ' cast('+ @FieldName +' as varchar(100)) ';                      
		end                       
        else if(@DataType = 'numeric' or @DataType = 'float' or @DataType = 'int' )                      
        begin                      
			set @FieldColumnText = ' cast(cast('+ @FieldName +' as nvarchar(100)) as numeric(18,4)) ';                      
		end                            
		else if(@DataType = 'datetime' and @FieldOperator <> 'between')                      
		begin                      
			set @FieldColumnText = ' cast('+ @FieldName +' as date) ';                      
		end                         
           else if(@DataType = 'datetime' and @FieldOperator = 'between')                      
		begin                      
			--set @FieldColumnText = ' DATEDIFF(DAY,cast(fieldvalue as date),getdate()) ';                      
			set @FieldColumnText = ' DATEDIFF(DAY,getdate(),cast('+ @FieldName +' as date)) ';                       
		end                      
                             
                      
		if(@RowIndex = 1)                      
		Begin                      
			--set @FilterQueryCustom = @FilterQueryCustom + ' ( fieldname =' +''''+@FieldName+'''' +' and '+ ' '+@FieldColumnText+' ' +@FieldOperator+' '+ @Value + ' ) '; 
		  set @FilterQueryCustom = @FilterQueryCustom + ' ( '+@FieldColumnText+' ' +@FieldOperator+' '+ @Value + ' ) ';	
			                     
		end                      
		else                       
		Begin                      
			--set @FilterQueryCustom = @FilterQueryCustom + @AndorOR + ' ( fieldname =' +'''' + @FieldName+'''' +' and '+ ' '+@FieldColumnText+' ' + @FieldOperator+' '+ @Value + ' ) ';
			set @FilterQueryCustom = @FilterQueryCustom + @AndorOR + ' ( '+@FieldColumnText+' ' + @FieldOperator+' '+ @Value + ' ) ';                       

		End                      
                      
		set @Count = @Count - 1                         
	End                      
                     
                         
	set @FilterQueryCustom = @FilterQueryCustom + ') ';                      
                   
  --select @FilterQuery as TableFilter                      
  --select @FilterQueryCustom as CustomFilter                      
   --  select * from #tempConditionsCustom                      
	drop table if exists  #tempConditionsCustom                      
       
	--if(@SearchType = 'Conversion')
	--Begin
		--set  @FilterQuery = '( ( FollowupStatus = ''Converted'' ) and  ' + '('+@FilterQuery +')'+ ')'  
	--End

	print @FilterQueryCustom + ',' + cast(@ParentID as varchar) + ',' + cast(@UserID as varchar) + ',' + @FilterQuery 
	 
	if(@SearchType = 'Conversion') 
	 begin
		if(@IsAdmin = 0)    
		Begin    
			--exec Usp_ViewUserLeadDetails2_New_withnofollowup @FilterQueryCustom,@ParentID,@UserID,@FilterQuery,@srno,@enno,'',0   
			exec Usp_ViewUserLeadDetails2_New_withnofollowup$_Converted @FilterQueryCustom,@ParentID,@UserID,@FilterQuery,@srno,@enno,'',0
		End    
