/* ============================================================
   Procedure: [dbo].[Usp_ViewMailSettingsCollectivelyAsDSTye]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ViewMailSettingsCollectivelyAsDSTye --'BIDashboard',34594    
	(
	@DashboardType NVARCHAR(200)
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = ISNULL(ParentID, User_Id)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	IF (@DashboardType = 'MainDashboard')
	BEGIN
		SELECT [ID]
			,[DashboardType]
			,[Sections]
			,[DashboardID]
			,[ReportID]
			,[DataDateRange]
			,[SendAtPeriod]
			,[SendAtTime]
			,[ParentID]
			,[UserCollections]
			,[IsActive]
			,[CreatedOn]
			,[ModifiedOn]
			,[CreatedBy]
			,[LastDeliveredAt]
			,SendAtWhichDay
			,EmailIDs
			,Scope
		FROM [tbl_dsboardMailSetting](NOLOCK)
		WHERE DashboardType = @DashboardType
			AND ParentID = @ParentID
		ORDER BY id DESC
	END -- end of maindashboard         
	ELSE IF (@DashboardType = 'BIDashboard')
	BEGIN
		SELECT tdms.[ID]
			,tdms.[DashboardType]
			,tdms.[Sections]
			,tdms.[DashboardID]
			,TD.DashboardName
			,tdms.[ReportID]
			,(
				SELECT stuff((
							SELECT ', ' + tbl.ReportName
							FROM (
								(
									SELECT ReportName
									FROM tbl_DashboardReports(NOLOCK)
									WHERE ReportId IN (
											SELECT value
											FROM fn_split(tdms.ReportID, ',')
											)
									)
								) AS tbl
							FOR XML PATH('')
							), 1, 1, '')
				) AS ReportNames
			,(
				SELECT stuff((
							SELECT ', ' + tbl.User_Login
							FROM (
								(
									SELECT User_Login
									FROM User_detail(NOLOCK)
									WHERE User_ID IN (
											SELECT value
											FROM fn_split(tdms.UserCollections, ',')
											)
									)
								) AS tbl
							FOR XML PATH('')
							), 1, 1, '')
				) AS UserCollectionsName
			,tdms.[DataDateRange]
			,tdms.[SendAtPeriod]
			,tdms.[SendAtTime]
			,tdms.[ParentID]
			,tdms.[UserCollections]
			,tdms.[IsActive]
			,tdms.[CreatedOn]
			,tdms.[ModifiedOn]
			,tdms.[CreatedBy]
			,ud1.User_Login AS CreatedByName
			,tdms.[LastDeliveredAt]
			,SendAtWhichDay
			,isnull((
					SELECT CASE 
							WHEN tdms.[SendAtPeriod] = 'weekly'
								THEN CASE 
										WHEN tdms.SendAtWhichDay = 1
											THEN 'Mon'
										WHEN tdms.SendAtWhichDay = 2
											THEN 'Tue'
										WHEN tdms.SendAtWhichDay = 3
											THEN 'Wed'
										WHEN tdms.SendAtWhichDay = 4
											THEN 'Thur'
										WHEN tdms.SendAtWhichDay = 5
											THEN 'Fri'
										WHEN tdms.SendAtWhichDay = 6
											THEN 'Sat'
										WHEN tdms.SendAtWhichDay = 7
											THEN 'Sun'
										ELSE tdms.SendAtWhichDay
										END
							ELSE tdms.SendAtWhichDay
							END
					), '') AS SendAtWhichDayByName
			,ISNULL(EmailIDs, '') AS EmailIDs
			,isnull(Scope, '') AS Scope
		FROM [tbl_dsboardMailSetting](NOLOCK) AS tdms
		JOIN tbl_Dashboard(NOLOCK) AS TD ON tdms.DashboardID = Td.DashboardId
		JOIN User_Detail(NOLOCK) AS ud1 ON tdms.CreatedBy = ud1.User_ID
		WHERE tdms.DashboardType = @DashboardType
			AND tdms.ParentID = @ParentID
		ORDER BY id DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_Dsbrd_mail'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = '[tbl_dsboardMailSetting]'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewMediumDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_ViewMediumDetails --''                   
 (  
 @SearchText NVARCHAR(max)=null  
 ,@IsActive BIT  
 ,@IsInactive BIT  
 ,@UserID INT  
 )  
AS  
BEGIN  
 DECLARE @ParentId BIGINT = 0;  
 DECLARE @IsAdmin BIT = 0;  
 DECLARE @RoleType VARCHAR(10);  
 DECLARE @TeamCode VARCHAR(20)  
  
 SELECT @ParentId = ParentID  
  ,@IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserId;  
  
 IF object_id('tempdb..#tblUserIds') IS NOT NULL  
 BEGIN  
  DROP TABLE #tblUserIds  
 END  
  
 CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)  
  
 SELECT @TeamCode = tum.TeamCode  
 FROM TBL_UA_TeamUserMappingMaster(NOLOCK) tum  
 INNER JOIN TBL_UA_TeamMaster(NOLOCK) tm ON tm.TeamCode = tum.TeamCode  
 WHERE tum.UserId = @UserId  
  
 IF (  
   (@TeamCode IS NULL)  
   AND (  
    @ParentId = @UserId  
    OR @IsAdmin = 1  
    )  
   )  
 BEGIN  
  SET @RoleType = 'Global'  
  
  INSERT INTO #tblUserIds (UserId)  
  SELECT User_Id UserId  
  FROM User_Detail(NOLOCK)  
  WHERE ParentId = @ParentId  
 END  
 ELSE IF (@TeamCode != NULL)  
 BEGIN  
  SET @RoleType = 'Team'  
  
  INSERT INTO #tblUserIds (UserId)  
  SELECT UserId  
  FROM TBL_UA_TeamUserMappingMaster(NOLOCK)  
  WHERE TeamCode = @TeamCode  
 END  
 ELSE  
 BEGIN  
  SET @RoleType = 'User'  
  
  INSERT INTO #tblUserIds (UserId)  
  SELECT @UserId  
 END  
  
 SELECT uss.MediumID  
  ,uss.Name  
  ,uss.IsEditable  
  ,uss.IsActive  
  ,ud1.User_Login  
  ,ud.FName + ISNULL(ud.LName, '') AS CreatedBy  
 FROM UserMediumSettings AS uss  
 LEFT JOIN User_Detail AS ud ON uss.UserID = ud.[User_ID]  
 LEFT JOIN User_Detail AS ud1 ON uss.ModifiedBy = ud1.User_ID  
 WHERE uss.UserID IN (  
   SELECT UserId  
   FROM #tblUserIds  
   )  
  AND (  
   ISNULL(@SearchText, '') = ''  
   OR uss.Name LIKE '%' + @SearchText + '%'  
   )  
  AND (  
   uss.IsActive = CASE   
    WHEN @IsActive = 0  
     THEN NULL  
    ELSE 1  
    END  
   OR uss.IsActive = CASE   
    WHEN @IsInactive = 1  
     THEN 0  
    ELSE NULL  
    END  
   )  
 ORDER BY uss.MediumID DESC  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'View_Mdm_Sttng'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserMediumSettings'  
END  


GO

