/* ============================================================
   Procedure: [dbo].[Usp_ViewMobileRequests]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ViewMobileRequests 
As
Begin

  SELECT

       FR.RequestID
      ,FR.UserID
      ,FR.ParentID
      ,FR.Mobile
      ,FR.RequestCreatedDate
	  ,FRH.LandLine 
	  ,FRH.[Action]
      ,FRH.ActionDate
      ,FRH.Remarks
      ,FRH.CreatedBy
	  ,(select top 1 user_login from user_detail where User_ID = FR.UserID) as UserIDByName
	  ,(select top 1 user_login from user_detail where User_ID = FR.ParentID) as ParentIDByName
	  ,(select top 1 user_login from user_detail where User_ID = FRH.CreatedBy) as CreatedByName

  FROM Cloud_MobileForwardingRequest as FR
  join Cloud_MobileForwardingRequestHistory as FRH
  on FR.RequestID = FRH.RequestID  
  where FRH.ID in ( select top 1 isnull(max(ID),0) from Cloud_MobileForwardingRequestHistory where RequestID = Fr.RequestID )
  order by FR.RequestID  ASC

End



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewPreEnquiryDetailsFromSearchDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROC [dbo].[Usp_ViewPreEnquiryDetailsFromSearchDetails]  --1                     
@IsActive BIT                    
AS                       
BEGIN
	SELECT A.ID,
	       A.SearchName,
	       A.PreEnquirySelectStatusName,
	       A.PreEnquirySelectStatusIsLastStatus,
	       A.PreEnquirySelectService,
	       A.PreEnquirySelectExecutive,
	       A.PreEnquirySelectExecutiveIsLast,
	       A.PreEnquirySelectLeadStatus,
	       A.PreEnquirySelectLeadStatusIsLastStatus,
	       A.PhoneNumber,
	       A.IsActive,
	       A.IsEnrolled,
	       A.SpecificDatesFrom,
	       A.SpecificDateTo,
	       A.SpecificDaysFrom,
	       A.SpecificDaysTo,
	       A.TotalBusinessFrom,
	       A.TotalBusinessTo,
	       A.SingleBusinessFrom,
	       A.SingleBusinessTo,
	       A.RetentionExecutive,
	       A.IsCurrentRetention,
	       A.EnrollName,
	       A.EnrollCompany,
	       A.EnrollOfficeAddress,
	       A.EnrollResidenceAddress,
	       A.[State],
	       A.City,
	       A.PinCode,
	       A.IsSpecificCheck,
	       A.IsEnrollCheck,
	       A.IsFollowUpCheck,
	       A.IsRetentionCheck,
	       A.EnrollExecutive,
	       A.EnquiryDateDaysFrom,
	       A.EnquiryDateDaysTo,
	       A.NextStatusDateDaysFrom,
	       A.NextStatusDateDaysTo,
	       CAST(A.EnrollMobile AS VARCHAR(50)) AS EnrollMobile,
	       A.EnrollEmailID,
	       (
	           CASE 
	                WHEN A.PreEnquirySelectStatusName <> '' THEN 
	                     '<p><b>Status Name :</b>' + REPLACE(A.PreEnquirySelectStatusName, '#', '/') 
	                     + '</p>' + CASE 
	                                     WHEN A.PreEnquirySelectStatusIsLastStatus 
	                                          = 1 THEN 
	                                          '<p><b>Is Last Status :</b> Yes</p>'
	                                     ELSE 
	                                          '<p><b>Is Last Status :</b> No </p>'
	                                END
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.PreEnquirySelectService 
	                     <> '' THEN '<p><b>Service :</b>' + REPLACE(A.PreEnquirySelectService, '#', ',') 
	                     + '</p>'
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.PreEnquirySelectExecutive <> '' THEN 
	                     '<p><b>Executive Name :</b>' + REPLACE(A.PreEnquirySelectExecutive, '#', ',') 
	                     + '</p>' + CASE 
	                                     WHEN A.PreEnquirySelectExecutiveIsLast 
	                                          = 1 THEN 
	                                          '<p><b>Is Last Executive :</b> Yes</p>'
	                                     ELSE 
	                                          '<p><b>Is Last Executive :</b> No </p>'
	                                END
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.PreEnquirySelectLeadStatus <> '' THEN 
	                     '<p><b>Lead Status Name :</b>' + REPLACE(A.PreEnquirySelectLeadStatus, '#', ',') 
	                     + '</p>' + CASE 
	                                     WHEN A.PreEnquirySelectLeadStatusIsLastStatus 
	                                          = 1 THEN 
	                                          '<p><b>Is Last Lead Status :</b> Yes</p>'
	                                     ELSE 
	                                          '<p><b>Is Last Lead Status :</b> No </p>'
	                                END
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.PhoneNumber 
	                     <> 0 THEN '<p><b>Phone Number :</b>' + CAST(A.PhoneNumber AS VARCHAR(50)) 
	                     + '</p>'
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.IsEnrolled 
	                     = 1 THEN '<p><b>Is Enrolled :</b> Yes</p>'
	                ELSE '<p><b>Is Enrolled :</b> No </p>'
	           END +
	           CASE 
	                WHEN A.SpecificDatesFrom 
	                     <> ''
	           AND A.SpecificDateTo <>
	               '' THEN '<p><b>Specific Dates :</b>' 
	               + A.SpecificDatesFrom + ' - ' 
	               + A.SpecificDateTo 
	               + '</p>' 
	               ELSE '' 
	               END +
	               CASE 
	                    WHEN A.SpecificDaysFrom 
	                         <> 0
	           AND A.SpecificDaysTo <>
	               0 THEN '<p><b>Specific Days :</b>' 
	               + CAST(A.SpecificDaysFrom AS VARCHAR(50)) + ' - ' 
	               + CAST(A.SpecificDaysTo AS VARCHAR(50)) 
	               + '</p>' 
	               ELSE '' 
	               END +
	               
	               CASE 
	                    WHEN A.TotalBusinessFrom 
	                         <> 0
	           AND A.TotalBusinessTo <>
	               0 THEN '<p><b>Total Business :</b>' 
	               + CAST(A.TotalBusinessFrom AS VARCHAR(50)) + ' - ' 
	               + CAST(A.TotalBusinessTo AS VARCHAR(50)) 
	               + '</p>' 
	               ELSE '' 
	               END +
	               CASE 
	                    WHEN A.SingleBusinessFrom 
	                         <> 0
	           AND A.SingleBusinessTo <>
	               0 THEN '<p><b>Total Business :</b>' 
	               + CAST(A.SingleBusinessFrom AS VARCHAR(50)) + ' - ' 
	               + CAST(A.SingleBusinessTo AS VARCHAR(50)) 
	               + '</p>' 
	               ELSE '' 
	               END +
	               CASE 
	                    WHEN A.RetentionExecutive <> '' THEN 
	                         '<p><b>Retention Executive :</b>' + REPLACE(A.RetentionExecutive, '#', ',') 
	                         + '</p>' + CASE 
	                                         WHEN A.IsCurrentRetention 
	                                              = 1 THEN 
	                                              '<p><b>Is Current Retention :</b> Yes</p>'
	                                         ELSE 
	                                              '<p><b>Is Current Retention :</b> No </p>'
	                                    END
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollName 
	                         <> '' THEN '<p><b>Name :</b>' 
	                         + A.EnrollName + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollCompany 
	                         <> '' THEN '<p><b>Company :</b>' 
	                         + A.EnrollCompany + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollOfficeAddress 
	                         <> '' THEN '<p><b> Office Address :</b>' 
	                         + A.EnrollOfficeAddress + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollResidenceAddress 
	                         <> '' THEN '<p><b> Residence Address :</b>' 
	                         + A.EnrollResidenceAddress + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.[State] 
	                         <> '' THEN '<p><b> State :</b>' 
	                         + A.[State] + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.City 
	                         <> '' THEN '<p><b> City :</b>' 
	                         + A.City + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.PinCode 
	                         <> '' THEN '<p><b> PinCode :</b>' 
	                         + A.PinCode + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollMobile 
	                         <> '' THEN '<p><b> Mobile :</b>' 
	                         + CAST(A.EnrollMobile AS VARCHAR(50)) + '</p>'
	                    ELSE ''
	               END +
	               CASE 
	                    WHEN A.EnrollEmailID 
	                         <> '' THEN '<p><b> Email-ID :</b>' 
	                         + A.EnrollEmailID + '</p>'
	                    ELSE ''
	               END + CASE 
	                          WHEN A.EnquiryDateDaysFrom 
	                               <> 0
	           OR A.EnquiryDateDaysTo <>
	              0 THEN '<p><b>Enquiry Days :</b>' 
	              + CAST(A.EnquiryDateDaysFrom AS VARCHAR(50)) + ' to ' 
	              + CAST(A.EnquiryDateDaysTo AS VARCHAR(50)) 
	              + '</p>' 
	              ELSE '' 
	              END + CASE 
	                         WHEN A.NextStatusDateDaysFrom 
	                              <> 0
	           OR A.NextStatusDateDaysTo <>
	              0 THEN '<p><b>Next Status Days :</b>' 
	              + CAST(A.NextStatusDateDaysFrom AS VARCHAR(50)) + ' to ' 
	              + CAST(A.NextStatusDateDaysTo AS VARCHAR(50)) 
	              + '</p>' 
	              ELSE '' 
	              END
	       )  AS SearchCriteria
	FROM   (
	           SELECT A.ID,
	                  A.SearchName,
	                  A.PreEnquirySelectStatusName,
	                  A.PreEnquirySelectStatusIsLastStatus,
	                  A.PreEnquirySelectService,
	                  A.PreEnquirySelectExecutive,
	                  A.PreEnquirySelectExecutiveIsLast,
	                  A.PreEnquirySelectLeadStatus,
	                  A.PreEnquirySelectLeadStatusIsLastStatus,
	                  A.PhoneNumber,
	                  A.IsActive,
	                  ISNULL(A.IsEnrolled, 0) AS IsEnrolled,
	                  A.SpecificDatesFrom,
	                  A.SpecificDateTo,
	                  ISNULL(A.SpecificDaysFrom, 0) AS SpecificDaysFrom,
	                  ISNULL(A.SpecificDaysTo, 0) AS SpecificDaysTo,
	                  ISNULL(A.TotalBusinessFrom, 0) AS TotalBusinessFrom,
	                  ISNULL(A.TotalBusinessTo, 0) AS TotalBusinessTo,
	                  ISNULL(A.SingleBusinessFrom, 0) AS SingleBusinessFrom,
	                  ISNULL(A.SingleBusinessTo, 0) AS SingleBusinessTo,
	                  A.RetentionExecutive,
	                  A.IsCurrentRetention,
	                  A.EnrollName,
	                  A.EnrollCompany,
	                  A.EnrollOfficeAddress,
	                  A.EnrollResidenceAddress,
	                  A.[State],
	                  A.City,
	                  A.PinCode,
	                  A.EnrollMobile,
	                  A.EnrollEmailID,
	                  A.IsSpecificCheck,
	                  A.IsEnrollCheck,
	                  A.IsFollowUpCheck,
	                  A.IsRetentionCheck,
	                  A.EnrollExecutive,
	                  A.EnquiryDateDaysFrom,
	                  A.EnquiryDateDaysTo,
	                  A.NextStatusDateDaysFrom,
	                  A.NextStatusDateDaysTo
	           FROM   SearchDetails A
	           WHERE  IsCRMDB = 1
	                  AND IsPreEnquiry = 1 
	                      --  AND IsActive = @IsActive
	       )     A
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewProductMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ViewProductMaster] --'',1,1,335      
(      
 @txtSearch nvarchar(100),      
 @IsActive bit,    
 @IsInactive bit,      
 @UserID int       
      
)      
as       
Begin      

 DECLARE @ParentId BIGINT = 0;              
 DECLARE @IsAdmin bit = 0;              
 DECLARE @RoleType varchar(10);              
 Declare @TeamCode VARCHAR(20)                            

SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;              

if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end

CREATE TABLE #tblUserIds(
   UserId bigint  NOT NULL)

select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode
where tum.UserId = @UserId
 
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))
Begin
--set @RoleType = 'Global'
Insert into #tblUserIds (UserId)
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId 
End
Else if(@TeamCode != null) 
Begin
---set @RoleType = 'Team'
Insert into #tblUserIds (UserId)
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode
End
Else 
Begin
--set @RoleType = 'User'
Insert into #tblUserIds (UserId)
select @UserId 
End

    if(@txtSearch ='' or @txtSearch =null)      
      Begin      
         if(@IsActive = 1 and @IsInactive = 1)    
         Begin    
           select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
		   left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
		   where  PM.UserID in (select UserId From #tblUserIds) 
		   order by ProductID   desc        
         End     
         else if(@IsActive = 1 and @IsInactive = 0)    
          Begin    
               select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
			   left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
			   where IsActive = 1 and PM.UserID in (select UserId From #tblUserIds) 
			   order by ProductID   desc        
          End    
          else if(@IsActive = 0 and @IsInactive = 1)    
          Begin    
             select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
			 left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
			 where IsActive = 0 and PM.UserID in (select UserId From #tblUserIds) 
			 order by ProductID   desc        
          End 
          else if(@IsActive = 0 and @IsInactive = 0)    
          Begin    
             select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
			 left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
			 where IsActive <> 0 and IsActive <> 1 and PM.UserID in (select UserId From #tblUserIds) 
			 order by ProductID   desc        
          End    
          
       End      
     else      
      Begin    
        if(@IsActive = 1 and @IsInactive = 1)    
         Begin       
        select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
		left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
		where (PM.UserID in (select UserId From #tblUserIds)) and (Name like '%'+@txtSearch+'%' or [Description] like '%'+@txtSearch+'%' ) 
		order by ProductID   

desc      
         End    
         else if(@IsActive = 1 and @IsInactive = 0)    
          Begin    
           select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
		   left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
		   where (PM.UserID in (select UserId From #tblUserIds) and IsActive = 1) and (Name like '%'+@txtSearch+'%' or [Description] like '%'+@txtSearch+'%' ) 
		   order by ProductID   desc      
              
          End     
          else if(@IsActive = 0 and @IsInactive = 1)    
          Begin    
        select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
		left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
		where (PM.UserID in (select UserId From #tblUserIds) and IsActive = 0) and (Name like '%'+@txtSearch+'%' or [Description] like '%'+@txtSearch+'%' ) 
		order by ProductID   desc      
              
          End     
              
          else if(@IsActive = 0 and @IsInactive = 0)    
          Begin    
            select PM.*,UD.User_Login from ProductMaster as PM(nolock) 
			left join User_Detail UD(Nolock) on PM.CreatedBy = UD.User_ID 
			where (PM.UserID in (select UserId From #tblUserIds) and IsActive <> 0 and IsActive <> 1) and (Name like '%'+@txtSearch+'%' or [Description] like '%'+@txtSearch+'%' ) 
			order by ProductID   desc      
                 
          end    
             
      End        
End  



GO

