/* ============================================================
   Procedure: [dbo].[Usp_ViewProductsBySearchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewProductsBySearchCriteria] --3        
(        
  @CriteriaID bigint        
)        
as        
Begin        
        
     --declare  @CriteriaID bigint = 2        
     Declare @UserID bigint = 0        
  Declare @CriteriaType nvarchar(50) = ''        
  Declare @AllProductDefault bit = 0        
  Declare @ProductIDCollections nvarchar(max) = ''         
  Declare @SearchApplyTo nvarchar(50) = ''        
  Declare @AndOrOR nvarchar(50) = ''        
  Declare @SortByColumnName nvarchar(500) = ''         
  Declare @OrderBy nvarchar(50) = ''        
        
          
   select top 1  @UserID = isnull(createdby,0), @CriteriaType = isnull(CriteriaType,''),@AllProductDefault = ISNULL(AllProductDefault,0) 
   , @SearchApplyTo = isnull(SearchApplyTo,'') , @ProductIDCollections =  isnull(ProductIDs,'') ,
    @SortByColumnName = isnull(SortByColumnName,'ProductID')        
   ,@OrderBy = ISNULL(OrderBy,'Desc')    from ProductSearchCriteria(nolock) where ID = @CriteriaID        
        
	declare @ParentID bigint = ( select top 1 isnull(parentid , 0) from User_Detail with(nolock) where User_ID = @UserID )

	exec Usp_createProductMasterTable @ParentID


     if(@SearchApplyTo = 'All')        
      Begin        
       set @AndOrOR = 'And'            
   End        
     else        
    Begin        
      set @AndOrOR = 'Or'            
    End        
        
        
   if(rtrim(ltrim(@CriteriaType))  = 'manual')        
      Begin        
        
    -- select @CriteriaType  , @SortByColumnName , @OrderBy        
          
 declare @QmxManual nvarchar(max) = N'         
  select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
      ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName        
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id    
   ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName         
      ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
      ,[IsGoods]        
      ,[IsServices]        
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_'+cast(@ParentID as nvarchar(20))+' (nolock) where isnull(IsActive,0) = 1 and  USERID = '+cast(@UserID as nvarchar)+' and ProductID in (select cast(isnull(value,0) as bigint) from fn_Split('''+@ProductIDCollections+''','',''))        
     order by category_id , '+ @SortByColumnName +' ' + @OrderBy          
        
   print @QmxManual        
        
    EXEC sp_executesql @QmxManual;        
        
        
   End        
   else if(rtrim(ltrim(@CriteriaType))  = 'Conditional')        
     Begin        
      if(isnull(@AllProductDefault,0) = 1)        
     Begin        
   declare @QmxTotal nvarchar(max) = N'         
  select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
      ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName         
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id       
      ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName    
   ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
      ,[IsGoods]        
      ,[IsServices]    
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_'+cast(@ParentID as nvarchar(20))+' (nolock) where isnull(IsActive,0) = 1 and  USERID = '+cast(@UserID as nvarchar)+'        
     order by category_id , '+ @SortByColumnName +' ' + @OrderBy          
        
   print @QmxTotal        
        
    EXEC sp_executesql @QmxTotal;        
               
     End        
           else        
    Begin        
    Declare @FilterText nvarchar(max) =  dbo.funcToGetSearchFilterByCriteriaID(@CriteriaID,@AndOrOR)         
    Declare @QueryMax nvarchar(max) = N'select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
  ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName         
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id        
      ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName    
   ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
      ,[IsGoods]        
      ,[IsServices]        
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_'+cast(@ParentID as nvarchar(20))+' (nolock) where isnull(IsActive,0) = 1 and  UserID = '+ cast( @UserID as nvarchar )+' and ( '+ @FilterText +' )        
    order by category_id , '+ @SortByColumnName +' ' + @OrderBy         
               
        
            
    print @QueryMax        
        
    EXEC sp_executesql @QueryMax;        
    End           
  End        
            
               
End


GO


